import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { Task, BoardSpace } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 20;
const MAX_FLORA = 100;
const MOVE_STEP_DELAY = 300;
const ZOMBIE_COUNT = 10;
const BOMB_COUNT = 8;
const MAX_ZOMBIE_HEALTH = 3;
const TOTAL_TILES_TARGET = 100;

const ANIMAL_EMOJIS = ['🦄', '🐉', '🦖', '🦁', '🦊', '🐸', '🐼', '🦀'];
const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];

interface CompletedTask extends Task {
  completedAt: string;
}

interface ZombieData {
  id: number;
  pos: number;
  health: number;
  isEliminating: boolean;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Reach 100 Flora', completed: false },
    { id: '2', text: 'Purge the Board', completed: false },
    { id: '3', text: 'Unlock Secret Tile', completed: false },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePosition, setDicePosition] = useState({ x: window.innerWidth * 0.9, y: window.innerHeight * 0.85 });
  const [isSpecialLanding, setIsSpecialLanding] = useState(false);
  const [isShaking, setIsShaking] = useState(false);
  const [confettiActive, setConfettiActive] = useState(false);
  const [isExploding, setIsExploding] = useState(false);

  const [floralCount, setFloralCount] = useState(10);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombies, setZombies] = useState<ZombieData[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const TILE_SIZE = 58; 
  const TILE_GAP = 8;
  const SAFE_MARGIN = 40;

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const step = TILE_SIZE + TILE_GAP;

    // Formula for perimeter: 2 * (cols + rows) - 4 = 100
    // => 2 * (cols + rows) = 104 => cols + rows = 52
    const usableWidth = window.innerWidth - (SAFE_MARGIN * 2);
    const usableHeight = window.innerHeight - (SAFE_MARGIN * 2);
    const ratio = usableWidth / usableHeight;

    // rows + ratio * rows = 52 => rows * (1 + ratio) = 52
    let rows = Math.round(52 / (1 + ratio));
    let cols = 52 - rows;

    const actualBoardWidth = (cols - 1) * step;
    const actualBoardHeight = (rows - 1) * step;

    const startX = (window.innerWidth - actualBoardWidth) / 2 - TILE_SIZE / 2;
    const startY = (window.innerHeight - actualBoardHeight) / 2 - TILE_SIZE / 2;

    // Top
    for (let i = 0; i < cols; i++) {
      spaces.push({ id: spaces.length, type: (spaces.length % 10 === 0) ? 'special' : 'normal', x: startX + (i * step), y: startY });
    }
    // Right
    for (let i = 1; i < rows; i++) {
      spaces.push({ id: spaces.length, type: (spaces.length % 10 === 0) ? 'special' : 'normal', x: startX + ((cols - 1) * step), y: startY + (i * step) });
    }
    // Bottom
    for (let i = cols - 2; i >= 0; i--) {
      spaces.push({ id: spaces.length, type: (spaces.length % 10 === 0) ? 'special' : 'normal', x: startX + (i * step), y: startY + ((rows - 1) * step) });
    }
    // Left
    for (let i = rows - 2; i >= 1; i--) {
      spaces.push({ id: spaces.length, type: (spaces.length % 10 === 0) ? 'special' : 'normal', x: startX, y: startY + (i * step) });
    }

    return spaces;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const total = boardSpaces.length;

    const getRandomUnique = (count: number, exclude: number[]) => {
      const result: number[] = [];
      while (result.length < count) {
        const r = Math.floor(Math.random() * total);
        if (!exclude.includes(r) && !result.includes(r)) result.push(r);
      }
      return result;
    };

    const initialZombies: ZombieData[] = getRandomUnique(ZOMBIE_COUNT, [0]).map((pos, id) => ({
      id, pos, health: MAX_ZOMBIE_HEALTH, isEliminating: false
    }));
    setZombies(initialZombies);

    const initialBombs = getRandomUnique(BOMB_COUNT, [0, ...initialZombies.map(z => z.pos)]);
    setBombIndices(initialBombs);
  }, [boardSpaces.length]);

  const triggerBloom = (spaceId: number) => {
    const randomFlower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [spaceId]: randomFlower }));
    setFloralCount(c => Math.min(MAX_FLORA, c + 1));
    setTimeout(() => {
      setBlooms(prev => {
        const next = { ...prev };
        delete next[spaceId];
        return next;
      });
    }, 1200);
  };

  const processMovement = useCallback((diceVal: number) => {
    let stepsTaken = 0;
    let currentIterativePos = currentPos;
    const TOTAL_CELLS = boardSpaces.length;

    const interval = setInterval(() => {
      stepsTaken++;
      currentIterativePos = (currentIterativePos + 1) % TOTAL_CELLS;
      setCurrentPos(currentIterativePos);
      triggerBloom(currentIterativePos);

      // Bomb trigger logic
      if (bombIndices.includes(currentIterativePos)) {
        setZombies(zs => zs.map(z => {
          const dist = Math.min(
            Math.abs(z.pos - currentIterativePos),
            TOTAL_CELLS - Math.abs(z.pos - currentIterativePos)
          );
          if (dist <= 5 && !z.isEliminating) {
            const newHealth = Math.max(0, z.health - 1);
            return { ...z, health: newHealth, isEliminating: newHealth === 0 };
          }
          return z;
        }));
        setBombIndices(prev => prev.map(idx => idx === currentIterativePos ? Math.floor(Math.random() * TOTAL_CELLS) : idx));
        setIsShaking(true);
        setTimeout(() => setIsShaking(false), 300);
      }

      if (stepsTaken >= diceVal) {
        clearInterval(interval);
        setIsMoving(false);
        if (boardSpaces[currentIterativePos]?.type === 'special') {
          setIsSpecialLanding(true);
          setRollBank(r => r + 4);
          setTimeout(() => setIsSpecialLanding(false), 1200);
        }
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, boardSpaces, bombIndices]);

  const handleDiceRoll = useCallback((landingPos: { x: number; y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(prev => prev - 1);
    setDicePosition(landingPos);
    const newValue = Math.floor(Math.random() * 6) + 1;

    // Zombie random jump
    setZombies(prev => prev.map(z => ({
      ...z,
      pos: (z.pos + Math.floor(Math.random() * 3) + 1) % boardSpaces.length
    })));

    setTimeout(() => {
      setIsRolling(false);
      setDiceValue(newValue);
      setIsShaking(true);
      setTimeout(() => setIsShaking(false), 200);
      setIsMoving(true);
      processMovement(newValue);
    }, 1200);
  }, [rollBank, isRolling, isMoving, boardSpaces.length, processMovement]);

  useEffect(() => {
    if (isMoving) return;
    const contact = zombies.find(z => z.pos === currentPos && !z.isEliminating);
    if (contact) {
      setIsShaking(true);
      setFloralCount(0);
      setCurrentPos(0);
      setRollBank(prev => Math.max(0, prev - 5));
      setTimeout(() => setIsShaking(false), 600);
    }
  }, [zombies, currentPos, isMoving]);

  const handleTaskComplete = (task: Task) => {
    setConfettiActive(true);
    setTimeout(() => setConfettiActive(false), 2000);
    setRollBank(r => r + 8);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setIsShaking(true);
    setRollBank(prev => prev + 30);
    setZombies(prev => prev.map(z => {
      const nh = 0;
      return { ...z, health: nh, isEliminating: true };
    }));
    setTimeout(() => {
      setIsExploding(false);
      setIsShaking(false);
      setFloralCount(0);
    }, 1500);
  };

  return (
    <div className={`h-screen w-screen relative select-none overflow-hidden notion-grid transition-all duration-700 ${isShaking ? 'shake-screen' : ''} ${isExploding ? 'flash-red' : ''}`}>

      {/* 100 Tile Perimeter Board */}
      <div className="absolute inset-0 z-10 pointer-events-none">
        {boardSpaces.map((s) => {
          const isSpecial = s.type === 'special';
          const activeBloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isStart = s.id === 0;

          return (
            <div
              key={s.id}
              className={`absolute transition-all duration-500 flex items-center justify-center border pointer-events-auto
                ${isStart ? 'bg-indigo-50 dark:bg-indigo-900/40 border-indigo-400 dark:border-indigo-400' : 
                  isSpecial ? 'bg-amber-50 dark:bg-amber-900/40 border-amber-300 dark:border-amber-700' : 
                  'bg-white/90 dark:bg-[#252525]/90 border-[#e5e5e5] dark:border-[#333]'}
                ${currentPos === s.id ? 'z-20 border-[#37352f] dark:border-white ring-4 ring-black/5 scale-110 shadow-2xl' : 'shadow-sm'}
                hover:scale-105 hover:z-20 transition-transform cursor-help
              `}
              style={{ left: s.x, top: s.y, width: `${TILE_SIZE}px`, height: `${TILE_SIZE}px`, borderRadius: '14px' }}
            >
              <span className="text-[8px] font-black opacity-10 absolute bottom-1 right-1.5 dark:text-white uppercase tracking-tighter">{s.id + 1}</span>
              {isStart && !activeBloom && <span className="text-xs font-black opacity-40">START</span>}
              {activeBloom && <div className="animate-flower-bloom text-2xl">{activeBloom}</div>}
              {isBomb && !activeBloom && <span className="text-2xl animate-bounce-slow">💣</span>}
              {isSpecial && !activeBloom && !isBomb && <span className="text-lg opacity-40 animate-pulse">✨</span>}
            </div>
          );
        })}

        {/* Zombies */}
        {zombies.map(z => {
          const coords = boardSpaces[z.pos];
          if (!coords) return null;
          const healthPercent = (z.health / MAX_ZOMBIE_HEALTH) * 100;
          return (
            <div key={z.id} className={`absolute z-30 transition-all duration-700 ease-in-out pointer-events-none ${z.isEliminating ? 'animate-zombie-die' : ''}`} style={{ left: coords.x + (TILE_SIZE / 2), top: coords.y + (TILE_SIZE / 2), transform: 'translate(-50%, -50%)' }}>
              <div className="relative flex flex-col items-center">
                <div className="absolute -top-12 w-10 h-1.5 bg-gray-200 dark:bg-gray-800 rounded-full overflow-hidden border border-white/20">
                  <div className={`h-full transition-all duration-300 ${healthPercent < 40 ? 'bg-red-500' : 'bg-indigo-500'}`} style={{ width: `${healthPercent}%` }} />
                </div>
                <span className="text-5xl drop-shadow-lg filter contrast-125">🧟</span>
              </div>
            </div>
          );
        })}

        {/* Player Piece */}
        <div 
          onClick={() => setAnimalIndex((p) => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-40 transition-all duration-500 ease-out cursor-pointer pointer-events-auto ${isMoving ? 'animate-piece-jump' : ''} ${isSpecialLanding ? 'animate-knight-special' : ''}`}
          style={{ left: (boardSpaces[currentPos]?.x || 0) + (TILE_SIZE / 2), top: (boardSpaces[currentPos]?.y || 0) + (TILE_SIZE / 2), transform: 'translate(-50%, -50%)' }}
        >
          <div className="relative flex flex-col items-center">
             <div className="absolute -bottom-1 w-12 h-3 bg-black/10 dark:bg-white/10 blur-md rounded-full"></div>
             <span className="text-6xl drop-shadow-xl filter contrast-125">{ANIMAL_EMOJIS[animalIndex]}</span>
          </div>
        </div>
      </div>

      {/* Main Dashboard UI */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-50 flex items-center gap-12 scale-90 lg:scale-100">
        <div className="glass-panel rounded-[40px] p-10 w-80 min-h-[500px] flex flex-col transition-all duration-500">
          <div className="flex items-center justify-between mb-10">
            <div className="flex gap-8">
              <div className="flex flex-col">
                <span className="text-[10px] font-black opacity-30 uppercase tracking-widest dark:text-white">Bank</span>
                <span className="text-3xl font-black text-[#37352f] dark:text-white tabular-nums">{rollBank}</span>
              </div>
              <div className="w-[1px] h-12 bg-[#e0e0e0] dark:bg-[#333]"></div>
              <div className="flex flex-col">
                <span className="text-[10px] font-black opacity-30 uppercase tracking-widest dark:text-white">Tile</span>
                <span className="text-3xl font-black text-[#37352f] dark:text-white">{currentPos + 1}</span>
              </div>
            </div>
            <div className="flex gap-4">
              <button onClick={() => setDarkMode(!darkMode)} className="w-12 h-12 glass-panel rounded-2xl flex items-center justify-center transition-all hover:scale-110 active:scale-95 text-xl">{darkMode ? '☀️' : '🌙'}</button>
            </div>
          </div>

          <div className="flex-grow overflow-y-auto mb-8 space-y-3 custom-scrollbar pr-2">
            {!showHistory ? (
              tasks.map(task => (
                <div key={task.id} onClick={() => handleTaskComplete(task)} className="flex items-center justify-between p-5 rounded-[24px] transition-all cursor-pointer group bg-white/40 dark:bg-[#2a2a2a]/40 border border-transparent hover:border-[#37352f] dark:hover:border-white shadow-sm hover:shadow-xl">
                  <div className="flex items-center gap-5">
                    <div className="w-6 h-6 rounded-lg border-2 border-[#d8d8d8] dark:border-[#4f4f4f] group-hover:bg-[#37352f] dark:group-hover:bg-white transition-all flex items-center justify-center">
                       <svg className="w-4 h-4 text-white dark:text-black opacity-0 group-hover:opacity-100" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M5 13l4 4L19 7" /></svg>
                    </div>
                    <span className="text-[14px] font-bold text-[#37352f] dark:text-zinc-200">{task.text}</span>
                  </div>
                </div>
              ))
            ) : (
              history.map(item => (
                <div key={item.id} className="p-4 rounded-2xl border border-dashed border-[#e0e0e0] dark:border-[#333] bg-zinc-50 dark:bg-[#1a1a1a] opacity-50">
                  <span className="text-[13px] font-bold dark:text-white block line-through">✓ {item.text}</span>
                  <span className="text-[9px] opacity-40 dark:text-white uppercase mt-1 block">{item.completedAt}</span>
                </div>
              ))
            )}
          </div>

          <div className="mt-auto flex gap-3">
             <button onClick={() => setShowHistory(!showHistory)} className="flex-1 py-4 bg-[#f0f0ef] dark:bg-[#333] rounded-2xl text-[11px] font-black uppercase tracking-widest text-[#37352f] dark:text-white hover:bg-[#e0e0df] transition-all">
                {showHistory ? 'Active Tasks' : 'Logs'}
             </button>
             <form onSubmit={(e) => { e.preventDefault(); if (!newTask.trim()) return; setTasks([...tasks, { id: Date.now().toString(), text: newTask, completed: false }]); setNewTask(''); }} className="flex-[2] relative">
               <input type="text" value={newTask} onChange={(e) => setNewTask(e.target.value)} placeholder="Task..." className="w-full bg-[#f0f0ef] dark:bg-[#333] rounded-2xl pl-4 pr-10 py-4 text-[13px] font-bold outline-none focus:bg-white dark:focus:bg-[#444] transition-all dark:text-white" />
               <button type="submit" className="absolute right-2 top-1/2 -translate-y-1/2 w-8 h-8 flex items-center justify-center rounded-xl hover:bg-black/5 dark:hover:bg-white/5">
                 <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="M12 5v14M5 12h14"/></svg>
               </button>
             </form>
          </div>
        </div>

        <AlchemyJar count={floralCount} max={MAX_FLORA} isExploding={isExploding} onExplode={onJarExplode} />
      </div>

      <Dice3D value={diceValue} isRolling={isRolling} currentPos={dicePosition} onRoll={handleDiceRoll} onDragEnd={setDicePosition} />

      <style>{`
        @keyframes flower-bloom {
          0% { transform: scale(0) translateY(10px); opacity: 0; }
          40% { transform: scale(1.3) translateY(-5px); opacity: 1; }
          100% { transform: scale(0.8) translateY(0); opacity: 0; }
        }
        .animate-flower-bloom { animation: flower-bloom 1s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        @keyframes zombie-die {
          0% { transform: scale(1) rotate(0); opacity: 1; }
          50% { transform: scale(1.5) rotate(180deg); opacity: 1; filter: brightness(2) blur(2px); }
          100% { transform: scale(0) rotate(360deg); opacity: 0; }
        }
        .animate-zombie-die { animation: zombie-die 0.8s ease-in forwards; }
        @keyframes knight-flip {
            0% { transform: translate(-50%, -50%) rotateY(0deg) scale(1); }
            50% { transform: translate(-50%, -150%) rotateY(180deg) scale(1.8); }
            100% { transform: translate(-50%, -50%) rotateY(360deg) scale(1); }
        }
        .animate-knight-special { animation: knight-flip 1s cubic-bezier(0.34, 1.56, 0.64, 1); }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';

interface Dice3DProps {
  value: number;
  isRolling: boolean;
  onRoll: (landingPos: { x: number; y: number }) => void;
  onDragEnd: (finalPos: { x: number; y: number }) => void;
  currentPos: { x: number; y: number };
}

export const Dice3D: React.FC<Dice3DProps> = ({ value, isRolling, onRoll, onDragEnd, currentPos }) => {
  const [pos, setPos] = useState(currentPos);
  const [isDragging, setIsDragging] = useState(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const elementPosStart = useRef({ x: 0, y: 0 });

  useEffect(() => {
    if (!isRolling && !isDragging) {
      setPos(currentPos);
    }
  }, [currentPos, isRolling, isDragging]);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (isRolling) return;
    setIsDragging(true);
    dragStart.current = { x: e.clientX, y: e.clientY };
    elementPosStart.current = { x: pos.x, y: pos.y };
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;
      const dx = e.clientX - dragStart.current.x;
      const dy = e.clientY - dragStart.current.y;
      setPos({
        x: elementPosStart.current.x + dx,
        y: elementPosStart.current.y + dy
      });
    };

    const handleMouseUp = () => {
      if (isDragging) {
        setIsDragging(false);
        onDragEnd(pos);
      }
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, pos, onDragEnd]);

  const getRotation = (v: number) => {
    switch (v) {
      case 1: return 'rotateX(0deg) rotateY(0deg)';
      case 2: return 'rotateY(-90deg)';
      case 3: return 'rotateY(90deg)';
      case 4: return 'rotateY(180deg)';
      case 5: return 'rotateX(-90deg)';
      case 6: return 'rotateX(90deg)';
      default: return 'rotateX(0deg)';
    }
  };

  const rollingRotation = isRolling 
    ? `rotateX(${Math.random() * 1080 + 360}deg) rotateY(${Math.random() * 1080 + 360}deg) scale(1.4)`
    : getRotation(value);

  const triggerRoll = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (isRolling) return;
    const landingX = Math.max(100, Math.min(window.innerWidth - 100, pos.x + (Math.random() - 0.5) * 150));
    const landingY = Math.max(100, Math.min(window.innerHeight - 100, pos.y + (Math.random() - 0.5) * 150));
    onRoll({ x: landingX, y: landingY });
  };

  return (
    <div 
      className={`fixed z-[60] transition-all ${isRolling ? 'duration-[1200ms]' : 'duration-75'} select-none cursor-grab active:cursor-grabbing`}
      style={{ 
        left: `${pos.x}px`, 
        top: `${pos.y}px`,
        transform: `translate(-50%, ${isDragging ? '-80px' : (isRolling ? '-150px' : '-50%')}) scale(${isDragging ? 1.2 : 1})`
      }}
      onMouseDown={handleMouseDown}
      onDoubleClick={triggerRoll}
    >
      <div className="dice-container">
        <div className="dice" style={{ transform: rollingRotation }}>
          <div className="dice-face front"><div className="dot"></div></div>
          <div className="dice-face back">
             <div className="dot" style={{ top: '15px', left: '15px' }}></div>
             <div className="dot" style={{ top: '15px', left: '51px' }}></div>
             <div className="dot" style={{ top: '51px', left: '15px' }}></div>
             <div className="dot" style={{ top: '51px', left: '51px' }}></div>
          </div>
          <div className="dice-face right">
             <div className="dot" style={{ top: '15px', left: '15px' }}></div>
             <div className="dot" style={{ top: '33px', left: '33px' }}></div>
             <div className="dot" style={{ top: '51px', left: '51px' }}></div>
          </div>
          <div className="dice-face left">
             <div className="dot" style={{ top: '15px', left: '15px' }}></div>
             <div className="dot" style={{ top: '51px', left: '51px' }}></div>
          </div>
          <div className="dice-face top">
             <div className="dot" style={{ top: '15px', left: '15px' }}></div>
             <div className="dot" style={{ top: '15px', left: '51px' }}></div>
             <div className="dot" style={{ top: '33px', left: '33px' }}></div>
             <div className="dot" style={{ top: '51px', left: '15px' }}></div>
             <div className="dot" style={{ top: '51px', left: '51px' }}></div>
          </div>
          <div className="dice-face bottom">
             <div className="dot" style={{ top: '15px', left: '15px' }}></div>
             <div className="dot" style={{ top: '15px', left: '51px' }}></div>
             <div className="dot" style={{ top: '33px', left: '15px' }}></div>
             <div className="dot" style={{ top: '33px', left: '51px' }}></div>
             <div className="dot" style={{ top: '51px', left: '15px' }}></div>
             <div className="dot" style={{ top: '51px', left: '51px' }}></div>
          </div>
        </div>
      </div>
      <div className={`mt-20 w-16 h-3 bg-black/10 dark:bg-white/10 blur-lg rounded-full mx-auto transition-all ${isDragging ? 'scale-[2.5] opacity-5' : 'scale-100 opacity-40'}`}></div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';

interface AlchemyJarProps {
  count: number;
  max: number;
  isExploding: boolean;
  onExplode: () => void;
}

export const AlchemyJar: React.FC<AlchemyJarProps> = ({ count, max, isExploding, onExplode }) => {
  const percent = Math.min(100, (count / max) * 100);
  const isFull = count >= max;
  const [holdProgress, setHoldProgress] = useState(0);
  const holdInterval = useRef<number | null>(null);

  const startHold = () => {
    if (!isFull || isExploding) return;
    holdInterval.current = window.setInterval(() => {
      setHoldProgress(prev => {
        if (prev >= 100) {
          if (holdInterval.current) clearInterval(holdInterval.current);
          onExplode();
          return 0;
        }
        return prev + 3;
      });
    }, 30);
  };

  const endHold = () => {
    if (holdInterval.current) {
      clearInterval(holdInterval.current);
      holdInterval.current = null;
    }
    setHoldProgress(0);
  };

  return (
    <div className="flex flex-col items-center gap-10">
      <div className={`relative w-36 h-64 bg-white/20 dark:bg-black/40 border-[10px] border-white/90 dark:border-white/10 rounded-b-[70px] rounded-t-[20px] overflow-hidden backdrop-blur-3xl shadow-3xl transition-all duration-700 ${isExploding ? 'scale-150 blur-3xl opacity-0' : 'scale-100'}`}>
        <div 
          className="absolute bottom-0 left-0 w-full bg-gradient-to-t from-blue-600 via-indigo-400 to-cyan-300 transition-all duration-1000 ease-out"
          style={{ height: `${percent}%` }}
        >
          <div className="absolute -top-3 left-0 w-full h-6 bg-white/60 blur-lg animate-pulse"></div>
          <div className="absolute inset-0 overflow-hidden">
             {[...Array(12)].map((_, i) => (
               <div 
                 key={i} 
                 className="bubble absolute bottom-0 bg-white/30 rounded-full animate-bubble-rise"
                 style={{
                   width: `${Math.random() * 15 + 5}px`,
                   height: `${Math.random() * 15 + 5}px`,
                   left: `${Math.random() * 95}%`,
                   animationDelay: `${Math.random() * 4}s`,
                   animationDuration: `${Math.random() * 2.5 + 2}s`
                 }}
               />
             ))}
          </div>
        </div>
        <div className="absolute top-10 left-8 w-4 h-36 bg-white/15 rounded-full blur-[3px]"></div>
        <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
          <span className="text-2xl font-black text-white drop-shadow-2xl">{Math.floor(percent)}%</span>
        </div>
      </div>

      <div className="relative w-full px-4">
        {isFull && holdProgress > 0 && (
          <div className="absolute -top-14 left-0 w-full h-3 bg-gray-200/50 dark:bg-gray-800/50 rounded-full overflow-hidden">
            <div className="h-full bg-indigo-500 transition-all shadow-[0_0_15px_rgba(99,102,241,0.6)]" style={{ width: `${holdProgress}%` }}></div>
          </div>
        )}
        <button
          onMouseDown={startHold}
          onMouseUp={endHold}
          onMouseLeave={endHold}
          onTouchStart={startHold}
          onTouchEnd={endHold}
          disabled={!isFull || isExploding}
          className={`w-full py-5 rounded-[28px] text-[11px] font-black uppercase tracking-[0.4em] transition-all transform select-none shadow-2xl
            ${isFull 
              ? 'bg-gradient-to-br from-indigo-500 to-blue-700 text-white cursor-pointer hover:scale-110 active:scale-95' 
              : 'bg-[#e0e0e0] dark:bg-[#333] text-gray-400 cursor-not-allowed opacity-40'
            }`}
        >
          {isFull ? 'Release Mana' : 'Gathering...'}
        </button>
      </div>

      <style>{`
        @keyframes bubble-rise {
          0% { transform: translateY(0) scale(0.4); opacity: 0; }
          40% { opacity: 0.9; }
          100% { transform: translateY(-220px) scale(1.6); opacity: 0; }
        }
        .animate-bubble-rise {
          animation: bubble-rise linear infinite;
        }
      `}</style>
    </div>
  );
};

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { Task, BoardSpace } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 15;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 250;
const ZOMBIE_COUNT = 7;
const BOMB_COUNT = 7;
const MAX_ZOMBIE_HEALTH = 3;
const TOTAL_TILES = 60;

const ANIMAL_EMOJIS = ['🐶', '🐱', '🐭', '🐹', '🐰', '🦊', '🐻', '🐼', '🐨', '🐯', '🦁', '🐮', '🐷', '🐸', '🐵'];
const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];

interface CompletedTask extends Task {
  completedAt: string;
}

interface ZombieData {
  id: number;
  pos: number;
  health: number;
  isEliminating: boolean;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Reach 100 Items', completed: false },
    { id: '2', text: 'Purge all Zombies', completed: false },
    { id: '3', text: 'Roll a 6', completed: false },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePosition, setDicePosition] = useState({ x: window.innerWidth / 2, y: window.innerHeight - 150 });
  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [blooms, setBlooms] = useState<Record<number, string>>({});
  const [zombies, setZombies] = useState<ZombieData[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const TILE_SIZE = 54; 
  const TILE_GAP = 0; // Adjacent as per Sudoku request
  const SAFE_MARGIN = 50;

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    // Perimeter formula: 2*(w + h) - 4 = 60 => w + h = 32
    const usableWidth = window.innerWidth - (SAFE_MARGIN * 2);
    const usableHeight = window.innerHeight - (SAFE_MARGIN * 2);
    const ratio = usableWidth / usableHeight;

    let h = Math.round(32 / (1 + ratio));
    let w = 32 - h;

    // Ensure it's exactly 60
    if (2 * (w + h) - 4 !== 60) {
        w = 18; h = 14; // Default safe 60-tile rectangle
    }

    const startX = (window.innerWidth - (w * TILE_SIZE)) / 2;
    const startY = (window.innerHeight - (h * TILE_SIZE)) / 2;

    // Top
    for (let i = 0; i < w; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * TILE_SIZE, y: startY });
    // Right
    for (let i = 1; i < h; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + (w-1) * TILE_SIZE, y: startY + i * TILE_SIZE });
    // Bottom
    for (let i = w - 2; i >= 0; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * TILE_SIZE, y: startY + (h-1) * TILE_SIZE });
    // Left
    for (let i = h - 2; i >= 1; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * TILE_SIZE });

    return spaces;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const getRandomUnique = (count: number, exclude: number[]) => {
      const res: number[] = [];
      while(res.length < count) {
        const r = Math.floor(Math.random() * TOTAL_TILES);
        if (!exclude.includes(r) && !res.includes(r)) res.push(r);
      }
      return res;
    };
    const zPos = getRandomUnique(ZOMBIE_COUNT, [0]);
    setZombies(zPos.map((pos, id) => ({ id, pos, health: MAX_ZOMBIE_HEALTH, isEliminating: false })));
    setBombIndices(getRandomUnique(BOMB_COUNT, [0, ...zPos]));
  }, [boardSpaces.length]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const processMovement = useCallback((diceVal: number) => {
    let steps = 0;
    let iterativePos = currentPos;

    const interval = setInterval(() => {
      steps++;
      iterativePos = (iterativePos + 1) % TOTAL_TILES;
      setCurrentPos(iterativePos);
      triggerBloom(iterativePos);

      // Check for Bomb collision while passing
      if (bombIndices.includes(iterativePos)) {
        setZombies(prev => prev.map(z => {
          const dist = Math.min(Math.abs(z.pos - iterativePos), TOTAL_TILES - Math.abs(z.pos - iterativePos));
          if (dist <= 3 && !z.isEliminating) {
            const nextHealth = z.health - 1;
            return { ...z, health: nextHealth, isEliminating: nextHealth <= 0 };
          }
          return z;
        }));
        setIsShaking(true);
        setTimeout(() => setIsShaking(false), 200);
      }

      if (steps >= diceVal) {
        clearInterval(interval);
        setIsMoving(false);
        // Move zombies 2 steps chasing player
        setZombies(prev => prev.map(z => {
            if (z.isEliminating) return z;
            const diffForward = (iterativePos - z.pos + TOTAL_TILES) % TOTAL_TILES;
            const direction = diffForward < 30 ? 1 : -1;
            return { ...z, pos: (z.pos + (direction * 2) + TOTAL_TILES) % TOTAL_TILES };
        }));
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices]);

  useEffect(() => {
    const contact = zombies.find(z => z.pos === currentPos && !z.isEliminating);
    if (contact && !isMoving) {
        setIsShaking(true);
        setJarCount(0);
        setCurrentPos(0);
        setRollBank(r => Math.max(0, r - 3));
        setTimeout(() => setIsShaking(false), 500);
    }
  }, [zombies, currentPos, isMoving]);

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);
    setDicePosition(landing);
    const val = Math.floor(Math.random() * 6) + 1;
    if (val === 6) {
        const t = tasks.find(x => x.text === 'Roll a 6');
        if (t) handleTaskComplete(t);
    }
    setTimeout(() => {
      setIsRolling(false);
      setDiceValue(val);
      setIsMoving(true);
      processMovement(val);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 5);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setZombies(prev => prev.map(z => ({ ...z, health: 0, isEliminating: true })));
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 20);
    }, 1500);
  };

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-500 overflow-hidden ${isExploding ? 'bg-red-500/10' : ''}`}>

      {/* 60 Tile Sudoku-style Map */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isStart = s.id === 0;
          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-colors duration-300
                ${isStart ? 'bg-indigo-50 dark:bg-indigo-950/30' : ''}
              `}
              style={{ left: s.x, top: s.y, width: TILE_SIZE, height: TILE_SIZE }}
            >
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {isBomb && <span className="text-xl">💣</span>}
              {bloom && <span className="text-2xl bloom">{bloom}</span>}
              {isStart && !bloom && <span className="text-[10px] font-black opacity-30">START</span>}
            </div>
          );
        })}

        {/* Zombies */}
        {zombies.map(z => {
          const coord = boardSpaces[z.pos];
          if (!coord || z.isEliminating) return null;
          return (
            <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ left: coord.x + TILE_SIZE/2, top: coord.y + TILE_SIZE/2, transform: 'translate(-50%, -50%)' }}>
               <div className="flex flex-col items-center">
                  <div className="w-8 h-1 bg-gray-200 dark:bg-gray-800 rounded-full mb-1 overflow-hidden">
                    <div className="bg-red-500 h-full" style={{ width: `${(z.health/MAX_ZOMBIE_HEALTH)*100}%` }} />
                  </div>
                  <span className="text-4xl drop-shadow-md">🧟</span>
               </div>
            </div>
          );
        })}

        {/* Player Piece (150% size) */}
        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto ${isMoving ? 'scale-110' : 'scale-100'}`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + TILE_SIZE/2, 
            top: (boardSpaces[currentPos]?.y || 0) + TILE_SIZE/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: TILE_SIZE * 1.5
          }}
        >
          <span className="drop-shadow-xl select-none">{ANIMAL_EMOJIS[animalIndex]}</span>
        </div>
      </div>

      {/* Center Panels */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-50 flex items-center gap-10 scale-90 lg:scale-100">
        <div className="glass-panel rounded-[16px] p-8 w-72 h-[480px] flex flex-col">
          <div className="flex justify-between items-start mb-8">
            <div>
              <span className="text-[10px] font-bold opacity-30 uppercase tracking-widest block">Bank</span>
              <span className="text-3xl font-black">{rollBank}</span>
            </div>
            <button onClick={() => setDarkMode(!darkMode)} className="p-2 hover:bg-black/5 dark:hover:bg-white/5 rounded-lg transition-colors">
              {darkMode ? '☀️' : '🌙'}
            </button>
          </div>

          <div className="flex-grow overflow-y-auto space-y-2 pr-2 custom-scrollbar">
            {!showHistory ? (
              tasks.map(t => (
                <div key={t.id} onClick={() => handleTaskComplete(t)} className="p-4 bg-white/50 dark:bg-white/5 border border-black/5 dark:border-white/5 rounded-lg cursor-pointer hover:border-black/20 dark:hover:border-white/20 transition-all flex items-center gap-3">
                  <div className="w-4 h-4 rounded border-2 border-black/10" />
                  <span className="text-sm font-medium">{t.text}</span>
                </div>
              ))
            ) : (
              history.map(h => (
                <div key={h.id} className="p-3 border-l-2 border-black/10 dark:border-white/10 opacity-60">
                  <span className="text-xs font-bold block line-through">{h.text}</span>
                  <span className="text-[9px] opacity-40 uppercase">{h.completedAt}</span>
                </div>
              ))
            )}
          </div>

          <div className="mt-6 flex gap-2">
            <button onClick={() => setShowHistory(!showHistory)} className="flex-1 py-3 text-[10px] font-bold uppercase tracking-widest border border-black/10 dark:border-white/10 rounded-lg">
              {showHistory ? 'Tasks' : 'History'}
            </button>
            <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([...tasks, { id: Date.now().toString(), text: newTask, completed: false }]); setNewTask(''); }} className="flex-[2] relative">
              <input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full bg-black/5 dark:bg-white/5 rounded-lg px-3 py-3 text-xs outline-none" placeholder="Add task..." />
            </form>
          </div>
        </div>

        <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} />
      </div>

      <Dice3D value={diceValue} isRolling={isRolling} currentPos={dicePosition} onRoll={handleRoll} onDragEnd={setDicePosition} />

    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';

interface Dice3DProps {
  value: number;
  isRolling: boolean;
  onRoll: (landingPos: { x: number; y: number }) => void;
  onDragEnd: (finalPos: { x: number; y: number }) => void;
  currentPos: { x: number; y: number };
}

export const Dice3D: React.FC<Dice3DProps> = ({ value, isRolling, onRoll, onDragEnd, currentPos }) => {
  const [pos, setPos] = useState(currentPos);
  const [isDragging, setIsDragging] = useState(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const elementPosStart = useRef({ x: 0, y: 0 });

  useEffect(() => {
    if (!isRolling && !isDragging) {
      setPos(currentPos);
    }
  }, [currentPos, isRolling, isDragging]);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (isRolling) return;
    setIsDragging(true);
    dragStart.current = { x: e.clientX, y: e.clientY };
    elementPosStart.current = { x: pos.x, y: pos.y };
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;
      const dx = e.clientX - dragStart.current.x;
      const dy = e.clientY - dragStart.current.y;
      setPos({
        x: elementPosStart.current.x + dx,
        y: elementPosStart.current.y + dy
      });
    };

    const handleMouseUp = () => {
      if (isDragging) {
        setIsDragging(false);
        onDragEnd(pos);
      }
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, pos, onDragEnd]);

  const getRotation = (v: number) => {
    switch (v) {
      case 1: return 'rotateX(0deg) rotateY(0deg)';
      case 2: return 'rotateY(-90deg)';
      case 3: return 'rotateY(90deg)';
      case 4: return 'rotateY(180deg)';
      case 5: return 'rotateX(-90deg)';
      case 6: return 'rotateX(90deg)';
      default: return 'rotateX(0deg)';
    }
  };

  const rollingRotation = isRolling 
    ? `rotateX(${Math.random() * 720 + 360}deg) rotateY(${Math.random() * 720 + 360}deg)`
    : getRotation(value);

  const triggerRoll = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (isRolling) return;
    // Roll lands near current position for realism
    const landingX = Math.max(100, Math.min(window.innerWidth - 100, pos.x + (Math.random() - 0.5) * 100));
    const landingY = Math.max(100, Math.min(window.innerHeight - 100, pos.y + (Math.random() - 0.5) * 100));
    onRoll({ x: landingX, y: landingY });
  };

  return (
    <div 
      className={`fixed z-[60] transition-all ${isRolling ? 'duration-[1200ms]' : 'duration-75'} select-none cursor-grab active:cursor-grabbing`}
      style={{ 
        left: `${pos.x}px`, 
        top: `${pos.y}px`,
        transform: `translate(-50%, -50%) scale(${isDragging ? 1.1 : (isRolling ? 1.3 : 1)})`
      }}
      onMouseDown={handleMouseDown}
      onDoubleClick={triggerRoll}
    >
      <div className="dice-container">
        <div className="dice" style={{ transform: rollingRotation }}>
          <div className="dice-face front"><div className="dot"></div></div>
          <div className="dice-face back">
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '15%', left: '60%' }}></div>
             <div className="dot" style={{ top: '60%', left: '15%' }}></div>
             <div className="dot" style={{ top: '60%', left: '60%' }}></div>
          </div>
          <div className="dice-face right">
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '40%', left: '40%' }}></div>
             <div className="dot" style={{ top: '65%', left: '65%' }}></div>
          </div>
          <div className="dice-face left">
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '65%', left: '65%' }}></div>
          </div>
          <div className="dice-face top">
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '15%', left: '60%' }}></div>
             <div className="dot" style={{ top: '40%', left: '40%' }}></div>
             <div className="dot" style={{ top: '65%', left: '15%' }}></div>
             <div className="dot" style={{ top: '65%', left: '65%' }}></div>
          </div>
          <div className="dice-face bottom">
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '15%', left: '60%' }}></div>
             <div className="dot" style={{ top: '40%', left: '15%' }}></div>
             <div className="dot" style={{ top: '40%', left: '60%' }}></div>
             <div className="dot" style={{ top: '65%', left: '15%' }}></div>
             <div className="dot" style={{ top: '65%', left: '65%' }}></div>
          </div>
        </div>
      </div>
      {!isRolling && (
          <div className="absolute -bottom-6 left-1/2 -translate-x-1/2 text-[9px] font-bold opacity-30 uppercase tracking-tighter whitespace-nowrap">Double Click to Roll</div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';

interface AlchemyJarProps {
  count: number;
  max: number;
  isExploding: boolean;
  onExplode: () => void;
}

export const AlchemyJar: React.FC<AlchemyJarProps> = ({ count, max, isExploding, onExplode }) => {
  const percent = Math.min(100, (count / max) * 100);
  const isFull = count >= max;
  const [holdProgress, setHoldProgress] = useState(0);
  const holdInterval = useRef<number | null>(null);

  const startHold = () => {
    if (!isFull || isExploding) return;
    holdInterval.current = window.setInterval(() => {
      setHoldProgress(prev => {
        if (prev >= 100) {
          if (holdInterval.current) clearInterval(holdInterval.current);
          onExplode();
          return 0;
        }
        return prev + 1; // Approx 3 seconds (100 / 33ms)
      });
    }, 30);
  };

  const endHold = () => {
    if (holdInterval.current) {
      clearInterval(holdInterval.current);
      holdInterval.current = null;
    }
    setHoldProgress(0);
  };

  return (
    <div className="flex flex-col items-center gap-6">
      <div className={`relative w-28 h-48 bg-gray-50/50 dark:bg-black/20 border-8 border-gray-100 dark:border-white/5 rounded-b-[40px] rounded-t-[10px] overflow-hidden backdrop-blur-xl transition-all duration-700 ${isExploding ? 'scale-150 blur-3xl opacity-0' : 'scale-100'}`}>
        <div 
          className="absolute bottom-0 left-0 w-full bg-indigo-500/80 transition-all duration-1000 ease-out"
          style={{ height: `${percent}%` }}
        >
          {/* Bubbles */}
          <div className="absolute inset-0 overflow-hidden">
             {[...Array(6)].map((_, i) => (
               <div 
                 key={i} 
                 className="absolute bottom-0 bg-white/20 rounded-full animate-bubble"
                 style={{
                   width: Math.random() * 8 + 4,
                   height: Math.random() * 8 + 4,
                   left: `${Math.random() * 100}%`,
                   animationDuration: `${Math.random() * 2 + 1}s`,
                   animationDelay: `${Math.random() * 2}s`
                 }}
               />
             ))}
          </div>
        </div>
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
          <span className="text-xl font-black text-indigo-900/50 dark:text-white/50">{Math.floor(percent)}%</span>
        </div>
      </div>

      <div className="w-full relative">
        {holdProgress > 0 && (
          <div className="absolute -top-4 left-0 w-full h-1 bg-gray-100 dark:bg-white/5 rounded-full overflow-hidden">
             <div className="h-full bg-indigo-500" style={{ width: `${holdProgress}%` }} />
          </div>
        )}
        <button
          onMouseDown={startHold}
          onMouseUp={endHold}
          onMouseLeave={endHold}
          onTouchStart={startHold}
          onTouchEnd={endHold}
          disabled={!isFull || isExploding}
          className={`w-full py-3 rounded-lg text-[10px] font-black uppercase tracking-[0.2em] transition-all
            ${isFull 
              ? 'bg-indigo-600 text-white shadow-lg cursor-pointer hover:scale-105 active:scale-95' 
              : 'bg-black/5 dark:bg-white/5 text-gray-400 cursor-not-allowed'
            }`}
        >
          {isFull ? (holdProgress > 0 ? 'Charging...' : 'Hold 3s to Use') : 'Collecting...'}
        </button>
      </div>

      <style>{`
        @keyframes bubble {
          0% { transform: translateY(0) scale(0.5); opacity: 0; }
          50% { opacity: 0.5; }
          100% { transform: translateY(-100px) scale(1.5); opacity: 0; }
        }
        .animate-bubble { animation: bubble linear infinite; }
      `}</style>
    </div>
  );
};

export interface Task {
  id: string;
  text: string;
  completed: boolean;
}

export interface BoardSpace {
  id: number;
  type: 'normal' | 'special';
  x: number;
  y: number;
}

export interface BigZombie {
  pos: number;
  health: number;
  isActive: boolean;
}

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 15;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 250;
const ZOMBIE_INDICATOR_COUNT = 7;
const BOMB_COUNT = 7;
const MAX_ZOMBIE_HEALTH = 3;
const TOTAL_TILES = 60;
const SPAWN_BEHIND_OFFSET = 6;

const ANIMAL_EMOJIS = ['🐶', '🐱', '🐭', '🐹', '🐰', '🦊', '🐻', '🐼', '🐨', '🐯', '🦁', '🐮', '🐷', '🐸', '🐵'];
const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Reach 100 Items', completed: false },
    { id: '2', text: 'Defeat a Stalker', completed: false },
    { id: '3', text: 'Roll a 6', completed: false },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePosition, setDicePosition] = useState({ x: window.innerWidth / 2, y: window.innerHeight - 150 });
  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  // New State for Mechanics
  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombie, setActiveZombie] = useState<BigZombie>({ pos: -1, health: 3, isActive: false });
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const TILE_SIZE = 54; 
  const SAFE_MARGIN = 50;

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const usableWidth = window.innerWidth - (SAFE_MARGIN * 2);
    const usableHeight = window.innerHeight - (SAFE_MARGIN * 2);
    const ratio = usableWidth / usableHeight;

    let h = Math.round(32 / (1 + ratio));
    let w = 32 - h;

    if (2 * (w + h) - 4 !== 60) { w = 18; h = 14; }

    const startX = (window.innerWidth - (w * TILE_SIZE)) / 2;
    const startY = (window.innerHeight - (h * TILE_SIZE)) / 2;

    for (let i = 0; i < w; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * TILE_SIZE, y: startY });
    for (let i = 1; i < h; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + (w-1) * TILE_SIZE, y: startY + i * TILE_SIZE });
    for (let i = w - 2; i >= 0; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * TILE_SIZE, y: startY + (h-1) * TILE_SIZE });
    for (let i = h - 2; i >= 1; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * TILE_SIZE });

    return spaces;
  }, []);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, [0]);
    setZombieIndicators(zInd);
    setBombIndices(getRandomUnique(BOMB_COUNT, [0, ...zInd]));
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: 'bomb' | 'zombie') => {
    const newList = list.filter(p => p !== pos);
    const [newPos] = getRandomUnique(1, [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, activeZombie.pos]);
    if (type === 'bomb') setBombIndices([...newList, newPos]);
    else setZombieIndicators([...newList, newPos]);
  };

  const processMovement = useCallback((diceVal: number) => {
    let steps = 0;
    let iterativePos = currentPos;

    const interval = setInterval(() => {
      steps++;
      iterativePos = (iterativePos + 1) % TOTAL_TILES;
      setCurrentPos(iterativePos);
      triggerBloom(iterativePos);

      // Bomb trigger during passing
      if (bombIndices.includes(iterativePos) && activeZombie.isActive) {
        setBombAnimation({ active: true, pos: iterativePos });
        setActiveZombie(prev => {
          const nextHealth = prev.health - 1;
          if (nextHealth <= 0) {
            const task = tasks.find(t => t.text === 'Defeat a Stalker');
            if (task) handleTaskComplete(task);
            return { ...prev, isActive: false, health: 0 };
          }
          return { ...prev, health: nextHealth };
        });
        setIsShaking(true);
        setTimeout(() => {
          setIsShaking(false);
          setBombAnimation({ active: false, pos: -1 });
        }, 500);
        relocateItem(bombIndices, iterativePos, 'bomb');
      }

      if (steps >= diceVal) {
        clearInterval(interval);
        setIsMoving(false);

        // Check for landing on small zombie indicator
        if (zombieIndicators.includes(iterativePos) && !activeZombie.isActive) {
          const spawnPos = (iterativePos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombie({ pos: spawnPos, health: MAX_ZOMBIE_HEALTH, isActive: true });
          relocateItem(zombieIndicators, iterativePos, 'zombie');
        }

        // Move active zombie 2 steps following player
        if (activeZombie.isActive) {
          setActiveZombie(prev => {
            if (!prev.isActive) return prev;
            // Chasing follows the path (always clockwise)
            const nextPos = (prev.pos + 2) % TOTAL_TILES;

            // Check if caught player after zombie move
            if (nextPos === iterativePos) {
              handleCaught();
              return { ...prev, isActive: false, pos: -1 };
            }
            return { ...prev, pos: nextPos };
          });
        }
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombie, tasks]);

  const handleCaught = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombie({ pos: -1, health: 3, isActive: false });
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);
    setDicePosition(landing);
    const val = Math.floor(Math.random() * 6) + 1;
    if (val === 6) {
        const t = tasks.find(x => x.text === 'Roll a 6');
        if (t) handleTaskComplete(t);
    }
    setTimeout(() => {
      setIsRolling(false);
      setDiceValue(val);
      setIsMoving(true);
      processMovement(val);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 5);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombie(prev => ({ ...prev, isActive: false, health: 0 }));
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 20);
    }, 1500);
  };

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-500 overflow-hidden ${isExploding ? 'bg-red-500/10' : ''}`}>

      {/* 60 Tile Map */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombieIndicator = zombieIndicators.includes(s.id);
          const isStart = s.id === 0;
          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-colors duration-300
                ${isStart ? 'bg-indigo-50 dark:bg-indigo-950/30' : ''}
              `}
              style={{ left: s.x, top: s.y, width: TILE_SIZE, height: TILE_SIZE }}
            >
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {isBomb && <span className="text-xl">💣</span>}
              {isZombieIndicator && !activeZombie.isActive && <span className="text-sm opacity-50 grayscale">🧟</span>}
              {bloom && <span className="text-2xl bloom">{bloom}</span>}
              {isStart && !bloom && <span className="text-[10px] font-black opacity-30">START</span>}
            </div>
          );
        })}

        {/* Big Zombie (Stalker) */}
        {activeZombie.isActive && (
          <div className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[activeZombie.pos]?.x + TILE_SIZE/2, 
            top: boardSpaces[activeZombie.pos]?.y + TILE_SIZE/2, 
            transform: 'translate(-50%, -60%)' 
          }}>
             <div className="flex flex-col items-center">
                {/* Segmented Health Bar (3 hits) */}
                <div className="flex gap-0.5 mb-1">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1.5 rounded-sm border border-black/10 ${i < activeZombie.health ? 'bg-red-500' : 'bg-gray-200 dark:bg-gray-800 opacity-30'}`} />
                   ))}
                </div>
                <span className="drop-shadow-lg" style={{ fontSize: TILE_SIZE * 1.3 }}>🧟</span>
             </div>
          </div>
        )}

        {/* Player Piece (150% size) */}
        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto ${isMoving ? 'scale-110' : 'scale-100'}`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + TILE_SIZE/2, 
            top: (boardSpaces[currentPos]?.y || 0) + TILE_SIZE/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: TILE_SIZE * 1.5
          }}
        >
          <span className="drop-shadow-xl select-none">{ANIMAL_EMOJIS[animalIndex]}</span>
        </div>

        {/* Bomb Strike Animation */}
        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[activeZombie.pos]?.x + TILE_SIZE/2, 
            top: boardSpaces[activeZombie.pos]?.y + TILE_SIZE/2,
            transform: 'translate(-50%, -150%)'
          }}>
            <span className="text-4xl">💥</span>
          </div>
        )}
      </div>

      {/* Center Panels */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-50 flex items-center gap-10 scale-90 lg:scale-100">
        <div className="glass-panel rounded-[12px] p-8 w-72 h-[480px] flex flex-col">
          <div className="flex justify-between items-start mb-8">
            <div>
              <span className="text-[10px] font-bold opacity-30 uppercase tracking-widest block">Bank</span>
              <span className="text-3xl font-black">{rollBank}</span>
            </div>
            <button onClick={() => setDarkMode(!darkMode)} className="p-2 hover:bg-black/5 dark:hover:bg-white/5 rounded-lg transition-colors">
              {darkMode ? '☀️' : '🌙'}
            </button>
          </div>

          <div className="flex-grow overflow-y-auto space-y-2 pr-2 custom-scrollbar">
            {!showHistory ? (
              tasks.map(t => (
                <div key={t.id} onClick={() => handleTaskComplete(t)} className="p-4 bg-white/50 dark:bg-white/5 border border-black/5 dark:border-white/5 rounded-lg cursor-pointer hover:border-black/20 dark:hover:border-white/20 transition-all flex items-center gap-3">
                  <div className="w-4 h-4 rounded-sm border-2 border-black/10" />
                  <span className="text-sm font-medium">{t.text}</span>
                </div>
              ))
            ) : (
              history.map(h => (
                <div key={h.id} className="p-3 border-l-2 border-black/10 dark:border-white/10 opacity-60">
                  <span className="text-xs font-bold block line-through">{h.text}</span>
                  <span className="text-[9px] opacity-40 uppercase">{h.completedAt}</span>
                </div>
              ))
            )}
          </div>

          <div className="mt-6 flex gap-2">
            <button onClick={() => setShowHistory(!showHistory)} className="flex-1 py-3 text-[10px] font-bold uppercase tracking-widest border border-black/10 dark:border-white/10 rounded-lg">
              {showHistory ? 'Tasks' : 'Logs'}
            </button>
            <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([...tasks, { id: Date.now().toString(), text: newTask, completed: false }]); setNewTask(''); }} className="flex-[2] relative">
              <input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full bg-black/5 dark:bg-white/5 rounded-lg px-3 py-3 text-xs outline-none" placeholder="Add task..." />
            </form>
          </div>
        </div>

        <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} />
      </div>

      <Dice3D value={diceValue} isRolling={isRolling} currentPos={dicePosition} onRoll={handleRoll} onDragEnd={setDicePosition} />

      <style>{`
        @keyframes bomb-drop {
          0% { transform: translate(-50%, -300%) scale(2); opacity: 0; }
          70% { transform: translate(-50%, -60%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(3); opacity: 0; }
        }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
      `}</style>

    </div>
  );
};

export default App;

