  '🦖', '🐉', '🐲', '🐟', '🐙', '🦈', '🐳', '🦄', '🦁', '🐯', 
  '🐼', '🦊', '🐸', '🐨', '🐮', '🦒', '🦓', '🦘', '🦙', '🦥'
];
