    const [newPos] = getRandomUnique(1, [currentPos, 0, ...newList, activeZombie.pos]);
    if (type === 'bomb') setBombIndices([...newList, newPos]);
    else setZombieIndicators([...newList, newPos]);
  };

  const processMovement = useCallback((diceVal: number) => {
    let stepsDone = 0;

    // Capture current values in refs or closure to ensure no off-by-one errors
    let tempPos = currentPos;

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      // Bomb trigger during passing
      if (bombIndices.includes(tempPos) && activeZombie.isActive) {
        setBombAnimation({ active: true, pos: tempPos });
        setActiveZombie(prev => {
          const nextHealth = prev.health - 1;
          if (nextHealth <= 0) {
            const task = tasks.find(t => t.text === 'Defeat the Stalker');
            if (task) handleTaskComplete(task);
            return { ...prev, isActive: false, health: 0 };
          }
          return { ...prev, health: nextHealth };
        });
        setIsShaking(true);
        setTimeout(() => {
          setIsShaking(false);
          setBombAnimation({ active: false, pos: -1 });
        }, 500);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceVal) {
        clearInterval(interval);
        setIsMoving(false);

        // Landing Check
        const finalPos = tempPos;

        // Check if landed on a corner (special)
        const isCorner = [0, TOTAL_TILES/4, TOTAL_TILES/2, (3*TOTAL_TILES)/4].some(c => Math.abs(finalPos - c) < 2);
        if (isCorner) {
           const t = tasks.find(x => x.text === 'Land on a Corner');
           if (t) handleTaskComplete(t);
        }

        // Spawn Big Zombie if landing on indicator
        if (zombieIndicators.includes(finalPos) && !activeZombie.isActive) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombie({ pos: spawnPos, health: MAX_ZOMBIE_HEALTH, isActive: true });
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }

        // Move active zombie 2 steps
        if (activeZombie.isActive) {
          setActiveZombie(prev => {
            if (!prev.isActive) return prev;
            const nextZPos = (prev.pos + 2) % TOTAL_TILES;
            if (nextZPos === finalPos) {
              handleCaught();
              return { ...prev, isActive: false, pos: -1 };
            }
            return { ...prev, pos: nextZPos };
          });
        }
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombie, tasks]);

  const handleCaught = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombie({ pos: -1, health: 3, isActive: false });
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);
    setDicePosition(landing);
    const val = Math.floor(Math.random() * 6) + 1;
    if (val === 6) {
        const t = tasks.find(x => x.text === 'Roll a 6');
        if (t) handleTaskComplete(t);
    }
    setTimeout(() => {
      setIsRolling(false);
      setDiceValue(val);
      setIsMoving(true);
      processMovement(val);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 8);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombie(prev => ({ ...prev, isActive: false, health: 0 }));
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 25);
    }, 1500);
  };

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-500 overflow-hidden ${isExploding ? 'bg-red-500/10' : ''}`}>

      {/* 80 Tile Sudoku-style Map */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombieIndicator = zombieIndicators.includes(s.id);
          const isStart = s.id === 0;
          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-colors duration-300
                ${isStart ? 'bg-indigo-50/80 dark:bg-indigo-950/40' : ''}
              `}
              style={{ left: s.x, top: s.y, width: TILE_SIZE, height: TILE_SIZE }}
            >
              <span className="text-[8px] opacity-10 absolute top-0.5 left-0.5 font-bold">{s.id + 1}</span>
              {isBomb && <span className="text-xl">💣</span>}
              {isZombieIndicator && !activeZombie.isActive && <span className="text-sm opacity-30 grayscale">🧟</span>}
              {bloom && <span className="text-xl bloom">{bloom}</span>}
              {isStart && !bloom && <span className="text-[8px] font-black opacity-30">HOME</span>}
            </div>
          );
        })}

        {/* Big Zombie */}
        {activeZombie.isActive && boardSpaces[activeZombie.pos] && (
          <div className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[activeZombie.pos].x + TILE_SIZE/2, 
            top: boardSpaces[activeZombie.pos].y + TILE_SIZE/2, 
            transform: 'translate(-50%, -60%)' 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-sm border border-black/10 ${i < activeZombie.health ? 'bg-red-500 shadow-[0_0_5px_rgba(239,68,68,0.5)]' : 'bg-gray-200 dark:bg-gray-800 opacity-20'}`} />
                   ))}
                </div>
                <span className="drop-shadow-lg" style={{ fontSize: TILE_SIZE * 1.2 }}>🧟</span>
             </div>
          </div>
        )}

        {/* Player Piece */}
        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto ${isMoving ? 'scale-110 -translate-y-4' : 'scale-100'}`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + TILE_SIZE/2, 
            top: (boardSpaces[currentPos]?.y || 0) + TILE_SIZE/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: TILE_SIZE * 1.5
          }}
        >
          <span className="drop-shadow-xl select-none filter contrast-125">{ANIMAL_EMOJIS[animalIndex]}</span>
        </div>

        {/* Bomb Strike */}
        {bombAnimation.active && activeZombie.isActive && boardSpaces[activeZombie.pos] && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[activeZombie.pos].x + TILE_SIZE/2, 
            top: boardSpaces[activeZombie.pos].y + TILE_SIZE/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-5xl">💥</span>
          </div>
        )}
      </div>

      {/* Center Panels - Positioned to NEVER overlap board */}
      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-center gap-6 lg:gap-12 scale-90 lg:scale-100 bg-transparent">

          {/* Task Panel */}
          <div className="glass-panel rounded-[12px] p-6 w-64 h-[440px] flex flex-col shadow-2xl">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-widest block dark:text-white">Energy</span>
                <span className="text-3xl font-black tabular-nums dark:text-white">{rollBank}</span>
              </div>
              <button onClick={() => setDarkMode(!darkMode)} className="p-2 hover:bg-black/5 dark:hover:bg-white/5 rounded-lg transition-colors">
                {darkMode ? '☀️' : '🌙'}
              </button>
            </div>

            <div className="flex-grow overflow-y-auto space-y-2 pr-2 custom-scrollbar">
              {!showHistory ? (
                tasks.map(t => (
                  <div key={t.id} onClick={() => handleTaskComplete(t)} className="p-3 bg-white/40 dark:bg-white/5 border border-black/5 dark:border-white/10 rounded-lg cursor-pointer hover:border-black/20 dark:hover:border-white/30 transition-all flex items-center gap-3 group">
                    <div className="w-4 h-4 rounded-sm border-2 border-black/10 dark:border-white/20 group-hover:bg-indigo-500 group-hover:border-indigo-500 transition-colors" />
                    <span className="text-[13px] font-semibold dark:text-zinc-200">{t.text}</span>
                  </div>
                ))
              ) : (
                history.map(h => (
                  <div key={h.id} className="p-2.5 border-l-2 border-black/10 dark:border-white/10 opacity-60">
                    <span className="text-[11px] font-bold block line-through dark:text-white">{h.text}</span>
                    <span className="text-[8px] opacity-40 uppercase dark:text-white">{h.completedAt}</span>
                  </div>
                ))
              )}
            </div>

            <div className="mt-4 flex gap-2">
              <button onClick={() => setShowHistory(!showHistory)} className="flex-1 py-2.5 text-[9px] font-bold uppercase tracking-widest border border-black/10 dark:border-white/10 rounded-lg dark:text-white">
                {showHistory ? 'Tasks' : 'Logs'}
              </button>
              <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([...tasks, { id: Date.now().toString(), text: newTask, completed: false }]); setNewTask(''); }} className="flex-[2] relative">
                <input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full bg-black/5 dark:bg-white/5 rounded-lg px-3 py-2.5 text-xs outline-none dark:text-white focus:ring-1 ring-indigo-500/30" placeholder="+" />
              </form>
            </div>
          </div>

          {/* Alchemy Jar */}
          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} />
        </div>
      </div>

      <Dice3D value={diceValue} isRolling={isRolling} currentPos={dicePosition} onRoll={handleRoll} onDragEnd={setDicePosition} />

      <style>{`
        @keyframes bomb-drop {
          0% { transform: translate(-50%, -300%) scale(2); opacity: 0; }
          70% { transform: translate(-50%, -60%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(4); opacity: 0; }
        }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile {
          border: 1px solid rgba(0,0,0,0.06);
          background: rgba(255,255,255,0.9);
        }
        .dark .sudoku-tile {
          border: 1px solid rgba(255,255,255,0.04);
          background: rgba(25,25,25,0.9);
        }
      `}</style>

    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 25;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 300; 
const ZOMBIE_INDICATOR_COUNT = 7;
const BOMB_COUNT = 7;
const MAX_ZOMBIE_HEALTH = 3;
const TOTAL_TILES = 80;
const SPAWN_BEHIND_OFFSET = 6;

const ANIMAL_EMOJIS = [
  '🦖', '🐉', '🐲', '🐟', '🐙', '🦈', '🐳', '🐋', '🐬', '🐘', 
  '🦄', '🦁', '🐯', '🐼', '🦊', '🐸', '🐨', '🦒', '🦓', '🦘'
];
const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false },
    { id: '2', text: 'Tiêu diệt Zombie lớn', completed: false },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePosition, setDicePosition] = useState({ x: window.innerWidth / 2, y: window.innerHeight / 2 });
  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombie, setActiveZombie] = useState<BigZombie>({ pos: -1, health: 3, isActive: false });
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  // Tile size for 80 tiles should be smaller to fit common screens
  const TILE_SIZE = 46; 
  const SAFE_MARGIN = 20;

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const availableWidth = window.innerWidth - (SAFE_MARGIN * 2);
    const availableHeight = window.innerHeight - (SAFE_MARGIN * 2);

    // 2*(W + H) - 4 = 80 => W + H = 42
    // Try to maintain screen aspect ratio
    const screenRatio = availableWidth / availableHeight;
    let h = Math.round(42 / (1 + screenRatio));
    let w = 42 - h;

    // Safety check to ensure exactly 80 tiles
    if (2 * (w + h) - 4 !== 80) {
      w = 24; h = 18; 
    }

    const startX = (window.innerWidth - (w * TILE_SIZE)) / 2;
    const startY = (window.innerHeight - (h * TILE_SIZE)) / 2;

    // Top
    for (let i = 0; i < w; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * TILE_SIZE, y: startY });
    // Right
    for (let i = 1; i < h; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + (w-1) * TILE_SIZE, y: startY + i * TILE_SIZE });
    // Bottom
    for (let i = w - 2; i >= 0; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * TILE_SIZE, y: startY + (h-1) * TILE_SIZE });
    // Left
    for (let i = h - 2; i >= 1; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * TILE_SIZE });

    return spaces;
  }, []);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, [0]);
    setZombieIndicators(zInd);
    setBombIndices(getRandomUnique(BOMB_COUNT, [0, ...zInd]));
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: 'bomb' | 'zombie') => {
    const newList = list.filter(p => p !== pos);
    const [newPos] = getRandomUnique(1, [currentPos, 0, ...newList, activeZombie.pos]);
    if (type === 'bomb') setBombIndices([...newList, newPos]);
    else setZombieIndicators([...newList, newPos]);
  };

  const processMovement = useCallback((diceVal: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      stepsDone++;
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);

      // Bomb trigger during passing - Always active if a big zombie exists
      if (bombIndices.includes(tempPos) && activeZombie.isActive) {
        setBombAnimation({ active: true, pos: tempPos });
        setActiveZombie(prev => {
          const nextHealth = prev.health - 1;
          if (nextHealth <= 0) {
            const task = tasks.find(t => t.text === 'Tiêu diệt Zombie lớn');
            if (task) handleTaskComplete(task);
            return { ...prev, isActive: false, health: 0 };
          }
          return { ...prev, health: nextHealth };
        });
        setIsShaking(true);
        setTimeout(() => {
          setIsShaking(false);
          setBombAnimation({ active: false, pos: -1 });
        }, 500);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceVal) {
        clearInterval(interval);
        setIsMoving(false);

        const finalPos = tempPos;

        // Spawn Big Zombie if landing on indicator and NO big zombie is chasing
        if (zombieIndicators.includes(finalPos) && !activeZombie.isActive) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombie({ pos: spawnPos, health: MAX_ZOMBIE_HEALTH, isActive: true });
          relocateItem(zombieIndicators, finalPos, 'zombie');
        } else if (zombieIndicators.includes(finalPos) && activeZombie.isActive) {
          // If already chasing, relocate just for trap effect
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }

        // Move active zombie 2 steps (following player path)
        if (activeZombie.isActive) {
          setActiveZombie(prev => {
            if (!prev.isActive) return prev;
            const nextZPos = (prev.pos + 2) % TOTAL_TILES;
            if (nextZPos === finalPos) {
              handleCaught();
              return { ...prev, isActive: false, pos: -1 };
            }
            return { ...prev, pos: nextZPos };
          });
        }
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombie, tasks]);

  const handleCaught = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombie({ pos: -1, health: 3, isActive: false });
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);
    setDicePosition(landing);
    const val = Math.floor(Math.random() * 6) + 1;
    if (val === 6) {
        const t = tasks.find(x => x.text === 'Lắc được xúc xắc 6');
        if (t) handleTaskComplete(t);
    }
    setTimeout(() => {
      setIsRolling(false);
      setDiceValue(val);
      setIsMoving(true);
      processMovement(val);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 10);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombie(prev => ({ ...prev, isActive: false, health: 0 }));
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 30);
    }, 1500);
  };

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-500 overflow-hidden ${isExploding ? 'bg-red-500/10' : ''}`}>

      {/* 80 Tile Sudoku-style Map */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombieIndicator = zombieIndicators.includes(s.id);
          const isStart = s.id === 0;
          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-colors duration-300
                ${isStart ? 'bg-indigo-50/90 dark:bg-indigo-950/40' : ''}
              `}
              style={{ left: s.x, top: s.y, width: TILE_SIZE, height: TILE_SIZE }}
            >
              <span className="text-[8px] opacity-10 absolute top-0.5 left-0.5 font-bold">{s.id + 1}</span>
              {isBomb && <span className="text-xl">💣</span>}
              {isZombieIndicator && <span className="text-sm opacity-40 grayscale">🧟</span>}
              {bloom && <span className="text-xl bloom">{bloom}</span>}
              {isStart && !bloom && <span className="text-[8px] font-black opacity-30">START</span>}
            </div>
          );
        })}

        {/* Big Zombie - Chasing */}
        {activeZombie.isActive && boardSpaces[activeZombie.pos] && (
          <div className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[activeZombie.pos].x + TILE_SIZE/2, 
            top: boardSpaces[activeZombie.pos].y + TILE_SIZE/2, 
            transform: 'translate(-50%, -60%)' 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/50 dark:bg-black/50 p-0.5 rounded">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-sm ${i < activeZombie.health ? 'bg-red-500 shadow-[0_0_5px_rgba(239,68,68,0.5)]' : 'bg-gray-300 dark:bg-gray-700'}`} />
                   ))}
                </div>
                <span className="drop-shadow-lg" style={{ fontSize: TILE_SIZE * 1.3 }}>🧟</span>
             </div>
          </div>
        )}

        {/* Player Piece (150% Size) */}
        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto ${isMoving ? 'scale-110 -translate-y-4' : 'scale-100'}`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + TILE_SIZE/2, 
            top: (boardSpaces[currentPos]?.y || 0) + TILE_SIZE/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: TILE_SIZE * 1.5
          }}
        >
          <span className="drop-shadow-xl select-none filter contrast-125">{ANIMAL_EMOJIS[animalIndex]}</span>
        </div>

        {/* Bomb Strike Animation */}
        {bombAnimation.active && activeZombie.isActive && boardSpaces[activeZombie.pos] && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[activeZombie.pos].x + TILE_SIZE/2, 
            top: boardSpaces[activeZombie.pos].y + TILE_SIZE/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-5xl">💥</span>
          </div>
        )}
      </div>

      {/* Center Panels - Positioned strictly inside the board ring */}
      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-center gap-6 lg:gap-16 scale-90 lg:scale-100 bg-transparent">

          {/* Task Dashboard */}
          <div className="glass-panel rounded-[12px] p-6 w-64 h-[420px] flex flex-col shadow-2xl">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-widest block dark:text-white/60">Energy</span>
                <span className="text-3xl font-black tabular-nums dark:text-white">{rollBank}</span>
              </div>
              <button onClick={() => setDarkMode(!darkMode)} className="p-2 hover:bg-black/5 dark:hover:bg-white/5 rounded-lg transition-colors">
                {darkMode ? '☀️' : '🌙'}
              </button>
            </div>

            <div className="flex-grow overflow-y-auto space-y-2 pr-2 custom-scrollbar">
              {!showHistory ? (
                tasks.map(t => (
                  <div key={t.id} onClick={() => handleTaskComplete(t)} className="p-3 bg-white/40 dark:bg-white/5 border border-black/5 dark:border-white/10 rounded-lg cursor-pointer hover:border-black/20 dark:hover:border-white/30 transition-all flex items-center gap-3 group">
                    <div className="w-4 h-4 rounded-sm border-2 border-black/10 dark:border-white/20 group-hover:bg-indigo-500 group-hover:border-indigo-500 transition-colors" />
                    <span className="text-[12px] font-semibold dark:text-zinc-200">{t.text}</span>
                  </div>
                ))
              ) : (
                history.map(h => (
                  <div key={h.id} className="p-2 border-l-2 border-black/10 dark:border-white/10 opacity-60">
                    <span className="text-[11px] font-bold block line-through dark:text-white">{h.text}</span>
                    <span className="text-[8px] opacity-40 uppercase dark:text-white">{h.completedAt}</span>
                  </div>
                ))
              )}
            </div>

            <div className="mt-4 flex gap-2">
              <button onClick={() => setShowHistory(!showHistory)} className="flex-1 py-2.5 text-[9px] font-bold uppercase tracking-widest border border-black/10 dark:border-white/10 rounded-lg dark:text-white">
                {showHistory ? 'Nhiệm vụ' : 'Lịch sử'}
              </button>
              <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([...tasks, { id: Date.now().toString(), text: newTask, completed: false }]); setNewTask(''); }} className="flex-[2] relative">
                <input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full bg-black/5 dark:bg-white/5 rounded-lg px-3 py-2.5 text-xs outline-none dark:text-white focus:ring-1 ring-indigo-500/30" placeholder="Thêm..." />
              </form>
            </div>
          </div>

          {/* Alchemy Jar Center */}
          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} />
        </div>
      </div>

      <Dice3D value={diceValue} isRolling={isRolling} currentPos={dicePosition} onRoll={handleRoll} onDragEnd={setDicePosition} />

      <style>{`
        @keyframes bomb-drop {
          0% { transform: translate(-50%, -300%) scale(2); opacity: 0; }
          70% { transform: translate(-50%, -60%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(4); opacity: 0; }
        }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile {
          border: 1px solid rgba(0,0,0,0.06);
          background: rgba(255,255,255,0.9);
        }
        .dark .sudoku-tile {
          border: 1px solid rgba(255,255,255,0.04);
          background: rgba(20,20,20,0.95);
        }
        .glass-panel {
          box-shadow: 0 40px 100px -20px rgba(0,0,0,0.1);
        }
        .dark .glass-panel {
          box-shadow: 0 40px 100px -20px rgba(0,0,0,0.5);
        }
      `}</style>

    </div>
  );
};

export default App;

export interface Task {
  id: string;
  text: string;
  completed: boolean;
}

export interface BoardSpace {
  id: number;
  x: number;
  y: number;
  type: 'normal' | 'special';
}

export interface BigZombie {
  id: string;
  pos: number;
  health: number;
  isActive: boolean;
}

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 30;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 250; 
const ZOMBIE_INDICATOR_COUNT = 8;
const BOMB_COUNT = 8;
const MAX_ZOMBIE_HEALTH = 3;
const TOTAL_TILES = 80;
const SPAWN_BEHIND_OFFSET = 6;

const ANIMAL_EMOJIS = [
  '🦖', '🐉', '🐲', '🐟', '🐙', '🦈', '🐳', '🐋', '🐬', '🐘', 
  '🦄', '🦁', '🐯', '🐼', '🦊', '🐸', '🐨', '🦒', '🦓', '🦘',
  '🦅', '🦉', '🦜', '🦚', '🦢', '🐢', '🐊', '🐍', '🦎'
];
const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false },
    { id: '2', text: 'Tiêu diệt 3 Zombie lớn', completed: false },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePosition, setDicePosition] = useState({ x: window.innerWidth / 2, y: window.innerHeight / 2 });
  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });
  const [zombiesKilled, setZombiesKilled] = useState(0);

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const TILE_SIZE = 42; 
  const SAFE_MARGIN = 15;

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const availableWidth = window.innerWidth - (SAFE_MARGIN * 2);
    const availableHeight = window.innerHeight - (SAFE_MARGIN * 2);

    // W + H = 42 for 80 tiles (2*(W+H)-4 = 80)
    const screenRatio = availableWidth / availableHeight;
    let h = Math.round(42 / (1 + screenRatio));
    let w = 42 - h;

    // Fixed aspect ratio fallback if extreme
    if (2 * (w + h) - 4 !== 80) { w = 24; h = 18; }

    const startX = (window.innerWidth - (w * TILE_SIZE)) / 2;
    const startY = (window.innerHeight - (h * TILE_SIZE)) / 2;

    for (let i = 0; i < w; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * TILE_SIZE, y: startY });
    for (let i = 1; i < h; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + (w-1) * TILE_SIZE, y: startY + i * TILE_SIZE });
    for (let i = w - 2; i >= 0; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * TILE_SIZE, y: startY + (h-1) * TILE_SIZE });
    for (let i = h - 2; i >= 1; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * TILE_SIZE });

    return spaces;
  }, []);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, [0]);
    setZombieIndicators(zInd);
    setBombIndices(getRandomUnique(BOMB_COUNT, [0, ...zInd]));
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: 'bomb' | 'zombie') => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);
    if (type === 'bomb') setBombIndices([...newList, newPos]);
    else setZombieIndicators([...newList, newPos]);
  };

  const processMovement = useCallback((diceVal: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      // Bomb trigger during passing - Always hits the nearest zombie
      if (bombIndices.includes(tempPos) && activeZombies.length > 0) {
        setBombAnimation({ active: true, pos: tempPos });

        setActiveZombies(prev => {
          if (prev.length === 0) return prev;
          // Find nearest zombie to the current player position
          let nearestIndex = 0;
          let minDistance = Infinity;
          prev.forEach((z, idx) => {
            const dist = Math.min(Math.abs(tempPos - z.pos), TOTAL_TILES - Math.abs(tempPos - z.pos));
            if (dist < minDistance) {
              minDistance = dist;
              nearestIndex = idx;
            }
          });

          const newZombies = [...prev];
          const target = { ...newZombies[nearestIndex] };
          target.health -= 1;

          if (target.health <= 0) {
            newZombies.splice(nearestIndex, 1);
            setZombiesKilled(k => {
                const total = k + 1;
                if (total >= 3) {
                    const t = tasks.find(x => x.text === 'Tiêu diệt 3 Zombie lớn');
                    if (t) handleTaskComplete(t);
                }
                return total;
            });
          } else {
            newZombies[nearestIndex] = target;
          }
          return newZombies;
        });

        setIsShaking(true);
        setTimeout(() => {
          setIsShaking(false);
          setBombAnimation({ active: false, pos: -1 });
        }, 500);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceVal) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        // Spawn Big Zombie if landing on indicator (Traps always stay visible as indicators)
        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          const newZombie: BigZombie = {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          };
          setActiveZombies(prev => [...prev, newZombie]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }

        // All active zombies move 2 steps
        setActiveZombies(prev => {
          let gameOver = false;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + 2) % TOTAL_TILES;
            if (nextZPos === finalPos) {
              gameOver = true;
            }
            return { ...z, pos: nextZPos };
          });

          if (gameOver) {
            handleCaught();
            return [];
          }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, tasks]);

  const handleCaught = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);
    setDicePosition(landing);
    const val = Math.floor(Math.random() * 6) + 1;
    if (val === 6) {
        const t = tasks.find(x => x.text === 'Lắc được xúc xắc 6');
        if (t) handleTaskComplete(t);
    }
    setTimeout(() => {
      setIsRolling(false);
      setDiceValue(val);
      setIsMoving(true);
      processMovement(val);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombies([]);
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-500 overflow-hidden ${isExploding ? 'bg-indigo-500/20' : ''}`}>

      {/* 80 Tile Board Ring */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombieIndicator = zombieIndicators.includes(s.id);
          const isStart = s.id === 0;
          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-colors duration-300
                ${isStart ? 'bg-indigo-50/90 dark:bg-indigo-950/40' : ''}
                ${isShaking ? 'animate-bounce' : ''}
              `}
              style={{ left: s.x, top: s.y, width: TILE_SIZE, height: TILE_SIZE }}
            >
              <span className="text-[7px] opacity-10 absolute top-0.5 left-0.5 font-bold">{s.id + 1}</span>
              {isBomb && <span className="text-lg">💣</span>}
              {isZombieIndicator && <span className="text-sm opacity-40 filter saturate-0 group-hover:saturate-100 transition-all">🧟</span>}
              {bloom && <span className="text-xl bloom">{bloom}</span>}
              {isStart && !bloom && <span className="text-[7px] font-black opacity-30">HOME</span>}
            </div>
          );
        })}

        {/* Big Zombies Rendering */}
        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[z.pos].x + TILE_SIZE/2, 
            top: boardSpaces[z.pos].y + TILE_SIZE/2, 
            transform: 'translate(-50%, -60%)' 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/60 dark:bg-black/60 p-0.5 rounded shadow-sm">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-sm ${i < z.health ? 'bg-red-500 shadow-[0_0_5px_rgba(239,68,68,0.5)]' : 'bg-gray-300 dark:bg-gray-700'}`} />
                   ))}
                </div>
                <span className="drop-shadow-lg" style={{ fontSize: TILE_SIZE * 1.3 }}>🧟</span>
             </div>
          </div>
        ))}

        {/* Player Piece */}
        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto ${isMoving ? 'scale-110 -translate-y-2' : 'scale-100'}`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + TILE_SIZE/2, 
            top: (boardSpaces[currentPos]?.y || 0) + TILE_SIZE/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: TILE_SIZE * 1.5
          }}
        >
          <span className="drop-shadow-xl select-none filter contrast-125 brightness-110">{ANIMAL_EMOJIS[animalIndex]}</span>
        </div>

        {/* Bomb Blast Animation */}
        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[currentPos]?.x + TILE_SIZE/2, 
            top: boardSpaces[currentPos]?.y + TILE_SIZE/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-5xl">💥</span>
          </div>
        )}
      </div>

      {/* Internal Ring UI Panels */}
      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-center gap-4 lg:gap-12 scale-75 md:scale-90 lg:scale-100">

          {/* Dashboard Panel */}
          <div className="glass-panel rounded-[16px] p-6 w-60 h-[400px] flex flex-col shadow-2xl border border-black/5 dark:border-white/5">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[9px] font-bold opacity-30 uppercase tracking-[0.2em] block dark:text-white/60">Energy</span>
                <span className="text-3xl font-black tabular-nums dark:text-white">{rollBank}</span>
              </div>
              <button onClick={() => setDarkMode(!darkMode)} className="p-2 hover:bg-black/5 dark:hover:bg-white/5 rounded-lg transition-colors">
                {darkMode ? '☀️' : '🌙'}
              </button>
            </div>

            <div className="flex-grow overflow-y-auto space-y-2 pr-1 custom-scrollbar">
              {!showHistory ? (
                tasks.map(t => (
                  <div key={t.id} onClick={() => handleTaskComplete(t)} className="p-3 bg-white/40 dark:bg-white/5 border border-black/5 dark:border-white/10 rounded-xl cursor-pointer hover:border-black/20 dark:hover:border-white/30 transition-all flex items-center gap-3 group">
                    <div className="w-4 h-4 rounded-md border-2 border-black/10 dark:border-white/20 group-hover:bg-indigo-500 group-hover:border-indigo-500 transition-colors" />
                    <span className="text-[11px] font-bold dark:text-zinc-200 tracking-tight">{t.text}</span>
                  </div>
                ))
              ) : (
                history.map(h => (
                  <div key={h.id} className="p-2 border-l-2 border-indigo-500/30 opacity-60">
                    <span className="text-[10px] font-bold block line-through dark:text-white">{h.text}</span>
                    <span className="text-[7px] opacity-40 uppercase dark:text-white">{h.completedAt}</span>
                  </div>
                ))
              )}
            </div>

            <div className="mt-4 flex gap-2">
              <button onClick={() => setShowHistory(!showHistory)} className="flex-1 py-2 text-[8px] font-black uppercase tracking-widest border border-black/10 dark:border-white/10 rounded-lg dark:text-white hover:bg-black/5">
                {showHistory ? 'Tasks' : 'Log'}
              </button>
              <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([...tasks, { id: Date.now().toString(), text: newTask, completed: false }]); setNewTask(''); }} className="flex-[2] relative">
                <input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full bg-black/5 dark:bg-white/5 rounded-lg px-3 py-2 text-[11px] outline-none dark:text-white font-medium" placeholder="Add..." />
              </form>
            </div>
          </div>

          {/* Centerpiece Jar */}
          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} />
        </div>
      </div>

      <Dice3D value={diceValue} isRolling={isRolling} currentPos={dicePosition} onRoll={handleRoll} onDragEnd={setDicePosition} />

      <style>{`
        @keyframes bomb-drop {
          0% { transform: translate(-50%, -300%) scale(2); opacity: 0; }
          60% { transform: translate(-50%, -60%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(5); opacity: 0; }
        }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile {
          border: 1px solid rgba(0,0,0,0.06);
          background: rgba(255,255,255,0.9);
          box-shadow: inset 0 1px 0 rgba(255,255,255,0.5);
        }
        .dark .sudoku-tile {
          border: 1px solid rgba(255,255,255,0.05);
          background: rgba(30,30,30,0.95);
          box-shadow: none;
        }
        .glass-panel {
          backdrop-filter: blur(40px);
        }
        .custom-scrollbar::-webkit-scrollbar { width: 3px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.1); border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); }
      `}</style>

    </div>
  );
};

export default App;

