import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 
const ZOMBIE_INDICATOR_COUNT = 8;
const BOMB_COUNT = 8;
const MAX_ZOMBIE_HEALTH = 3;
const TOTAL_TILES = 80;
const SPAWN_BEHIND_OFFSET = 6;

const ANIMAL_EMOJIS = [
  '🦖', '🐉', '🐲', '🐟', '🐙', '🦈', '🐳', '🐋', '🐬', '🐘', 
  '🦄', '🦁', '🐯', '🐼', '🦊', '🐸', '🐨', '🦒', '🦓', '🦘'
];
const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePosition, setDicePosition] = useState({ x: window.innerWidth / 2, y: window.innerHeight / 2 });
  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });
  const [zombiesKilled, setZombiesKilled] = useState(0);

  // Theme icons
  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const TILE_SIZE = 42; 
  const SAFE_MARGIN = 20;

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const availableWidth = window.innerWidth - (SAFE_MARGIN * 2);
    const availableHeight = window.innerHeight - (SAFE_MARGIN * 2);
    const screenRatio = availableWidth / availableHeight;
    let h = Math.round(42 / (1 + screenRatio));
    let w = 42 - h;

    if (2 * (w + h) - 4 !== 80) { w = 24; h = 18; }

    const startX = (window.innerWidth - (w * TILE_SIZE)) / 2;
    const startY = (window.innerHeight - (h * TILE_SIZE)) / 2;

    for (let i = 0; i < w; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * TILE_SIZE, y: startY });
    for (let i = 1; i < h; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + (w-1) * TILE_SIZE, y: startY + i * TILE_SIZE });
    for (let i = w - 2; i >= 0; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * TILE_SIZE, y: startY + (h-1) * TILE_SIZE });
    for (let i = h - 2; i >= 1; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * TILE_SIZE });

    return spaces;
  }, []);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, [0]);
    setZombieIndicators(zInd);
    setBombIndices(getRandomUnique(BOMB_COUNT, [0, ...zInd]));
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: 'bomb' | 'zombie') => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);
    if (type === 'bomb') setBombIndices([...newList, newPos]);
    else setZombieIndicators([...newList, newPos]);
  };

  const processMovement = useCallback((diceVal: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      if (bombIndices.includes(tempPos) && activeZombies.length > 0) {
        setBombAnimation({ active: true, pos: tempPos });
        setActiveZombies(prev => {
          if (prev.length === 0) return prev;
          let nearestIndex = 0;
          let minDistance = Infinity;
          prev.forEach((z, idx) => {
            const dist = Math.min(Math.abs(tempPos - z.pos), TOTAL_TILES - Math.abs(tempPos - z.pos));
            if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
          });
          const newZombies = [...prev];
          const target = { ...newZombies[nearestIndex] };
          target.health -= 1;
          if (target.health <= 0) {
            newZombies.splice(nearestIndex, 1);
            setZombiesKilled(k => {
                const total = k + 1;
                if (total >= 3) {
                    const t = tasks.find(x => x.text === 'Tiêu diệt 3 Quỷ lớn');
                    if (t) handleTaskComplete(t);
                }
                return total;
            });
          } else { newZombies[nearestIndex] = target; }
          return newZombies;
        });
        setIsShaking(true);
        setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceVal) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          const newZombie: BigZombie = {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          };
          setActiveZombies(prev => [...prev, newZombie]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }

        setActiveZombies(prev => {
          let gameOver = false;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + 2) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) { handleCaught(); return []; }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, tasks]);

  const handleCaught = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);
    setDicePosition(landing);
    const val = Math.floor(Math.random() * 6) + 1;
    if (val === 6) {
        const t = tasks.find(x => x.text === 'Lắc được xúc xắc 6');
        if (t) handleTaskComplete(t);
    }
    setTimeout(() => {
      setIsRolling(false);
      setDiceValue(val);
      setIsMoving(true);
      processMovement(val);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
    if (tasks.length <= 1) {
       setTasks(p => [...p, { id: Date.now().toString(), text: 'New Goal', completed: false, priority: 'medium' }]);
    }
  };

  const onJarExplode = () => {
    setIsExploding(true);
    // When jar explodes, it kills ALL active zombies
    setZombiesKilled(k => k + activeZombies.length);
    setActiveZombies([]);
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
        // Reward for cleansing the board
        const t = tasks.find(x => x.text === 'Nạp đầy 100 Alchemy');
        if (t) handleTaskComplete(t);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-500/10 text-red-600 dark:text-red-400 border-red-200 dark:border-red-900/30';
        case 'medium': return 'bg-orange-500/10 text-orange-600 dark:text-orange-400 border-orange-200 dark:border-orange-900/30';
        default: return 'bg-blue-500/10 text-blue-600 dark:text-blue-400 border-blue-200 dark:border-blue-900/30';
    }
  }

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden ${isExploding ? 'bg-indigo-600/30 animate-pulse' : ''}`}>

      {/* 80 Tile Board */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombieIndicator = zombieIndicators.includes(s.id);
          const isStart = s.id === 0;
          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500
                ${isStart ? 'bg-indigo-50/90 dark:bg-indigo-950/40 shadow-inner' : ''}
              `}
              style={{ left: s.x, top: s.y, width: TILE_SIZE, height: TILE_SIZE }}
            >
              <span className="text-[7px] opacity-10 absolute top-0.5 left-0.5 font-bold">{s.id + 1}</span>
              {isBomb && <span className="text-xl drop-shadow-sm">{BOMB_ICON}</span>}
              {isZombieIndicator && <span className="text-sm opacity-40 grayscale-[0.5] hover:grayscale-0 transition-all">{ENEMY_ICON}</span>}
              {bloom && <span className="text-xl bloom">{bloom}</span>}
              {isStart && !bloom && <span className="text-[7px] font-black opacity-30 tracking-widest">START</span>}
            </div>
          );
        })}

        {/* Enemies */}
        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[z.pos].x + TILE_SIZE/2, 
            top: boardSpaces[z.pos].y + TILE_SIZE/2, 
            transform: 'translate(-50%, -60%)' 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/80 dark:bg-black/80 p-0.5 rounded-full px-2 border border-black/5">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-300 dark:bg-gray-700'}`} />
                   ))}
                </div>
                <span className="drop-shadow-2xl animate-bounce" style={{ fontSize: TILE_SIZE * 1.4 }}>{ENEMY_ICON}</span>
             </div>
          </div>
        ))}

        {/* Player */}
        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto ${isMoving ? 'scale-110 -translate-y-3' : 'scale-100 hover:rotate-12'}`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + TILE_SIZE/2, 
            top: (boardSpaces[currentPos]?.y || 0) + TILE_SIZE/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: TILE_SIZE * 1.5
          }}
        >
          <span className="drop-shadow-xl select-none filter contrast-125 brightness-110">{ANIMAL_EMOJIS[animalIndex]}</span>
        </div>

        {/* Bomb Strike */}
        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[currentPos]?.x + TILE_SIZE/2, 
            top: boardSpaces[currentPos]?.y + TILE_SIZE/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-5xl">{darkMode ? '✨' : '💥'}</span>
          </div>
        )}
      </div>

      {/* Internal Ring UI */}
      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-6 lg:gap-14 scale-75 md:scale-90 lg:scale-100">

          {/* Enhanced Task Creation & List */}
          <div className="glass-panel rounded-[24px] p-7 w-72 h-[480px] flex flex-col shadow-2xl border border-black/5 dark:border-white/5">
            <div className="flex justify-between items-center mb-6">
              <div>
                <span className="text-[9px] font-black opacity-40 uppercase tracking-[0.3em] block dark:text-white/60">Energy Unit</span>
                <span className="text-4xl font-black tabular-nums dark:text-white tracking-tighter">{rollBank}</span>
              </div>
              <button 
                onClick={() => setDarkMode(!darkMode)} 
                className="w-10 h-10 flex items-center justify-center bg-black/5 dark:bg-white/5 rounded-full hover:bg-black/10 dark:hover:bg-white/10 transition-all active:scale-90"
              >
                {darkMode ? '🧛🏻' : '🧟'}
              </button>
            </div>

            {/* Task List */}
            <div className="flex-grow overflow-y-auto space-y-2 pr-1 custom-scrollbar">
              {!showHistory ? (
                tasks.map(t => (
                  <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-4 bg-white/50 dark:bg-black/20 border border-black/5 dark:border-white/5 rounded-2xl cursor-pointer hover:border-indigo-500/30 transition-all flex flex-col gap-2 relative overflow-hidden">
                    <div className="flex items-center gap-3">
                        <div className="w-5 h-5 rounded-full border-2 border-indigo-500/20 group-hover:bg-indigo-500 group-hover:border-indigo-500 transition-all flex items-center justify-center">
                            <span className="text-[10px] text-white opacity-0 group-hover:opacity-100">✓</span>
                        </div>
                        <span className="text-[13px] font-bold dark:text-zinc-100 leading-tight">{t.text}</span>
                    </div>
                    {t.priority && (
                        <div className={`self-start px-2 py-0.5 rounded-md text-[8px] font-black uppercase tracking-widest border ${getPriorityColor(t.priority)}`}>
                            {t.priority}
                        </div>
                    )}
                  </div>
                ))
              ) : (
                history.map(h => (
                  <div key={h.id} className="p-3 border-l-4 border-indigo-500/20 bg-indigo-500/5 rounded-r-xl opacity-60">
                    <span className="text-[11px] font-bold block line-through dark:text-white">{h.text}</span>
                    <span className="text-[8px] opacity-40 uppercase dark:text-white font-black">{h.completedAt}</span>
                  </div>
                ))
              )}
            </div>

            {/* Premium Task Creator */}
            <div className="mt-6 flex flex-col gap-3">
              <div className="flex gap-1 justify-between">
                {(['low', 'medium', 'high'] as const).map(p => (
                    <button 
                        key={p}
                        onClick={() => setNewTaskPriority(p)}
                        className={`flex-1 py-1.5 text-[8px] font-black uppercase tracking-tighter rounded-lg border transition-all ${newTaskPriority === p ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-black/5 dark:bg-white/5 dark:text-white/50 border-transparent'}`}
                    >
                        {p}
                    </button>
                ))}
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowHistory(!showHistory)} className="w-12 h-10 flex items-center justify-center bg-black/5 dark:bg-white/5 rounded-xl dark:text-white hover:bg-black/10 transition-colors">
                    {showHistory ? '📝' : '📖'}
                </button>
                <form 
                    onSubmit={e => { 
                        e.preventDefault(); 
                        if(!newTask.trim()) return; 
                        setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); 
                        setNewTask(''); 
                    }} 
                    className="flex-1 relative"
                >
                    <input 
                        value={newTask} 
                        onChange={e => setNewTask(e.target.value)} 
                        className="w-full h-10 bg-black/5 dark:bg-white/5 border border-transparent focus:border-indigo-500/30 rounded-xl px-4 text-xs outline-none dark:text-white font-bold transition-all" 
                        placeholder="Add mission..." 
                    />
                </form>
              </div>
            </div>
          </div>

          {/* Jar */}
          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} />
        </div>
      </div>

      <Dice3D value={diceValue} isRolling={isRolling} currentPos={dicePosition} onRoll={handleRoll} onDragEnd={setDicePosition} />

      <style>{`
        @keyframes bomb-drop {
          0% { transform: translate(-50%, -300%) scale(2); opacity: 0; }
          60% { transform: translate(-50%, -60%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(8); opacity: 0; filter: blur(20px); }
        }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile {
          border: 1px solid rgba(0,0,0,0.06);
          background: rgba(255,255,255,0.95);
          box-shadow: inset 0 1px 0 rgba(255,255,255,0.8);
          border-radius: 8px;
        }
        .dark .sudoku-tile {
          border: 1px solid rgba(255,255,255,0.04);
          background: rgba(25,25,25,0.98);
          box-shadow: none;
        }
        .glass-panel {
          backdrop-filter: blur(50px);
          box-shadow: 0 50px 100px -20px rgba(0,0,0,0.15);
        }
        .dark .glass-panel {
          box-shadow: 0 50px 120px -10px rgba(0,0,0,0.6);
          background: rgba(20, 20, 25, 0.85);
        }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.05); border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.05); }
      `}</style>

    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 
const ZOMBIE_INDICATOR_COUNT = 8;
const BOMB_COUNT = 8;
const MAX_ZOMBIE_HEALTH = 3;
const TOTAL_TILES = 80;
const SPAWN_BEHIND_OFFSET = 6;

const ANIMAL_EMOJIS = [
  '🦖', '🐉', '🐲', '🐟', '🐙', '🦈', '🐳', '🐋', '🐬', '🐘', 
  '🦄', '🦁', '🐯', '🐼', '🦊', '🐸', '🐨', '🦒', '🦓', '🦘'
];
const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePosition, setDicePosition] = useState({ x: window.innerWidth / 2, y: window.innerHeight / 2 });
  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });
  const [zombiesKilled, setZombiesKilled] = useState(0);

  // Theme icons: 🧛🏻 and 🧄 for Dark Mode
  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  // Adjust tile size and board layout to fit screen and prevent UI overlap
  // 80 tiles: 2*(W+H)-4 = 80 => W+H = 42. Let's use 26x16
  const TILE_SIZE = 42; 
  const BOARD_W = 26;
  const BOARD_H = 16;

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];

    // Center the board based on calculated dimensions
    const totalW = BOARD_W * TILE_SIZE;
    const totalH = BOARD_H * TILE_SIZE;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    // Top edge
    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * TILE_SIZE, y: startY });
    // Right edge
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * TILE_SIZE, y: startY + i * TILE_SIZE });
    // Bottom edge
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * TILE_SIZE, y: startY + (BOARD_H - 1) * TILE_SIZE });
    // Left edge
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * TILE_SIZE });

    return spaces;
  }, []);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, [0]);
    setZombieIndicators(zInd);
    setBombIndices(getRandomUnique(BOMB_COUNT, [0, ...zInd]));
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: 'bomb' | 'zombie') => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);
    if (type === 'bomb') setBombIndices([...newList, newPos]);
    else setZombieIndicators([...newList, newPos]);
  };

  const processMovement = useCallback((diceVal: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      // Bomb strike logic
      if (bombIndices.includes(tempPos) && activeZombies.length > 0) {
        setBombAnimation({ active: true, pos: tempPos });
        setActiveZombies(prev => {
          if (prev.length === 0) return prev;
          let nearestIndex = 0;
          let minDistance = Infinity;
          prev.forEach((z, idx) => {
            const dist = Math.min(Math.abs(tempPos - z.pos), TOTAL_TILES - Math.abs(tempPos - z.pos));
            if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
          });
          const newZombies = [...prev];
          const target = { ...newZombies[nearestIndex] };
          target.health -= 1;
          if (target.health <= 0) {
            newZombies.splice(nearestIndex, 1);
            setZombiesKilled(k => {
                const total = k + 1;
                if (total >= 3) {
                    const t = tasks.find(x => x.text === 'Tiêu diệt 3 Quỷ lớn');
                    if (t) handleTaskComplete(t);
                }
                return total;
            });
          } else { newZombies[nearestIndex] = target; }
          return newZombies;
        });
        setIsShaking(true);
        setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceVal) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        // Zombie trap trigger
        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          const newZombie: BigZombie = {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          };
          setActiveZombies(prev => [...prev, newZombie]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }

        // Move all active zombies
        setActiveZombies(prev => {
          let gameOver = false;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + 2) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) { handleCaught(); return []; }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, tasks]);

  const handleCaught = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);
    setDicePosition(landing);
    const val = Math.floor(Math.random() * 6) + 1;
    if (val === 6) {
        const t = tasks.find(x => x.text === 'Lắc được xúc xắc 6');
        if (t) handleTaskComplete(t);
    }
    setTimeout(() => {
      setIsRolling(false);
      setDiceValue(val);
      setIsMoving(true);
      processMovement(val);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
    if (tasks.length <= 1) {
       setTasks(p => [...p, { id: Date.now().toString(), text: 'New Goal', completed: false, priority: 'medium' }]);
    }
  };

  const onJarExplode = () => {
    setIsExploding(true);
    // Kills ALL active zombies when exploded
    setZombiesKilled(k => k + activeZombies.length);
    setActiveZombies([]);
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
        const t = tasks.find(x => x.text === 'Nạp đầy 100 Alchemy');
        if (t) handleTaskComplete(t);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-500/10 text-red-600 dark:text-red-400 border-red-200 dark:border-red-900/30';
        case 'medium': return 'bg-orange-500/10 text-orange-600 dark:text-orange-400 border-orange-200 dark:border-orange-900/30';
        default: return 'bg-blue-500/10 text-blue-600 dark:text-blue-400 border-blue-200 dark:border-blue-900/30';
    }
  }

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden ${isExploding ? 'bg-indigo-600/20 animate-pulse' : ''}`}>

      {/* 80 Tile Ring Board */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombieIndicator = zombieIndicators.includes(s.id);
          const isStart = s.id === 0;
          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500
                ${isStart ? 'bg-indigo-50/90 dark:bg-indigo-950/40 shadow-inner' : ''}
              `}
              style={{ left: s.x, top: s.y, width: TILE_SIZE, height: TILE_SIZE }}
            >
              <span className="text-[7px] opacity-10 absolute top-0.5 left-0.5 font-bold">{s.id + 1}</span>
              {isBomb && <span className="text-xl drop-shadow-sm">{BOMB_ICON}</span>}
              {isZombieIndicator && <span className="text-sm opacity-40 grayscale-[0.5] transition-all">{ENEMY_ICON}</span>}
              {bloom && <span className="text-xl bloom">{bloom}</span>}
              {isStart && !bloom && <span className="text-[7px] font-black opacity-30 tracking-widest">START</span>}
            </div>
          );
        })}

        {/* Enemies Layer */}
        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[z.pos].x + TILE_SIZE/2, 
            top: boardSpaces[z.pos].y + TILE_SIZE/2, 
            transform: 'translate(-50%, -60%)' 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/80 dark:bg-black/80 p-0.5 rounded-full px-2 border border-black/5">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-300 dark:bg-gray-700'}`} />
                   ))}
                </div>
                <span className="drop-shadow-2xl animate-bounce" style={{ fontSize: TILE_SIZE * 1.4 }}>{ENEMY_ICON}</span>
             </div>
          </div>
        ))}

        {/* Player Character */}
        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto ${isMoving ? 'scale-110 -translate-y-3' : 'scale-100 hover:rotate-12'}`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + TILE_SIZE/2, 
            top: (boardSpaces[currentPos]?.y || 0) + TILE_SIZE/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: TILE_SIZE * 1.5
          }}
        >
          <span className="drop-shadow-xl select-none filter contrast-125 brightness-110">{ANIMAL_EMOJIS[animalIndex]}</span>
        </div>

        {/* Interaction VFX */}
        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[currentPos]?.x + TILE_SIZE/2, 
            top: boardSpaces[currentPos]?.y + TILE_SIZE/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-5xl">{darkMode ? '✨' : '💥'}</span>
          </div>
        )}
      </div>

      {/* Internal UI Ring - Guaranteed Centered Gap */}
      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-6 lg:gap-14 scale-75 md:scale-90 lg:scale-100 bg-transparent">

          {/* Task Management Dashboard */}
          <div className="glass-panel rounded-[24px] p-7 w-72 h-[480px] flex flex-col shadow-2xl border border-black/5 dark:border-white/5">
            <div className="flex justify-between items-center mb-6">
              <div>
                <span className="text-[9px] font-black opacity-40 uppercase tracking-[0.3em] block dark:text-white/60">Energy Unit</span>
                <span className="text-4xl font-black tabular-nums dark:text-white tracking-tighter">{rollBank}</span>
              </div>
              <button 
                onClick={() => setDarkMode(!darkMode)} 
                className="w-10 h-10 flex items-center justify-center bg-black/5 dark:bg-white/5 rounded-full hover:bg-black/10 dark:hover:bg-white/10 transition-all active:scale-90 shadow-sm"
              >
                {darkMode ? '🧛🏻' : '🧟'}
              </button>
            </div>

            {/* Scrollable Tasks */}
            <div className="flex-grow overflow-y-auto space-y-2 pr-1 custom-scrollbar">
              {!showHistory ? (
                tasks.map(t => (
                  <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-4 bg-white/50 dark:bg-black/20 border border-black/5 dark:border-white/5 rounded-2xl cursor-pointer hover:border-indigo-500/30 transition-all flex flex-col gap-2 relative overflow-hidden active:scale-[0.98]">
                    <div className="flex items-center gap-3">
                        <div className="w-5 h-5 rounded-full border-2 border-indigo-500/20 group-hover:bg-indigo-500 group-hover:border-indigo-500 transition-all flex items-center justify-center">
                            <span className="text-[10px] text-white opacity-0 group-hover:opacity-100">✓</span>
                        </div>
                        <span className="text-[13px] font-bold dark:text-zinc-100 leading-tight">{t.text}</span>
                    </div>
                    {t.priority && (
                        <div className={`self-start px-2 py-0.5 rounded-md text-[8px] font-black uppercase tracking-widest border ${getPriorityColor(t.priority)}`}>
                            {t.priority}
                        </div>
                    )}
                  </div>
                ))
              ) : (
                history.map(h => (
                  <div key={h.id} className="p-3 border-l-4 border-indigo-500/20 bg-indigo-500/5 rounded-r-xl opacity-60">
                    <span className="text-[11px] font-bold block line-through dark:text-white">{h.text}</span>
                    <span className="text-[8px] opacity-40 uppercase dark:text-white font-black">{h.completedAt}</span>
                  </div>
                ))
              )}
            </div>

            {/* Mission Creation Tool */}
            <div className="mt-6 flex flex-col gap-3">
              <div className="flex gap-1 justify-between">
                {(['low', 'medium', 'high'] as const).map(p => (
                    <button 
                        key={p}
                        onClick={() => setNewTaskPriority(p)}
                        className={`flex-1 py-1.5 text-[8px] font-black uppercase tracking-tighter rounded-lg border transition-all ${newTaskPriority === p ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-black/5 dark:bg-white/5 dark:text-white/50 border-transparent hover:bg-black/10'}`}
                    >
                        {p}
                    </button>
                ))}
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowHistory(!showHistory)} className="w-12 h-10 flex items-center justify-center bg-black/5 dark:bg-white/5 rounded-xl dark:text-white hover:bg-black/10 transition-colors shadow-sm">
                    {showHistory ? '📝' : '📖'}
                </button>
                <form 
                    onSubmit={e => { 
                        e.preventDefault(); 
                        if(!newTask.trim()) return; 
                        setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); 
                        setNewTask(''); 
                    }} 
                    className="flex-1 relative"
                >
                    <input 
                        value={newTask} 
                        onChange={e => setNewTask(e.target.value)} 
                        className="w-full h-10 bg-black/5 dark:bg-white/5 border border-transparent focus:border-indigo-500/30 rounded-xl px-4 text-xs outline-none dark:text-white font-bold transition-all" 
                        placeholder="Add mission..." 
                    />
                </form>
              </div>
            </div>
          </div>

          {/* Alchemy Jar Power-up */}
          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} />
        </div>
      </div>

      <Dice3D value={diceValue} isRolling={isRolling} currentPos={dicePosition} onRoll={handleRoll} onDragEnd={setDicePosition} />

      <style>{`
        @keyframes bomb-drop {
          0% { transform: translate(-50%, -300%) scale(2); opacity: 0; }
          60% { transform: translate(-50%, -60%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(8); opacity: 0; filter: blur(20px); }
        }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile {
          border: 1px solid rgba(0,0,0,0.06);
          background: rgba(255,255,255,0.95);
          box-shadow: inset 0 1px 0 rgba(255,255,255,0.8);
          border-radius: 8px;
        }
        .dark .sudoku-tile {
          border: 1px solid rgba(255,255,255,0.04);
          background: rgba(25,25,25,0.98);
          box-shadow: none;
        }
        .glass-panel {
          backdrop-filter: blur(50px);
          box-shadow: 0 50px 100px -20px rgba(0,0,0,0.15);
        }
        .dark .glass-panel {
          box-shadow: 0 50px 120px -10px rgba(0,0,0,0.6);
          background: rgba(20, 20, 25, 0.85);
        }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.05); border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.05); }
      `}</style>

    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 
const ZOMBIE_INDICATOR_COUNT = 8;
const BOMB_COUNT = 8;
const MAX_ZOMBIE_HEALTH = 3;
const TOTAL_TILES = 80;
const SPAWN_BEHIND_OFFSET = 6;

const ANIMAL_EMOJIS = [
  '🦖', '🐉', '🐲', '🐟', '🐙', '🦈', '🐳', '🐋', '🐬', '🐘', 
  '🦄', '🦁', '🐯', '🐼', '🦊', '🐸', '🐨', '🦒', '🦓', '🦘'
];
const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePosition, setDicePosition] = useState({ x: window.innerWidth / 2, y: window.innerHeight / 2 });
  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });
  const [zombiesKilled, setZombiesKilled] = useState(0);

  // Theme icons: 🧛🏻 and 🧄 for Dark Mode
  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  // Adjust tile size and board layout (80 tiles: 2*(W+H)-4 = 80 => W+H = 42)
  // W=28, H=14 for a wider cinematic look
  const TILE_SIZE = 54; 
  const BOARD_W = 28;
  const BOARD_H = 14;

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * TILE_SIZE;
    const totalH = BOARD_H * TILE_SIZE;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    // Top
    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * TILE_SIZE, y: startY });
    // Right
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * TILE_SIZE, y: startY + i * TILE_SIZE });
    // Bottom
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * TILE_SIZE, y: startY + (BOARD_H - 1) * TILE_SIZE });
    // Left
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * TILE_SIZE });

    return spaces;
  }, []);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, [0]);
    setZombieIndicators(zInd);
    setBombIndices(getRandomUnique(BOMB_COUNT, [0, ...zInd]));
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: 'bomb' | 'zombie') => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);
    if (type === 'bomb') setBombIndices([...newList, newPos]);
    else setZombieIndicators([...newList, newPos]);
  };

  const processMovement = useCallback((diceVal: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      if (bombIndices.includes(tempPos) && activeZombies.length > 0) {
        setBombAnimation({ active: true, pos: tempPos });
        setActiveZombies(prev => {
          if (prev.length === 0) return prev;
          let nearestIndex = 0;
          let minDistance = Infinity;
          prev.forEach((z, idx) => {
            const dist = Math.min(Math.abs(tempPos - z.pos), TOTAL_TILES - Math.abs(tempPos - z.pos));
            if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
          });
          const newZombies = [...prev];
          const target = { ...newZombies[nearestIndex] };
          target.health -= 1;
          if (target.health <= 0) {
            newZombies.splice(nearestIndex, 1);
            setZombiesKilled(k => {
                const total = k + 1;
                if (total >= 3) {
                    const t = tasks.find(x => x.text === 'Tiêu diệt 3 Quỷ lớn');
                    if (t) handleTaskComplete(t);
                }
                return total;
            });
          } else { newZombies[nearestIndex] = target; }
          return newZombies;
        });
        setIsShaking(true);
        setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceVal) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          const newZombie: BigZombie = {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          };
          setActiveZombies(prev => [...prev, newZombie]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }

        setActiveZombies(prev => {
          let gameOver = false;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + 2) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) { handleCaught(); return []; }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, tasks]);

  const handleCaught = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);
    setDicePosition(landing);
    const val = Math.floor(Math.random() * 6) + 1;
    if (val === 6) {
        const t = tasks.find(x => x.text === 'Lắc được xúc xắc 6');
        if (t) handleTaskComplete(t);
    }
    setTimeout(() => {
      setIsRolling(false);
      setDiceValue(val);
      setIsMoving(true);
      processMovement(val);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
    if (tasks.length <= 1) {
       setTasks(p => [...p, { id: Date.now().toString(), text: 'New Mission', completed: false, priority: 'medium' }]);
    }
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setZombiesKilled(k => k + activeZombies.length);
    setActiveZombies([]);
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
        const t = tasks.find(x => x.text === 'Nạp đầy 100 Alchemy');
        if (t) handleTaskComplete(t);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-500/10 text-red-600 dark:text-red-400';
        case 'medium': return 'bg-orange-500/10 text-orange-600 dark:text-orange-400';
        default: return 'bg-blue-500/10 text-blue-600 dark:text-blue-400';
    }
  }

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden ${isExploding ? 'bg-indigo-600/10' : ''}`}>

      {/* 80 Tile Ring Board - Wider and Larger Tiles */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombieIndicator = zombieIndicators.includes(s.id);
          const isStart = s.id === 0;
          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500
                ${isStart ? 'bg-indigo-50/90 dark:bg-indigo-950/30' : ''}
              `}
              style={{ left: s.x, top: s.y, width: TILE_SIZE, height: TILE_SIZE }}
            >
              <span className="text-[8px] opacity-10 absolute top-0.5 left-0.5 font-bold">{s.id + 1}</span>
              {isBomb && <span className="text-2xl drop-shadow-sm">{BOMB_ICON}</span>}
              {isZombieIndicator && <span className="text-2xl drop-shadow-sm">{ENEMY_ICON}</span>}
              {bloom && <span className="text-2xl bloom">{bloom}</span>}
              {isStart && !bloom && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}

        {/* Enemies */}
        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[z.pos].x + TILE_SIZE/2, 
            top: boardSpaces[z.pos].y + TILE_SIZE/2, 
            transform: 'translate(-50%, -60%)' 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/80 dark:bg-black/60 p-0.5 rounded-full px-2 border border-black/5">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.5)]' : 'bg-gray-300 dark:bg-gray-700'}`} />
                   ))}
                </div>
                <span className="drop-shadow-2xl animate-pulse" style={{ fontSize: TILE_SIZE * 1.5 }}>{ENEMY_ICON}</span>
             </div>
          </div>
        ))}

        {/* Player Character */}
        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto ${isMoving ? 'scale-110 -translate-y-4' : 'scale-100'}`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + TILE_SIZE/2, 
            top: (boardSpaces[currentPos]?.y || 0) + TILE_SIZE/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: TILE_SIZE * 1.6
          }}
        >
          <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">{ANIMAL_EMOJIS[animalIndex]}</span>
        </div>

        {/* VFX Layer */}
        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[currentPos]?.x + TILE_SIZE/2, 
            top: boardSpaces[currentPos]?.y + TILE_SIZE/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-6xl">{darkMode ? '🧄' : '💥'}</span>
          </div>
        )}
      </div>

      {/* Internal Ring UI - Minimalist Notion Inspired */}
      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-10 lg:gap-16 scale-90 lg:scale-100 bg-transparent">

          {/* Notion Minimalist Task Board */}
          <div className="glass-panel rounded-xl p-6 w-80 h-[520px] flex flex-col shadow-xl border border-black/5 dark:border-white/5 transition-colors">
            <div className="flex justify-between items-center mb-8">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block dark:text-white/40">Roll Bank</span>
                <span className="text-4xl font-semibold tabular-nums dark:text-white tracking-tight">{rollBank}</span>
              </div>
              <button 
                onClick={() => setDarkMode(!darkMode)} 
                className="w-10 h-10 flex items-center justify-center bg-transparent border border-black/5 dark:border-white/5 rounded-md hover:bg-black/5 dark:hover:bg-white/5 transition-all"
              >
                {darkMode ? '🧛🏻' : '🧟'}
              </button>
            </div>

            {/* Task Area - Simple and Clean */}
            <div className="flex-grow overflow-y-auto space-y-1 pr-1 custom-scrollbar">
              {!showHistory ? (
                tasks.map(t => (
                  <div 
                    key={t.id} 
                    onClick={() => handleTaskComplete(t)} 
                    className="group p-3 hover:bg-black/5 dark:hover:bg-white/5 rounded-lg cursor-pointer transition-colors flex items-center gap-4"
                  >
                    <div className="w-4 h-4 rounded-sm border border-black/20 dark:border-white/20 flex-shrink-0 group-hover:bg-indigo-500/10 group-hover:border-indigo-500 transition-all" />
                    <div className="flex flex-col">
                      <span className="text-[14px] font-medium text-gray-800 dark:text-zinc-100 leading-tight">{t.text}</span>
                      {t.priority && (
                          <span className={`text-[9px] font-bold uppercase mt-1 px-1.5 py-0.5 rounded-sm self-start ${getPriorityColor(t.priority)}`}>
                              {t.priority}
                          </span>
                      )}
                    </div>
                  </div>
                ))
              ) : (
                history.map(h => (
                  <div key={h.id} className="p-3 border-l border-indigo-500/20 opacity-50">
                    <span className="text-[13px] font-normal block line-through dark:text-white/60">{h.text}</span>
                    <span className="text-[10px] opacity-40 uppercase dark:text-white/30">{h.completedAt}</span>
                  </div>
                ))
              )}
            </div>

            {/* Notion-style Input */}
            <div className="mt-8 border-t border-black/5 dark:border-white/5 pt-6 flex flex-col gap-4">
              <div className="flex gap-2">
                {(['low', 'medium', 'high'] as const).map(p => (
                    <button 
                        key={p}
                        onClick={() => setNewTaskPriority(p)}
                        className={`flex-1 py-1.5 text-[9px] font-bold uppercase rounded border transition-all ${newTaskPriority === p ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-transparent border-black/5 dark:border-white/5 dark:text-white/40 hover:bg-black/5'}`}
                    >
                        {p}
                    </button>
                ))}
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowHistory(!showHistory)} className="px-3 h-10 border border-black/5 dark:border-white/5 rounded-md dark:text-white hover:bg-black/5 active:bg-black/10 transition-colors">
                    {showHistory ? 'Tasks' : 'Log'}
                </button>
                <form 
                    onSubmit={e => { 
                        e.preventDefault(); 
                        if(!newTask.trim()) return; 
                        setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); 
                        setNewTask(''); 
                    }} 
                    className="flex-1"
                >
                    <input 
                        value={newTask} 
                        onChange={e => setNewTask(e.target.value)} 
                        className="w-full h-10 bg-transparent border border-black/5 dark:border-white/5 rounded-md px-4 text-sm outline-none dark:text-white placeholder:opacity-30 focus:border-indigo-500/40 transition-all" 
                        placeholder="Add a new page..." 
                    />
                </form>
              </div>
            </div>
          </div>

          {/* Jar Control */}
          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} />
        </div>
      </div>

      <Dice3D value={diceValue} isRolling={isRolling} currentPos={dicePosition} onRoll={handleRoll} onDragEnd={setDicePosition} />

      <style>{`
        @keyframes bomb-drop {
          0% { transform: translate(-50%, -300%) scale(2); opacity: 0; }
          60% { transform: translate(-50%, -60%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(10); opacity: 0; filter: blur(30px); }
        }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }

        .sudoku-tile {
          border: 1px solid rgba(0,0,0,0.06);
          background: rgba(255,255,255,0.98);
          border-radius: 6px;
        }
        .dark .sudoku-tile {
          border: 1px solid rgba(255,255,255,0.03);
          background: rgba(22,22,22,0.98);
        }
        .glass-panel {
          background: rgba(255, 255, 255, 0.95);
          backdrop-filter: blur(40px);
        }
        .dark .glass-panel {
          background: rgba(20, 20, 20, 0.95);
        }
        .custom-scrollbar::-webkit-scrollbar { width: 3px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.1); border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.05); }
      `}</style>

    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 
const ZOMBIE_INDICATOR_COUNT = 6; // Reduced slightly for 60 tiles
const BOMB_COUNT = 6;           // Reduced slightly for 60 tiles
const MAX_ZOMBIE_HEALTH = 3;
const TOTAL_TILES = 60;
const SPAWN_BEHIND_OFFSET = 5;

const ANIMAL_EMOJIS = [
  '🦖', '🐉', '🐲', '🐟', '🐙', '🦈', '🐳', '🐋', '🐬', '🐘', 
  '🦄', '🦁', '🐯', '🐼', '🦊', '🐸', '🐨', '🦒', '🦓', '🦘'
];
const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePosition, setDicePosition] = useState({ x: window.innerWidth / 2, y: window.innerHeight / 2 });
  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });
  const [zombiesKilled, setZombiesKilled] = useState(0);

  // Theme icons: 🧛🏻 and 🧄 for Dark Mode
  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  // Adjust board layout for exactly 60 tiles (2*(W+H)-4 = 60 => W+H = 32)
  // W=20, H=12 gives a nice cinematic wide layout
  const TILE_SIZE = 64; 
  const BOARD_W = 20;
  const BOARD_H = 12;

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * TILE_SIZE;
    const totalH = BOARD_H * TILE_SIZE;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    // Top edge
    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * TILE_SIZE, y: startY });
    // Right edge
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * TILE_SIZE, y: startY + i * TILE_SIZE });
    // Bottom edge
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * TILE_SIZE, y: startY + (BOARD_H - 1) * TILE_SIZE });
    // Left edge
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * TILE_SIZE });

    return spaces;
  }, [TILE_SIZE]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, [0]);
    setZombieIndicators(zInd);
    setBombIndices(getRandomUnique(BOMB_COUNT, [0, ...zInd]));
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: 'bomb' | 'zombie') => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);
    if (type === 'bomb') setBombIndices([...newList, newPos]);
    else setZombieIndicators([...newList, newPos]);
  };

  const processMovement = useCallback((diceVal: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      if (bombIndices.includes(tempPos) && activeZombies.length > 0) {
        setBombAnimation({ active: true, pos: tempPos });
        setActiveZombies(prev => {
          if (prev.length === 0) return prev;
          let nearestIndex = 0;
          let minDistance = Infinity;
          prev.forEach((z, idx) => {
            const dist = Math.min(Math.abs(tempPos - z.pos), TOTAL_TILES - Math.abs(tempPos - z.pos));
            if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
          });
          const newZombies = [...prev];
          const target = { ...newZombies[nearestIndex] };
          target.health -= 1;
          if (target.health <= 0) {
            newZombies.splice(nearestIndex, 1);
            setZombiesKilled(k => {
                const total = k + 1;
                if (total >= 3) {
                    const t = tasks.find(x => x.text === 'Tiêu diệt 3 Quỷ lớn');
                    if (t) handleTaskComplete(t);
                }
                return total;
            });
          } else { newZombies[nearestIndex] = target; }
          return newZombies;
        });
        setIsShaking(true);
        setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceVal) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          const newZombie: BigZombie = {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          };
          setActiveZombies(prev => [...prev, newZombie]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }

        setActiveZombies(prev => {
          let gameOver = false;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + 2) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) { handleCaught(); return []; }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, tasks]);

  const handleCaught = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);
    setDicePosition(landing);
    const val = Math.floor(Math.random() * 6) + 1;
    if (val === 6) {
        const t = tasks.find(x => x.text === 'Lắc được xúc xắc 6');
        if (t) handleTaskComplete(t);
    }
    setTimeout(() => {
      setIsRolling(false);
      setDiceValue(val);
      setIsMoving(true);
      processMovement(val);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
    if (tasks.length <= 1) {
       setTasks(p => [...p, { id: Date.now().toString(), text: 'New Mission', completed: false, priority: 'medium' }]);
    }
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setZombiesKilled(k => k + activeZombies.length);
    setActiveZombies([]);
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
        const t = tasks.find(x => x.text === 'Nạp đầy 100 Alchemy');
        if (t) handleTaskComplete(t);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-500/10 text-red-600 dark:text-red-400';
        case 'medium': return 'bg-orange-500/10 text-orange-600 dark:text-orange-400';
        default: return 'bg-blue-500/10 text-blue-600 dark:text-blue-400';
    }
  }

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden ${isExploding ? 'bg-indigo-600/10' : ''}`}>

      {/* 60 Tile Board Board */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombieIndicator = zombieIndicators.includes(s.id);
          const isStart = s.id === 0;
          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500
                ${isStart ? 'bg-indigo-50/90 dark:bg-indigo-950/30' : ''}
              `}
              style={{ left: s.x, top: s.y, width: TILE_SIZE, height: TILE_SIZE }}
            >
              <span className="text-[10px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {isBomb && <span className="text-3xl drop-shadow-sm">{BOMB_ICON}</span>}
              {isZombieIndicator && <span className="text-3xl drop-shadow-sm">{ENEMY_ICON}</span>}
              {bloom && <span className="text-3xl bloom">{bloom}</span>}
              {isStart && !bloom && <span className="text-[10px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}

        {/* Enemies */}
        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[z.pos].x + TILE_SIZE/2, 
            top: boardSpaces[z.pos].y + TILE_SIZE/2, 
            transform: 'translate(-50%, -60%)' 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/80 dark:bg-black/60 p-0.5 rounded-full px-2 border border-black/5">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.5)]' : 'bg-gray-300 dark:bg-gray-700'}`} />
                   ))}
                </div>
                <span className="drop-shadow-2xl animate-pulse" style={{ fontSize: TILE_SIZE * 1.3 }}>{ENEMY_ICON}</span>
             </div>
          </div>
        ))}

        {/* Player Character */}
        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto ${isMoving ? 'scale-110 -translate-y-4' : 'scale-100'}`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + TILE_SIZE/2, 
            top: (boardSpaces[currentPos]?.y || 0) + TILE_SIZE/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: TILE_SIZE * 1.4
          }}
        >
          <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">{ANIMAL_EMOJIS[animalIndex]}</span>
        </div>

        {/* VFX Strike */}
        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[currentPos]?.x + TILE_SIZE/2, 
            top: boardSpaces[currentPos]?.y + TILE_SIZE/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-7xl">{darkMode ? '🧄' : '💥'}</span>
          </div>
        )}
      </div>

      {/* Internal Ring UI - Minimalist Notion Inspired */}
      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-10 lg:gap-16 scale-90 lg:scale-100 bg-transparent">

          {/* Notion Minimalist Task Board */}
          <div className="glass-panel rounded-xl p-6 w-80 h-[460px] flex flex-col shadow-xl border border-black/5 dark:border-white/5 transition-colors">
            <div className="flex justify-between items-center mb-8">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block dark:text-white/40">Roll Bank</span>
                <span className="text-4xl font-semibold tabular-nums dark:text-white tracking-tight">{rollBank}</span>
              </div>
              <button 
                onClick={() => setDarkMode(!darkMode)} 
                className="w-10 h-10 flex items-center justify-center bg-transparent border border-black/5 dark:border-white/5 rounded-md hover:bg-black/5 dark:hover:bg-white/5 transition-all"
              >
                {darkMode ? '🧛🏻' : '🧟'}
              </button>
            </div>

            {/* Task Area - Simple and Clean */}
            <div className="flex-grow overflow-y-auto space-y-1 pr-1 custom-scrollbar">
              {!showHistory ? (
                tasks.map(t => (
                  <div 
                    key={t.id} 
                    onClick={() => handleTaskComplete(t)} 
                    className="group p-3 hover:bg-black/5 dark:hover:bg-white/5 rounded-lg cursor-pointer transition-colors flex items-center gap-4"
                  >
                    <div className="w-4 h-4 rounded-sm border border-black/20 dark:border-white/20 flex-shrink-0 group-hover:bg-indigo-500/10 group-hover:border-indigo-500 transition-all" />
                    <div className="flex flex-col">
                      <span className="text-[14px] font-medium text-gray-800 dark:text-zinc-100 leading-tight">{t.text}</span>
                      {t.priority && (
                          <span className={`text-[9px] font-bold uppercase mt-1 px-1.5 py-0.5 rounded-sm self-start ${getPriorityColor(t.priority)}`}>
                              {t.priority}
                          </span>
                      )}
                    </div>
                  </div>
                ))
              ) : (
                history.map(h => (
                  <div key={h.id} className="p-3 border-l border-indigo-500/20 opacity-50">
                    <span className="text-[13px] font-normal block line-through dark:text-white/60">{h.text}</span>
                    <span className="text-[10px] opacity-40 uppercase dark:text-white/30">{h.completedAt}</span>
                  </div>
                ))
              )}
            </div>

            {/* Notion-style Input */}
            <div className="mt-8 border-t border-black/5 dark:border-white/5 pt-6 flex flex-col gap-4">
              <div className="flex gap-2">
                {(['low', 'medium', 'high'] as const).map(p => (
                    <button 
                        key={p}
                        onClick={() => setNewTaskPriority(p)}
                        className={`flex-1 py-1.5 text-[9px] font-bold uppercase rounded border transition-all ${newTaskPriority === p ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-transparent border-black/5 dark:border-white/5 dark:text-white/40 hover:bg-black/5'}`}
                    >
                        {p}
                    </button>
                ))}
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowHistory(!showHistory)} className="px-3 h-10 border border-black/5 dark:border-white/5 rounded-md dark:text-white hover:bg-black/5 active:bg-black/10 transition-colors">
                    {showHistory ? 'Tasks' : 'Log'}
                </button>
                <form 
                    onSubmit={e => { 
                        e.preventDefault(); 
                        if(!newTask.trim()) return; 
                        setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); 
                        setNewTask(''); 
                    }} 
                    className="flex-1"
                >
                    <input 
                        value={newTask} 
                        onChange={e => setNewTask(e.target.value)} 
                        className="w-full h-10 bg-transparent border border-black/5 dark:border-white/5 rounded-md px-4 text-sm outline-none dark:text-white placeholder:opacity-30 focus:border-indigo-500/40 transition-all" 
                        placeholder="Add mission..." 
                    />
                </form>
              </div>
            </div>
          </div>

          {/* Jar Control */}
          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} />
        </div>
      </div>

      <Dice3D value={diceValue} isRolling={isRolling} currentPos={dicePosition} onRoll={handleRoll} onDragEnd={setDicePosition} />

      <style>{`
        @keyframes bomb-drop {
          0% { transform: translate(-50%, -300%) scale(2); opacity: 0; }
          60% { transform: translate(-50%, -60%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(10); opacity: 0; filter: blur(30px); }
        }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }

        .sudoku-tile {
          border: 1px solid rgba(0,0,0,0.06);
          background: rgba(255,255,255,0.98);
          border-radius: 8px;
        }
        .dark .sudoku-tile {
          border: 1px solid rgba(255,255,255,0.03);
          background: rgba(22,22,22,0.98);
        }
        .glass-panel {
          background: rgba(255, 255, 255, 0.95);
          backdrop-filter: blur(40px);
        }
        .dark .glass-panel {
          background: rgba(20, 20, 20, 0.95);
        }
        .custom-scrollbar::-webkit-scrollbar { width: 3px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.1); border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.05); }
      `}</style>

    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 
const ZOMBIE_INDICATOR_COUNT = 6; 
const BOMB_COUNT = 6;           
const MAX_ZOMBIE_HEALTH = 3;
const TOTAL_TILES = 60;
const SPAWN_BEHIND_OFFSET = 5;

const ANIMAL_EMOJIS = [
  '🦖', '🐉', '🐲', '🐟', '🐙', '🦈', '🐳', '🐋', '🐬', '🐘', 
  '🦄', '🦁', '🐯', '🐼', '🦊', '🐸', '🐨', '🦒', '🦓', '🦘'
];
const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePosition, setDicePosition] = useState({ x: window.innerWidth / 2, y: window.innerHeight / 2 });
  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });
  const [zombiesKilled, setZombiesKilled] = useState(0);

  // Theme icons
  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  // Layout calculations for 60 tiles (W=20, H=12 => 2*(20+12)-4 = 60)
  // Responsive tile size calculation to avoid screen overflow
  const [tileSize, setTileSize] = useState(64);
  const BOARD_W = 20;
  const BOARD_H = 12;

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      const bestSize = Math.max(48, Math.min(horizontalLimit, verticalLimit, 72));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, [0]);
    setZombieIndicators(zInd);
    setBombIndices(getRandomUnique(BOMB_COUNT, [0, ...zInd]));
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: 'bomb' | 'zombie') => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);
    if (type === 'bomb') setBombIndices([...newList, newPos]);
    else setZombieIndicators([...newList, newPos]);
  };

  const processMovement = useCallback((diceVal: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      if (bombIndices.includes(tempPos) && activeZombies.length > 0) {
        setBombAnimation({ active: true, pos: tempPos });
        setActiveZombies(prev => {
          if (prev.length === 0) return prev;
          let nearestIndex = 0;
          let minDistance = Infinity;
          prev.forEach((z, idx) => {
            const dist = Math.min(Math.abs(tempPos - z.pos), TOTAL_TILES - Math.abs(tempPos - z.pos));
            if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
          });
          const newZombies = [...prev];
          const target = { ...newZombies[nearestIndex] };
          target.health -= 1;
          if (target.health <= 0) {
            newZombies.splice(nearestIndex, 1);
            setZombiesKilled(k => {
                const total = k + 1;
                if (total >= 3) {
                    const t = tasks.find(x => x.text === 'Tiêu diệt 3 Quỷ lớn');
                    if (t) handleTaskComplete(t);
                }
                return total;
            });
          } else { newZombies[nearestIndex] = target; }
          return newZombies;
        });
        setIsShaking(true);
        setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceVal) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          const newZombie: BigZombie = {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          };
          setActiveZombies(prev => [...prev, newZombie]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }

        setActiveZombies(prev => {
          let gameOver = false;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + 2) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) { handleCaught(); return []; }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, tasks]);

  const handleCaught = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);
    setDicePosition(landing);
    const val = Math.floor(Math.random() * 6) + 1;
    if (val === 6) {
        const t = tasks.find(x => x.text === 'Lắc được xúc xắc 6');
        if (t) handleTaskComplete(t);
    }
    setTimeout(() => {
      setIsRolling(false);
      setDiceValue(val);
      setIsMoving(true);
      processMovement(val);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
    if (tasks.length <= 1) {
       setTasks(p => [...p, { id: Date.now().toString(), text: 'New Mission', completed: false, priority: 'medium' }]);
    }
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setZombiesKilled(k => k + activeZombies.length);
    setActiveZombies([]);
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
        const t = tasks.find(x => x.text === 'Nạp đầy 100 Alchemy');
        if (t) handleTaskComplete(t);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden ${isExploding ? 'bg-indigo-600/10' : ''}`}>

      {/* 60 Tile Board Ring */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombieIndicator = zombieIndicators.includes(s.id);
          const isStart = s.id === 0;
          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500
                ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}
              `}
              style={{ left: s.x, top: s.y, width: tileSize, height: tileSize }}
            >
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {isBomb && <span className="drop-shadow-sm" style={{ fontSize: tileSize * 0.5 }}>{BOMB_ICON}</span>}
              {isZombieIndicator && <span className="drop-shadow-sm" style={{ fontSize: tileSize * 0.5 }}>{ENEMY_ICON}</span>}
              {bloom && <span className="bloom" style={{ fontSize: tileSize * 0.5 }}>{bloom}</span>}
              {isStart && !bloom && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}

        {/* Enemies Layer */}
        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[z.pos].x + tileSize/2, 
            top: boardSpaces[z.pos].y + tileSize/2, 
            transform: 'translate(-50%, -60%)' 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/90 dark:bg-black/80 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-200 dark:bg-gray-800'}`} />
                   ))}
                </div>
                <span className="drop-shadow-2xl animate-pulse" style={{ fontSize: tileSize * 1.2 }}>{ENEMY_ICON}</span>
             </div>
          </div>
        ))}

        {/* Player Piece */}
        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto ${isMoving ? 'scale-110 -translate-y-4' : 'scale-100'}`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, 
            top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: tileSize * 1.3
          }}
        >
          <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">{ANIMAL_EMOJIS[animalIndex]}</span>
        </div>

        {/* Explosion VFX */}
        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[currentPos]?.x + tileSize/2, 
            top: boardSpaces[currentPos]?.y + tileSize/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-7xl drop-shadow-2xl">{darkMode ? '✨' : '💥'}</span>
          </div>
        )}
      </div>

      {/* Internal UI Gap - Centered panels inside the ring */}
      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-8 lg:gap-12 scale-90 lg:scale-100">

          {/* Notion Inspired Minimalist Dashboard */}
          <div className="glass-panel rounded-lg p-5 w-72 h-[420px] flex flex-col shadow-sm border border-black/5 dark:border-white/5 bg-white/95 dark:bg-zinc-900/95">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span>
                <span className="text-3xl font-normal tabular-nums tracking-tight">{rollBank}</span>
              </div>
              <button 
                onClick={() => setDarkMode(!darkMode)} 
                className="w-8 h-8 flex items-center justify-center rounded hover:bg-black/5 dark:hover:bg-white/5 transition-all text-lg"
              >
                {darkMode ? '☀️' : '🌙'}
              </button>
            </div>

            {/* Clean Task Area */}
            <div className="flex-grow overflow-y-auto pr-1 custom-scrollbar space-y-px">
              {!showHistory ? (
                tasks.map(t => (
                  <div 
                    key={t.id} 
                    onClick={() => handleTaskComplete(t)} 
                    className="group p-2 hover:bg-black/5 dark:hover:bg-white/5 rounded transition-colors flex items-center gap-3 cursor-pointer"
                  >
                    <div className="w-3.5 h-3.5 rounded-sm border border-black/20 dark:border-white/20 flex-shrink-0 group-hover:bg-indigo-500/10 group-hover:border-indigo-500 transition-all" />
                    <div className="flex-grow overflow-hidden">
                      <div className="text-[13px] font-medium truncate opacity-90">{t.text}</div>
                      {t.priority && (
                          <div className={`inline-block text-[8px] font-black uppercase px-1 rounded-sm mt-0.5 border ${getPriorityColor(t.priority)}`}>
                              {t.priority}
                          </div>
                      )}
                    </div>
                  </div>
                ))
              ) : (
                history.map(h => (
                  <div key={h.id} className="p-2 border-l border-indigo-500/10 opacity-40">
                    <span className="text-[12px] line-through block">{h.text}</span>
                    <span className="text-[9px] uppercase tracking-tighter">{h.completedAt}</span>
                  </div>
                ))
              )}
            </div>

            {/* Input & Controls */}
            <div className="mt-4 pt-4 border-t border-black/5 dark:border-white/5 flex flex-col gap-3">
              <div className="flex gap-1">
                {(['low', 'medium', 'high'] as const).map(p => (
                    <button 
                        key={p}
                        onClick={() => setNewTaskPriority(p)}
                        className={`flex-1 py-1 text-[8px] font-bold uppercase rounded border transition-all ${newTaskPriority === p ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-transparent border-black/5 dark:border-white/5 opacity-50 hover:opacity-100 hover:bg-black/5'}`}
                    >
                        {p}
                    </button>
                ))}
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowHistory(!showHistory)} className="px-3 py-2 text-[10px] font-bold border border-black/5 dark:border-white/5 rounded hover:bg-black/5 transition-colors">
                    {showHistory ? 'Tasks' : 'Log'}
                </button>
                <form 
                    onSubmit={e => { 
                        e.preventDefault(); 
                        if(!newTask.trim()) return; 
                        setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); 
                        setNewTask(''); 
                    }} 
                    className="flex-1"
                >
                    <input 
                        value={newTask} 
                        onChange={e => setNewTask(e.target.value)} 
                        className="w-full h-8 bg-black/[0.02] dark:bg-white/[0.02] border border-black/5 dark:border-white/5 rounded px-3 text-[12px] outline-none focus:border-indigo-500/20 transition-all placeholder:opacity-20" 
                        placeholder="Add page..." 
                    />
                </form>
              </div>
            </div>
          </div>

          {/* Jar Area */}
          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} />
        </div>
      </div>

      <Dice3D value={diceValue} isRolling={isRolling} currentPos={dicePosition} onRoll={handleRoll} onDragEnd={setDicePosition} />

      <style>{`
        @keyframes bomb-drop {
          0% { transform: translate(-50%, -300%) scale(2); opacity: 0; }
          60% { transform: translate(-50%, -60%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(12); opacity: 0; filter: blur(40px); }
        }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }

        .sudoku-tile {
          border: 1px solid rgba(0,0,0,0.06);
          background: rgba(255,255,255,0.95);
          border-radius: 4px;
        }
        .dark .sudoku-tile {
          border: 1px solid rgba(255,255,255,0.03);
          background: rgba(18,18,18,0.95);
        }
        .glass-panel {
          backdrop-filter: blur(30px);
        }
        .custom-scrollbar::-webkit-scrollbar { width: 3px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.05); border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.03); }
      `}</style>

    </div>
  );
};

export default App;

export interface Task {
  id: string;
  text: string;
  completed: boolean;
  priority?: 'low' | 'medium' | 'high';
}

export interface BoardSpace {
  id: number;
  x: number;
  y: number;
  type: 'normal' | 'special';
}

export interface BigZombie {
  id: string;
  pos: number;
  health: number;
  isActive: boolean;
}

export interface PumpkinBoss {
  isActive: boolean;
  health: number;
}

import React, { useState, useRef, useEffect } from 'react';

interface AlchemyJarProps {
  count: number;
  max: number;
  isExploding: boolean;
  onExplode: () => void;
  isDeducting?: boolean;
}

export const AlchemyJar: React.FC<AlchemyJarProps> = ({ count, max, isExploding, onExplode, isDeducting }) => {
  const percent = Math.min(100, (count / max) * 100);
  const isFull = count >= max;
  const [holdProgress, setHoldProgress] = useState(0);
  const holdInterval = useRef<number | null>(null);

  const startHold = () => {
    if (!isFull || isExploding) return;
    holdInterval.current = window.setInterval(() => {
      setHoldProgress(prev => {
        if (prev >= 100) {
          if (holdInterval.current) clearInterval(holdInterval.current);
          onExplode();
          return 0;
        }
        return prev + 1;
      });
    }, 30);
  };

  const endHold = () => {
    if (holdInterval.current) {
      clearInterval(holdInterval.current);
      holdInterval.current = null;
    }
    setHoldProgress(0);
  };

  return (
    <div className="flex flex-col gap-4 h-[420px] w-28">
      <div className={`relative flex-grow bg-gray-50/50 dark:bg-black/20 border-8 border-gray-100 dark:border-white/5 rounded-b-[40px] rounded-t-[10px] overflow-hidden backdrop-blur-xl transition-all duration-700 ${isExploding ? 'scale-150 blur-3xl opacity-0' : 'scale-100'} ${isDeducting ? 'border-red-500/30' : ''}`}>
        <div 
          className={`absolute bottom-0 left-0 w-full transition-all duration-1000 ease-out ${isDeducting ? 'bg-red-400/80' : 'bg-indigo-500/80'}`}
          style={{ height: `${percent}%` }}
        >
          <div className="absolute inset-0 overflow-hidden">
             {[...Array(6)].map((_, i) => (
               <div 
                 key={i} 
                 className="absolute bottom-0 bg-white/20 rounded-full animate-bubble"
                 style={{
                   width: Math.random() * 8 + 4,
                   height: Math.random() * 8 + 4,
                   left: `${Math.random() * 100}%`,
                   animationDuration: `${Math.random() * 2 + 1}s`,
                   animationDelay: `${Math.random() * 2}s`
                 }}
               />
             ))}
          </div>
        </div>
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
          <span className={`text-xl font-black transition-colors ${isDeducting ? 'text-red-600' : 'text-indigo-900/50 dark:text-white/50'}`}>
            {isDeducting ? '-5%' : `${Math.floor(percent)}%`}
          </span>
        </div>
      </div>

      <div className="w-full relative h-16 flex flex-col justify-end">
        {holdProgress > 0 && (
          <div className="absolute top-0 left-0 w-full h-1 bg-gray-100 dark:bg-white/5 rounded-full overflow-hidden">
             <div className="h-full bg-indigo-500" style={{ width: `${holdProgress}%` }} />
          </div>
        )}
        <button
          onMouseDown={startHold}
          onMouseUp={endHold}
          onMouseLeave={endHold}
          onTouchStart={startHold}
          onTouchEnd={endHold}
          disabled={!isFull || isExploding}
          className={`w-full h-12 rounded-lg text-[9px] font-black uppercase tracking-[0.2em] transition-all
            ${isFull 
              ? 'bg-indigo-600 text-white shadow-lg cursor-pointer hover:scale-105 active:scale-95' 
              : 'bg-black/5 dark:bg-white/5 text-gray-400 cursor-not-allowed'
            }`}
        >
          {isFull ? (holdProgress > 0 ? 'Charging...' : 'Hold 3s') : 'Collect'}
        </button>
      </div>

      <style>{`
        @keyframes bubble {
          0% { transform: translateY(0) scale(0.5); opacity: 0; }
          50% { opacity: 0.5; }
          100% { transform: translateY(-100px) scale(1.5); opacity: 0; }
        }
        .animate-bubble { animation: bubble linear infinite; }
      `}</style>
    </div>
  );
};

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 
const ZOMBIE_INDICATOR_COUNT = 6; 
const BOMB_COUNT = 6;           
const PUMPKIN_COUNT = 10;
const MAX_ZOMBIE_HEALTH = 3;
const MAX_PUMPKIN_HEALTH = 5;
const TOTAL_TILES = 60;
const SPAWN_BEHIND_OFFSET = 5;

const ANIMAL_EMOJIS = [
  '🦖', '🐉', '🐲', '🐟', '🐙', '🦈', '🐳', '🐋', '🐬', '🐘', 
  '🦄', '🦁', '🐯', '🐼', '🦊', '🐸', '🐨', '🦒', '🦓', '🦘'
];
const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePosition, setDicePosition] = useState({ x: window.innerWidth / 2, y: window.innerHeight / 2 });
  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });
  const [zombiesKilled, setZombiesKilled] = useState(0);

  // Theme icons
  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(64);
  const BOARD_W = 20;
  const BOARD_H = 12;

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      const bestSize = Math.max(48, Math.min(horizontalLimit, verticalLimit, 72));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, [0]);
    const bInd = getRandomUnique(BOMB_COUNT, [0, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [0, ...zInd, ...bInd]);
    setZombieIndicators(zInd);
    setBombIndices(bInd);
    setPumpkinIndices(pInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: 'bomb' | 'zombie' | 'pumpkin') => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);
    if (type === 'bomb') setBombIndices([...newList, newPos]);
    else if (type === 'zombie') setZombieIndicators([...newList, newPos]);
    else setPumpkinIndices([...newList, newPos]);
  };

  const processMovement = useCallback((diceVal: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      if (bombIndices.includes(tempPos)) {
        setBombAnimation({ active: true, pos: tempPos });
        if (pumpkinBoss.isActive) {
           setPumpkinBoss(prev => {
             const newHealth = prev.health - 1;
             if (newHealth <= 0) return { isActive: false, health: 0 };
             return { ...prev, health: newHealth };
           });
        }
        setActiveZombies(prev => {
          if (prev.length === 0) return prev;
          let nearestIndex = 0;
          let minDistance = Infinity;
          prev.forEach((z, idx) => {
            const dist = Math.min(Math.abs(tempPos - z.pos), TOTAL_TILES - Math.abs(tempPos - z.pos));
            if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
          });
          const newZombies = [...prev];
          const target = { ...newZombies[nearestIndex] };
          target.health -= 1;
          if (target.health <= 0) {
            newZombies.splice(nearestIndex, 1);
            setZombiesKilled(k => k + 1);
          } else { newZombies[nearestIndex] = target; }
          return newZombies;
        });
        setIsShaking(true);
        setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceVal) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombies(prev => [...prev, {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          }]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }

        if (pumpkinIndices.includes(finalPos)) {
          setPumpkinBoss({ isActive: true, health: MAX_PUMPKIN_HEALTH });
          relocateItem(pumpkinIndices, finalPos, 'pumpkin');
        }

        setActiveZombies(prev => {
          let gameOver = false;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + 2) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) { handleCaught(); return []; }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, pumpkinBoss, pumpkinIndices]);

  const handleCaught = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;

    // Deduct 5% from jar with visual effect
    setIsDeducting(true);
    setJarCount(prev => Math.max(0, prev - 5));
    setTimeout(() => setIsDeducting(false), 800);

    setIsRolling(true);
    setRollBank(r => r - 1);
    setDicePosition(landing);
    const val = Math.floor(Math.random() * 6) + 1;
    setTimeout(() => {
      setIsRolling(false);
      setDiceValue(val);
      setIsMoving(true);
      processMovement(val);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombies([]);
    if (pumpkinBoss.isActive) setPumpkinBoss({ isActive: false, health: 0 });
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden ${isExploding ? 'bg-indigo-600/10' : ''}`}>

      {/* Tile Board */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombie = zombieIndicators.includes(s.id);
          const isPumpkin = pumpkinIndices.includes(s.id);
          const isStart = s.id === 0;
          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
              style={{ left: s.x, top: s.y, width: tileSize, height: tileSize }}
            >
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {isBomb && <span className="drop-shadow-sm" style={{ fontSize: tileSize * 0.5 }}>{BOMB_ICON}</span>}
              {isZombie && <span className="drop-shadow-sm" style={{ fontSize: tileSize * 0.5 }}>{ENEMY_ICON}</span>}
              {isPumpkin && <span className="drop-shadow-sm" style={{ fontSize: tileSize * 0.6 }}>🎃</span>}
              {bloom && <span className="bloom" style={{ fontSize: tileSize * 0.5 }}>{bloom}</span>}
              {isStart && !bloom && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}

        {/* Zombies */}
        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[z.pos].x + tileSize/2, 
            top: boardSpaces[z.pos].y + tileSize/2, 
            transform: 'translate(-50%, -60%)' 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/90 dark:bg-black/80 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-200 dark:bg-gray-800'}`} />
                   ))}
                </div>
                <span className="drop-shadow-2xl animate-pulse" style={{ fontSize: tileSize * 1.2 }}>{ENEMY_ICON}</span>
             </div>
          </div>
        ))}

        {/* Player */}
        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto ${isMoving ? 'scale-110 -translate-y-4' : 'scale-100'}`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, 
            top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: tileSize * 1.3
          }}
        >
          <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">{ANIMAL_EMOJIS[animalIndex]}</span>
        </div>

        {/* Bomb Strike */}
        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[currentPos]?.x + tileSize/2, 
            top: boardSpaces[currentPos]?.y + tileSize/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-7xl drop-shadow-2xl">{darkMode ? '✨' : '💥'}</span>
          </div>
        )}
      </div>

      {/* Internal UI Ring */}
      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-8 scale-90 lg:scale-100 h-[420px]">

          {/* Notion Dashboard - 1.5x width (288 * 1.5 = 432px) */}
          <div className="glass-panel rounded-lg p-5 w-[432px] flex flex-col shadow-sm border border-black/5 dark:border-white/5 bg-white/95 dark:bg-zinc-900/95">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span>
                <span className="text-3xl font-normal tabular-nums tracking-tight">{rollBank}</span>
              </div>
              <button onClick={() => setDarkMode(!darkMode)} className="w-8 h-8 flex items-center justify-center rounded hover:bg-black/5 transition-all text-lg">
                {darkMode ? '☀️' : '🌙'}
              </button>
            </div>

            <div className="flex-grow overflow-y-auto pr-1 custom-scrollbar space-y-px">
              {!showHistory ? tasks.map(t => (
                <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-2 hover:bg-black/5 rounded transition-colors flex items-center gap-3 cursor-pointer">
                  <div className="w-3.5 h-3.5 rounded-sm border border-black/20 group-hover:bg-indigo-500/10 group-hover:border-indigo-500 transition-all" />
                  <div className="flex-grow overflow-hidden">
                    <div className="text-[13px] font-medium truncate opacity-90">{t.text}</div>
                    {t.priority && <div className={`inline-block text-[8px] font-black uppercase px-1 rounded-sm mt-0.5 border ${getPriorityColor(t.priority)}`}>{t.priority}</div>}
                  </div>
                </div>
              )) : history.map(h => (
                <div key={h.id} className="p-2 border-l border-indigo-500/10 opacity-40">
                  <span className="text-[12px] line-through block">{h.text}</span>
                  <span className="text-[9px] uppercase tracking-tighter">{h.completedAt}</span>
                </div>
              ))}
            </div>

            <div className="mt-4 pt-4 border-t border-black/5 flex flex-col gap-3">
              <div className="flex gap-1">
                {(['low', 'medium', 'high'] as const).map(p => (
                    <button key={p} onClick={() => setNewTaskPriority(p)} className={`flex-1 py-1 text-[8px] font-bold uppercase rounded border transition-all ${newTaskPriority === p ? 'bg-indigo-600 border-indigo-600 text-white' : 'opacity-50 hover:bg-black/5'}`}>
                        {p}
                    </button>
                ))}
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowHistory(!showHistory)} className="px-3 py-2 text-[10px] font-bold border rounded hover:bg-black/5 transition-colors">{showHistory ? 'Tasks' : 'Log'}</button>
                <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); setNewTask(''); }} className="flex-1">
                    <input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full h-8 bg-black/[0.02] border rounded px-3 text-[12px] outline-none" placeholder="Add mission..." />
                </form>
              </div>
            </div>
          </div>

          {/* Jar Area - Matching Height */}
          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} />

          {/* Special Boss Side (Right Slot) */}
          <div className="w-72 flex items-center justify-center">
            {pumpkinBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow">
                <div className="flex gap-1 mb-4 bg-white/90 p-1.5 rounded-full shadow-lg border-2 border-orange-500/20">
                   {[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-3 h-1.5 rounded-full ${i < pumpkinBoss.health ? 'bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.6)]' : 'bg-gray-200'}`} />
                   ))}
                </div>
                <span className="text-[200px] drop-shadow-[0_25px_50px_rgba(249,115,22,0.4)] filter brightness-110">🎃</span>
                <span className="text-[10px] font-black uppercase tracking-[0.3em] text-orange-600 mt-2">Pumpkin Overlord</span>
              </div>
            )}
          </div>
        </div>
      </div>

      <Dice3D value={diceValue} isRolling={isRolling} currentPos={dicePosition} onRoll={handleRoll} onDragEnd={setDicePosition} />

      <style>{`
        @keyframes bounce-slow {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-20px); }
        }
        .animate-bounce-slow { animation: bounce-slow 3s ease-in-out infinite; }
        @keyframes bomb-drop {
          0% { transform: translate(-50%, -300%) scale(2); opacity: 0; }
          60% { transform: translate(-50%, -60%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(12); opacity: 0; filter: blur(40px); }
        }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.06); background: rgba(255,255,255,0.95); border-radius: 4px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.03); background: rgba(18,18,18,0.95); }
        .glass-panel { backdrop-filter: blur(30px); }
      `}</style>

    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 
const ZOMBIE_INDICATOR_COUNT = 6; 
const BOMB_COUNT = 6;           
const PUMPKIN_COUNT = 10;
const MAX_ZOMBIE_HEALTH = 3;
const MAX_PUMPKIN_HEALTH = 5;
const TOTAL_TILES = 60;
const SPAWN_BEHIND_OFFSET = 5;

const ANIMAL_EMOJIS = [
  '🦖', '🐉', '🐲', '🐟', '🐙', '🦈', '🐳', '🐋', '🐬', '🐘', 
  '🦄', '🦁', '🐯', '🐼', '🦊', '🐸', '🐨', '🦒', '🦓', '🦘'
];
const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePosition, setDicePosition] = useState({ x: window.innerWidth / 2, y: window.innerHeight / 2 });
  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });
  const [zombiesKilled, setZombiesKilled] = useState(0);

  // Theme icons
  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  // Map and Dice are strictly preserved as per request
  const [tileSize, setTileSize] = useState(64);
  const BOARD_W = 20;
  const BOARD_H = 12;

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      const bestSize = Math.max(48, Math.min(horizontalLimit, verticalLimit, 72));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, [0]);
    const bInd = getRandomUnique(BOMB_COUNT, [0, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [0, ...zInd, ...bInd]);
    setZombieIndicators(zInd);
    setBombIndices(bInd);
    setPumpkinIndices(pInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: 'bomb' | 'zombie' | 'pumpkin') => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);
    if (type === 'bomb') setBombIndices([...newList, newPos]);
    else if (type === 'zombie') setZombieIndicators([...newList, newPos]);
    else setPumpkinIndices([...newList, newPos]);
  };

  const processMovement = useCallback((diceVal: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      // Bombs damage zombies AND Pumpkin Boss
      if (bombIndices.includes(tempPos)) {
        setBombAnimation({ active: true, pos: tempPos });
        if (pumpkinBoss.isActive) {
           setPumpkinBoss(prev => {
             const newHealth = prev.health - 1;
             if (newHealth <= 0) return { isActive: false, health: 0 };
             return { ...prev, health: newHealth };
           });
        }
        setActiveZombies(prev => {
          if (prev.length === 0) return prev;
          let nearestIndex = 0;
          let minDistance = Infinity;
          prev.forEach((z, idx) => {
            const dist = Math.min(Math.abs(tempPos - z.pos), TOTAL_TILES - Math.abs(tempPos - z.pos));
            if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
          });
          const newZombies = [...prev];
          const target = { ...newZombies[nearestIndex] };
          target.health -= 1;
          if (target.health <= 0) {
            newZombies.splice(nearestIndex, 1);
            setZombiesKilled(k => k + 1);
          } else { newZombies[nearestIndex] = target; }
          return newZombies;
        });
        setIsShaking(true);
        setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceVal) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        // Final position triggers
        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombies(prev => [...prev, {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          }]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }

        // ONLY trigger Pumpkin Boss if landing exactly on pumpkin tile
        if (pumpkinIndices.includes(finalPos)) {
          setPumpkinBoss({ isActive: true, health: MAX_PUMPKIN_HEALTH });
          relocateItem(pumpkinIndices, finalPos, 'pumpkin');
        }

        setActiveZombies(prev => {
          let gameOver = false;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + 2) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) { handleCaught(); return []; }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, pumpkinBoss, pumpkinIndices]);

  const handleCaught = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;

    // Deduct 5% from jar ONLY if Pumpkin Boss is active
    if (pumpkinBoss.isActive) {
      setIsDeducting(true);
      setJarCount(prev => Math.max(0, prev - 5));
      setTimeout(() => setIsDeducting(false), 800);
    }

    setIsRolling(true);
    setRollBank(r => r - 1);
    setDicePosition(landing);
    const val = Math.floor(Math.random() * 6) + 1;
    setTimeout(() => {
      setIsRolling(false);
      setDiceValue(val);
      setIsMoving(true);
      processMovement(val);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombies([]);
    if (pumpkinBoss.isActive) setPumpkinBoss({ isActive: false, health: 0 });
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden ${isExploding ? 'bg-indigo-600/10' : ''}`}>

      {/* Tile Board Layer (Untouched layout) */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombie = zombieIndicators.includes(s.id);
          const isPumpkin = pumpkinIndices.includes(s.id);
          const isStart = s.id === 0;
          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
              style={{ left: s.x, top: s.y, width: tileSize, height: tileSize }}
            >
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {isBomb && <span className="drop-shadow-sm" style={{ fontSize: tileSize * 0.5 }}>{BOMB_ICON}</span>}
              {isZombie && <span className="drop-shadow-sm" style={{ fontSize: tileSize * 0.5 }}>{ENEMY_ICON}</span>}
              {isPumpkin && <span className="drop-shadow-sm" style={{ fontSize: tileSize * 0.6 }}>🎃</span>}
              {bloom && <span className="bloom" style={{ fontSize: tileSize * 0.5 }}>{bloom}</span>}
              {isStart && !bloom && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}

        {/* Zombies Layer */}
        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[z.pos].x + tileSize/2, 
            top: boardSpaces[z.pos].y + tileSize/2, 
            transform: 'translate(-50%, -60%)' 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/90 dark:bg-black/80 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-200 dark:bg-gray-800'}`} />
                   ))}
                </div>
                <span className="drop-shadow-2xl animate-pulse" style={{ fontSize: tileSize * 1.2 }}>{ENEMY_ICON}</span>
             </div>
          </div>
        ))}

        {/* Player Piece Layer */}
        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto ${isMoving ? 'scale-110 -translate-y-4' : 'scale-100'}`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, 
            top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: tileSize * 1.3
          }}
        >
          <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">{ANIMAL_EMOJIS[animalIndex]}</span>
        </div>

        {/* VFX Layer */}
        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[currentPos]?.x + tileSize/2, 
            top: boardSpaces[currentPos]?.y + tileSize/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-7xl drop-shadow-2xl">{darkMode ? '✨' : '💥'}</span>
          </div>
        )}
      </div>

      {/* UI Interaction Layer (Taskboard, Jar, Boss) */}
      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-6 scale-90 lg:scale-100 h-[420px]">

          {/* Notion Dashboard - 1.5x width to the left (432px) */}
          <div className="glass-panel rounded-lg p-5 w-[432px] flex flex-col shadow-sm border border-black/5 dark:border-white/5 bg-white/95 dark:bg-zinc-900/95">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span>
                <span className="text-3xl font-normal tabular-nums tracking-tight">{rollBank}</span>
              </div>
              <button onClick={() => setDarkMode(!darkMode)} className="w-8 h-8 flex items-center justify-center rounded hover:bg-black/5 transition-all text-lg">
                {darkMode ? '☀️' : '🌙'}
              </button>
            </div>

            <div className="flex-grow overflow-y-auto pr-1 custom-scrollbar space-y-px">
              {!showHistory ? tasks.map(t => (
                <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-2 hover:bg-black/5 rounded transition-colors flex items-center gap-3 cursor-pointer">
                  <div className="w-3.5 h-3.5 rounded-sm border border-black/20 group-hover:bg-indigo-500/10 group-hover:border-indigo-500 transition-all" />
                  <div className="flex-grow overflow-hidden">
                    <div className="text-[13px] font-medium truncate opacity-90">{t.text}</div>
                    {t.priority && <div className={`inline-block text-[8px] font-black uppercase px-1 rounded-sm mt-0.5 border ${getPriorityColor(t.priority)}`}>{t.priority}</div>}
                  </div>
                </div>
              )) : history.map(h => (
                <div key={h.id} className="p-2 border-l border-indigo-500/10 opacity-40">
                  <span className="text-[12px] line-through block">{h.text}</span>
                  <span className="text-[9px] uppercase tracking-tighter">{h.completedAt}</span>
                </div>
              ))}
            </div>

            <div className="mt-4 pt-4 border-t border-black/5 flex flex-col gap-3">
              <div className="flex gap-1">
                {(['low', 'medium', 'high'] as const).map(p => (
                    <button key={p} onClick={() => setNewTaskPriority(p)} className={`flex-1 py-1 text-[8px] font-bold uppercase rounded border transition-all ${newTaskPriority === p ? 'bg-indigo-600 border-indigo-600 text-white' : 'opacity-50 hover:bg-black/5'}`}>
                        {p}
                    </button>
                ))}
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowHistory(!showHistory)} className="px-3 py-2 text-[10px] font-bold border rounded hover:bg-black/5 transition-colors">{showHistory ? 'Tasks' : 'Log'}</button>
                <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); setNewTask(''); }} className="flex-1">
                    <input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full h-8 bg-black/[0.02] border rounded px-3 text-[12px] outline-none" placeholder="Add mission..." />
                </form>
              </div>
            </div>
          </div>

          {/* Jar Area - Matching Taskboard Height */}
          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} />

          {/* Pumpkin Boss Area - Right next to Jar, same height */}
          <div className="w-40 flex items-center justify-center relative h-[420px]">
            {pumpkinBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow h-full justify-end pb-8">
                <div className="flex gap-1 mb-4 bg-white/90 p-1 rounded-full shadow-lg border border-orange-500/20">
                   {[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-3 h-1 rounded-full ${i < pumpkinBoss.health ? 'bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.4)]' : 'bg-gray-200'}`} />
                   ))}
                </div>
                {/* Boss height approximately matches the jar visual height */}
                <span className="leading-none drop-shadow-[0_20px_40px_rgba(249,115,22,0.3)] filter brightness-110" style={{ fontSize: '180px' }}>🎃</span>
                <span className="text-[10px] font-black uppercase tracking-[0.3em] text-orange-600 mt-2 opacity-50">Boss Active</span>
              </div>
            )}
          </div>

          {/* Explicitly empty right side as requested */}
          <div className="flex-grow"></div>
        </div>
      </div>

      <Dice3D value={diceValue} isRolling={isRolling} currentPos={dicePosition} onRoll={handleRoll} onDragEnd={setDicePosition} />

      <style>{`
        @keyframes bounce-slow {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-15px); }
        }
        .animate-bounce-slow { animation: bounce-slow 2.5s ease-in-out infinite; }
        @keyframes bomb-drop {
          0% { transform: translate(-50%, -300%) scale(2); opacity: 0; }
          60% { transform: translate(-50%, -60%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(12); opacity: 0; filter: blur(40px); }
        }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.06); background: rgba(255,255,255,0.95); border-radius: 4px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.03); background: rgba(18,18,18,0.95); }
        .glass-panel { backdrop-filter: blur(30px); }
      `}</style>

    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 
const ZOMBIE_INDICATOR_COUNT = 6; 
const BOMB_COUNT = 6;           
const PUMPKIN_COUNT = 5; // Reduced to 5
const MAX_ZOMBIE_HEALTH = 3;
const MAX_PUMPKIN_HEALTH = 5;
const TOTAL_TILES = 60;
const SPAWN_BEHIND_OFFSET = 5;

const ANIMAL_EMOJIS = [
  '🦖', '🐉', '🐲', '🐟', '🐙', '🦈', '🐳', '🐋', '🐬', '🐘', 
  '🦄', '🦁', '🐯', '🐼', '🦊', '🐸', '🐨', '🦒', '🦓', '🦘'
];
const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePosition, setDicePosition] = useState({ x: window.innerWidth / 2, y: window.innerHeight / 2 });
  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  // Dimensions strictly preserved as requested
  const [tileSize, setTileSize] = useState(64);
  const BOARD_W = 20;
  const BOARD_H = 12;

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      const bestSize = Math.max(48, Math.min(horizontalLimit, verticalLimit, 72));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    setZombieIndicators(zInd);
    setBombIndices(bInd);
    setPumpkinIndices(pInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: 'bomb' | 'zombie' | 'pumpkin') => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);
    if (type === 'bomb') setBombIndices([...newList, newPos]);
    else if (type === 'zombie') setZombieIndicators([...newList, newPos]);
    else if (type === 'pumpkin') setPumpkinIndices([...newList, newPos]);
  };

  const processMovement = useCallback((diceVal: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      if (bombIndices.includes(tempPos)) {
        setBombAnimation({ active: true, pos: tempPos });
        if (pumpkinBoss.isActive) {
           setPumpkinBoss(prev => {
             const newHealth = prev.health - 1;
             if (newHealth <= 0) return { isActive: false, health: 0 };
             return { ...prev, health: newHealth };
           });
        }
        setActiveZombies(prev => {
          if (prev.length === 0) return prev;
          let nearestIndex = 0;
          let minDistance = Infinity;
          prev.forEach((z, idx) => {
            const dist = Math.min(Math.abs(tempPos - z.pos), TOTAL_TILES - Math.abs(tempPos - z.pos));
            if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
          });
          const newZombies = [...prev];
          const target = { ...newZombies[nearestIndex] };
          target.health -= 1;
          if (target.health <= 0) {
            newZombies.splice(nearestIndex, 1);
          } else { newZombies[nearestIndex] = target; }
          return newZombies;
        });
        setIsShaking(true);
        setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceVal) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombies(prev => [...prev, {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          }]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }

        // Logic update: land on pumpkin tile
        if (pumpkinIndices.includes(finalPos)) {
          if (pumpkinBoss.isActive) {
            // Heal if already active
            setPumpkinBoss(prev => ({ ...prev, health: MAX_PUMPKIN_HEALTH }));
          } else {
            // Spawn if not active
            setPumpkinBoss({ isActive: true, health: MAX_PUMPKIN_HEALTH });
          }
          relocateItem(pumpkinIndices, finalPos, 'pumpkin');
        }

        setActiveZombies(prev => {
          let gameOver = false;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + 2) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) { handleCaught(); return []; }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, pumpkinBoss, pumpkinIndices]);

  const handleCaught = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;

    if (pumpkinBoss.isActive) {
      setIsDeducting(true);
      setJarCount(prev => Math.max(0, prev - 5));
      setTimeout(() => setIsDeducting(false), 800);
    }

    setIsRolling(true);
    setRollBank(r => r - 1);
    setDicePosition(landing);
    const val = Math.floor(Math.random() * 6) + 1;
    setTimeout(() => {
      setIsRolling(false);
      setDiceValue(val);
      setIsMoving(true);
      processMovement(val);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombies([]);
    if (pumpkinBoss.isActive) setPumpkinBoss({ isActive: false, health: 0 });
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  // Theme icons
  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden ${isExploding ? 'bg-indigo-600/10' : ''}`}>

      {/* Tile Board Layer */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombie = zombieIndicators.includes(s.id);
          const isPumpkin = pumpkinIndices.includes(s.id);
          const isStart = s.id === 0;
          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
              style={{ left: s.x, top: s.y, width: tileSize, height: tileSize }}
            >
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {isBomb && <span className="drop-shadow-sm" style={{ fontSize: tileSize * 0.5 }}>{BOMB_ICON}</span>}
              {isZombie && <span className="drop-shadow-sm" style={{ fontSize: tileSize * 0.5 }}>{ENEMY_ICON}</span>}
              {isPumpkin && <span className="drop-shadow-sm" style={{ fontSize: tileSize * 0.6 }}>🎃</span>}
              {bloom && <span className="bloom" style={{ fontSize: tileSize * 0.5 }}>{bloom}</span>}
              {isStart && !bloom && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}

        {/* Zombies */}
        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[z.pos].x + tileSize/2, 
            top: boardSpaces[z.pos].y + tileSize/2, 
            transform: 'translate(-50%, -60%)' 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/90 dark:bg-black/80 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-200 dark:bg-gray-800'}`} />
                   ))}
                </div>
                <span className="drop-shadow-2xl animate-pulse" style={{ fontSize: tileSize * 1.2 }}>{ENEMY_ICON}</span>
             </div>
          </div>
        ))}

        {/* Player Piece */}
        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto ${isMoving ? 'scale-110 -translate-y-4' : 'scale-100'}`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, 
            top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: tileSize * 1.3
          }}
        >
          <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">{ANIMAL_EMOJIS[animalIndex]}</span>
        </div>

        {/* Explosion VFX */}
        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[currentPos]?.x + tileSize/2, 
            top: boardSpaces[currentPos]?.y + tileSize/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-7xl drop-shadow-2xl">{darkMode ? '✨' : '💥'}</span>
          </div>
        )}
      </div>

      {/* Main UI Container */}
      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-10 scale-90 lg:scale-100 h-[420px]">

          {/* Balanced Task Board (432px wide) */}
          <div className="glass-panel rounded-lg p-5 w-[432px] flex flex-col shadow-sm border border-black/5 dark:border-white/5 bg-white/95 dark:bg-zinc-900/95 transition-all">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span>
                <span className="text-3xl font-normal tabular-nums tracking-tight">{rollBank}</span>
              </div>
              <button onClick={() => setDarkMode(!darkMode)} className="w-8 h-8 flex items-center justify-center rounded hover:bg-black/5 transition-all text-lg">
                {darkMode ? '☀️' : '🌙'}
              </button>
            </div>

            <div className="flex-grow overflow-y-auto pr-1 custom-scrollbar space-y-px">
              {!showHistory ? tasks.map(t => (
                <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-2 hover:bg-black/5 rounded transition-colors flex items-center gap-3 cursor-pointer">
                  <div className="w-3.5 h-3.5 rounded-sm border border-black/20 group-hover:bg-indigo-500/10 group-hover:border-indigo-500 transition-all" />
                  <div className="flex-grow overflow-hidden">
                    <div className="text-[13px] font-medium truncate opacity-90">{t.text}</div>
                    {t.priority && <div className={`inline-block text-[8px] font-black uppercase px-1 rounded-sm mt-0.5 border ${getPriorityColor(t.priority)}`}>{t.priority}</div>}
                  </div>
                </div>
              )) : history.map(h => (
                <div key={h.id} className="p-2 border-l border-indigo-500/10 opacity-40">
                  <span className="text-[12px] line-through block">{h.text}</span>
                  <span className="text-[9px] uppercase tracking-tighter">{h.completedAt}</span>
                </div>
              ))}
            </div>

            <div className="mt-4 pt-4 border-t border-black/5 flex flex-col gap-3">
              <div className="flex gap-1">
                {(['low', 'medium', 'high'] as const).map(p => (
                    <button key={p} onClick={() => setNewTaskPriority(p)} className={`flex-1 py-1 text-[8px] font-bold uppercase rounded border transition-all ${newTaskPriority === p ? 'bg-indigo-600 border-indigo-600 text-white' : 'opacity-50 hover:bg-black/5'}`}>
                        {p}
                    </button>
                ))}
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowHistory(!showHistory)} className="px-3 py-2 text-[10px] font-bold border rounded hover:bg-black/5 transition-colors">{showHistory ? 'Tasks' : 'Log'}</button>
                <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); setNewTask(''); }} className="flex-1">
                    <input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full h-8 bg-black/[0.02] border rounded px-3 text-[12px] outline-none" placeholder="Add mission..." />
                </form>
              </div>
            </div>
          </div>

          {/* Jar Area (112px wide) */}
          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} />

          {/* Pumpkin Boss Area (Spaced for no-cramped feeling) */}
          <div className="w-56 flex items-center justify-center relative h-[420px]">
            {pumpkinBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow h-full justify-end pb-12">
                <div className="flex gap-1 mb-6 bg-white/90 p-1.5 rounded-full shadow-lg border border-orange-500/10 backdrop-blur-md">
                   {[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-3.5 h-1.5 rounded-full transition-all duration-500 ${i < pumpkinBoss.health ? 'bg-orange-500 shadow-[0_0_10px_rgba(249,115,22,0.5)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                {/* Visual balance: Boss is large but doesn't overlap the jar */}
                <span className="leading-none drop-shadow-[0_30px_60px_rgba(249,115,22,0.4)] filter brightness-110" style={{ fontSize: '200px' }}>🎃</span>
                <span className="text-[10px] font-black uppercase tracking-[0.4em] text-orange-600/60 mt-4">Overlord</span>
              </div>
            )}
          </div>

          {/* Explicitly empty right side for spatial balance */}
          <div className="w-12 lg:w-24"></div>
        </div>
      </div>

      <Dice3D value={diceValue} isRolling={isRolling} currentPos={dicePosition} onRoll={handleRoll} onDragEnd={setDicePosition} />

      <style>{`
        @keyframes bounce-slow {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-20px); }
        }
        .animate-bounce-slow { animation: bounce-slow 3s ease-in-out infinite; }
        @keyframes bomb-drop {
          0% { transform: translate(-50%, -300%) scale(2); opacity: 0; }
          60% { transform: translate(-50%, -60%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(14); opacity: 0; filter: blur(50px); }
        }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.06); background: rgba(255,255,255,0.95); border-radius: 4px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.03); background: rgba(18,18,18,0.95); }
        .glass-panel { backdrop-filter: blur(40px); }
      `}</style>

    </div>
  );
};

export default App;

export interface Task {
  id: string;
  text: string;
  completed: boolean;
  priority?: 'low' | 'medium' | 'high';
}

export interface BoardSpace {
  id: number;
  x: number;
  y: number;
  type: 'normal' | 'special';
}

export interface BigZombie {
  id: string;
  pos: number;
  health: number;
  isActive: boolean;
}

export interface PumpkinBoss {
  isActive: boolean;
  health: number;
}

export interface DemonBoss {
  isActive: boolean;
  health: number;
}

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 
const ZOMBIE_INDICATOR_COUNT = 6; 
const BOMB_COUNT = 6;           
const PUMPKIN_COUNT = 5; 
const DEMON_COUNT = 5; // Added 5 demon tiles
const MAX_ZOMBIE_HEALTH = 3; // Reset to 3
const MAX_PUMPKIN_HEALTH = 3; // Reset to 3
const MAX_DEMON_HEALTH = 2; // Demon has 2 HP
const TOTAL_TILES = 60;
const SPAWN_BEHIND_OFFSET = 5;

const ANIMAL_EMOJIS = [
  '🦖', '🐉', '🐲', '🐟', '🐙', '🦈', '🐳', '🐋', '🐬', '🐘', 
  '🦄', '🦁', '🐯', '🐼', '🦊', '🐸', '🐨', '🦒', '🦓', '🦘'
];
const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePosition, setDicePosition] = useState({ x: window.innerWidth / 2, y: window.innerHeight / 2 });
  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(64);
  const BOARD_W = 20;
  const BOARD_H = 12;

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      const bestSize = Math.max(48, Math.min(horizontalLimit, verticalLimit, 72));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    setZombieIndicators(zInd);
    setBombIndices(bInd);
    setPumpkinIndices(pInd);
    setDemonIndices(dInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: 'bomb' | 'zombie' | 'pumpkin' | 'demon') => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);
    if (type === 'bomb') setBombIndices([...newList, newPos]);
    else if (type === 'zombie') setZombieIndicators([...newList, newPos]);
    else if (type === 'pumpkin') setPumpkinIndices([...newList, newPos]);
    else if (type === 'demon') setDemonIndices([...newList, newPos]);
  };

  const processMovement = useCallback((diceVal: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      // Bombs affect all active enemies
      if (bombIndices.includes(tempPos)) {
        setBombAnimation({ active: true, pos: tempPos });

        // Damage bosses
        if (pumpkinBoss.isActive) {
          setPumpkinBoss(prev => {
            const newHealth = prev.health - 1;
            return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
          });
        }
        if (demonBoss.isActive) {
          setDemonBoss(prev => {
            const newHealth = prev.health - 1;
            return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
          });
        }

        // Damage zombies
        setActiveZombies(prev => {
          if (prev.length === 0) return prev;
          let nearestIndex = 0;
          let minDistance = Infinity;
          prev.forEach((z, idx) => {
            const dist = Math.min(Math.abs(tempPos - z.pos), TOTAL_TILES - Math.abs(tempPos - z.pos));
            if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
          });
          const newZombies = [...prev];
          const target = { ...newZombies[nearestIndex] };
          target.health -= 1;
          if (target.health <= 0) {
            newZombies.splice(nearestIndex, 1);
          } else { newZombies[nearestIndex] = target; }
          return newZombies;
        });

        setIsShaking(true);
        setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceVal) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombies(prev => [...prev, {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          }]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }

        if (pumpkinIndices.includes(finalPos)) {
          setPumpkinBoss(prev => ({ isActive: true, health: prev.isActive ? MAX_PUMPKIN_HEALTH : MAX_PUMPKIN_HEALTH }));
          relocateItem(pumpkinIndices, finalPos, 'pumpkin');
        }

        if (demonIndices.includes(finalPos)) {
          setDemonBoss(prev => ({ isActive: true, health: prev.isActive ? MAX_DEMON_HEALTH : MAX_DEMON_HEALTH }));
          relocateItem(demonIndices, finalPos, 'demon');
        }

        setActiveZombies(prev => {
          let gameOver = false;
          // Demon Boss buff: Move 3 steps instead of 2
          const moveSteps = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + moveSteps) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) { handleCaught(); return []; }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, pumpkinBoss, demonBoss, pumpkinIndices, demonIndices]);

  const handleCaught = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;

    if (pumpkinBoss.isActive) {
      setIsDeducting(true);
      setJarCount(prev => Math.max(0, prev - 5));
      setTimeout(() => setIsDeducting(false), 800);
    }

    setIsRolling(true);
    setRollBank(r => r - 1);
    setDicePosition(landing);
    const val = Math.floor(Math.random() * 6) + 1;
    setTimeout(() => {
      setIsRolling(false);
      setDiceValue(val);
      setIsMoving(true);
      processMovement(val);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden ${isExploding ? 'bg-indigo-600/10' : ''}`}>

      {/* Tile Board Layer */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombie = zombieIndicators.includes(s.id);
          const isPumpkin = pumpkinIndices.includes(s.id);
          const isDemon = demonIndices.includes(s.id);
          const isStart = s.id === 0;

          // Determine which icon to show (only one allowed)
          let icon = null;
          if (isBomb) icon = BOMB_ICON;
          else if (isZombie) icon = ENEMY_ICON;
          else if (isPumpkin) icon = '🎃';
          else if (isDemon) icon = '👹';

          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
              style={{ left: s.x, top: s.y, width: tileSize, height: tileSize }}
            >
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {icon && (
                <span className="drop-shadow-sm opacity-40" style={{ fontSize: tileSize * 0.55 }}>
                  {icon}
                </span>
              )}
              {bloom && <span className="bloom absolute" style={{ fontSize: tileSize * 0.5 }}>{bloom}</span>}
              {isStart && !bloom && !icon && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}

        {/* Zombies */}
        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[z.pos].x + tileSize/2, 
            top: boardSpaces[z.pos].y + tileSize/2, 
            transform: `translate(-50%, -60%) scale(${demonBoss.isActive ? 2.0 : 1.0})` 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/90 dark:bg-black/80 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-200 dark:bg-gray-800'}`} />
                   ))}
                </div>
                <span className="drop-shadow-2xl animate-pulse" style={{ fontSize: tileSize * 1.2 }}>{ENEMY_ICON}</span>
             </div>
          </div>
        ))}

        {/* Player Piece (No movement animations as requested) */}
        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, 
            top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: tileSize * 1.3
          }}
        >
          <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">{ANIMAL_EMOJIS[animalIndex]}</span>
        </div>

        {/* Explosion VFX */}
        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[currentPos]?.x + tileSize/2, 
            top: boardSpaces[currentPos]?.y + tileSize/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-7xl drop-shadow-2xl">{darkMode ? '✨' : '💥'}</span>
          </div>
        )}
      </div>

      {/* Main UI Container */}
      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-10 scale-90 lg:scale-100 h-[420px]">

          {/* Balanced Task Board */}
          <div className="glass-panel rounded-lg p-5 w-[432px] flex flex-col shadow-sm border border-black/5 dark:border-white/5 bg-white/95 dark:bg-zinc-900/95 transition-all">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span>
                <span className="text-3xl font-normal tabular-nums tracking-tight">{rollBank}</span>
              </div>
              <button onClick={() => setDarkMode(!darkMode)} className="w-8 h-8 flex items-center justify-center rounded hover:bg-black/5 transition-all text-lg">
                {darkMode ? '☀️' : '🌙'}
              </button>
            </div>

            <div className="flex-grow overflow-y-auto pr-1 custom-scrollbar space-y-px">
              {!showHistory ? tasks.map(t => (
                <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-2 hover:bg-black/5 rounded transition-colors flex items-center gap-3 cursor-pointer">
                  <div className="w-3.5 h-3.5 rounded-sm border border-black/20 group-hover:bg-indigo-500/10 group-hover:border-indigo-500 transition-all" />
                  <div className="flex-grow overflow-hidden">
                    <div className="text-[13px] font-medium truncate opacity-90">{t.text}</div>
                    {t.priority && <div className={`inline-block text-[8px] font-black uppercase px-1 rounded-sm mt-0.5 border ${getPriorityColor(t.priority)}`}>{t.priority}</div>}
                  </div>
                </div>
              )) : history.map(h => (
                <div key={h.id} className="p-2 border-l border-indigo-500/10 opacity-40">
                  <span className="text-[12px] line-through block">{h.text}</span>
                  <span className="text-[9px] uppercase tracking-tighter">{h.completedAt}</span>
                </div>
              ))}
            </div>

            <div className="mt-4 pt-4 border-t border-black/5 flex flex-col gap-3">
              <div className="flex gap-1">
                {(['low', 'medium', 'high'] as const).map(p => (
                    <button key={p} onClick={() => setNewTaskPriority(p)} className={`flex-1 py-1 text-[8px] font-bold uppercase rounded border transition-all ${newTaskPriority === p ? 'bg-indigo-600 border-indigo-600 text-white' : 'opacity-50 hover:bg-black/5'}`}>
                        {p}
                    </button>
                ))}
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowHistory(!showHistory)} className="px-3 py-2 text-[10px] font-bold border rounded hover:bg-black/5 transition-colors">{showHistory ? 'Tasks' : 'Log'}</button>
                <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); setNewTask(''); }} className="flex-1">
                    <input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full h-8 bg-black/[0.02] border rounded px-3 text-[12px] outline-none" placeholder="Add mission..." />
                </form>
              </div>
            </div>
          </div>

          {/* Jar Area */}
          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} />

          {/* Bosses Area (Right of Jar, stacked vertically) */}
          <div className="w-64 flex flex-col gap-6 items-center justify-center relative h-[420px]">
            {/* Pumpkin Boss - Top, 1/2 height of jar */}
            {pumpkinBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow h-1/2 justify-center">
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-orange-500/20 backdrop-blur-md">
                   {[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < pumpkinBoss.health ? 'bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl filter brightness-110" style={{ fontSize: '110px' }}>🎃</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-orange-600/60 mt-1">Pumpkin Boss</span>
              </div>
            )}

            {/* Demon Boss - Bottom */}
            {demonBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow h-1/2 justify-center" style={{ animationDelay: '-1.5s' }}>
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-red-500/20 backdrop-blur-md">
                   {[...Array(MAX_DEMON_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < demonBoss.health ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl filter brightness-110" style={{ fontSize: '110px' }}>👹</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-red-600/60 mt-1">Demon Buff</span>
              </div>
            )}
          </div>

          {/* Spacing to Map: Balance with Taskboard spacing */}
          <div className="w-12"></div>
        </div>
      </div>

      <Dice3D value={diceValue} isRolling={isRolling} currentPos={dicePosition} onRoll={handleRoll} onDragEnd={setDicePosition} />

      <style>{`
        @keyframes bounce-slow {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-12px); }
        }
        .animate-bounce-slow { animation: bounce-slow 3s ease-in-out infinite; }
        @keyframes bomb-drop {
          0% { transform: translate(-50%, -300%) scale(2); opacity: 0; }
          60% { transform: translate(-50%, -60%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(14); opacity: 0; filter: blur(50px); }
        }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.06); background: rgba(255,255,255,0.95); border-radius: 4px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.03); background: rgba(18,18,18,0.95); }
        .glass-panel { backdrop-filter: blur(40px); }
      `}</style>

    </div>
  );
};

