import React, { useState, useRef, useEffect } from 'react';

interface Dice3DProps {
  value: number;
  isRolling: boolean;
  onRoll: (landingPos: { x: number; y: number }) => void;
  onDragEnd: (finalPos: { x: number; y: number }) => void;
  currentPos: { x: number; y: number };
  color?: string;
}

export const Dice3D: React.FC<Dice3DProps> = ({ value, isRolling, onRoll, onDragEnd, currentPos, color = 'rgba(255, 255, 255, 0.3)' }) => {
  const [pos, setPos] = useState(currentPos);
  const [isDragging, setIsDragging] = useState(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const elementPosStart = useRef({ x: 0, y: 0 });

  useEffect(() => {
    if (!isRolling && !isDragging) {
      setPos(currentPos);
    }
  }, [currentPos, isRolling, isDragging]);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (isRolling) return;
    setIsDragging(true);
    dragStart.current = { x: e.clientX, y: e.clientY };
    elementPosStart.current = { x: pos.x, y: pos.y };
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;
      const dx = e.clientX - dragStart.current.x;
      const dy = e.clientY - dragStart.current.y;
      setPos({
        x: elementPosStart.current.x + dx,
        y: elementPosStart.current.y + dy
      });
    };

    const handleMouseUp = () => {
      if (isDragging) {
        setIsDragging(false);
        onDragEnd(pos);
      }
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, pos, onDragEnd]);

  const getRotation = (v: number) => {
    switch (v) {
      case 1: return 'rotateX(0deg) rotateY(0deg)';
      case 2: return 'rotateY(-90deg)';
      case 3: return 'rotateY(90deg)';
      case 4: return 'rotateY(180deg)';
      case 5: return 'rotateX(-90deg)';
      case 6: return 'rotateX(90deg)';
      default: return 'rotateX(0deg)';
    }
  };

  const rollingRotation = isRolling 
    ? `rotateX(${Math.random() * 720 + 360}deg) rotateY(${Math.random() * 720 + 360}deg)`
    : getRotation(value);

  const triggerRoll = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (isRolling) return;
    const landingX = Math.max(100, Math.min(window.innerWidth - 100, pos.x + (Math.random() - 0.5) * 100));
    const landingY = Math.max(100, Math.min(window.innerHeight - 100, pos.y + (Math.random() - 0.5) * 100));
    onRoll({ x: landingX, y: landingY });
  };

  const faceStyle = {
    background: color,
  };

  return (
    <div 
      className={`fixed z-[60] transition-all ${isRolling ? 'duration-[1200ms]' : 'duration-75'} select-none cursor-grab active:cursor-grabbing`}
      style={{ 
        left: `${pos.x}px`, 
        top: `${pos.y}px`,
        transform: `translate(-50%, -50%) scale(${isDragging ? 1.1 : (isRolling ? 1.3 : 1)})`
      }}
      onMouseDown={handleMouseDown}
      onDoubleClick={triggerRoll}
    >
      <div className="dice-container">
        <div className="dice" style={{ transform: rollingRotation }}>
          <div className="dice-face front" style={faceStyle}><div className="dot"></div></div>
          <div className="dice-face back" style={faceStyle}>
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '15%', left: '60%' }}></div>
             <div className="dot" style={{ top: '60%', left: '15%' }}></div>
             <div className="dot" style={{ top: '60%', left: '60%' }}></div>
          </div>
          <div className="dice-face right" style={faceStyle}>
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '40%', left: '40%' }}></div>
             <div className="dot" style={{ top: '65%', left: '65%' }}></div>
          </div>
          <div className="dice-face left" style={faceStyle}>
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '65%', left: '65%' }}></div>
          </div>
          <div className="dice-face top" style={faceStyle}>
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '15%', left: '60%' }}></div>
             <div className="dot" style={{ top: '40%', left: '40%' }}></div>
             <div className="dot" style={{ top: '65%', left: '15%' }}></div>
             <div className="dot" style={{ top: '65%', left: '65%' }}></div>
          </div>
          <div className="dice-face bottom" style={faceStyle}>
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '15%', left: '60%' }}></div>
             <div className="dot" style={{ top: '40%', left: '15%' }}></div>
             <div className="dot" style={{ top: '40%', left: '60%' }}></div>
             <div className="dot" style={{ top: '65%', left: '15%' }}></div>
             <div className="dot" style={{ top: '65%', left: '65%' }}></div>
          </div>
        </div>
      </div>
      {!isRolling && (
          <div className="absolute -bottom-6 left-1/2 -translate-x-1/2 text-[9px] font-bold opacity-30 uppercase tracking-tighter whitespace-nowrap">Double Click to Roll</div>
      )}
    </div>
  );
};

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 
const ZOMBIE_INDICATOR_COUNT = 6; 
const BOMB_COUNT = 6;           
const PUMPKIN_COUNT = 5; 
const DEMON_COUNT = 5; 
const CLOVER_COUNT = 5; // 5 Clovers for healing
const MAX_ZOMBIE_HEALTH = 5; // Increased to 5
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; // Increased to 3
const MAX_PLAYER_HEALTH = 5; // Player has 5 HP
const TOTAL_TILES = 60;
const SPAWN_BEHIND_OFFSET = 5;

const ANIMAL_EMOJIS = [
  '🦖', '🐉', '🐲', '🐟', '🐙', '🦈', '🐳', '🐋', '🐬', '🐘', 
  '🦄', '🦁', '🐯', '🐼', '🦊', '🐸', '🐨', '🦒', '🦓', '🦘'
];
const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.3)', // Default
  'rgba(199, 210, 254, 0.5)', // Indigo
  'rgba(254, 202, 202, 0.5)', // Red
  'rgba(167, 243, 208, 0.5)', // Green
  'rgba(253, 230, 138, 0.5)', // Amber
];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePosition, setDicePosition] = useState({ x: window.innerWidth / 2, y: window.innerHeight / 2 });
  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(64);
  const BOARD_W = 20;
  const BOARD_H = 12;

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      const bestSize = Math.max(48, Math.min(horizontalLimit, verticalLimit, 72));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    setZombieIndicators(zInd);
    setBombIndices(bInd);
    setPumpkinIndices(pInd);
    setDemonIndices(dInd);
    setCloverIndices(cInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: 'bomb' | 'zombie' | 'pumpkin' | 'demon' | 'clover') => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);
    if (type === 'bomb') setBombIndices([...newList, newPos]);
    else if (type === 'zombie') setZombieIndicators([...newList, newPos]);
    else if (type === 'pumpkin') setPumpkinIndices([...newList, newPos]);
    else if (type === 'demon') setDemonIndices([...newList, newPos]);
    else if (type === 'clover') setCloverIndices([...newList, newPos]);
  };

  const processMovement = useCallback((diceVal: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      // Clover healing logic - occurs when passing through
      if (cloverIndices.includes(tempPos)) {
        setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1));
        relocateItem(cloverIndices, tempPos, 'clover');
      }

      if (bombIndices.includes(tempPos)) {
        setBombAnimation({ active: true, pos: tempPos });
        if (pumpkinBoss.isActive) {
          setPumpkinBoss(prev => {
            const newHealth = prev.health - 1;
            return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
          });
        }
        if (demonBoss.isActive) {
          setDemonBoss(prev => {
            const newHealth = prev.health - 1;
            return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
          });
        }
        setActiveZombies(prev => {
          if (prev.length === 0) return prev;
          let nearestIndex = 0;
          let minDistance = Infinity;
          prev.forEach((z, idx) => {
            const dist = Math.min(Math.abs(tempPos - z.pos), TOTAL_TILES - Math.abs(tempPos - z.pos));
            if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
          });
          const newZombies = [...prev];
          const target = { ...newZombies[nearestIndex] };
          target.health -= 1;
          if (target.health <= 0) {
            newZombies.splice(nearestIndex, 1);
          } else { newZombies[nearestIndex] = target; }
          return newZombies;
        });
        setIsShaking(true);
        setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceVal) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombies(prev => [...prev, {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          }]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }

        if (pumpkinIndices.includes(finalPos)) {
          setPumpkinBoss(prev => ({ isActive: true, health: MAX_PUMPKIN_HEALTH }));
          relocateItem(pumpkinIndices, finalPos, 'pumpkin');
        }

        if (demonIndices.includes(finalPos)) {
          setDemonBoss(prev => ({ isActive: true, health: MAX_DEMON_HEALTH }));
          relocateItem(demonIndices, finalPos, 'demon');
        }

        setActiveZombies(prev => {
          let gameOver = false;
          const moveSteps = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + moveSteps) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) {
            setPlayerHealth(h => {
              const next = h - 1;
              if (next <= 0) {
                handleGameOver();
                return MAX_PLAYER_HEALTH;
              }
              return next;
            });
            return [];
          }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, pumpkinBoss, demonBoss, pumpkinIndices, demonIndices, cloverIndices]);

  const handleGameOver = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;

    if (pumpkinBoss.isActive) {
      setIsDeducting(true);
      setJarCount(prev => Math.max(0, prev - 5));
      setTimeout(() => setIsDeducting(false), 800);
    }

    setIsRolling(true);
    setRollBank(r => r - 1);
    setDicePosition(landing);
    const val = Math.floor(Math.random() * 6) + 1;
    setTimeout(() => {
      setIsRolling(false);
      setDiceValue(val);
      setIsMoving(true);
      processMovement(val);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombies([]);
    // Jar kills ALL bosses as requested
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden ${isExploding ? 'bg-indigo-600/10' : ''}`}>

      {/* Tile Board Layer */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombie = zombieIndicators.includes(s.id);
          const isPumpkin = pumpkinIndices.includes(s.id);
          const isDemon = demonIndices.includes(s.id);
          const isClover = cloverIndices.includes(s.id);
          const isStart = s.id === 0;

          let icon = null;
          if (isBomb) icon = BOMB_ICON;
          else if (isZombie) icon = ENEMY_ICON;
          else if (isPumpkin) icon = '🎃';
          else if (isDemon) icon = '👹';
          else if (isClover) icon = '🍀';

          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
              style={{ left: s.x, top: s.y, width: tileSize, height: tileSize }}
            >
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {icon && (
                <span className="drop-shadow-sm opacity-40 grayscale filter" style={{ fontSize: tileSize * 0.55 }}>
                  {icon}
                </span>
              )}
              {bloom && <span className="bloom absolute grayscale filter" style={{ fontSize: tileSize * 0.5 }}>{bloom}</span>}
              {isStart && !bloom && !icon && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}

        {/* Zombies */}
        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[z.pos].x + tileSize/2, 
            top: boardSpaces[z.pos].y + tileSize/2, 
            transform: `translate(-50%, -60%) scale(${demonBoss.isActive ? 2.0 : 1.0})` 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/90 dark:bg-black/80 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-200 dark:bg-gray-800'}`} />
                   ))}
                </div>
                <span className="drop-shadow-2xl animate-pulse grayscale filter" style={{ fontSize: tileSize * 1.2 }}>{ENEMY_ICON}</span>
             </div>
          </div>
        ))}

        {/* Player Piece */}
        <div 
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, 
            top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: tileSize * 1.3
          }}
        >
          <div className="flex flex-col items-center">
             <div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (
                   <div key={i} className={`w-2 h-1 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />
                ))}
             </div>
             <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">{ANIMAL_EMOJIS[animalIndex]}</span>
          </div>
        </div>

        {/* Explosion VFX */}
        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[currentPos]?.x + tileSize/2, 
            top: boardSpaces[currentPos]?.y + tileSize/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-7xl drop-shadow-2xl grayscale filter">{darkMode ? '✨' : '💥'}</span>
          </div>
        )}
      </div>

      {/* Main UI Container */}
      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-10 scale-90 lg:scale-100 h-[420px]">

          {/* Task Board */}
          <div className="glass-panel rounded-lg p-5 w-[432px] flex flex-col shadow-sm border border-black/5 dark:border-white/5 bg-white/95 dark:bg-zinc-900/95 transition-all">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span>
                <span className="text-3xl font-normal tabular-nums tracking-tight">{rollBank}</span>
              </div>
              <div className="flex items-center gap-3">
                {/* Dice Color Selector */}
                <div className="flex gap-1.5 p-1 bg-black/5 dark:bg-white/5 rounded">
                  {DICE_COLORS.map(c => (
                    <button 
                      key={c} 
                      onClick={() => setDiceColor(c)} 
                      className={`w-4 h-4 rounded-full border border-black/10 transition-transform ${diceColor === c ? 'scale-125' : 'hover:scale-110'}`} 
                      style={{ background: c }}
                    />
                  ))}
                </div>
                <button onClick={() => setDarkMode(!darkMode)} className="w-8 h-8 flex items-center justify-center rounded hover:bg-black/5 transition-all text-lg">
                  {darkMode ? '☀️' : '🌙'}
                </button>
              </div>
            </div>

            <div className="flex-grow overflow-y-auto pr-1 custom-scrollbar space-y-px">
              {!showHistory ? tasks.map(t => (
                <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-2 hover:bg-black/5 rounded transition-colors flex items-center gap-3 cursor-pointer">
                  <div className="w-3.5 h-3.5 rounded-sm border border-black/20 group-hover:bg-indigo-500/10 group-hover:border-indigo-500 transition-all" />
                  <div className="flex-grow overflow-hidden">
                    <div className="text-[13px] font-medium truncate opacity-90">{t.text}</div>
                    {t.priority && <div className={`inline-block text-[8px] font-black uppercase px-1 rounded-sm mt-0.5 border ${getPriorityColor(t.priority)}`}>{t.priority}</div>}
                  </div>
                </div>
              )) : history.map(h => (
                <div key={h.id} className="p-2 border-l border-indigo-500/10 opacity-40">
                  <span className="text-[12px] line-through block">{h.text}</span>
                  <span className="text-[9px] uppercase tracking-tighter">{h.completedAt}</span>
                </div>
              ))}
            </div>

            <div className="mt-4 pt-4 border-t border-black/5 flex flex-col gap-3">
              <div className="flex gap-1">
                {(['low', 'medium', 'high'] as const).map(p => (
                    <button key={p} onClick={() => setNewTaskPriority(p)} className={`flex-1 py-1 text-[8px] font-bold uppercase rounded border transition-all ${newTaskPriority === p ? 'bg-indigo-600 border-indigo-600 text-white' : 'opacity-50 hover:bg-black/5'}`}>
                        {p}
                    </button>
                ))}
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowHistory(!showHistory)} className="px-3 py-2 text-[10px] font-bold border rounded hover:bg-black/5 transition-colors">{showHistory ? 'Tasks' : 'Log'}</button>
                <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); setNewTask(''); }} className="flex-1">
                    <input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full h-8 bg-black/[0.02] border rounded px-3 text-[12px] outline-none" placeholder="Add mission..." />
                </form>
              </div>
            </div>
          </div>

          {/* Jar Area */}
          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} />

          {/* Bosses Area (Stacked Vertically, Right of Jar) */}
          <div className="w-64 flex flex-col items-center justify-center relative h-[420px] gap-4">
            {pumpkinBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center">
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-orange-500/20 backdrop-blur-md">
                   {[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < pumpkinBoss.health ? 'bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                {/* 1/2 size of jar visually (jar is ~300px, so ~150px) */}
                <span className="leading-none drop-shadow-xl grayscale filter" style={{ fontSize: '120px' }}>🎃</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-orange-600/60 mt-1">Pumpkin Boss</span>
              </div>
            )}

            {demonBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center" style={{ animationDelay: '-1.5s' }}>
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-red-500/20 backdrop-blur-md">
                   {[...Array(MAX_DEMON_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < demonBoss.health ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl grayscale filter" style={{ fontSize: '120px' }}>👹</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-red-600/60 mt-1">Demon Buff</span>
              </div>
            )}
          </div>

          <div className="w-12"></div>
        </div>
      </div>

      <Dice3D color={diceColor} value={diceValue} isRolling={isRolling} currentPos={dicePosition} onRoll={handleRoll} onDragEnd={setDicePosition} />

      <style>{`
        @keyframes bounce-slow {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-12px); }
        }
        .animate-bounce-slow { animation: bounce-slow 3s ease-in-out infinite; }
        @keyframes bomb-drop {
          0% { transform: translate(-50%, -300%) scale(2); opacity: 0; }
          60% { transform: translate(-50%, -60%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(14); opacity: 0; filter: blur(50px); }
        }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.06); background: rgba(255,255,255,0.95); border-radius: 4px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.03); background: rgba(18,18,18,0.95); }
        .glass-panel { backdrop-filter: blur(40px); }
      `}</style>

    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 
const ZOMBIE_INDICATOR_COUNT = 6; 
const BOMB_COUNT = 6;           
const PUMPKIN_COUNT = 5; 
const DEMON_COUNT = 5; 
const CLOVER_COUNT = 5; 
const GHOST_COUNT = 5; // Added 5 ghost tiles
const RAINBOW_COUNT = 5; // Added 5 rainbow tiles
const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 
const TOTAL_TILES = 60;
const SPAWN_BEHIND_OFFSET = 5;

const ANIMAL_EMOJIS = [
  '🦖', '🐉', '🐲', '🐟', '🐙', '🦈', '🐳', '🐋', '🐬', '🐘', 
  '🦄', '🦁', '🐯', '🐼', '🦊', '🐸', '🐨', '🦒', '🦓', '🦘'
];
const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.3)', 
  'rgba(199, 210, 254, 0.5)', 
  'rgba(254, 202, 202, 0.5)', 
  'rgba(167, 243, 208, 0.5)', 
  'rgba(253, 230, 138, 0.5)', 
];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false); // World monochrome state
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePosition, setDicePosition] = useState({ x: window.innerWidth / 2, y: window.innerHeight / 2 });
  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(64);
  const BOARD_W = 20;
  const BOARD_H = 12;

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      const bestSize = Math.max(48, Math.min(horizontalLimit, verticalLimit, 72));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    const gInd = getRandomUnique(GHOST_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd]);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd]);

    setZombieIndicators(zInd);
    setBombIndices(bInd);
    setPumpkinIndices(pInd);
    setDemonIndices(dInd);
    setCloverIndices(cInd);
    setGhostIndices(gInd);
    setRainbowIndices(rInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);

    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
    }
  };

  const processMovement = useCallback((diceVal: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      // Clover logic
      if (cloverIndices.includes(tempPos)) {
        setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1));
        relocateItem(cloverIndices, tempPos, 'clover');
      }

      // Ghost logic: passing over makes it monochrome
      if (ghostIndices.includes(tempPos)) {
        setIsGrayscale(true);
        relocateItem(ghostIndices, tempPos, 'ghost');
      }

      // Rainbow logic: passing over restores color
      if (rainbowIndices.includes(tempPos)) {
        setIsGrayscale(false);
        relocateItem(rainbowIndices, tempPos, 'rainbow');
      }

      if (bombIndices.includes(tempPos)) {
        setBombAnimation({ active: true, pos: tempPos });
        if (pumpkinBoss.isActive) {
          setPumpkinBoss(prev => {
            const newHealth = prev.health - 1;
            return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
          });
        }
        if (demonBoss.isActive) {
          setDemonBoss(prev => {
            const newHealth = prev.health - 1;
            return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
          });
        }
        setActiveZombies(prev => {
          if (prev.length === 0) return prev;
          let nearestIndex = 0;
          let minDistance = Infinity;
          prev.forEach((z, idx) => {
            const dist = Math.min(Math.abs(tempPos - z.pos), TOTAL_TILES - Math.abs(tempPos - z.pos));
            if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
          });
          const newZombies = [...prev];
          const target = { ...newZombies[nearestIndex] };
          target.health -= 1;
          if (target.health <= 0) {
            newZombies.splice(nearestIndex, 1);
          } else { newZombies[nearestIndex] = target; }
          return newZombies;
        });
        setIsShaking(true);
        setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceVal) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombies(prev => [...prev, {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          }]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }

        if (pumpkinIndices.includes(finalPos)) {
          setPumpkinBoss(prev => ({ isActive: true, health: MAX_PUMPKIN_HEALTH }));
          relocateItem(pumpkinIndices, finalPos, 'pumpkin');
        }

        if (demonIndices.includes(finalPos)) {
          setDemonBoss(prev => ({ isActive: true, health: MAX_DEMON_HEALTH }));
          relocateItem(demonIndices, finalPos, 'demon');
        }

        setActiveZombies(prev => {
          let gameOver = false;
          const moveSteps = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + moveSteps) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) {
            setPlayerHealth(h => {
              const next = h - 1;
              if (next <= 0) {
                handleGameOver();
                return MAX_PLAYER_HEALTH;
              }
              return next;
            });
            return [];
          }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, pumpkinBoss, demonBoss, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices]);

  const handleGameOver = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setIsGrayscale(false); // Reset color on game over
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;

    if (pumpkinBoss.isActive) {
      setIsDeducting(true);
      setJarCount(prev => Math.max(0, prev - 5));
      setTimeout(() => setIsDeducting(false), 800);
    }

    setIsRolling(true);
    setRollBank(r => r - 1);
    setDicePosition(landing);
    const val = Math.floor(Math.random() * 6) + 1;
    setTimeout(() => {
      setIsRolling(false);
      setDiceValue(val);
      setIsMoving(true);
      processMovement(val);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden ${isExploding ? 'bg-indigo-600/10' : ''} ${isGrayscale ? 'filter grayscale' : ''}`}>

      {/* Tile Board Layer */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombie = zombieIndicators.includes(s.id);
          const isPumpkin = pumpkinIndices.includes(s.id);
          const isDemon = demonIndices.includes(s.id);
          const isClover = cloverIndices.includes(s.id);
          const isGhost = ghostIndices.includes(s.id);
          const isRainbow = rainbowIndices.includes(s.id);
          const isStart = s.id === 0;

          let icon = null;
          if (isBomb) icon = BOMB_ICON;
          else if (isZombie) icon = ENEMY_ICON;
          else if (isPumpkin) icon = '🎃';
          else if (isDemon) icon = '👹';
          else if (isClover) icon = '🍀';
          else if (isGhost) icon = '👻';
          else if (isRainbow) icon = '🌈';

          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
              style={{ left: s.x, top: s.y, width: tileSize, height: tileSize }}
            >
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {icon && (
                <span className="drop-shadow-sm opacity-25" style={{ fontSize: tileSize * 0.55 }}>
                  {icon}
                </span>
              )}
              {bloom && <span className="bloom absolute opacity-25" style={{ fontSize: tileSize * 0.5 }}>{bloom}</span>}
              {isStart && !bloom && !icon && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}

        {/* Zombies */}
        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[z.pos].x + tileSize/2, 
            top: boardSpaces[z.pos].y + tileSize/2, 
            transform: `translate(-50%, -60%) scale(${demonBoss.isActive ? 2.0 : 1.0})` 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/90 dark:bg-black/80 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-200 dark:bg-gray-800'}`} />
                   ))}
                </div>
                <span className="drop-shadow-2xl animate-pulse" style={{ fontSize: tileSize * 1.2 }}>{ENEMY_ICON}</span>
             </div>
          </div>
        ))}

        {/* Player Piece */}
        <div 
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, 
            top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: tileSize * 1.3
          }}
        >
          <div className="flex flex-col items-center">
             <div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (
                   <div key={i} className={`w-2 h-1 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />
                ))}
             </div>
             <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">{ANIMAL_EMOJIS[animalIndex]}</span>
          </div>
        </div>

        {/* Explosion VFX */}
        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[currentPos]?.x + tileSize/2, 
            top: boardSpaces[currentPos]?.y + tileSize/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-7xl drop-shadow-2xl">{darkMode ? '✨' : '💥'}</span>
          </div>
        )}
      </div>

      {/* Main UI Container */}
      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-10 scale-90 lg:scale-100 h-[420px]">

          {/* Task Board */}
          <div className="glass-panel rounded-lg p-5 w-[432px] flex flex-col shadow-sm border border-black/5 dark:border-white/5 bg-white/95 dark:bg-zinc-900/95 transition-all">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span>
                <span className="text-3xl font-normal tabular-nums tracking-tight">{rollBank}</span>
              </div>
              <div className="flex items-center gap-3">
                <div className="flex gap-1.5 p-1 bg-black/5 dark:bg-white/5 rounded">
                  {DICE_COLORS.map(c => (
                    <button 
                      key={c} 
                      onClick={() => setDiceColor(c)} 
                      className={`w-4 h-4 rounded-full border border-black/10 transition-transform ${diceColor === c ? 'scale-125' : 'hover:scale-110'}`} 
                      style={{ background: c }}
                    />
                  ))}
                </div>
                <button onClick={() => setDarkMode(!darkMode)} className="w-8 h-8 flex items-center justify-center rounded hover:bg-black/5 transition-all text-lg">
                  {darkMode ? '☀️' : '🌙'}
                </button>
              </div>
            </div>

            <div className="flex-grow overflow-y-auto pr-1 custom-scrollbar space-y-px">
              {!showHistory ? tasks.map(t => (
                <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-2 hover:bg-black/5 rounded transition-colors flex items-center gap-3 cursor-pointer">
                  <div className="w-3.5 h-3.5 rounded-sm border border-black/20 group-hover:bg-indigo-500/10 group-hover:border-indigo-500 transition-all" />
                  <div className="flex-grow overflow-hidden">
                    <div className="text-[13px] font-medium truncate opacity-90">{t.text}</div>
                    {t.priority && <div className={`inline-block text-[8px] font-black uppercase px-1 rounded-sm mt-0.5 border ${getPriorityColor(t.priority)}`}>{t.priority}</div>}
                  </div>
                </div>
              )) : history.map(h => (
                <div key={h.id} className="p-2 border-l border-indigo-500/10 opacity-40">
                  <span className="text-[12px] line-through block">{h.text}</span>
                  <span className="text-[9px] uppercase tracking-tighter">{h.completedAt}</span>
                </div>
              ))}
            </div>

            <div className="mt-4 pt-4 border-t border-black/5 flex flex-col gap-3">
              <div className="flex gap-1">
                {(['low', 'medium', 'high'] as const).map(p => (
                    <button key={p} onClick={() => setNewTaskPriority(p)} className={`flex-1 py-1 text-[8px] font-bold uppercase rounded border transition-all ${newTaskPriority === p ? 'bg-indigo-600 border-indigo-600 text-white' : 'opacity-50 hover:bg-black/5'}`}>
                        {p}
                    </button>
                ))}
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowHistory(!showHistory)} className="px-3 py-2 text-[10px] font-bold border rounded hover:bg-black/5 transition-colors">{showHistory ? 'Tasks' : 'Log'}</button>
                <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); setNewTask(''); }} className="flex-1">
                    <input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full h-8 bg-black/[0.02] border rounded px-3 text-[12px] outline-none" placeholder="Add mission..." />
                </form>
              </div>
            </div>
          </div>

          {/* Jar Area */}
          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} />

          {/* Bosses Area */}
          <div className="w-64 flex flex-col items-center justify-center relative h-[420px] gap-4">
            {pumpkinBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center">
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-orange-500/20 backdrop-blur-md">
                   {[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < pumpkinBoss.health ? 'bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>🎃</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-orange-600/60 mt-1">Pumpkin Boss</span>
              </div>
            )}

            {demonBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center" style={{ animationDelay: '-1.5s' }}>
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-red-500/20 backdrop-blur-md">
                   {[...Array(MAX_DEMON_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < demonBoss.health ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>👹</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-red-600/60 mt-1">Demon Buff</span>
              </div>
            )}
          </div>

          <div className="w-12"></div>
        </div>
      </div>

      <Dice3D color={diceColor} value={diceValue} isRolling={isRolling} currentPos={dicePosition} onRoll={handleRoll} onDragEnd={setDicePosition} />

      <style>{`
        @keyframes bounce-slow {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-12px); }
        }
        .animate-bounce-slow { animation: bounce-slow 3s ease-in-out infinite; }
        @keyframes bomb-drop {
          0% { transform: translate(-50%, -300%) scale(2); opacity: 0; }
          60% { transform: translate(-50%, -60%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(14); opacity: 0; filter: blur(50px); }
        }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.06); background: rgba(255,255,255,0.95); border-radius: 4px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.03); background: rgba(18,18,18,0.95); }
        .glass-panel { backdrop-filter: blur(40px); }
      `}</style>

    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

// New Tile Counts per request
const ZOMBIE_INDICATOR_COUNT = 5; 
const BOMB_COUNT = 6;           
const PUMPKIN_COUNT = 3; 
const DEMON_COUNT = 3; 
const CLOVER_COUNT = 3; 
const GHOST_COUNT = 3; 
const RAINBOW_COUNT = 5; 
const CLOWN_COUNT = 5; 

// HP Settings
const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

// Board Dimensions for ~72 tiles
const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; // 72
const SPAWN_BEHIND_OFFSET = 5;

const ANIMAL_EMOJIS = [
  '🦖', '🐉', '🐲', '🐟', '🐙', '🦈', '🐳', '🐋', '🐬', '🐘', 
  '🦄', '🦁', '🐯', '🐼', '🦊', '🐸', '🐨', '🦒', '🦓', '🦘'
];
const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.3)', 
  'rgba(199, 210, 254, 0.5)', 
  'rgba(254, 202, 202, 0.5)', 
  'rgba(167, 243, 208, 0.5)', 
  'rgba(253, 230, 138, 0.5)', 
];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePosition, setDicePosition] = useState({ x: window.innerWidth / 2, y: window.innerHeight / 2 });
  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(64);

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      const bestSize = Math.max(38, Math.min(horizontalLimit, verticalLimit, 64));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    const gInd = getRandomUnique(GHOST_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd]);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd, ...rInd]);

    setZombieIndicators(zInd);
    setBombIndices(bInd);
    setPumpkinIndices(pInd);
    setDemonIndices(dInd);
    setCloverIndices(cInd);
    setGhostIndices(gInd);
    setRainbowIndices(rInd);
    setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...clownIndices, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);

    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  };

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) {
      setPumpkinBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    if (demonBoss.isActive) {
      setDemonBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    setActiveZombies(prev => {
      if (prev.length === 0) return prev;
      let nearestIndex = 0;
      let minDistance = Infinity;
      prev.forEach((z, idx) => {
        const dist = Math.min(Math.abs(damagePos - z.pos), TOTAL_TILES - Math.abs(damagePos - z.pos));
        if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
      });
      const newZombies = [...prev];
      const target = { ...newZombies[nearestIndex] };
      target.health -= 1;
      if (target.health <= 0) {
        newZombies.splice(nearestIndex, 1);
      } else { newZombies[nearestIndex] = target; }
      return newZombies;
    });
    setIsShaking(true);
    setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
  }, [pumpkinBoss, demonBoss, activeZombies]);

  const processMovement = useCallback((diceVal: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    // Dice 1 logic: Damage enemies like a bomb
    if (diceVal === 1) {
       applyBombDamage(tempPos);
    }

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      // Tile interactions on passing
      if (cloverIndices.includes(tempPos)) {
        setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1));
        relocateItem(cloverIndices, tempPos, 'clover');
      }
      if (ghostIndices.includes(tempPos)) {
        setIsGrayscale(true);
        setIsClownMode(false);
        relocateItem(ghostIndices, tempPos, 'ghost');
      }
      if (rainbowIndices.includes(tempPos)) {
        setIsGrayscale(false);
        setIsClownMode(false);
        relocateItem(rainbowIndices, tempPos, 'rainbow');
      }
      if (clownIndices.includes(tempPos)) {
        setIsClownMode(true);
        setIsGrayscale(false);
        relocateItem(clownIndices, tempPos, 'clown');
      }
      if (bombIndices.includes(tempPos)) {
        applyBombDamage(tempPos);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceVal) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        // Final tile interactions
        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombies(prev => [...prev, {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          }]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }
        if (pumpkinIndices.includes(finalPos)) {
          setPumpkinBoss(prev => ({ isActive: true, health: MAX_PUMPKIN_HEALTH }));
          relocateItem(pumpkinIndices, finalPos, 'pumpkin');
        }
        if (demonIndices.includes(finalPos)) {
          setDemonBoss(prev => ({ isActive: true, health: MAX_DEMON_HEALTH }));
          relocateItem(demonIndices, finalPos, 'demon');
        }

        setActiveZombies(prev => {
          let gameOver = false;
          const moveSteps = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + moveSteps) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) {
            setPlayerHealth(h => {
              const next = h - 1;
              if (next <= 0) {
                handleGameOver();
                return MAX_PLAYER_HEALTH;
              }
              return next;
            });
            return [];
          }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, pumpkinBoss, demonBoss, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, applyBombDamage]);

  const handleGameOver = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setIsGrayscale(false);
    setIsClownMode(false);
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    if (pumpkinBoss.isActive) {
      setIsDeducting(true);
      setJarCount(prev => Math.max(0, prev - 5));
      setTimeout(() => setIsDeducting(false), 800);
    }
    setIsRolling(true);
    setRollBank(r => r - 1);
    setDicePosition(landing);
    const val = Math.floor(Math.random() * 6) + 1;
    setTimeout(() => {
      setIsRolling(false);
      setDiceValue(val);
      setIsMoving(true);
      processMovement(val);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  // Clown Mode messy colors generator
  const getClownTileColor = (id: number) => {
    if (!isClownMode) return '';
    const colors = ['#ff00ff', '#00ffff', '#ffff00', '#ff0000', '#00ff00', '#ff8800', '#8800ff'];
    return colors[id % colors.length];
  };

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden 
      ${isExploding ? 'bg-indigo-600/10' : ''} 
      ${isGrayscale ? 'filter grayscale' : ''}
      ${isClownMode ? 'clown-bg animate-color-chaos' : ''}
    `}>

      {/* Confetti for Clown Mode rolls */}
      {isClownMode && isRolling && <div className="absolute inset-0 z-[100] pointer-events-none confetti-effect" />}

      {/* Tile Board Layer */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombie = zombieIndicators.includes(s.id);
          const isPumpkin = pumpkinIndices.includes(s.id);
          const isDemon = demonIndices.includes(s.id);
          const isClover = cloverIndices.includes(s.id);
          const isGhost = ghostIndices.includes(s.id);
          const isRainbow = rainbowIndices.includes(s.id);
          const isClown = clownIndices.includes(s.id);
          const isStart = s.id === 0;

          let icon = null;
          if (isBomb) icon = BOMB_ICON;
          else if (isZombie) icon = ENEMY_ICON;
          else if (isPumpkin) icon = '🎃';
          else if (isDemon) icon = '👹';
          else if (isClover) icon = '🍀';
          else if (isGhost) icon = '👻';
          else if (isRainbow) icon = '🌈';
          else if (isClown) icon = '🤡';

          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
              style={{ 
                left: s.x, top: s.y, width: tileSize, height: tileSize,
                backgroundColor: isClownMode ? getClownTileColor(s.id) : undefined 
              }}
            >
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {icon && (
                <span className="drop-shadow-sm opacity-25" style={{ fontSize: tileSize * 0.55 }}>
                  {icon}
                </span>
              )}
              {bloom && <span className="bloom absolute opacity-25" style={{ fontSize: tileSize * 0.5 }}>{bloom}</span>}
              {isStart && !bloom && !icon && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}

        {/* Zombies */}
        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[z.pos].x + tileSize/2, 
            top: boardSpaces[z.pos].y + tileSize/2, 
            transform: `translate(-50%, -60%) scale(${demonBoss.isActive ? 2.0 : 1.0})` 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/90 dark:bg-black/80 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-200 dark:bg-gray-800'}`} />
                   ))}
                </div>
                <span className="drop-shadow-2xl animate-pulse" style={{ fontSize: tileSize * 1.2 }}>{ENEMY_ICON}</span>
             </div>
          </div>
        ))}

        {/* Player Piece */}
        <div 
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, 
            top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: tileSize * 1.3
          }}
        >
          <div className="flex flex-col items-center">
             <div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (
                   <div key={i} className={`w-2 h-1 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />
                ))}
             </div>
             <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">
               {isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}
             </span>
          </div>
        </div>

        {/* Explosion VFX */}
        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[bombAnimation.pos]?.x + tileSize/2, 
            top: boardSpaces[bombAnimation.pos]?.y + tileSize/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-7xl drop-shadow-2xl">{darkMode ? '✨' : '💥'}</span>
          </div>
        )}
      </div>

      {/* Main UI Container */}
      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-10 scale-90 lg:scale-100 h-[420px]">

          {/* Task Board */}
          <div className="glass-panel rounded-lg p-5 w-[432px] flex flex-col shadow-sm border border-black/5 dark:border-white/5 bg-white/95 dark:bg-zinc-900/95 transition-all">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span>
                <span className="text-3xl font-normal tabular-nums tracking-tight">{rollBank}</span>
              </div>
              <div className="flex items-center gap-3">
                <div className="flex gap-1.5 p-1 bg-black/5 dark:bg-white/5 rounded">
                  {DICE_COLORS.map(c => (
                    <button 
                      key={c} 
                      onClick={() => setDiceColor(c)} 
                      className={`w-4 h-4 rounded-full border border-black/10 transition-transform ${diceColor === c ? 'scale-125' : 'hover:scale-110'}`} 
                      style={{ background: c }}
                    />
                  ))}
                </div>
                <button onClick={() => setDarkMode(!darkMode)} className="w-8 h-8 flex items-center justify-center rounded hover:bg-black/5 transition-all text-lg">
                  {darkMode ? '☀️' : '🌙'}
                </button>
              </div>
            </div>

            <div className="flex-grow overflow-y-auto pr-1 custom-scrollbar space-y-px">
              {!showHistory ? tasks.map(t => (
                <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-2 hover:bg-black/5 rounded transition-colors flex items-center gap-3 cursor-pointer">
                  <div className="w-3.5 h-3.5 rounded-sm border border-black/20 group-hover:bg-indigo-500/10 group-hover:border-indigo-500 transition-all" />
                  <div className="flex-grow overflow-hidden">
                    <div className="text-[13px] font-medium truncate opacity-90">{t.text}</div>
                    {t.priority && <div className={`inline-block text-[8px] font-black uppercase px-1 rounded-sm mt-0.5 border ${getPriorityColor(t.priority)}`}>{t.priority}</div>}
                  </div>
                </div>
              )) : history.map(h => (
                <div key={h.id} className="p-2 border-l border-indigo-500/10 opacity-40">
                  <span className="text-[12px] line-through block">{h.text}</span>
                  <span className="text-[9px] uppercase tracking-tighter">{h.completedAt}</span>
                </div>
              ))}
            </div>

            <div className="mt-4 pt-4 border-t border-black/5 flex flex-col gap-3">
              <div className="flex gap-1">
                {(['low', 'medium', 'high'] as const).map(p => (
                    <button key={p} onClick={() => setNewTaskPriority(p)} className={`flex-1 py-1 text-[8px] font-bold uppercase rounded border transition-all ${newTaskPriority === p ? 'bg-indigo-600 border-indigo-600 text-white' : 'opacity-50 hover:bg-black/5'}`}>
                        {p}
                    </button>
                ))}
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowHistory(!showHistory)} className="px-3 py-2 text-[10px] font-bold border rounded hover:bg-black/5 transition-colors">{showHistory ? 'Tasks' : 'Log'}</button>
                <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); setNewTask(''); }} className="flex-1">
                    <input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full h-8 bg-black/[0.02] border rounded px-3 text-[12px] outline-none" placeholder="Add mission..." />
                </form>
              </div>
            </div>
          </div>

          {/* Jar Area */}
          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} />

          {/* Bosses Area */}
          <div className="w-64 flex flex-col items-center justify-center relative h-[420px] gap-4">
            {pumpkinBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center">
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-orange-500/20 backdrop-blur-md">
                   {[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < pumpkinBoss.health ? 'bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>🎃</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-orange-600/60 mt-1">Pumpkin Boss</span>
              </div>
            )}

            {demonBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center" style={{ animationDelay: '-1.5s' }}>
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-red-500/20 backdrop-blur-md">
                   {[...Array(MAX_DEMON_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < demonBoss.health ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>👹</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-red-600/60 mt-1">Demon Buff</span>
              </div>
            )}
          </div>

          <div className="w-12"></div>
        </div>
      </div>

      <Dice3D color={diceColor} value={diceValue} isRolling={isRolling} currentPos={dicePosition} onRoll={handleRoll} onDragEnd={setDicePosition} />

      <style>{`
        @keyframes bounce-slow {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-12px); }
        }
        .animate-bounce-slow { animation: bounce-slow 3s ease-in-out infinite; }
        @keyframes bomb-drop {
          0% { transform: translate(-50%, -300%) scale(2); opacity: 0; }
          60% { transform: translate(-50%, -60%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(14); opacity: 0; filter: blur(50px); }
        }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.06); background: rgba(255,255,255,0.95); border-radius: 4px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.03); background: rgba(18,18,18,0.95); }
        .glass-panel { backdrop-filter: blur(40px); }

        /* Clown Mode Effects */
        @keyframes color-chaos {
          0% { background-color: #ff0000; }
          25% { background-color: #00ff00; }
          50% { background-color: #0000ff; }
          75% { background-color: #ffff00; }
          100% { background-color: #ff00ff; }
        }
        .animate-color-chaos { animation: color-chaos 5s infinite linear; }

        .confetti-effect {
          background-image: radial-gradient(circle, #ff0 10%, transparent 10.5%),
                            radial-gradient(circle, #f00 10%, transparent 10.5%),
                            radial-gradient(circle, #0f0 10%, transparent 10.5%),
                            radial-gradient(circle, #00f 10%, transparent 10.5%);
          background-size: 10px 10px, 15px 15px, 20px 20px, 12px 12px;
          background-position: 0 0, 5px 5px, 10px 10px, 15px 15px;
          animation: confetti-fall 2s infinite linear;
          opacity: 0.6;
        }
        @keyframes confetti-fall {
          0% { background-position: 0 0; }
          100% { background-position: 100px 500px; }
        }
      `}</style>

    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

// New Tile Counts per request
const ZOMBIE_INDICATOR_COUNT = 5; 
const BOMB_COUNT = 6;           
const PUMPKIN_COUNT = 3; 
const DEMON_COUNT = 3; 
const CLOVER_COUNT = 3; 
const GHOST_COUNT = 3; 
const RAINBOW_COUNT = 5; 
const CLOWN_COUNT = 5; 

// HP Settings
const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

// Board Dimensions for ~72 tiles
const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; // 72
const SPAWN_BEHIND_OFFSET = 5;

const ANIMAL_EMOJIS = [
  // Dinosaurs & Reptiles
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', 
  // Aquatic Life
  '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  // Wild Beasts
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🦌',
  // Primates & Forest
  '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  // Birds
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤',
  // Pets & Farm
  '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.3)', 
  'rgba(199, 210, 254, 0.5)', 
  'rgba(254, 202, 202, 0.5)', 
  'rgba(167, 243, 208, 0.5)', 
  'rgba(253, 230, 138, 0.5)', 
];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValue, setDiceValue] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePosition, setDicePosition] = useState({ x: window.innerWidth / 2, y: window.innerHeight / 2 });
  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(64);

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      const bestSize = Math.max(38, Math.min(horizontalLimit, verticalLimit, 64));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    const gInd = getRandomUnique(GHOST_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd]);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd, ...rInd]);

    setZombieIndicators(zInd);
    setBombIndices(bInd);
    setPumpkinIndices(pInd);
    setDemonIndices(dInd);
    setCloverIndices(cInd);
    setGhostIndices(gInd);
    setRainbowIndices(rInd);
    setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...clownIndices, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);

    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  };

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) {
      setPumpkinBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    if (demonBoss.isActive) {
      setDemonBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    setActiveZombies(prev => {
      if (prev.length === 0) return prev;
      let nearestIndex = 0;
      let minDistance = Infinity;
      prev.forEach((z, idx) => {
        const dist = Math.min(Math.abs(damagePos - z.pos), TOTAL_TILES - Math.abs(damagePos - z.pos));
        if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
      });
      const newZombies = [...prev];
      const target = { ...newZombies[nearestIndex] };
      target.health -= 1;
      if (target.health <= 0) {
        newZombies.splice(nearestIndex, 1);
      } else { newZombies[nearestIndex] = target; }
      return newZombies;
    });
    setIsShaking(true);
    setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
  }, [pumpkinBoss, demonBoss, activeZombies]);

  const processMovement = useCallback((diceVal: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    // Dice 1 logic: Damage enemies like a bomb
    if (diceVal === 1) {
       applyBombDamage(tempPos);
    }

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      // Tile interactions on passing
      if (cloverIndices.includes(tempPos)) {
        setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1));
        relocateItem(cloverIndices, tempPos, 'clover');
      }
      if (ghostIndices.includes(tempPos)) {
        setIsGrayscale(true);
        setIsClownMode(false);
        relocateItem(ghostIndices, tempPos, 'ghost');
      }
      if (rainbowIndices.includes(tempPos)) {
        setIsGrayscale(false);
        setIsClownMode(false);
        relocateItem(rainbowIndices, tempPos, 'rainbow');
      }
      if (clownIndices.includes(tempPos)) {
        setIsClownMode(true);
        setIsGrayscale(false);
        relocateItem(clownIndices, tempPos, 'clown');
      }
      if (bombIndices.includes(tempPos)) {
        applyBombDamage(tempPos);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceVal) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        // Final tile interactions
        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombies(prev => [...prev, {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          }]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }
        if (pumpkinIndices.includes(finalPos)) {
          setPumpkinBoss(prev => ({ isActive: true, health: MAX_PUMPKIN_HEALTH }));
          relocateItem(pumpkinIndices, finalPos, 'pumpkin');
        }
        if (demonIndices.includes(finalPos)) {
          setDemonBoss(prev => ({ isActive: true, health: MAX_DEMON_HEALTH }));
          relocateItem(demonIndices, finalPos, 'demon');
        }

        setActiveZombies(prev => {
          let gameOver = false;
          const moveSteps = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + moveSteps) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) {
            setPlayerHealth(h => {
              const next = h - 1;
              if (next <= 0) {
                handleGameOver();
                return MAX_PLAYER_HEALTH;
              }
              return next;
            });
            return [];
          }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, pumpkinBoss, demonBoss, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, applyBombDamage]);

  const handleGameOver = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setIsGrayscale(false);
    setIsClownMode(false);
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    if (pumpkinBoss.isActive) {
      setIsDeducting(true);
      setJarCount(prev => Math.max(0, prev - 5));
      setTimeout(() => setIsDeducting(false), 800);
    }
    setIsRolling(true);
    setRollBank(r => r - 1);
    setDicePosition(landing);
    const val = Math.floor(Math.random() * 6) + 1;
    setTimeout(() => {
      setIsRolling(false);
      setDiceValue(val);
      setIsMoving(true);
      processMovement(val);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  // Clown Mode messy colors generator
  const getClownTileColor = (id: number) => {
    if (!isClownMode) return '';
    const colors = ['#ff00ff', '#00ffff', '#ffff00', '#ff0000', '#00ff00', '#ff8800', '#8800ff'];
    return colors[id % colors.length];
  };

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden 
      ${isExploding ? 'bg-indigo-600/10' : ''} 
      ${isGrayscale ? 'filter grayscale' : ''}
      ${isClownMode ? 'clown-bg animate-color-chaos' : ''}
    `}>

      {/* Confetti for Clown Mode rolls */}
      {isClownMode && isRolling && <div className="absolute inset-0 z-[100] pointer-events-none confetti-effect" />}

      {/* Tile Board Layer */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombie = zombieIndicators.includes(s.id);
          const isPumpkin = pumpkinIndices.includes(s.id);
          const isDemon = demonIndices.includes(s.id);
          const isClover = cloverIndices.includes(s.id);
          const isGhost = ghostIndices.includes(s.id);
          const isRainbow = rainbowIndices.includes(s.id);
          const isClown = clownIndices.includes(s.id);
          const isStart = s.id === 0;

          let icon = null;
          if (isBomb) icon = BOMB_ICON;
          else if (isZombie) icon = ENEMY_ICON;
          else if (isPumpkin) icon = '🎃';
          else if (isDemon) icon = '👹';
          else if (isClover) icon = '🍀';
          else if (isGhost) icon = '👻';
          else if (isRainbow) icon = '🌈';
          else if (isClown) icon = '🤡';

          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
              style={{ 
                left: s.x, top: s.y, width: tileSize, height: tileSize,
                backgroundColor: isClownMode ? getClownTileColor(s.id) : undefined 
              }}
            >
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {icon && (
                <span className="drop-shadow-sm opacity-25" style={{ fontSize: tileSize * 0.55 }}>
                  {icon}
                </span>
              )}
              {bloom && <span className="bloom absolute opacity-25" style={{ fontSize: tileSize * 0.5 }}>{bloom}</span>}
              {isStart && !bloom && !icon && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}

        {/* Zombies */}
        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[z.pos].x + tileSize/2, 
            top: boardSpaces[z.pos].y + tileSize/2, 
            transform: `translate(-50%, -60%) scale(${demonBoss.isActive ? 2.0 : 1.0})` 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/90 dark:bg-black/80 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-200 dark:bg-gray-800'}`} />
                   ))}
                </div>
                <span className="drop-shadow-2xl animate-pulse" style={{ fontSize: tileSize * 1.2 }}>{ENEMY_ICON}</span>
             </div>
          </div>
        ))}

        {/* Player Piece */}
        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, 
            top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: tileSize * 1.3
          }}
        >
          <div className="flex flex-col items-center">
             <div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (
                   <div key={i} className={`w-2 h-1 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />
                ))}
             </div>
             <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">
               {isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}
             </span>
          </div>
        </div>

        {/* Explosion VFX */}
        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[bombAnimation.pos]?.x + tileSize/2, 
            top: boardSpaces[bombAnimation.pos]?.y + tileSize/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-7xl drop-shadow-2xl">{darkMode ? '✨' : '💥'}</span>
          </div>
        )}
      </div>

      {/* Main UI Container */}
      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-10 scale-90 lg:scale-100 h-[420px]">

          {/* Task Board */}
          <div className="glass-panel rounded-lg p-5 w-[432px] flex flex-col shadow-sm border border-black/5 dark:border-white/5 bg-white/95 dark:bg-zinc-900/95 transition-all">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span>
                <span className="text-3xl font-normal tabular-nums tracking-tight">{rollBank}</span>
              </div>
              <div className="flex items-center gap-3">
                <div className="flex gap-1.5 p-1 bg-black/5 dark:bg-white/5 rounded">
                  {DICE_COLORS.map(c => (
                    <button 
                      key={c} 
                      onClick={() => setDiceColor(c)} 
                      className={`w-4 h-4 rounded-full border border-black/10 transition-transform ${diceColor === c ? 'scale-125' : 'hover:scale-110'}`} 
                      style={{ background: c }}
                    />
                  ))}
                </div>
                <button onClick={() => setDarkMode(!darkMode)} className="w-8 h-8 flex items-center justify-center rounded hover:bg-black/5 transition-all text-lg">
                  {darkMode ? '☀️' : '🌙'}
                </button>
              </div>
            </div>

            <div className="flex-grow overflow-y-auto pr-1 custom-scrollbar space-y-px">
              {!showHistory ? tasks.map(t => (
                <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-2 hover:bg-black/5 rounded transition-colors flex items-center gap-3 cursor-pointer">
                  <div className="w-3.5 h-3.5 rounded-sm border border-black/20 group-hover:bg-indigo-500/10 group-hover:border-indigo-500 transition-all" />
                  <div className="flex-grow overflow-hidden">
                    <div className="text-[13px] font-medium truncate opacity-90">{t.text}</div>
                    {t.priority && <div className={`inline-block text-[8px] font-black uppercase px-1 rounded-sm mt-0.5 border ${getPriorityColor(t.priority)}`}>{t.priority}</div>}
                  </div>
                </div>
              )) : history.map(h => (
                <div key={h.id} className="p-2 border-l border-indigo-500/10 opacity-40">
                  <span className="text-[12px] line-through block">{h.text}</span>
                  <span className="text-[9px] uppercase tracking-tighter">{h.completedAt}</span>
                </div>
              ))}
            </div>

            <div className="mt-4 pt-4 border-t border-black/5 flex flex-col gap-3">
              <div className="flex gap-1">
                {(['low', 'medium', 'high'] as const).map(p => (
                    <button key={p} onClick={() => setNewTaskPriority(p)} className={`flex-1 py-1 text-[8px] font-bold uppercase rounded border transition-all ${newTaskPriority === p ? 'bg-indigo-600 border-indigo-600 text-white' : 'opacity-50 hover:bg-black/5'}`}>
                        {p}
                    </button>
                ))}
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowHistory(!showHistory)} className="px-3 py-2 text-[10px] font-bold border rounded hover:bg-black/5 transition-colors">{showHistory ? 'Tasks' : 'Log'}</button>
                <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); setNewTask(''); }} className="flex-1">
                    <input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full h-8 bg-black/[0.02] border rounded px-3 text-[12px] outline-none" placeholder="Add mission..." />
                </form>
              </div>
            </div>
          </div>

          {/* Jar Area */}
          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} />

          {/* Bosses Area */}
          <div className="w-64 flex flex-col items-center justify-center relative h-[420px] gap-4">
            {pumpkinBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center">
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-orange-500/20 backdrop-blur-md">
                   {[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < pumpkinBoss.health ? 'bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>🎃</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-orange-600/60 mt-1">Pumpkin Boss</span>
              </div>
            )}

            {demonBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center" style={{ animationDelay: '-1.5s' }}>
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-red-500/20 backdrop-blur-md">
                   {[...Array(MAX_DEMON_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < demonBoss.health ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>👹</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-red-600/60 mt-1">Demon Buff</span>
              </div>
            )}
          </div>

          <div className="w-12"></div>
        </div>
      </div>

      <Dice3D color={diceColor} value={diceValue} isRolling={isRolling} currentPos={dicePosition} onRoll={handleRoll} onDragEnd={setDicePosition} />

      <style>{`
        @keyframes bounce-slow {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-12px); }
        }
        .animate-bounce-slow { animation: bounce-slow 3s ease-in-out infinite; }
        @keyframes bomb-drop {
          0% { transform: translate(-50%, -300%) scale(2); opacity: 0; }
          60% { transform: translate(-50%, -60%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(14); opacity: 0; filter: blur(50px); }
        }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.06); background: rgba(255,255,255,0.95); border-radius: 4px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.03); background: rgba(18,18,18,0.95); }
        .glass-panel { backdrop-filter: blur(40px); }

        /* Clown Mode Effects */
        @keyframes color-chaos {
          0% { background-color: #ff0000; }
          25% { background-color: #00ff00; }
          50% { background-color: #0000ff; }
          75% { background-color: #ffff00; }
          100% { background-color: #ff00ff; }
        }
        .animate-color-chaos { animation: color-chaos 5s infinite linear; }

        .confetti-effect {
          background-image: radial-gradient(circle, #ff0 10%, transparent 10.5%),
                            radial-gradient(circle, #f00 10%, transparent 10.5%),
                            radial-gradient(circle, #0f0 10%, transparent 10.5%),
                            radial-gradient(circle, #00f 10%, transparent 10.5%);
          background-size: 10px 10px, 15px 15px, 20px 20px, 12px 12px;
          background-position: 0 0, 5px 5px, 10px 10px, 15px 15px;
          animation: confetti-fall 2s infinite linear;
          opacity: 0.6;
        }
        @keyframes confetti-fall {
          0% { background-position: 0 0; }
          100% { background-position: 100px 500px; }
        }
      `}</style>

    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';

interface Dice3DProps {
  value: number;
  isRolling: boolean;
  onRoll: (landingPos: { x: number; y: number }) => void;
  onDragEnd: (finalPos: { x: number; y: number }) => void;
  currentPos: { x: number; y: number };
  color?: string;
  scale?: number;
}

export const Dice3D: React.FC<Dice3DProps> = ({ 
  value, 
  isRolling, 
  onRoll, 
  onDragEnd, 
  currentPos, 
  color = 'rgba(255, 255, 255, 0.3)',
  scale = 1
}) => {
  const [pos, setPos] = useState(currentPos);
  const [isDragging, setIsDragging] = useState(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const elementPosStart = useRef({ x: 0, y: 0 });

  useEffect(() => {
    if (!isRolling && !isDragging) {
      setPos(currentPos);
    }
  }, [currentPos, isRolling, isDragging]);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (isRolling) return;
    setIsDragging(true);
    dragStart.current = { x: e.clientX, y: e.clientY };
    elementPosStart.current = { x: pos.x, y: pos.y };
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;
      const dx = e.clientX - dragStart.current.x;
      const dy = e.clientY - dragStart.current.y;
      setPos({
        x: elementPosStart.current.x + dx,
        y: elementPosStart.current.y + dy
      });
    };

    const handleMouseUp = () => {
      if (isDragging) {
        setIsDragging(false);
        onDragEnd(pos);
      }
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, pos, onDragEnd]);

  const getRotation = (v: number) => {
    switch (v) {
      case 1: return 'rotateX(0deg) rotateY(0deg)';
      case 2: return 'rotateY(-90deg)';
      case 3: return 'rotateY(90deg)';
      case 4: return 'rotateY(180deg)';
      case 5: return 'rotateX(-90deg)';
      case 6: return 'rotateX(90deg)';
      default: return 'rotateX(0deg)';
    }
  };

  const rollingRotation = isRolling 
    ? `rotateX(${Math.random() * 720 + 360}deg) rotateY(${Math.random() * 720 + 360}deg)`
    : getRotation(value);

  const triggerRoll = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (isRolling) return;
    // Calculate a landing position that isn't just the current one to give some "throw" feel
    const landingX = Math.max(100, Math.min(window.innerWidth - 100, pos.x + (Math.random() - 0.5) * 200));
    const landingY = Math.max(100, Math.min(window.innerHeight - 100, pos.y + (Math.random() - 0.5) * 200));
    onRoll({ x: landingX, y: landingY });
  };

  const faceStyle = {
    background: color,
  };

  const baseScale = isDragging ? 1.1 : (isRolling ? 1.3 : 1);
  const finalScale = baseScale * scale;

  return (
    <div 
      className={`fixed z-[60] transition-all ${isRolling ? 'duration-[1200ms]' : 'duration-75'} select-none cursor-grab active:cursor-grabbing`}
      style={{ 
        left: `${pos.x}px`, 
        top: `${pos.y}px`,
        transform: `translate(-50%, -50%) scale(${finalScale})`
      }}
      onMouseDown={handleMouseDown}
      onDoubleClick={triggerRoll}
    >
      <div className="dice-container">
        <div className="dice" style={{ transform: rollingRotation }}>
          <div className="dice-face front" style={faceStyle}><div className="dot"></div></div>
          <div className="dice-face back" style={faceStyle}>
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '15%', left: '60%' }}></div>
             <div className="dot" style={{ top: '60%', left: '15%' }}></div>
             <div className="dot" style={{ top: '60%', left: '60%' }}></div>
          </div>
          <div className="dice-face right" style={faceStyle}>
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '40%', left: '40%' }}></div>
             <div className="dot" style={{ top: '65%', left: '65%' }}></div>
          </div>
          <div className="dice-face left" style={faceStyle}>
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '65%', left: '65%' }}></div>
          </div>
          <div className="dice-face top" style={faceStyle}>
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '15%', left: '60%' }}></div>
             <div className="dot" style={{ top: '40%', left: '40%' }}></div>
             <div className="dot" style={{ top: '65%', left: '15%' }}></div>
             <div className="dot" style={{ top: '65%', left: '65%' }}></div>
          </div>
          <div className="dice-face bottom" style={faceStyle}>
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '15%', left: '60%' }}></div>
             <div className="dot" style={{ top: '40%', left: '15%' }}></div>
             <div className="dot" style={{ top: '40%', left: '60%' }}></div>
             <div className="dot" style={{ top: '65%', left: '15%' }}></div>
             <div className="dot" style={{ top: '65%', left: '65%' }}></div>
          </div>
        </div>
      </div>
      {!isRolling && scale < 2 && (
          <div className="absolute -bottom-6 left-1/2 -translate-x-1/2 text-[9px] font-bold opacity-30 uppercase tracking-tighter whitespace-nowrap">Double Click</div>
      )}
    </div>
  );
};

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

// Tile Counts
const ZOMBIE_INDICATOR_COUNT = 5; 
const BOMB_COUNT = 6;           
const PUMPKIN_COUNT = 3; 
const DEMON_COUNT = 3; 
const CLOVER_COUNT = 3; 
const GHOST_COUNT = 3; 
const RAINBOW_COUNT = 5; 
const CLOWN_COUNT = 5; 

// HP Settings
const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

// Board Dimensions for ~72 tiles
const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; // 72
const SPAWN_BEHIND_OFFSET = 5;

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', 
  '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🦌',
  '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤',
  '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.3)', 
  'rgba(199, 210, 254, 0.5)', 
  'rgba(254, 202, 202, 0.5)', 
  'rgba(167, 243, 208, 0.5)', 
  'rgba(253, 230, 138, 0.5)', 
];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  // Multiple dice support
  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([
    { x: window.innerWidth / 2, y: window.innerHeight / 2 }
  ]);

  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(64);

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      const bestSize = Math.max(38, Math.min(horizontalLimit, verticalLimit, 64));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    const gInd = getRandomUnique(GHOST_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd]);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd, ...rInd]);

    setZombieIndicators(zInd);
    setBombIndices(bInd);
    setPumpkinIndices(pInd);
    setDemonIndices(dInd);
    setCloverIndices(cInd);
    setGhostIndices(gInd);
    setRainbowIndices(rInd);
    setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...clownIndices, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);

    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  };

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) {
      setPumpkinBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    if (demonBoss.isActive) {
      setDemonBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    setActiveZombies(prev => {
      if (prev.length === 0) return prev;
      let nearestIndex = 0;
      let minDistance = Infinity;
      prev.forEach((z, idx) => {
        const dist = Math.min(Math.abs(damagePos - z.pos), TOTAL_TILES - Math.abs(damagePos - z.pos));
        if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
      });
      const newZombies = [...prev];
      const target = { ...newZombies[nearestIndex] };
      target.health -= 1;
      if (target.health <= 0) {
        newZombies.splice(nearestIndex, 1);
      } else { newZombies[nearestIndex] = target; }
      return newZombies;
    });
    setIsShaking(true);
    setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
  }, [pumpkinBoss, demonBoss, activeZombies]);

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    // If sum is 1, it act like a bomb
    if (diceSum === 1) {
       applyBombDamage(tempPos);
    }

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      // Tile interactions on passing
      if (cloverIndices.includes(tempPos)) {
        setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1));
        relocateItem(cloverIndices, tempPos, 'clover');
      }
      if (ghostIndices.includes(tempPos)) {
        setIsGrayscale(true);
        setIsClownMode(false);
        relocateItem(ghostIndices, tempPos, 'ghost');
      }
      if (rainbowIndices.includes(tempPos)) {
        setIsGrayscale(false);
        setIsClownMode(false);
        relocateItem(rainbowIndices, tempPos, 'rainbow');
      }
      if (clownIndices.includes(tempPos)) {
        setIsClownMode(true);
        setIsGrayscale(false);
        relocateItem(clownIndices, tempPos, 'clown');
      }
      if (bombIndices.includes(tempPos)) {
        applyBombDamage(tempPos);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        // Final tile interactions
        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombies(prev => [...prev, {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          }]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }
        if (pumpkinIndices.includes(finalPos)) {
          setPumpkinBoss(prev => ({ isActive: true, health: MAX_PUMPKIN_HEALTH }));
          relocateItem(pumpkinIndices, finalPos, 'pumpkin');
        }
        if (demonIndices.includes(finalPos)) {
          setDemonBoss(prev => ({ isActive: true, health: MAX_DEMON_HEALTH }));
          relocateItem(demonIndices, finalPos, 'demon');
        }

        setActiveZombies(prev => {
          let gameOver = false;
          const moveSteps = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + moveSteps) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) {
            setPlayerHealth(h => {
              const next = h - 1;
              if (next <= 0) {
                handleGameOver();
                return MAX_PLAYER_HEALTH;
              }
              return next;
            });
            return [];
          }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, pumpkinBoss, demonBoss, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, applyBombDamage]);

  const handleGameOver = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setIsGrayscale(false);
    setIsClownMode(false);
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }, index: number) => {
    if (rollBank <= 0 || isRolling || isMoving) return;

    if (pumpkinBoss.isActive) {
      setIsDeducting(true);
      setJarCount(prev => Math.max(0, prev - 5));
      setTimeout(() => setIsDeducting(false), 800);
    }

    setIsRolling(true);
    setRollBank(r => r - 1);

    // Update positions and values for all active dice
    const diceCount = isGrayscale ? 3 : 1;
    const newValues = Array.from({ length: diceCount }, () => Math.floor(Math.random() * 6) + 1);
    const newPositions = Array.from({ length: diceCount }, (_, i) => ({
      x: landing.x + (i - Math.floor(diceCount / 2)) * (isClownMode ? 150 : 80),
      y: landing.y
    }));

    setDicePositions(newPositions);

    setTimeout(() => {
      setIsRolling(false);
      setDiceValues(newValues);
      setIsMoving(true);
      const sum = newValues.reduce((a, b) => a + b, 0);
      processMovement(sum);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  const getClownTileColor = (id: number) => {
    if (!isClownMode) return '';
    const colors = ['#ff00ff', '#00ffff', '#ffff00', '#ff0000', '#00ff00', '#ff8800', '#8800ff'];
    return colors[id % colors.length];
  };

  // Determine current dice count and scales
  const activeDiceCount = isGrayscale ? 3 : 1;
  const currentDiceScale = isClownMode ? 3 : 1;

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden 
      ${isExploding ? 'bg-indigo-600/10' : ''} 
      ${isGrayscale ? 'filter grayscale' : ''}
      ${isClownMode ? 'clown-bg animate-color-chaos' : ''}
    `}>

      {/* Confetti for Clown Mode rolls */}
      {isClownMode && isRolling && <div className="absolute inset-0 z-[100] pointer-events-none confetti-effect" />}

      {/* Tile Board Layer */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombie = zombieIndicators.includes(s.id);
          const isPumpkin = pumpkinIndices.includes(s.id);
          const isDemon = demonIndices.includes(s.id);
          const isClover = cloverIndices.includes(s.id);
          const isGhost = ghostIndices.includes(s.id);
          const isRainbow = rainbowIndices.includes(s.id);
          const isClown = clownIndices.includes(s.id);
          const isStart = s.id === 0;

          let icon = null;
          if (isBomb) icon = BOMB_ICON;
          else if (isZombie) icon = ENEMY_ICON;
          else if (isPumpkin) icon = '🎃';
          else if (isDemon) icon = '👹';
          else if (isClover) icon = '🍀';
          else if (isGhost) icon = '👻';
          else if (isRainbow) icon = '🌈';
          else if (isClown) icon = '🤡';

          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
              style={{ 
                left: s.x, top: s.y, width: tileSize, height: tileSize,
                backgroundColor: isClownMode ? getClownTileColor(s.id) : undefined 
              }}
            >
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {icon && (
                <span className="drop-shadow-sm opacity-25" style={{ fontSize: tileSize * 0.55 }}>
                  {icon}
                </span>
              )}
              {bloom && <span className="bloom absolute opacity-25" style={{ fontSize: tileSize * 0.5 }}>{bloom}</span>}
              {isStart && !bloom && !icon && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}

        {/* Zombies */}
        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[z.pos].x + tileSize/2, 
            top: boardSpaces[z.pos].y + tileSize/2, 
            transform: `translate(-50%, -60%) scale(${demonBoss.isActive ? 2.0 : 1.0})` 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/90 dark:bg-black/80 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-200 dark:bg-gray-800'}`} />
                   ))}
                </div>
                <span className="drop-shadow-2xl animate-pulse" style={{ fontSize: tileSize * 1.2 }}>{ENEMY_ICON}</span>
             </div>
          </div>
        ))}

        {/* Player Piece */}
        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, 
            top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: tileSize * 1.3
          }}
        >
          <div className="flex flex-col items-center">
             <div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (
                   <div key={i} className={`w-2 h-1 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />
                ))}
             </div>
             <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">
               {isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}
             </span>
          </div>
        </div>

        {/* Explosion VFX */}
        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[bombAnimation.pos]?.x + tileSize/2, 
            top: boardSpaces[bombAnimation.pos]?.y + tileSize/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-7xl drop-shadow-2xl">{darkMode ? '✨' : '💥'}</span>
          </div>
        )}
      </div>

      {/* Main UI Container */}
      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-10 scale-90 lg:scale-100 h-[420px]">

          <div className="glass-panel rounded-lg p-5 w-[432px] flex flex-col shadow-sm border border-black/5 dark:border-white/5 bg-white/95 dark:bg-zinc-900/95 transition-all">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span>
                <span className="text-3xl font-normal tabular-nums tracking-tight">{rollBank}</span>
              </div>
              <div className="flex items-center gap-3">
                <div className="flex gap-1.5 p-1 bg-black/5 dark:bg-white/5 rounded">
                  {DICE_COLORS.map(c => (
                    <button 
                      key={c} 
                      onClick={() => setDiceColor(c)} 
                      className={`w-4 h-4 rounded-full border border-black/10 transition-transform ${diceColor === c ? 'scale-125' : 'hover:scale-110'}`} 
                      style={{ background: c }}
                    />
                  ))}
                </div>
                <button onClick={() => setDarkMode(!darkMode)} className="w-8 h-8 flex items-center justify-center rounded hover:bg-black/5 transition-all text-lg">
                  {darkMode ? '☀️' : '🌙'}
                </button>
              </div>
            </div>

            <div className="flex-grow overflow-y-auto pr-1 custom-scrollbar space-y-px">
              {!showHistory ? tasks.map(t => (
                <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-2 hover:bg-black/5 rounded transition-colors flex items-center gap-3 cursor-pointer">
                  <div className="w-3.5 h-3.5 rounded-sm border border-black/20 group-hover:bg-indigo-500/10 group-hover:border-indigo-500 transition-all" />
                  <div className="flex-grow overflow-hidden">
                    <div className="text-[13px] font-medium truncate opacity-90">{t.text}</div>
                    {t.priority && <div className={`inline-block text-[8px] font-black uppercase px-1 rounded-sm mt-0.5 border ${getPriorityColor(t.priority)}`}>{t.priority}</div>}
                  </div>
                </div>
              )) : history.map(h => (
                <div key={h.id} className="p-2 border-l border-indigo-500/10 opacity-40">
                  <span className="text-[12px] line-through block">{h.text}</span>
                  <span className="text-[9px] uppercase tracking-tighter">{h.completedAt}</span>
                </div>
              ))}
            </div>

            <div className="mt-4 pt-4 border-t border-black/5 flex flex-col gap-3">
              <div className="flex gap-1">
                {(['low', 'medium', 'high'] as const).map(p => (
                    <button key={p} onClick={() => setNewTaskPriority(p)} className={`flex-1 py-1 text-[8px] font-bold uppercase rounded border transition-all ${newTaskPriority === p ? 'bg-indigo-600 border-indigo-600 text-white' : 'opacity-50 hover:bg-black/5'}`}>
                        {p}
                    </button>
                ))}
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowHistory(!showHistory)} className="px-3 py-2 text-[10px] font-bold border rounded hover:bg-black/5 transition-colors">{showHistory ? 'Tasks' : 'Log'}</button>
                <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); setNewTask(''); }} className="flex-1">
                    <input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full h-8 bg-black/[0.02] border rounded px-3 text-[12px] outline-none" placeholder="Add mission..." />
                </form>
              </div>
            </div>
          </div>

          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} />

          <div className="w-64 flex flex-col items-center justify-center relative h-[420px] gap-4">
            {pumpkinBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center">
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-orange-500/20 backdrop-blur-md">
                   {[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < pumpkinBoss.health ? 'bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>🎃</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-orange-600/60 mt-1">Pumpkin Boss</span>
              </div>
            )}

            {demonBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center" style={{ animationDelay: '-1.5s' }}>
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-red-500/20 backdrop-blur-md">
                   {[...Array(MAX_DEMON_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < demonBoss.health ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>👹</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-red-600/60 mt-1">Demon Buff</span>
              </div>
            )}
          </div>

          <div className="w-12"></div>
        </div>
      </div>

      {/* Render Dice list */}
      {Array.from({ length: activeDiceCount }).map((_, i) => (
        <Dice3D 
          key={i}
          color={diceColor} 
          value={diceValues[i] || 1} 
          isRolling={isRolling} 
          currentPos={dicePositions[i] || { x: window.innerWidth / 2, y: window.innerHeight / 2 }} 
          onRoll={(landing) => handleRoll(landing, i)} 
          onDragEnd={(finalPos) => setDicePositions(prev => {
            const next = [...prev];
            next[i] = finalPos;
            return next;
          })} 
          scale={currentDiceScale}
        />
      ))}

      <style>{`
        @keyframes bounce-slow {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-12px); }
        }
        .animate-bounce-slow { animation: bounce-slow 3s ease-in-out infinite; }
        @keyframes bomb-drop {
          0% { transform: translate(-50%, -300%) scale(2); opacity: 0; }
          60% { transform: translate(-50%, -60%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(14); opacity: 0; filter: blur(50px); }
        }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.06); background: rgba(255,255,255,0.95); border-radius: 4px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.03); background: rgba(18,18,18,0.95); }
        .glass-panel { backdrop-filter: blur(40px); }

        @keyframes color-chaos {
          0% { background-color: #ff0000; }
          25% { background-color: #00ff00; }
          50% { background-color: #0000ff; }
          75% { background-color: #ffff00; }
          100% { background-color: #ff00ff; }
        }
        .animate-color-chaos { animation: color-chaos 5s infinite linear; }

        .confetti-effect {
          background-image: radial-gradient(circle, #ff0 10%, transparent 10.5%),
                            radial-gradient(circle, #f00 10%, transparent 10.5%),
                            radial-gradient(circle, #0f0 10%, transparent 10.5%),
                            radial-gradient(circle, #00f 10%, transparent 10.5%);
          background-size: 10px 10px, 15px 15px, 20px 20px, 12px 12px;
          background-position: 0 0, 5px 5px, 10px 10px, 15px 15px;
          animation: confetti-fall 2s infinite linear;
          opacity: 0.6;
        }
        @keyframes confetti-fall {
          0% { background-position: 0 0; }
          100% { background-position: 100px 500px; }
        }
      `}</style>

    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

// Updated Tile Counts per request
const ZOMBIE_INDICATOR_COUNT = 10; 
const BOMB_COUNT = 10;           
const PUMPKIN_COUNT = 5; 
const DEMON_COUNT = 5; 
const CLOVER_COUNT = 5; 
const GHOST_COUNT = 3; 
const RAINBOW_COUNT = 3; 
const CLOWN_COUNT = 2; 

// HP Settings
const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

// Board Dimensions for ~72 tiles
const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; // 72
const SPAWN_BEHIND_OFFSET = 5;

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', 
  '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🦌',
  '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤',
  '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.3)', 
  'rgba(199, 210, 254, 0.5)', 
  'rgba(254, 202, 202, 0.5)', 
  'rgba(167, 243, 208, 0.5)', 
  'rgba(253, 230, 138, 0.5)', 
];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  // Multiple dice support
  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([
    { x: window.innerWidth / 2, y: window.innerHeight / 2 }
  ]);

  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(64);

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      const bestSize = Math.max(38, Math.min(horizontalLimit, verticalLimit, 64));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    const gInd = getRandomUnique(GHOST_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd]);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd, ...rInd]);

    setZombieIndicators(zInd);
    setBombIndices(bInd);
    setPumpkinIndices(pInd);
    setDemonIndices(dInd);
    setCloverIndices(cInd);
    setGhostIndices(gInd);
    setRainbowIndices(rInd);
    setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...clownIndices, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);

    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  };

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) {
      setPumpkinBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    if (demonBoss.isActive) {
      setDemonBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    setActiveZombies(prev => {
      if (prev.length === 0) return prev;
      let nearestIndex = 0;
      let minDistance = Infinity;
      prev.forEach((z, idx) => {
        const dist = Math.min(Math.abs(damagePos - z.pos), TOTAL_TILES - Math.abs(damagePos - z.pos));
        if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
      });
      const newZombies = [...prev];
      const target = { ...newZombies[nearestIndex] };
      target.health -= 1;
      if (target.health <= 0) {
        newZombies.splice(nearestIndex, 1);
      } else { newZombies[nearestIndex] = target; }
      return newZombies;
    });
    setIsShaking(true);
    setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
  }, [pumpkinBoss, demonBoss, activeZombies]);

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    // If sum is 1, it act like a bomb
    if (diceSum === 1) {
       applyBombDamage(tempPos);
    }

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      // Tile interactions on passing
      if (cloverIndices.includes(tempPos)) {
        setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1));
        relocateItem(cloverIndices, tempPos, 'clover');
      }
      if (ghostIndices.includes(tempPos)) {
        setIsGrayscale(true);
        setIsClownMode(false);
        relocateItem(ghostIndices, tempPos, 'ghost');
      }
      if (rainbowIndices.includes(tempPos)) {
        setIsGrayscale(false);
        setIsClownMode(false);
        relocateItem(rainbowIndices, tempPos, 'rainbow');
      }
      if (clownIndices.includes(tempPos)) {
        setIsClownMode(true);
        setIsGrayscale(false);
        relocateItem(clownIndices, tempPos, 'clown');
      }
      if (bombIndices.includes(tempPos)) {
        applyBombDamage(tempPos);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        // Final tile interactions
        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombies(prev => [...prev, {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          }]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }
        if (pumpkinIndices.includes(finalPos)) {
          setPumpkinBoss(prev => ({ isActive: true, health: MAX_PUMPKIN_HEALTH }));
          relocateItem(pumpkinIndices, finalPos, 'pumpkin');
        }
        if (demonIndices.includes(finalPos)) {
          setDemonBoss(prev => ({ isActive: true, health: MAX_DEMON_HEALTH }));
          relocateItem(demonIndices, finalPos, 'demon');
        }

        setActiveZombies(prev => {
          let gameOver = false;
          const moveSteps = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + moveSteps) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) {
            setPlayerHealth(h => {
              const next = h - 1;
              if (next <= 0) {
                handleGameOver();
                return MAX_PLAYER_HEALTH;
              }
              return next;
            });
            return [];
          }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, pumpkinBoss, demonBoss, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, applyBombDamage]);

  const handleGameOver = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setIsGrayscale(false);
    setIsClownMode(false);
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }, index: number) => {
    if (rollBank <= 0 || isRolling || isMoving) return;

    if (pumpkinBoss.isActive) {
      setIsDeducting(true);
      setJarCount(prev => Math.max(0, prev - 5));
      setTimeout(() => setIsDeducting(false), 800);
    }

    setIsRolling(true);
    setRollBank(r => r - 1);

    // Update positions and values for all active dice
    const diceCount = isGrayscale ? 3 : 1;
    const newValues = Array.from({ length: diceCount }, () => Math.floor(Math.random() * 6) + 1);
    const newPositions = Array.from({ length: diceCount }, (_, i) => ({
      x: landing.x + (i - Math.floor(diceCount / 2)) * (isClownMode ? 150 : 80),
      y: landing.y
    }));

    setDicePositions(newPositions);

    setTimeout(() => {
      setIsRolling(false);
      setDiceValues(newValues);
      setIsMoving(true);
      const sum = newValues.reduce((a, b) => a + b, 0);
      processMovement(sum);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  const getClownTileColor = (id: number) => {
    if (!isClownMode) return '';
    const colors = ['#ff00ff', '#00ffff', '#ffff00', '#ff0000', '#00ff00', '#ff8800', '#8800ff'];
    return colors[id % colors.length];
  };

  // Determine current dice count and scales
  const activeDiceCount = isGrayscale ? 3 : 1;
  const currentDiceScale = isClownMode ? 3 : 1;

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden 
      ${isExploding ? 'bg-indigo-600/10' : ''} 
      ${isGrayscale ? 'filter grayscale' : ''}
      ${isClownMode ? 'clown-bg animate-color-chaos' : ''}
    `}>

      {/* Confetti for Clown Mode rolls */}
      {isClownMode && isRolling && <div className="absolute inset-0 z-[100] pointer-events-none confetti-effect" />}

      {/* Tile Board Layer */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombie = zombieIndicators.includes(s.id);
          const isPumpkin = pumpkinIndices.includes(s.id);
          const isDemon = demonIndices.includes(s.id);
          const isClover = cloverIndices.includes(s.id);
          const isGhost = ghostIndices.includes(s.id);
          const isRainbow = rainbowIndices.includes(s.id);
          const isClown = clownIndices.includes(s.id);
          const isStart = s.id === 0;

          let icon = null;
          if (isBomb) icon = BOMB_ICON;
          else if (isZombie) icon = ENEMY_ICON;
          else if (isPumpkin) icon = '🎃';
          else if (isDemon) icon = '👹';
          else if (isClover) icon = '🍀';
          else if (isGhost) icon = '👻';
          else if (isRainbow) icon = '🌈';
          else if (isClown) icon = '🤡';

          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
              style={{ 
                left: s.x, top: s.y, width: tileSize, height: tileSize,
                backgroundColor: isClownMode ? getClownTileColor(s.id) : undefined 
              }}
            >
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {icon && (
                <span className="drop-shadow-sm opacity-25" style={{ fontSize: tileSize * 0.55 }}>
                  {icon}
                </span>
              )}
              {bloom && <span className="bloom absolute opacity-25" style={{ fontSize: tileSize * 0.5 }}>{bloom}</span>}
              {isStart && !bloom && !icon && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}

        {/* Zombies */}
        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[z.pos].x + tileSize/2, 
            top: boardSpaces[z.pos].y + tileSize/2, 
            transform: `translate(-50%, -60%) scale(${demonBoss.isActive ? 2.0 : 1.0})` 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/90 dark:bg-black/80 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-200 dark:bg-gray-800'}`} />
                   ))}
                </div>
                <span className="drop-shadow-2xl animate-pulse" style={{ fontSize: tileSize * 1.2 }}>{ENEMY_ICON}</span>
             </div>
          </div>
        ))}

        {/* Player Piece */}
        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, 
            top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: tileSize * 1.3
          }}
        >
          <div className="flex flex-col items-center">
             <div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (
                   <div key={i} className={`w-2 h-1 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />
                ))}
             </div>
             <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">
               {isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}
             </span>
          </div>
        </div>

        {/* Explosion VFX */}
        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[bombAnimation.pos]?.x + tileSize/2, 
            top: boardSpaces[bombAnimation.pos]?.y + tileSize/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-7xl drop-shadow-2xl">{darkMode ? '✨' : '💥'}</span>
          </div>
        )}
      </div>

      {/* Main UI Container */}
      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-10 scale-90 lg:scale-100 h-[420px]">

          <div className="glass-panel rounded-lg p-5 w-[432px] flex flex-col shadow-sm border border-black/5 dark:border-white/5 bg-white/95 dark:bg-zinc-900/95 transition-all">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span>
                <span className="text-3xl font-normal tabular-nums tracking-tight">{rollBank}</span>
              </div>
              <div className="flex items-center gap-3">
                <div className="flex gap-1.5 p-1 bg-black/5 dark:bg-white/5 rounded">
                  {DICE_COLORS.map(c => (
                    <button 
                      key={c} 
                      onClick={() => setDiceColor(c)} 
                      className={`w-4 h-4 rounded-full border border-black/10 transition-transform ${diceColor === c ? 'scale-125' : 'hover:scale-110'}`} 
                      style={{ background: c }}
                    />
                  ))}
                </div>
                <button onClick={() => setDarkMode(!darkMode)} className="w-8 h-8 flex items-center justify-center rounded hover:bg-black/5 transition-all text-lg">
                  {darkMode ? '☀️' : '🌙'}
                </button>
              </div>
            </div>

            <div className="flex-grow overflow-y-auto pr-1 custom-scrollbar space-y-px">
              {!showHistory ? tasks.map(t => (
                <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-2 hover:bg-black/5 rounded transition-colors flex items-center gap-3 cursor-pointer">
                  <div className="w-3.5 h-3.5 rounded-sm border border-black/20 group-hover:bg-indigo-500/10 group-hover:border-indigo-500 transition-all" />
                  <div className="flex-grow overflow-hidden">
                    <div className="text-[13px] font-medium truncate opacity-90">{t.text}</div>
                    {t.priority && <div className={`inline-block text-[8px] font-black uppercase px-1 rounded-sm mt-0.5 border ${getPriorityColor(t.priority)}`}>{t.priority}</div>}
                  </div>
                </div>
              )) : history.map(h => (
                <div key={h.id} className="p-2 border-l border-indigo-500/10 opacity-40">
                  <span className="text-[12px] line-through block">{h.text}</span>
                  <span className="text-[9px] uppercase tracking-tighter">{h.completedAt}</span>
                </div>
              ))}
            </div>

            <div className="mt-4 pt-4 border-t border-black/5 flex flex-col gap-3">
              <div className="flex gap-1">
                {(['low', 'medium', 'high'] as const).map(p => (
                    <button key={p} onClick={() => setNewTaskPriority(p)} className={`flex-1 py-1 text-[8px] font-bold uppercase rounded border transition-all ${newTaskPriority === p ? 'bg-indigo-600 border-indigo-600 text-white' : 'opacity-50 hover:bg-black/5'}`}>
                        {p}
                    </button>
                ))}
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowHistory(!showHistory)} className="px-3 py-2 text-[10px] font-bold border rounded hover:bg-black/5 transition-colors">{showHistory ? 'Tasks' : 'Log'}</button>
                <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); setNewTask(''); }} className="flex-1">
                    <input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full h-8 bg-black/[0.02] border rounded px-3 text-[12px] outline-none" placeholder="Add mission..." />
                </form>
              </div>
            </div>
          </div>

          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} />

          <div className="w-64 flex flex-col items-center justify-center relative h-[420px] gap-4">
            {pumpkinBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center">
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-orange-500/20 backdrop-blur-md">
                   {[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < pumpkinBoss.health ? 'bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>🎃</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-orange-600/60 mt-1">Pumpkin Boss</span>
              </div>
            )}

            {demonBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center" style={{ animationDelay: '-1.5s' }}>
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-red-500/20 backdrop-blur-md">
                   {[...Array(MAX_DEMON_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < demonBoss.health ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>👹</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-red-600/60 mt-1">Demon Buff</span>
              </div>
            )}
          </div>

          <div className="w-12"></div>
        </div>
      </div>

      {/* Render Dice list */}
      {Array.from({ length: activeDiceCount }).map((_, i) => (
        <Dice3D 
          key={i}
          color={diceColor} 
          value={diceValues[i] || 1} 
          isRolling={isRolling} 
          currentPos={dicePositions[i] || { x: window.innerWidth / 2, y: window.innerHeight / 2 }} 
          onRoll={(landing) => handleRoll(landing, i)} 
          onDragEnd={(finalPos) => setDicePositions(prev => {
            const next = [...prev];
            next[i] = finalPos;
            return next;
          })} 
          scale={currentDiceScale}
        />
      ))}

      <style>{`
        @keyframes bounce-slow {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-12px); }
        }
        .animate-bounce-slow { animation: bounce-slow 3s ease-in-out infinite; }
        @keyframes bomb-drop {
          0% { transform: translate(-50%, -300%) scale(2); opacity: 0; }
          60% { transform: translate(-50%, -60%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(14); opacity: 0; filter: blur(50px); }
        }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.06); background: rgba(255,255,255,0.95); border-radius: 4px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.03); background: rgba(18,18,18,0.95); }
        .glass-panel { backdrop-filter: blur(40px); }

        @keyframes color-chaos {
          0% { background-color: #ff0000; }
          25% { background-color: #00ff00; }
          50% { background-color: #0000ff; }
          75% { background-color: #ffff00; }
          100% { background-color: #ff00ff; }
        }
        .animate-color-chaos { animation: color-chaos 5s infinite linear; }

        .confetti-effect {
          background-image: radial-gradient(circle, #ff0 10%, transparent 10.5%),
                            radial-gradient(circle, #f00 10%, transparent 10.5%),
                            radial-gradient(circle, #0f0 10%, transparent 10.5%),
                            radial-gradient(circle, #00f 10%, transparent 10.5%);
          background-size: 10px 10px, 15px 15px, 20px 20px, 12px 12px;
          background-position: 0 0, 5px 5px, 10px 10px, 15px 15px;
          animation: confetti-fall 2s infinite linear;
          opacity: 0.6;
        }
        @keyframes confetti-fall {
          0% { background-position: 0 0; }
          100% { background-position: 100px 500px; }
        }
      `}</style>

    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

// Strictly updated Tile Counts per the latest request ("chỉ có nhiêu này thôi")
const ZOMBIE_INDICATOR_COUNT = 0; 
const BOMB_COUNT = 0;           
const PUMPKIN_COUNT = 0; 
const DEMON_COUNT = 0; 
const CLOVER_COUNT = 0; 
const GHOST_COUNT = 3; 
const RAINBOW_COUNT = 3; 
const CLOWN_COUNT = 2; 

// HP Settings
const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

// Board Dimensions for ~72 tiles
const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; // 72
const SPAWN_BEHIND_OFFSET = 5;

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', 
  '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🦌',
  '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤',
  '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.3)', 
  'rgba(199, 210, 254, 0.5)', 
  'rgba(254, 202, 202, 0.5)', 
  'rgba(167, 243, 208, 0.5)', 
  'rgba(253, 230, 138, 0.5)', 
];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  // Multiple dice support
  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([
    { x: window.innerWidth / 2, y: window.innerHeight / 2 }
  ]);

  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(64);

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      const bestSize = Math.max(38, Math.min(horizontalLimit, verticalLimit, 64));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    if (count <= 0) return [];
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    const gInd = getRandomUnique(GHOST_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd]);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd, ...rInd]);

    setZombieIndicators(zInd);
    setBombIndices(bInd);
    setPumpkinIndices(pInd);
    setDemonIndices(dInd);
    setCloverIndices(cInd);
    setGhostIndices(gInd);
    setRainbowIndices(rInd);
    setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...clownIndices, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);

    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  };

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) {
      setPumpkinBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    if (demonBoss.isActive) {
      setDemonBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    setActiveZombies(prev => {
      if (prev.length === 0) return prev;
      let nearestIndex = 0;
      let minDistance = Infinity;
      prev.forEach((z, idx) => {
        const dist = Math.min(Math.abs(damagePos - z.pos), TOTAL_TILES - Math.abs(damagePos - z.pos));
        if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
      });
      const newZombies = [...prev];
      const target = { ...newZombies[nearestIndex] };
      target.health -= 1;
      if (target.health <= 0) {
        newZombies.splice(nearestIndex, 1);
      } else { newZombies[nearestIndex] = target; }
      return newZombies;
    });
    setIsShaking(true);
    setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
  }, [pumpkinBoss, demonBoss, activeZombies]);

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    if (diceSum === 1) {
       applyBombDamage(tempPos);
    }

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      if (cloverIndices.includes(tempPos)) {
        setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1));
        relocateItem(cloverIndices, tempPos, 'clover');
      }
      if (ghostIndices.includes(tempPos)) {
        setIsGrayscale(true);
        setIsClownMode(false);
        relocateItem(ghostIndices, tempPos, 'ghost');
      }
      if (rainbowIndices.includes(tempPos)) {
        setIsGrayscale(false);
        setIsClownMode(false);
        relocateItem(rainbowIndices, tempPos, 'rainbow');
      }
      if (clownIndices.includes(tempPos)) {
        setIsClownMode(true);
        setIsGrayscale(false);
        relocateItem(clownIndices, tempPos, 'clown');
      }
      if (bombIndices.includes(tempPos)) {
        applyBombDamage(tempPos);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombies(prev => [...prev, {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          }]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }
        if (pumpkinIndices.includes(finalPos)) {
          setPumpkinBoss(prev => ({ isActive: true, health: MAX_PUMPKIN_HEALTH }));
          relocateItem(pumpkinIndices, finalPos, 'pumpkin');
        }
        if (demonIndices.includes(finalPos)) {
          setDemonBoss(prev => ({ isActive: true, health: MAX_DEMON_HEALTH }));
          relocateItem(demonIndices, finalPos, 'demon');
        }

        setActiveZombies(prev => {
          let gameOver = false;
          const moveSteps = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + moveSteps) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) {
            setPlayerHealth(h => {
              const next = h - 1;
              if (next <= 0) {
                handleGameOver();
                return MAX_PLAYER_HEALTH;
              }
              return next;
            });
            return [];
          }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, pumpkinBoss, demonBoss, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, applyBombDamage]);

  const handleGameOver = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setIsGrayscale(false);
    setIsClownMode(false);
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }, index: number) => {
    if (rollBank <= 0 || isRolling || isMoving) return;

    if (pumpkinBoss.isActive) {
      setIsDeducting(true);
      setJarCount(prev => Math.max(0, prev - 5));
      setTimeout(() => setIsDeducting(false), 800);
    }

    setIsRolling(true);
    setRollBank(r => r - 1);

    const diceCount = isGrayscale ? 3 : 1;
    const newValues = Array.from({ length: diceCount }, () => Math.floor(Math.random() * 6) + 1);
    const newPositions = Array.from({ length: diceCount }, (_, i) => ({
      x: landing.x + (i - Math.floor(diceCount / 2)) * (isClownMode ? 150 : 80),
      y: landing.y
    }));

    setDicePositions(newPositions);

    setTimeout(() => {
      setIsRolling(false);
      setDiceValues(newValues);
      setIsMoving(true);
      const sum = newValues.reduce((a, b) => a + b, 0);
      processMovement(sum);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  const getClownTileColor = (id: number) => {
    if (!isClownMode) return '';
    const colors = ['#ff00ff', '#00ffff', '#ffff00', '#ff0000', '#00ff00', '#ff8800', '#8800ff'];
    return colors[id % colors.length];
  };

  const activeDiceCount = isGrayscale ? 3 : 1;
  const currentDiceScale = isClownMode ? 3 : 1;

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden 
      ${isExploding ? 'bg-indigo-600/10' : ''} 
      ${isGrayscale ? 'filter grayscale' : ''}
      ${isClownMode ? 'clown-bg animate-color-chaos' : ''}
    `}>

      {isClownMode && isRolling && <div className="absolute inset-0 z-[100] pointer-events-none confetti-effect" />}

      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombie = zombieIndicators.includes(s.id);
          const isPumpkin = pumpkinIndices.includes(s.id);
          const isDemon = demonIndices.includes(s.id);
          const isClover = cloverIndices.includes(s.id);
          const isGhost = ghostIndices.includes(s.id);
          const isRainbow = rainbowIndices.includes(s.id);
          const isClown = clownIndices.includes(s.id);
          const isStart = s.id === 0;

          let icon = null;
          if (isBomb) icon = BOMB_ICON;
          else if (isZombie) icon = ENEMY_ICON;
          else if (isPumpkin) icon = '🎃';
          else if (isDemon) icon = '👹';
          else if (isClover) icon = '🍀';
          else if (isGhost) icon = '👻';
          else if (isRainbow) icon = '🌈';
          else if (isClown) icon = '🤡';

          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
              style={{ 
                left: s.x, top: s.y, width: tileSize, height: tileSize,
                backgroundColor: isClownMode ? getClownTileColor(s.id) : undefined 
              }}
            >
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {icon && (
                <span className="drop-shadow-sm opacity-25" style={{ fontSize: tileSize * 0.55 }}>
                  {icon}
                </span>
              )}
              {bloom && <span className="bloom absolute opacity-25" style={{ fontSize: tileSize * 0.5 }}>{bloom}</span>}
              {isStart && !bloom && !icon && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}

        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[z.pos].x + tileSize/2, 
            top: boardSpaces[z.pos].y + tileSize/2, 
            transform: `translate(-50%, -60%) scale(${demonBoss.isActive ? 2.0 : 1.0})` 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/90 dark:bg-black/80 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-200 dark:bg-gray-800'}`} />
                   ))}
                </div>
                <span className="drop-shadow-2xl animate-pulse" style={{ fontSize: tileSize * 1.2 }}>{ENEMY_ICON}</span>
             </div>
          </div>
        ))}

        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, 
            top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: tileSize * 1.3
          }}
        >
          <div className="flex flex-col items-center">
             <div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (
                   <div key={i} className={`w-2 h-1 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />
                ))}
             </div>
             <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">
               {isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}
             </span>
          </div>
        </div>

        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[bombAnimation.pos]?.x + tileSize/2, 
            top: boardSpaces[bombAnimation.pos]?.y + tileSize/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-7xl drop-shadow-2xl">{darkMode ? '✨' : '💥'}</span>
          </div>
        )}
      </div>

      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-10 scale-90 lg:scale-100 h-[420px]">

          <div className="glass-panel rounded-lg p-5 w-[432px] flex flex-col shadow-sm border border-black/5 dark:border-white/5 bg-white/95 dark:bg-zinc-900/95 transition-all">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span>
                <span className="text-3xl font-normal tabular-nums tracking-tight">{rollBank}</span>
              </div>
              <div className="flex items-center gap-3">
                <div className="flex gap-1.5 p-1 bg-black/5 dark:bg-white/5 rounded">
                  {DICE_COLORS.map(c => (
                    <button 
                      key={c} 
                      onClick={() => setDiceColor(c)} 
                      className={`w-4 h-4 rounded-full border border-black/10 transition-transform ${diceColor === c ? 'scale-125' : 'hover:scale-110'}`} 
                      style={{ background: c }}
                    />
                  ))}
                </div>
                <button onClick={() => setDarkMode(!darkMode)} className="w-8 h-8 flex items-center justify-center rounded hover:bg-black/5 transition-all text-lg">
                  {darkMode ? '☀️' : '🌙'}
                </button>
              </div>
            </div>

            <div className="flex-grow overflow-y-auto pr-1 custom-scrollbar space-y-px">
              {!showHistory ? tasks.map(t => (
                <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-2 hover:bg-black/5 rounded transition-colors flex items-center gap-3 cursor-pointer">
                  <div className="w-3.5 h-3.5 rounded-sm border border-black/20 group-hover:bg-indigo-500/10 group-hover:border-indigo-500 transition-all" />
                  <div className="flex-grow overflow-hidden">
                    <div className="text-[13px] font-medium truncate opacity-90">{t.text}</div>
                    {t.priority && <div className={`inline-block text-[8px] font-black uppercase px-1 rounded-sm mt-0.5 border ${getPriorityColor(t.priority)}`}>{t.priority}</div>}
                  </div>
                </div>
              )) : history.map(h => (
                <div key={h.id} className="p-2 border-l border-indigo-500/10 opacity-40">
                  <span className="text-[12px] line-through block">{h.text}</span>
                  <span className="text-[9px] uppercase tracking-tighter">{h.completedAt}</span>
                </div>
              ))}
            </div>

            <div className="mt-4 pt-4 border-t border-black/5 flex flex-col gap-3">
              <div className="flex gap-1">
                {(['low', 'medium', 'high'] as const).map(p => (
                    <button key={p} onClick={() => setNewTaskPriority(p)} className={`flex-1 py-1 text-[8px] font-bold uppercase rounded border transition-all ${newTaskPriority === p ? 'bg-indigo-600 border-indigo-600 text-white' : 'opacity-50 hover:bg-black/5'}`}>
                        {p}
                    </button>
                ))}
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowHistory(!showHistory)} className="px-3 py-2 text-[10px] font-bold border rounded hover:bg-black/5 transition-colors">{showHistory ? 'Tasks' : 'Log'}</button>
                <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); setNewTask(''); }} className="flex-1">
                    <input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full h-8 bg-black/[0.02] border rounded px-3 text-[12px] outline-none" placeholder="Add mission..." />
                </form>
              </div>
            </div>
          </div>

          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} />

          <div className="w-64 flex flex-col items-center justify-center relative h-[420px] gap-4">
            {pumpkinBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center">
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-orange-500/20 backdrop-blur-md">
                   {[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < pumpkinBoss.health ? 'bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>🎃</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-orange-600/60 mt-1">Pumpkin Boss</span>
              </div>
            )}

            {demonBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center" style={{ animationDelay: '-1.5s' }}>
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-red-500/20 backdrop-blur-md">
                   {[...Array(MAX_DEMON_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < demonBoss.health ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>👹</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-red-600/60 mt-1">Demon Buff</span>
              </div>
            )}
          </div>

          <div className="w-12"></div>
        </div>
      </div>

      {Array.from({ length: activeDiceCount }).map((_, i) => (
        <Dice3D 
          key={i}
          color={diceColor} 
          value={diceValues[i] || 1} 
          isRolling={isRolling} 
          currentPos={dicePositions[i] || { x: window.innerWidth / 2, y: window.innerHeight / 2 }} 
          onRoll={(landing) => handleRoll(landing, i)} 
          onDragEnd={(finalPos) => setDicePositions(prev => {
            const next = [...prev];
            next[i] = finalPos;
            return next;
          })} 
          scale={currentDiceScale}
        />
      ))}

      <style>{`
        @keyframes bounce-slow {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-12px); }
        }
        .animate-bounce-slow { animation: bounce-slow 3s ease-in-out infinite; }
        @keyframes bomb-drop {
          0% { transform: translate(-50%, -300%) scale(2); opacity: 0; }
          60% { transform: translate(-50%, -60%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(14); opacity: 0; filter: blur(50px); }
        }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.06); background: rgba(255,255,255,0.95); border-radius: 4px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.03); background: rgba(18,18,18,0.95); }
        .glass-panel { backdrop-filter: blur(40px); }

        @keyframes color-chaos {
          0% { background-color: #ff0000; }
          25% { background-color: #00ff00; }
          50% { background-color: #0000ff; }
          75% { background-color: #ffff00; }
          100% { background-color: #ff00ff; }
        }
        .animate-color-chaos { animation: color-chaos 5s infinite linear; }

        .confetti-effect {
          background-image: radial-gradient(circle, #ff0 10%, transparent 10.5%),
                            radial-gradient(circle, #f00 10%, transparent 10.5%),
                            radial-gradient(circle, #0f0 10%, transparent 10.5%),
                            radial-gradient(circle, #00f 10%, transparent 10.5%);
          background-size: 10px 10px, 15px 15px, 20px 20px, 12px 12px;
          background-position: 0 0, 5px 5px, 10px 10px, 15px 15px;
          animation: confetti-fall 2s infinite linear;
          opacity: 0.6;
        }
        @keyframes confetti-fall {
          0% { background-position: 0 0; }
          100% { background-position: 100px 500px; }
        }
      `}</style>

    </div>
  );
};

export default App;

export interface Task {
  id: string;
  title: string;
  description?: string;
  dueDate?: string;
  completed: boolean;
  priority?: 'low' | 'medium' | 'high';
}

export interface BoardSpace {
  id: number;
  x: number;
  y: number;
  type: 'normal' | 'special';
}

export interface BigZombie {
  id: string;
  pos: number;
  health: number;
  isActive: boolean;
}

export interface PumpkinBoss {
  isActive: boolean;
  health: number;
}

export interface DemonBoss {
  isActive: boolean;
  health: number;
}

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

// Tile Counts per latest request
const ZOMBIE_INDICATOR_COUNT = 0; 
const BOMB_COUNT = 0;           
const PUMPKIN_COUNT = 0; 
const DEMON_COUNT = 0; 
const CLOVER_COUNT = 0; 
const GHOST_COUNT = 3; 
const RAINBOW_COUNT = 3; 
const CLOWN_COUNT = 2; 

// HP Settings
const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

// Board Dimensions
const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 
const SPAWN_BEHIND_OFFSET = 5;

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🦌', '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤', '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.3)', 'rgba(199, 210, 254, 0.5)', 'rgba(254, 202, 202, 0.5)', 'rgba(167, 243, 208, 0.5)', 'rgba(253, 230, 138, 0.5)', 
];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  // Tasks State
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', title: 'Nạp đầy Alchemy', description: 'Đạt mốc 100 năng lượng trong bình chứa', completed: false, priority: 'high', dueDate: 'Today' },
    { id: '2', title: 'Thu thập 3 Cầu vồng', description: 'Chạm vào ô 🌈 để xóa bỏ lời nguyền Ghost', completed: false, priority: 'medium' },
    { id: '3', title: 'Lắc xúc xắc 6', description: 'Cố gắng quay được điểm cao nhất', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);

  // Task Creation Form State
  const [isAddingTask, setIsAddingTask] = useState(false);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskDesc, setNewTaskDesc] = useState('');
  const [newTaskDueDate, setNewTaskDueDate] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([{ x: window.innerWidth / 2, y: window.innerHeight / 2 }]);

  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(64);

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      const bestSize = Math.max(38, Math.min(horizontalLimit, verticalLimit, 64));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    for (let i = 0; i < BOARD_W; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    if (count <= 0) return [];
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const gInd = getRandomUnique(GHOST_COUNT, startExclude);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...gInd, ...rInd]);

    setGhostIndices(gInd);
    setRainbowIndices(rInd);
    setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...clownIndices, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);

    switch(type) {
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  };

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    setIsShaking(true);
    setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
  }, []);

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      if (ghostIndices.includes(tempPos)) {
        setIsGrayscale(true);
        setIsClownMode(false);
        relocateItem(ghostIndices, tempPos, 'ghost');
      }
      if (rainbowIndices.includes(tempPos)) {
        setIsGrayscale(false);
        setIsClownMode(false);
        relocateItem(rainbowIndices, tempPos, 'rainbow');
      }
      if (clownIndices.includes(tempPos)) {
        setIsClownMode(true);
        setIsGrayscale(false);
        relocateItem(clownIndices, tempPos, 'clown');
      }

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, ghostIndices, rainbowIndices, clownIndices]);

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);

    const diceCount = isGrayscale ? 3 : 1;
    const newValues = Array.from({ length: diceCount }, () => Math.floor(Math.random() * 6) + 1);
    const newPositions = Array.from({ length: diceCount }, (_, i) => ({
      x: landing.x + (i - Math.floor(diceCount / 2)) * (isClownMode ? 150 : 80),
      y: landing.y
    }));

    setDicePositions(newPositions);

    setTimeout(() => {
      setIsRolling(false);
      setDiceValues(newValues);
      setIsMoving(true);
      const sum = newValues.reduce((a, b) => a + b, 0);
      processMovement(sum);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  const handleAddNewTask = (e: React.FormEvent) => {
    e.preventDefault();
    if(!newTaskTitle.trim()) return;
    const newTask: Task = {
      id: Date.now().toString(),
      title: newTaskTitle,
      description: newTaskDesc,
      dueDate: newTaskDueDate,
      priority: newTaskPriority,
      completed: false
    };
    setTasks([newTask, ...tasks]);
    setNewTaskTitle('');
    setNewTaskDesc('');
    setNewTaskDueDate('');
    setIsAddingTask(false);
  };

  const activeDiceCount = isGrayscale ? 3 : 1;
  const currentDiceScale = isClownMode ? 3 : 1;

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden 
      ${isExploding ? 'bg-indigo-600/10' : ''} 
      ${isGrayscale ? 'filter grayscale' : ''}
      ${isClownMode ? 'clown-bg animate-color-chaos' : ''}
    `}>

      {isClownMode && isRolling && <div className="absolute inset-0 z-[100] pointer-events-none confetti-effect" />}

      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const isGhost = ghostIndices.includes(s.id);
          const isRainbow = rainbowIndices.includes(s.id);
          const isClown = clownIndices.includes(s.id);
          const isStart = s.id === 0;
          let icon = null;
          if (isGhost) icon = '👻';
          else if (isRainbow) icon = '🌈';
          else if (isClown) icon = '🤡';

          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
              style={{ left: s.x, top: s.y, width: tileSize, height: tileSize, backgroundColor: isClownMode ? 'transparent' : undefined }}
            >
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {icon && <span className="drop-shadow-sm opacity-25" style={{ fontSize: tileSize * 0.55 }}>{icon}</span>}
              {isStart && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}

        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto`}
          style={{ left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, transform: 'translate(-50%, -60%)', fontSize: tileSize * 1.3 }}
        >
          <div className="flex flex-col items-center">
             <div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (
                   <div key={i} className={`w-2 h-1 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />
                ))}
             </div>
             <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">{isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}</span>
          </div>
        </div>
      </div>

      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-10 scale-90 lg:scale-100 h-[520px]">

          <div className="glass-panel rounded-xl p-5 w-[460px] flex flex-col shadow-2xl border border-black/5 dark:border-white/5 bg-white/90 dark:bg-zinc-900/90 transition-all">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span>
                <span className="text-4xl font-normal tabular-nums tracking-tighter text-indigo-600 dark:text-indigo-400">{rollBank}</span>
              </div>
              <div className="flex items-center gap-3">
                <button onClick={() => setDarkMode(!darkMode)} className="w-10 h-10 flex items-center justify-center rounded-lg hover:bg-black/5 dark:hover:bg-white/5 transition-all text-xl">
                  {darkMode ? '☀️' : '🌙'}
                </button>
              </div>
            </div>

            <div className="flex-grow overflow-y-auto pr-1 custom-scrollbar space-y-3">
              <div className="flex items-center justify-between mb-2">
                 <h2 className="text-sm font-bold opacity-40 uppercase tracking-widest">{showHistory ? 'History' : 'Active Missions'}</h2>
                 <button onClick={() => setShowHistory(!showHistory)} className="text-[10px] font-bold text-indigo-500 hover:underline">{showHistory ? 'Back to Tasks' : 'View Log'}</button>
              </div>

              {!showHistory ? (
                <>
                  {tasks.map(t => (
                    <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-3 bg-white dark:bg-zinc-800/50 rounded-lg border border-black/5 dark:border-white/5 hover:border-indigo-500/50 transition-all cursor-pointer shadow-sm hover:shadow-md">
                      <div className="flex items-start gap-3">
                        <div className="mt-1 w-4 h-4 rounded border border-black/10 dark:border-white/10 group-hover:bg-indigo-500 group-hover:border-indigo-500 transition-all flex items-center justify-center">
                           <span className="text-white text-[10px] opacity-0 group-hover:opacity-100">✓</span>
                        </div>
                        <div className="flex-grow">
                          <div className="flex items-center justify-between">
                             <span className="text-[14px] font-semibold opacity-90">{t.title}</span>
                             {t.priority && <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-full border ${getPriorityColor(t.priority)}`}>{t.priority}</span>}
                          </div>
                          {t.description && <p className="text-[11px] opacity-50 mt-1 line-clamp-2">{t.description}</p>}
                          {t.dueDate && (
                            <div className="flex items-center gap-1 mt-2 opacity-40">
                               <span className="text-[10px]">🕒 {t.dueDate}</span>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  ))}

                  {isAddingTask ? (
                    <form onSubmit={handleAddNewTask} className="p-4 bg-black/5 dark:bg-white/5 rounded-lg space-y-3 border border-indigo-500/20">
                      <input autoFocus value={newTaskTitle} onChange={e => setNewTaskTitle(e.target.value)} className="w-full bg-transparent border-b border-black/10 dark:border-white/10 py-1 text-sm outline-none font-bold" placeholder="Task Title..." />
                      <textarea value={newTaskDesc} onChange={e => setNewTaskDesc(e.target.value)} className="w-full bg-transparent py-1 text-xs outline-none h-16 resize-none" placeholder="Add a description..." />
                      <div className="flex gap-2">
                        <input value={newTaskDueDate} onChange={e => setNewTaskDueDate(e.target.value)} className="flex-1 bg-white/50 dark:bg-black/20 text-[10px] rounded px-2 py-1 outline-none border border-black/5" placeholder="Due date (e.g. 10 PM)" />
                        <select value={newTaskPriority} onChange={e => setNewTaskPriority(e.target.value as any)} className="bg-white/50 dark:bg-black/20 text-[10px] rounded px-2 py-1 outline-none border border-black/5">
                           <option value="low">Low</option>
                           <option value="medium">Medium</option>
                           <option value="high">High</option>
                        </select>
                      </div>
                      <div className="flex gap-2 pt-2">
                        <button type="submit" className="flex-1 py-2 bg-indigo-600 text-white text-[10px] font-bold rounded-md hover:bg-indigo-700">Add Task</button>
                        <button type="button" onClick={() => setIsAddingTask(false)} className="px-4 py-2 text-[10px] font-bold opacity-40 hover:opacity-100">Cancel</button>
                      </div>
                    </form>
                  ) : (
                    <button onClick={() => setIsAddingTask(true)} className="w-full py-3 border-2 border-dashed border-black/5 dark:border-white/5 rounded-lg text-[11px] font-bold opacity-40 hover:opacity-100 hover:border-indigo-500/50 transition-all">+ New Mission</button>
                  )}
                </>
              ) : history.map(h => (
                <div key={h.id} className="p-3 bg-black/[0.02] dark:bg-white/[0.02] rounded-lg border border-black/5 dark:border-white/5 opacity-50">
                  <div className="flex items-center justify-between">
                    <span className="text-xs font-semibold line-through">{h.title}</span>
                    <span className="text-[9px] opacity-60 uppercase">{h.completedAt}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} />

          <div className="w-64 flex flex-col items-center justify-center h-full">
            <div className="dice-color-picker flex gap-2 p-2 glass-panel rounded-full mb-8">
               {DICE_COLORS.map(c => (
                 <button key={c} onClick={() => setDiceColor(c)} className={`w-6 h-6 rounded-full border-2 transition-transform ${diceColor === c ? 'scale-125 border-indigo-500' : 'border-white/20 hover:scale-110'}`} style={{ background: c }} />
               ))}
            </div>
          </div>
        </div>
      </div>

      {Array.from({ length: activeDiceCount }).map((_, i) => (
        <Dice3D 
          key={i}
          color={diceColor} 
          value={diceValues[i] || 1} 
          isRolling={isRolling} 
          currentPos={dicePositions[i] || { x: window.innerWidth / 2, y: window.innerHeight / 2 }} 
          onRoll={handleRoll} 
          onDragEnd={(finalPos) => setDicePositions(prev => {
            const next = [...prev];
            next[i] = finalPos;
            return next;
          })} 
          scale={currentDiceScale}
        />
      ))}

      <style>{`
        @keyframes color-chaos {
          0% { background-color: #ff0000; }
          25% { background-color: #00ff00; }
          50% { background-color: #0000ff; }
          75% { background-color: #ffff00; }
          100% { background-color: #ff00ff; }
        }
        .animate-color-chaos { animation: color-chaos 5s infinite linear; }
        .clown-bg { background-image: radial-gradient(circle, rgba(255,255,255,0.2) 2px, transparent 2.5px); background-size: 20px 20px; }
        .confetti-effect {
          background-image: radial-gradient(circle, #ff0 10%, transparent 10.5%),
                            radial-gradient(circle, #f00 10%, transparent 10.5%),
                            radial-gradient(circle, #0f0 10%, transparent 10.5%),
                            radial-gradient(circle, #00f 10%, transparent 10.5%);
          background-size: 10px 10px, 15px 15px, 20px 20px, 12px 12px;
          background-position: 0 0, 5px 5px, 10px 10px, 15px 15px;
          animation: confetti-fall 2s infinite linear;
          opacity: 0.6;
        }
        @keyframes confetti-fall {
          0% { background-position: 0 0; }
          100% { background-position: 100px 500px; }
        }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.1); border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

// Tile Counts per latest request
const ZOMBIE_INDICATOR_COUNT = 0; 
const BOMB_COUNT = 0;           
const PUMPKIN_COUNT = 0; 
const DEMON_COUNT = 0; 
const CLOVER_COUNT = 0; 
const GHOST_COUNT = 3; 
const RAINBOW_COUNT = 3; 
const CLOWN_COUNT = 2; 

// HP Settings
const MAX_PLAYER_HEALTH = 5; 

// Board Dimensions
const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🦌', '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', 'FOX', 'WOLF',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤', '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.3)', 'rgba(199, 210, 254, 0.5)', 'rgba(254, 202, 202, 0.5)', 'rgba(167, 243, 208, 0.5)', 'rgba(253, 230, 138, 0.5)', 
];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  // Tasks State
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', title: 'Nạp đầy Alchemy', description: 'Đạt mốc 100 năng lượng trong bình chứa để mở khóa phần thưởng đặc biệt.', completed: false, priority: 'high', dueDate: '10:00 PM' },
    { id: '2', title: 'Thu thập 3 Cầu vồng', description: 'Chạm vào ô 🌈 để xóa bỏ hiệu ứng xám của lời nguyền Ghost.', completed: false, priority: 'medium', dueDate: 'Today' },
    { id: '3', title: 'Thử vận may', description: 'Cố gắng lắc được xúc xắc 6 để nhận thêm 1 lượt Energy miễn phí.', completed: false, priority: 'low', dueDate: 'Soon' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);

  // Task Creation Form State
  const [isAddingTask, setIsAddingTask] = useState(false);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskDesc, setNewTaskDesc] = useState('');
  const [newTaskDueDate, setNewTaskDueDate] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([{ x: window.innerWidth / 2, y: window.innerHeight / 2 }]);

  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(64);

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      const bestSize = Math.max(38, Math.min(horizontalLimit, verticalLimit, 64));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    for (let i = 0; i < BOARD_W; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    if (count <= 0) return [];
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const gInd = getRandomUnique(GHOST_COUNT, startExclude);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...gInd, ...rInd]);

    setGhostIndices(gInd);
    setRainbowIndices(rInd);
    setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...ghostIndices, ...rainbowIndices, ...clownIndices];
    const [newPos] = getRandomUnique(1, exclude);

    switch(type) {
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  };

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      if (ghostIndices.includes(tempPos)) {
        setIsGrayscale(true);
        setIsClownMode(false);
        relocateItem(ghostIndices, tempPos, 'ghost');
      }
      if (rainbowIndices.includes(tempPos)) {
        setIsGrayscale(false);
        setIsClownMode(false);
        relocateItem(rainbowIndices, tempPos, 'rainbow');
      }
      if (clownIndices.includes(tempPos)) {
        setIsClownMode(true);
        setIsGrayscale(false);
        relocateItem(clownIndices, tempPos, 'clown');
      }

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, ghostIndices, rainbowIndices, clownIndices]);

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);

    const diceCount = isGrayscale ? 3 : 1;
    const newValues = Array.from({ length: diceCount }, () => Math.floor(Math.random() * 6) + 1);
    const newPositions = Array.from({ length: diceCount }, (_, i) => ({
      x: landing.x + (i - Math.floor(diceCount / 2)) * (isClownMode ? 150 : 80),
      y: landing.y
    }));

    setDicePositions(newPositions);

    setTimeout(() => {
      setIsRolling(false);
      setDiceValues(newValues);
      setIsMoving(true);
      const sum = newValues.reduce((a, b) => a + b, 0);
      processMovement(sum);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-700 border-red-200 dark:bg-red-900/30 dark:text-red-300 dark:border-red-900/50';
        case 'medium': return 'bg-amber-50 text-amber-700 border-amber-200 dark:bg-amber-900/30 dark:text-amber-300 dark:border-amber-900/50';
        default: return 'bg-sky-50 text-sky-700 border-sky-200 dark:bg-sky-900/30 dark:text-sky-300 dark:border-sky-900/50';
    }
  }

  const handleAddNewTask = (e: React.FormEvent) => {
    e.preventDefault();
    if(!newTaskTitle.trim()) return;
    const newTask: Task = {
      id: Date.now().toString(),
      title: newTaskTitle,
      description: newTaskDesc,
      dueDate: newTaskDueDate,
      priority: newTaskPriority,
      completed: false
    };
    setTasks([newTask, ...tasks]);
    setNewTaskTitle('');
    setNewTaskDesc('');
    setNewTaskDueDate('');
    setIsAddingTask(false);
  };

  const activeDiceCount = isGrayscale ? 3 : 1;
  const currentDiceScale = isClownMode ? 3 : 1;

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden 
      ${isExploding ? 'bg-indigo-600/10' : ''} 
      ${isGrayscale ? 'filter grayscale' : ''}
      ${isClownMode ? 'clown-bg animate-color-chaos' : ''}
    `}>

      {isClownMode && isRolling && <div className="absolute inset-0 z-[100] pointer-events-none confetti-effect" />}

      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const isGhost = ghostIndices.includes(s.id);
          const isRainbow = rainbowIndices.includes(s.id);
          const isClown = clownIndices.includes(s.id);
          const isStart = s.id === 0;
          let icon = null;
          if (isGhost) icon = '👻';
          else if (isRainbow) icon = '🌈';
          else if (isClown) icon = '🤡';

          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
              style={{ left: s.x, top: s.y, width: tileSize, height: tileSize, backgroundColor: isClownMode ? 'transparent' : undefined }}
            >
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {icon && <span className="drop-shadow-sm opacity-25" style={{ fontSize: tileSize * 0.55 }}>{icon}</span>}
              {isStart && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}

        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto`}
          style={{ left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, transform: 'translate(-50%, -60%)', fontSize: tileSize * 1.3 }}
        >
          <div className="flex flex-col items-center">
             <div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (
                   <div key={i} className={`w-2 h-1 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />
                ))}
             </div>
             <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">{isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}</span>
          </div>
        </div>
      </div>

      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-10 scale-90 lg:scale-100 h-[580px]">

          <div className="glass-panel rounded-2xl p-6 w-[480px] flex flex-col shadow-2xl border border-black/10 dark:border-white/10 bg-white/90 dark:bg-zinc-900/90 transition-all overflow-hidden">
            <div className="flex justify-between items-start mb-8">
              <div>
                <span className="text-[11px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Total Power</span>
                <span className="text-5xl font-black tabular-nums tracking-tighter text-indigo-600 dark:text-indigo-400">{rollBank}</span>
              </div>
              <div className="flex items-center gap-2">
                <button onClick={() => setDarkMode(!darkMode)} className="w-10 h-10 flex items-center justify-center rounded-xl bg-black/5 dark:bg-white/5 hover:bg-black/10 transition-all text-xl">
                  {darkMode ? '☀️' : '🌙'}
                </button>
              </div>
            </div>

            <div className="flex-grow overflow-y-auto pr-2 custom-scrollbar space-y-4">
              <div className="flex items-center justify-between mb-4">
                 <h2 className="text-xs font-black opacity-30 uppercase tracking-[0.3em]">{showHistory ? 'History Log' : 'Objectives'}</h2>
                 <button onClick={() => setShowHistory(!showHistory)} className="text-[11px] font-bold text-indigo-600 dark:text-indigo-400 bg-indigo-50 dark:bg-indigo-900/30 px-3 py-1 rounded-full hover:scale-105 transition-all">
                   {showHistory ? 'Active' : 'History'}
                 </button>
              </div>

              {!showHistory ? (
                <>
                  <div className="space-y-3">
                    {tasks.map(t => (
                      <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-4 bg-white dark:bg-zinc-800 rounded-xl border border-black/5 dark:border-white/5 hover:border-indigo-500/50 transition-all cursor-pointer shadow-sm hover:shadow-xl hover:-translate-y-1">
                        <div className="flex items-start gap-4">
                          <div className="mt-1 w-5 h-5 rounded-md border-2 border-black/10 dark:border-white/10 group-hover:bg-indigo-500 group-hover:border-indigo-500 transition-all flex items-center justify-center">
                             <span className="text-white text-xs opacity-0 group-hover:opacity-100 font-bold">✓</span>
                          </div>
                          <div className="flex-grow">
                            <div className="flex items-center justify-between gap-2 mb-1">
                               <span className="text-[15px] font-bold tracking-tight opacity-90 leading-tight">{t.title}</span>
                               <span className={`text-[9px] font-black uppercase px-2 py-0.5 rounded border leading-none shrink-0 ${getPriorityColor(t.priority)}`}>{t.priority}</span>
                            </div>
                            {t.description && <p className="text-[12px] opacity-50 mt-1 leading-relaxed">{t.description}</p>}
                            <div className="flex items-center gap-3 mt-3">
                               {t.dueDate && (
                                  <div className="flex items-center gap-1.5 opacity-60 bg-black/5 dark:bg-white/5 px-2 py-1 rounded-md">
                                     <span className="text-[10px] font-bold">🕒 {t.dueDate}</span>
                                  </div>
                               )}
                               <div className="flex items-center gap-1.5 opacity-60 bg-black/5 dark:bg-white/5 px-2 py-1 rounded-md">
                                  <span className="text-[10px] font-bold">⚡ +15 Rolls</span>
                               </div>
                            </div>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>

                  {isAddingTask ? (
                    <form onSubmit={handleAddNewTask} className="p-5 bg-indigo-50/50 dark:bg-indigo-950/20 rounded-2xl space-y-4 border border-indigo-500/30 animate-in slide-in-from-top-4 duration-300">
                      <div className="space-y-1">
                         <label className="text-[10px] font-black uppercase tracking-widest opacity-40">Task Title</label>
                         <input autoFocus value={newTaskTitle} onChange={e => setNewTaskTitle(e.target.value)} className="w-full bg-transparent border-b-2 border-black/10 dark:border-white/10 py-2 text-base outline-none font-bold focus:border-indigo-500 transition-all" placeholder="Enter task title..." />
                      </div>
                      <div className="space-y-1">
                         <label className="text-[10px] font-black uppercase tracking-widest opacity-40">Description</label>
                         <textarea value={newTaskDesc} onChange={e => setNewTaskDesc(e.target.value)} className="w-full bg-black/5 dark:bg-white/5 rounded-lg p-3 text-sm outline-none h-24 resize-none focus:ring-2 focus:ring-indigo-500/20" placeholder="Describe the goal..." />
                      </div>
                      <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1">
                          <label className="text-[10px] font-black uppercase tracking-widest opacity-40">Due Time/Date</label>
                          <input value={newTaskDueDate} onChange={e => setNewTaskDueDate(e.target.value)} className="w-full bg-white dark:bg-black/40 text-[12px] rounded-lg px-3 py-2 outline-none border border-black/5 focus:border-indigo-500" placeholder="e.g. 10 PM, Friday" />
                        </div>
                        <div className="space-y-1">
                          <label className="text-[10px] font-black uppercase tracking-widest opacity-40">Priority</label>
                          <select value={newTaskPriority} onChange={e => setNewTaskPriority(e.target.value as any)} className="w-full bg-white dark:bg-black/40 text-[12px] rounded-lg px-3 py-2 outline-none border border-black/5 focus:border-indigo-500 appearance-none">
                             <option value="low">Low</option>
                             <option value="medium">Medium</option>
                             <option value="high">High</option>
                          </select>
                        </div>
                      </div>
                      <div className="flex gap-3 pt-2">
                        <button type="submit" className="flex-1 py-3 bg-indigo-600 text-white text-[13px] font-black rounded-xl hover:bg-indigo-700 shadow-lg shadow-indigo-600/20 transition-all">Add Mission</button>
                        <button type="button" onClick={() => setIsAddingTask(false)} className="px-5 py-3 text-[13px] font-bold opacity-40 hover:opacity-100 transition-all">Cancel</button>
                      </div>
                    </form>
                  ) : (
                    <button onClick={() => setIsAddingTask(true)} className="w-full py-5 border-2 border-dashed border-black/10 dark:border-white/10 rounded-2xl text-[12px] font-black uppercase tracking-widest opacity-30 hover:opacity-100 hover:border-indigo-500/50 hover:bg-indigo-50/10 transition-all">
                      + Create New Objective
                    </button>
                  )}
                </>
              ) : (
                <div className="space-y-2">
                   {history.map(h => (
                    <div key={h.id} className="p-4 bg-black/[0.02] dark:bg-white/[0.02] rounded-xl border border-black/5 dark:border-white/5 opacity-60">
                      <div className="flex items-center justify-between">
                        <div>
                           <span className="text-sm font-bold line-through block">{h.title}</span>
                           <span className="text-[10px] opacity-50 block mt-1">{h.description}</span>
                        </div>
                        <span className="text-[10px] font-black opacity-60 bg-black/5 px-2 py-1 rounded shrink-0 uppercase tracking-tighter">{h.completedAt}</span>
                      </div>
                    </div>
                  ))}
                  {history.length === 0 && (
                    <div className="py-10 text-center opacity-20 text-sm font-bold uppercase tracking-widest italic">No finished missions yet...</div>
                  )}
                </div>
              )}
            </div>
          </div>

          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} />

          <div className="w-64 flex flex-col items-center justify-center h-full">
            <div className="dice-color-picker flex gap-3 p-3 glass-panel rounded-3xl mb-12 shadow-2xl border border-white/20">
               {DICE_COLORS.map(c => (
                 <button key={c} onClick={() => setDiceColor(c)} className={`w-8 h-8 rounded-full border-2 transition-all ${diceColor === c ? 'scale-125 border-indigo-500 shadow-xl' : 'border-white/10 hover:scale-110'}`} style={{ background: c }} />
               ))}
            </div>
          </div>
        </div>
      </div>

      {Array.from({ length: activeDiceCount }).map((_, i) => (
        <Dice3D 
          key={i}
          color={diceColor} 
          value={diceValues[i] || 1} 
          isRolling={isRolling} 
          currentPos={dicePositions[i] || { x: window.innerWidth / 2, y: window.innerHeight / 2 }} 
          onRoll={handleRoll} 
          onDragEnd={(finalPos) => setDicePositions(prev => {
            const next = [...prev];
            next[i] = finalPos;
            return next;
          })} 
          scale={currentDiceScale}
        />
      ))}

      <style>{`
        @keyframes color-chaos {
          0% { background-color: #ff0000; }
          25% { background-color: #00ff00; }
          50% { background-color: #0000ff; }
          75% { background-color: #ffff00; }
          100% { background-color: #ff00ff; }
        }
        .animate-color-chaos { animation: color-chaos 5s infinite linear; }
        .clown-bg { background-image: radial-gradient(circle, rgba(255,255,255,0.2) 2px, transparent 2.5px); background-size: 20px 20px; }
        .confetti-effect {
          background-image: radial-gradient(circle, #ff0 10%, transparent 10.5%),
                            radial-gradient(circle, #f00 10%, transparent 10.5%),
                            radial-gradient(circle, #0f0 10%, transparent 10.5%),
                            radial-gradient(circle, #00f 10%, transparent 10.5%);
          background-size: 10px 10px, 15px 15px, 20px 20px, 12px 12px;
          background-position: 0 0, 5px 5px, 10px 10px, 15px 15px;
          animation: confetti-fall 2s infinite linear;
          opacity: 0.6;
        }
        @keyframes confetti-fall {
          0% { background-position: 0 0; }
          100% { background-position: 100px 500px; }
        }
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.1); border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); }

        .animate-in { animation: animate-in 0.3s ease-out; }
        @keyframes animate-in {
          from { opacity: 0; transform: translateY(-10px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </div>
  );
};

