import React, { useState, useRef, useEffect } from 'react';

interface AlchemyJarProps {
  count: number;
  max: number;
  isExploding: boolean;
  onExplode: () => void;
  isDeducting?: boolean;
  liquidColor?: string;
}

export const AlchemyJar: React.FC<AlchemyJarProps> = ({ count, max, isExploding, onExplode, isDeducting, liquidColor = '#6366f1' }) => {
  const percent = Math.min(100, (count / max) * 100);
  const isFull = count >= max;
  const [holdProgress, setHoldProgress] = useState(0);
  const holdInterval = useRef<number | null>(null);

  const startHold = () => {
    if (!isFull || isExploding) return;
    holdInterval.current = window.setInterval(() => {
      setHoldProgress(prev => {
        if (prev >= 100) {
          if (holdInterval.current) clearInterval(holdInterval.current);
          onExplode();
          return 0;
        }
        return prev + 1;
      });
    }, 30);
  };

  const endHold = () => {
    if (holdInterval.current) {
      clearInterval(holdInterval.current);
      holdInterval.current = null;
    }
    setHoldProgress(0);
  };

  return (
    <div className="flex flex-col gap-4 h-[420px] w-32">
      <div 
        className={`relative flex-grow bg-white/5 dark:bg-black/20 border-4 border-black/10 dark:border-white/10 rounded-b-[45px] rounded-t-[15px] overflow-hidden backdrop-blur-3xl transition-all duration-700 shadow-inner ${isExploding ? 'scale-150 blur-3xl opacity-0' : 'scale-100'}`}
      >
        <div 
          className="absolute bottom-0 left-0 w-full transition-all duration-700 ease-out"
          style={{ 
            height: `${percent}%`,
            backgroundColor: liquidColor
          }}
        >
          {/* Simple Bubbles */}
          {percent > 0 && (
            <div className="absolute inset-0 overflow-hidden">
               {[...Array(5)].map((_, i) => (
                 <div 
                   key={i} 
                   className="absolute bottom-0 bg-white/20 rounded-full animate-bubble"
                   style={{
                     width: Math.random() * 8 + 4,
                     height: Math.random() * 8 + 4,
                     left: `${Math.random() * 100}%`,
                     animationDuration: `${Math.random() * 2 + 1}s`,
                     animationDelay: `${Math.random() * 2}s`
                   }}
                 />
               ))}
            </div>
          )}
        </div>

        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
          <div className="flex flex-col items-center">
            <span className="text-2xl font-black text-white drop-shadow-md">
              {Math.floor(percent)}%
            </span>
            <span className="text-[8px] font-black uppercase tracking-widest opacity-40 text-white">Power</span>
          </div>
        </div>
      </div>

      <div className="w-full relative h-16 flex flex-col justify-end">
        {holdProgress > 0 && (
          <div className="absolute top-0 left-0 w-full h-1 bg-gray-100 dark:bg-white/5 rounded-full overflow-hidden">
             <div className="h-full bg-indigo-500 shadow-[0_0_10px_#6366f1]" style={{ width: `${holdProgress}%` }} />
          </div>
        )}
        <button
          onMouseDown={startHold}
          onMouseUp={endHold}
          onMouseLeave={endHold}
          onTouchStart={startHold}
          onTouchEnd={endHold}
          disabled={!isFull || isExploding}
          className={`w-full h-12 rounded-xl text-[10px] font-black uppercase tracking-[0.2em] transition-all border-2
            ${isFull 
              ? 'bg-indigo-600 text-white border-indigo-500 shadow-xl shadow-indigo-500/20 cursor-pointer hover:scale-105 active:scale-95' 
              : 'bg-black/5 dark:bg-white/5 text-gray-400 border-transparent cursor-not-allowed'
            }`}
        >
          {isFull ? (holdProgress > 0 ? 'Hold...' : 'Extract') : 'Collecting'}
        </button>
      </div>

      <style>{`
        @keyframes bubble {
          0% { transform: translateY(0) scale(0.5); opacity: 0; }
          50% { opacity: 0.5; }
          100% { transform: translateY(-100px) scale(1.5); opacity: 0; }
        }
        .animate-bubble { animation: bubble linear infinite; }
      `}</style>
    </div>
  );
};

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

// Strictly updated Tile Counts per request
const ZOMBIE_INDICATOR_COUNT = 0; 
const BOMB_COUNT = 0;           
const PUMPKIN_COUNT = 0; 
const DEMON_COUNT = 0; 
const CLOVER_COUNT = 0; 
const GHOST_COUNT = 3; 
const RAINBOW_COUNT = 3; 
const CLOWN_COUNT = 2; 

// HP Settings
const MAX_PLAYER_HEALTH = 5; 

// Board Dimensions
const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🦌', '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤', '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.3)', 'rgba(199, 210, 254, 0.5)', 'rgba(254, 202, 202, 0.5)', 'rgba(167, 243, 208, 0.5)', 'rgba(253, 230, 138, 0.5)', 
];

const JAR_COLOR = '#6366f1';

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  // Tasks State
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', title: 'Alchemy Recharge', description: 'Reach 100% alchemy volume to extract massive roll energy.', completed: false, priority: 'high', dueDate: 'Soon' },
    { id: '2', title: 'Ghost Hunt', description: 'Find 3 Ghost tiles while navigating the elite board.', completed: false, priority: 'medium', dueDate: 'Ongoing' },
    { id: '3', title: 'Luck Master', description: 'Roll a perfect 6 to demonstrate your elite status.', completed: false, priority: 'low', dueDate: 'Anytime' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);

  // Task Form
  const [isAddingTask, setIsAddingTask] = useState(false);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskDesc, setNewTaskDesc] = useState('');
  const [newTaskDueDate, setNewTaskDueDate] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([{ x: window.innerWidth / 2, y: window.innerHeight / 2 }]);

  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(64);

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      const bestSize = Math.max(38, Math.min(horizontalLimit, verticalLimit, 64));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    for (let i = 0; i < BOARD_W; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    if (count <= 0) return [];
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const gInd = getRandomUnique(GHOST_COUNT, startExclude);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...gInd, ...rInd]);
    setGhostIndices(gInd);
    setRainbowIndices(rInd);
    setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...ghostIndices, ...rainbowIndices, ...clownIndices];
    const [newPos] = getRandomUnique(1, exclude);
    switch(type) {
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  };

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;
    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;
      if (ghostIndices.includes(tempPos)) {
        setIsGrayscale(true);
        setIsClownMode(false);
        relocateItem(ghostIndices, tempPos, 'ghost');
      }
      if (rainbowIndices.includes(tempPos)) {
        setIsGrayscale(false);
        setIsClownMode(false);
        relocateItem(rainbowIndices, tempPos, 'rainbow');
      }
      if (clownIndices.includes(tempPos)) {
        setIsClownMode(true);
        setIsGrayscale(false);
        relocateItem(clownIndices, tempPos, 'clown');
      }
      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, ghostIndices, rainbowIndices, clownIndices]);

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);
    const diceCount = isGrayscale ? 3 : 1;
    const newValues = Array.from({ length: diceCount }, () => Math.floor(Math.random() * 6) + 1);
    const newPositions = Array.from({ length: diceCount }, (_, i) => ({
      x: landing.x + (i - Math.floor(diceCount / 2)) * (isClownMode ? 150 : 80),
      y: landing.y
    }));
    setDicePositions(newPositions);
    setTimeout(() => {
      setIsRolling(false);
      setDiceValues(newValues);
      setIsMoving(true);
      const sum = newValues.reduce((a, b) => a + b, 0);
      processMovement(sum);
    }, 1200);
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const handleAddNewTask = (e: React.FormEvent) => {
    e.preventDefault();
    if(!newTaskTitle.trim()) return;
    const newTask: Task = {
      id: Date.now().toString(),
      title: newTaskTitle,
      description: newTaskDesc,
      dueDate: newTaskDueDate,
      priority: newTaskPriority,
      completed: false
    };
    setTasks([newTask, ...tasks]);
    setNewTaskTitle('');
    setNewTaskDesc('');
    setNewTaskDueDate('');
    setIsAddingTask(false);
  };

  const activeDiceCount = isGrayscale ? 3 : 1;
  const currentDiceScale = isClownMode ? 3 : 1;

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400';
        case 'medium': return 'bg-amber-50 text-amber-600 border-amber-100 dark:bg-amber-900/10 dark:text-amber-400';
        default: return 'bg-sky-50 text-sky-600 border-sky-100 dark:bg-sky-900/10 dark:text-sky-400';
    }
  }

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden 
      ${isExploding ? 'bg-indigo-600/10' : ''} 
      ${isGrayscale ? 'filter grayscale' : ''}
      ${isClownMode ? 'clown-bg animate-color-chaos' : ''}
    `}>
      {isClownMode && isRolling && <div className="absolute inset-0 z-[100] pointer-events-none confetti-effect" />}

      {/* Tile Board Layer */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const isGhost = ghostIndices.includes(s.id);
          const isRainbow = rainbowIndices.includes(s.id);
          const isClown = clownIndices.includes(s.id);
          const isStart = s.id === 0;
          let icon = null;
          if (isGhost) icon = '👻';
          else if (isRainbow) icon = '🌈';
          else if (isClown) icon = '🤡';

          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
              style={{ left: s.x, top: s.y, width: tileSize, height: tileSize, backgroundColor: isClownMode ? 'transparent' : undefined }}
            >
              <span className="text-[10px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {icon && <span className="drop-shadow-sm opacity-25" style={{ fontSize: tileSize * 0.55 }}>{icon}</span>}
              {isStart && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}

        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto`}
          style={{ left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, transform: 'translate(-50%, -60%)', fontSize: tileSize * 1.3 }}
        >
          <div className="flex flex-col items-center">
             <div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (
                   <div key={i} className={`w-2 h-1 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />
                ))}
             </div>
             <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">{isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}</span>
          </div>
        </div>
      </div>

      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-10 scale-90 lg:scale-100 h-[520px]">

          {/* Detailed Task Panel */}
          <div className="glass-panel rounded-2xl p-5 w-[460px] flex flex-col shadow-2xl border border-black/5 dark:border-white/5 bg-white/90 dark:bg-zinc-900/90 transition-all">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span>
                <span className="text-4xl font-normal tabular-nums tracking-tighter text-indigo-600 dark:text-indigo-400">{rollBank}</span>
              </div>
              <button onClick={() => setDarkMode(!darkMode)} className="w-10 h-10 flex items-center justify-center rounded-lg hover:bg-black/5 dark:hover:bg-white/5 transition-all text-xl">
                {darkMode ? '☀️' : '🌙'}
              </button>
            </div>

            <div className="flex-grow overflow-y-auto pr-2 custom-scrollbar space-y-3">
              <div className="flex items-center justify-between mb-4">
                 <h2 className="text-xs font-bold opacity-40 uppercase tracking-widest">{showHistory ? 'Completed' : 'Missions'}</h2>
                 <button onClick={() => setShowHistory(!showHistory)} className="text-[10px] font-bold text-indigo-500 hover:underline">{showHistory ? 'Back' : 'History'}</button>
              </div>

              {!showHistory ? (
                <>
                  {tasks.map(t => (
                    <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-4 bg-white dark:bg-zinc-800/50 rounded-xl border border-black/5 dark:border-white/5 hover:border-indigo-500/50 transition-all cursor-pointer shadow-sm hover:shadow-md">
                      <div className="flex items-start gap-3">
                        <div className="mt-1 w-4 h-4 rounded border border-black/10 dark:border-white/10 group-hover:bg-indigo-500 group-hover:border-indigo-500 transition-all flex items-center justify-center shadow-sm">
                           <span className="text-white text-[10px] opacity-0 group-hover:opacity-100">✓</span>
                        </div>
                        <div className="flex-grow">
                          <div className="flex items-center justify-between">
                             <span className="text-[14px] font-bold opacity-90">{t.title}</span>
                             <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded border ${getPriorityColor(t.priority)}`}>{t.priority}</span>
                          </div>
                          {t.description && <p className="text-[11px] opacity-50 mt-1 line-clamp-2">{t.description}</p>}
                          {t.dueDate && <div className="text-[10px] opacity-40 mt-2 font-medium">🕒 {t.dueDate}</div>}
                        </div>
                      </div>
                    </div>
                  ))}

                  {isAddingTask ? (
                    <form onSubmit={handleAddNewTask} className="p-5 bg-black/5 dark:bg-white/5 rounded-xl space-y-3 border border-indigo-500/20">
                      <input autoFocus value={newTaskTitle} onChange={e => setNewTaskTitle(e.target.value)} className="w-full bg-transparent border-b border-black/10 dark:border-white/10 py-1 text-sm outline-none font-bold" placeholder="Mission Name..." />
                      <textarea value={newTaskDesc} onChange={e => setNewTaskDesc(e.target.value)} className="w-full bg-transparent py-1 text-xs outline-none h-16 resize-none" placeholder="Description..." />
                      <div className="grid grid-cols-2 gap-2">
                        <input value={newTaskDueDate} onChange={e => setNewTaskDueDate(e.target.value)} className="w-full bg-white dark:bg-black/60 text-[10px] rounded px-3 py-2 outline-none border border-black/5" placeholder="Deadline..." />
                        <select value={newTaskPriority} onChange={e => setNewTaskPriority(e.target.value as any)} className="w-full bg-white dark:bg-black/60 text-[10px] rounded px-3 py-2 outline-none border border-black/5">
                           <option value="low">Low</option>
                           <option value="medium">Medium</option>
                           <option value="high">High</option>
                        </select>
                      </div>
                      <div className="flex gap-2 pt-2">
                        <button type="submit" className="flex-1 py-2 bg-indigo-600 text-white text-[11px] font-bold rounded-md hover:bg-indigo-700 shadow-lg shadow-indigo-500/20 transition-all">Add Mission</button>
                        <button type="button" onClick={() => setIsAddingTask(false)} className="px-4 py-2 text-[11px] font-bold opacity-40 hover:opacity-100 transition-all">Cancel</button>
                      </div>
                    </form>
                  ) : (
                    <button onClick={() => setIsAddingTask(true)} className="w-full py-4 border-2 border-dashed border-black/5 dark:border-white/5 rounded-xl text-[11px] font-bold opacity-40 hover:opacity-100 hover:border-indigo-500/50 transition-all">
                      + Add New Mission
                    </button>
                  )}
                </>
              ) : (
                <div className="space-y-2">
                   {history.map(h => (
                    <div key={h.id} className="p-3 bg-black/[0.02] dark:bg-white/[0.02] rounded-lg border border-black/5 opacity-50 flex justify-between items-center">
                      <div>
                         <span className="text-xs font-bold line-through block">{h.title}</span>
                         <span className="text-[10px] opacity-60 block">{h.completedAt}</span>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          <AlchemyJar 
            count={jarCount} 
            max={MAX_JAR} 
            isExploding={isExploding} 
            onExplode={onJarExplode} 
            liquidColor={JAR_COLOR}
          />

          <div className="w-64 flex flex-col items-center justify-center">
            <div className="dice-color-picker flex gap-3 p-3 glass-panel rounded-full border border-black/5 shadow-xl">
               {DICE_COLORS.map(c => (
                 <button key={c} onClick={() => setDiceColor(c)} className={`w-6 h-6 rounded-full border-2 transition-transform ${diceColor === c ? 'scale-125 border-indigo-500' : 'border-white/20 hover:scale-110'}`} style={{ background: c }} />
               ))}
            </div>
          </div>
        </div>
      </div>

      {Array.from({ length: activeDiceCount }).map((_, i) => (
        <Dice3D 
          key={i}
          color={diceColor} 
          value={diceValues[i] || 1} 
          isRolling={isRolling} 
          currentPos={dicePositions[i] || { x: window.innerWidth / 2, y: window.innerHeight / 2 }} 
          onRoll={handleRoll} 
          onDragEnd={(finalPos) => setDicePositions(prev => {
            const next = [...prev];
            next[i] = finalPos;
            return next;
          })} 
          scale={currentDiceScale}
        />
      ))}

      <style>{`
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.08); }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.05); }
        .clown-bg { background-image: radial-gradient(circle, rgba(255,255,255,0.2) 2px, transparent 2.5px); background-size: 20px 20px; }
        .animate-color-chaos { animation: color-chaos 5s infinite linear; }
        @keyframes color-chaos {
          0% { background-color: #ff0000; }
          25% { background-color: #00ff00; }
          50% { background-color: #0000ff; }
          75% { background-color: #ffff00; }
          100% { background-color: #ff00ff; }
        }
        .confetti-effect {
          background-image: radial-gradient(circle, #ff0 10%, transparent 10.5%), radial-gradient(circle, #f00 10%, transparent 10.5%);
          background-size: 10px 10px;
          animation: confetti-fall 2s infinite linear;
          opacity: 0.6;
        }
        @keyframes confetti-fall {
          0% { background-position: 0 0; }
          100% { background-position: 100px 500px; }
        }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.1); border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

// Tile Counts per previous request
const GHOST_COUNT = 3; 
const RAINBOW_COUNT = 3; 
const CLOWN_COUNT = 2; 

// HP Settings
const MAX_PLAYER_HEALTH = 5; 

// Board Dimensions
const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🦌', '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤', '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.3)', 'rgba(199, 210, 254, 0.5)', 'rgba(254, 202, 202, 0.5)', 'rgba(167, 243, 208, 0.5)', 'rgba(253, 230, 138, 0.5)', 
];

const JAR_COLOR = '#6366f1';

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  // Tasks State
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', title: 'Alchemy Recharge', description: 'Reach 100% alchemy volume to extract massive roll energy.', completed: false, priority: 'high', dueDate: 'Soon' },
    { id: '2', title: 'Ghost Hunt', description: 'Find 3 Ghost tiles while navigating the board.', completed: false, priority: 'medium', dueDate: 'Ongoing' },
    { id: '3', title: 'Luck Master', description: 'Roll a perfect 6 to demonstrate your elite status.', completed: false, priority: 'low', dueDate: 'Anytime' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);

  // Task Form
  const [isAddingTask, setIsAddingTask] = useState(false);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskDesc, setNewTaskDesc] = useState('');
  const [newTaskDueDate, setNewTaskDueDate] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([{ x: window.innerWidth / 2, y: window.innerHeight / 2 }]);

  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(64);

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      const bestSize = Math.max(38, Math.min(horizontalLimit, verticalLimit, 64));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    for (let i = 0; i < BOARD_W; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    if (count <= 0) return [];
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const gInd = getRandomUnique(GHOST_COUNT, startExclude);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...gInd, ...rInd]);
    setGhostIndices(gInd);
    setRainbowIndices(rInd);
    setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...ghostIndices, ...rainbowIndices, ...clownIndices];
    const [newPos] = getRandomUnique(1, exclude);
    switch(type) {
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  };

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;
    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;
      if (ghostIndices.includes(tempPos)) {
        setIsGrayscale(true);
        setIsClownMode(false);
        relocateItem(ghostIndices, tempPos, 'ghost');
      }
      if (rainbowIndices.includes(tempPos)) {
        setIsGrayscale(false);
        setIsClownMode(false);
        relocateItem(rainbowIndices, tempPos, 'rainbow');
      }
      if (clownIndices.includes(tempPos)) {
        setIsClownMode(true);
        setIsGrayscale(false);
        relocateItem(clownIndices, tempPos, 'clown');
      }
      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, ghostIndices, rainbowIndices, clownIndices]);

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);
    const diceCount = isGrayscale ? 3 : 1;
    const newValues = Array.from({ length: diceCount }, () => Math.floor(Math.random() * 6) + 1);
    const newPositions = Array.from({ length: diceCount }, (_, i) => ({
      x: landing.x + (i - Math.floor(diceCount / 2)) * (isClownMode ? 150 : 80),
      y: landing.y
    }));
    setDicePositions(newPositions);
    setTimeout(() => {
      setIsRolling(false);
      setDiceValues(newValues);
      setIsMoving(true);
      const sum = newValues.reduce((a, b) => a + b, 0);
      processMovement(sum);
    }, 1200);
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const handleAddNewTask = (e: React.FormEvent) => {
    e.preventDefault();
    if(!newTaskTitle.trim()) return;
    const newTask: Task = {
      id: Date.now().toString(),
      title: newTaskTitle,
      description: newTaskDesc,
      dueDate: newTaskDueDate,
      priority: newTaskPriority,
      completed: false
    };
    setTasks([newTask, ...tasks]);
    setNewTaskTitle('');
    setNewTaskDesc('');
    setNewTaskDueDate('');
    setIsAddingTask(false);
  };

  const activeDiceCount = isGrayscale ? 3 : 1;
  const currentDiceScale = isClownMode ? 3 : 1;

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400';
        case 'medium': return 'bg-amber-50 text-amber-600 border-amber-100 dark:bg-amber-900/10 dark:text-amber-400';
        default: return 'bg-sky-50 text-sky-600 border-sky-100 dark:bg-sky-900/10 dark:text-sky-400';
    }
  }

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden 
      ${isExploding ? 'bg-indigo-600/10' : ''} 
      ${isGrayscale ? 'filter grayscale' : ''}
      ${isClownMode ? 'clown-bg animate-color-chaos' : ''}
    `}>
      {isClownMode && isRolling && <div className="absolute inset-0 z-[100] pointer-events-none confetti-effect" />}

      {/* Tile Board Layer */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const isGhost = ghostIndices.includes(s.id);
          const isRainbow = rainbowIndices.includes(s.id);
          const isClown = clownIndices.includes(s.id);
          const isStart = s.id === 0;
          let icon = null;
          if (isGhost) icon = '👻';
          else if (isRainbow) icon = '🌈';
          else if (isClown) icon = '🤡';

          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
              style={{ left: s.x, top: s.y, width: tileSize, height: tileSize, backgroundColor: isClownMode ? 'transparent' : undefined }}
            >
              <span className="text-[10px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {icon && <span className="drop-shadow-sm opacity-25" style={{ fontSize: tileSize * 0.55 }}>{icon}</span>}
              {isStart && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}

        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto`}
          style={{ left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, transform: 'translate(-50%, -60%)', fontSize: tileSize * 1.3 }}
        >
          <div className="flex flex-col items-center">
             <div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (
                   <div key={i} className={`w-2 h-1 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />
                ))}
             </div>
             <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">{isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}</span>
          </div>
        </div>
      </div>

      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-10 scale-90 lg:scale-100 h-[520px]">

          <div className="glass-panel rounded-2xl p-5 w-[460px] flex flex-col shadow-2xl border border-black/5 dark:border-white/5 bg-white/90 dark:bg-zinc-900/90 transition-all">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span>
                <span className="text-4xl font-normal tabular-nums tracking-tighter text-indigo-600 dark:text-indigo-400">{rollBank}</span>
              </div>
              <button onClick={() => setDarkMode(!darkMode)} className="w-10 h-10 flex items-center justify-center rounded-lg hover:bg-black/5 dark:hover:bg-white/5 transition-all text-xl">
                {darkMode ? '☀️' : '🌙'}
