            <div className="flex-grow overflow-y-auto pr-2 custom-scrollbar space-y-3">
              <div className="flex items-center justify-between mb-4">
                 <h2 className="text-xs font-bold opacity-40 uppercase tracking-widest">{showHistory ? 'Completed' : 'Active'}</h2>
                 <button onClick={() => setShowHistory(!showHistory)} className="text-[10px] font-bold text-indigo-500 hover:underline">{showHistory ? 'Missions' : 'History'}</button>
              </div>

              {!showHistory ? (
                <>
                  {tasks.map(t => (
                    <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-4 bg-white dark:bg-zinc-800/50 rounded-xl border border-black/5 dark:border-white/5 hover:border-indigo-500/50 transition-all cursor-pointer shadow-sm hover:shadow-md">
                      <div className="flex items-start gap-3">
                        <div className="mt-1 w-4 h-4 rounded border border-black/10 dark:border-white/10 group-hover:bg-indigo-500 group-hover:border-indigo-500 transition-all flex items-center justify-center shadow-sm">
                           <span className="text-white text-[10px] opacity-0 group-hover:opacity-100">✓</span>
                        </div>
                        <div className="flex-grow">
                          <div className="flex items-center justify-between">
                             <span className="text-[14px] font-bold opacity-90">{t.title}</span>
                             <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded border ${getPriorityColor(t.priority)}`}>{t.priority}</span>
                          </div>
                          {t.description && <p className="text-[11px] opacity-50 mt-1 line-clamp-2">{t.description}</p>}
                          {t.dueDate && <div className="text-[10px] opacity-40 mt-2 font-medium">🕒 {t.dueDate}</div>}
                        </div>
                      </div>
                    </div>
                  ))}

                  {isAddingTask ? (
                    <form onSubmit={handleAddNewTask} className="p-5 bg-black/5 dark:bg-white/5 rounded-xl space-y-3 border border-indigo-500/20">
                      <input autoFocus value={newTaskTitle} onChange={e => setNewTaskTitle(e.target.value)} className="w-full bg-transparent border-b border-black/10 dark:border-white/10 py-1 text-sm outline-none font-bold" placeholder="Mission Name..." />
                      <textarea value={newTaskDesc} onChange={e => setNewTaskDesc(e.target.value)} className="w-full bg-transparent py-1 text-xs outline-none h-16 resize-none" placeholder="Description..." />
                      <div className="grid grid-cols-2 gap-2">
                        <input value={newTaskDueDate} onChange={e => setNewTaskDueDate(e.target.value)} className="w-full bg-white dark:bg-black/60 text-[10px] rounded px-3 py-2 outline-none border border-black/5" placeholder="Time..." />
                        <select value={newTaskPriority} onChange={e => setNewTaskPriority(e.target.value as any)} className="w-full bg-white dark:bg-black/60 text-[10px] rounded px-3 py-2 outline-none border border-black/5">
                           <option value="low">Low</option>
                           <option value="medium">Medium</option>
                           <option value="high">High</option>
                        </select>
                      </div>
                      <div className="flex gap-2 pt-2">
                        <button type="submit" className="flex-1 py-2 bg-indigo-600 text-white text-[11px] font-bold rounded-md hover:bg-indigo-700 shadow-lg shadow-indigo-500/20 transition-all">Add</button>
                        <button type="button" onClick={() => setIsAddingTask(false)} className="px-4 py-2 text-[11px] font-bold opacity-40 hover:opacity-100 transition-all">Cancel</button>
                      </div>
                    </form>
                  ) : (
                    <button onClick={() => setIsAddingTask(true)} className="w-full py-4 border-2 border-dashed border-black/5 dark:border-white/5 rounded-xl text-[11px] font-bold opacity-40 hover:opacity-100 hover:border-indigo-500/50 transition-all">
                      + Add New Goal
                    </button>
                  )}
                </>
              ) : (
                <div className="space-y-2">
                   {history.map(h => (
                    <div key={h.id} className="p-3 bg-black/[0.02] dark:bg-white/[0.02] rounded-lg border border-black/5 opacity-50 flex justify-between items-center">
                      <div>
                         <span className="text-xs font-bold line-through block">{h.title}</span>
                         <span className="text-[10px] opacity-60 block">{h.completedAt}</span>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          <AlchemyJar 
            count={jarCount} 
            max={MAX_JAR} 
            isExploding={isExploding} 
            onExplode={onJarExplode} 
            liquidColor={JAR_COLOR}
          />

          <div className="w-64 flex flex-col items-center justify-center">
            <div className="dice-color-picker flex gap-3 p-3 glass-panel rounded-full border border-black/5 shadow-xl">
               {DICE_COLORS.map(c => (
                 <button key={c} onClick={() => setDiceColor(c)} className={`w-6 h-6 rounded-full border-2 transition-transform ${diceColor === c ? 'scale-125 border-indigo-500' : 'border-white/20 hover:scale-110'}`} style={{ background: c }} />
               ))}
            </div>
          </div>
        </div>
      </div>

      {Array.from({ length: activeDiceCount }).map((_, i) => (
        <Dice3D 
          key={i}
          color={diceColor} 
          value={diceValues[i] || 1} 
          isRolling={isRolling} 
          currentPos={dicePositions[i] || { x: window.innerWidth / 2, y: window.innerHeight / 2 }} 
          onRoll={handleRoll} 
          onDragEnd={(finalPos) => setDicePositions(prev => {
            const next = [...prev];
            next[i] = finalPos;
            return next;
          })} 
          scale={currentDiceScale}
        />
      ))}

      <style>{`
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.08); }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.05); }
        .clown-bg { background-image: radial-gradient(circle, rgba(255,255,255,0.2) 2px, transparent 2.5px); background-size: 20px 20px; }
        .animate-color-chaos { animation: color-chaos 5s infinite linear; }
        @keyframes color-chaos {
          0% { background-color: #ff0000; }
          25% { background-color: #00ff00; }
          50% { background-color: #0000ff; }
          75% { background-color: #ffff00; }
          100% { background-color: #ff00ff; }
        }
        .confetti-effect {
          background-image: radial-gradient(circle, #ff0 10%, transparent 10.5%), radial-gradient(circle, #f00 10%, transparent 10.5%);
          background-size: 10px 10px;
          animation: confetti-fall 2s infinite linear;
          opacity: 0.6;
        }
        @keyframes confetti-fall {
          0% { background-position: 0 0; }
          100% { background-position: 100px 500px; }
        }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.1); border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

// Tile Counts per request
const ZOMBIE_INDICATOR_COUNT = 10; 
const BOMB_COUNT = 10;           
const PUMPKIN_COUNT = 5; 
const DEMON_COUNT = 5; 
const CLOVER_COUNT = 5; 
const GHOST_COUNT = 3; 
const RAINBOW_COUNT = 3; 
const CLOWN_COUNT = 2; 

// HP Settings
const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

// Board Dimensions for ~72 tiles
const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 
const SPAWN_BEHIND_OFFSET = 5;

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', 
  '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🦌',
  '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', 'FOX', 'WOLF',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤',
  '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.3)', 
  'rgba(199, 210, 254, 0.5)', 
  'rgba(254, 202, 202, 0.5)', 
  'rgba(167, 243, 208, 0.5)', 
  'rgba(253, 230, 138, 0.5)', 
];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([
    { x: window.innerWidth / 2, y: window.innerHeight / 2 }
  ]);

  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(64);

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      const bestSize = Math.max(38, Math.min(horizontalLimit, verticalLimit, 64));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    const gInd = getRandomUnique(GHOST_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd]);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd, ...rInd]);

    setZombieIndicators(zInd);
    setBombIndices(bInd);
    setPumpkinIndices(pInd);
    setDemonIndices(dInd);
    setCloverIndices(cInd);
    setGhostIndices(gInd);
    setRainbowIndices(rInd);
    setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = useCallback((list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...clownIndices, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);

    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  }, [currentPos, bombIndices, zombieIndicators, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, activeZombies, getRandomUnique]);

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) {
      setPumpkinBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    if (demonBoss.isActive) {
      setDemonBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    setActiveZombies(prev => {
      if (prev.length === 0) return prev;
      let nearestIndex = 0;
      let minDistance = Infinity;
      prev.forEach((z, idx) => {
        const dist = Math.min(Math.abs(damagePos - z.pos), TOTAL_TILES - Math.abs(damagePos - z.pos));
        if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
      });
      const newZombies = [...prev];
      const target = { ...newZombies[nearestIndex] };
      target.health -= 1;
      if (target.health <= 0) {
        newZombies.splice(nearestIndex, 1);
      } else { newZombies[nearestIndex] = target; }
      return newZombies;
    });
    setIsShaking(true);
    setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
  }, [pumpkinBoss, demonBoss, activeZombies]);

  const handleGameOver = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setIsGrayscale(false);
    setIsClownMode(false);
    setTimeout(() => setIsShaking(false), 500);
  };

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    if (diceSum === 1) {
       applyBombDamage(tempPos);
    }

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      // Tile interactions on passing - ONLY Clover and Bomb trigger as you walk over them
      if (cloverIndices.includes(tempPos)) {
        setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1));
        relocateItem(cloverIndices, tempPos, 'clover');
      }
      if (bombIndices.includes(tempPos)) {
        applyBombDamage(tempPos);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        // DESTINATION TILES: trigger only when movement ends
        if (ghostIndices.includes(finalPos)) {
          setIsGrayscale(true);
          setIsClownMode(false);
          relocateItem(ghostIndices, finalPos, 'ghost');
        }
        if (rainbowIndices.includes(finalPos)) {
          setIsGrayscale(false);
          setIsClownMode(false);
          relocateItem(rainbowIndices, finalPos, 'rainbow');
        }
        if (clownIndices.includes(finalPos)) {
          setIsClownMode(true);
          setIsGrayscale(false);
          relocateItem(clownIndices, finalPos, 'clown');
        }

        // Final tile interactions
        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombies(prev => [...prev, {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          }]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }
        if (pumpkinIndices.includes(finalPos)) {
          setPumpkinBoss(prev => ({ isActive: true, health: MAX_PUMPKIN_HEALTH }));
          relocateItem(pumpkinIndices, finalPos, 'pumpkin');
        }
        if (demonIndices.includes(finalPos)) {
          setDemonBoss(prev => ({ isActive: true, health: MAX_DEMON_HEALTH }));
          relocateItem(demonIndices, finalPos, 'demon');
        }

        // Enemies update
        setActiveZombies(prev => {
          let gameOver = false;
          const moveSteps = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + moveSteps) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) {
            setPlayerHealth(h => {
              const next = h - 1;
              if (next <= 0) {
                handleGameOver();
                return MAX_PLAYER_HEALTH;
              }
              return next;
            });
            return [];
          }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, pumpkinBoss, demonBoss, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, applyBombDamage, relocateItem]);

  const handleRoll = (landing: { x: number, y: number }, index: number) => {
    if (rollBank <= 0 || isRolling || isMoving) return;

    if (pumpkinBoss.isActive) {
      setIsDeducting(true);
      setJarCount(prev => Math.max(0, prev - 5));
      setTimeout(() => setIsDeducting(false), 800);
    }

    setIsRolling(true);
    setRollBank(r => r - 1);

    const diceCount = isGrayscale ? 3 : 1;
    const newValues = Array.from({ length: diceCount }, () => Math.floor(Math.random() * 6) + 1);
    const newPositions = Array.from({ length: diceCount }, (_, i) => ({
      x: landing.x + (i - Math.floor(diceCount / 2)) * (isClownMode ? 150 : 80),
      y: landing.y
    }));

    setDicePositions(newPositions);

    setTimeout(() => {
      setIsRolling(false);
      setDiceValues(newValues);
      setIsMoving(true);
      const sum = newValues.reduce((a, b) => a + b, 0);
      processMovement(sum);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  const getClownTileColor = (id: number) => {
    if (!isClownMode) return '';
    const colors = ['#ff00ff', '#00ffff', '#ffff00', '#ff0000', '#00ff00', '#ff8800', '#8800ff'];
    return colors[id % colors.length];
  };

  const activeDiceCount = isGrayscale ? 3 : 1;
  const currentDiceScale = isClownMode ? 3 : 1;

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden 
      ${isExploding ? 'bg-indigo-600/10' : ''} 
      ${isGrayscale ? 'filter grayscale' : ''}
      ${isClownMode ? 'clown-bg animate-color-chaos' : ''}
    `}>
      {isClownMode && isRolling && <div className="absolute inset-0 z-[100] pointer-events-none confetti-effect" />}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombie = zombieIndicators.includes(s.id);
          const isPumpkin = pumpkinIndices.includes(s.id);
          const isDemon = demonIndices.includes(s.id);
          const isClover = cloverIndices.includes(s.id);
          const isGhost = ghostIndices.includes(s.id);
          const isRainbow = rainbowIndices.includes(s.id);
          const isClown = clownIndices.includes(s.id);
          const isStart = s.id === 0;
          let icon = null;
          if (isBomb) icon = BOMB_ICON;
          else if (isZombie) icon = ENEMY_ICON;
          else if (isPumpkin) icon = '🎃';
          else if (isDemon) icon = '👹';
          else if (isClover) icon = '🍀';
          else if (isGhost) icon = '👻';
          else if (isRainbow) icon = '🌈';
          else if (isClown) icon = '🤡';
          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
              style={{ 
                left: s.x, top: s.y, width: tileSize, height: tileSize,
                backgroundColor: isClownMode ? getClownTileColor(s.id) : undefined 
              }}
            >
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {icon && (
                <span className="drop-shadow-sm opacity-25" style={{ fontSize: tileSize * 0.55 }}>
                  {icon}
                </span>
              )}
              {bloom && <span className="bloom absolute opacity-25" style={{ fontSize: tileSize * 0.5 }}>{bloom}</span>}
              {isStart && !bloom && !icon && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}
        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[z.pos].x + tileSize/2, 
            top: boardSpaces[z.pos].y + tileSize/2, 
            transform: `translate(-50%, -60%) scale(${demonBoss.isActive ? 2.0 : 1.0})` 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/90 dark:bg-black/80 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-200 dark:bg-gray-800'}`} />
                   ))}
                </div>
                <span className="drop-shadow-2xl animate-pulse" style={{ fontSize: tileSize * 1.2 }}>{ENEMY_ICON}</span>
             </div>
          </div>
        ))}
        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, 
            top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: tileSize * 1.3
          }}
        >
          <div className="flex flex-col items-center">
             <div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (
                   <div key={i} className={`w-2 h-1 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />
                ))}
             </div>
             <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">
               {isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}
             </span>
          </div>
        </div>
        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[bombAnimation.pos]?.x + tileSize/2, 
            top: boardSpaces[bombAnimation.pos]?.y + tileSize/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-7xl drop-shadow-2xl">{darkMode ? '✨' : '💥'}</span>
          </div>
        )}
      </div>
      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-10 scale-90 lg:scale-100 h-[420px]">
          <div className="glass-panel rounded-lg p-5 w-[432px] flex flex-col shadow-sm border border-black/5 dark:border-white/5 bg-white/95 dark:bg-zinc-900/95 transition-all">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span>
                <span className="text-3xl font-normal tabular-nums tracking-tight">{rollBank}</span>
              </div>
              <div className="flex items-center gap-3">
                <div className="flex gap-1.5 p-1 bg-black/5 dark:bg-white/5 rounded">
                  {DICE_COLORS.map(c => (
                    <button key={c} onClick={() => setDiceColor(c)} className={`w-4 h-4 rounded-full border border-black/10 transition-transform ${diceColor === c ? 'scale-125' : 'hover:scale-110'}`} style={{ background: c }} />
                  ))}
                </div>
                <button onClick={() => setDarkMode(!darkMode)} className="w-8 h-8 flex items-center justify-center rounded hover:bg-black/5 transition-all text-lg">{darkMode ? '☀️' : '🌙'}</button>
              </div>
            </div>
            <div className="flex-grow overflow-y-auto pr-1 custom-scrollbar space-y-px">
              {!showHistory ? tasks.map(t => (
                <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-2 hover:bg-black/5 rounded transition-colors flex items-center gap-3 cursor-pointer">
                  <div className="w-3.5 h-3.5 rounded-sm border border-black/20 group-hover:bg-indigo-500/10 group-hover:border-indigo-500 transition-all" />
                  <div className="flex-grow overflow-hidden">
                    <div className="text-[13px] font-medium truncate opacity-90">{t.text}</div>
                    {t.priority && <div className={`inline-block text-[8px] font-black uppercase px-1 rounded-sm mt-0.5 border ${getPriorityColor(t.priority)}`}>{t.priority}</div>}
                  </div>
                </div>
              )) : history.map(h => (
                <div key={h.id} className="p-2 border-l border-indigo-500/10 opacity-40">
                  <span className="text-[12px] line-through block">{h.text}</span>
                  <span className="text-[9px] uppercase tracking-tighter">{h.completedAt}</span>
                </div>
              ))}
            </div>
            <div className="mt-4 pt-4 border-t border-black/5 flex flex-col gap-3">
              <div className="flex gap-1">
                {(['low', 'medium', 'high'] as const).map(p => (
                    <button key={p} onClick={() => setNewTaskPriority(p)} className={`flex-1 py-1 text-[8px] font-bold uppercase rounded border transition-all ${newTaskPriority === p ? 'bg-indigo-600 border-indigo-600 text-white' : 'opacity-50 hover:bg-black/5'}`}>{p}</button>
                ))}
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowHistory(!showHistory)} className="px-3 py-2 text-[10px] font-bold border rounded hover:bg-black/5 transition-colors">{showHistory ? 'Tasks' : 'Log'}</button>
                <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); setNewTask(''); }} className="flex-1">
                    <input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full h-8 bg-black/[0.02] border rounded px-3 text-[12px] outline-none" placeholder="Add mission..." />
                </form>
              </div>
            </div>
          </div>
          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} />
          <div className="w-64 flex flex-col items-center justify-center relative h-[420px] gap-4">
            {pumpkinBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center">
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-orange-500/20 backdrop-blur-md">
                   {[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < pumpkinBoss.health ? 'bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>🎃</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-orange-600/60 mt-1">Pumpkin Boss</span>
              </div>
            )}
            {demonBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center" style={{ animationDelay: '-1.5s' }}>
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-red-500/20 backdrop-blur-md">
                   {[...Array(MAX_DEMON_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < demonBoss.health ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>👹</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-red-600/60 mt-1">Demon Buff</span>
              </div>
            )}
          </div>
          <div className="w-12"></div>
        </div>
      </div>
      {Array.from({ length: activeDiceCount }).map((_, i) => (
        <Dice3D 
          key={i}
          color={diceColor} 
          value={diceValues[i] || 1} 
          isRolling={isRolling} 
          currentPos={dicePositions[i] || { x: window.innerWidth / 2, y: window.innerHeight / 2 }} 
          onRoll={(landing) => handleRoll(landing, i)} 
          onDragEnd={(finalPos) => setDicePositions(prev => {
            const next = [...prev];
            next[i] = finalPos;
            return next;
          })} 
          scale={currentDiceScale}
        />
      ))}
      <style>{`
        @keyframes bounce-slow { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-12px); } }
        .animate-bounce-slow { animation: bounce-slow 3s ease-in-out infinite; }
        @keyframes bomb-drop { 0% { transform: translate(-50%, -300%) scale(2); opacity: 0; } 60% { transform: translate(-50%, -60%) scale(1); opacity: 1; } 100% { transform: translate(-50%, -60%) scale(14); opacity: 0; filter: blur(50px); } }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.06); background: rgba(255,255,255,0.95); border-radius: 4px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.03); background: rgba(18,18,18,0.95); }
        .glass-panel { backdrop-filter: blur(40px); }
        @keyframes color-chaos { 0% { background-color: #ff0000; } 25% { background-color: #00ff00; } 50% { background-color: #0000ff; } 75% { background-color: #ffff00; } 100% { background-color: #ff00ff; } }
        .animate-color-chaos { animation: color-chaos 5s infinite linear; }
        .confetti-effect { background-image: radial-gradient(circle, #ff0 10%, transparent 10.5%), radial-gradient(circle, #f00 10%, transparent 10.5%), radial-gradient(circle, #0f0 10%, transparent 10.5%), radial-gradient(circle, #00f 10%, transparent 10.5%); background-size: 10px 10px, 15px 15px, 20px 20px, 12px 12px; background-position: 0 0, 5px 5px, 10px 10px, 15px 15px; animation: confetti-fall 2s infinite linear; opacity: 0.6; }
        @keyframes confetti-fall { 0% { background-position: 0 0; } 100% { background-position: 100px 500px; } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

// Tile Counts
const ZOMBIE_INDICATOR_COUNT = 10; 
const BOMB_COUNT = 10;           
const PUMPKIN_COUNT = 5; 
const DEMON_COUNT = 5; 
const CLOVER_COUNT = 5; 
const GHOST_COUNT = 3; 
const RAINBOW_COUNT = 3; 
const CLOWN_COUNT = 2; 

// HP Settings
const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

// Board Dimensions for ~72 tiles
const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 
const SPAWN_BEHIND_OFFSET = 5;

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', 
  '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🦌',
  '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', 'FOX', 'WOLF',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤',
  '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.3)', 
  'rgba(199, 210, 254, 0.5)', 
  'rgba(254, 202, 202, 0.5)', 
  'rgba(167, 243, 208, 0.5)', 
  'rgba(253, 230, 138, 0.5)', 
];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);
  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([
    { x: window.innerWidth / 2, y: window.innerHeight / 2 }
  ]);

  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(64);

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      const bestSize = Math.max(38, Math.min(horizontalLimit, verticalLimit, 64));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    const gInd = getRandomUnique(GHOST_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd]);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd, ...rInd]);

    setZombieIndicators(zInd);
    setBombIndices(bInd);
    setPumpkinIndices(pInd);
    setDemonIndices(dInd);
    setCloverIndices(cInd);
    setGhostIndices(gInd);
    setRainbowIndices(rInd);
    setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = useCallback((list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...clownIndices, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);

    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  }, [currentPos, bombIndices, zombieIndicators, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, activeZombies, getRandomUnique]);

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) {
      setPumpkinBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    if (demonBoss.isActive) {
      setDemonBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    setActiveZombies(prev => {
      if (prev.length === 0) return prev;
      let nearestIndex = 0;
      let minDistance = Infinity;
      prev.forEach((z, idx) => {
        const dist = Math.min(Math.abs(damagePos - z.pos), TOTAL_TILES - Math.abs(damagePos - z.pos));
        if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
      });
      const newZombies = [...prev];
      const target = { ...newZombies[nearestIndex] };
      target.health -= 1;
      if (target.health <= 0) {
        newZombies.splice(nearestIndex, 1);
      } else { newZombies[nearestIndex] = target; }
      return newZombies;
    });
    setIsShaking(true);
    setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
  }, [pumpkinBoss, demonBoss, activeZombies]);

  const handleGameOver = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setIsGrayscale(false);
    setIsClownMode(false);
    setTimeout(() => setIsShaking(false), 500);
  };

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    if (diceSum === 1) {
       applyBombDamage(tempPos);
    }

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      // Reset effects when passing through HOME (index 0)
      if (tempPos === 0) {
        setIsGrayscale(false);
        setIsClownMode(false);
      }

      // Tile interactions on passing
      if (cloverIndices.includes(tempPos)) {
        setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1));
        relocateItem(cloverIndices, tempPos, 'clover');
      }
      if (bombIndices.includes(tempPos)) {
        applyBombDamage(tempPos);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        // DESTINATION TILES: trigger only when movement ends
        if (ghostIndices.includes(finalPos)) {
          setIsGrayscale(true);
          setIsClownMode(false);
          relocateItem(ghostIndices, finalPos, 'ghost');
        }
        if (rainbowIndices.includes(finalPos)) {
          setIsGrayscale(false);
          setIsClownMode(false);
          relocateItem(rainbowIndices, finalPos, 'rainbow');
        }
        if (clownIndices.includes(finalPos)) {
          setIsClownMode(true);
          setIsGrayscale(false);
          relocateItem(clownIndices, finalPos, 'clown');
        }

        // Final tile interactions
        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombies(prev => [...prev, {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          }]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }
        if (pumpkinIndices.includes(finalPos)) {
          setPumpkinBoss(prev => ({ isActive: true, health: MAX_PUMPKIN_HEALTH }));
          relocateItem(pumpkinIndices, finalPos, 'pumpkin');
        }
        if (demonIndices.includes(finalPos)) {
          setDemonBoss(prev => ({ isActive: true, health: MAX_DEMON_HEALTH }));
          relocateItem(demonIndices, finalPos, 'demon');
        }

        // Enemies update
        setActiveZombies(prev => {
          let gameOver = false;
          const moveSteps = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + moveSteps) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) {
            setPlayerHealth(h => {
              const next = h - 1;
              if (next <= 0) {
                handleGameOver();
                return MAX_PLAYER_HEALTH;
              }
              return next;
            });
            return [];
          }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, pumpkinBoss, demonBoss, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, applyBombDamage, relocateItem]);

  const handleRoll = (landing: { x: number, y: number }, index: number) => {
    if (rollBank <= 0 || isRolling || isMoving) return;

    if (pumpkinBoss.isActive) {
      setIsDeducting(true);
      setJarCount(prev => Math.max(0, prev - 5));
      setTimeout(() => setIsDeducting(false), 800);
    }

    setIsRolling(true);
    setRollBank(r => r - 1);

    const diceCount = isGrayscale ? 3 : 1;
    const newValues = Array.from({ length: diceCount }, () => Math.floor(Math.random() * 6) + 1);
    const newPositions = Array.from({ length: diceCount }, (_, i) => ({
      x: landing.x + (i - Math.floor(diceCount / 2)) * (isClownMode ? 150 : 80),
      y: landing.y
    }));

    setDicePositions(newPositions);

    setTimeout(() => {
      setIsRolling(false);
      setDiceValues(newValues);
      setIsMoving(true);
      const sum = newValues.reduce((a, b) => a + b, 0);
      processMovement(sum);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  const getClownTileColor = (id: number) => {
    if (!isClownMode) return '';
    const colors = ['#ff00ff', '#00ffff', '#ffff00', '#ff0000', '#00ff00', '#ff8800', '#8800ff'];
    return colors[id % colors.length];
  };

  const activeDiceCount = isGrayscale ? 3 : 1;
  const currentDiceScale = isClownMode ? 3 : 1;

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden 
      ${isExploding ? 'bg-indigo-600/10' : ''} 
      ${isGrayscale ? 'filter grayscale' : ''}
      ${isClownMode ? 'clown-bg animate-color-chaos' : ''}
    `}>
      {isClownMode && isRolling && <div className="absolute inset-0 z-[100] pointer-events-none confetti-effect" />}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombie = zombieIndicators.includes(s.id);
          const isPumpkin = pumpkinIndices.includes(s.id);
          const isDemon = demonIndices.includes(s.id);
          const isClover = cloverIndices.includes(s.id);
          const isGhost = ghostIndices.includes(s.id);
          const isRainbow = rainbowIndices.includes(s.id);
          const isClown = clownIndices.includes(s.id);
          const isStart = s.id === 0;
          let icon = null;
          if (isBomb) icon = BOMB_ICON;
          else if (isZombie) icon = ENEMY_ICON;
          else if (isPumpkin) icon = '🎃';
          else if (isDemon) icon = '👹';
          else if (isClover) icon = '🍀';
          else if (isGhost) icon = '👻';
          else if (isRainbow) icon = '🌈';
          else if (isClown) icon = '🤡';
          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
              style={{ 
                left: s.x, top: s.y, width: tileSize, height: tileSize,
                backgroundColor: isClownMode ? getClownTileColor(s.id) : undefined 
              }}
            >
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {icon && (
                <span className="drop-shadow-sm opacity-25" style={{ fontSize: tileSize * 0.55 }}>
                  {icon}
                </span>
              )}
              {bloom && <span className="bloom absolute opacity-25" style={{ fontSize: tileSize * 0.5 }}>{bloom}</span>}
              {isStart && !bloom && !icon && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}
        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[z.pos].x + tileSize/2, 
            top: boardSpaces[z.pos].y + tileSize/2, 
            transform: `translate(-50%, -60%) scale(${demonBoss.isActive ? 2.0 : 1.0})` 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/90 dark:bg-black/80 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-200 dark:bg-gray-800'}`} />
                   ))}
                </div>
                <span className="drop-shadow-2xl animate-pulse" style={{ fontSize: tileSize * 1.2 }}>{ENEMY_ICON}</span>
             </div>
          </div>
        ))}
        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, 
            top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: tileSize * 1.3
          }}
        >
          <div className="flex flex-col items-center">
             <div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (
                   <div key={i} className={`w-2 h-1 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />
                ))}
             </div>
             <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">
               {isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}
             </span>
          </div>
        </div>
        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[bombAnimation.pos]?.x + tileSize/2, 
            top: boardSpaces[bombAnimation.pos]?.y + tileSize/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-7xl drop-shadow-2xl">{darkMode ? '✨' : '💥'}</span>
          </div>
        )}
      </div>
      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-10 scale-90 lg:scale-100 h-[420px]">
          <div className="glass-panel rounded-lg p-5 w-[432px] flex flex-col shadow-sm border border-black/5 dark:border-white/5 bg-white/95 dark:bg-zinc-900/95 transition-all">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span>
                <span className="text-3xl font-normal tabular-nums tracking-tight">{rollBank}</span>
              </div>
              <div className="flex items-center gap-3">
                <div className="flex gap-1.5 p-1 bg-black/5 dark:bg-white/5 rounded">
                  {DICE_COLORS.map(c => (
                    <button key={c} onClick={() => setDiceColor(c)} className={`w-4 h-4 rounded-full border border-black/10 transition-transform ${diceColor === c ? 'scale-125' : 'hover:scale-110'}`} style={{ background: c }} />
                  ))}
                </div>
                <button onClick={() => setDarkMode(!darkMode)} className="w-8 h-8 flex items-center justify-center rounded hover:bg-black/5 transition-all text-lg">{darkMode ? '☀️' : '🌙'}</button>
              </div>
            </div>
            <div className="flex-grow overflow-y-auto pr-1 custom-scrollbar space-y-px">
              {!showHistory ? tasks.map(t => (
                <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-2 hover:bg-black/5 rounded transition-colors flex items-center gap-3 cursor-pointer">
                  <div className="w-3.5 h-3.5 rounded-sm border border-black/20 group-hover:bg-indigo-500/10 group-hover:border-indigo-500 transition-all" />
                  <div className="flex-grow overflow-hidden">
                    <div className="text-[13px] font-medium truncate opacity-90">{t.text}</div>
                    {t.priority && <div className={`inline-block text-[8px] font-black uppercase px-1 rounded-sm mt-0.5 border ${getPriorityColor(t.priority)}`}>{t.priority}</div>}
                  </div>
                </div>
              )) : history.map(h => (
                <div key={h.id} className="p-2 border-l border-indigo-500/10 opacity-40">
                  <span className="text-[12px] line-through block">{h.text}</span>
                  <span className="text-[9px] uppercase tracking-tighter">{h.completedAt}</span>
                </div>
              ))}
            </div>
            <div className="mt-4 pt-4 border-t border-black/5 flex flex-col gap-3">
              <div className="flex gap-1">
                {(['low', 'medium', 'high'] as const).map(p => (
                    <button key={p} onClick={() => setNewTaskPriority(p)} className={`flex-1 py-1 text-[8px] font-bold uppercase rounded border transition-all ${newTaskPriority === p ? 'bg-indigo-600 border-indigo-600 text-white' : 'opacity-50 hover:bg-black/5'}`}>{p}</button>
                ))}
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowHistory(!showHistory)} className="px-3 py-2 text-[10px] font-bold border rounded hover:bg-black/5 transition-colors">{showHistory ? 'Tasks' : 'Log'}</button>
                <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); setNewTask(''); }} className="flex-1">
                    <input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full h-8 bg-black/[0.02] border rounded px-3 text-[12px] outline-none" placeholder="Add mission..." />
                </form>
              </div>
            </div>
          </div>
          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} />
          <div className="w-64 flex flex-col items-center justify-center relative h-[420px] gap-4">
            {pumpkinBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center">
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-orange-500/20 backdrop-blur-md">
                   {[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < pumpkinBoss.health ? 'bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>🎃</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-orange-600/60 mt-1">Pumpkin Boss</span>
              </div>
            )}
            {demonBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center" style={{ animationDelay: '-1.5s' }}>
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-red-500/20 backdrop-blur-md">
                   {[...Array(MAX_DEMON_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < demonBoss.health ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>👹</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-red-600/60 mt-1">Demon Buff</span>
              </div>
            )}
          </div>
          <div className="w-12"></div>
        </div>
      </div>
      {Array.from({ length: activeDiceCount }).map((_, i) => (
        <Dice3D 
          key={i}
          color={diceColor} 
          value={diceValues[i] || 1} 
          isRolling={isRolling} 
          currentPos={dicePositions[i] || { x: window.innerWidth / 2, y: window.innerHeight / 2 }} 
          onRoll={(landing) => handleRoll(landing, i)} 
          onDragEnd={(finalPos) => setDicePositions(prev => {
            const next = [...prev];
            next[i] = finalPos;
            return next;
          })} 
          scale={currentDiceScale}
        />
      ))}
      <style>{`
        @keyframes bounce-slow { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-12px); } }
        .animate-bounce-slow { animation: bounce-slow 3s ease-in-out infinite; }
        @keyframes bomb-drop { 0% { transform: translate(-50%, -300%) scale(2); opacity: 0; } 60% { transform: translate(-50%, -60%) scale(1); opacity: 1; } 100% { transform: translate(-50%, -60%) scale(14); opacity: 0; filter: blur(50px); } }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.06); background: rgba(255,255,255,0.95); border-radius: 4px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.03); background: rgba(18,18,18,0.95); }
        .glass-panel { backdrop-filter: blur(40px); }
        @keyframes color-chaos { 0% { background-color: #ff0000; } 25% { background-color: #00ff00; } 50% { background-color: #0000ff; } 75% { background-color: #ffff00; } 100% { background-color: #ff00ff; } }
        .animate-color-chaos { animation: color-chaos 5s infinite linear; }
        .confetti-effect { background-image: radial-gradient(circle, #ff0 10%, transparent 10.5%), radial-gradient(circle, #f00 10%, transparent 10.5%), radial-gradient(circle, #0f0 10%, transparent 10.5%), radial-gradient(circle, #00f 10%, transparent 10.5%); background-size: 10px 10px, 15px 15px, 20px 20px, 12px 12px; background-position: 0 0, 5px 5px, 10px 10px, 15px 15px; animation: confetti-fall 2s infinite linear; opacity: 0.6; }
        @keyframes confetti-fall { 0% { background-position: 0 0; } 100% { background-position: 100px 500px; } }
      `}</style>
    </div>
  );
};

export default App;

export interface Task {
  id: string;
  text: string;
  completed: boolean;
  priority?: 'low' | 'medium' | 'high';
}

export interface BoardSpace {
  id: number;
  x: number;
  y: number;
  type: 'normal' | 'special';
}

export interface BigZombie {
  id: string;
  pos: number;
  health: number;
  isActive: boolean;
}

export interface PumpkinBoss {
  isActive: boolean;
  health: number;
}

export interface DemonBoss {
  isActive: boolean;
  health: number;
}

export interface Gift {
  id: string;
  type: 1 | 2 | 3;
  pos: number; // Start tile index
  size: number; // Number of tiles it occupies
  expiry: number; // Timestamp in ms
  rewards: { gems: number; coins: number };
}

export interface Resources {
  gems: number;
  coins: number;
}

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss, Gift, Resources } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 
const ROLLS_FOR_GIFT = 7;

// Tile Counts
const ZOMBIE_INDICATOR_COUNT = 10; 
const BOMB_COUNT = 10;           
const PUMPKIN_COUNT = 5; 
const DEMON_COUNT = 5; 
const CLOVER_COUNT = 5; 
const GHOST_COUNT = 3; 
const RAINBOW_COUNT = 3; 
const CLOWN_COUNT = 2; 

// HP Settings
const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

// Board Dimensions
const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 
const SPAWN_BEHIND_OFFSET = 5;

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🦌', '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤', '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.3)', 'rgba(199, 210, 254, 0.5)', 'rgba(254, 202, 202, 0.5)', 'rgba(167, 243, 208, 0.5)', 'rgba(253, 230, 138, 0.5)', 
];

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  const [resources, setResources] = useState<Resources>({ gems: 0, coins: 0 });
  const [rollCounter, setRollCounter] = useState(0);
  const [activeGifts, setActiveGifts] = useState<Gift[]>([]);
  const [popup, setPopup] = useState<{ text: string; sub: string } | null>(null);

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<(Task & { completedAt: string })[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([{ x: window.innerWidth / 2, y: window.innerHeight / 2 }]);

  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  const [now, setNow] = useState(Date.now());

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  useEffect(() => {
    const timer = setInterval(() => {
      setNow(Date.now());
      setActiveGifts(prev => prev.filter(g => g.expiry > Date.now()));
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const [tileSize, setTileSize] = useState(64);

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      setTileSize(Math.max(38, Math.min(horizontalLimit, verticalLimit, 64)));
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;
    for (let i = 0; i < BOARD_W; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });
    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    const gInd = getRandomUnique(GHOST_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd]);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd, ...rInd]);
    setZombieIndicators(zInd); setBombIndices(bInd); setPumpkinIndices(pInd); setDemonIndices(dInd); setCloverIndices(cInd); setGhostIndices(gInd); setRainbowIndices(rInd); setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    setBlooms(prev => ({ ...prev, [pos]: FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)] }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => { const n = { ...prev }; delete n[pos]; return n; }), 800);
  };

  const spawnGifts = useCallback(() => {
    const t = Date.now();
    const g1: Gift = { id: 'g1', type: 1, pos: (currentPos + 20) % TOTAL_TILES, size: 1, expiry: t + 2 * 3600 * 1000, rewards: { gems: 1, coins: 10 } };
    const g2: Gift = { id: 'g2', type: 2, pos: (currentPos + 30) % TOTAL_TILES, size: 2, expiry: t + 3 * 3600 * 1000, rewards: { gems: 3, coins: 20 } };
    const g3: Gift = { id: 'g3', type: 3, pos: (currentPos + 50) % TOTAL_TILES, size: 3, expiry: t + 24 * 3600 * 1000, rewards: { gems: 5, coins: 30 } };
    setActiveGifts([g1, g2, g3]);
  }, [currentPos]);

  const collectGift = (gift: Gift) => {
    setActiveGifts(prev => prev.filter(g => g.id !== gift.id));
    setResources(r => ({ gems: r.gems + gift.rewards.gems, coins: r.coins + gift.rewards.coins }));
    setPopup({ text: `Hộp quà ${gift.type} !`, sub: `Nhận ${gift.rewards.gems}💎 & ${gift.rewards.coins}🪙` });
    setTimeout(() => setPopup(null), 2500);
  };

  const relocateItem = useCallback((list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...clownIndices];
    const [newPos] = getRandomUnique(1, exclude);
    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  }, [currentPos, bombIndices, zombieIndicators, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, getRandomUnique]);

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) setPumpkinBoss(p => ({ ...p, health: Math.max(0, p.health - 1), isActive: p.health > 1 }));
    if (demonBoss.isActive) setDemonBoss(d => ({ ...d, health: Math.max(0, d.health - 1), isActive: d.health > 1 }));
    setActiveZombies(prev => {
      if (prev.length === 0) return prev;
      let minIdx = -1, minD = Infinity;
      prev.forEach((z, i) => { const d = Math.min(Math.abs(damagePos - z.pos), TOTAL_TILES - Math.abs(damagePos - z.pos)); if(d < minD){ minD = d; minIdx = i; }});
      if(minIdx === -1) return prev;
      const next = [...prev]; next[minIdx] = { ...next[minIdx], health: next[minIdx].health - 1 };
      return next.filter(z => z.health > 0);
    });
    setIsShaking(true); setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
  }, [pumpkinBoss, demonBoss, activeZombies]);

  const handleGameOver = () => {
    setIsShaking(true); setJarCount(0); setCurrentPos(0); setActiveZombies([]); setPumpkinBoss({ isActive: false, health: 0 }); setDemonBoss({ isActive: false, health: 0 }); setIsGrayscale(false); setIsClownMode(false);
    setTimeout(() => setIsShaking(false), 500);
  };

  const processMovement = useCallback((diceSum: number) => {
    let steps = 0, temp = currentPos;
    if (diceSum === 1) applyBombDamage(temp);
    const interval = setInterval(() => {
      temp = (temp + 1) % TOTAL_TILES;
      setCurrentPos(temp); triggerBloom(temp); steps++;

      // Check for Gifts collection (passing through)
      activeGifts.forEach(g => {
        for(let i=0; i<g.size; i++) {
          if((g.pos + i) % TOTAL_TILES === temp) { collectGift(g); break; }
        }
      });

      if (temp === 0) { setIsGrayscale(false); setIsClownMode(false); }
      if (cloverIndices.includes(temp)) { setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1)); relocateItem(cloverIndices, temp, 'clover'); }
      if (bombIndices.includes(temp)) { applyBombDamage(temp); relocateItem(bombIndices, temp, 'bomb'); }

      if (steps >= diceSum) {
        clearInterval(interval); setIsMoving(false);
        if (ghostIndices.includes(temp)) { setIsGrayscale(true); setIsClownMode(false); relocateItem(ghostIndices, temp, 'ghost'); }
        if (rainbowIndices.includes(temp)) { setIsGrayscale(false); setIsClownMode(false); relocateItem(rainbowIndices, temp, 'rainbow'); }
        if (clownIndices.includes(temp)) { setIsClownMode(true); setIsGrayscale(false); relocateItem(clownIndices, temp, 'clown'); }
        if (zombieIndicators.includes(temp)) {
          setActiveZombies(p => [...p, { id: Math.random().toString(36).substr(2, 9), pos: (temp - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES, health: MAX_ZOMBIE_HEALTH, isActive: true }]);
          relocateItem(zombieIndicators, temp, 'zombie');
        }
        if (pumpkinIndices.includes(temp)) { setPumpkinBoss({ isActive: true, health: MAX_PUMPKIN_HEALTH }); relocateItem(pumpkinIndices, temp, 'pumpkin'); }
        if (demonIndices.includes(temp)) { setDemonBoss({ isActive: true, health: MAX_DEMON_HEALTH }); relocateItem(demonIndices, temp, 'demon'); }
        setActiveZombies(prev => {
          let hit = false; const move = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => { const n = (z.pos + move) % TOTAL_TILES; if (n === temp) hit = true; return { ...z, pos: n }; });
          if (hit) { setPlayerHealth(h => { const n = h - 1; if (n <= 0) { handleGameOver(); return MAX_PLAYER_HEALTH; } return n; }); return []; }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, activeGifts, cloverIndices, bombIndices, ghostIndices, rainbowIndices, clownIndices, zombieIndicators, pumpkinIndices, demonIndices, demonBoss.isActive, applyBombDamage, relocateItem]);

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    if (pumpkinBoss.isActive) { setIsDeducting(true); setJarCount(p => Math.max(0, p - 5)); setTimeout(() => setIsDeducting(false), 800); }

    // Counter rolls only if no gifts on screen
    if (activeGifts.length === 0) {
      setRollCounter(prev => {
        const next = prev + 1;
        if (next >= ROLLS_FOR_GIFT) { spawnGifts(); return 0; }
        return next;
      });
    }

    setIsRolling(true); setRollBank(r => r - 1);
    const count = isGrayscale ? 3 : 1;
    const vals = Array.from({ length: count }, () => Math.floor(Math.random() * 6) + 1);
    setDicePositions(Array.from({ length: count }, (_, i) => ({ x: landing.x + (i - Math.floor(count/2)) * (isClownMode ? 150 : 80), y: landing.y })));
    setTimeout(() => { setIsRolling(false); setDiceValues(vals); setIsMoving(true); processMovement(vals.reduce((a, b) => a + b, 0)); }, 1200);
  };

  const formatTime = (ms: number) => {
    const s = Math.max(0, Math.floor(ms / 1000));
    const h = Math.floor(s / 3600), m = Math.floor((s % 3600) / 60), sc = s % 60;
    return `${h}h ${m}m ${sc}s`;
  };

  return (
    <div className={`h-screen w-screen relative transition-all duration-700 overflow-hidden notion-grid ${isExploding ? 'bg-indigo-600/10' : ''} ${isGrayscale ? 'filter grayscale' : ''} ${isClownMode ? 'clown-bg animate-color-chaos' : ''}`}>
      {isClownMode && isRolling && <div className="absolute inset-0 z-[100] pointer-events-none confetti-effect" />}

      {/* Gift Layer */}
      <div className="absolute inset-0 z-10 pointer-events-none">
        {activeGifts.map(g => {
          const space = boardSpaces[g.pos];
          if (!space) return null;
          const remaining = g.expiry - now;
          const totalDuration = g.type === 1 ? 2 * 3600 * 1000 : (g.type === 2 ? 3 * 3600 * 1000 : 24 * 3600 * 1000);
          const ratio = Math.max(0, remaining / totalDuration);
          return (
            <div key={g.id} className="absolute z-40 flex flex-col items-center justify-end" style={{ left: space.x + (tileSize * g.size) / 2, top: space.y + tileSize / 2, transform: 'translate(-50%, -50%)', height: tileSize * 3 }}>
              <div className="bg-white/90 dark:bg-black/80 px-2 py-0.5 rounded-full border border-black/10 shadow-sm mb-1">
                <div className="text-[7px] font-black uppercase text-center opacity-40 leading-none mb-0.5">{formatTime(remaining)}</div>
                <div className="w-10 h-0.5 bg-gray-200 rounded-full overflow-hidden">
                  <div className="h-full bg-indigo-500" style={{ width: `${ratio * 100}%` }} />
                </div>
              </div>
              <span className="drop-shadow-lg leading-none transition-transform" style={{ fontSize: tileSize * g.type, transform: `scale(${1 + Math.sin(now / 300) * 0.05})` }}>🎁</span>
            </div>
          );
        })}
      </div>

      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const isB = bombIndices.includes(s.id), isZ = zombieIndicators.includes(s.id), isP = pumpkinIndices.includes(s.id), isD = demonIndices.includes(s.id), isC = cloverIndices.includes(s.id), isG = ghostIndices.includes(s.id), isR = rainbowIndices.includes(s.id), isCl = clownIndices.includes(s.id), isSt = s.id === 0;
          let icon = null; if (isB) icon = darkMode ? '🧄' : '💣'; else if (isZ) icon = darkMode ? '🧛🏻' : '🧟'; else if (isP) icon = '🎃'; else if (isD) icon = '👹'; else if (isC) icon = '🍀'; else if (isG) icon = '👻'; else if (isR) icon = '🌈'; else if (isCl) icon = '🤡';
          return (
            <div key={s.id} className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isSt ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`} style={{ left: s.x, top: s.y, width: tileSize, height: tileSize, backgroundColor: isClownMode ? '' : undefined }}>
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {icon && <span className="drop-shadow-sm opacity-25" style={{ fontSize: tileSize * 0.55 }}>{icon}</span>}
              {blooms[s.id] && <span className="bloom absolute opacity-25" style={{ fontSize: tileSize * 0.5 }}>{blooms[s.id]}</span>}
              {isSt && !blooms[s.id] && !icon && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}
        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ left: boardSpaces[z.pos].x + tileSize/2, top: boardSpaces[z.pos].y + tileSize/2, transform: `translate(-50%, -60%) scale(${demonBoss.isActive ? 2 : 1})` }}>
            <div className="flex flex-col items-center"><div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-2 shadow-sm">{[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (<div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-200'}`} />))}</div><span className="drop-shadow-2xl animate-pulse" style={{ fontSize: tileSize * 1.2 }}>{darkMode ? '🧛🏻' : '🧟'}</span></div>
          </div>
        ))}
        <div onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)} className="absolute z-30 transition-all duration-300 cursor-pointer pointer-events-auto" style={{ left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, transform: 'translate(-50%, -60%)', fontSize: tileSize * 1.3 }}>
          <div className="flex flex-col items-center"><div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-2 shadow-sm">{[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (<div key={i} className={`w-2 h-1 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />))}</div><span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">{isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}</span></div>
        </div>
      </div>

      <div className="absolute inset-0 z-50 pointer-events-none flex flex-col items-center p-10">
        {/* Resource Bar Top */}
        <div className="pointer-events-auto glass-panel px-6 py-3 rounded-2xl flex items-center gap-8 shadow-2xl border border-black/5 animate-in slide-in-from-top-10">
          <div className="flex items-center gap-3">
            <span className="text-xl">💎</span>
            <span className="text-2xl font-black tabular-nums">{resources.gems}</span>
          </div>
          <div className="w-px h-6 bg-black/5 dark:bg-white/5" />
          <div className="flex items-center gap-3">
            <span className="text-xl">🪙</span>
            <span className="text-2xl font-black tabular-nums">{resources.coins}</span>
          </div>
          <div className="w-px h-6 bg-black/5 dark:bg-white/5" />
          <div className="flex flex-col items-center">
            <span className="text-[8px] font-black uppercase opacity-40 tracking-widest mb-1">Gift Progress</span>
            <div className="flex gap-1">
              {[...Array(ROLLS_FOR_GIFT)].map((_, i) => (
                <div key={i} className={`w-3 h-1.5 rounded-full transition-all ${i < rollCounter ? 'bg-indigo-500 shadow-[0_0_8px_rgba(99,102,241,0.5)]' : 'bg-black/10 dark:bg-white/10'}`} />
              ))}
            </div>
          </div>
        </div>

        <div className="flex-grow flex items-center justify-center gap-10">
          <div className="pointer-events-auto flex items-stretch gap-10 scale-90 lg:scale-100 h-[420px]">
            <div className="glass-panel rounded-lg p-5 w-[432px] flex flex-col shadow-sm border border-black/5 bg-white/95 dark:bg-zinc-900/95 transition-all">
              <div className="flex justify-between items-start mb-6">
                <div><span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span><span className="text-3xl font-normal tabular-nums">{rollBank}</span></div>
                <div className="flex gap-2">
                  <div className="flex gap-1.5 p-1 bg-black/5 rounded">{DICE_COLORS.map(c => (<button key={c} onClick={() => setDiceColor(c)} className={`w-4 h-4 rounded-full border border-black/10 transition-transform ${diceColor === c ? 'scale-125' : 'hover:scale-110'}`} style={{ background: c }} />))}</div>
                  <button onClick={() => setDarkMode(!darkMode)} className="w-8 h-8 flex items-center justify-center rounded hover:bg-black/5 transition-all text-lg">{darkMode ? '☀️' : '🌙'}</button>
                </div>
              </div>
              <div className="flex-grow overflow-y-auto pr-1 custom-scrollbar space-y-px">
                {!showHistory ? tasks.map(t => (<div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-2 hover:bg-black/5 rounded transition-colors flex items-center gap-3 cursor-pointer"><div className="w-3.5 h-3.5 rounded-sm border border-black/20 group-hover:bg-indigo-500/10 group-hover:border-indigo-500 transition-all" /><div className="flex-grow overflow-hidden"><div className="text-[13px] font-medium truncate opacity-90">{t.text}</div>{t.priority && <div className={`inline-block text-[8px] font-black uppercase px-1 rounded-sm mt-0.5 border ${getPriorityColor(t.priority)}`}>{t.priority}</div>}</div></div>)) : history.map(h => (<div key={h.id} className="p-2 border-l border-indigo-500/10 opacity-40"><span className="text-[12px] line-through block">{h.text}</span><span className="text-[9px] uppercase tracking-tighter">{h.completedAt}</span></div>))}
              </div>
              <div className="mt-4 pt-4 border-t border-black/5 flex gap-2"><button onClick={() => setShowHistory(!showHistory)} className="px-3 py-2 text-[10px] font-bold border rounded hover:bg-black/5">{showHistory ? 'Tasks' : 'Log'}</button><form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); setNewTask(''); }} className="flex-1"><input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full h-8 bg-black/[0.02] border rounded px-3 text-[12px] outline-none" placeholder="Add mission..." /></form></div>
            </div>
            <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} />
            <div className="w-64 flex flex-col items-center justify-center relative h-[420px] gap-4">
              {pumpkinBoss.isActive && (<div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center"><div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-orange-500/20 backdrop-blur-md">{[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (<div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < pumpkinBoss.health ? 'bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.4)]' : 'bg-gray-200 opacity-20'}`} />))}</div><span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>🎃</span><span className="text-[8px] font-black uppercase tracking-[0.2em] text-orange-600/60 mt-1">Pumpkin Boss</span></div>)}
              {demonBoss.isActive && (<div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center" style={{ animationDelay: '-1.5s' }}><div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-red-500/20 backdrop-blur-md">{[...Array(MAX_DEMON_HEALTH)].map((_, i) => (<div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < demonBoss.health ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.4)]' : 'bg-gray-200 opacity-20'}`} />))}</div><span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>👹</span><span className="text-[8px] font-black uppercase tracking-[0.2em] text-red-600/60 mt-1">Demon Buff</span></div>)}
            </div>
          </div>
        </div>
      </div>

      {popup && (
        <div className="fixed top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-[200] glass-panel p-8 rounded-3xl text-center shadow-[0_40px_100px_rgba(0,0,0,0.3)] animate-in zoom-in-50 duration-300">
           <div className="text-6xl mb-4">🎁</div>
           <div className="text-2xl font-black mb-2">{popup.text}</div>
           <div className="text-indigo-600 font-bold">{popup.sub}</div>
        </div>
      )}

      {Array.from({ length: activeDiceCount }).map((_, i) => (
        <Dice3D key={i} color={diceColor} value={diceValues[i] || 1} isRolling={isRolling} currentPos={dicePositions[i] || { x: window.innerWidth / 2, y: window.innerHeight / 2 }} onRoll={handleRoll} onDragEnd={(f) => setDicePositions(p => { const n = [...p]; n[i] = f; return n; })} scale={currentDiceScale} />
      ))}
      <style>{`
        @keyframes bounce-slow { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-12px); } }
        .animate-bounce-slow { animation: bounce-slow 3s ease-in-out infinite; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.06); background: rgba(255,255,255,0.95); border-radius: 4px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.03); background: rgba(18,18,18,0.95); }
        .glass-panel { backdrop-filter: blur(40px); }
        @keyframes color-chaos { 0% { background-color: #ff0000; } 25% { background-color: #00ff00; } 50% { background-color: #0000ff; } 75% { background-color: #ffff00; } 100% { background-color: #ff00ff; } }
        .animate-color-chaos { animation: color-chaos 5s infinite linear; }
        .confetti-effect { background-image: radial-gradient(circle, #ff0 10%, transparent 10.5%), radial-gradient(circle, #f00 10%, transparent 10.5%); background-size: 10px 10px; animation: confetti-fall 2s infinite linear; opacity: 0.6; }
        @keyframes confetti-fall { 0% { background-position: 0 0; } 100% { background-position: 100px 500px; } }
      `}</style>
    </div>
  );
};

const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10';
        default: return 'bg-blue-50 text-blue-600 border-blue-100';
    }
}

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss, Gift, Resources } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 
const ROLLS_FOR_GIFT = 7;

// Tile Counts
const ZOMBIE_INDICATOR_COUNT = 10; 
const BOMB_COUNT = 10;           
const PUMPKIN_COUNT = 5; 
const DEMON_COUNT = 5; 
const CLOVER_COUNT = 5; 
const GHOST_COUNT = 3; 
const RAINBOW_COUNT = 3; 
const CLOWN_COUNT = 2; 

// HP Settings
const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

// Board Dimensions for ~72 tiles
const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 
const SPAWN_BEHIND_OFFSET = 5;

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', 
  '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🦌',
  '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', 'FOX', 'WOLF',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤',
  '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.3)', 
  'rgba(199, 210, 254, 0.5)', 
  'rgba(254, 202, 202, 0.5)', 
  'rgba(167, 243, 208, 0.5)', 
  'rgba(253, 230, 138, 0.5)', 
];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  // Gift Mechanic State
  const [rollCounter, setRollCounter] = useState(0);
  const [activeGifts, setActiveGifts] = useState<Gift[]>([]);
  const [resources, setResources] = useState<Resources>({ gems: 0, coins: 0 });
  const [giftPopup, setGiftPopup] = useState<{ type: number; rewards: { gems: number; coins: number } } | null>(null);
  const [currentTime, setCurrentTime] = useState(Date.now());

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([
    { x: window.innerWidth / 2, y: window.innerHeight / 2 }
  ]);

  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  // Global timer for gift expiry
  useEffect(() => {
    const timer = setInterval(() => {
      const now = Date.now();
      setCurrentTime(now);
      setActiveGifts(prev => prev.filter(g => g.expiry > now));
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const [tileSize, setTileSize] = useState(64);

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      const bestSize = Math.max(38, Math.min(horizontalLimit, verticalLimit, 64));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    const gInd = getRandomUnique(GHOST_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd]);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd, ...rInd]);

    setZombieIndicators(zInd);
    setBombIndices(bInd);
    setPumpkinIndices(pInd);
    setDemonIndices(dInd);
    setCloverIndices(cInd);
    setGhostIndices(gInd);
    setRainbowIndices(rInd);
    setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const spawnGifts = useCallback(() => {
    const now = Date.now();
    const gifts: Gift[] = [
      {
        id: 'gift-1',
        type: 1,
        pos: (currentPos + 20) % TOTAL_TILES,
        size: 1,
        expiry: now + (2 * 60 * 60 * 1000), // 2 hours
        rewards: { gems: 1, coins: 10 }
      },
      {
        id: 'gift-2',
        type: 2,
        pos: (currentPos + 30) % TOTAL_TILES,
        size: 2,
        expiry: now + (3 * 60 * 60 * 1000), // 3 hours
        rewards: { gems: 3, coins: 20 }
      },
      {
        id: 'gift-3',
        type: 3,
        pos: (currentPos + 50) % TOTAL_TILES,
        size: 3,
        expiry: now + (24 * 60 * 60 * 1000), // 24 hours
        rewards: { gems: 5, coins: 30 }
      }
    ];
    setActiveGifts(gifts);
  }, [currentPos]);

  const collectGift = useCallback((gift: Gift) => {
    setActiveGifts(prev => prev.filter(g => g.id !== gift.id));
    setResources(prev => ({
      gems: prev.gems + gift.rewards.gems,
      coins: prev.coins + gift.rewards.coins
    }));
    setGiftPopup({ type: gift.type, rewards: gift.rewards });
    setTimeout(() => setGiftPopup(null), 3000);
  }, []);

  const relocateItem = useCallback((list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...clownIndices, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);

    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  }, [currentPos, bombIndices, zombieIndicators, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, activeZombies, getRandomUnique]);

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) {
      setPumpkinBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    if (demonBoss.isActive) {
      setDemonBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    setActiveZombies(prev => {
      if (prev.length === 0) return prev;
      let nearestIndex = 0;
      let minDistance = Infinity;
      prev.forEach((z, idx) => {
        const dist = Math.min(Math.abs(damagePos - z.pos), TOTAL_TILES - Math.abs(damagePos - z.pos));
        if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
      });
      const newZombies = [...prev];
      const target = { ...newZombies[nearestIndex] };
      target.health -= 1;
      if (target.health <= 0) {
        newZombies.splice(nearestIndex, 1);
      } else { newZombies[nearestIndex] = target; }
      return newZombies;
    });
    setIsShaking(true);
    setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
  }, [pumpkinBoss, demonBoss, activeZombies]);

  const handleGameOver = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setIsGrayscale(false);
    setIsClownMode(false);
    setTimeout(() => setIsShaking(false), 500);
  };

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    if (diceSum === 1) {
       applyBombDamage(tempPos);
    }

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      // Gift collection check (passing through)
      activeGifts.forEach(g => {
        // Gift occupies range [pos, pos + size - 1]
        for (let i = 0; i < g.size; i++) {
          if ((g.pos + i) % TOTAL_TILES === tempPos) {
            collectGift(g);
          }
        }
      });

      // Reset effects when passing through HOME (index 0)
      if (tempPos === 0) {
        setIsGrayscale(false);
        setIsClownMode(false);
      }

      // Tile interactions on passing
      if (cloverIndices.includes(tempPos)) {
        setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1));
        relocateItem(cloverIndices, tempPos, 'clover');
      }
      if (bombIndices.includes(tempPos)) {
        applyBombDamage(tempPos);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        // DESTINATION TILES: trigger only when movement ends
        if (ghostIndices.includes(finalPos)) {
          setIsGrayscale(true);
          setIsClownMode(false);
          relocateItem(ghostIndices, finalPos, 'ghost');
        }
        if (rainbowIndices.includes(finalPos)) {
          setIsGrayscale(false);
          setIsClownMode(false);
          relocateItem(rainbowIndices, finalPos, 'rainbow');
        }
        if (clownIndices.includes(finalPos)) {
          setIsClownMode(true);
          setIsGrayscale(false);
          relocateItem(clownIndices, finalPos, 'clown');
        }

        // Final tile interactions
        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombies(prev => [...prev, {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          }]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }
        if (pumpkinIndices.includes(finalPos)) {
          setPumpkinBoss(prev => ({ isActive: true, health: MAX_PUMPKIN_HEALTH }));
          relocateItem(pumpkinIndices, finalPos, 'pumpkin');
        }
        if (demonIndices.includes(finalPos)) {
          setDemonBoss(prev => ({ isActive: true, health: MAX_DEMON_HEALTH }));
          relocateItem(demonIndices, finalPos, 'demon');
        }

        // Enemies update
        setActiveZombies(prev => {
          let gameOver = false;
          const moveSteps = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + moveSteps) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) {
            setPlayerHealth(h => {
              const next = h - 1;
              if (next <= 0) {
                handleGameOver();
                return MAX_PLAYER_HEALTH;
              }
              return next;
            });
            return [];
          }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, activeGifts, bombIndices, activeZombies, pumpkinBoss, demonBoss, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, applyBombDamage, relocateItem, collectGift]);

  const handleRoll = (landing: { x: number, y: number }, index: number) => {
    if (rollBank <= 0 || isRolling || isMoving) return;

    if (pumpkinBoss.isActive) {
      setIsDeducting(true);
      setJarCount(prev => Math.max(0, prev - 5));
      setTimeout(() => setIsDeducting(false), 800);
    }

    // Gift Counter logic: only count if NO gifts are on screen
    if (activeGifts.length === 0) {
      setRollCounter(prev => {
        const next = prev + 1;
        if (next >= ROLLS_FOR_GIFT) {
          spawnGifts();
          return 0;
        }
        return next;
      });
    }

    setIsRolling(true);
    setRollBank(r => r - 1);

    const diceCount = isGrayscale ? 3 : 1;
    const newValues = Array.from({ length: diceCount }, () => Math.floor(Math.random() * 6) + 1);
    const newPositions = Array.from({ length: diceCount }, (_, i) => ({
      x: landing.x + (i - Math.floor(diceCount / 2)) * (isClownMode ? 150 : 80),
      y: landing.y
    }));

    setDicePositions(newPositions);

    setTimeout(() => {
      setIsRolling(false);
      setDiceValues(newValues);
      setIsMoving(true);
      const sum = newValues.reduce((a, b) => a + b, 0);
      processMovement(sum);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  const getClownTileColor = (id: number) => {
    if (!isClownMode) return '';
    const colors = ['#ff00ff', '#00ffff', '#ffff00', '#ff0000', '#00ff00', '#ff8800', '#8800ff'];
    return colors[id % colors.length];
  };

  const activeDiceCount = isGrayscale ? 3 : 1;
  const currentDiceScale = isClownMode ? 3 : 1;

  const formatRemainingTime = (expiry: number) => {
    const diff = expiry - currentTime;
    if (diff <= 0) return '00:00:00';
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const mins = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
    const secs = Math.floor((diff % (1000 * 60)) / 1000);
    return `${hours.toString().padStart(2, '0')}:${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className={`h-screen w-screen relative notion-grid transition-all duration-700 overflow-hidden 
      ${isExploding ? 'bg-indigo-600/10' : ''} 
      ${isGrayscale ? 'filter grayscale' : ''}
      ${isClownMode ? 'clown-bg animate-color-chaos' : ''}
    `}>
      {isClownMode && isRolling && <div className="absolute inset-0 z-[100] pointer-events-none confetti-effect" />}

      {/* Top Resource Bar */}
      <div className="absolute top-8 left-1/2 -translate-x-1/2 z-[100] flex flex-col items-center gap-4">
        <div className="glass-panel px-8 py-4 rounded-3xl flex items-center gap-8 shadow-2xl border-white/20 transition-all pointer-events-auto">
          <div className="flex items-center gap-3">
             <span className="text-3xl drop-shadow-md">💎</span>
             <span className="text-2xl font-black tabular-nums">{resources.gems}</span>
          </div>
          <div className="w-px h-8 bg-black/5 dark:bg-white/5" />
          <div className="flex items-center gap-3">
             <span className="text-3xl drop-shadow-md">🪙</span>
             <span className="text-2xl font-black tabular-nums">{resources.coins}</span>
          </div>
          <div className="w-px h-8 bg-black/5 dark:bg-white/5" />
          <div className="flex flex-col items-center">
             <span className="text-[8px] font-black uppercase opacity-40 tracking-widest mb-1">Gift Progress</span>
             <div className="flex gap-1.5">
                {[...Array(ROLLS_FOR_GIFT)].map((_, i) => (
                  <div 
                    key={i} 
                    className={`h-2 rounded-full transition-all duration-500 shadow-sm ${i < rollCounter ? 'w-6 bg-indigo-500 shadow-indigo-500/50' : 'w-2 bg-black/10 dark:bg-white/10'}`} 
                  />
                ))}
             </div>
          </div>
        </div>
      </div>

      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const bloom = blooms[s.id];
          const isBomb = bombIndices.includes(s.id);
          const isZombie = zombieIndicators.includes(s.id);
          const isPumpkin = pumpkinIndices.includes(s.id);
          const isDemon = demonIndices.includes(s.id);
          const isClover = cloverIndices.includes(s.id);
          const isGhost = ghostIndices.includes(s.id);
          const isRainbow = rainbowIndices.includes(s.id);
          const isClown = clownIndices.includes(s.id);
          const isStart = s.id === 0;
          let icon = null;
          if (isBomb) icon = BOMB_ICON;
          else if (isZombie) icon = ENEMY_ICON;
          else if (isPumpkin) icon = '🎃';
          else if (isDemon) icon = '👹';
          else if (isClover) icon = '🍀';
          else if (isGhost) icon = '👻';
          else if (isRainbow) icon = '🌈';
          else if (isClown) icon = '🤡';
          return (
            <div 
              key={s.id}
              className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
              style={{ 
                left: s.x, top: s.y, width: tileSize, height: tileSize,
                backgroundColor: isClownMode ? getClownTileColor(s.id) : undefined 
              }}
            >
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {icon && (
                <span className="drop-shadow-sm opacity-25" style={{ fontSize: tileSize * 0.55 }}>
                  {icon}
                </span>
              )}
              {bloom && <span className="bloom absolute opacity-25" style={{ fontSize: tileSize * 0.5 }}>{bloom}</span>}
              {isStart && !bloom && !icon && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}

        {/* Gift Render Layer */}
        {activeGifts.map(g => {
          const space = boardSpaces[g.pos];
          if (!space) return null;
          const remaining = g.expiry - currentTime;
          const ratio = Math.max(0, remaining / (g.type === 1 ? 2*3600*1000 : (g.type === 2 ? 3*3600*1000 : 24*3600*1000)));

          return (
            <div 
              key={g.id} 
              className="absolute z-40 pointer-events-none flex flex-col items-center transition-all"
              style={{ 
                left: space.x + (tileSize * g.size) / 2, 
                top: space.y + tileSize / 2, 
                transform: 'translate(-50%, -60%)'
              }}
            >
              {/* Timer Bar */}
              <div className="bg-white/90 dark:bg-black/90 px-3 py-1 rounded-full border border-black/10 shadow-xl mb-2 flex flex-col items-center min-w-[60px]">
                 <span className="text-[8px] font-black opacity-60 tabular-nums">{formatRemainingTime(g.expiry)}</span>
                 <div className="w-full h-1 bg-black/10 rounded-full overflow-hidden mt-0.5">
                    <div className="h-full bg-indigo-500 transition-all duration-1000" style={{ width: `${ratio * 100}%` }} />
                 </div>
              </div>
              <span 
                className="drop-shadow-2xl animate-bounce-slow" 
                style={{ fontSize: tileSize * g.type }}
              >
                🎁
              </span>
            </div>
          );
        })}

        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
            left: boardSpaces[z.pos].x + tileSize/2, 
            top: boardSpaces[z.pos].y + tileSize/2, 
            transform: `translate(-50%, -60%) scale(${demonBoss.isActive ? 2.0 : 1.0})` 
          }}>
             <div className="flex flex-col items-center">
                <div className="flex gap-0.5 mb-1 bg-white/90 dark:bg-black/80 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                   {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-200 dark:bg-gray-800'}`} />
                   ))}
                </div>
                <span className="drop-shadow-2xl animate-pulse" style={{ fontSize: tileSize * 1.2 }}>{ENEMY_ICON}</span>
             </div>
          </div>
        ))}
        <div 
          onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
          className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto`}
          style={{ 
            left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, 
            top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, 
            transform: 'translate(-50%, -60%)',
            fontSize: tileSize * 1.3
          }}
        >
          <div className="flex flex-col items-center">
             <div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-2 border border-black/5 shadow-sm">
                {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (
                   <div key={i} className={`w-2 h-1 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />
                ))}
             </div>
             <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">
               {isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}
             </span>
          </div>
        </div>
        {bombAnimation.active && (
          <div className="absolute z-50 animate-bomb-drop" style={{ 
            left: boardSpaces[bombAnimation.pos]?.x + tileSize/2, 
            top: boardSpaces[bombAnimation.pos]?.y + tileSize/2,
            transform: 'translate(-50%, -100%)'
          }}>
            <span className="text-7xl drop-shadow-2xl">{darkMode ? '✨' : '💥'}</span>
          </div>
        )}
      </div>

      {/* Reward Popup */}
      {giftPopup && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center pointer-events-none">
          <div className="glass-panel p-10 rounded-[40px] shadow-2xl border-white/20 flex flex-col items-center animate-in zoom-in-50 duration-500">
             <span className="text-8xl mb-6">🎁</span>
             <h2 className="text-3xl font-black mb-4">MỞ HỘP QUÀ {giftPopup.type}!</h2>
             <div className="flex gap-8 items-center bg-black/5 dark:bg-white/5 px-8 py-4 rounded-3xl">
                <div className="flex items-center gap-3">
                   <span className="text-4xl">💎</span>
                   <span className="text-3xl font-black">+{giftPopup.rewards.gems}</span>
                </div>
                <div className="w-px h-10 bg-black/10 dark:bg-white/10" />
                <div className="flex items-center gap-3">
                   <span className="text-4xl">🪙</span>
                   <span className="text-3xl font-black">+{giftPopup.rewards.coins}</span>
                </div>
             </div>
          </div>
        </div>
      )}

      <div className="absolute inset-0 z-50 pointer-events-none flex items-center justify-center">
        <div className="pointer-events-auto flex items-stretch gap-10 scale-90 lg:scale-100 h-[420px]">
          <div className="glass-panel rounded-lg p-5 w-[432px] flex flex-col shadow-sm border border-black/5 dark:border-white/5 bg-white/95 dark:bg-zinc-900/95 transition-all">
            <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span>
                <span className="text-3xl font-normal tabular-nums tracking-tight">{rollBank}</span>
              </div>
              <div className="flex items-center gap-3">
                <div className="flex gap-1.5 p-1 bg-black/5 dark:bg-white/5 rounded">
                  {DICE_COLORS.map(c => (
                    <button key={c} onClick={() => setDiceColor(c)} className={`w-4 h-4 rounded-full border border-black/10 transition-transform ${diceColor === c ? 'scale-125' : 'hover:scale-110'}`} style={{ background: c }} />
                  ))}
                </div>
                <button onClick={() => setDarkMode(!darkMode)} className="w-8 h-8 flex items-center justify-center rounded hover:bg-black/5 transition-all text-lg">{darkMode ? '☀️' : '🌙'}</button>
              </div>
            </div>
            <div className="flex-grow overflow-y-auto pr-1 custom-scrollbar space-y-px">
              {!showHistory ? tasks.map(t => (
                <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-2 hover:bg-black/5 rounded transition-colors flex items-center gap-3 cursor-pointer">
                  <div className="w-3.5 h-3.5 rounded-sm border border-black/20 group-hover:bg-indigo-500/10 group-hover:border-indigo-500 transition-all" />
                  <div className="flex-grow overflow-hidden">
                    <div className="text-[13px] font-medium truncate opacity-90">{t.text}</div>
                    {t.priority && <div className={`inline-block text-[8px] font-black uppercase px-1 rounded-sm mt-0.5 border ${getPriorityColor(t.priority)}`}>{t.priority}</div>}
                  </div>
                </div>
              )) : history.map(h => (
                <div key={h.id} className="p-2 border-l border-indigo-500/10 opacity-40">
                  <span className="text-[12px] line-through block">{h.text}</span>
                  <span className="text-[9px] uppercase tracking-tighter">{h.completedAt}</span>
                </div>
              ))}
            </div>
            <div className="mt-4 pt-4 border-t border-black/5 flex flex-col gap-3">
              <div className="flex gap-1">
                {(['low', 'medium', 'high'] as const).map(p => (
                    <button key={p} onClick={() => setNewTaskPriority(p)} className={`flex-1 py-1 text-[8px] font-bold uppercase rounded border transition-all ${newTaskPriority === p ? 'bg-indigo-600 border-indigo-600 text-white' : 'opacity-50 hover:bg-black/5'}`}>{p}</button>
                ))}
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowHistory(!showHistory)} className="px-3 py-2 text-[10px] font-bold border rounded hover:bg-black/5 transition-colors">{showHistory ? 'Tasks' : 'Log'}</button>
                <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); setNewTask(''); }} className="flex-1">
                    <input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full h-8 bg-black/[0.02] border rounded px-3 text-[12px] outline-none" placeholder="Add mission..." />
                </form>
              </div>
            </div>
          </div>
          <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} />
          <div className="w-64 flex flex-col items-center justify-center relative h-[420px] gap-4">
            {pumpkinBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center">
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-orange-500/20 backdrop-blur-md">
                   {[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < pumpkinBoss.health ? 'bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>🎃</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-orange-600/60 mt-1">Pumpkin Boss</span>
              </div>
            )}
            {demonBoss.isActive && (
              <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center" style={{ animationDelay: '-1.5s' }}>
                <div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-red-500/20 backdrop-blur-md">
                   {[...Array(MAX_DEMON_HEALTH)].map((_, i) => (
                      <div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < demonBoss.health ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.4)]' : 'bg-gray-200 opacity-20'}`} />
                   ))}
                </div>
                <span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>👹</span>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-red-600/60 mt-1">Demon Buff</span>
              </div>
            )}
          </div>
          <div className="w-12"></div>
        </div>
      </div>
      {Array.from({ length: activeDiceCount }).map((_, i) => (
        <Dice3D 
          key={i}
          color={diceColor} 
          value={diceValues[i] || 1} 
          isRolling={isRolling} 
          currentPos={dicePositions[i] || { x: window.innerWidth / 2, y: window.innerHeight / 2 }} 
          onRoll={(landing) => handleRoll(landing, i)} 
          onDragEnd={(finalPos) => setDicePositions(prev => {
            const next = [...prev];
            next[i] = finalPos;
            return next;
          })} 
          scale={currentDiceScale}
        />
      ))}
      <style>{`
        @keyframes bounce-slow { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-12px); } }
        .animate-bounce-slow { animation: bounce-slow 3s ease-in-out infinite; }
        @keyframes bomb-drop { 0% { transform: translate(-50%, -300%) scale(2); opacity: 0; } 60% { transform: translate(-50%, -60%) scale(1); opacity: 1; } 100% { transform: translate(-50%, -60%) scale(14); opacity: 0; filter: blur(50px); } }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.06); background: rgba(255,255,255,0.95); border-radius: 4px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.03); background: rgba(18,18,18,0.95); }
        .glass-panel { backdrop-filter: blur(40px); }
        @keyframes color-chaos { 0% { background-color: #ff0000; } 25% { background-color: #00ff00; } 50% { background-color: #0000ff; } 75% { background-color: #ffff00; } 100% { background-color: #ff00ff; } }
        .animate-color-chaos { animation: color-chaos 5s infinite linear; }
        .confetti-effect { background-image: radial-gradient(circle, #ff0 10%, transparent 10.5%), radial-gradient(circle, #f00 10%, transparent 10.5%), radial-gradient(circle, #0f0 10%, transparent 10.5%), radial-gradient(circle, #00f 10%, transparent 10.5%); background-size: 10px 10px, 15px 15px, 20px 20px, 12px 12px; background-position: 0 0, 5px 5px, 10px 10px, 15px 15px; animation: confetti-fall 2s infinite linear; opacity: 0.6; }
        @keyframes confetti-fall { 0% { background-position: 0 0; } 100% { background-position: 100px 500px; } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss, Gift, Resources } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 
const ROLLS_FOR_GIFT = 7;

// Tile Counts
const ZOMBIE_INDICATOR_COUNT = 10; 
const BOMB_COUNT = 10;           
const PUMPKIN_COUNT = 5; 
const DEMON_COUNT = 5; 
const CLOVER_COUNT = 5; 
const GHOST_COUNT = 3; 
const RAINBOW_COUNT = 3; 
const CLOWN_COUNT = 2; 

// HP Settings
const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

// Board Dimensions
const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 
const SPAWN_BEHIND_OFFSET = 5;

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🦌', '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤', '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.3)', 'rgba(199, 210, 254, 0.5)', 'rgba(254, 202, 202, 0.5)', 'rgba(167, 243, 208, 0.5)', 'rgba(253, 230, 138, 0.5)', 
];

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  const [resources, setResources] = useState<Resources>({ gems: 0, coins: 0 });
  const [rollCounter, setRollCounter] = useState(0);
  const [activeGifts, setActiveGifts] = useState<Gift[]>([]);
  const [popup, setPopup] = useState<{ text: string; sub: string } | null>(null);

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<(Task & { completedAt: string })[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([{ x: window.innerWidth / 2, y: window.innerHeight / 2 }]);

  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  const [now, setNow] = useState(Date.now());

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  useEffect(() => {
    const timer = setInterval(() => {
      setNow(Date.now());
      setActiveGifts(prev => prev.filter(g => g.expiry > Date.now()));
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const [tileSize, setTileSize] = useState(64);

  useEffect(() => {
    const updateSize = () => {
      const horizontalLimit = (window.innerWidth - 40) / BOARD_W;
      const verticalLimit = (window.innerHeight - 40) / BOARD_H;
      setTileSize(Math.max(38, Math.min(horizontalLimit, verticalLimit, 64)));
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeResizeListener?.(updateSize) || window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = BOARD_W * tileSize;
    const totalH = BOARD_H * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2;
    for (let i = 0; i < BOARD_W; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });
    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    const gInd = getRandomUnique(GHOST_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd]);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd, ...rInd]);
    setZombieIndicators(zInd); setBombIndices(bInd); setPumpkinIndices(pInd); setDemonIndices(dInd); setCloverIndices(cInd); setGhostIndices(gInd); setRainbowIndices(rInd); setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    setBlooms(prev => ({ ...prev, [pos]: FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)] }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => { const n = { ...prev }; delete n[pos]; return n; }), 800);
  };

  const spawnGifts = useCallback(() => {
    const t = Date.now();
    const g1: Gift = { id: 'g1', type: 1, pos: (currentPos + 20) % TOTAL_TILES, size: 1, expiry: t + 2 * 3600 * 1000, rewards: { gems: 1, coins: 10 } };
    const g2: Gift = { id: 'g2', type: 2, pos: (currentPos + 30) % TOTAL_TILES, size: 2, expiry: t + 3 * 3600 * 1000, rewards: { gems: 3, coins: 20 } };
    const g3: Gift = { id: 'g3', type: 3, pos: (currentPos + 50) % TOTAL_TILES, size: 3, expiry: t + 24 * 3600 * 1000, rewards: { gems: 5, coins: 30 } };
    setActiveGifts([g1, g2, g3]);
  }, [currentPos]);

  const collectGift = (gift: Gift) => {
    setActiveGifts(prev => prev.filter(g => g.id !== gift.id));
    setResources(r => ({ gems: r.gems + gift.rewards.gems, coins: r.coins + gift.rewards.coins }));
    setPopup({ text: `Hộp quà ${gift.type} !`, sub: `Nhận ${gift.rewards.gems}💎 & ${gift.rewards.coins}🪙` });
    setTimeout(() => setPopup(null), 2500);
  };

  const relocateItem = useCallback((list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...clownIndices];
    const [newPos] = getRandomUnique(1, exclude);
    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  }, [currentPos, bombIndices, zombieIndicators, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, getRandomUnique]);

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) setPumpkinBoss(p => ({ ...p, health: Math.max(0, p.health - 1), isActive: p.health > 1 }));
    if (demonBoss.isActive) setDemonBoss(d => ({ ...d, health: Math.max(0, d.health - 1), isActive: d.health > 1 }));
    setActiveZombies(prev => {
      if (prev.length === 0) return prev;
      let minIdx = -1, minD = Infinity;
      prev.forEach((z, i) => { const d = Math.min(Math.abs(damagePos - z.pos), TOTAL_TILES - Math.abs(damagePos - z.pos)); if(d < minD){ minD = d; minIdx = i; }});
      if(minIdx === -1) return prev;
      const next = [...prev]; next[minIdx] = { ...next[minIdx], health: next[minIdx].health - 1 };
      return next.filter(z => z.health > 0);
    });
    setIsShaking(true); setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
  }, [pumpkinBoss, demonBoss, activeZombies]);

  const handleGameOver = () => {
    setIsShaking(true); setJarCount(0); setCurrentPos(0); setActiveZombies([]); setPumpkinBoss({ isActive: false, health: 0 }); setDemonBoss({ isActive: false, health: 0 }); setIsGrayscale(false); setIsClownMode(false);
    setTimeout(() => setIsShaking(false), 500);
  };

  const processMovement = useCallback((diceSum: number) => {
    let steps = 0, temp = currentPos;
    if (diceSum === 1) applyBombDamage(temp);
    const interval = setInterval(() => {
      temp = (temp + 1) % TOTAL_TILES;
      setCurrentPos(temp); triggerBloom(temp); steps++;

      // Check for Gifts collection (passing through)
      activeGifts.forEach(g => {
        for(let i=0; i<g.size; i++) {
          if((g.pos + i) % TOTAL_TILES === temp) { collectGift(g); break; }
        }
      });

      if (temp === 0) { setIsGrayscale(false); setIsClownMode(false); }
      if (cloverIndices.includes(temp)) { setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1)); relocateItem(cloverIndices, temp, 'clover'); }
      if (bombIndices.includes(temp)) { applyBombDamage(temp); relocateItem(bombIndices, temp, 'bomb'); }

      if (steps >= diceSum) {
        clearInterval(interval); setIsMoving(false);
        if (ghostIndices.includes(temp)) { setIsGrayscale(true); setIsClownMode(false); relocateItem(ghostIndices, temp, 'ghost'); }
        if (rainbowIndices.includes(temp)) { setIsGrayscale(false); setIsClownMode(false); relocateItem(rainbowIndices, temp, 'rainbow'); }
        if (clownIndices.includes(temp)) { setIsClownMode(true); setIsGrayscale(false); relocateItem(clownIndices, temp, 'clown'); }
        if (zombieIndicators.includes(temp)) {
          setActiveZombies(p => [...p, { id: Math.random().toString(36).substr(2, 9), pos: (temp - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES, health: MAX_ZOMBIE_HEALTH, isActive: true }]);
          relocateItem(zombieIndicators, temp, 'zombie');
        }
        if (pumpkinIndices.includes(temp)) { setPumpkinBoss({ isActive: true, health: MAX_PUMPKIN_HEALTH }); relocateItem(pumpkinIndices, temp, 'pumpkin'); }
        if (demonIndices.includes(temp)) { setDemonBoss({ isActive: true, health: MAX_DEMON_HEALTH }); relocateItem(demonIndices, temp, 'demon'); }
        setActiveZombies(prev => {
          let hit = false; const move = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => { const n = (z.pos + move) % TOTAL_TILES; if (n === temp) hit = true; return { ...z, pos: n }; });
          if (hit) { setPlayerHealth(h => { const n = h - 1; if (n <= 0) { handleGameOver(); return MAX_PLAYER_HEALTH; } return n; }); return []; }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, activeGifts, cloverIndices, bombIndices, ghostIndices, rainbowIndices, clownIndices, zombieIndicators, pumpkinIndices, demonIndices, demonBoss.isActive, applyBombDamage, relocateItem]);

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    if (pumpkinBoss.isActive) { setIsDeducting(true); setJarCount(p => Math.max(0, p - 5)); setTimeout(() => setIsDeducting(false), 800); }

    // Counter rolls only if no gifts on screen
    if (activeGifts.length === 0) {
      setRollCounter(prev => {
        const next = prev + 1;
        if (next >= ROLLS_FOR_GIFT) { spawnGifts(); return 0; }
        return next;
      });
    }

    setIsRolling(true); setRollBank(r => r - 1);
    const count = isGrayscale ? 3 : 1;
    const vals = Array.from({ length: count }, () => Math.floor(Math.random() * 6) + 1);
    setDicePositions(Array.from({ length: count }, (_, i) => ({ x: landing.x + (i - Math.floor(count/2)) * (isClownMode ? 150 : 80), y: landing.y })));
    setTimeout(() => { setIsRolling(false); setDiceValues(vals); setIsMoving(true); processMovement(vals.reduce((a, b) => a + b, 0)); }, 1200);
  };

  const formatTime = (ms: number) => {
    const s = Math.max(0, Math.floor(ms / 1000));
    const h = Math.floor(s / 3600), m = Math.floor((s % 3600) / 60), sc = s % 60;
    return `${h}h ${m}m ${sc}s`;
  };

  // Add missing logic for task completion and alchemy jar explosion
  const handleTaskComplete = (task: Task) => {
    setTasks(prev => prev.filter(t => t.id !== task.id));
    setHistory(prev => [{ ...task, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setRollBank(r => r + (task.priority === 'high' ? 15 : task.priority === 'medium' ? 10 : 5));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setTimeout(() => {
      setIsExploding(false);
      setJarCount(0);
      setRollBank(r => r + 50);
      setPopup({ text: "ALCHEMY EXPLOSION!", sub: "+50 Energy Received" });
      setTimeout(() => setPopup(null), 2500);
    }, 1000);
  };

  // Calculate dice count and scale based on active effects
  const activeDiceCount = diceValues.length;
  const currentDiceScale = isGrayscale ? 0.8 : (isClownMode ? 1.4 : 1);

  return (
    <div className={`h-screen w-screen relative transition-all duration-700 overflow-hidden notion-grid ${isExploding ? 'bg-indigo-600/10' : ''} ${isGrayscale ? 'filter grayscale' : ''} ${isClownMode ? 'clown-bg animate-color-chaos' : ''}`}>
      {isClownMode && isRolling && <div className="absolute inset-0 z-[100] pointer-events-none confetti-effect" />}

      {/* Gift Layer */}
      <div className="absolute inset-0 z-10 pointer-events-none">
        {activeGifts.map(g => {
          const space = boardSpaces[g.pos];
          if (!space) return null;
          const remaining = g.expiry - now;
          const totalDuration = g.type === 1 ? 2 * 3600 * 1000 : (g.type === 2 ? 3 * 3600 * 1000 : 24 * 3600 * 1000);
          const ratio = Math.max(0, remaining / totalDuration);
          return (
            <div key={g.id} className="absolute z-40 flex flex-col items-center justify-end" style={{ left: space.x + (tileSize * g.size) / 2, top: space.y + tileSize / 2, transform: 'translate(-50%, -50%)', height: tileSize * 3 }}>
              <div className="bg-white/90 dark:bg-black/80 px-2 py-0.5 rounded-full border border-black/10 shadow-sm mb-1">
                <div className="text-[7px] font-black uppercase text-center opacity-40 leading-none mb-0.5">{formatTime(remaining)}</div>
                <div className="w-10 h-0.5 bg-gray-200 rounded-full overflow-hidden">
                  <div className="h-full bg-indigo-500" style={{ width: `${ratio * 100}%` }} />
                </div>
              </div>
              <span className="drop-shadow-lg leading-none transition-transform" style={{ fontSize: tileSize * g.type, transform: `scale(${1 + Math.sin(now / 300) * 0.05})` }}>🎁</span>
            </div>
          );
        })}
      </div>

      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const isB = bombIndices.includes(s.id), isZ = zombieIndicators.includes(s.id), isP = pumpkinIndices.includes(s.id), isD = demonIndices.includes(s.id), isC = cloverIndices.includes(s.id), isG = ghostIndices.includes(s.id), isR = rainbowIndices.includes(s.id), isCl = clownIndices.includes(s.id), isSt = s.id === 0;
          let icon = null; if (isB) icon = darkMode ? '🧄' : '💣'; else if (isZ) icon = darkMode ? '🧛🏻' : '🧟'; else if (isP) icon = '🎃'; else if (isD) icon = '👹'; else if (isC) icon = '🍀'; else if (isG) icon = '👻'; else if (isR) icon = '🌈'; else if (isCl) icon = '🤡';
          return (
            <div key={s.id} className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isSt ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`} style={{ left: s.x, top: s.y, width: tileSize, height: tileSize, backgroundColor: isClownMode ? '' : undefined }}>
              <span className="text-[9px] opacity-10 absolute top-1 left-1 font-bold">{s.id + 1}</span>
              {icon && <span className="drop-shadow-sm opacity-25" style={{ fontSize: tileSize * 0.55 }}>{icon}</span>}
              {blooms[s.id] && <span className="bloom absolute opacity-25" style={{ fontSize: tileSize * 0.5 }}>{blooms[s.id]}</span>}
              {isSt && !blooms[s.id] && !icon && <span className="text-[8px] font-black opacity-30 uppercase tracking-widest">Home</span>}
            </div>
          );
        })}
        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ left: boardSpaces[z.pos].x + tileSize/2, top: boardSpaces[z.pos].y + tileSize/2, transform: `translate(-50%, -60%) scale(${demonBoss.isActive ? 2 : 1})` }}>
            <div className="flex flex-col items-center"><div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-2 shadow-sm">{[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (<div key={i} className={`w-2 h-1 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-200'}`} />))}</div><span className="drop-shadow-2xl animate-pulse" style={{ fontSize: tileSize * 1.2 }}>{darkMode ? '🧛🏻' : '🧟'}</span></div>
          </div>
        ))}
        <div onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)} className="absolute z-30 transition-all duration-300 cursor-pointer pointer-events-auto" style={{ left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, transform: 'translate(-50%, -60%)', fontSize: tileSize * 1.3 }}>
          <div className="flex flex-col items-center"><div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-2 shadow-sm">{[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (<div key={i} className={`w-2 h-1 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />))}</div><span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">{isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}</span></div>
        </div>
      </div>

      <div className="absolute inset-0 z-50 pointer-events-none flex flex-col items-center p-10">
        {/* Resource Bar Top */}
        <div className="pointer-events-auto glass-panel px-6 py-3 rounded-2xl flex items-center gap-8 shadow-2xl border border-black/5 animate-in slide-in-from-top-10">
          <div className="flex items-center gap-3">
            <span className="text-xl">💎</span>
            <span className="text-2xl font-black tabular-nums">{resources.gems}</span>
          </div>
          <div className="w-px h-6 bg-black/5 dark:bg-white/5" />
          <div className="flex items-center gap-3">
            <span className="text-xl">🪙</span>
            <span className="text-2xl font-black tabular-nums">{resources.coins}</span>
          </div>
          <div className="w-px h-6 bg-black/5 dark:bg-white/5" />
          <div className="flex flex-col items-center">
            <span className="text-[8px] font-black uppercase opacity-40 tracking-widest mb-1">Gift Progress</span>
            <div className="flex gap-1">
              {[...Array(ROLLS_FOR_GIFT)].map((_, i) => (
                <div key={i} className={`w-3 h-1.5 rounded-full transition-all ${i < rollCounter ? 'bg-indigo-500 shadow-[0_0_8px_rgba(99,102,241,0.5)]' : 'bg-black/10 dark:bg-white/10'}`} />
              ))}
            </div>
          </div>
        </div>

        <div className="flex-grow flex items-center justify-center gap-10">
          <div className="pointer-events-auto flex items-stretch gap-10 scale-90 lg:scale-100 h-[420px]">
            <div className="glass-panel rounded-lg p-5 w-[432px] flex flex-col shadow-sm border border-black/5 bg-white/95 dark:bg-zinc-900/95 transition-all">
              <div className="flex justify-between items-start mb-6">
                <div><span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span><span className="text-3xl font-normal tabular-nums">{rollBank}</span></div>
                <div className="flex gap-2">
                  <div className="flex gap-1.5 p-1 bg-black/5 rounded">{DICE_COLORS.map(c => (<button key={c} onClick={() => setDiceColor(c)} className={`w-4 h-4 rounded-full border border-black/10 transition-transform ${diceColor === c ? 'scale-125' : 'hover:scale-110'}`} style={{ background: c }} />))}</div>
                  <button onClick={() => setDarkMode(!darkMode)} className="w-8 h-8 flex items-center justify-center rounded hover:bg-black/5 transition-all text-lg">{darkMode ? '☀️' : '🌙'}</button>
                </div>
              </div>
              <div className="flex-grow overflow-y-auto pr-1 custom-scrollbar space-y-px">
                {!showHistory ? tasks.map(t => (<div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-2 hover:bg-black/5 rounded transition-colors flex items-center gap-3 cursor-pointer"><div className="w-3.5 h-3.5 rounded-sm border border-black/20 group-hover:bg-indigo-500/10 group-hover:border-indigo-500 transition-all" /><div className="flex-grow overflow-hidden"><div className="text-[13px] font-medium truncate opacity-90">{t.text}</div>{t.priority && <div className={`inline-block text-[8px] font-black uppercase px-1 rounded-sm mt-0.5 border ${getPriorityColor(t.priority)}`}>{t.priority}</div>}</div></div>)) : history.map(h => (<div key={h.id} className="p-2 border-l border-indigo-500/10 opacity-40"><span className="text-[12px] line-through block">{h.text}</span><span className="text-[9px] uppercase tracking-tighter">{h.completedAt}</span></div>))}
              </div>
              <div className="mt-4 pt-4 border-t border-black/5 flex gap-2"><button onClick={() => setShowHistory(!showHistory)} className="px-3 py-2 text-[10px] font-bold border rounded hover:bg-black/5">{showHistory ? 'Tasks' : 'Log'}</button><form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); setNewTask(''); }} className="flex-1"><input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full h-8 bg-black/[0.02] border rounded px-3 text-[12px] outline-none" placeholder="Add mission..." /></form></div>
            </div>
            <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} />
            <div className="w-64 flex flex-col items-center justify-center relative h-[420px] gap-4">
              {pumpkinBoss.isActive && (<div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center"><div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-orange-500/20 backdrop-blur-md">{[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (<div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < pumpkinBoss.health ? 'bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.4)]' : 'bg-gray-200 opacity-20'}`} />))}</div><span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>🎃</span><span className="text-[8px] font-black uppercase tracking-[0.2em] text-orange-600/60 mt-1">Pumpkin Boss</span></div>)}
              {demonBoss.isActive && (<div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center" style={{ animationDelay: '-1.5s' }}><div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-red-500/20 backdrop-blur-md">{[...Array(MAX_DEMON_HEALTH)].map((_, i) => (<div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < demonBoss.health ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.4)]' : 'bg-gray-200 opacity-20'}`} />))}</div><span className="leading-none drop-shadow-xl" style={{ fontSize: '120px' }}>👹</span><span className="text-[8px] font-black uppercase tracking-[0.2em] text-red-600/60 mt-1">Demon Buff</span></div>)}
            </div>
          </div>
        </div>
      </div>

      {popup && (
        <div className="fixed top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-[200] glass-panel p-8 rounded-3xl text-center shadow-[0_40px_100px_rgba(0,0,0,0.3)] animate-in zoom-in-50 duration-300">
           <div className="text-6xl mb-4">🎁</div>
           <div className="text-2xl font-black mb-2">{popup.text}</div>
           <div className="text-indigo-600 font-bold">{popup.sub}</div>
        </div>
      )}

      {Array.from({ length: activeDiceCount }).map((_, i) => (
        <Dice3D key={i} color={diceColor} value={diceValues[i] || 1} isRolling={isRolling} currentPos={dicePositions[i] || { x: window.innerWidth / 2, y: window.innerHeight / 2 }} onRoll={handleRoll} onDragEnd={(f) => setDicePositions(p => { const n = [...p]; n[i] = f; return n; })} scale={currentDiceScale} />
      ))}
      <style>{`
        @keyframes bounce-slow { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-12px); } }
        .animate-bounce-slow { animation: bounce-slow 3s ease-in-out infinite; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.06); background: rgba(255,255,255,0.95); border-radius: 4px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.03); background: rgba(18,18,18,0.95); }
        .glass-panel { backdrop-filter: blur(40px); }
        @keyframes color-chaos { 0% { background-color: #ff0000; } 25% { background-color: #00ff00; } 50% { background-color: #0000ff; } 75% { background-color: #ffff00; } 100% { background-color: #ff00ff; } }
        .animate-color-chaos { animation: color-chaos 5s infinite linear; }
        .confetti-effect { background-image: radial-gradient(circle, #ff0 10%, transparent 10.5%), radial-gradient(circle, #f00 10%, transparent 10.5%); background-size: 10px 10px; animation: confetti-fall 2s infinite linear; opacity: 0.6; }
        @keyframes confetti-fall { 0% { background-position: 0 0; } 100% { background-position: 100px 500px; } }
      `}</style>
    </div>
  );
};

const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10';
        default: return 'bg-blue-50 text-blue-600 border-blue-100';
    }
}

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss, Gift, Resources } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 
const ROLLS_FOR_GIFT = 7;

// Balanced Board Dimensions to allow vertical clearance for 3-tile high gifts
const BOARD_W = 18; 
const BOARD_H = 16; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 
const SPAWN_BEHIND_OFFSET = 5;

// Tile Counts
const ZOMBIE_INDICATOR_COUNT = 8; 
const BOMB_COUNT = 8;           
const PUMPKIN_COUNT = 4; 
const DEMON_COUNT = 4; 
const CLOVER_COUNT = 5; 
const GHOST_COUNT = 3; 
const RAINBOW_COUNT = 3; 
const CLOWN_COUNT = 2; 

// HP Settings
const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🦌', '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤', '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.3)', 'rgba(199, 210, 254, 0.5)', 'rgba(254, 202, 202, 0.5)', 'rgba(167, 243, 208, 0.5)', 'rgba(253, 230, 138, 0.5)', 
];

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  const [resources, setResources] = useState<Resources>({ gems: 0, coins: 0 });
  const [rollCounter, setRollCounter] = useState(0);
  const [activeGifts, setActiveGifts] = useState<Gift[]>([]);
  const [popup, setPopup] = useState<{ text: string; sub: string } | null>(null);

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<(Task & { completedAt: string })[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([{ x: window.innerWidth / 2, y: window.innerHeight / 2 }]);

  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  const [now, setNow] = useState(Date.now());

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  useEffect(() => {
    const timer = setInterval(() => {
      setNow(Date.now());
      setActiveGifts(prev => prev.filter(g => g.expiry > Date.now()));
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const [tileSize, setTileSize] = useState(64);

  useEffect(() => {
    const updateSize = () => {
      const hPadding = 100;
      // vPadding is larger to accommodate the tallest 🎁 which is 3 tiles high
      const vPadding = 240; 
      const horizontalLimit = (window.innerWidth - hPadding) / BOARD_W;
      const verticalLimit = (window.innerHeight - vPadding) / BOARD_H;
      setTileSize(Math.max(32, Math.min(horizontalLimit, verticalLimit, 58)));
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = (BOARD_W - 1) * tileSize;
    const totalH = (BOARD_H - 1) * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    // Push map down slightly to give room for tall gifts on the top row
    const startY = (window.innerHeight - totalH) / 2 + 40; 

    // Top edge
    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, x: startX + i * tileSize, y: startY, type: 'normal' });
    // Right edge
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize, type: 'normal' });
    // Bottom edge
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize, type: 'normal' });
    // Left edge
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, x: startX, y: startY + i * tileSize, type: 'normal' });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    const gInd = getRandomUnique(GHOST_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd]);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd, ...rInd]);
    setZombieIndicators(zInd); setBombIndices(bInd); setPumpkinIndices(pInd); setDemonIndices(dInd); setCloverIndices(cInd); setGhostIndices(gInd); setRainbowIndices(rInd); setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    setBlooms(prev => ({ ...prev, [pos]: FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)] }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => { const n = { ...prev }; delete n[pos]; return n; }), 800);
  };

  const spawnGifts = useCallback(() => {
    const t = Date.now();
    const g1: Gift = { id: 'g1', type: 1, pos: (currentPos + 20) % TOTAL_TILES, size: 1, expiry: t + 2 * 3600 * 1000, rewards: { gems: 1, coins: 10 } };
    const g2: Gift = { id: 'g2', type: 2, pos: (currentPos + 30) % TOTAL_TILES, size: 2, expiry: t + 3 * 3600 * 1000, rewards: { gems: 3, coins: 20 } };
    const g3: Gift = { id: 'g3', type: 3, pos: (currentPos + 50) % TOTAL_TILES, size: 3, expiry: t + 24 * 3600 * 1000, rewards: { gems: 5, coins: 30 } };
    setActiveGifts([g1, g2, g3]);
  }, [currentPos]);

  const collectGift = (gift: Gift) => {
    setActiveGifts(prev => prev.filter(g => g.id !== gift.id));
    setResources(r => ({ gems: r.gems + gift.rewards.gems, coins: r.coins + gift.rewards.coins }));
    setPopup({ text: `Hộp quà ${gift.type} !`, sub: `Nhận ${gift.rewards.gems}💎 & ${gift.rewards.coins}🪙` });
    setTimeout(() => setPopup(null), 2500);
  };

  const relocateItem = useCallback((list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...clownIndices];
    const [newPos] = getRandomUnique(1, exclude);
    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  }, [currentPos, bombIndices, zombieIndicators, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, getRandomUnique]);

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) setPumpkinBoss(p => ({ ...p, health: Math.max(0, p.health - 1), isActive: p.health > 1 }));
    if (demonBoss.isActive) setDemonBoss(d => ({ ...d, health: Math.max(0, d.health - 1), isActive: d.health > 1 }));
    setActiveZombies(prev => {
      if (prev.length === 0) return prev;
      let minIdx = -1, minD = Infinity;
      prev.forEach((z, i) => { const d = Math.min(Math.abs(damagePos - z.pos), TOTAL_TILES - Math.abs(damagePos - z.pos)); if(d < minD){ minD = d; minIdx = i; }});
      if(minIdx === -1) return prev;
      const next = [...prev]; next[minIdx] = { ...next[minIdx], health: next[minIdx].health - 1 };
      return next.filter(z => z.health > 0);
    });
    setIsShaking(true); setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
  }, [pumpkinBoss, demonBoss, activeZombies]);

  const handleGameOver = () => {
    setIsShaking(true); setJarCount(0); setCurrentPos(0); setActiveZombies([]); setPumpkinBoss({ isActive: false, health: 0 }); setDemonBoss({ isActive: false, health: 0 }); setIsGrayscale(false); setIsClownMode(false);
    setTimeout(() => setIsShaking(false), 500);
  };

  const processMovement = useCallback((diceSum: number) => {
    let steps = 0, temp = currentPos;
    if (diceSum === 1) applyBombDamage(temp);
    const interval = setInterval(() => {
      temp = (temp + 1) % TOTAL_TILES;
      setCurrentPos(temp); triggerBloom(temp); steps++;

      activeGifts.forEach(g => {
        for(let i=0; i<g.size; i++) {
          if((g.pos + i) % TOTAL_TILES === temp) { collectGift(g); break; }
        }
      });

      if (temp === 0) { setIsGrayscale(false); setIsClownMode(false); }
      if (cloverIndices.includes(temp)) { setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1)); relocateItem(cloverIndices, temp, 'clover'); }
      if (bombIndices.includes(temp)) { applyBombDamage(temp); relocateItem(bombIndices, temp, 'bomb'); }

      if (steps >= diceSum) {
        clearInterval(interval); setIsMoving(false);
        if (ghostIndices.includes(temp)) { setIsGrayscale(true); setIsClownMode(false); relocateItem(ghostIndices, temp, 'ghost'); }
        if (rainbowIndices.includes(temp)) { setIsGrayscale(false); setIsClownMode(false); relocateItem(rainbowIndices, temp, 'rainbow'); }
        if (clownIndices.includes(temp)) { setIsClownMode(true); setIsGrayscale(false); relocateItem(clownIndices, temp, 'clown'); }
        if (zombieIndicators.includes(temp)) {
          setActiveZombies(p => [...p, { id: Math.random().toString(36).substr(2, 9), pos: (temp - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES, health: MAX_ZOMBIE_HEALTH, isActive: true }]);
          relocateItem(zombieIndicators, temp, 'zombie');
        }
        if (pumpkinIndices.includes(temp)) { setPumpkinBoss({ isActive: true, health: MAX_PUMPKIN_HEALTH }); relocateItem(pumpkinIndices, temp, 'pumpkin'); }
        if (demonIndices.includes(temp)) { setDemonBoss({ isActive: true, health: MAX_DEMON_HEALTH }); relocateItem(demonIndices, temp, 'demon'); }
        setActiveZombies(prev => {
          let hit = false; const move = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => { const n = (z.pos + move) % TOTAL_TILES; if (n === temp) hit = true; return { ...z, pos: n }; });
          if (hit) { setPlayerHealth(h => { const n = h - 1; if (n <= 0) { handleGameOver(); return MAX_PLAYER_HEALTH; } return n; }); return []; }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, activeGifts, cloverIndices, bombIndices, ghostIndices, rainbowIndices, clownIndices, zombieIndicators, pumpkinIndices, demonIndices, demonBoss.isActive, applyBombDamage, relocateItem]);

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    if (pumpkinBoss.isActive) { setIsDeducting(true); setJarCount(p => Math.max(0, p - 5)); setTimeout(() => setIsDeducting(false), 800); }

    if (activeGifts.length === 0) {
      setRollCounter(prev => {
        const next = prev + 1;
        if (next >= ROLLS_FOR_GIFT) { spawnGifts(); return 0; }
        return next;
      });
    }

    setIsRolling(true); setRollBank(r => r - 1);
    const count = isGrayscale ? 3 : 1;
    const vals = Array.from({ length: count }, () => Math.floor(Math.random() * 6) + 1);
    setDicePositions(Array.from({ length: count }, (_, i) => ({ x: landing.x + (i - Math.floor(count/2)) * (isClownMode ? 150 : 80), y: landing.y })));
    setTimeout(() => { setIsRolling(false); setDiceValues(vals); setIsMoving(true); processMovement(vals.reduce((a, b) => a + b, 0)); }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setTasks(prev => prev.filter(t => t.id !== task.id));
    setHistory(prev => [{ ...task, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setRollBank(r => r + (task.priority === 'high' ? 15 : task.priority === 'medium' ? 10 : 5));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setTimeout(() => {
      setIsExploding(false);
      setJarCount(0);
      setRollBank(r => r + 50);
      setPopup({ text: "ALCHEMY EXPLOSION!", sub: "+50 Energy Received" });
      setTimeout(() => setPopup(null), 2500);
    }, 1000);
  };

  const formatTime = (ms: number) => {
    const s = Math.max(0, Math.floor(ms / 1000));
    const h = Math.floor(s / 3600), m = Math.floor((s % 3600) / 60), sc = s % 60;
    return `${h}h ${m}m ${sc}s`;
  };

  const activeDiceCount = diceValues.length;
  const currentDiceScale = isGrayscale ? 0.8 : (isClownMode ? 1.4 : 1);

  return (
    <div className={`h-screen w-screen relative transition-all duration-700 overflow-hidden notion-grid ${isExploding ? 'bg-indigo-600/10' : ''} ${isGrayscale ? 'filter grayscale' : ''} ${isClownMode ? 'clown-bg animate-color-chaos' : ''}`}>
      {isClownMode && isRolling && <div className="absolute inset-0 z-[100] pointer-events-none confetti-effect" />}

      {/* Gift Layer */}
      <div className="absolute inset-0 z-10 pointer-events-none">
        {activeGifts.map(g => {
          const space = boardSpaces[g.pos];
          if (!space) return null;
          const remaining = g.expiry - now;
          const totalDuration = g.type === 1 ? 2 * 3600 * 1000 : (g.type === 2 ? 3 * 3600 * 1000 : 24 * 3600 * 1000);
          const ratio = Math.max(0, remaining / totalDuration);
          return (
            <div key={g.id} className="absolute z-40 flex flex-col items-center justify-end" style={{ left: space.x + (tileSize * g.size) / 2, top: space.y + tileSize / 2, transform: 'translate(-50%, -60%)', height: tileSize * 3 }}>
              <div className="bg-white/95 dark:bg-black/95 px-2 py-0.5 rounded-full border border-black/10 shadow-sm mb-2 backdrop-blur-md">
                <div className="text-[7px] font-black uppercase text-center opacity-60 leading-none mb-0.5 tabular-nums">{formatTime(remaining)}</div>
                <div className="w-12 h-1 bg-gray-100 dark:bg-white/5 rounded-full overflow-hidden">
