          let icon = null; if (isB) icon = darkMode ? '🧄' : '💣'; else if (isZ) icon = darkMode ? '🧛🏻' : '🧟'; else if (isP) icon = '🎃'; else if (isD) icon = '👹'; else if (isC) icon = '🍀'; else if (isG) icon = '👻'; else if (isR) icon = '🌈'; else if (isCl) icon = '🤡';
          return (
            <div key={s.id} className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isSt ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`} style={{ left: s.x, top: s.y, width: tileSize, height: tileSize }}>
