          </div>
        ))}
        <div onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)} className="absolute z-30 transition-all duration-300 cursor-pointer pointer-events-auto" style={{ left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, transform: 'translate(-50%, -60%)', fontSize: tileSize * 1.3 }}>
          <div className="flex flex-col items-center"><div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-2 shadow-sm">{[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (<div key={i} className={`w-2 h-1 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />))}</div><span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">{isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}</span></div>
        </div>
      </div>

      <div className="absolute inset-0 z-50 pointer-events-none flex flex-col items-center pt-8">
        <div className="pointer-events-auto glass-panel px-6 py-3 rounded-2xl flex items-center gap-8 shadow-2xl border border-black/5 animate-in slide-in-from-top-10">
          <div className="flex items-center gap-3"><span className="text-xl">💎</span><span className="text-2xl font-black tabular-nums">{resources.gems}</span></div>
          <div className="w-px h-6 bg-black/5 dark:bg-white/5" />
          <div className="flex items-center gap-3"><span className="text-xl">🪙</span><span className="text-2xl font-black tabular-nums">{resources.coins}</span></div>
          <div className="w-px h-6 bg-black/5 dark:bg-white/5" />
          <div className="flex flex-col items-center">
            <span className="text-[8px] font-black uppercase opacity-40 tracking-widest mb-1">Gift Progress</span>
            <div className="flex gap-1">
              {[...Array(ROLLS_FOR_GIFT)].map((_, i) => (
                <div key={i} className={`w-3 h-1.5 rounded-full transition-all ${i < rollCounter ? 'bg-indigo-500 shadow-[0_0_8px_rgba(99,102,241,0.5)]' : 'bg-black/10 dark:bg-white/10'}`} />
