            <div className="glass-panel rounded-lg p-5 w-[420px] flex flex-col shadow-sm border border-black/5 bg-white/95 dark:bg-zinc-900/95">
              <div className="flex justify-between items-start mb-6">
                <div><span className="text-[10px] font-bold opacity-30 uppercase tracking-[0.2em] block mb-1">Energy Bank</span><span className="text-3xl font-normal tabular-nums">{rollBank}</span></div>
                <div className="flex gap-2">
                  <div className="flex gap-1.5 p-1 bg-black/5 rounded">{DICE_COLORS.map(c => (<button key={c} onClick={() => setDiceColor(c)} className={`w-4 h-4 rounded-full border border-black/10 transition-transform ${diceColor === c ? 'scale-125' : 'hover:scale-110'}`} style={{ background: c }} />))}</div>
                  <button onClick={() => setDarkMode(!darkMode)} className="w-8 h-8 flex items-center justify-center rounded hover:bg-black/5 transition-all text-lg">{darkMode ? '☀️' : '🌙'}</button>
