            </div>
            <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} />
            <div className="w-48 flex flex-col items-center justify-center relative h-full gap-4">
              {pumpkinBoss.isActive && (<div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center"><div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-orange-500/20 backdrop-blur-md">{[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (<div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < pumpkinBoss.health ? 'bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.4)]' : 'bg-gray-200 opacity-20'}`} />))}</div><span className="leading-none drop-shadow-xl" style={{ fontSize: '100px' }}>🎃</span></div>)}
              {demonBoss.isActive && (<div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center" style={{ animationDelay: '-1.5s' }}><div className="flex gap-1 mb-2 bg-white/90 p-1 rounded-full shadow border border-red-500/20 backdrop-blur-md">{[...Array(MAX_DEMON_HEALTH)].map((_, i) => (<div key={i} className={`w-2.5 h-1 rounded-full transition-all duration-500 ${i < demonBoss.health ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.4)]' : 'bg-gray-200 opacity-20'}`} />))}</div><span className="leading-none drop-shadow-xl" style={{ fontSize: '100px' }}>👹</span></div>)}
            </div>
          </div>
        </div>
      </div>

      {popup && (
        <div className="fixed top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-[200] glass-panel p-8 rounded-3xl text-center shadow-[0_40px_100px_rgba(0,0,0,0.3)] animate-in zoom-in-50 duration-300">
           <div className="text-6xl mb-4">🎁</div>
           <div className="text-2xl font-black mb-2">{popup.text}</div>
           <div className="text-indigo-600 font-bold">{popup.sub}</div>
        </div>
      )}

      {Array.from({ length: activeDiceCount }).map((_, i) => (
        <Dice3D key={i} color={diceColor} value={diceValues[i] || 1} isRolling={isRolling} currentPos={dicePositions[i] || { x: window.innerWidth / 2, y: window.innerHeight / 2 }} onRoll={handleRoll} onDragEnd={(f) => setDicePositions(p => { const n = [...p]; n[i] = f; return n; })} scale={currentDiceScale} />
      ))}
      <style>{`
        @keyframes bounce-slow { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-12px); } }
        .animate-bounce-slow { animation: bounce-slow 3s ease-in-out infinite; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.06); background: rgba(255,255,255,0.95); border-radius: 4px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.03); background: rgba(18,18,18,0.95); }
        .glass-panel { backdrop-filter: blur(40px); }
        @keyframes color-chaos { 0% { background-color: #ff0000; } 25% { background-color: #00ff00; } 50% { background-color: #0000ff; } 75% { background-color: #ffff00; } 100% { background-color: #ff00ff; } }
        .animate-color-chaos { animation: color-chaos 5s infinite linear; }
        .confetti-effect { background-image: radial-gradient(circle, #ff0 10%, transparent 10.5%), radial-gradient(circle, #f00 10%, transparent 10.5%); background-size: 10px 10px; animation: confetti-fall 2s infinite linear; opacity: 0.6; }
        @keyframes confetti-fall { 0% { background-position: 0 0; } 100% { background-position: 100px 500px; } }
      `}</style>
    </div>
  );
};

const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10';
        default: return 'bg-blue-50 text-blue-600 border-blue-100';
    }
}

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss, Gift, Resources } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 
const ROLLS_FOR_GIFT = 7;

// Wide Layout: Increased width significantly to surround center UI panels
const BOARD_W = 30; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 
const SPAWN_BEHIND_OFFSET = 5;

// Tile Counts
const ZOMBIE_INDICATOR_COUNT = 10; 
const BOMB_COUNT = 10;           
const PUMPKIN_COUNT = 5; 
const DEMON_COUNT = 5; 
const CLOVER_COUNT = 6; 
const GHOST_COUNT = 4; 
const RAINBOW_COUNT = 4; 
const CLOWN_COUNT = 2; 

// HP Settings
const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🦌', '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤', '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.3)', 'rgba(199, 210, 254, 0.5)', 'rgba(254, 202, 202, 0.5)', 'rgba(167, 243, 208, 0.5)', 'rgba(253, 230, 138, 0.5)', 
];

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  const [resources, setResources] = useState<Resources>({ gems: 0, coins: 0 });
  const [rollCounter, setRollCounter] = useState(0);
  const [activeGifts, setActiveGifts] = useState<Gift[]>([]);
  const [popup, setPopup] = useState<{ text: string; sub: string } | null>(null);

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<(Task & { completedAt: string })[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([{ x: window.innerWidth / 2, y: window.innerHeight / 2 }]);

  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  const [now, setNow] = useState(Date.now());

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  useEffect(() => {
    const timer = setInterval(() => {
      setNow(Date.now());
      setActiveGifts(prev => prev.filter(g => g.expiry > Date.now()));
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const [tileSize, setTileSize] = useState(50);

  useEffect(() => {
    const updateSize = () => {
      // Adjusted padding to allow full horizontal spread
      const hPadding = 40;
      const vPadding = 220; 
      const horizontalLimit = (window.innerWidth - hPadding) / BOARD_W;
      const verticalLimit = (window.innerHeight - vPadding) / BOARD_H;
      // Slightly smaller max tile size to fit more on screen
      setTileSize(Math.max(28, Math.min(horizontalLimit, verticalLimit, 52)));
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = (BOARD_W - 1) * tileSize;
    const totalH = (BOARD_H - 1) * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    //startY is higher to give space for the resource bar, but not so high it cuts off the top gifts
    const startY = (window.innerHeight - totalH) / 2 + 30; 

    // Perimeter Loop Logic
    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, x: startX + i * tileSize, y: startY, type: 'normal' });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize, type: 'normal' });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize, type: 'normal' });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, x: startX, y: startY + i * tileSize, type: 'normal' });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    const gInd = getRandomUnique(GHOST_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd]);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd, ...rInd]);
    setZombieIndicators(zInd); setBombIndices(bInd); setPumpkinIndices(pInd); setDemonIndices(dInd); setCloverIndices(cInd); setGhostIndices(gInd); setRainbowIndices(rInd); setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    setBlooms(prev => ({ ...prev, [pos]: FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)] }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => { const n = { ...prev }; delete n[pos]; return n; }), 800);
  };

  const spawnGifts = useCallback(() => {
    const t = Date.now();
    const g1: Gift = { id: 'g1', type: 1, pos: (currentPos + 20) % TOTAL_TILES, size: 1, expiry: t + 2 * 3600 * 1000, rewards: { gems: 1, coins: 10 } };
    const g2: Gift = { id: 'g2', type: 2, pos: (currentPos + 30) % TOTAL_TILES, size: 2, expiry: t + 3 * 3600 * 1000, rewards: { gems: 3, coins: 20 } };
    const g3: Gift = { id: 'g3', type: 3, pos: (currentPos + 50) % TOTAL_TILES, size: 3, expiry: t + 24 * 3600 * 1000, rewards: { gems: 5, coins: 30 } };
    setActiveGifts([g1, g2, g3]);
  }, [currentPos]);

  const collectGift = (gift: Gift) => {
    setActiveGifts(prev => prev.filter(g => g.id !== gift.id));
    setResources(r => ({ gems: r.gems + gift.rewards.gems, coins: r.coins + gift.rewards.coins }));
    setPopup({ text: `Hộp quà ${gift.type} !`, sub: `Nhận ${gift.rewards.gems}💎 & ${gift.rewards.coins}🪙` });
    setTimeout(() => setPopup(null), 2500);
  };

  const relocateItem = useCallback((list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...clownIndices];
    const [newPos] = getRandomUnique(1, exclude);
    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  }, [currentPos, bombIndices, zombieIndicators, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, getRandomUnique]);

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) setPumpkinBoss(p => ({ ...p, health: Math.max(0, p.health - 1), isActive: p.health > 1 }));
    if (demonBoss.isActive) setDemonBoss(d => ({ ...d, health: Math.max(0, d.health - 1), isActive: d.health > 1 }));
    setActiveZombies(prev => {
      if (prev.length === 0) return prev;
      let minIdx = -1, minD = Infinity;
      prev.forEach((z, i) => { const d = Math.min(Math.abs(damagePos - z.pos), TOTAL_TILES - Math.abs(damagePos - z.pos)); if(d < minD){ minD = d; minIdx = i; }});
      if(minIdx === -1) return prev;
      const next = [...prev]; next[minIdx] = { ...next[minIdx], health: next[minIdx].health - 1 };
      return next.filter(z => z.health > 0);
    });
    setIsShaking(true); setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
  }, [pumpkinBoss, demonBoss, activeZombies]);

  const handleGameOver = () => {
    setIsShaking(true); setJarCount(0); setCurrentPos(0); setActiveZombies([]); setPumpkinBoss({ isActive: false, health: 0 }); setDemonBoss({ isActive: false, health: 0 }); setIsGrayscale(false); setIsClownMode(false);
    setTimeout(() => setIsShaking(false), 500);
  };

  const processMovement = useCallback((diceSum: number) => {
    let steps = 0, temp = currentPos;
    if (diceSum === 1) applyBombDamage(temp);
    const interval = setInterval(() => {
      temp = (temp + 1) % TOTAL_TILES;
      setCurrentPos(temp); triggerBloom(temp); steps++;

      activeGifts.forEach(g => {
        for(let i=0; i<g.size; i++) {
          if((g.pos + i) % TOTAL_TILES === temp) { collectGift(g); break; }
        }
      });

      if (temp === 0) { setIsGrayscale(false); setIsClownMode(false); }
      if (cloverIndices.includes(temp)) { setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1)); relocateItem(cloverIndices, temp, 'clover'); }
      if (bombIndices.includes(temp)) { applyBombDamage(temp); relocateItem(bombIndices, temp, 'bomb'); }

      if (steps >= diceSum) {
        clearInterval(interval); setIsMoving(false);
        if (ghostIndices.includes(temp)) { setIsGrayscale(true); setIsClownMode(false); relocateItem(ghostIndices, temp, 'ghost'); }
        if (rainbowIndices.includes(temp)) { setIsGrayscale(false); setIsClownMode(false); relocateItem(rainbowIndices, temp, 'rainbow'); }
        if (clownIndices.includes(temp)) { setIsClownMode(true); setIsGrayscale(false); relocateItem(clownIndices, temp, 'clown'); }
        if (zombieIndicators.includes(temp)) {
          setActiveZombies(p => [...p, { id: Math.random().toString(36).substr(2, 9), pos: (temp - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES, health: MAX_ZOMBIE_HEALTH, isActive: true }]);
          relocateItem(zombieIndicators, temp, 'zombie');
        }
        if (pumpkinIndices.includes(temp)) { setPumpkinBoss({ isActive: true, health: MAX_PUMPKIN_HEALTH }); relocateItem(pumpkinIndices, temp, 'pumpkin'); }
        if (demonIndices.includes(temp)) { setDemonBoss({ isActive: true, health: MAX_DEMON_HEALTH }); relocateItem(demonIndices, temp, 'demon'); }
        setActiveZombies(prev => {
          let hit = false; const move = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => { const n = (z.pos + move) % TOTAL_TILES; if (n === temp) hit = true; return { ...z, pos: n }; });
          if (hit) { setPlayerHealth(h => { const n = h - 1; if (n <= 0) { handleGameOver(); return MAX_PLAYER_HEALTH; } return n; }); return []; }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, activeGifts, cloverIndices, bombIndices, ghostIndices, rainbowIndices, clownIndices, zombieIndicators, pumpkinIndices, demonIndices, demonBoss.isActive, applyBombDamage, relocateItem]);

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    if (pumpkinBoss.isActive) { setIsDeducting(true); setJarCount(p => Math.max(0, p - 5)); setTimeout(() => setIsDeducting(false), 800); }

    if (activeGifts.length === 0) {
      setRollCounter(prev => {
        const next = prev + 1;
        if (next >= ROLLS_FOR_GIFT) { spawnGifts(); return 0; }
        return next;
      });
    }

    setIsRolling(true); setRollBank(r => r - 1);
    const count = isGrayscale ? 3 : 1;
    const vals = Array.from({ length: count }, () => Math.floor(Math.random() * 6) + 1);
    setDicePositions(Array.from({ length: count }, (_, i) => ({ x: landing.x + (i - Math.floor(count/2)) * (isClownMode ? 150 : 80), y: landing.y })));
    setTimeout(() => { setIsRolling(false); setDiceValues(vals); setIsMoving(true); processMovement(vals.reduce((a, b) => a + b, 0)); }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setTasks(prev => prev.filter(t => t.id !== task.id));
    setHistory(prev => [{ ...task, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setRollBank(r => r + (task.priority === 'high' ? 15 : task.priority === 'medium' ? 10 : 5));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setTimeout(() => {
      setIsExploding(false);
      setJarCount(0);
      setRollBank(r => r + 50);
