  };

  const formatTime = (ms: number) => {
    const s = Math.max(0, Math.floor(ms / 1000));
    const h = Math.floor(s / 3600), m = Math.floor((s % 3600) / 60), sc = s % 60;
    return `${h}h ${m}m ${sc}s`;
  };

  const activeDiceCount = diceValues.length;
  const currentDiceScale = isGrayscale ? 0.8 : (isClownMode ? 1.4 : 1);

  return (
    <div className={`h-screen w-screen relative transition-all duration-700 overflow-hidden notion-grid ${isExploding ? 'bg-indigo-600/10' : ''} ${isGrayscale ? 'filter grayscale' : ''} ${isClownMode ? 'clown-bg animate-color-chaos' : ''}`}>
