import React, { useState, useRef, useEffect } from 'react';

interface AlchemyJarProps {
  count: number;
  max: number;
  isExploding: boolean;
  onExplode: () => void;
  isDeducting?: boolean;
  themeColor?: string;
}

export const AlchemyJar: React.FC<AlchemyJarProps> = ({ 
  count, 
  max, 
  isExploding, 
  onExplode, 
  isDeducting,
  themeColor = '#6366f1'
}) => {
  const percent = Math.min(100, (count / max) * 100);
  const isFull = count >= max;
  const [holdProgress, setHoldProgress] = useState(0);
  const holdInterval = useRef<number | null>(null);

  const startHold = () => {
    if (!isFull || isExploding) return;
    holdInterval.current = window.setInterval(() => {
      setHoldProgress(prev => {
        if (prev >= 100) {
          if (holdInterval.current) clearInterval(holdInterval.current);
          onExplode();
          return 0;
        }
        return prev + 1;
      });
    }, 30);
  };

  const endHold = () => {
    if (holdInterval.current) {
      clearInterval(holdInterval.current);
      holdInterval.current = null;
    }
    setHoldProgress(0);
  };

  return (
    <div className="flex flex-col gap-3 h-[252px] w-[68px]">
      <div className={`relative flex-grow bg-gray-50/50 dark:bg-black/20 border-4 border-gray-100 dark:border-white/5 rounded-b-[24px] rounded-t-[8px] overflow-hidden backdrop-blur-xl transition-all duration-700 ${isExploding ? 'scale-150 blur-3xl opacity-0' : 'scale-100'} ${isDeducting ? 'border-red-500/30' : ''}`}>
        <div 
          className={`absolute bottom-0 left-0 w-full transition-all duration-1000 ease-out`}
          style={{ 
            height: `${percent}%`,
            backgroundColor: isDeducting ? '#ef4444' : themeColor,
            opacity: 0.8
          }}
        >
          <div className="absolute inset-0 overflow-hidden">
             {[...Array(4)].map((_, i) => (
               <div 
                 key={i} 
                 className="absolute bottom-0 bg-white/20 rounded-full animate-bubble"
                 style={{
                   width: Math.random() * 6 + 2,
                   height: Math.random() * 6 + 2,
                   left: `${Math.random() * 100}%`,
                   animationDuration: `${Math.random() * 1.5 + 0.8}s`,
                   animationDelay: `${Math.random() * 2}s`
                 }}
               />
             ))}
          </div>
        </div>
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
          <span className={`text-[12px] font-black transition-colors ${isDeducting ? 'text-red-600' : 'text-indigo-900/40 dark:text-white/40'}`}>
            {isDeducting ? '-5%' : `${Math.floor(percent)}%`}
          </span>
        </div>
      </div>

      <div className="w-full relative h-10 flex flex-col justify-end">
        {holdProgress > 0 && (
          <div className="absolute top-0 left-0 w-full h-0.5 bg-gray-100 dark:bg-white/5 rounded-full overflow-hidden">
             <div className="h-full bg-indigo-500" style={{ width: `${holdProgress}%` }} />
          </div>
        )}
        <button
          onMouseDown={startHold}
          onMouseUp={endHold}
          onMouseLeave={endHold}
          onTouchStart={startHold}
          onTouchEnd={endHold}
          disabled={!isFull || isExploding}
          style={{ backgroundColor: isFull ? themeColor : undefined }}
          className={`w-full h-8 rounded-lg text-[7px] font-black uppercase tracking-[0.1em] transition-all
            ${isFull 
              ? 'text-white shadow-lg cursor-pointer hover:brightness-110 active:scale-95' 
              : 'bg-black/5 dark:bg-white/5 text-gray-400 cursor-not-allowed'
            }`}
        >
          {isFull ? (holdProgress > 0 ? 'Wait' : 'Collect') : 'Empty'}
        </button>
      </div>

      <style>{`
        @keyframes bubble {
          0% { transform: translateY(0) scale(0.5); opacity: 0; }
          50% { opacity: 0.5; }
          100% { transform: translateY(-60px) scale(1.5); opacity: 0; }
        }
        .animate-bubble { animation: bubble linear infinite; }
      `}</style>
    </div>
  );
};

