import React, { useState, useRef, useEffect } from 'react';

interface AlchemyJarProps {
  count: number;
  max: number;
  isExploding: boolean;
  onExplode: () => void;
  isDeducting?: boolean;
  themeColor?: string;
  customHeight?: number;
}

export const AlchemyJar: React.FC<AlchemyJarProps> = ({ 
  count, 
  max, 
  isExploding, 
  onExplode, 
  isDeducting,
  themeColor = '#6366f1',
  customHeight = 252
}) => {
  const percent = Math.min(100, (count / max) * 100);
  const isFull = count >= max;
  const [holdProgress, setHoldProgress] = useState(0);
  const holdInterval = useRef<number | null>(null);

  const startHold = () => {
    if (!isFull || isExploding) return;
    holdInterval.current = window.setInterval(() => {
      setHoldProgress(prev => {
        if (prev >= 100) {
          if (holdInterval.current) clearInterval(holdInterval.current);
          onExplode();
          return 0;
        }
        return prev + 1;
      });
    }, 30);
  };

  const endHold = () => {
    if (holdInterval.current) {
      clearInterval(holdInterval.current);
      holdInterval.current = null;
    }
    setHoldProgress(0);
  };

  return (
    <div 
      className="relative w-[68px] flex flex-col group transition-all"
      style={{ height: customHeight }}
    >
      <div 
        onMouseDown={startHold}
        onMouseUp={endHold}
        onMouseLeave={endHold}
        onTouchStart={startHold}
        onTouchEnd={endHold}
        className={`relative flex-grow bg-gray-50/30 dark:bg-black/10 border-4 border-gray-100/50 dark:border-white/5 rounded-b-[24px] rounded-t-[12px] overflow-hidden backdrop-blur-xl transition-all duration-700 
          ${isExploding ? 'scale-150 blur-3xl opacity-0' : 'scale-100'} 
          ${isDeducting ? 'border-red-500/30' : ''}
          ${isFull && !isExploding ? 'cursor-pointer hover:border-white/20 active:scale-95' : 'cursor-default'}
        `}
      >
        {/* Hold Progress Overlay */}
        {holdProgress > 0 && (
          <div 
            className="absolute inset-0 z-20 bg-indigo-500/10 pointer-events-none"
            style={{ 
                clipPath: `inset(${100 - holdProgress}% 0 0 0)`
            }}
          />
        )}

        {/* Liquid Liquid Content */}
        <div 
          className={`absolute bottom-0 left-0 w-full transition-all duration-1000 ease-out z-10`}
          style={{ 
            height: `${percent}%`,
            backgroundColor: isDeducting ? '#ef4444' : themeColor,
            opacity: isFull ? 0.9 : 0.6
          }}
        >
          <div className="absolute inset-0 overflow-hidden">
             {[...Array(6)].map((_, i) => (
               <div 
                 key={i} 
                 className="absolute bottom-0 bg-white/30 rounded-full animate-bubble"
                 style={{
                   width: Math.random() * 8 + 2,
                   height: Math.random() * 8 + 2,
                   left: `${Math.random() * 100}%`,
                   animationDuration: `${Math.random() * 1.5 + 0.8}s`,
                   animationDelay: `${Math.random() * 2}s`
                 }}
               />
             ))}
          </div>
        </div>

        {/* Labels */}
        <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none z-30">
          <span className={`text-[11px] font-black tracking-tighter transition-colors ${isDeducting ? 'text-red-600' : 'text-indigo-900/40 dark:text-white/30'}`}>
            {isDeducting ? '-5%' : isFull ? (holdProgress > 0 ? 'READY' : 'FULL') : `${Math.floor(percent)}%`}
          </span>
          {isFull && !holdProgress && (
            <span className="text-[6px] font-black opacity-30 mt-1 uppercase tracking-widest">Hold</span>
          )}
        </div>
      </div>

      <style>{`
        @keyframes bubble {
          0% { transform: translateY(0) scale(0.5); opacity: 0; }
          50% { opacity: 0.5; }
          100% { transform: translateY(-100px) scale(1.5); opacity: 0; }
        }
        .animate-bubble { animation: bubble linear infinite; }
      `}</style>
    </div>
  );
};

