  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([{ x: window.innerWidth / 2, y: window.innerHeight / 2 }]);

  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  const [now, setNow] = useState(Date.now());

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  useEffect(() => {
    const timer = setInterval(() => {
      setNow(Date.now());
      setActiveGifts(prev => prev.filter(g => g.expiry > Date.now()));
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const [tileSize, setTileSize] = useState(80);

  useEffect(() => {
    const updateSize = () => {
      const totalHUnits = BOARD_W + (H_MARGIN_UNITS * 2);
      const totalVUnits = BOARD_H + (V_MARGIN_UNITS * 2);
      const horizontalLimit = window.innerWidth / totalHUnits;
      const verticalLimit = window.innerHeight / totalVUnits;
      setTileSize(Math.max(30, Math.min(horizontalLimit, verticalLimit)));
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = (BOARD_W - 1) * tileSize;
    const totalH = (BOARD_H - 1) * tileSize;
    const startX = (window.innerWidth - totalW) / 2;
    const startY = (window.innerHeight - totalH) / 2; 

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, x: startX + i * tileSize, y: startY, type: 'normal' });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize, type: 'normal' });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize, type: 'normal' });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, x: startX, y: startY + i * tileSize, type: 'normal' });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    const gInd = getRandomUnique(GHOST_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd]);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd, ...rInd]);
    setZombieIndicators(zInd); setBombIndices(bInd); setPumpkinIndices(pInd); setDemonIndices(dInd); setCloverIndices(cInd); setGhostIndices(gInd); setRainbowIndices(rInd); setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    setBlooms(prev => ({ ...prev, [pos]: FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)] }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => { const n = { ...prev }; delete n[pos]; return n; }), 800);
  };

  const spawnGifts = useCallback(() => {
    const t = Date.now();
    const g1: Gift = { id: 'g1', type: 1, pos: (currentPos + 4) % TOTAL_TILES, size: 1, expiry: t + 2 * 3600 * 1000, rewards: { gems: 1, coins: 10 } };
    const g2: Gift = { id: 'g2', type: 2, pos: (currentPos + 8) % TOTAL_TILES, size: 2, expiry: t + 3 * 3600 * 1000, rewards: { gems: 3, coins: 20 } };
    const g3: Gift = { id: 'g3', type: 3, pos: (currentPos + 12) % TOTAL_TILES, size: 3, expiry: t + 24 * 3600 * 1000, rewards: { gems: 5, coins: 30 } };
    setActiveGifts([g1, g2, g3]);
  }, [currentPos]);

  const collectGift = (gift: Gift) => {
    setActiveGifts(prev => prev.filter(g => g.id !== gift.id));
    setResources(r => ({ gems: r.gems + gift.rewards.gems, coins: r.coins + gift.rewards.coins }));
    setPopup({ text: `Hộp quà ${gift.type} !`, sub: `Nhận ${gift.rewards.gems}💎 & ${gift.rewards.coins}🪙` });
    setTimeout(() => setPopup(null), 2500);
  };

  const relocateItem = useCallback((list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...clownIndices];
    const [newPos] = getRandomUnique(1, exclude);
    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  }, [currentPos, bombIndices, zombieIndicators, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, getRandomUnique]);

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) setPumpkinBoss(p => ({ ...p, health: Math.max(0, p.health - 1), isActive: p.health > 1 }));
    if (demonBoss.isActive) setDemonBoss(d => ({ ...d, health: Math.max(0, d.health - 1), isActive: d.health > 1 }));
    setActiveZombies(prev => {
      if (prev.length === 0) return prev;
      let minIdx = -1, minD = Infinity;
      prev.forEach((z, i) => { const d = Math.min(Math.abs(damagePos - z.pos), TOTAL_TILES - Math.abs(damagePos - z.pos)); if(d < minD){ minD = d; minIdx = i; }});
      if(minIdx === -1) return prev;
      const next = [...prev]; next[minIdx] = { ...next[minIdx], health: next[minIdx].health - 1 };
      return next.filter(z => z.health > 0);
    });
    setIsShaking(true); setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
  }, [pumpkinBoss, demonBoss, activeZombies]);

  const handleGameOver = () => {
    setIsShaking(true); setJarCount(0); setCurrentPos(0); setActiveZombies([]); setPumpkinBoss({ isActive: false, health: 0 }); setDemonBoss({ isActive: false, health: 0 }); setIsGrayscale(false); setIsClownMode(false);
    setTimeout(() => setIsShaking(false), 500);
  };

  const processMovement = useCallback((diceSum: number) => {
    let steps = 0, temp = currentPos;
    if (diceSum === 1) applyBombDamage(temp);
    const interval = setInterval(() => {
      temp = (temp + 1) % TOTAL_TILES;
      setCurrentPos(temp); triggerBloom(temp); steps++;

      activeGifts.forEach(g => {
        for(let i=0; i<g.size; i++) {
          if((g.pos + i) % TOTAL_TILES === temp) { collectGift(g); break; }
        }
      });

      if (temp === 0) { setIsGrayscale(false); setIsClownMode(false); }
      if (cloverIndices.includes(temp)) { setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1)); relocateItem(cloverIndices, temp, 'clover'); }
      if (bombIndices.includes(temp)) { applyBombDamage(temp); relocateItem(bombIndices, temp, 'bomb'); }

      if (steps >= diceSum) {
        clearInterval(interval); setIsMoving(false);
        if (ghostIndices.includes(temp)) { setIsGrayscale(true); setIsClownMode(false); relocateItem(ghostIndices, temp, 'ghost'); }
        if (rainbowIndices.includes(temp)) { setIsGrayscale(false); setIsClownMode(false); relocateItem(rainbowIndices, temp, 'rainbow'); }
        if (clownIndices.includes(temp)) { setIsClownMode(true); setIsGrayscale(false); relocateItem(clownIndices, temp, 'clown'); }
        if (zombieIndicators.includes(temp)) {
          setActiveZombies(p => [...p, { id: Math.random().toString(36).substr(2, 9), pos: (temp - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES, health: MAX_ZOMBIE_HEALTH, isActive: true }]);
          relocateItem(zombieIndicators, temp, 'zombie');
        }
        if (pumpkinIndices.includes(temp)) { setPumpkinBoss({ isActive: true, health: MAX_PUMPKIN_HEALTH }); relocateItem(pumpkinIndices, temp, 'pumpkin'); }
        if (demonIndices.includes(temp)) { setDemonBoss({ isActive: true, health: MAX_DEMON_HEALTH }); relocateItem(demonIndices, temp, 'demon'); }
        setActiveZombies(prev => {
          let hit = false; const move = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => { const n = (z.pos + move) % TOTAL_TILES; if (n === temp) hit = true; return { ...z, pos: n }; });
          if (hit) { setPlayerHealth(h => { const n = h - 1; if (n <= 0) { handleGameOver(); return MAX_PLAYER_HEALTH; } return n; }); return []; }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, activeGifts, cloverIndices, bombIndices, ghostIndices, rainbowIndices, clownIndices, zombieIndicators, pumpkinIndices, demonIndices, demonBoss.isActive, applyBombDamage, relocateItem]);

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    if (pumpkinBoss.isActive) { setIsDeducting(true); setJarCount(p => Math.max(0, p - 5)); setTimeout(() => setIsDeducting(false), 800); }

    if (activeGifts.length === 0) {
      setRollCounter(prev => {
        const next = prev + 1;
        if (next >= ROLLS_FOR_GIFT) { spawnGifts(); return 0; }
        return next;
      });
    }

    setIsRolling(true); setRollBank(r => r - 1);
    const count = isGrayscale ? 3 : 1;
    const vals = Array.from({ length: count }, () => Math.floor(Math.random() * 6) + 1);
    setDicePositions(Array.from({ length: count }, (_, i) => ({ x: landing.x + (i - Math.floor(count/2)) * (isClownMode ? 100 : 60), y: landing.y })));
    setTimeout(() => { setIsRolling(false); setDiceValues(vals); setIsMoving(true); processMovement(vals.reduce((a, b) => a + b, 0)); }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setTasks(prev => prev.filter(t => t.id !== task.id));
    setHistory(prev => [{ ...task, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setRollBank(r => r + (task.priority === 'high' ? 15 : task.priority === 'medium' ? 10 : 5));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setTimeout(() => {
      setIsExploding(false);
      setJarCount(0);
      setRollBank(r => r + 50);
      setPopup({ text: "ALCHEMY EXPLOSION!", sub: "+50 Energy Received" });
      setTimeout(() => setPopup(null), 2500);
    }, 1000);
  };

  const formatTime = (ms: number) => {
    const s = Math.max(0, Math.floor(ms / 1000));
    const h = Math.floor(s / 3600), m = Math.floor((s % 3600) / 60), sc = s % 60;
    return `${h}h ${m}m ${sc}s`;
  };

  const hexToRgba = (hex: string, alpha: number) => {
    const r = parseInt(hex.slice(1, 3), 16);
    const g = parseInt(hex.slice(3, 5), 16);
    const b = parseInt(hex.slice(5, 7), 16);
    return `rgba(${r}, ${g}, ${b}, ${alpha})`;
  };

  const activeDiceCount = diceValues.length;
  const currentDiceScale = isGrayscale ? 0.7 : (isClownMode ? 1.2 : 0.9);
  // Mixed themeColor with more transparency (~0.1) for an ethereal glass feel
  const currentDiceColor = hexToRgba(themeColor, 0.08);

  // Layout calculations for the "1 tile margin" panel
  const totalW = (BOARD_W - 1) * tileSize;
  const totalH = (BOARD_H - 1) * tileSize;
  const startX = (window.innerWidth - totalW) / 2;
  const startY = (window.innerHeight - totalH) / 2;

  const PANEL_WIDTH = 280;
  const PANEL_HEIGHT = totalH - tileSize * 3;
  const PANEL_LEFT = startX + tileSize * 2;
  const PANEL_TOP = startY + tileSize * 2;
  const JAR_LEFT = PANEL_LEFT + PANEL_WIDTH + tileSize;
  const BOSS_LEFT = JAR_LEFT + 70 + tileSize * 3;

  return (
    <div className={`h-screen w-screen relative transition-all duration-700 overflow-hidden notion-grid ${isExploding ? 'bg-indigo-600/10' : ''} ${isGrayscale ? 'filter grayscale' : ''} ${isClownMode ? 'clown-bg animate-color-chaos' : ''}`}>
      {isClownMode && isRolling && <div className="absolute inset-0 z-[100] pointer-events-none confetti-effect" />}

      <div className="absolute inset-0 z-0 pointer-events-none">
        {boardSpaces.map(s => {
          const isB = bombIndices.includes(s.id), isZ = zombieIndicators.includes(s.id), isP = pumpkinIndices.includes(s.id), isD = demonIndices.includes(s.id), isC = cloverIndices.includes(s.id), isG = ghostIndices.includes(s.id), isR = rainbowIndices.includes(s.id), isCl = clownIndices.includes(s.id), isSt = s.id === 0;
          let icon = null; if (isB) icon = darkMode ? '🧄' : '💣'; else if (isZ) icon = darkMode ? '🧛🏻' : '🧟'; else if (isP) icon = '🎃'; else if (isD) icon = '👹'; else if (isC) icon = '🍀'; else if (isG) icon = '👻'; else if (isR) icon = '🌈'; else if (isCl) icon = '🤡';
          return (
            <div key={s.id} className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 shadow-sm ${isSt ? 'bg-indigo-50/70 dark:bg-indigo-950/40 border-indigo-500/20' : ''}`} style={{ left: s.x, top: s.y, width: tileSize, height: tileSize }}>
              <span className="text-[10px] opacity-10 absolute top-1 left-1 font-black">{s.id + 1}</span>
              {icon && <span className="drop-shadow-sm opacity-30 select-none" style={{ fontSize: tileSize * 0.55 }}>{icon}</span>}
              {blooms[s.id] && <span className="bloom absolute opacity-40" style={{ fontSize: tileSize * 0.55 }}>{blooms[s.id]}</span>}
              {isSt && !blooms[s.id] && !icon && <span className="text-[9px] font-black opacity-40 uppercase tracking-[0.1em] -rotate-12">Start</span>}
            </div>
          );
        })}

        {activeZombies.map(z => boardSpaces[z.pos] && (
          <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ left: boardSpaces[z.pos].x + tileSize/2, top: boardSpaces[z.pos].y + tileSize/2, transform: `translate(-50%, -60%) scale(${demonBoss.isActive ? 1.6 : 1.1})` }}>
            <div className="flex flex-col items-center">
              <div className="flex gap-0.5 mb-1 bg-white/10 p-0.5 rounded-full px-1 shadow-sm backdrop-blur-sm overflow-hidden">
                {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                  <div key={i} className={`w-2 h-0.5 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-white/10'}`} />
                ))}
              </div>
              <span className="drop-shadow-2xl animate-pulse" style={{ fontSize: tileSize * 1.2 }}>{darkMode ? '🧛🏻' : '🧟'}</span>
            </div>
          </div>
        ))}

        <div onClick={() => {
          const nextIdx = (animalIndex + 1) % ANIMAL_EMOJIS.length;
          setAnimalIndex(nextIdx);
          setThemeColor(THEME_COLORS[nextIdx % THEME_COLORS.length]);
        }} className="absolute z-30 transition-all duration-500 cursor-pointer pointer-events-auto" style={{ left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, transform: 'translate(-50%, -65%)', fontSize: tileSize * 1.4 }}>
          <div className="flex flex-col items-center">
            <div className="flex gap-0.5 mb-1.5 p-0.5 rounded-full bg-black/5 dark:bg-white/5 backdrop-blur-sm">
              {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (
                <div key={i} className={`w-3 h-0.5 rounded-full transition-colors ${i < playerHealth ? 'bg-green-500' : 'bg-black/10 dark:bg-white/10'}`} />
              ))}
            </div>
            <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">{isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}</span>
          </div>
        </div>
      </div>

      <div className="absolute inset-0 z-10 pointer-events-none">
        {activeGifts.map(g => {
          const space = boardSpaces[g.pos];
          if (!space) return null;
          const remaining = g.expiry - now;
          return (
            <div key={g.id} className="absolute z-40 flex flex-col items-center justify-end" style={{ left: space.x + (tileSize * g.size) / 2, top: space.y + tileSize / 2, transform: 'translate(-50%, -60%)', height: tileSize * 3.5 }}>
              <div className="px-2 py-0.5 rounded-full mb-2 bg-white/20 dark:bg-black/20 backdrop-blur-md">
                <div className="text-[7px] font-black uppercase text-center opacity-60 tabular-nums tracking-wider">{formatTime(remaining)}</div>
              </div>
              <span className="drop-shadow-2xl leading-none animate-bounce-slow" style={{ fontSize: tileSize * (g.type === 3 ? 2.2 : g.type === 2 ? 1.7 : 1.1) }}>🎁</span>
            </div>
          );
        })}
      </div>

      {/* Main UI Overlay */}
      <div className="absolute inset-0 z-50 pointer-events-none">

        {/* Task Panel */}
        <div 
          className="absolute glass-panel rounded-[12px] p-4 flex flex-col pointer-events-auto transition-all"
          style={{
            left: PANEL_LEFT, 
            top: PANEL_TOP,
            height: PANEL_HEIGHT,
            width: PANEL_WIDTH
          }}
        >
          {/* Resource header with Dark Mode Integrated */}
          <div className="flex items-center justify-between mb-3 bg-black/[0.03] dark:bg-white/[0.03] p-2 rounded-[8px] border border-black/5 backdrop-blur-md">
              <div className="flex items-center gap-1.5">
                  <span className="text-[11px]">💎</span>
                  <span className="text-[12px] font-black tabular-nums">{resources.gems}</span>
              </div>
              <div className="w-px h-4 bg-black/10 dark:bg-white/10" />
              <div className="flex items-center gap-1.5">
                  <span className="text-[11px]">🪙</span>
                  <span className="text-[12px] font-black tabular-nums">{resources.coins}</span>
              </div>
              <button onClick={() => setDarkMode(!darkMode)} className="ml-1 w-6 h-6 flex items-center justify-center rounded-md bg-white dark:bg-zinc-800 text-[10px] active:scale-95 transition-transform">
                {darkMode ? '☀️' : '🌙'}
              </button>
          </div>

          <div className="flex justify-between items-center mb-3 px-1">
            <div>
              <span className="text-[6px] font-black opacity-30 uppercase tracking-[0.1em] block">Energy</span>
              <span className="text-[16px] font-bold tabular-nums tracking-tight">{rollBank}</span>
            </div>
            <div className="flex flex-col items-end">
              <span className="text-[6px] font-black uppercase opacity-40 tracking-widest mb-0.5">Radar</span>
              <div className="flex gap-0.5">
                  {[...Array(ROLLS_FOR_GIFT)].map((_, i) => (
                      <div key={i} className={`h-0.5 rounded-full transition-all duration-700 ease-out ${i < rollCounter ? 'w-2 bg-indigo-500' : 'w-1 bg-black/10 dark:bg-white/10'}`} />
                  ))}
              </div>
            </div>
          </div>

          <div className="flex-grow overflow-y-auto pr-1 custom-scrollbar space-y-0.5">
            {!showHistory ? tasks.map(t => (
              <div key={t.id} onClick={() => handleTaskComplete(t)} className="group p-1.5 hover:bg-black/[0.02] dark:hover:bg-white/[0.02] rounded-md transition-all flex items-center gap-2 cursor-pointer border border-transparent">
                <div className="shrink-0 w-2 h-2 rounded-sm border-[1px] border-black/20 dark:border-white/20 group-hover:bg-indigo-500 group-hover:border-indigo-500" />
                <div className="flex-grow overflow-hidden">
                  <div className="text-[10px] font-bold truncate opacity-80 leading-tight">{t.text}</div>
                  {t.priority && <div className={`inline-block text-[5px] font-black uppercase px-1 py-0.5 rounded mt-0.5 border ${getPriorityColor(t.priority)}`}>{t.priority}</div>}
                </div>
              </div>
            )) : history.map(h => (
              <div key={h.id} className="p-1.5 border-l border-indigo-500/20 opacity-40 bg-black/[0.01] rounded-r-md mb-0.5">
                <span className="text-[9px] line-through block font-bold truncate">{h.text}</span>
                <span className="text-[7px] uppercase font-black text-indigo-500">{h.completedAt}</span>
              </div>
            ))}
          </div>

          <div className="mt-2 pt-2 border-t border-black/5 dark:border-white/5 flex gap-1.5">
            <button onClick={() => setShowHistory(!showHistory)} className="shrink-0 px-1.5 py-1 text-[8px] font-black uppercase border border-black/5 dark:border-white/5 rounded-md hover:bg-black/[0.05] transition-all">
              {showHistory ? 'Tasks' : 'Log'}
            </button>
            <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); setNewTask(''); }} className="flex-1">
              <input value={newTask} onChange={e => setNewTask(e.target.value)} className="w-full h-7 bg-black/[0.03] dark:bg-white/[0.03] rounded-md px-2 text-[10px] font-bold outline-none placeholder:opacity-20" placeholder="New..." />
            </form>
          </div>
        </div>

        {/* Jar */}
        <div 
          className="absolute pointer-events-auto"
          style={{
            left: JAR_LEFT,
            top: PANEL_TOP,
            height: PANEL_HEIGHT,
            width: 70
          }}
        >
          <AlchemyJar 
            count={jarCount} 
            max={MAX_JAR} 
            isExploding={isExploding} 
            onExplode={onJarExplode} 
            isDeducting={isDeducting} 
            themeColor={themeColor} 
            customHeight={PANEL_HEIGHT}
          />
        </div>

        {/* Bosses Group positioned 3 tiles right of the jar */}
        <div 
          className="absolute z-10 pointer-events-none flex items-center justify-center transition-all duration-700"
          style={{ 
            left: BOSS_LEFT,
            top: PANEL_TOP,
            height: PANEL_HEIGHT,
            width: 192 // Matching w-48
          }}
        >
             <div className="w-48 flex flex-col items-center justify-center relative h-full gap-6">
                {pumpkinBoss.isActive && (
                  <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center">
                    <div className="flex gap-1 mb-2 bg-black/5 dark:bg-white/5 p-0.5 rounded-full px-1.5 backdrop-blur-md">
                      {[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (
                        <div key={i} className={`w-3.5 h-0.5 rounded-full transition-all ${i < pumpkinBoss.health ? 'bg-orange-500' : 'bg-black/10 dark:bg-white/10'}`} />
                      ))}
                    </div>
                    <span className="leading-none drop-shadow-lg filter contrast-125 saturate-150" style={{ fontSize: '80px' }}>🎃</span>
                  </div>
                )}
                {demonBoss.isActive && (
                  <div className="flex flex-col items-center animate-bounce-slow flex-1 justify-center" style={{ animationDelay: '-1.8s' }}>
                    <div className="flex gap-1 mb-2 bg-black/5 dark:bg-white/5 p-0.5 rounded-full px-1.5 backdrop-blur-md">
                      {[...Array(MAX_DEMON_HEALTH)].map((_, i) => (
                        <div key={i} className={`w-3.5 h-0.5 rounded-full transition-all ${i < demonBoss.health ? 'bg-red-500' : 'bg-black/10 dark:bg-white/10'}`} />
                      ))}
                    </div>
                    <span className="leading-none drop-shadow-lg filter contrast-125 saturate-150" style={{ fontSize: '80px' }}>👹</span>
                  </div>
                )}
                {!pumpkinBoss.isActive && !demonBoss.isActive && (
                  <div className="opacity-[0.03] text-[9px] font-black uppercase tracking-[0.5em] rotate-90 whitespace-nowrap select-none">Apex Nexus</div>
                )}
             </div>
        </div>
      </div>

      {popup && (
        <div className="fixed top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-[200] glass-panel p-10 rounded-[40px] text-center shadow-[0_40px_100px_rgba(0,0,0,0.3)] animate-in zoom-in-50 duration-500 backdrop-blur-3xl border border-white/10">
           <div className="text-7xl mb-6 animate-bounce">🎁</div>
           <div className="text-3xl font-black mb-3 tracking-tighter">{popup.text}</div>
           <div className="text-indigo-500 font-black text-lg uppercase tracking-[0.2em]">{popup.sub}</div>
        </div>
      )}

      {Array.from({ length: activeDiceCount }).map((_, i) => (
        <Dice3D key={i} color={currentDiceColor} value={diceValues[i] || 1} isRolling={isRolling} currentPos={dicePositions[i] || { x: window.innerWidth / 2, y: window.innerHeight / 2 }} onRoll={handleRoll} onDragEnd={(f) => setDicePositions(p => { const n = [...p]; n[i] = f; return n; })} scale={currentDiceScale} />
      ))}

      <style>{`
        @keyframes bounce-slow { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-12px); } }
        .animate-bounce-slow { animation: bounce-slow 5s ease-in-out infinite; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.05); background: rgba(255,255,255,0.95); border-radius: 6px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.02); background: rgba(20,20,22,0.98); }
        .glass-panel { box-shadow: none; }
        .custom-scrollbar::-webkit-scrollbar { width: 2px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.05); border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.05); }
        @keyframes color-chaos { 0% { background-color: #ff0000; } 25% { background-color: #00ff00; } 50% { background-color: #0000ff; } 75% { background-color: #ffff00; } 100% { background-color: #ff00ff; } }
        .animate-color-chaos { animation: color-chaos 8s infinite linear; opacity: 0.1; }
        .confetti-effect { background-image: radial-gradient(circle, #ff0 15%, transparent 15.5%), radial-gradient(circle, #f00 15%, transparent 15.5%); background-size: 20px 20px; animation: confetti-fall 6s infinite linear; opacity: 0.2; }
        @keyframes confetti-fall { 0% { background-position: 0 0; } 100% { background-position: 200px 800px; } }
      `}</style>
    </div>
  );
};

const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-500/10 dark:text-red-400 dark:border-red-500/10';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-500/10 dark:text-orange-400 dark:border-orange-500/10';
        default: return 'bg-indigo-50 text-indigo-600 border-indigo-100 dark:bg-indigo-500/10 dark:text-indigo-400 dark:border-indigo-500/10';
    }
}

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss, Gift, Resources } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 
const ROLLS_FOR_GIFT = 7;

// Aspect Ratio 2:1 (Width:Height)
const BOARD_W = 22; 
const BOARD_H = 11; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 
const SPAWN_BEHIND_OFFSET = 3;

// Margins in tile units
const H_MARGIN_UNITS = 5;
const V_MARGIN_UNITS = 3;

const ZOMBIE_INDICATOR_COUNT = 6; 
const BOMB_COUNT = 8;           
const PUMPKIN_COUNT = 3; 
const DEMON_COUNT = 3; 
const CLOVER_COUNT = 4; 
const GHOST_COUNT = 2; 
const RAINBOW_COUNT = 2; 
const CLOWN_COUNT = 2; 

const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🦌', '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤', '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const THEME_COLORS = [
  '#6366f1', // Indigo
  '#10b981', // Emerald
  '#f43f5e', // Rose
  '#f59e0b', // Amber
  '#8b5cf6', // Violet
  '#0ea5e9', // Sky
  '#ec4899', // Pink
  '#06b6d4', // Cyan
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [themeColor, setThemeColor] = useState(THEME_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  const [resources, setResources] = useState<Resources>({ gems: 0, coins: 0 });
  const [rollCounter, setRollCounter] = useState(0);
  const [activeGifts, setActiveGifts] = useState<Gift[]>([]);
  const [popup, setPopup] = useState<{ text: string; sub: string } | null>(null);

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<(Task & { completedAt: string })[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([{ x: window.innerWidth / 2, y: window.innerHeight / 2 }]);

  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  const [now, setNow] = useState(Date.now());

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  useEffect(() => {
    const timer = setInterval(() => {
      setNow(Date.now());
      setActiveGifts(prev => prev.filter(g => g.expiry > Date.now()));
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const [tileSize, setTileSize] = useState(80);

  useEffect(() => {
    const updateSize = () => {
      const totalHUnits = BOARD_W + (H_MARGIN_UNITS * 2);
      const totalVUnits = BOARD_H + (V_MARGIN_UNITS * 2);
      const horizontalLimit = window.innerWidth / (totalHUnits * 1.25); // Account for zoom
      const verticalLimit = window.innerHeight / (totalVUnits * 1.25); // Account for zoom
      setTileSize(Math.max(30, Math.min(horizontalLimit, verticalLimit)));
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = (BOARD_W - 1) * tileSize;
    const totalH = (BOARD_H - 1) * tileSize;
    const startX = (window.innerWidth / 1.25 - totalW) / 2;
    const startY = (window.innerHeight / 1.25 - totalH) / 2; 

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, x: startX + i * tileSize, y: startY, type: 'normal' });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize, type: 'normal' });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize, type: 'normal' });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, x: startX, y: startY + i * tileSize, type: 'normal' });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    const gInd = getRandomUnique(GHOST_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd]);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd, ...rInd]);
    setZombieIndicators(zInd); setBombIndices(bInd); setPumpkinIndices(pInd); setDemonIndices(dInd); setCloverIndices(cInd); setGhostIndices(gInd); setRainbowIndices(rInd); setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    setBlooms(prev => ({ ...prev, [pos]: FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)] }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => { const n = { ...prev }; delete n[pos]; return n; }), 800);
  };

  const spawnGifts = useCallback(() => {
    const t = Date.now();
    const g1: Gift = { id: 'g1', type: 1, pos: (currentPos + 4) % TOTAL_TILES, size: 1, expiry: t + 2 * 3600 * 1000, rewards: { gems: 1, coins: 10 } };
    const g2: Gift = { id: 'g2', type: 2, pos: (currentPos + 8) % TOTAL_TILES, size: 2, expiry: t + 3 * 3600 * 1000, rewards: { gems: 3, coins: 20 } };
    const g3: Gift = { id: 'g3', type: 3, pos: (currentPos + 12) % TOTAL_TILES, size: 3, expiry: t + 24 * 3600 * 1000, rewards: { gems: 5, coins: 30 } };
    setActiveGifts([g1, g2, g3]);
  }, [currentPos]);

  const collectGift = (gift: Gift) => {
    setActiveGifts(prev => prev.filter(g => g.id !== gift.id));
    setResources(r => ({ gems: r.gems + gift.rewards.gems, coins: r.coins + gift.rewards.coins }));
    setPopup({ text: `Hộp quà ${gift.type} !`, sub: `Nhận ${gift.rewards.gems}💎 & ${gift.rewards.coins}🪙` });
    setTimeout(() => setPopup(null), 2500);
  };

  const relocateItem = useCallback((list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...clownIndices];
    const [newPos] = getRandomUnique(1, exclude);
    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  }, [currentPos, bombIndices, zombieIndicators, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, getRandomUnique]);

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) setPumpkinBoss(p => ({ ...p, health: Math.max(0, p.health - 1), isActive: p.health > 1 }));
    if (demonBoss.isActive) setDemonBoss(d => ({ ...d, health: Math.max(0, d.health - 1), isActive: d.health > 1 }));
    setActiveZombies(prev => {
      if (prev.length === 0) return prev;
      let minIdx = -1, minD = Infinity;
      prev.forEach((z, i) => { const d = Math.min(Math.abs(damagePos - z.pos), TOTAL_TILES - Math.abs(damagePos - z.pos)); if(d < minD){ minD = d; minIdx = i; }});
      if(minIdx === -1) return prev;
      const next = [...prev]; next[minIdx] = { ...next[minIdx], health: next[minIdx].health - 1 };
      return next.filter(z => z.health > 0);
    });
    setIsShaking(true); setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
  }, [pumpkinBoss, demonBoss, activeZombies]);

  const handleGameOver = () => {
    setIsShaking(true); setJarCount(0); setCurrentPos(0); setActiveZombies([]); setPumpkinBoss({ isActive: false, health: 0 }); setDemonBoss({ isActive: false, health: 0 }); setIsGrayscale(false); setIsClownMode(false);
    setTimeout(() => setIsShaking(false), 500);
  };

  const processMovement = useCallback((diceSum: number) => {
    let steps = 0, temp = currentPos;
    if (diceSum === 1) applyBombDamage(temp);
    const interval = setInterval(() => {
      temp = (temp + 1) % TOTAL_TILES;
      setCurrentPos(temp); triggerBloom(temp); steps++;

      activeGifts.forEach(g => {
        for(let i=0; i<g.size; i++) {
          if((g.pos + i) % TOTAL_TILES === temp) { collectGift(g); break; }
        }
      });

      if (temp === 0) { setIsGrayscale(false); setIsClownMode(false); }
      if (cloverIndices.includes(temp)) { setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1)); relocateItem(cloverIndices, temp, 'clover'); }
      if (bombIndices.includes(temp)) { applyBombDamage(temp); relocateItem(bombIndices, temp, 'bomb'); }

      if (steps >= diceSum) {
        clearInterval(interval); setIsMoving(false);
        if (ghostIndices.includes(temp)) { setIsGrayscale(true); setIsClownMode(false); relocateItem(ghostIndices, temp, 'ghost'); }
        if (rainbowIndices.includes(temp)) { setIsGrayscale(false); setIsClownMode(false); relocateItem(rainbowIndices, temp, 'rainbow'); }
        if (clownIndices.includes(temp)) { setIsClownMode(true); setIsGrayscale(false); relocateItem(clownIndices, temp, 'clown'); }
        if (zombieIndicators.includes(temp)) {
          setActiveZombies(p => [...p, { id: Math.random().toString(36).substr(2, 9), pos: (temp - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES, health: MAX_ZOMBIE_HEALTH, isActive: true }]);
          relocateItem(zombieIndicators, temp, 'zombie');
        }
        if (pumpkinIndices.includes(temp)) { setPumpkinBoss({ isActive: true, health: MAX_PUMPKIN_HEALTH }); relocateItem(pumpkinIndices, temp, 'pumpkin'); }
        if (demonIndices.includes(temp)) { setDemonBoss({ isActive: true, health: MAX_DEMON_HEALTH }); relocateItem(demonIndices, temp, 'demon'); }
        setActiveZombies(prev => {
          let hit = false; const move = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => { const n = (z.pos + move) % TOTAL_TILES; if (n === temp) hit = true; return { ...z, pos: n }; });
          if (hit) { setPlayerHealth(h => { const n = h - 1; if (n <= 0) { handleGameOver(); return MAX_PLAYER_HEALTH; } return n; }); return []; }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, activeGifts, cloverIndices, bombIndices, ghostIndices, rainbowIndices, clownIndices, zombieIndicators, pumpkinIndices, demonIndices, demonBoss.isActive, applyBombDamage, relocateItem]);

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    if (pumpkinBoss.isActive) { setIsDeducting(true); setJarCount(p => Math.max(0, p - 5)); setTimeout(() => setIsDeducting(false), 800); }

    if (activeGifts.length === 0) {
      setRollCounter(prev => {
        const next = prev + 1;
        if (next >= ROLLS_FOR_GIFT) { spawnGifts(); return 0; }
        return next;
      });
    }

    setIsRolling(true); setRollBank(r => r - 1);
    const count = isGrayscale ? 3 : 1;
    const vals = Array.from({ length: count }, () => Math.floor(Math.random() * 6) + 1);
    setDicePositions(Array.from({ length: count }, (_, i) => ({ x: landing.x + (i - Math.floor(count/2)) * (isClownMode ? 100 : 60), y: landing.y })));
    setTimeout(() => { setIsRolling(false); setDiceValues(vals); setIsMoving(true); processMovement(vals.reduce((a, b) => a + b, 0)); }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
