  x: number;
  y: number;
  type: 'normal' | 'special';
}

export interface BigZombie {
  id: string;
  pos: number;
  health: number;
  isActive: boolean;
}

export interface PumpkinBoss {
  isActive: boolean;
  health: number;
}

export interface DemonBoss {
  isActive: boolean;
  health: number;
}

export interface Gift {
  id: string;
  type: 1 | 2 | 3;
  pos: number;
  size: number;
  expiry: number;
