// Layout Margins
const H_MARGIN_UNITS = 5;
const V_MARGIN_UNITS = 3;

const ZOMBIE_INDICATOR_COUNT = 6; 
const BOMB_COUNT = 8;           
const PUMPKIN_COUNT = 3; 
const DEMON_COUNT = 3; 
const CLOVER_COUNT = 4; 
const GHOST_COUNT = 2; 
