import React, { useState, useRef } from 'react';

interface AlchemyJarProps {
  count: number;
  max: number;
  isExploding: boolean;
  onExplode: () => void;
  isDeducting?: boolean;
  themeColor?: string;
  customHeight?: number;
}

export const AlchemyJar: React.FC<AlchemyJarProps> = ({ count, max, isExploding, onExplode, isDeducting, themeColor = '#6366f1', customHeight = 420 }) => {
  const percent = Math.min(100, (count / max) * 100);
  const isFull = count >= max;
  const [holdProgress, setHoldProgress] = useState(0);
  const holdInterval = useRef<number | null>(null);

  const startHold = () => {
    if (!isFull || isExploding) return;
    holdInterval.current = window.setInterval(() => {
      setHoldProgress(prev => {
        if (prev >= 100) {
          if (holdInterval.current) clearInterval(holdInterval.current);
          onExplode();
          return 0;
        }
        return prev + 1;
      });
    }, 30);
  };

  const endHold = () => {
    if (holdInterval.current) {
      clearInterval(holdInterval.current);
      holdInterval.current = null;
    }
    setHoldProgress(0);
  };

  return (
    <div className="flex flex-col gap-2" style={{ height: customHeight }}>
      <div className={`relative flex-grow bg-black/[0.03] dark:bg-white/[0.03] border-[6px] border-white dark:border-zinc-800 rounded-b-[25px] rounded-t-[5px] overflow-hidden backdrop-blur-xl transition-all duration-700 ${isExploding ? 'scale-150 blur-3xl opacity-0' : 'scale-100'} ${isDeducting ? 'border-red-500/30' : ''}`}>
        <div 
          className="absolute bottom-0 left-0 w-full transition-all duration-1000 ease-out"
          style={{ height: `${percent}%`, backgroundColor: isDeducting ? '#f43f5e' : themeColor, opacity: 0.6 }}
        >
          <div className="absolute inset-0 overflow-hidden">
             {[...Array(4)].map((_, i) => (
               <div 
                 key={i} 
                 className="absolute bottom-0 bg-white/30 rounded-full animate-bubble"
                 style={{
                   width: 6,
                   height: 6,
                   left: `${Math.random() * 100}%`,
                   animationDuration: `${Math.random() * 2 + 1}s`,
                   animationDelay: `${Math.random() * 2}s`
                 }}
               />
             ))}
          </div>
        </div>
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
          <span className={`text-[10px] font-black transition-colors ${isDeducting ? 'text-white' : 'opacity-40'}`}>
            {isDeducting ? '-5%' : `${Math.floor(percent)}%`}
          </span>
        </div>
      </div>

      <div className="shrink-0 flex flex-col gap-1.5">
        {holdProgress > 0 && (
          <div className="w-full h-0.5 bg-black/10 dark:bg-white/10 rounded-full overflow-hidden">
             <div className="h-full bg-indigo-500" style={{ width: `${holdProgress}%` }} />
          </div>
        )}
        <button
          onMouseDown={startHold}
          onMouseUp={endHold}
          onMouseLeave={endHold}
          onTouchStart={startHold}
          onTouchEnd={endHold}
          disabled={!isFull || isExploding}
          className={`w-full h-8 rounded-md text-[8px] font-black uppercase tracking-[0.1em] transition-all
            ${isFull 
              ? 'bg-indigo-600 text-white shadow-md cursor-pointer hover:brightness-110 active:scale-95' 
              : 'bg-black/5 dark:bg-white/5 text-gray-400 cursor-not-allowed'
            }`}
        >
          {isFull ? (holdProgress > 0 ? 'Charging' : 'Jar Full') : 'Alchemy'}
        </button>
      </div>

      <style>{`
        @keyframes bubble {
          0% { transform: translateY(0) scale(0.5); opacity: 0; }
          50% { opacity: 0.5; }
          100% { transform: translateY(-80px) scale(1.5); opacity: 0; }
        }
        .animate-bubble { animation: bubble linear infinite; }
      `}</style>
    </div>
  );
};

import React, { useState, useRef, useEffect, useMemo } from 'react';

interface Dice3DProps {
  value: number;
  isRolling: boolean;
  onRoll: (landingPos: { x: number; y: number }) => void;
  onDragEnd: (finalPos: { x: number; y: number }) => void;
  currentPos: { x: number; y: number };
  color?: string;
  scale?: number;
  isD20?: boolean;
}

export const Dice3D: React.FC<Dice3DProps> = ({ 
  value, 
  isRolling, 
  onRoll, 
  onDragEnd, 
  currentPos, 
  color = 'rgba(255, 255, 255, 0.3)',
  scale = 1,
  isD20 = false
}) => {
  const [pos, setPos] = useState(currentPos);
  const [isDragging, setIsDragging] = useState(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const elementPosStart = useRef({ x: 0, y: 0 });

  useEffect(() => {
    if (!isRolling && !isDragging) {
      setPos(currentPos);
    }
  }, [currentPos, isRolling, isDragging]);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (isRolling) return;
    setIsDragging(true);
    dragStart.current = { x: e.clientX, y: e.clientY };
    elementPosStart.current = { x: pos.x, y: pos.y };
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;
      const dx = e.clientX - dragStart.current.x;
      const dy = e.clientY - dragStart.current.y;
      setPos({
        x: elementPosStart.current.x + dx,
        y: elementPosStart.current.y + dy
      });
    };

    const handleMouseUp = () => {
      if (isDragging) {
        setIsDragging(false);
        onDragEnd(pos);
      }
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, pos, onDragEnd]);

  const getRotation = (v: number) => {
    if (isD20) {
      // Simplified D20 rotations for 20 faces
      // Each face is spaced out; we roughly map values to standard angles
      const rotMap: Record<number, string> = {
        1: 'rotateX(0deg) rotateY(0deg)',
        2: 'rotateX(40deg) rotateY(72deg)',
        3: 'rotateX(40deg) rotateY(144deg)',
        4: 'rotateX(40deg) rotateY(216deg)',
        5: 'rotateX(40deg) rotateY(288deg)',
        6: 'rotateX(100deg) rotateY(36deg)',
        7: 'rotateX(100deg) rotateY(108deg)',
        8: 'rotateX(100deg) rotateY(180deg)',
        9: 'rotateX(100deg) rotateY(252deg)',
        10: 'rotateX(100deg) rotateY(324deg)',
        11: 'rotateX(180deg) rotateY(0deg)',
        12: 'rotateX(220deg) rotateY(72deg)',
        13: 'rotateX(220deg) rotateY(144deg)',
        14: 'rotateX(220deg) rotateY(216deg)',
        15: 'rotateX(220deg) rotateY(288deg)',
        16: 'rotateX(280deg) rotateY(36deg)',
        17: 'rotateX(280deg) rotateY(108deg)',
        18: 'rotateX(280deg) rotateY(180deg)',
        19: 'rotateX(280deg) rotateY(252deg)',
        20: 'rotateX(280deg) rotateY(324deg)',
      };
      return rotMap[v] || 'rotateX(0deg)';
    }

    switch (v) {
      case 1: return 'rotateX(0deg) rotateY(0deg)';
      case 2: return 'rotateY(-90deg)';
      case 3: return 'rotateY(90deg)';
      case 4: return 'rotateY(180deg)';
      case 5: return 'rotateX(-90deg)';
      case 6: return 'rotateX(90deg)';
      default: return 'rotateX(0deg)';
    }
  };

  const rollingRotation = isRolling 
    ? `rotateX(${Math.random() * 1080 + 720}deg) rotateY(${Math.random() * 1080 + 720}deg) rotateZ(${Math.random() * 360}deg)`
    : getRotation(value);

  const triggerRoll = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (isRolling) return;
    const landingX = Math.max(100, Math.min(window.innerWidth - 100, pos.x + (Math.random() - 0.5) * 200));
    const landingY = Math.max(100, Math.min(window.innerHeight - 100, pos.y + (Math.random() - 0.5) * 200));
    onRoll({ x: landingX, y: landingY });
  };

  const baseScale = isDragging ? 1.1 : (isRolling ? 1.3 : 1);
  const finalScale = baseScale * scale;

  // D20 faces positions (approximate icosahedron)
  const d20Faces = useMemo(() => {
    if (!isD20) return null;
    return Array.from({ length: 20 }, (_, i) => {
      const faceNum = i + 1;
      let rotX = 0, rotY = 0, transZ = 45;

      // Top 5
      if (faceNum <= 5) {
        rotX = 37; rotY = (faceNum - 1) * 72;
      } 
      // Middle top 5
      else if (faceNum <= 10) {
        rotX = 100; rotY = (faceNum - 6) * 72 + 36;
      }
      // Middle bottom 5
      else if (faceNum <= 15) {
        rotX = 180 + 37; rotY = (faceNum - 11) * 72;
      }
      // Bottom 5
      else {
        rotX = 180 + 100; rotY = (faceNum - 16) * 72 + 36;
      }

      return (
        <div 
          key={faceNum} 
          className="d20-face" 
          style={{ 
            background: color,
            transform: `rotateY(${rotY}deg) rotateX(${rotX}deg) translateZ(${transZ}px)` 
          }}
        >
          <span style={{ transform: 'translateY(12px)' }}>{faceNum}</span>
        </div>
      );
    });
  }, [isD20, color]);

  return (
    <div 
      className={`fixed z-[60] transition-all ${isRolling ? 'duration-[1200ms]' : 'duration-75'} select-none cursor-grab active:cursor-grabbing`}
      style={{ 
        left: `${pos.x}px`, 
        top: `${pos.y}px`,
        transform: `translate(-50%, -50%) scale(${finalScale})`
      }}
      onMouseDown={handleMouseDown}
      onDoubleClick={triggerRoll}
    >
      <div className="dice-container">
        <div className="dice" style={{ transform: rollingRotation }}>
          {!isD20 ? (
            <>
              <div className="dice-face front" style={{ background: color }}><div className="dot"></div></div>
              <div className="dice-face back" style={{ background: color }}>
                <div className="dot" style={{ top: '15%', left: '15%' }}></div>
                <div className="dot" style={{ top: '15%', left: '60%' }}></div>
                <div className="dot" style={{ top: '60%', left: '15%' }}></div>
                <div className="dot" style={{ top: '60%', left: '60%' }}></div>
              </div>
              <div className="dice-face right" style={{ background: color }}>
                <div className="dot" style={{ top: '15%', left: '15%' }}></div>
                <div className="dot" style={{ top: '40%', left: '40%' }}></div>
                <div className="dot" style={{ top: '65%', left: '65%' }}></div>
              </div>
              <div className="dice-face left" style={{ background: color }}>
                <div className="dot" style={{ top: '15%', left: '15%' }}></div>
                <div className="dot" style={{ top: '65%', left: '65%' }}></div>
              </div>
              <div className="dice-face top" style={{ background: color }}>
                <div className="dot" style={{ top: '15%', left: '15%' }}></div>
                <div className="dot" style={{ top: '15%', left: '60%' }}></div>
                <div className="dot" style={{ top: '40%', left: '40%' }}></div>
                <div className="dot" style={{ top: '65%', left: '15%' }}></div>
                <div className="dot" style={{ top: '65%', left: '65%' }}></div>
              </div>
              <div className="dice-face bottom" style={{ background: color }}>
                <div className="dot" style={{ top: '15%', left: '15%' }}></div>
                <div className="dot" style={{ top: '15%', left: '60%' }}></div>
                <div className="dot" style={{ top: '40%', left: '15%' }}></div>
                <div className="dot" style={{ top: '40%', left: '60%' }}></div>
                <div className="dot" style={{ top: '65%', left: '15%' }}></div>
                <div className="dot" style={{ top: '65%', left: '65%' }}></div>
              </div>
            </>
          ) : (
            d20Faces
          )}
        </div>
      </div>
      {!isRolling && scale < 2 && (
          <div className="absolute -bottom-6 left-1/2 -translate-x-1/2 text-[9px] font-bold opacity-30 uppercase tracking-tighter whitespace-nowrap">Double Click</div>
      )}
    </div>
  );
};

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss, Gift, Resources } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 
const ROLLS_FOR_GIFT = 7;
const APP_SCALE = 2.5; 

// Board Dimensions for consistent centering
const BOARD_W = 22; 
const BOARD_H = 11; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 
const SPAWN_BEHIND_OFFSET = 3;

// Layout Margins
const H_MARGIN_UNITS = 5;
const V_MARGIN_UNITS = 3;

const ZOMBIE_INDICATOR_COUNT = 6; 
const BOMB_COUNT = 8;           
const PUMPKIN_COUNT = 3; 
const DEMON_COUNT = 3; 
const CLOVER_COUNT = 4; 
const GHOST_COUNT = 2; 
const RAINBOW_COUNT = 2; 
const CLOWN_COUNT = 2; 

const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🦌', '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤', '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const THEME_COLORS = [
  '#6366f1', // Indigo
  '#10b981', // Emerald
  '#f43f5e', // Rose
  '#f59e0b', // Amber
  '#8b5cf6', // Violet
  '#0ea5e9', // Sky
  '#ec4899', // Pink
  '#06b6d4', // Cyan
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [themeColor, setThemeColor] = useState(THEME_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [isD20Mode, setIsD20Mode] = useState(false);
  const [isFlashing, setIsFlashing] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  const [resources, setResources] = useState<Resources>({ gems: 0, coins: 0 });
  const [rollCounter, setRollCounter] = useState(0);
  const [activeGifts, setActiveGifts] = useState<Gift[]>([]);
  const [popup, setPopup] = useState<{ text: string; sub: string } | null>(null);

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<(Task & { completedAt: string })[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([{ x: window.innerWidth / (2 * APP_SCALE), y: window.innerHeight / (2 * APP_SCALE) }]);

  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  const [now, setNow] = useState(Date.now());

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  useEffect(() => {
    const timer = setInterval(() => {
      setNow(Date.now());
      setActiveGifts(prev => prev.filter(g => g.expiry > Date.now()));
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const [tileSize, setTileSize] = useState(40);

  useEffect(() => {
    const updateSize = () => {
      const totalHUnits = BOARD_W + (H_MARGIN_UNITS * 2);
      const totalVUnits = BOARD_H + (V_MARGIN_UNITS * 2);
      const horizontalLimit = window.innerWidth / (totalHUnits * APP_SCALE);
      const verticalLimit = window.innerHeight / (totalVUnits * APP_SCALE);
      setTileSize(Math.max(15, Math.min(horizontalLimit, verticalLimit)));
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const totalW = (BOARD_W - 1) * tileSize;
    const totalH = (BOARD_H - 1) * tileSize;
    const startX = (window.innerWidth / APP_SCALE - totalW) / 2;
    const startY = (window.innerHeight / APP_SCALE - totalH) / 2; 

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, x: startX + i * tileSize, y: startY, type: 'normal' });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize, type: 'normal' });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize, type: 'normal' });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, x: startX, y: startY + i * tileSize, type: 'normal' });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    const gInd = getRandomUnique(GHOST_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd]);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd, ...rInd]);
    setZombieIndicators(zInd); setBombIndices(bInd); setPumpkinIndices(pInd); setDemonIndices(dInd); setCloverIndices(cInd); setGhostIndices(gInd); setRainbowIndices(rInd); setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    setBlooms(prev => ({ ...prev, [pos]: FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)] }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => { const n = { ...prev }; delete n[pos]; return n; }), 800);
  };

  const spawnGifts = useCallback(() => {
    const t = Date.now();
    const g1: Gift = { id: 'g1', type: 1, pos: (currentPos + 20) % TOTAL_TILES, size: 1, expiry: t + 2 * 3600 * 1000, rewards: { gems: 1, coins: 10 } };
    const g2: Gift = { id: 'g2', type: 2, pos: (currentPos + 30) % TOTAL_TILES, size: 2, expiry: t + 3 * 3600 * 1000, rewards: { gems: 3, coins: 20 } };
    const g3: Gift = { id: 'g3', type: 3, pos: (currentPos + 50) % TOTAL_TILES, size: 3, expiry: t + 24 * 3600 * 1000, rewards: { gems: 5, coins: 30 } };
    setActiveGifts([g1, g2, g3]);
  }, [currentPos]);

  const collectGift = (gift: Gift) => {
    setActiveGifts(prev => prev.filter(g => g.id !== gift.id));
    setResources(r => ({ gems: r.gems + gift.rewards.gems, coins: r.coins + gift.rewards.coins }));
    setPopup({ text: `Hộp quà ${gift.type} !`, sub: `Nhận ${gift.rewards.gems}💎 & ${gift.rewards.coins}🪙` });
    setTimeout(() => setPopup(null), 2500);
  };

  const relocateItem = useCallback((list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...clownIndices];
    const [newPos] = getRandomUnique(1, exclude);
    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  }, [currentPos, bombIndices, zombieIndicators, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, getRandomUnique]);

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) setPumpkinBoss(p => ({ ...p, health: Math.max(0, p.health - 1), isActive: p.health > 1 }));
    if (demonBoss.isActive) setDemonBoss(d => ({ ...d, health: Math.max(0, d.health - 1), isActive: d.health > 1 }));
    setActiveZombies(prev => {
      if (prev.length === 0) return prev;
      let minIdx = -1, minD = Infinity;
      prev.forEach((z, i) => { const d = Math.min(Math.abs(damagePos - z.pos), TOTAL_TILES - Math.abs(damagePos - z.pos)); if(d < minD){ minD = d; minIdx = i; }});
      if(minIdx === -1) return prev;
      const next = [...prev]; next[minIdx] = { ...next[minIdx], health: next[minIdx].health - 1 };
      return next.filter(z => z.health > 0);
    });
    setIsShaking(true); setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
  }, [pumpkinBoss, demonBoss, activeZombies]);

  const handleGameOver = () => {
    setIsShaking(true); setJarCount(0); setCurrentPos(0); setActiveZombies([]); setPumpkinBoss({ isActive: false, health: 0 }); setDemonBoss({ isActive: false, health: 0 }); setIsGrayscale(false); setIsClownMode(false); setIsD20Mode(false);
    setTimeout(() => setIsShaking(false), 500);
  };

  const processMovement = useCallback((diceSum: number) => {
    let steps = 0, temp = currentPos;
    if (diceSum === 1) applyBombDamage(temp);
    const interval = setInterval(() => {
      temp = (temp + 1) % TOTAL_TILES;
      setCurrentPos(temp); triggerBloom(temp); steps++;

      activeGifts.forEach(g => {
        for(let i=0; i<g.size; i++) {
          if((g.pos + i) % TOTAL_TILES === temp) { collectGift(g); break; }
        }
      });

      if (temp === 0) { setIsGrayscale(false); setIsClownMode(false); setIsD20Mode(false); }
      if (cloverIndices.includes(temp)) { setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1)); relocateItem(cloverIndices, temp, 'clover'); }
      if (bombIndices.includes(temp)) { applyBombDamage(temp); relocateItem(bombIndices, temp, 'bomb'); }

      if (steps >= diceSum) {
        clearInterval(interval); setIsMoving(false);
        if (ghostIndices.includes(temp)) { setIsGrayscale(true); setIsClownMode(false); setIsD20Mode(false); relocateItem(ghostIndices, temp, 'ghost'); }
        if (rainbowIndices.includes(temp)) { setIsGrayscale(false); setIsClownMode(false); setIsD20Mode(true); relocateItem(rainbowIndices, temp, 'rainbow'); }
        if (clownIndices.includes(temp)) { setIsClownMode(true); setIsGrayscale(false); setIsD20Mode(false); relocateItem(clownIndices, temp, 'clown'); }
        if (zombieIndicators.includes(temp)) {
          setActiveZombies(p => [...p, { id: Math.random().toString(36).substr(2, 9), pos: (temp - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES, health: MAX_ZOMBIE_HEALTH, isActive: true }]);
          relocateItem(zombieIndicators, temp, 'zombie');
        }
        if (pumpkinIndices.includes(temp)) { setPumpkinBoss({ isActive: true, health: MAX_PUMPKIN_HEALTH }); relocateItem(pumpkinIndices, temp, 'pumpkin'); }
        if (demonIndices.includes(temp)) { setDemonBoss({ isActive: true, health: MAX_DEMON_HEALTH }); relocateItem(demonIndices, temp, 'demon'); }
        setActiveZombies(prev => {
          let hit = false; const move = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => { const n = (z.pos + move) % TOTAL_TILES; if (n === temp) hit = true; return { ...z, pos: n }; });
          if (hit) { setPlayerHealth(h => { const n = h - 1; if (n <= 0) { handleGameOver(); return MAX_PLAYER_HEALTH; } return n; }); return []; }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, activeGifts, cloverIndices, bombIndices, ghostIndices, rainbowIndices, clownIndices, zombieIndicators, pumpkinIndices, demonIndices, demonBoss.isActive, applyBombDamage, relocateItem]);

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    if (pumpkinBoss.isActive) { setIsDeducting(true); setJarCount(p => Math.max(0, p - 5)); setTimeout(() => setIsDeducting(false), 800); }

    if (isClownMode) {
        setIsFlashing(true);
        setTimeout(() => setIsFlashing(false), 1200);
    }

    if (activeGifts.length === 0) {
      setRollCounter(prev => {
        const next = prev + 1;
        if (next >= ROLLS_FOR_GIFT) { spawnGifts(); return 0; }
        return next;
      });
    }

    setIsRolling(true); setRollBank(r => r - 1);
    const count = isGrayscale ? 3 : 1;
    const maxVal = isD20Mode ? 20 : 6;
    const vals = Array.from({ length: count }, () => Math.floor(Math.random() * maxVal) + 1);
    setDicePositions(Array.from({ length: count }, (_, i) => ({ x: landing.x, y: landing.y })));
    setTimeout(() => { setIsRolling(false); setDiceValues(vals); setIsMoving(true); processMovement(vals.reduce((a, b) => a + b, 0)); }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setTasks(prev => prev.filter(t => t.id !== task.id));
    setHistory(prev => [{ ...task, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setRollBank(r => r + (task.priority === 'high' ? 15 : task.priority === 'medium' ? 10 : 5));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setTimeout(() => {
      setIsExploding(false);
      setJarCount(0);
      setRollBank(r => r + 50);
      setPopup({ text: "ALCHEMY EXPLOSION!", sub: "+50 Energy Received" });
      setTimeout(() => setPopup(null), 2500);
    }, 1000);
  };

  const formatTime = (ms: number) => {
    const s = Math.max(0, Math.floor(ms / 1000));
    const h = Math.floor(s / 3600), m = Math.floor((s % 3600) / 60), sc = s % 60;
    return `${h}h ${m}m ${sc}s`;
  };

  const hexToRgba = (hex: string, alpha: number) => {
    const r = parseInt(hex.slice(1, 3), 16);
    const g = parseInt(hex.slice(3, 5), 16);
    const b = parseInt(hex.slice(5, 7), 16);
    return `rgba(${r}, ${g}, ${b}, ${alpha})`;
  };

  const activeDiceCount = diceValues.length;
  const currentDiceScale = isGrayscale ? 0.7 : (isClownMode ? 5.0 : 0.9);
  const currentDiceColor = hexToRgba(themeColor, 0.2);

  const totalW = (BOARD_W - 1) * tileSize;
  const totalH = (BOARD_H - 1) * tileSize;
  const startX = (window.innerWidth / APP_SCALE - totalW) / 2;
  const startY = (window.innerHeight / APP_SCALE - totalH) / 2;

  const PANEL_WIDTH = 280;
  const PANEL_HEIGHT = totalH - tileSize * 3;
  const PANEL_LEFT = startX + tileSize * 2;
  const PANEL_TOP = startY + tileSize * 2;
  const JAR_LEFT = PANEL_LEFT + PANEL_WIDTH + tileSize;
  const BOSS_LEFT = JAR_LEFT + 70 + tileSize * 3;

  return (
    <div 
      className={`h-screen w-screen relative transition-all duration-700 overflow-hidden flex items-center justify-center notion-grid ${isExploding ? 'bg-indigo-600/10' : ''} ${isGrayscale ? 'filter grayscale' : ''} ${isClownMode ? 'clown-bg animate-color-chaos' : ''}`}
    >
      <div 
        className="relative w-full h-full origin-center"
        style={{ transform: `scale(${APP_SCALE})` }}
      >
        {isFlashing && <div className="absolute inset-0 z-[200] pointer-events-none blinding-effect" />}
        {isClownMode && isRolling && <div className="absolute inset-0 z-[100] pointer-events-none confetti-effect" />}

        <div className="absolute inset-0 z-0 pointer-events-none">
          {boardSpaces.map(s => {
