import React, { useState, useRef, useEffect } from 'react';

// Fix: Added themeColor and customHeight to the props interface to match App.tsx usage
interface AlchemyJarProps {
  count: number;
  max: number;
  isExploding: boolean;
  onExplode: () => void;
  isDeducting?: boolean;
  themeColor?: string;
  customHeight?: number;
}

export const AlchemyJar: React.FC<AlchemyJarProps> = ({ 
  count, 
  max, 
  isExploding, 
  onExplode, 
  isDeducting,
  themeColor,
  customHeight 
}) => {
  const percent = Math.min(100, (count / max) * 100);
  const isFull = count >= max;
  const [holdProgress, setHoldProgress] = useState(0);
  const holdInterval = useRef<number | null>(null);

  const startHold = () => {
    if (!isFull || isExploding) return;
    holdInterval.current = window.setInterval(() => {
      setHoldProgress(prev => {
        if (prev >= 100) {
          if (holdInterval.current) clearInterval(holdInterval.current);
          onExplode();
          return 0;
        }
        return prev + 1;
      });
    }, 30);
  };

  const endHold = () => {
    if (holdInterval.current) {
      clearInterval(holdInterval.current);
      holdInterval.current = null;
    }
    setHoldProgress(0);
  };

  // Fix: Use customHeight if provided for the container height
  const containerStyle = {
    height: customHeight ? `${customHeight}px` : '420px'
  };

  return (
    <div className="flex flex-col gap-4 w-28" style={containerStyle}>
      <div className={`relative flex-grow bg-gray-50/50 dark:bg-black/20 border-8 border-gray-100 dark:border-white/5 rounded-b-[40px] rounded-t-[10px] overflow-hidden backdrop-blur-xl transition-all duration-700 ${isExploding ? 'scale-150 blur-3xl opacity-0' : 'scale-100'} ${isDeducting ? 'border-red-500/30' : ''}`}>
        <div 
          className={`absolute bottom-0 left-0 w-full transition-all duration-1000 ease-out ${isDeducting ? 'bg-red-400/80' : 'bg-indigo-500/80'}`}
          style={{ height: `${percent}%`, backgroundColor: !isDeducting && themeColor ? `${themeColor}cc` : undefined }}
        >
          <div className="absolute inset-0 overflow-hidden">
             {[...Array(6)].map((_, i) => (
               <div 
                 key={i} 
                 className="absolute bottom-0 bg-white/20 rounded-full animate-bubble"
                 style={{
                   width: Math.random() * 8 + 4,
                   height: Math.random() * 8 + 4,
                   left: `${Math.random() * 100}%`,
                   animationDuration: `${Math.random() * 2 + 1}s`,
                   animationDelay: `${Math.random() * 2}s`
                 }}
               />
             ))}
          </div>
        </div>
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
          <span className={`text-xl font-black transition-colors ${isDeducting ? 'text-red-600' : 'text-indigo-900/50 dark:text-white/50'}`}>
            {isDeducting ? '-5%' : `${Math.floor(percent)}%`}
          </span>
        </div>
      </div>

      <div className="w-full relative h-16 flex flex-col justify-end">
        {holdProgress > 0 && (
          <div className="absolute top-0 left-0 w-full h-1 bg-gray-100 dark:bg-white/5 rounded-full overflow-hidden">
             <div className="h-full bg-indigo-500" style={{ width: `${holdProgress}%`, backgroundColor: themeColor }} />
          </div>
        )}
        <button
          onMouseDown={startHold}
          onMouseUp={endHold}
          onMouseLeave={endHold}
          onTouchStart={startHold}
          onTouchEnd={endHold}
          disabled={!isFull || isExploding}
          className={`w-full h-12 rounded-lg text-[9px] font-black uppercase tracking-[0.2em] transition-all
            ${isFull 
              ? 'bg-indigo-600 text-white shadow-lg cursor-pointer hover:scale-105 active:scale-95' 
              : 'bg-black/5 dark:bg-white/5 text-gray-400 cursor-not-allowed'
            }`}
          style={isFull ? { backgroundColor: themeColor } : {}}
        >
          {isFull ? (holdProgress > 0 ? 'Charging...' : 'Hold 3s') : 'Collect'}
        </button>
      </div>

      <style>{`
        @keyframes bubble {
          0% { transform: translateY(0) scale(0.5); opacity: 0; }
          50% { opacity: 0.5; }
          100% { transform: translateY(-100px) scale(1.5); opacity: 0; }
        }
        .animate-bubble { animation: bubble linear infinite; }
      `}</style>
    </div>
  );
};

