import React, { useState, useRef, useEffect } from 'react';

interface AlchemyJarProps {
  count: number;
  max: number;
  isExploding: boolean;
  onExplode: () => void;
  isDeducting?: boolean;
  height?: number;
}

export const AlchemyJar: React.FC<AlchemyJarProps> = ({ 
  count, 
  max, 
  isExploding, 
  onExplode, 
  isDeducting,
  height = 320
}) => {
  const percent = Math.min(100, (count / max) * 100);
  const isFull = count >= max;
  const [holdProgress, setHoldProgress] = useState(0);
  const holdInterval = useRef<number | null>(null);

  const startHold = () => {
    if (!isFull || isExploding) return;
    holdInterval.current = window.setInterval(() => {
      setHoldProgress(prev => {
        if (prev >= 100) {
          if (holdInterval.current) clearInterval(holdInterval.current);
          onExplode();
          return 0;
        }
        return prev + 1;
      });
    }, 30);
  };

  const endHold = () => {
    if (holdInterval.current) {
      clearInterval(holdInterval.current);
      holdInterval.current = null;
    }
    setHoldProgress(0);
  };

  return (
    <div 
      className="flex flex-col items-center justify-end relative w-24 group"
      style={{ height: `${height}px` }}
    >
      <div 
        className={`relative w-full cursor-pointer transition-all duration-700 
          ${isExploding ? 'scale-150 blur-3xl opacity-0' : 'scale-100'} 
          ${isFull && !isExploding ? 'hover:scale-105' : ''}`}
        style={{ height: '80%' }}
        onMouseDown={startHold}
        onMouseUp={endHold}
        onMouseLeave={endHold}
        onTouchStart={startHold}
        onTouchEnd={endHold}
      >
        {/* Flask Body */}
        <div className="absolute bottom-0 left-0 w-full h-full bg-gray-50/50 dark:bg-black/20 border-2 border-gray-100 dark:border-white/5 backdrop-blur-xl overflow-hidden shadow-2xl rounded-2xl">

          {/* Fluid Level */}
          <div 
            className={`absolute bottom-0 left-0 w-full transition-all duration-1000 ease-out ${isDeducting ? 'bg-red-500/80' : 'bg-indigo-500/80 shadow-[0_-5px_15px_rgba(99,102,241,0.5)]'}`}
            style={{ height: `${percent}%` }}
          >
            {/* Bubbles */}
            <div className="absolute inset-0 overflow-hidden">
               {[...Array(6)].map((_, i) => (
                 <div 
                   key={i} 
                   className="absolute bottom-0 bg-white/20 rounded-full animate-bubble"
                   style={{
                     width: Math.random() * 5 + 2,
                     height: Math.random() * 5 + 2,
                     left: `${Math.random() * 100}%`,
                     animationDuration: `${Math.random() * 2 + 1}s`,
                     animationDelay: `${Math.random() * 2}s`
                   }}
                 />
               ))}
            </div>
          </div>

          {/* Label / Percentage */}
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
            <span className={`text-[10px] font-black transition-colors ${isDeducting ? 'text-red-200' : 'text-white'}`}>
              {isDeducting ? '-5%' : `${Math.floor(percent)}%`}
            </span>
          </div>
        </div>

        {/* Hold progress overlay */}
        {holdProgress > 0 && (
          <div className="absolute inset-0 flex items-center justify-center z-20 pointer-events-none">
            <div className="w-12 h-12 rounded-full border-4 border-white/20 flex items-center justify-center">
              <div className="w-10 h-10 rounded-full border-4 border-white border-t-transparent animate-spin" />
            </div>
          </div>
        )}
      </div>

      <div className="mt-3 text-center">
        <span className={`text-[8px] font-black uppercase tracking-[0.2em] px-2 py-1 rounded-full border transition-all
          ${isFull ? 'bg-indigo-500 text-white border-indigo-400' : 'bg-black/5 dark:bg-white/5 text-gray-400 border-transparent opacity-50'}`}>
          {isFull ? 'Hold 3s' : 'Jar'}
        </span>
      </div>

      <style>{`
        @keyframes bubble {
          0% { transform: translateY(0) scale(0.5); opacity: 0; }
          50% { opacity: 0.6; }
          100% { transform: translateY(-100px) scale(1.5); opacity: 0; }
        }
        .animate-bubble { animation: bubble linear infinite; }
      `}</style>
    </div>
  );
};

