                <>
                  {tasks.length === 0 && (
                    <div className="h-32 flex flex-col items-center justify-center opacity-20 border-2 border-dashed border-black/10 rounded-2xl p-6 text-center">
                       <span className="text-2xl mb-2">📋</span>
