                      className="group p-4 bg-white dark:bg-black/20 hover:bg-indigo-50 dark:hover:bg-indigo-900/10 rounded-xl border border-black/5 dark:border-white/10 transition-all cursor-pointer flex items-center gap-4 hover:border-indigo-500/30"
                    >
                      <div className="w-6 h-6 rounded-lg border-2 border-black/10 group-hover:bg-indigo-500 group-hover:border-indigo-500 transition-all flex items-center justify-center">
                        <div className="w-2.5 h-2.5 bg-white rounded-sm opacity-0 group-hover:opacity-100 transition-opacity" />
                      </div>
                      <div className="flex-grow min-w-0">
                        <div className="text-[14px] font-semibold truncate leading-tight opacity-90">{t.text}</div>
                        {t.priority && <div className={`inline-block text-[8px] font-black uppercase px-2 py-0.5 rounded-md mt-1.5 border ${getPriorityColor(t.priority)}`}>{t.priority}</div>}
                      </div>
                    </div>
                  ))}
                </>
              ) : (
                history.map(h => (
                  <div key={h.id} className="p-4 bg-black/[0.02] dark:bg-white/[0.02] rounded-xl border-l-4 border-indigo-500/40 opacity-50 mb-2">
                    <span className="text-[13px] line-through block font-medium opacity-80">{h.text}</span>
                    <span className="text-[9px] font-black opacity-30 uppercase tracking-widest mt-2 block">{h.completedAt}</span>
                  </div>
                ))
