            {/* Add New Quest */}
            <div className="mt-6 pt-6 border-t border-black/5">
               <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([{ id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }, ...tasks]); setNewTask(''); }} className="flex flex-col gap-3">
                  <div className="flex gap-2">
                    {['low', 'medium', 'high'].map(p => (
                      <button key={p} type="button" onClick={() => setNewTaskPriority(p as any)} className={`flex-1 py-1.5 rounded-lg text-[9px] font-black uppercase tracking-widest border transition-all ${newTaskPriority === p ? 'bg-indigo-500 text-white border-indigo-500 shadow-md' : 'bg-black/5 dark:bg-white/5 border-transparent opacity-40 hover:opacity-100'}`}>{p}</button>
                    ))}
                  </div>
                  <input 
                    value={newTask} 
                    onChange={e => setNewTask(e.target.value)} 
                    className="w-full h-12 bg-white dark:bg-black/40 border border-black/5 dark:border-white/10 focus:border-indigo-500/50 rounded-xl px-4 text-[13px] font-medium outline-none transition-all shadow-inner placeholder:opacity-30" 
                    placeholder="Type new mission..." 
                  />
               </form>
            </div>
          </div>
        </div>
      </div>

      <style>{`
        @keyframes bounce-slow { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-12px); } }
        .animate-bounce-slow { animation: bounce-slow 3s ease-in-out infinite; }
        @keyframes bomb-drop { 0% { transform: translate(-50%, -300%) scale(2); opacity: 0; } 60% { transform: translate(-50%, -60%) scale(1); opacity: 1; } 100% { transform: translate(-50%, -60%) scale(14); opacity: 0; filter: blur(50px); } }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.06); background: rgba(255,255,255,0.95); border-radius: 4px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.03); background: rgba(18,18,18,0.95); }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.1); border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); }
        @keyframes color-chaos { 0% { background-color: #ff0000; } 25% { background-color: #00ff00; } 50% { background-color: #0000ff; } 75% { background-color: #ffff00; } 100% { background-color: #ff00ff; } }
        .animate-color-chaos { animation: color-chaos 5s infinite linear; }
        .confetti-effect { background-image: radial-gradient(circle, #ff0 10%, transparent 10.5%), radial-gradient(circle, #f00 10%, transparent 10.5%), radial-gradient(circle, #0f0 10%, transparent 10.5%), radial-gradient(circle, #00f 10%, transparent 10.5%); background-size: 10px 10px, 15px 15px, 20px 20px, 12px 12px; background-position: 0 0, 5px 5px, 10px 10px, 15px 15px; animation: confetti-fall 2s infinite linear; opacity: 0.6; }
        @keyframes confetti-fall { 0% { background-position: 0 0; } 100% { background-position: 100px 500px; } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss, Gift, Resources } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

const ZOMBIE_INDICATOR_COUNT = 10; 
const BOMB_COUNT = 10;           
const PUMPKIN_COUNT = 5; 
const DEMON_COUNT = 5; 
const CLOVER_COUNT = 5; 
const GHOST_COUNT = 3; 
const RAINBOW_COUNT = 3; 
const CLOWN_COUNT = 2; 

const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 
const SPAWN_BEHIND_OFFSET = 5;

const APP_SCALE = 1.25; 
const SIDEBAR_WIDTH = 380;

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', 
  '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🦌',
  '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤',
  '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.4)', 
  'rgba(199, 210, 254, 0.6)', 
  'rgba(254, 202, 202, 0.6)', 
  'rgba(167, 243, 208, 0.6)', 
  'rgba(253, 230, 138, 0.6)', 
];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  const [diamonds, setDiamonds] = useState(0);
  const [coins, setCoins] = useState(0);

  const [rollCountForGifts, setRollCountForGifts] = useState(0);
  const [activeGifts, setActiveGifts] = useState<Gift[]>([]);
  const [giftPopup, setGiftPopup] = useState<{show: boolean, msg: string}>({show: false, msg: ""});

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);

  const gameAreaRef = useRef<HTMLDivElement>(null);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2, y: window.innerHeight / 2 }
  ]);

  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(48);

  useEffect(() => {
    const updateSize = () => {
      const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
      const availableH = window.innerHeight / APP_SCALE;
      const horizontalLimit = (availableW - 60) / BOARD_W;
      const verticalLimit = (availableH - 60) / BOARD_H;
      const bestSize = Math.max(25, Math.min(horizontalLimit, verticalLimit, 45));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
    const availableH = window.innerHeight / APP_SCALE;
    const boardRealW = (BOARD_W - 1) * tileSize;
    const boardRealH = (BOARD_H - 1) * tileSize;
    const startX = (availableW - boardRealW) / 2;
    const startY = (availableH - boardRealH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    const gInd = getRandomUnique(GHOST_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd]);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd, ...rInd]);

    setZombieIndicators(zInd);
    setBombIndices(bInd);
    setPumpkinIndices(pInd);
    setDemonIndices(dInd);
    setCloverIndices(cInd);
    setGhostIndices(gInd);
    setRainbowIndices(rInd);
    setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  useEffect(() => {
    const timer = setInterval(() => {
      setActiveGifts(prev => {
        const next = prev.map(g => ({ ...g, timeLeft: g.timeLeft - 1 })).filter(g => g.timeLeft > 0);
        return next;
      });
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...clownIndices, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);

    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  };

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) {
      setPumpkinBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    if (demonBoss.isActive) {
      setDemonBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    setActiveZombies(prev => {
      if (prev.length === 0) return prev;
      let nearestIndex = 0;
      let minDistance = Infinity;
      prev.forEach((z, idx) => {
        const dist = Math.min(Math.abs(damagePos - z.pos), TOTAL_TILES - Math.abs(damagePos - z.pos));
        if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
      });
      const newZombies = [...prev];
      const target = { ...newZombies[nearestIndex] };
      target.health -= 1;
      if (target.health <= 0) {
        newZombies.splice(nearestIndex, 1);
      } else { newZombies[nearestIndex] = target; }
      return newZombies;
    });
    setIsShaking(true);
    setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
  }, [pumpkinBoss, demonBoss, activeZombies]);

  const collectGift = (gift: Gift) => {
    let d = 0, c = 0;
    if (gift.type === 1) { d = 1; c = 10; }
    else if (gift.type === 2) { d = 3; c = 20; }
    else if (gift.type === 3) { d = 5; c = 30; }

    setDiamonds(prev => prev + d);
    setCoins(prev => prev + c);
    setActiveGifts(prev => prev.filter(g => g.id !== gift.id));
    setGiftPopup({ show: true, msg: `Nhận ${d}💎 và ${c}🪙!` });
    setTimeout(() => setGiftPopup({ show: false, msg: "" }), 3000);
  };

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    if (diceSum === 1) applyBombDamage(tempPos);

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      const giftOnTile = activeGifts.find(g => g.pos === tempPos);
      if (giftOnTile) collectGift(giftOnTile);

      if (tempPos === 0) {
        setIsGrayscale(false);
        setIsClownMode(false);
      }

      if (cloverIndices.includes(tempPos)) {
        setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1));
        relocateItem(cloverIndices, tempPos, 'clover');
      }
      if (bombIndices.includes(tempPos)) {
        applyBombDamage(tempPos);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (ghostIndices.includes(finalPos)) {
          setIsGrayscale(true);
          setIsClownMode(false);
          relocateItem(ghostIndices, finalPos, 'ghost');
        } else if (rainbowIndices.includes(finalPos)) {
          setIsGrayscale(false);
          setIsClownMode(false);
          relocateItem(rainbowIndices, finalPos, 'rainbow');
        } else if (clownIndices.includes(finalPos)) {
          setIsClownMode(true);
          setIsGrayscale(false);
          relocateItem(clownIndices, finalPos, 'clown');
        }

        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombies(prev => [...prev, {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          }]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }
        if (pumpkinIndices.includes(finalPos)) {
          setPumpkinBoss(prev => ({ isActive: true, health: MAX_PUMPKIN_HEALTH }));
          relocateItem(pumpkinIndices, finalPos, 'pumpkin');
        }
        if (demonIndices.includes(finalPos)) {
          setDemonBoss(prev => ({ isActive: true, health: MAX_DEMON_HEALTH }));
          relocateItem(demonIndices, finalPos, 'demon');
        }

        setActiveZombies(prev => {
          let gameOver = false;
          const moveSteps = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + moveSteps) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) {
            setPlayerHealth(h => {
              const next = h - 1;
              if (next <= 0) {
                handleGameOver();
                return MAX_PLAYER_HEALTH;
              }
              return next;
            });
            return [];
          }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, pumpkinBoss, demonBoss, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, activeGifts, applyBombDamage]);

  const handleGameOver = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setIsGrayscale(false);
    setIsClownMode(false);
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }, index: number) => {
    if (rollBank <= 0 || isRolling || isMoving) return;

    if (pumpkinBoss.isActive) {
      setIsDeducting(true);
      setJarCount(prev => Math.max(0, prev - 5));
      setTimeout(() => setIsDeducting(false), 800);
    }

    setIsRolling(true);
    setRollBank(r => r - 1);

    if (activeGifts.length === 0) {
      const nextCount = rollCountForGifts + 1;
      if (nextCount >= 7) {
        const gift1Pos = (currentPos + 10) % TOTAL_TILES;
        const gift2Pos = (gift1Pos + 10) % TOTAL_TILES;
        const gift3Pos = (gift2Pos + 17) % TOTAL_TILES;
        setActiveGifts([
          { id: 1, type: 1, pos: gift1Pos, timeLeft: 2 * 3600, totalTime: 2 * 3600 },
          { id: 2, type: 2, pos: gift2Pos, timeLeft: 3 * 3600, totalTime: 3 * 3600 },
          { id: 3, type: 3, pos: gift3Pos, timeLeft: 24 * 3600, totalTime: 24 * 3600 },
        ]);
        setRollCountForGifts(0);
      } else {
        setRollCountForGifts(nextCount);
      }
    }

    const diceCount = isGrayscale ? 3 : 1;
    const newValues = Array.from({ length: diceCount }, () => Math.floor(Math.random() * 6) + 1);
    const newPositions = Array.from({ length: diceCount }, (_, i) => ({
      x: landing.x + (i - Math.floor(diceCount / 2)) * (isClownMode ? 180 : 80),
      y: landing.y
    }));

    setDicePositions(newPositions);

    setTimeout(() => {
      setIsRolling(false);
      setDiceValues(newValues);
      setIsMoving(true);
      const sum = newValues.reduce((a, b) => a + b, 0);
      processMovement(sum);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  const formatTime = (sec: number) => {
    const h = Math.floor(sec / 3600);
    const m = Math.floor((sec % 3600) / 60);
    const s = sec % 60;
    return `${h}h ${m}m ${s}s`;
  };

  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  const getClownTileColor = (id: number) => {
    if (!isClownMode) return undefined;
    const colors = ['#ff00ff', '#00ffff', '#ffff00', '#ff0000', '#00ff00', '#ff8800', '#8800ff'];
    return colors[id % colors.length] + 'cc';
  };

  const activeDiceCount = isGrayscale ? 3 : 1;
  const currentDiceScale = isClownMode ? 3.5 : 1;

  return (
    <div className={`h-screen w-screen flex transition-all duration-700 bg-white dark:bg-zinc-950
      ${isExploding ? 'bg-indigo-600/10' : ''} 
      ${isGrayscale ? 'filter grayscale' : ''}
    `}>
      {/* Main Game Area (Left) */}
      <div 
        ref={gameAreaRef}
        className="flex-1 relative overflow-hidden notion-grid"
      >
        <div 
          className="relative w-full h-full origin-top-left flex items-center justify-center"
          style={{ transform: `scale(${APP_SCALE})` }}
        >
          <div className="relative w-full h-full">
            <div className="absolute inset-0 z-0 pointer-events-none">
                {boardSpaces.map(s => {
                  const bloom = blooms[s.id];
                  const isBomb = bombIndices.includes(s.id);
                  const isZombie = zombieIndicators.includes(s.id);
                  const isPumpkin = pumpkinIndices.includes(s.id);
                  const isDemon = demonIndices.includes(s.id);
                  const isClover = cloverIndices.includes(s.id);
                  const isGhost = ghostIndices.includes(s.id);
                  const isRainbow = rainbowIndices.includes(s.id);
                  const isClown = clownIndices.includes(s.id);
                  const isStart = s.id === 0;

                  let icon = null;
                  if (isBomb) icon = BOMB_ICON;
                  else if (isZombie) icon = ENEMY_ICON;
                  else if (isPumpkin) icon = '🎃';
                  else if (isDemon) icon = '👹';
                  else if (isClover) icon = '🍀';
                  else if (isGhost) icon = '👻';
                  else if (isRainbow) icon = '🌈';
                  else if (isClown) icon = '🤡';

                  return (
                    <div 
                      key={s.id}
                      className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
                      style={{ 
                          left: s.x, top: s.y, width: tileSize, height: tileSize,
                          backgroundColor: isClownMode ? getClownTileColor(s.id) : undefined 
                      }}
                    >
                      <span className="text-[6px] opacity-20 absolute top-0.5 left-0.5 font-bold">{s.id + 1}</span>
                      {icon && <span className="drop-shadow-sm opacity-25" style={{ fontSize: tileSize * 0.55 }}>{icon}</span>}
                      {bloom && <span className="bloom absolute opacity-25" style={{ fontSize: tileSize * 0.5 }}>{bloom}</span>}
                      {isStart && !bloom && !icon && <span className="text-[7px] font-black opacity-30 uppercase tracking-widest">Home</span>}
                    </div>
                  );
                })}

                {activeGifts.map(gift => boardSpaces[gift.pos] && (
                <div 
                    key={gift.id} 
                    className="absolute z-20 transition-all duration-700 pointer-events-none"
                    style={{ 
                    left: boardSpaces[gift.pos].x + tileSize/2, 
                    top: boardSpaces[gift.pos].y + tileSize/2, 
                    transform: `translate(-50%, -100%) scale(${gift.type * 0.4 + 0.5})`,
                    transformOrigin: 'bottom'
                    }}
                >
                    <div className="flex flex-col items-center">
                    <div className="bg-white/90 dark:bg-black/80 px-2 py-0.5 rounded-full mb-1 border border-indigo-500/20 shadow-sm flex flex-col items-center">
                        <span className="text-[5px] font-bold opacity-50 uppercase tracking-tighter leading-none">Gift</span>
                        <div className="w-10 h-0.5 bg-gray-100 dark:bg-white/5 rounded-full overflow-hidden mt-0.5">
                          <div className="h-full bg-indigo-500" style={{ width: `${(gift.timeLeft / gift.totalTime) * 100}%` }} />
                        </div>
                    </div>
                    <span className="text-[28px] drop-shadow-xl">🎁</span>
                    </div>
                </div>
                ))}

                {activeZombies.map(z => boardSpaces[z.pos] && (
                <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
                    left: boardSpaces[z.pos].x + tileSize/2, 
                    top: boardSpaces[z.pos].y + tileSize/2, 
                    transform: `translate(-50%, -60%) scale(${demonBoss.isActive ? 1.8 : 0.9})` 
                }}>
                    <div className="flex flex-col items-center">
                        <div className="flex gap-0.5 mb-1 bg-white/90 dark:bg-black/80 p-0.5 rounded-full px-1.5 border border-black/5 shadow-sm">
                        {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                            <div key={i} className={`w-1.5 h-0.5 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-200 dark:bg-gray-800'}`} />
                        ))}
                        </div>
                        <span className="drop-shadow-2xl animate-pulse" style={{ fontSize: tileSize * 1.1 }}>{ENEMY_ICON}</span>
                    </div>
                </div>
                ))}

                <div 
                onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
                className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto`}
                style={{ 
                    left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, 
                    top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, 
                    transform: 'translate(-50%, -60%)',
                    fontSize: tileSize * 1.3
                }}
                >
                <div className="flex flex-col items-center">
                    <div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-1.5 border border-black/5 shadow-sm">
                        {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (
                        <div key={i} className={`w-1.5 h-0.5 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />
                        ))}
                    </div>
                    <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">
                    {isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}
                    </span>
                </div>
                </div>

                {bombAnimation.active && (
                <div className="absolute z-50 animate-bomb-drop" style={{ 
                    left: boardSpaces[bombAnimation.pos]?.x + tileSize/2, 
                    top: boardSpaces[bombAnimation.pos]?.y + tileSize/2,
                    transform: 'translate(-50%, -100%)'
                }}>
                    <span className="text-7xl drop-shadow-2xl">{darkMode ? '✨' : '💥'}</span>
                </div>
                )}
            </div>

            <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
                <div className="flex items-center gap-16 translate-y-6">
                    <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} height={tileSize * 5} />

                    <div className="flex flex-col items-center gap-10">
                    {pumpkinBoss.isActive && (
                        <div className="flex flex-col items-center animate-bounce-slow">
                        <div className="flex gap-1 mb-1.5 bg-white/90 p-1 rounded-full shadow-lg border border-orange-500/20 backdrop-blur-md">
                            {[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (
                                <div key={i} className={`w-3.5 h-1 rounded-full ${i < pumpkinBoss.health ? 'bg-orange-500' : 'bg-gray-200 opacity-20'}`} />
                            ))}
                        </div>
                        <span className="leading-none drop-shadow-2xl" style={{ fontSize: tileSize * 1.8 }}>🎃</span>
                        </div>
                    )}

                    {demonBoss.isActive && (
                        <div className="flex flex-col items-center animate-bounce-slow" style={{ animationDelay: '-1.5s' }}>
                        <div className="flex gap-1 mb-1.5 bg-white/90 p-1 rounded-full shadow-lg border border-red-500/20 backdrop-blur-md">
                            {[...Array(MAX_DEMON_HEALTH)].map((_, i) => (
                                <div key={i} className={`w-3.5 h-1 rounded-full ${i < demonBoss.health ? 'bg-red-500' : 'bg-gray-200 opacity-20'}`} />
                            ))}
                        </div>
                        <span className="leading-none drop-shadow-2xl" style={{ fontSize: tileSize * 1.8 }}>👹</span>
                        </div>
                    )}
                    </div>
                </div>
            </div>
          </div>
        </div>

        {Array.from({ length: activeDiceCount }).map((_, i) => (
          <Dice3D 
            key={i}
            color={diceColor} 
            value={diceValues[i] || 1} 
            isRolling={isRolling} 
            currentPos={dicePositions[i]} 
            onRoll={(landing) => handleRoll(landing, i)} 
            onDragEnd={(finalPos) => setDicePositions(prev => {
              const next = [...prev];
              next[i] = finalPos;
              return next;
            })} 
            scale={currentDiceScale}
          />
        ))}
      </div>

      {/* Sidebar (Right) - Notion Inspired */}
      <div 
        className="w-[380px] h-full bg-[#fbfbfa] dark:bg-[#191919] border-l border-[#efefef] dark:border-white/5 flex flex-col z-50 shadow-2xl transition-colors duration-500 overflow-hidden"
      >
        <div className="p-4 flex flex-col h-full">
          {/* Minimalism Top Header (1/10 space) */}
          <div className="flex items-center justify-between py-2 border-b border-[#eee] dark:border-white/5 mb-4">
             <div className="flex items-center gap-3">
                <div className="flex items-center gap-1 group cursor-pointer">
                   <span className="text-[14px]">💎</span>
                   <span className="text-[13px] font-bold tabular-nums opacity-80">{diamonds}</span>
                </div>
                <div className="flex items-center gap-1 group cursor-pointer">
                   <span className="text-[14px]">🪙</span>
                   <span className="text-[13px] font-bold tabular-nums opacity-80">{coins}</span>
                </div>
             </div>

             <div className="flex items-center gap-2">
                <div className="flex items-center gap-2 mr-2 border-r border-[#eee] pr-2">
                  <span className="text-[10px] font-black opacity-30 uppercase tracking-tighter">⚡ Bank</span>
                  <span className="text-[16px] font-black tracking-tighter">{rollBank}</span>
                </div>
                <button onClick={() => setDarkMode(!darkMode)} className="p-1.5 rounded-md hover:bg-black/5 dark:hover:bg-white/5 transition-colors text-sm">{darkMode ? '☀️' : '🌙'}</button>
                <div className="w-5 h-5 rounded overflow-hidden flex flex-wrap gap-0.5 p-0.5 bg-black/5 dark:bg-white/5 cursor-pointer" onClick={() => {
                  const idx = DICE_COLORS.indexOf(diceColor);
                  setDiceColor(DICE_COLORS[(idx + 1) % DICE_COLORS.length]);
                }}>
                  <div className="flex-1 h-full rounded-[1px]" style={{background: diceColor}} />
                </div>
             </div>
          </div>

          {/* Task Management (9/10 space) - Notion Task Interface */}
          <div className="flex-1 flex flex-col overflow-hidden">
             <div className="flex items-center justify-between px-1 mb-6">
                <div className="flex items-center gap-2 text-[14px] font-bold opacity-90">
                   <span>📋</span>
                   <h1>Quests</h1>
                </div>
                <div className="flex gap-4">
                   <button onClick={() => setShowHistory(false)} className={`text-[12px] font-medium transition-all ${!showHistory ? 'text-indigo-600 underline underline-offset-4' : 'opacity-40 hover:opacity-100'}`}>Active</button>
                   <button onClick={() => setShowHistory(true)} className={`text-[12px] font-medium transition-all ${showHistory ? 'text-indigo-600 underline underline-offset-4' : 'opacity-40 hover:opacity-100'}`}>Logbook</button>
                </div>
             </div>

             <div className="flex-1 overflow-y-auto custom-scrollbar px-1 pb-4">
                {!showHistory ? (
                   <div className="flex flex-col gap-1">
                      {tasks.map(t => (
                        <div key={t.id} className="group flex items-start gap-3 p-2 hover:bg-[#f3f3f2] dark:hover:bg-white/5 rounded-lg transition-all cursor-pointer border border-transparent">
                           <button onClick={() => handleTaskComplete(t)} className="mt-0.5 w-4.5 h-4.5 rounded-[4px] border border-[#ccc] dark:border-white/20 group-hover:border-indigo-500 group-hover:bg-indigo-50 dark:group-hover:bg-indigo-900/20 transition-all flex items-center justify-center">
                              <div className="w-2 h-2 bg-indigo-500 rounded-[1px] opacity-0 group-hover:opacity-40 transition-opacity" />
                           </button>
                           <div className="flex-1 min-w-0" onClick={() => handleTaskComplete(t)}>
                              <p className="text-[14px] leading-[1.4] opacity-80 group-hover:opacity-100 transition-opacity">{t.text}</p>
                              <div className={`mt-2 inline-flex items-center px-2 py-0.5 rounded-md text-[10px] font-bold uppercase border ${getPriorityColor(t.priority)}`}>
                                {t.priority}
                              </div>
                           </div>
                        </div>
                      ))}

                      {/* Notion Style "+ New" button */}
                      <div className="mt-4 border-t border-[#efefef] dark:border-white/5 pt-6">
                        <form 
                          className="flex flex-col gap-4"
                          onSubmit={e => { 
                            e.preventDefault(); 
                            if(!newTask.trim()) return; 
                            setTasks([...tasks, { id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }]); 
                            setNewTask(''); 
                          }}
                        >
                           <div className="flex items-center gap-2 px-1">
                              {['low', 'medium', 'high'].map(p => (
                                <button key={p} type="button" onClick={() => setNewTaskPriority(p as any)} className={`px-2 py-1 rounded text-[9px] font-black uppercase tracking-widest transition-all border ${newTaskPriority === p ? 'bg-indigo-500 text-white border-indigo-500 shadow-sm' : 'bg-transparent border-transparent opacity-40 hover:opacity-100'}`}>
                                   {p}
                                </button>
                              ))}
                           </div>
                           <div className="group relative">
                             <span className="absolute left-3 top-3 text-[#ccc] group-focus-within:text-indigo-500 transition-colors">+</span>
                             <input 
                                value={newTask} 
                                onChange={e => setNewTask(e.target.value)}
                                placeholder="New mission..."
                                className="w-full pl-8 pr-4 py-2.5 bg-transparent border-none outline-none text-[15px] placeholder:opacity-40 focus:placeholder:opacity-20"
                             />
                           </div>
                           <button type="submit" className="hidden" />
                        </form>
                      </div>
                   </div>
                ) : (
                  <div className="flex flex-col gap-2">
                     {history.map(h => (
                       <div key={h.id} className="p-3 bg-black/[0.01] dark:bg-white/[0.01] rounded-lg border-l-2 border-[#efefef] dark:border-white/10 opacity-60">
                          <p className="text-[13px] line-through opacity-80">{h.text}</p>
                          <span className="text-[9px] font-black opacity-30 mt-2 block">{h.completedAt}</span>
                       </div>
                     ))}
                  </div>
                )}
             </div>
          </div>
        </div>
      </div>

      <style>{`
        .notion-grid { background-image: radial-gradient(#efefef 1px, transparent 1px); background-size: 20px 20px; }
        .dark .notion-grid { background-image: radial-gradient(rgba(255,255,255,0.05) 1px, transparent 1px); }
        @keyframes bounce-slow { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-12px); } }
        .animate-bounce-slow { animation: bounce-slow 4s ease-in-out infinite; }
        @keyframes bomb-drop { 0% { transform: translate(-50%, -300%) scale(2); opacity: 0; } 60% { transform: translate(-50%, -60%) scale(1); opacity: 1; } 100% { transform: translate(-50%, -60%) scale(14); opacity: 0; filter: blur(50px); } }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.06); background: rgba(255,255,255,0.98); border-radius: 4px; box-shadow: 0 1px 2px rgba(0,0,0,0.02); }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.03); background: rgba(18,18,18,0.95); }
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.08); border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.08); }
        @keyframes color-chaos { 0% { background-color: #ff0000; } 25% { background-color: #00ff00; } 50% { background-color: #0000ff; } 75% { background-color: #ffff00; } 100% { background-color: #ff00ff; } }
        .clown-bg { background-color: #ff00ff05 !important; }
        .confetti-effect { background-image: radial-gradient(circle, #ff0 10%, transparent 10.5%), radial-gradient(circle, #f00 10%, transparent 10.5%), radial-gradient(circle, #0f0 10%, transparent 10.5%), radial-gradient(circle, #00f 10%, transparent 10.5%); background-size: 10px 10px, 15px 15px, 20px 20px, 12px 12px; background-position: 0 0, 5px 5px, 10px 10px, 15px 15px; animation: confetti-fall 2s infinite linear; opacity: 0.2; }
        @keyframes confetti-fall { 0% { background-position: 0 0; } 100% { background-position: 100px 500px; } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss, Gift, Resources } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

const ZOMBIE_INDICATOR_COUNT = 10; 
const BOMB_COUNT = 10;           
const PUMPKIN_COUNT = 5; 
const DEMON_COUNT = 5; 
const CLOVER_COUNT = 5; 
const GHOST_COUNT = 3; 
const RAINBOW_COUNT = 3; 
const CLOWN_COUNT = 2; 

const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 
const SPAWN_BEHIND_OFFSET = 5;

const APP_SCALE = 1.25; 
const SIDEBAR_WIDTH = 380;

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', 
  '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🦌',
  '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤',
  '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.4)', 
  'rgba(199, 210, 254, 0.6)', 
  'rgba(254, 202, 202, 0.6)', 
  'rgba(167, 243, 208, 0.6)', 
  'rgba(253, 230, 138, 0.6)', 
];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  const [diamonds, setDiamonds] = useState(0);
  const [coins, setCoins] = useState(0);

  const [rollCountForGifts, setRollCountForGifts] = useState(0);
  const [activeGifts, setActiveGifts] = useState<Gift[]>([]);
  const [giftPopup, setGiftPopup] = useState<{show: boolean, msg: string}>({show: false, msg: ""});

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);

  const gameAreaRef = useRef<HTMLDivElement>(null);

  // Initialize with 3 positions to avoid out-of-bounds errors when 3 dice are used
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2, y: window.innerHeight / 2 },
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2 - 100, y: window.innerHeight / 2 },
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2 + 100, y: window.innerHeight / 2 }
  ]);

  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(48);

  useEffect(() => {
    const updateSize = () => {
      const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
      const availableH = window.innerHeight / APP_SCALE;
      const horizontalLimit = (availableW - 60) / BOARD_W;
      const verticalLimit = (availableH - 60) / BOARD_H;
      const bestSize = Math.max(25, Math.min(horizontalLimit, verticalLimit, 45));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
    const availableH = window.innerHeight / APP_SCALE;
    const boardRealW = (BOARD_W - 1) * tileSize;
    const boardRealH = (BOARD_H - 1) * tileSize;
    const startX = (availableW - boardRealW) / 2;
    const startY = (availableH - boardRealH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    const gInd = getRandomUnique(GHOST_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd]);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd, ...rInd]);

    setZombieIndicators(zInd);
    setBombIndices(bInd);
    setPumpkinIndices(pInd);
    setDemonIndices(dInd);
    setCloverIndices(cInd);
    setGhostIndices(gInd);
    setRainbowIndices(rInd);
    setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  useEffect(() => {
    const timer = setInterval(() => {
      setActiveGifts(prev => {
        const next = prev.map(g => ({ ...g, timeLeft: g.timeLeft - 1 })).filter(g => g.timeLeft > 0);
        return next;
      });
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...clownIndices, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);

    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  };

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) {
      setPumpkinBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    if (demonBoss.isActive) {
      setDemonBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    setActiveZombies(prev => {
      if (prev.length === 0) return prev;
      let nearestIndex = 0;
      let minDistance = Infinity;
      prev.forEach((z, idx) => {
        const dist = Math.min(Math.abs(damagePos - z.pos), TOTAL_TILES - Math.abs(damagePos - z.pos));
        if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
      });
      const newZombies = [...prev];
      const target = { ...newZombies[nearestIndex] };
      target.health -= 1;
      if (target.health <= 0) {
        newZombies.splice(nearestIndex, 1);
      } else { newZombies[nearestIndex] = target; }
      return newZombies;
    });
    setIsShaking(true);
    setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
  }, [pumpkinBoss, demonBoss, activeZombies]);

  const collectGift = (gift: Gift) => {
    let d = 0, c = 0;
    if (gift.type === 1) { d = 1; c = 10; }
    else if (gift.type === 2) { d = 3; c = 20; }
    else if (gift.type === 3) { d = 5; c = 30; }

    setDiamonds(prev => prev + d);
    setCoins(prev => prev + c);
    setActiveGifts(prev => prev.filter(g => g.id !== gift.id));
    setGiftPopup({ show: true, msg: `Nhận ${d}💎 và ${c}🪙!` });
    setTimeout(() => setGiftPopup({ show: false, msg: "" }), 3000);
  };

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    if (diceSum === 1) applyBombDamage(tempPos);

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      const giftOnTile = activeGifts.find(g => g.pos === tempPos);
      if (giftOnTile) collectGift(giftOnTile);

      if (tempPos === 0) {
        setIsGrayscale(false);
        setIsClownMode(false);
      }

      if (cloverIndices.includes(tempPos)) {
        setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1));
        relocateItem(cloverIndices, tempPos, 'clover');
      }
      if (bombIndices.includes(tempPos)) {
        applyBombDamage(tempPos);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (ghostIndices.includes(finalPos)) {
          setIsGrayscale(true);
          setIsClownMode(false);
          relocateItem(ghostIndices, finalPos, 'ghost');
        } else if (rainbowIndices.includes(finalPos)) {
          setIsGrayscale(false);
          setIsClownMode(false);
          relocateItem(rainbowIndices, finalPos, 'rainbow');
        } else if (clownIndices.includes(finalPos)) {
          setIsClownMode(true);
          setIsGrayscale(false);
          relocateItem(clownIndices, finalPos, 'clown');
        }

        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombies(prev => [...prev, {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          }]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }
        if (pumpkinIndices.includes(finalPos)) {
          setPumpkinBoss(prev => ({ isActive: true, health: MAX_PUMPKIN_HEALTH }));
          relocateItem(pumpkinIndices, finalPos, 'pumpkin');
        }
        if (demonIndices.includes(finalPos)) {
          setDemonBoss(prev => ({ isActive: true, health: MAX_DEMON_HEALTH }));
          relocateItem(demonIndices, finalPos, 'demon');
        }

        setActiveZombies(prev => {
          let gameOver = false;
          const moveSteps = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + moveSteps) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) {
            setPlayerHealth(h => {
              const next = h - 1;
              if (next <= 0) {
                handleGameOver();
                return MAX_PLAYER_HEALTH;
              }
              return next;
            });
            return [];
          }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, pumpkinBoss, demonBoss, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, activeGifts, applyBombDamage]);

  const handleGameOver = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setIsGrayscale(false);
    setIsClownMode(false);
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }, index: number) => {
    if (rollBank <= 0 || isRolling || isMoving) return;

    if (pumpkinBoss.isActive) {
      setIsDeducting(true);
      setJarCount(prev => Math.max(0, prev - 5));
      setTimeout(() => setIsDeducting(false), 800);
    }

    setIsRolling(true);
    setRollBank(r => r - 1);

    if (activeGifts.length === 0) {
      const nextCount = rollCountForGifts + 1;
      if (nextCount >= 7) {
        const gift1Pos = (currentPos + 10) % TOTAL_TILES;
        const gift2Pos = (gift1Pos + 10) % TOTAL_TILES;
        const gift3Pos = (gift2Pos + 17) % TOTAL_TILES;
        setActiveGifts([
          { id: 1, type: 1, pos: gift1Pos, timeLeft: 2 * 3600, totalTime: 2 * 3600 },
          { id: 2, type: 2, pos: gift2Pos, timeLeft: 3 * 3600, totalTime: 3 * 3600 },
          { id: 3, type: 3, pos: gift3Pos, timeLeft: 24 * 3600, totalTime: 24 * 3600 },
        ]);
        setRollCountForGifts(0);
      } else {
        setRollCountForGifts(nextCount);
      }
    }

    const diceCount = isGrayscale ? 3 : 1;
    const newValues = Array.from({ length: diceCount }, () => Math.floor(Math.random() * 6) + 1);
    const newPositions = Array.from({ length: diceCount }, (_, i) => ({
      x: landing.x + (i - Math.floor(diceCount / 2)) * (isClownMode ? 180 : 80),
      y: landing.y
    }));

    setDicePositions(newPositions);

    setTimeout(() => {
      setIsRolling(false);
      setDiceValues(newValues);
      setIsMoving(true);
      const sum = newValues.reduce((a, b) => a + b, 0);
      processMovement(sum);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  const formatTime = (sec: number) => {
    const h = Math.floor(sec / 3600);
    const m = Math.floor((sec % 3600) / 60);
    const s = sec % 60;
    return `${h}h ${m}m ${s}s`;
  };

  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  const getClownTileColor = (id: number) => {
    if (!isClownMode) return undefined;
    const colors = ['#ff00ff', '#00ffff', '#ffff00', '#ff0000', '#00ff00', '#ff8800', '#8800ff'];
    return colors[id % colors.length] + 'cc';
  };

  const activeDiceCount = isGrayscale ? 3 : 1;
  const currentDiceScale = isClownMode ? 3.5 : 1;

  return (
    <div className={`h-screen w-screen flex transition-all duration-700 bg-white dark:bg-zinc-950
      ${isExploding ? 'bg-indigo-600/10' : ''} 
      ${isGrayscale ? 'filter grayscale' : ''}
    `}>
      {/* Main Game Area (Left) */}
      <div 
        ref={gameAreaRef}
        className="flex-1 relative overflow-hidden notion-grid"
      >
        <div 
          className="relative w-full h-full origin-top-left flex items-center justify-center"
          style={{ transform: `scale(${APP_SCALE})` }}
        >
          <div className="relative w-full h-full">
            <div className="absolute inset-0 z-0 pointer-events-none">
                {boardSpaces.map(s => {
                  const bloom = blooms[s.id];
                  const isBomb = bombIndices.includes(s.id);
                  const isZombie = zombieIndicators.includes(s.id);
                  const isPumpkin = pumpkinIndices.includes(s.id);
                  const isDemon = demonIndices.includes(s.id);
                  const isClover = cloverIndices.includes(s.id);
                  const isGhost = ghostIndices.includes(s.id);
                  const isRainbow = rainbowIndices.includes(s.id);
                  const isClown = clownIndices.includes(s.id);
                  const isStart = s.id === 0;

                  let icon = null;
                  if (isBomb) icon = BOMB_ICON;
                  else if (isZombie) icon = ENEMY_ICON;
                  else if (isPumpkin) icon = '🎃';
                  else if (isDemon) icon = '👹';
                  else if (isClover) icon = '🍀';
                  else if (isGhost) icon = '👻';
                  else if (isRainbow) icon = '🌈';
                  else if (isClown) icon = '🤡';

                  return (
                    <div 
                      key={s.id}
                      className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
                      style={{ 
                          left: s.x, top: s.y, width: tileSize, height: tileSize,
                          backgroundColor: isClownMode ? getClownTileColor(s.id) : undefined 
                      }}
                    >
                      <span className="text-[5px] opacity-20 absolute top-0.5 left-0.5 font-bold">{s.id + 1}</span>
                      {icon && <span className="drop-shadow-sm opacity-25" style={{ fontSize: tileSize * 0.55 }}>{icon}</span>}
                      {bloom && <span className="bloom absolute opacity-25" style={{ fontSize: tileSize * 0.5 }}>{bloom}</span>}
                      {isStart && !bloom && !icon && <span className="text-[7px] font-black opacity-30 uppercase tracking-widest">Home</span>}
                    </div>
                  );
                })}

                {activeGifts.map(gift => boardSpaces[gift.pos] && (
                <div 
                    key={gift.id} 
                    className="absolute z-20 transition-all duration-700 pointer-events-none"
                    style={{ 
                    left: boardSpaces[gift.pos].x + tileSize/2, 
                    top: boardSpaces[gift.pos].y + tileSize/2, 
                    transform: `translate(-50%, -100%) scale(${gift.type * 0.4 + 0.5})`,
                    transformOrigin: 'bottom'
                    }}
                >
                    <div className="flex flex-col items-center">
                    <div className="bg-white/90 dark:bg-black/80 px-2 py-0.5 rounded-full mb-1 border border-indigo-500/20 shadow-sm flex flex-col items-center">
                        <span className="text-[5px] font-bold opacity-50 uppercase tracking-tighter leading-none">Gift</span>
                        <div className="w-10 h-0.5 bg-gray-100 dark:bg-white/5 rounded-full overflow-hidden mt-0.5">
                          <div className="h-full bg-indigo-500" style={{ width: `${(gift.timeLeft / gift.totalTime) * 100}%` }} />
                        </div>
                    </div>
                    <span className="text-[28px] drop-shadow-xl">🎁</span>
                    </div>
                </div>
                ))}

                {activeZombies.map(z => boardSpaces[z.pos] && (
                <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
                    left: boardSpaces[z.pos].x + tileSize/2, 
                    top: boardSpaces[z.pos].y + tileSize/2, 
                    transform: `translate(-50%, -60%) scale(${demonBoss.isActive ? 1.8 : 0.9})` 
                }}>
                    <div className="flex flex-col items-center">
