                    <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">
                    {isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}
                    </span>
                </div>
                </div>

                {bombAnimation.active && (
                <div className="absolute z-50 animate-bomb-drop" style={{ 
                    left: boardSpaces[bombAnimation.pos]?.x + tileSize/2, 
                    top: boardSpaces[bombAnimation.pos]?.y + tileSize/2,
                    transform: 'translate(-50%, -100%)'
                }}>
                    <span className="text-7xl drop-shadow-2xl">{darkMode ? '✨' : '💥'}</span>
                </div>
                )}
            </div>

            {/* Central Area: Divided into Left (Sweets) | Center (Jar) | Right (Bosses) */}
            <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
                <div className="flex items-center gap-16 translate-y-6">

                    {/* LEFT: Random Sweets (Goal Gifts) */}
                    <div className="flex items-center gap-8 h-full min-w-[300px] justify-end">
                        {centralGiftsActive && goalGifts.map(g => (
                          <div key={g.id} className="flex flex-col items-center relative transition-all duration-500 animate-in fade-in zoom-in slide-in-from-left-4">
                             <div className="absolute -top-12 flex flex-col items-center w-20">
                                <div className="w-full h-1 bg-gray-200 dark:bg-white/5 rounded-full overflow-hidden border border-black/5">
                                   <div className="h-full bg-pink-500 transition-all duration-300" style={{ width: `${(g.currentSteps / g.stepsRequired) * 100}%` }} />
                                </div>
                                <span className="text-[7px] font-black uppercase tracking-tighter mt-1 opacity-40">{g.stepsRequired - g.currentSteps} left</span>
                             </div>
                             <span className="drop-shadow-2xl leading-none select-none" style={{ fontSize: tileSize * 3 }}>{g.emoji}</span>
                          </div>
