  sizeMultiplier: number;
  active: boolean;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [isWinterMode, setIsWinterMode] = useState(false);
  const [diceColor, setDiceColor] = useState('rgba(255, 255, 255, 0.4)');
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  const [rewardPoints, setRewardPoints] = useState(0);
  const [rollsSinceSweets, setRollsSinceSweets] = useState(0);
  const [particles, setParticles] = useState<Particle[]>([]);

  const [activeSweets, setActiveSweets] = useState<SweetGoal[]>([]);

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<(Task & { completedAt: string })[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2, y: window.innerHeight / 2 },
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2 - 80, y: window.innerHeight / 2 },
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2 + 80, y: window.innerHeight / 2 }
  ]);

  // Added gameAreaRef to fix reference error
  const gameAreaRef = useRef<HTMLDivElement>(null);
  const [jarCount, setJarCount] = useState(0);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(48);

  useEffect(() => {
    const updateSize = () => {
      const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
      const availableH = window.innerHeight / APP_SCALE;
      const horizontalLimit = (availableW - 60) / BOARD_W;
      const verticalLimit = (availableH - 60) / BOARD_H;
      const bestSize = Math.max(25, Math.min(horizontalLimit, verticalLimit, 45));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
    const availableH = window.innerHeight / APP_SCALE;
    const boardRealW = (BOARD_W - 1) * tileSize;
    const boardRealH = (BOARD_H - 1) * tileSize;
    const startX = (availableW - boardRealW) / 2;
    const startY = (availableH - boardRealH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    setZombieIndicators(getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude));
    setBombIndices(getRandomUnique(BOMB_COUNT, [...startExclude]));
    setPumpkinIndices(getRandomUnique(5, [...startExclude]));
    setDemonIndices(getRandomUnique(5, [...startExclude]));
    setCloverIndices(getRandomUnique(5, [...startExclude]));
    setGhostIndices(getRandomUnique(3, [...startExclude]));
    setRainbowIndices(getRandomUnique(3, [...startExclude]));
    setClownIndices(getRandomUnique(2, [...startExclude]));
  }, [boardSpaces.length, getRandomUnique]);

  // Particle and Time Tickers
  useEffect(() => {
    const ticker = setInterval(() => {
      // Sweets Time
      setActiveSweets(prev => prev.map(s => ({ ...s, timeLeft: Math.max(0, s.timeLeft - 1) })).filter(s => s.timeLeft > 0));

      // Particle Physics
      setParticles(prev => {
        if (prev.length === 0) return prev;
        return prev.map(p => {
          if (p.isFlying) {
            // Fly towards top-right (Sidebar area)
            const targetX = (window.innerWidth - 200) / APP_SCALE;
            const targetY = 100 / APP_SCALE;
            const dx = targetX - p.x;
            const dy = targetY - p.y;
            const dist = Math.sqrt(dx*dx + dy*dy);
            if (dist < 10) return null;
            return {
              ...p,
              x: p.x + dx * 0.15,
              y: p.y + dy * 0.15
            };
          } else {
            // Initial Explosion
            const nextX = p.x + p.vx;
            const nextY = p.y + p.vy;
            const nextVx = p.vx * 0.95;
            const nextVy = p.vy * 0.95;
            if (Math.abs(nextVx) < 0.1 && Math.abs(nextVy) < 0.1) {
              return { ...p, isFlying: true };
            }
            return { ...p, x: nextX, y: nextY, vx: nextVx, vy: nextVy };
          }
        }).filter(Boolean) as Particle[];
      });
    }, 50);
    return () => clearInterval(ticker);
  }, []);

  const spawnExplosion = (startX: number, startY: number, points: number) => {
    const count = 15;
    const newParticles: Particle[] = [];
    for (let i = 0; i < count; i++) {
      const angle = (Math.PI * 2 * i) / count;
      const speed = Math.random() * 8 + 4;
      newParticles.push({
        id: Math.random(),
        emoji: EXPLOSION_POOL[Math.floor(Math.random() * EXPLOSION_POOL.length)],
        x: startX,
        y: startY,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        isFlying: false
      });
    }
    setParticles(prev => [...prev, ...newParticles]);
    setRewardPoints(p => p + points);
  };

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      stepsDone++;

      // Update active sweets
      setActiveSweets(prev => {
        const next = prev.map(s => {
          const remainingSteps = Math.max(0, s.steps - 1);
          return { ...s, steps: remainingSteps };
        });
        return next;
      });

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        // Effects
        if (ghostIndices.includes(finalPos)) setIsGrayscale(true);
        if (rainbowIndices.includes(finalPos)) setIsGrayscale(false);
        if (clownIndices.includes(finalPos)) setIsClownMode(true);

        // Enemies
        setActiveZombies(prev => {
          let hit = false;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + 2) % TOTAL_TILES;
            if (nextZPos === finalPos) hit = true;
            return { ...z, pos: nextZPos };
          });
          if (hit) {
            setPlayerHealth(h => Math.max(0, h - 1));
          }
          return moved;
        });

        if (zombieIndicators.includes(finalPos)) {
          setActiveZombies(z => [...z, { id: Math.random().toString(), pos: (finalPos - 5 + TOTAL_TILES) % TOTAL_TILES, health: 5, isActive: true }]);
        }
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, ghostIndices, rainbowIndices, clownIndices, zombieIndicators]);

  // Handle sweets explosion when steps reach zero
  useEffect(() => {
    activeSweets.forEach(s => {
      if (s.steps === 0) {
        // Find position for explosion
        const leftSideX = (window.innerWidth - SIDEBAR_WIDTH) / 2 / APP_SCALE - 200;
        const centerY = window.innerHeight / 2 / APP_SCALE;
        // Approximation of the sweet's layout position
        let x = leftSideX;
        let y = centerY;
        if (s.id === '🍦') { x -= 40; y -= 40; }
        if (s.id === '🍰') { x += 40; y -= 40; }
        if (s.id === '🎂') { x += 0; y += 40; }

        spawnExplosion(x, y, s.points);
        setActiveSweets(prev => prev.filter(item => item.id !== s.id));
      }
    });
  }, [activeSweets]);

  const handleRoll = (landing: { x: number, y: number }, index: number) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);

    const nextRolls = rollsSinceSweets + 1;
    if (nextRolls >= 5) {
      setActiveSweets([
        { id: '🍦', emoji: '🍦', steps: 12, maxSteps: 12, timeLeft: 2*3600, totalTime: 2*3600, points: 10, sizeMultiplier: 3, active: true },
        { id: '🍰', emoji: '🍰', steps: 18, maxSteps: 18, timeLeft: 4*3600, totalTime: 4*3600, points: 20, sizeMultiplier: 3, active: true },
        { id: '🎂', emoji: '🎂', steps: 28, maxSteps: 28, timeLeft: 8*3600, totalTime: 8*3600, points: 30, sizeMultiplier: 5, active: true },
      ]);
      setRollsSinceSweets(0);
    } else {
      setRollsSinceSweets(nextRolls);
    }

    const diceCount = isGrayscale ? 3 : 1;
    const newValues = Array.from({ length: diceCount }, () => Math.floor(Math.random() * 6) + 1);
    setDiceValues(newValues);

    setTimeout(() => {
      setIsRolling(false);
      setIsMoving(true);
      processMovement(newValues.reduce((a, b) => a + b, 0));
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  return (
    <div className={`h-screen w-screen flex bg-white dark:bg-zinc-950 transition-all duration-700 ${isGrayscale ? 'filter grayscale' : ''}`}>
      {isWinterMode && <div className="fixed inset-0 z-10 pointer-events-none snow-effect" />}

      {/* Game View */}
      <div ref={gameAreaRef} className="flex-1 relative overflow-hidden notion-grid">
        <div className="relative w-full h-full flex items-center justify-center origin-top-left" style={{ transform: `scale(${APP_SCALE})` }}>
          <div className="relative w-full h-full">

            {/* Particles */}
            {particles.map(p => (
              <div key={p.id} className="absolute z-[100] transition-all duration-300 pointer-events-none" style={{ left: p.x, top: p.y, fontSize: '20px' }}>
                {p.emoji}
              </div>
            ))}

            {/* Board Tiles */}
            {boardSpaces.map(s => (
              <div key={s.id} className="absolute sudoku-tile flex items-center justify-center" style={{ left: s.x, top: s.y, width: tileSize, height: tileSize, backgroundColor: isClownMode ? `hsl(${s.id * 15 % 360}, 70%, 50%)` : undefined }}>
                <span className="text-[5px] opacity-20 absolute top-0.5 left-0.5 font-bold">{s.id + 1}</span>
                {zombieIndicators.includes(s.id) && <span className="opacity-20 text-xs">🧟</span>}
              </div>
            ))}

            {/* Central Area: Left | Center | Right */}
            <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
                <div className="flex items-center gap-16 translate-y-6">

                    {/* LEFT: Sweets Inverted Triangle */}
                    <div className="flex flex-col items-center gap-4 min-w-[200px]">
                      <div className="flex gap-12">
                        {activeSweets.filter(s => s.id !== '🎂').map(s => (
                          <div key={s.id} className="flex flex-col items-center relative animate-bounce" style={{ animationDuration: '3s' }}>
                             <span className="leading-none drop-shadow-xl select-none" style={{ fontSize: tileSize * s.sizeMultiplier }}>{s.emoji}</span>
                             <div className="mt-2 w-16 h-1 bg-gray-200 dark:bg-white/10 rounded-full overflow-hidden">
                                <div className="h-full bg-pink-500" style={{ width: `${(s.steps / s.maxSteps) * 100}%` }} />
                             </div>
                             <span className="text-[7px] font-black uppercase tracking-widest mt-1 opacity-60">{s.steps} steps</span>
                          </div>
                        ))}
                      </div>
                      {activeSweets.find(s => s.id === '🎂') && (
                        <div className="flex flex-col items-center relative animate-bounce" style={{ animationDuration: '4s' }}>
                           <span className="leading-none drop-shadow-2xl select-none" style={{ fontSize: tileSize * 5 }}>🎂</span>
                           <div className="mt-2 w-24 h-1.5 bg-gray-200 dark:bg-white/10 rounded-full overflow-hidden">
                              <div className="h-full bg-pink-500" style={{ width: `${(activeSweets.find(s => s.id === '🎂')!.steps / 28) * 100}%` }} />
                           </div>
                           <span className="text-[8px] font-black uppercase tracking-widest mt-1 opacity-60">{activeSweets.find(s => s.id === '🎂')!.steps} steps</span>
                        </div>
                      )}
                    </div>

                    {/* CENTER: Jar */}
                    <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={() => setIsExploding(true)} height={tileSize * 5} />

                    {/* RIGHT: Bosses */}
                    <div className="flex flex-col items-center gap-10 min-w-[150px]">
                      {pumpkinBoss.isActive && <span className="text-6xl animate-pulse">🎃</span>}
                      {demonBoss.isActive && <span className="text-6xl animate-bounce">👹</span>}
                    </div>
                </div>
            </div>

            {/* Player Piece */}
            <div className="absolute z-30 transition-all duration-300" style={{ left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, transform: 'translate(-50%, -60%)', fontSize: tileSize * 1.3 }}>
               <div className="flex flex-col items-center">
                  <div className="flex gap-0.5 mb-1 bg-white/80 p-0.5 rounded-full px-1.5 border border-black/5">
                    {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => <div key={i} className={`w-1.5 h-0.5 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />)}
                  </div>
                  <span>{isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}</span>
               </div>
            </div>

            {/* Enemies */}
            {activeZombies.map(z => (
              <div key={z.id} className="absolute z-20 transition-all duration-700" style={{ left: boardSpaces[z.pos].x + tileSize/2, top: boardSpaces[z.pos].y + tileSize/2, transform: 'translate(-50%, -50%)', fontSize: tileSize }}>
                {ENEMY_ICON}
              </div>
            ))}
          </div>
        </div>

        {Array.from({ length: isGrayscale ? 3 : 1 }).map((_, i) => (
          <Dice3D 
            key={i} color={diceColor} value={diceValues[i] || 1} isRolling={isRolling} 
            currentPos={dicePositions[i]} 
            onRoll={(p) => handleRoll(p, i)} 
            onDragEnd={(p) => setDicePositions(prev => { const n = [...prev]; n[i] = p; return n; })} 
            scale={isClownMode ? 3.5 : 1}
          />
        ))}
      </div>

      {/* Sidebar - Notion Inspired */}
      <div className="w-[380px] h-full bg-[#fbfbfa] dark:bg-[#191919] border-l border-[#efefef] dark:border-white/5 flex flex-col z-50">
        <div className="p-4 flex flex-col h-full">
          {/* Header (1/10) */}
          <div className="flex items-center justify-between py-2 border-b border-[#eee] dark:border-white/5 mb-4">
            <div className="flex items-center gap-3">
              <div className="flex items-center gap-2">
                <span className="text-xl">🎁</span>
                <span className="text-[18px] font-black tabular-nums">{rewardPoints}</span>
              </div>
            </div>
            <div className="flex items-center gap-1">
              <div className="mr-2 pr-2 border-r border-gray-200 dark:border-gray-800">
                <span className="text-[16px] font-black">⚡ {rollBank}</span>
              </div>
              <button onClick={() => setIsWinterMode(!isWinterMode)} className="p-1.5 text-sm">❄️</button>
              <button onClick={() => setDarkMode(!darkMode)} className="p-1.5 text-sm">{darkMode ? '☀️' : '🌙'}</button>
            </div>
          </div>

          {/* Quests (9/10) */}
          <div className="flex-1 flex flex-col overflow-hidden">
             <div className="flex items-center justify-between mb-6">
                <h1 className="text-[14px] font-bold opacity-90">📋 Quests</h1>
                <div className="flex gap-4">
                   <button onClick={() => setShowHistory(false)} className={`text-[12px] font-medium ${!showHistory ? 'text-indigo-600 underline' : 'opacity-40'}`}>Active</button>
                   <button onClick={() => setShowHistory(true)} className={`text-[12px] font-medium ${showHistory ? 'text-indigo-600 underline' : 'opacity-40'}`}>Logbook</button>
                </div>
             </div>

             <div className="flex-1 overflow-y-auto custom-scrollbar">
                {!showHistory ? (
                   <div className="flex flex-col gap-1">
                      {tasks.map(t => (
                        <div key={t.id} onClick={() => handleTaskComplete(t)} className="group flex items-start gap-3 p-2 hover:bg-[#f3f3f2] dark:hover:bg-white/5 rounded-lg transition-all cursor-pointer">
                           <div className="mt-0.5 w-4.5 h-4.5 rounded-[4px] border border-[#ccc] dark:border-white/20 group-hover:bg-indigo-500 transition-all flex items-center justify-center">
                              <div className="w-2 h-2 bg-white rounded-[1px] opacity-0 group-hover:opacity-100" />
                           </div>
                           <p className="text-[14px] leading-[1.4] opacity-80">{t.text}</p>
                        </div>
                      ))}
                      <div className="mt-4 border-t border-[#efefef] dark:border-white/5 pt-6">
                        <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([...tasks, { id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }]); setNewTask(''); }}>
                           <input value={newTask} onChange={e => setNewTask(e.target.value)} placeholder="+ New mission..." className="w-full py-2 bg-transparent outline-none text-[15px] placeholder:opacity-40" />
                        </form>
                      </div>
                   </div>
                ) : (
                  <div className="flex flex-col gap-2">
                     {history.map(h => (
                       <div key={h.id} className="p-3 bg-black/[0.01] dark:bg-white/[0.01] rounded-lg opacity-60">
                          <p className="text-[13px] line-through">{h.text}</p>
                          <span className="text-[9px] font-black opacity-30 mt-2 block">{h.completedAt}</span>
                       </div>
                     ))}
                  </div>
                )}
             </div>
          </div>
        </div>
      </div>

      <style>{`
        .notion-grid { background-image: radial-gradient(#efefef 1px, transparent 1px); background-size: 20px 20px; }
        .dark .notion-grid { background-image: radial-gradient(rgba(255,255,255,0.05) 1px, transparent 1px); }
        .snow-effect { background-image: radial-gradient(circle, #fff 10%, transparent 10%), radial-gradient(circle, #fff 10%, transparent 10%); background-size: 15px 15px, 25px 25px; animation: snow-fall 10s linear infinite; opacity: 0.5; }
        @keyframes snow-fall { 0% { background-position: 0 0, 50px 50px; } 100% { background-position: 100px 500px, 150px 1000px; } }
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.08); border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss, Gift, Resources } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

const ZOMBIE_INDICATOR_COUNT = 10; 
const BOMB_COUNT = 10;           
const MAX_PLAYER_HEALTH = 5; 

const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 

const APP_SCALE = 1.25; 
const SIDEBAR_WIDTH = 380;

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', 
  '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🐾',
  '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤',
  '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const EXPLOSION_POOL = [
  '🍦','🍧','🍨','🍩','🍪','🎂','🍰','🧁','🥧','🍫','🍬','🍭','🍮',
  '🍇','🍈','🍉','🍊','🍋','🍋‍🟩','🍌','🍍','🥭','🍎','🍏','🍐','🍑','🍒','🍓','🫐','🥝','🍅','🫒','🥥'
];

interface Particle {
  id: number;
  emoji: string;
  x: number;
  y: number;
  vx: number;
  vy: number;
  isFlying: boolean;
}

interface SweetGoal {
  id: string;
  emoji: string;
  steps: number;
  maxSteps: number;
  timeLeft: number;
  totalTime: number;
  points: number;
  sizeMultiplier: number;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [isWinterMode, setIsWinterMode] = useState(false);
  const [diceColor, setDiceColor] = useState('rgba(255, 255, 255, 0.4)');
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  const [rewardPoints, setRewardPoints] = useState(0);
  const [rollsSinceSweets, setRollsSinceSweets] = useState(0);
  const [particles, setParticles] = useState<Particle[]>([]);
  const [activeSweets, setActiveSweets] = useState<SweetGoal[]>([]);

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<(Task & { completedAt: string })[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValues, setDiceValues] = useState<number[]>([1, 1, 1]);
  const [isRolling, setIsRolling] = useState(false);

  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2, y: window.innerHeight / 2 },
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2 - 80, y: window.innerHeight / 2 },
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2 + 80, y: window.innerHeight / 2 }
  ]);

  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });

  const gameAreaRef = useRef<HTMLDivElement>(null);

  const ENEMY_ICON = isWinterMode ? '⛄' : (darkMode ? '🧛🏻' : '🧟');

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(48);

  useEffect(() => {
    const updateSize = () => {
      const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
      const availableH = window.innerHeight / APP_SCALE;
      const horizontalLimit = (availableW - 60) / BOARD_W;
      const verticalLimit = (availableH - 60) / BOARD_H;
      const bestSize = Math.max(25, Math.min(horizontalLimit, verticalLimit, 45));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
    const availableH = window.innerHeight / APP_SCALE;
    const boardRealW = (BOARD_W - 1) * tileSize;
    const boardRealH = (BOARD_H - 1) * tileSize;
    const startX = (availableW - boardRealW) / 2;
    const startY = (availableH - boardRealH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    setZombieIndicators(getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude));
    setBombIndices(getRandomUnique(BOMB_COUNT, startExclude));
    setPumpkinIndices(getRandomUnique(5, startExclude));
    setDemonIndices(getRandomUnique(5, startExclude));
    setCloverIndices(getRandomUnique(5, startExclude));
    setGhostIndices(getRandomUnique(3, startExclude));
    setRainbowIndices(getRandomUnique(3, startExclude));
    setClownIndices(getRandomUnique(2, startExclude));
  }, [boardSpaces.length, getRandomUnique]);

  useEffect(() => {
    const ticker = setInterval(() => {
      // Sweets Time Limit
      setActiveSweets(prev => prev.map(s => ({ ...s, timeLeft: Math.max(0, s.timeLeft - 1) })).filter(s => s.timeLeft > 0));

      // Particle Physics
      setParticles(prev => {
        if (prev.length === 0) return prev;
        return prev.map(p => {
          if (p.isFlying) {
            const targetX = (window.innerWidth - 100) / APP_SCALE;
            const targetY = 100 / APP_SCALE;
            const dx = targetX - p.x;
            const dy = targetY - p.y;
            const dist = Math.sqrt(dx*dx + dy*dy);
            if (dist < 15) return null;
            return {
              ...p,
              x: p.x + dx * 0.1,
              y: p.y + dy * 0.1
            };
          } else {
            const nextX = p.x + p.vx;
            const nextY = p.y + p.vy;
            const nextVx = p.vx * 0.94;
            const nextVy = p.vy * 0.94;
            if (Math.abs(nextVx) < 0.2 && Math.abs(nextVy) < 0.2) {
              return { ...p, isFlying: true };
            }
            return { ...p, x: nextX, y: nextY, vx: nextVx, vy: nextVy };
          }
        }).filter(Boolean) as Particle[];
      });
    }, 40);
    return () => clearInterval(ticker);
  }, []);

  const triggerExplosion = (emoji: string, points: number) => {
    // Relative coordinates for the sweets layout area (Left of Jar)
    const centerX = (window.innerWidth - SIDEBAR_WIDTH) / 2 / APP_SCALE;
    const centerY = window.innerHeight / 2 / APP_SCALE;
    const startX = centerX - 180; // Left side of jar
    const startY = centerY;

    const count = 20;
    const newParticles: Particle[] = [];
    for (let i = 0; i < count; i++) {
      const angle = (Math.PI * 2 * i) / count;
      const speed = Math.random() * 12 + 5;
      newParticles.push({
        id: Math.random(),
        emoji: EXPLOSION_POOL[Math.floor(Math.random() * EXPLOSION_POOL.length)],
        x: startX,
        y: startY,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        isFlying: false
      });
    }
    setParticles(prev => [...prev, ...newParticles]);
    setRewardPoints(p => p + points);
  };

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      stepsDone++;

      // Progress active sweets steps
      setActiveSweets(prev => prev.map(s => ({ ...s, steps: Math.max(0, s.steps - 1) })));

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (ghostIndices.includes(finalPos)) setIsGrayscale(true);
        if (rainbowIndices.includes(finalPos)) setIsGrayscale(false);
        if (clownIndices.includes(finalPos)) setIsClownMode(true);

        setActiveZombies(prev => {
          let hit = false;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + 2) % TOTAL_TILES;
            if (nextZPos === finalPos) hit = true;
            return { ...z, pos: nextZPos };
          });
          if (hit) setPlayerHealth(h => Math.max(0, h - 1));
          return moved;
        });

        if (zombieIndicators.includes(finalPos)) {
          setActiveZombies(z => [...z, { id: Math.random().toString(), pos: (finalPos - 5 + TOTAL_TILES) % TOTAL_TILES, health: 5, isActive: true }]);
        }
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, ghostIndices, rainbowIndices, clownIndices, zombieIndicators]);

  // Monitor sweet completion
  useEffect(() => {
    activeSweets.forEach(s => {
      if (s.steps === 0) {
        triggerExplosion(s.emoji, s.points);
        setActiveSweets(prev => prev.filter(item => item.id !== s.id));
      }
    });
  }, [activeSweets]);

  const handleRoll = (landing: { x: number, y: number }, index: number) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);

    const nextRolls = rollsSinceSweets + 1;
    if (nextRolls >= 5) {
      setActiveSweets([
        { id: 'ice', emoji: '🍦', steps: 12, maxSteps: 12, timeLeft: 2*3600, totalTime: 2*3600, points: 10, sizeMultiplier: 3 },
        { id: 'cake', emoji: '🍰', steps: 18, maxSteps: 18, timeLeft: 4*3600, totalTime: 4*3600, points: 20, sizeMultiplier: 3 },
        { id: 'bigcake', emoji: '🎂', steps: 28, maxSteps: 28, timeLeft: 8*3600, totalTime: 8*3600, points: 30, sizeMultiplier: 5 },
      ]);
      setRollsSinceSweets(0);
    } else {
      setRollsSinceSweets(nextRolls);
    }

    const diceCount = isGrayscale ? 3 : 1;
    const newValues = Array.from({ length: diceCount }, () => Math.floor(Math.random() * 6) + 1);
    setDiceValues(newValues);

    setTimeout(() => {
      setIsRolling(false);
      setIsMoving(true);
      processMovement(newValues.reduce((a, b) => a + b, 0));
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  return (
    <div className={`h-screen w-screen flex bg-white dark:bg-zinc-950 transition-all duration-700 ${isGrayscale ? 'filter grayscale' : ''} ${isExploding ? 'bg-indigo-600/10' : ''}`}>
      {isWinterMode && <div className="fixed inset-0 z-10 pointer-events-none snow-effect" />}

      <div ref={gameAreaRef} className="flex-1 relative overflow-hidden notion-grid">
        <div className="relative w-full h-full flex items-center justify-center origin-top-left" style={{ transform: `scale(${APP_SCALE})` }}>
          <div className="relative w-full h-full">

            {/* Particles */}
            {particles.map(p => (
              <div key={p.id} className="absolute z-[100] transition-all duration-300 pointer-events-none" style={{ left: p.x, top: p.y, fontSize: '24px' }}>
                {p.emoji}
              </div>
            ))}

            {/* Tiles */}
            {boardSpaces.map(s => (
              <div key={s.id} className="absolute sudoku-tile flex items-center justify-center" style={{ left: s.x, top: s.y, width: tileSize, height: tileSize, backgroundColor: isClownMode ? `hsl(${s.id * 18 % 360}, 60%, 50%)` : undefined }}>
                <span className="text-[5px] opacity-20 absolute top-0.5 left-0.5 font-bold">{s.id + 1}</span>
                {zombieIndicators.includes(s.id) && <span className="opacity-10 text-xs">{ENEMY_ICON}</span>}
              </div>
            ))}

            {/* Center Area */}
            <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
                <div className="flex items-center gap-16 translate-y-6">

                    {/* LEFT: Sweets layout */}
                    <div className="flex flex-col items-center gap-6 min-w-[240px]">
                      <div className="flex gap-14">
                        {activeSweets.filter(s => s.id !== 'bigcake').map(s => (
                          <div key={s.id} className="flex flex-col items-center relative animate-bounce" style={{ animationDuration: '3s' }}>
                             <span className="leading-none drop-shadow-xl" style={{ fontSize: tileSize * s.sizeMultiplier }}>{s.emoji}</span>
                             <div className="mt-2 w-20 h-1.5 bg-gray-100 dark:bg-white/5 rounded-full overflow-hidden border border-black/5">
                                <div className="h-full bg-pink-500 transition-all duration-300" style={{ width: `${(s.steps / s.maxSteps) * 100}%` }} />
                             </div>
                             <span className="text-[7px] font-black uppercase mt-1 opacity-50">{s.steps} steps left</span>
                          </div>
                        ))}
                      </div>
                      {activeSweets.find(s => s.id === 'bigcake') && (
                        <div className="flex flex-col items-center relative animate-bounce" style={{ animationDuration: '4s' }}>
                           <span className="leading-none drop-shadow-2xl" style={{ fontSize: tileSize * 5 }}>🎂</span>
                           <div className="mt-2 w-32 h-2 bg-gray-100 dark:bg-white/5 rounded-full overflow-hidden border border-black/5">
                              <div className="h-full bg-pink-500 transition-all duration-300" style={{ width: `${(activeSweets.find(s => s.id === 'bigcake')!.steps / 28) * 100}%` }} />
                           </div>
                           <span className="text-[8px] font-black uppercase mt-1 opacity-60">{activeSweets.find(s => s.id === 'bigcake')!.steps} steps left</span>
                        </div>
                      )}
                    </div>

                    {/* CENTER: Jar */}
                    <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={() => setIsExploding(true)} height={tileSize * 5} />

                    {/* RIGHT: Bosses */}
                    <div className="flex flex-col items-center gap-10 min-w-[150px]">
                      {pumpkinBoss.isActive && <span className="text-7xl">🎃</span>}
                      {demonBoss.isActive && <span className="text-7xl">👹</span>}
                    </div>
                </div>
            </div>

            {/* Player */}
            <div className="absolute z-30 transition-all duration-300" style={{ left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, transform: 'translate(-50%, -60%)', fontSize: tileSize * 1.3 }}>
               <div className="flex flex-col items-center">
                  <div className="flex gap-0.5 mb-1 bg-white/80 p-0.5 rounded-full px-1.5 border border-black/5">
                    {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => <div key={i} className={`w-1.5 h-0.5 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />)}
                  </div>
                  <span>{isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}</span>
               </div>
            </div>

            {/* Enemies */}
            {activeZombies.map(z => (
              <div key={z.id} className="absolute z-20 transition-all duration-700" style={{ left: boardSpaces[z.pos].x + tileSize/2, top: boardSpaces[z.pos].y + tileSize/2, transform: 'translate(-50%, -50%)', fontSize: tileSize }}>
                {ENEMY_ICON}
              </div>
            ))}
          </div>
        </div>

        {Array.from({ length: isGrayscale ? 3 : 1 }).map((_, i) => (
          <Dice3D 
            key={i} color={diceColor} value={diceValues[i] || 1} isRolling={isRolling} 
            currentPos={dicePositions[i] ?? { x: 0, y: 0 }} 
            onRoll={(p) => handleRoll(p, i)} 
            onDragEnd={(p) => setDicePositions(prev => { const n = [...prev]; n[i] = p; return n; })} 
            scale={isClownMode ? 3.5 : 1}
          />
        ))}
      </div>

      <div className="w-[380px] h-full bg-[#fbfbfa] dark:bg-[#191919] border-l border-[#efefef] dark:border-white/5 flex flex-col z-50">
        <div className="p-4 flex flex-col h-full">
          <div className="flex items-center justify-between py-2 border-b border-[#eee] dark:border-white/5 mb-4">
            <div className="flex items-center gap-3">
              <div className="flex items-center gap-2">
                <span className="text-2xl drop-shadow-sm">🎁</span>
                <span className="text-[20px] font-black tabular-nums">{rewardPoints}</span>
              </div>
            </div>
            <div className="flex items-center gap-1">
              <div className="mr-2 pr-2 border-r border-gray-200 dark:border-gray-800">
                <span className="text-[16px] font-black">⚡ {rollBank}</span>
              </div>
              <button onClick={() => setIsWinterMode(!isWinterMode)} className={`p-1.5 text-sm rounded ${isWinterMode ? 'bg-blue-100 text-blue-600' : 'opacity-40'}`}>❄️</button>
              <button onClick={() => setDarkMode(!darkMode)} className="p-1.5 text-sm">{darkMode ? '☀️' : '🌙'}</button>
            </div>
          </div>

          <div className="flex-1 flex flex-col overflow-hidden">
             <div className="flex items-center justify-between mb-6">
                <h1 className="text-[14px] font-bold opacity-90">📋 Quests</h1>
                <div className="flex gap-4">
                   <button onClick={() => setShowHistory(false)} className={`text-[12px] font-medium ${!showHistory ? 'text-indigo-600 underline' : 'opacity-40'}`}>Active</button>
                   <button onClick={() => setShowHistory(true)} className={`text-[12px] font-medium ${showHistory ? 'text-indigo-600 underline' : 'opacity-40'}`}>Logbook</button>
                </div>
             </div>

             <div className="flex-1 overflow-y-auto custom-scrollbar">
                {!showHistory ? (
                   <div className="flex flex-col gap-1">
                      {tasks.map(t => (
                        <div key={t.id} onClick={() => handleTaskComplete(t)} className="group flex items-start gap-3 p-2 hover:bg-[#f3f3f2] dark:hover:bg-white/5 rounded-lg transition-all cursor-pointer">
                           <div className="mt-0.5 w-4.5 h-4.5 rounded-[4px] border border-[#ccc] dark:border-white/20 group-hover:bg-indigo-500 transition-all flex items-center justify-center">
                              <div className="w-2 h-2 bg-white rounded-[1px] opacity-0 group-hover:opacity-100" />
                           </div>
                           <p className="text-[14px] leading-[1.4] opacity-80">{t.text}</p>
                        </div>
                      ))}
                      <div className="mt-4 border-t border-[#efefef] dark:border-white/5 pt-6">
                        <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([...tasks, { id: Date.now().toString(), text: newTask, completed: false }]); setNewTask(''); }}>
                           <input value={newTask} onChange={e => setNewTask(e.target.value)} placeholder="+ New mission..." className="w-full py-2 bg-transparent outline-none text-[15px] placeholder:opacity-40" />
                        </form>
                      </div>
                   </div>
                ) : (
                  <div className="flex flex-col gap-2">
                     {history.map(h => (
                       <div key={h.id} className="p-3 bg-black/[0.01] dark:bg-white/[0.01] rounded-lg opacity-60">
                          <p className="text-[13px] line-through">{h.text}</p>
                          <span className="text-[9px] font-black opacity-30 mt-2 block">{h.completedAt}</span>
                       </div>
                     ))}
                  </div>
                )}
             </div>
          </div>
        </div>
      </div>

      <style>{`
        .notion-grid { background-image: radial-gradient(#efefef 1px, transparent 1px); background-size: 20px 20px; }
        .dark .notion-grid { background-image: radial-gradient(rgba(255,255,255,0.05) 1px, transparent 1px); }
        .snow-effect { background-image: radial-gradient(circle, #fff 10%, transparent 10%), radial-gradient(circle, #fff 10%, transparent 10%); background-size: 15px 15px, 25px 25px; animation: snow-fall 10s linear infinite; opacity: 0.5; }
        @keyframes snow-fall { 0% { background-position: 0 0, 50px 50px; } 100% { background-position: 100px 500px, 150px 1000px; } }
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.08); border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';

interface Dice3DProps {
  value: number;
  isRolling: boolean;
  onRoll: (landingPos: { x: number; y: number }) => void;
  onDragEnd: (finalPos: { x: number; y: number }) => void;
  currentPos: { x: number; y: number };
  color?: string;
  scale?: number;
}

export const Dice3D: React.FC<Dice3DProps> = ({ 
  value, 
  isRolling, 
  onRoll, 
  onDragEnd, 
  currentPos, 
  color = 'rgba(255, 255, 255, 0.3)',
  scale = 1
}) => {
  // Added fallback to avoid TypeError: Cannot read properties of undefined (reading 'x')
  const safeCurrentPos = currentPos ?? { x: window.innerWidth / 2, y: window.innerHeight / 2 };
  const [pos, setPos] = useState(safeCurrentPos);
  const [isDragging, setIsDragging] = useState(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const elementPosStart = useRef({ x: 0, y: 0 });

  useEffect(() => {
    if (!isRolling && !isDragging) {
      setPos(safeCurrentPos);
    }
  }, [safeCurrentPos, isRolling, isDragging]);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (isRolling) return;
    setIsDragging(true);
    dragStart.current = { x: e.clientX, y: e.clientY };
    elementPosStart.current = { x: pos.x, y: pos.y };
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;
      const dx = e.clientX - dragStart.current.x;
      const dy = e.clientY - dragStart.current.y;
      setPos({
        x: elementPosStart.current.x + dx,
        y: elementPosStart.current.y + dy
      });
    };

    const handleMouseUp = () => {
      if (isDragging) {
        setIsDragging(false);
        onDragEnd(pos);
      }
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, pos, onDragEnd]);

  const getRotation = (v: number) => {
    switch (v) {
      case 1: return 'rotateX(0deg) rotateY(0deg)';
      case 2: return 'rotateY(-90deg)';
      case 3: return 'rotateY(90deg)';
      case 4: return 'rotateY(180deg)';
      case 5: return 'rotateX(-90deg)';
      case 6: return 'rotateX(90deg)';
      default: return 'rotateX(0deg)';
    }
  };

  const rollingRotation = isRolling 
    ? `rotateX(${Math.random() * 720 + 360}deg) rotateY(${Math.random() * 720 + 360}deg)`
    : getRotation(value);

  const triggerRoll = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (isRolling) return;
    const landingX = Math.max(100, Math.min(window.innerWidth - 100, pos.x + (Math.random() - 0.5) * 200));
    const landingY = Math.max(100, Math.min(window.innerHeight - 100, pos.y + (Math.random() - 0.5) * 200));
    onRoll({ x: landingX, y: landingY });
  };

  const faceStyle = {
    background: color,
  };

  const baseScale = isDragging ? 1.1 : (isRolling ? 1.3 : 1);
  const finalScale = baseScale * scale;

  return (
    <div 
      className={`fixed z-[60] transition-all ${isRolling ? 'duration-[1200ms]' : 'duration-75'} select-none cursor-grab active:cursor-grabbing`}
      style={{ 
        left: `${pos.x}px`, 
        top: `${pos.y}px`,
        transform: `translate(-50%, -50%) scale(${finalScale})`
      }}
      onMouseDown={handleMouseDown}
      onDoubleClick={triggerRoll}
    >
      <div className="dice-container">
        <div className="dice" style={{ transform: rollingRotation }}>
          <div className="dice-face front" style={faceStyle}><div className="dot"></div></div>
          <div className="dice-face back" style={faceStyle}>
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '15%', left: '60%' }}></div>
             <div className="dot" style={{ top: '60%', left: '15%' }}></div>
             <div className="dot" style={{ top: '60%', left: '60%' }}></div>
          </div>
