import React, { useState, useRef, useEffect } from 'react';

interface Dice3DProps {
  value: number;
  isRolling: boolean;
  onRoll: (landingPos: { x: number; y: number }) => void;
  onDragEnd: (finalPos: { x: number; y: number }) => void;
  currentPos: { x: number; y: number };
  color?: string;
  scale?: number;
}

export const Dice3D: React.FC<Dice3DProps> = ({ 
  value, 
  isRolling, 
  onRoll, 
  onDragEnd, 
  currentPos, 
  color = 'rgba(255, 255, 255, 0.3)',
  scale = 1
}) => {
  // Use a safe fallback for currentPos to prevent TypeError
  const safePos = currentPos ?? { x: window.innerWidth / 2, y: window.innerHeight / 2 };
  const [pos, setPos] = useState(safePos);
  const [isDragging, setIsDragging] = useState(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const elementPosStart = useRef({ x: 0, y: 0 });

  useEffect(() => {
    if (!isRolling && !isDragging) {
      setPos(safePos);
    }
  }, [safePos, isRolling, isDragging]);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (isRolling) return;
    setIsDragging(true);
    dragStart.current = { x: e.clientX, y: e.clientY };
    elementPosStart.current = { x: pos.x, y: pos.y };
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;
      const dx = e.clientX - dragStart.current.x;
      const dy = e.clientY - dragStart.current.y;
      setPos({
        x: elementPosStart.current.x + dx,
        y: elementPosStart.current.y + dy
      });
    };

    const handleMouseUp = () => {
      if (isDragging) {
        setIsDragging(false);
        onDragEnd(pos);
      }
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, pos, onDragEnd]);

  const getRotation = (v: number) => {
    switch (v) {
      case 1: return 'rotateX(0deg) rotateY(0deg)';
      case 2: return 'rotateY(-90deg)';
      case 3: return 'rotateY(90deg)';
      case 4: return 'rotateY(180deg)';
      case 5: return 'rotateX(-90deg)';
      case 6: return 'rotateX(90deg)';
      default: return 'rotateX(0deg)';
    }
  };

  const rollingRotation = isRolling 
    ? `rotateX(${Math.random() * 720 + 360}deg) rotateY(${Math.random() * 720 + 360}deg)`
    : getRotation(value);

  const triggerRoll = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (isRolling) return;
    const landingX = Math.max(100, Math.min(window.innerWidth - 100, pos.x + (Math.random() - 0.5) * 200));
    const landingY = Math.max(100, Math.min(window.innerHeight - 100, pos.y + (Math.random() - 0.5) * 200));
    onRoll({ x: landingX, y: landingY });
  };

  const faceStyle = {
    background: color,
  };

  const baseScale = isDragging ? 1.1 : (isRolling ? 1.3 : 1);
  const finalScale = baseScale * scale;

  return (
    <div 
      className={`fixed z-[60] transition-all ${isRolling ? 'duration-[1200ms]' : 'duration-75'} select-none cursor-grab active:cursor-grabbing`}
      style={{ 
        left: `${pos.x}px`, 
        top: `${pos.y}px`,
        transform: `translate(-50%, -50%) scale(${finalScale})`
      }}
      onMouseDown={handleMouseDown}
      onDoubleClick={triggerRoll}
    >
      <div className="dice-container">
        <div className="dice" style={{ transform: rollingRotation }}>
          <div className="dice-face front" style={faceStyle}><div className="dot"></div></div>
          <div className="dice-face back" style={faceStyle}>
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '15%', left: '60%' }}></div>
             <div className="dot" style={{ top: '60%', left: '15%' }}></div>
             <div className="dot" style={{ top: '60%', left: '60%' }}></div>
          </div>
          <div className="dice-face right" style={faceStyle}>
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '40%', left: '40%' }}></div>
             <div className="dot" style={{ top: '65%', left: '65%' }}></div>
          </div>
          <div className="dice-face left" style={faceStyle}>
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '65%', left: '65%' }}></div>
          </div>
          <div className="dice-face top" style={faceStyle}>
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '15%', left: '60%' }}></div>
             <div className="dot" style={{ top: '40%', left: '40%' }}></div>
             <div className="dot" style={{ top: '65%', left: '15%' }}></div>
             <div className="dot" style={{ top: '65%', left: '65%' }}></div>
          </div>
          <div className="dice-face bottom" style={faceStyle}>
             <div className="dot" style={{ top: '15%', left: '15%' }}></div>
             <div className="dot" style={{ top: '15%', left: '60%' }}></div>
             <div className="dot" style={{ top: '40%', left: '15%' }}></div>
             <div className="dot" style={{ top: '40%', left: '60%' }}></div>
             <div className="dot" style={{ top: '65%', left: '15%' }}></div>
             <div className="dot" style={{ top: '65%', left: '65%' }}></div>
          </div>
        </div>
      </div>
      {!isRolling && scale < 2 && (
          <div className="absolute -bottom-6 left-1/2 -translate-x-1/2 text-[9px] font-bold opacity-30 uppercase tracking-tighter whitespace-nowrap">Double Click</div>
      )}
    </div>
  );
};

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss, SweetGoal } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

const ZOMBIE_INDICATOR_COUNT = 10; 
const BOMB_COUNT = 10;           
const MAX_PLAYER_HEALTH = 5; 

const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 

const APP_SCALE = 1.25; 
const SIDEBAR_WIDTH = 380;

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', 
  '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🐾',
  '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤',
  '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const EXPLOSION_POOL = [
  '🍦','🍧','🍨','🍩','🍪','🎂','🍰','🧁','🥧','🍫','🍬','🍭','Pudding',
  '🍇','🍈','🍉','🍊','🍋','🍋‍🟩','🍌','🍍','🥭','🍎','🍏','🍐','🍑','🍒','🍓','🫐','🥝','🍅','🫒','🥥'
];

interface Particle {
  id: number;
  emoji: string;
  x: number;
  y: number;
  vx: number;
  vy: number;
  isFlying: boolean;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState('rgba(255, 255, 255, 0.4)');
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  const [rewardPoints, setRewardPoints] = useState(0);
  const [rollsSinceSweets, setRollsSinceSweets] = useState(0);
  const [particles, setParticles] = useState<Particle[]>([]);
  const [activeSweets, setActiveSweets] = useState<SweetGoal[]>([]);

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<(Task & { completedAt: string })[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValues, setDiceValues] = useState<number[]>([1, 1, 1]);
  const [isRolling, setIsRolling] = useState(false);

  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2, y: window.innerHeight / 2 },
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2 - 80, y: window.innerHeight / 2 },
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2 + 80, y: window.innerHeight / 2 }
  ]);

  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });

  const gameAreaRef = useRef<HTMLDivElement>(null);

  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(48);

  useEffect(() => {
    const updateSize = () => {
      const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
      const availableH = window.innerHeight / APP_SCALE;
      const horizontalLimit = (availableW - 60) / BOARD_W;
      const verticalLimit = (availableH - 60) / BOARD_H;
      const bestSize = Math.max(25, Math.min(horizontalLimit, verticalLimit, 45));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
    const availableH = window.innerHeight / APP_SCALE;
    const boardRealW = (BOARD_W - 1) * tileSize;
    const boardRealH = (BOARD_H - 1) * tileSize;
    const startX = (availableW - boardRealW) / 2;
    const startY = (availableH - boardRealH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    setZombieIndicators(getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude));
    setBombIndices(getRandomUnique(BOMB_COUNT, startExclude));
    setGhostIndices(getRandomUnique(3, startExclude));
    setRainbowIndices(getRandomUnique(3, startExclude));
    setClownIndices(getRandomUnique(2, startExclude));
  }, [boardSpaces.length, getRandomUnique]);

  // Main Ticker for Sweets Time and Particles
  useEffect(() => {
    const ticker = setInterval(() => {
      // Countdown time for sweets
      setActiveSweets(prev => prev.map(s => ({ ...s, timeLeft: Math.max(0, s.timeLeft - 1) })).filter(s => s.timeLeft > 0));

      // Update particles
      setParticles(prev => {
        if (prev.length === 0) return prev;
        return prev.map(p => {
          if (p.isFlying) {
            // Target the unified Gift Box 🎁 reward counter in the sidebar
            const targetX = (window.innerWidth - 100) / APP_SCALE;
            const targetY = 100 / APP_SCALE;
            const dx = targetX - p.x;
            const dy = targetY - p.y;
            const dist = Math.sqrt(dx*dx + dy*dy);
            if (dist < 15) return null;
            return {
              ...p,
              x: p.x + dx * 0.1,
              y: p.y + dy * 0.1
            };
          } else {
            // Burst phase
            const nextX = p.x + p.vx;
            const nextY = p.y + p.vy;
            const nextVx = p.vx * 0.94;
            const nextVy = p.vy * 0.94;
            if (Math.abs(nextVx) < 0.2 && Math.abs(nextVy) < 0.2) {
              return { ...p, isFlying: true };
            }
            return { ...p, x: nextX, y: nextY, vx: nextVx, vy: nextVy };
          }
        }).filter(Boolean) as Particle[];
      });
    }, 40);
    return () => clearInterval(ticker);
  }, []);

  const triggerExplosion = (startX: number, startY: number, points: number) => {
    const count = 30;
    const newParticles: Particle[] = [];
    for (let i = 0; i < count; i++) {
      const angle = (Math.PI * 2 * i) / count;
      const speed = Math.random() * 12 + 5;
      newParticles.push({
        id: Math.random(),
        emoji: EXPLOSION_POOL[Math.floor(Math.random() * EXPLOSION_POOL.length)],
        x: startX,
        y: startY,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        isFlying: false
      });
    }
    setParticles(prev => [...prev, ...newParticles]);
    setRewardPoints(p => p + points);
  };

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      stepsDone++;
      setJarCount(prev => Math.min(MAX_JAR, prev + 0.5));

      // Decrement steps for active sweets
      setActiveSweets(prev => prev.map(s => ({ ...s, steps: Math.max(0, s.steps - 1) })));

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (ghostIndices.includes(finalPos)) setIsGrayscale(true);
        if (rainbowIndices.includes(finalPos)) setIsGrayscale(false);
        if (clownIndices.includes(finalPos)) setIsClownMode(true);

        setActiveZombies(prev => {
          let hit = false;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + 2) % TOTAL_TILES;
            if (nextZPos === finalPos) hit = true;
            return { ...z, pos: nextZPos };
          });
          if (hit) setPlayerHealth(h => Math.max(0, h - 1));
          return moved;
        });

        if (zombieIndicators.includes(finalPos)) {
          setActiveZombies(z => [...z, { id: Math.random().toString(), pos: (finalPos - 5 + TOTAL_TILES) % TOTAL_TILES, health: 5, isActive: true }]);
        }
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, ghostIndices, rainbowIndices, clownIndices, zombieIndicators]);

  // Monitor sweet completion
  useEffect(() => {
    activeSweets.forEach(s => {
      if (s.steps === 0) {
        // Center-left explosion
        const centerX = (window.innerWidth - SIDEBAR_WIDTH) / 2 / APP_SCALE;
        const centerY = window.innerHeight / 2 / APP_SCALE;
        let x = centerX - 180;
        let y = centerY;
        if (s.id === '🍦') { x -= 40; y -= 40; }
        if (s.id === '🍰') { x += 40; y -= 40; }
        if (s.id === '🎂') { y += 40; }

        triggerExplosion(x, y, s.points);
        setActiveSweets(prev => prev.filter(item => item.id !== s.id));
      }
    });
  }, [activeSweets]);

  const handleRoll = (landing: { x: number, y: number }, index: number) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);

    const nextRolls = rollsSinceSweets + 1;
    if (nextRolls >= 5) {
      setActiveSweets([
        { id: '🍦', emoji: '🍦', steps: 12, maxSteps: 12, timeLeft: 7200, totalTime: 7200, points: 10, sizeMultiplier: 3 },
        { id: '🍰', emoji: '🍰', steps: 18, maxSteps: 18, timeLeft: 14400, totalTime: 14400, points: 20, sizeMultiplier: 3 },
        { id: '🎂', emoji: '🎂', steps: 28, maxSteps: 28, timeLeft: 28800, totalTime: 28800, points: 30, sizeMultiplier: 5 },
      ]);
      setRollsSinceSweets(0);
    } else {
      setRollsSinceSweets(nextRolls);
    }

    const diceCount = isGrayscale ? 3 : 1;
    const newValues = Array.from({ length: diceCount }, () => Math.floor(Math.random() * 6) + 1);
    setDiceValues(newValues);

    setTimeout(() => {
      setIsRolling(false);
      setIsMoving(true);
      processMovement(newValues.reduce((a, b) => a + b, 0));
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const formatTime = (sec: number) => {
    const h = Math.floor(sec / 3600);
    const m = Math.floor((sec % 3600) / 60);
    const s = sec % 60;
    return `${h}h ${m}m ${s}s`;
  };

  return (
    <div className={`h-screen w-screen flex bg-white dark:bg-zinc-950 transition-all duration-700 ${isGrayscale ? 'filter grayscale' : ''} ${isExploding ? 'bg-indigo-600/10' : ''}`}>

      {/* Game Area */}
      <div ref={gameAreaRef} className="flex-1 relative overflow-hidden notion-grid">
        <div className="relative w-full h-full flex items-center justify-center origin-top-left" style={{ transform: `scale(${APP_SCALE})` }}>
          <div className="relative w-full h-full">

            {/* Particles */}
            {particles.map(p => (
              <div key={p.id} className="absolute z-[100] transition-all duration-300 pointer-events-none" style={{ left: p.x, top: p.y, fontSize: '24px' }}>
                {p.emoji}
              </div>
            ))}

            {/* Board Tiles */}
            {boardSpaces.map(s => (
              <div key={s.id} className="absolute sudoku-tile flex items-center justify-center" style={{ left: s.x, top: s.y, width: tileSize, height: tileSize, backgroundColor: isClownMode ? `hsl(${s.id * 18 % 360}, 60%, 50%)` : undefined }}>
                <span className="text-[5px] opacity-20 absolute top-0.5 left-0.5 font-bold">{s.id + 1}</span>
                {zombieIndicators.includes(s.id) && <span className="opacity-10 text-xs">{ENEMY_ICON}</span>}
              </div>
            ))}

            {/* Central Layout: Divided into Left (Sweets) | Center (Jar) | Right (Bosses) */}
            <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
                <div className="flex items-center gap-16 translate-y-6">

                    {/* ZONE 1 (LEFT): Sweets Inverted Triangle */}
                    <div className="flex flex-col items-center gap-6 min-w-[240px]">
                      {/* Top Row: 🍦 and 🍰 */}
                      <div className="flex gap-14">
                        {activeSweets.filter(s => s.emoji !== '🎂').map(s => (
                          <div key={s.id} className="flex flex-col items-center relative animate-bounce" style={{ animationDuration: '3s' }}>
                             <span className="leading-none drop-shadow-xl select-none" style={{ fontSize: tileSize * s.sizeMultiplier }}>{s.emoji}</span>
                             <div className="mt-2 w-20 h-1.5 bg-gray-100 dark:bg-white/5 rounded-full overflow-hidden border border-black/5">
                                <div className="h-full bg-pink-500 transition-all duration-300" style={{ width: `${(s.steps / s.maxSteps) * 100}%` }} />
                             </div>
                             <div className="flex flex-col items-center mt-1 opacity-50">
                                <span className="text-[7px] font-black uppercase tracking-widest">{s.steps} steps</span>
                                <span className="text-[6px] font-bold tabular-nums">{formatTime(s.timeLeft)}</span>
                             </div>
                          </div>
                        ))}
                      </div>
                      {/* Bottom Row: 🎂 */}
                      {activeSweets.find(s => s.emoji === '🎂') && (
                        <div className="flex flex-col items-center relative animate-bounce" style={{ animationDuration: '4s' }}>
                           <span className="leading-none drop-shadow-2xl select-none" style={{ fontSize: tileSize * 5 }}>🎂</span>
                           <div className="mt-2 w-32 h-2 bg-gray-100 dark:bg-white/5 rounded-full overflow-hidden border border-black/5">
                              <div className="h-full bg-pink-500 transition-all duration-300" style={{ width: `${(activeSweets.find(s => s.emoji === '🎂')!.steps / 28) * 100}%` }} />
                           </div>
                           <div className="flex flex-col items-center mt-1 opacity-60">
                              <span className="text-[8px] font-black uppercase tracking-widest">{activeSweets.find(s => s.emoji === '🎂')!.steps} steps</span>
                              <span className="text-[7px] font-bold tabular-nums">{formatTime(activeSweets.find(s => s.emoji === '🎂')!.timeLeft)}</span>
                           </div>
                        </div>
                      )}
                      {activeSweets.length === 0 && (
                        <div className="text-[10px] font-black opacity-10 uppercase tracking-[0.2em]">{5 - rollsSinceSweets} rolls to unlock sweets</div>
                      )}
                    </div>

                    {/* ZONE 2 (CENTER): Alchemy Jar */}
                    <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={() => {
                        setIsExploding(true);
                        setTimeout(() => {
                            setIsExploding(false);
                            setJarCount(0);
                            setRollBank(r => r + 40);
                        }, 1500);
                    }} isDeducting={isDeducting} height={tileSize * 5} />

                    {/* ZONE 3 (RIGHT): Bosses */}
                    <div className="flex flex-col items-center gap-10 min-w-[150px]">
                      {pumpkinBoss.isActive && <div className="flex flex-col items-center animate-pulse"><span className="text-7xl">🎃</span></div>}
                      {demonBoss.isActive && <div className="flex flex-col items-center animate-bounce"><span className="text-7xl">👹</span></div>}
                    </div>
                </div>
            </div>

            {/* Player Piece */}
            <div className="absolute z-30 transition-all duration-300" style={{ left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, transform: 'translate(-50%, -60%)', fontSize: tileSize * 1.3 }}>
               <div className="flex flex-col items-center">
                  <div className="flex gap-0.5 mb-1 bg-white/80 p-0.5 rounded-full px-1.5 border border-black/5">
                    {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => <div key={i} className={`w-1.5 h-0.5 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />)}
                  </div>
                  <span>{isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}</span>
               </div>
            </div>

            {/* Enemies */}
            {activeZombies.map(z => (
              <div key={z.id} className="absolute z-20 transition-all duration-700" style={{ left: boardSpaces[z.pos].x + tileSize/2, top: boardSpaces[z.pos].y + tileSize/2, transform: 'translate(-50%, -50%)', fontSize: tileSize }}>
                {ENEMY_ICON}
              </div>
            ))}
          </div>
        </div>

        {Array.from({ length: isGrayscale ? 3 : 1 }).map((_, i) => (
          <Dice3D 
            key={i} color={diceColor} value={diceValues[i] || 1} isRolling={isRolling} 
            currentPos={dicePositions[i] ?? { x: 0, y: 0 }} 
            onRoll={(p) => handleRoll(p, i)} 
            onDragEnd={(p) => setDicePositions(prev => { const n = [...prev]; n[i] = p; return n; })} 
            scale={isClownMode ? 3.5 : 1}
          />
        ))}
      </div>

      {/* Sidebar - Unified Reward Gift Box */}
      <div className="w-[380px] h-full bg-[#fbfbfa] dark:bg-[#191919] border-l border-[#efefef] dark:border-white/5 flex flex-col z-50">
        <div className="p-4 flex flex-col h-full">
          <div className="flex items-center justify-between py-2 border-b border-[#eee] dark:border-white/5 mb-4">
            <div className="flex items-center gap-3">
              <div className="flex items-center gap-2">
                <span className="text-3xl drop-shadow-sm">🎁</span>
                <span className="text-[24px] font-black tabular-nums">{rewardPoints}</span>
              </div>
            </div>
            <div className="flex items-center gap-1">
              <div className="mr-2 pr-2 border-r border-gray-200 dark:border-gray-800">
                <span className="text-[16px] font-black">⚡ {rollBank}</span>
              </div>
              <button onClick={() => setDarkMode(!darkMode)} className="p-1.5 text-sm">{darkMode ? '☀️' : '🌙'}</button>
            </div>
          </div>

          <div className="flex-1 flex flex-col overflow-hidden">
             <div className="flex items-center justify-between mb-6 px-1">
                <h1 className="text-[14px] font-bold opacity-90">📋 Quests</h1>
                <div className="flex gap-4">
                   <button onClick={() => setShowHistory(false)} className={`text-[12px] font-medium ${!showHistory ? 'text-indigo-600 underline underline-offset-4' : 'opacity-40'}`}>Active</button>
                   <button onClick={() => setShowHistory(true)} className={`text-[12px] font-medium ${showHistory ? 'text-indigo-600 underline underline-offset-4' : 'opacity-40'}`}>Logbook</button>
                </div>
             </div>

             <div className="flex-1 overflow-y-auto custom-scrollbar">
                {!showHistory ? (
                   <div className="flex flex-col gap-1">
                      {tasks.map(t => (
                        <div key={t.id} onClick={() => handleTaskComplete(t)} className="group flex items-start gap-3 p-2 hover:bg-[#f3f3f2] dark:hover:bg-white/5 rounded-lg transition-all cursor-pointer">
                           <div className="mt-0.5 w-4.5 h-4.5 rounded-[4px] border border-[#ccc] dark:border-white/20 group-hover:bg-indigo-500 transition-all flex items-center justify-center">
                              <div className="w-2 h-2 bg-white rounded-[1px] opacity-0 group-hover:opacity-100" />
                           </div>
                           <p className="text-[14px] leading-[1.4] opacity-80">{t.text}</p>
                        </div>
                      ))}
                      <div className="mt-4 border-t border-[#efefef] dark:border-white/5 pt-6">
                        <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([...tasks, { id: Date.now().toString(), text: newTask, completed: false }]); setNewTask(''); }}>
                           <input value={newTask} onChange={e => setNewTask(e.target.value)} placeholder="+ New mission..." className="w-full py-2 bg-transparent outline-none text-[15px] placeholder:opacity-40 focus:placeholder:opacity-10" />
                        </form>
                      </div>
                   </div>
                ) : (
                  <div className="flex flex-col gap-2">
                     {history.map(h => (
                       <div key={h.id} className="p-3 bg-black/[0.01] dark:bg-white/[0.01] rounded-lg opacity-60">
                          <p className="text-[13px] line-through">{h.text}</p>
                          <span className="text-[9px] font-black opacity-30 mt-2 block">{h.completedAt}</span>
                       </div>
                     ))}
                  </div>
                )}
             </div>
          </div>
        </div>
      </div>

      <style>{`
        .notion-grid { background-image: radial-gradient(#efefef 1px, transparent 1px); background-size: 20px 20px; }
        .dark .notion-grid { background-image: radial-gradient(rgba(255,255,255,0.05) 1px, transparent 1px); }
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.08); border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.08); }
      `}</style>
    </div>
  );
};

export default App;

export interface Task {
  id: string;
  text: string;
  completed: boolean;
  priority?: 'low' | 'medium' | 'high';
}

export interface BoardSpace {
  id: number;
  x: number;
  y: number;
  type: 'normal' | 'special';
}

export interface BigZombie {
  id: string;
  pos: number;
  health: number;
  isActive: boolean;
}

export interface PumpkinBoss {
  isActive: boolean;
  health: number;
}

export interface DemonBoss {
  isActive: boolean;
  health: number;
}

export interface SweetGoal {
  id: string;
  emoji: string;
  steps: number;
  maxSteps: number;
  timeLeft: number; // in seconds
  totalTime: number; // in seconds
  points: number;
  sizeMultiplier: number;
}

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss, SweetGoal } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

const ZOMBIE_INDICATOR_COUNT = 10; 
const BOMB_COUNT = 10;           
const MAX_PLAYER_HEALTH = 5; 

const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 

const APP_SCALE = 1.25; 
const SIDEBAR_WIDTH = 380;

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', 
  '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🐾',
  '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤',
  '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const EXPLOSION_POOL = [
  '🍦','🍧','🍨','🍩','🍪','🎂','🍰','🧁','🥧','🍫','🍬','🍭','🍮',
  '🍇','🍈','🍉','🍊','🍋','🍋‍🟩','🍌','🍍','🥭','🍎','🍏','🍐','🍑','🍒','🍓','🫐','🥝','🍅','🫒','🥥'
];

interface Particle {
  id: number;
  emoji: string;
  x: number;
  y: number;
  vx: number;
  vy: number;
  isFlying: boolean;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState('rgba(255, 255, 255, 0.4)');
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  const [rewardPoints, setRewardPoints] = useState(0);
  const [rollsSinceSweets, setRollsSinceSweets] = useState(0);
  const [activeSweets, setActiveSweets] = useState<SweetGoal[]>([]);
  const [particles, setParticles] = useState<Particle[]>([]);

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<(Task & { completedAt: string })[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);

  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2, y: window.innerHeight / 2 },
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2 - 80, y: window.innerHeight / 2 },
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2 + 80, y: window.innerHeight / 2 }
  ]);

  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });

  const gameAreaRef = useRef<HTMLDivElement>(null);

  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(48);

  useEffect(() => {
    const updateSize = () => {
      const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
      const availableH = window.innerHeight / APP_SCALE;
      const horizontalLimit = (availableW - 60) / BOARD_W;
      const verticalLimit = (availableH - 60) / BOARD_H;
      const bestSize = Math.max(25, Math.min(horizontalLimit, verticalLimit, 45));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
    const availableH = window.innerHeight / APP_SCALE;
    const boardRealW = (BOARD_W - 1) * tileSize;
    const boardRealH = (BOARD_H - 1) * tileSize;
    const startX = (availableW - boardRealW) / 2;
    const startY = (availableH - boardRealH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, x: startX + i * tileSize, y: startY, type: 'normal' });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize, type: 'normal' });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize, type: 'normal' });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, x: startX, y: startY + i * tileSize, type: 'normal' });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    setZombieIndicators(getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude));
    setBombIndices(getRandomUnique(BOMB_COUNT, startExclude));
    setGhostIndices(getRandomUnique(3, startExclude));
    setRainbowIndices(getRandomUnique(3, startExclude));
    setClownIndices(getRandomUnique(2, startExclude));
  }, [boardSpaces.length, getRandomUnique]);

  // Main Ticker for Sweets and Particles
  useEffect(() => {
    const ticker = setInterval(() => {
      // Countdown time for sweets
      setActiveSweets(prev => {
        const next = prev.map(s => ({ ...s, timeLeft: Math.max(0, s.timeLeft - 1) }));
        // Remove sweets where time reached 0 but steps > 0
        return next.filter(s => s.timeLeft > 0);
      });

      // Update particles
      setParticles(prev => {
        if (prev.length === 0) return prev;
        return prev.map(p => {
          if (p.isFlying) {
            // Target the 🎁 Box in sidebar (Top-Right of game area approx)
            const targetX = (window.innerWidth - 100) / APP_SCALE;
            const targetY = 100 / APP_SCALE;
            const dx = targetX - p.x;
            const dy = targetY - p.y;
            const dist = Math.sqrt(dx*dx + dy*dy);
            if (dist < 15) return null;
            return {
              ...p,
              x: p.x + dx * 0.12,
              y: p.y + dy * 0.12
            };
          } else {
            // Burst phase
            const nextX = p.x + p.vx;
            const nextY = p.y + p.vy;
            const nextVx = p.vx * 0.94;
            const nextVy = p.vy * 0.94;
            if (Math.abs(nextVx) < 0.2 && Math.abs(nextVy) < 0.2) {
              return { ...p, isFlying: true };
            }
            return { ...p, x: nextX, y: nextY, vx: nextVx, vy: nextVy };
          }
        }).filter(Boolean) as Particle[];
      });
    }, 40);
    return () => clearInterval(ticker);
  }, []);

  const triggerExplosion = (startX: number, startY: number, points: number) => {
    const count = 25;
    const newParts: Particle[] = [];
    for (let i = 0; i < count; i++) {
      const angle = (Math.PI * 2 * i) / count;
      const speed = Math.random() * 8 + 4;
      newParts.push({
        id: Math.random(),
        emoji: EXPLOSION_POOL[Math.floor(Math.random() * EXPLOSION_POOL.length)],
        x: startX,
        y: startY,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        isFlying: false
      });
    }
    setParticles(prev => [...prev, ...newParts]);
    setRewardPoints(p => p + points);
  };

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      stepsDone++;
      setJarCount(prev => Math.min(MAX_JAR, prev + 0.5));

      // Decrement steps for active sweets
      setActiveSweets(prev => prev.map(s => ({ ...s, steps: Math.max(0, s.steps - 1) })));

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (ghostIndices.includes(finalPos)) setIsGrayscale(true);
        if (rainbowIndices.includes(finalPos)) setIsGrayscale(false);
        if (clownIndices.includes(finalPos)) setIsClownMode(true);

        setActiveZombies(prev => {
          let hit = false;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + 2) % TOTAL_TILES;
            if (nextZPos === finalPos) hit = true;
            return { ...z, pos: nextZPos };
          });
          if (hit) setPlayerHealth(h => Math.max(0, h - 1));
          return moved;
        });

        if (zombieIndicators.includes(finalPos)) {
          setActiveZombies(z => [...z, { id: Math.random().toString(), pos: (finalPos - 5 + TOTAL_TILES) % TOTAL_TILES, health: 5, isActive: true }]);
        }
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, ghostIndices, rainbowIndices, clownIndices, zombieIndicators]);

  // Sweet completion check
  useEffect(() => {
    activeSweets.forEach(s => {
      if (s.steps === 0) {
        // Calculate explosion origin (Left of center jar)
        const centerX = (window.innerWidth - SIDEBAR_WIDTH) / 2 / APP_SCALE;
        const centerY = window.innerHeight / 2 / APP_SCALE;
        let x = centerX - 180;
        let y = centerY;
        // Inverted triangle offsets
        if (s.id === 'ice') { x -= 40; y -= 40; }
        if (s.id === 'cake') { x += 40; y -= 40; }
        if (s.id === 'bigcake') { y += 40; }

        triggerExplosion(x, y, s.points);
        setActiveSweets(prev => prev.filter(item => item.id !== s.id));
      }
    });
  }, [activeSweets]);

  const handleRoll = (landing: { x: number, y: number }, index: number) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);

    const nextRollCount = rollsSinceSweets + 1;
    if (nextRollCount >= 5) {
      setActiveSweets([
        { id: 'ice', emoji: '🍦', steps: 12, maxSteps: 12, timeLeft: 7200, totalTime: 7200, points: 10, sizeMultiplier: 3.9 },
        { id: 'cake', emoji: '🍰', steps: 18, maxSteps: 18, timeLeft: 14400, totalTime: 14400, points: 20, sizeMultiplier: 3.9 },
        { id: 'bigcake', emoji: '🎂', steps: 28, maxSteps: 28, timeLeft: 28800, totalTime: 28800, points: 30, sizeMultiplier: 6.5 },
      ]);
      setRollsSinceSweets(0);
    } else {
      setRollsSinceSweets(nextRollCount);
    }

    const diceCount = isGrayscale ? 3 : 1;
    const newValues = Array.from({ length: diceCount }, () => Math.floor(Math.random() * 6) + 1);
    setDiceValues(newValues);

    setTimeout(() => {
      setIsRolling(false);
      setIsMoving(true);
      processMovement(newValues.reduce((a, b) => a + b, 0));
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const formatTime = (sec: number) => {
    const h = Math.floor(sec / 3600);
    const m = Math.floor((sec % 3600) / 60);
    const s = sec % 60;
    return `${h}h ${m}m ${s}s`;
  };

  return (
    <div className={`h-screen w-screen flex bg-white dark:bg-zinc-950 transition-all duration-700 ${isGrayscale ? 'filter grayscale' : ''}`}>

      {/* Game Area */}
      <div ref={gameAreaRef} className="flex-1 relative overflow-hidden notion-grid">
        <div className="relative w-full h-full flex items-center justify-center origin-top-left" style={{ transform: `scale(${APP_SCALE})` }}>
          <div className="relative w-full h-full">

            {/* Particles */}
            {particles.map(p => (
              <div key={p.id} className="absolute z-[100] transition-all duration-300 pointer-events-none" style={{ left: p.x, top: p.y, fontSize: '22px' }}>
                {p.emoji}
              </div>
            ))}

            {/* Board Tiles */}
            {boardSpaces.map(s => (
              <div key={s.id} className="absolute sudoku-tile flex items-center justify-center" style={{ left: s.x, top: s.y, width: tileSize, height: tileSize, backgroundColor: isClownMode ? `hsl(${s.id * 15 % 360}, 65%, 50%)` : undefined }}>
                <span className="text-[5px] opacity-20 absolute top-0.5 left-0.5 font-bold">{s.id + 1}</span>
                {zombieIndicators.includes(s.id) && <span className="opacity-10 text-xs">{ENEMY_ICON}</span>}
              </div>
            ))}

            {/* Central Layout: Divided into Left (Sweets) | Center (Jar) | Right (Bosses) */}
            <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
                <div className="flex items-center gap-20 translate-y-6">

                    {/* LEFT: Sweets Inverted Triangle */}
                    <div className="flex flex-col items-center gap-10 min-w-[260px]">
                      {/* Top Row: 🍦 🍰 */}
                      <div className="flex gap-16">
                        {activeSweets.filter(s => s.id !== 'bigcake').map(s => (
                          <div key={s.id} className="flex flex-col items-center relative animate-bounce" style={{ animationDuration: '3.5s' }}>
                             <span className="leading-none drop-shadow-xl" style={{ fontSize: tileSize * 3.9 }}>{s.emoji}</span>
                             <div className="mt-2 w-24 h-1.5 bg-gray-100 dark:bg-white/5 rounded-full overflow-hidden border border-black/5">
                                <div className="h-full bg-pink-500 transition-all duration-300" style={{ width: `${(s.steps / s.maxSteps) * 100}%` }} />
                             </div>
                             <div className="flex flex-col items-center mt-1 opacity-60">
                                <span className="text-[7px] font-black uppercase tracking-widest">{s.steps} steps</span>
                                <span className="text-[6px] font-bold tabular-nums">{formatTime(s.timeLeft)}</span>
                             </div>
                          </div>
                        ))}
                      </div>
                      {/* Bottom Row: 🎂 */}
                      {activeSweets.find(s => s.id === 'bigcake') && (
                        <div className="flex flex-col items-center relative animate-bounce" style={{ animationDuration: '4.5s' }}>
                           <span className="leading-none drop-shadow-2xl" style={{ fontSize: tileSize * 6.5 }}>🎂</span>
                           <div className="mt-2 w-36 h-2 bg-gray-100 dark:bg-white/5 rounded-full overflow-hidden border border-black/5">
                              <div className="h-full bg-pink-500 transition-all duration-300" style={{ width: `${(activeSweets.find(s => s.id === 'bigcake')!.steps / 28) * 100}%` }} />
                           </div>
                           <div className="flex flex-col items-center mt-1 opacity-60">
                              <span className="text-[8px] font-black uppercase tracking-widest">{activeSweets.find(s => s.id === 'bigcake')!.steps} steps</span>
                              <span className="text-[7px] font-bold tabular-nums">{formatTime(activeSweets.find(s => s.id === 'bigcake')!.timeLeft)}</span>
                           </div>
                        </div>
                      )}
                    </div>

                    {/* CENTER: Alchemy Jar */}
                    <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={() => {
                        setIsExploding(true);
                        setTimeout(() => {
                            setIsExploding(false);
                            setJarCount(0);
                            setRollBank(r => r + 40);
                        }, 1500);
                    }} height={tileSize * 6} />

                    {/* RIGHT: Bosses */}
                    <div className="flex flex-col items-center gap-14 min-w-[150px]">
                      {pumpkinBoss.isActive && <span className="text-7xl animate-pulse">🎃</span>}
                      {demonBoss.isActive && <span className="text-7xl animate-bounce">👹</span>}
                    </div>
                </div>
            </div>

            {/* Player Piece */}
            <div className="absolute z-30 transition-all duration-300" style={{ left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, transform: 'translate(-50%, -60%)', fontSize: tileSize * 1.3 }}>
               <div className="flex flex-col items-center">
                  <div className="flex gap-0.5 mb-1 bg-white/80 p-0.5 rounded-full px-1.5 border border-black/5">
                    {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => <div key={i} className={`w-1.5 h-0.5 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />)}
                  </div>
                  <span>{isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}</span>
               </div>
            </div>

            {/* Enemies */}
            {activeZombies.map(z => (
              <div key={z.id} className="absolute z-20 transition-all duration-700" style={{ left: boardSpaces[z.pos].x + tileSize/2, top: boardSpaces[z.pos].y + tileSize/2, transform: 'translate(-50%, -50%)', fontSize: tileSize }}>
                {ENEMY_ICON}
              </div>
            ))}
          </div>
        </div>

        {Array.from({ length: isGrayscale ? 3 : 1 }).map((_, i) => (
          <Dice3D 
            key={i} color={diceColor} value={diceValues[i] || 1} isRolling={isRolling} 
            currentPos={dicePositions[i] ?? { x: window.innerWidth/2, y: window.innerHeight/2 }} 
            onRoll={(p) => handleRoll(p, i)} 
            onDragEnd={(p) => setDicePositions(prev => { const n = [...prev]; n[i] = p; return n; })} 
            scale={isClownMode ? 3.5 : 1}
          />
        ))}
      </div>

      {/* Sidebar */}
      <div className="w-[380px] h-full bg-[#fbfbfa] dark:bg-[#191919] border-l border-[#efefef] dark:border-white/5 flex flex-col z-50 shadow-2xl">
        <div className="p-4 flex flex-col h-full">
          {/* Header */}
          <div className="flex items-center justify-between py-2 border-b border-[#eee] dark:border-white/5 mb-4">
            <div className="flex items-center gap-3">
              <div className="flex items-center gap-2">
                <span className="text-3xl drop-shadow-sm">🎁</span>
                <span className="text-[24px] font-black tabular-nums">{rewardPoints}</span>
              </div>
            </div>
            <div className="flex items-center gap-1">
              <div className="mr-2 pr-2 border-r border-gray-200 dark:border-gray-800">
                <span className="text-[16px] font-black">⚡ {rollBank}</span>
              </div>
              <button onClick={() => setDarkMode(!darkMode)} className="p-1.5 text-sm">{darkMode ? '☀️' : '🌙'}</button>
            </div>
          </div>

          {/* Quests */}
          <div className="flex-1 flex flex-col overflow-hidden">
             <div className="flex items-center justify-between mb-6">
                <h1 className="text-[14px] font-bold opacity-90">📋 Quests</h1>
                <div className="flex gap-4">
                   <button onClick={() => setShowHistory(false)} className={`text-[12px] font-medium ${!showHistory ? 'text-indigo-600 underline' : 'opacity-40'}`}>Active</button>
                   <button onClick={() => setShowHistory(true)} className={`text-[12px] font-medium ${showHistory ? 'text-indigo-600 underline' : 'opacity-40'}`}>Logbook</button>
                </div>
             </div>

             <div className="flex-1 overflow-y-auto custom-scrollbar">
                {!showHistory ? (
                   <div className="flex flex-col gap-1">
                      {tasks.map(t => (
                        <div key={t.id} onClick={() => handleTaskComplete(t)} className="group flex items-start gap-3 p-2 hover:bg-[#f3f3f2] dark:hover:bg-white/5 rounded-lg transition-all cursor-pointer">
                           <div className="mt-0.5 w-4.5 h-4.5 rounded-[4px] border border-[#ccc] dark:border-white/20 group-hover:bg-indigo-500 transition-all flex items-center justify-center">
                              <div className="w-2 h-2 bg-white rounded-[1px] opacity-0 group-hover:opacity-100" />
                           </div>
                           <p className="text-[14px] leading-[1.4] opacity-80">{t.text}</p>
                        </div>
                      ))}
                      <div className="mt-4 border-t border-[#efefef] dark:border-white/5 pt-6">
                        <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([...tasks, { id: Date.now().toString(), text: newTask, completed: false }]); setNewTask(''); }}>
                           <input value={newTask} onChange={e => setNewTask(e.target.value)} placeholder="+ New mission..." className="w-full py-2 bg-transparent outline-none text-[15px] placeholder:opacity-40" />
                        </form>
                      </div>
                   </div>
                ) : (
                  <div className="flex flex-col gap-2">
                     {history.map(h => (
                       <div key={h.id} className="p-3 bg-black/[0.01] dark:bg-white/[0.01] rounded-lg opacity-60">
                          <p className="text-[13px] line-through">{h.text}</p>
                          <span className="text-[9px] font-black opacity-30 mt-2 block">{h.completedAt}</span>
                       </div>
                     ))}
                  </div>
                )}
             </div>
          </div>
        </div>
      </div>

      <style>{`
        .notion-grid { background-image: radial-gradient(#efefef 1px, transparent 1px); background-size: 20px 20px; }
        .dark .notion-grid { background-image: radial-gradient(rgba(255,255,255,0.05) 1px, transparent 1px); }
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.08); border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

const ZOMBIE_INDICATOR_COUNT = 10; 
const BOMB_COUNT = 10;           
const PUMPKIN_COUNT = 5; 
const DEMON_COUNT = 5; 
const CLOVER_COUNT = 5; 
const GHOST_COUNT = 3; 
const RAINBOW_COUNT = 3; 
const CLOWN_COUNT = 2; 

const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 
const SPAWN_BEHIND_OFFSET = 5;

const APP_SCALE = 1.25; 
const SIDEBAR_WIDTH = 380;

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', 
  '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🐾',
  '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤',
  '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.4)', 
  'rgba(199, 210, 254, 0.6)', 
  'rgba(254, 202, 202, 0.6)', 
  'rgba(167, 243, 208, 0.6)', 
  'rgba(253, 230, 138, 0.6)', 
];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [isWinterMode, setIsWinterMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  const [diamonds, setDiamonds] = useState(0);
  const [coins, setCoins] = useState(0);

  // New State for Sweets mechanic
  const [rollsCount, setRollsCount] = useState(0);
  const [showSweets, setShowSweets] = useState(false);

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);

  const gameAreaRef = useRef<HTMLDivElement>(null);

  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2, y: window.innerHeight / 2 },
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2 - 100, y: window.innerHeight / 2 },
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2 + 100, y: window.innerHeight / 2 }
  ]);

  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(48);

  useEffect(() => {
    const updateSize = () => {
      const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
      const availableH = window.innerHeight / APP_SCALE;
      const horizontalLimit = (availableW - 60) / BOARD_W;
      const verticalLimit = (availableH - 60) / BOARD_H;
      const bestSize = Math.max(25, Math.min(horizontalLimit, verticalLimit, 45));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
    const availableH = window.innerHeight / APP_SCALE;
    const boardRealW = (BOARD_W - 1) * tileSize;
    const boardRealH = (BOARD_H - 1) * tileSize;
    const startX = (availableW - boardRealW) / 2;
    const startY = (availableH - boardRealH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    const gInd = getRandomUnique(GHOST_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd]);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd, ...rInd]);

    setZombieIndicators(zInd);
    setBombIndices(bInd);
    setPumpkinIndices(pInd);
    setDemonIndices(dInd);
    setCloverIndices(cInd);
    setGhostIndices(gInd);
    setRainbowIndices(rInd);
    setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...clownIndices, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);

    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  };

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) {
      setPumpkinBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    if (demonBoss.isActive) {
      setDemonBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    setActiveZombies(prev => {
      if (prev.length === 0) return prev;
      let nearestIndex = 0;
      let minDistance = Infinity;
      prev.forEach((z, idx) => {
        const dist = Math.min(Math.abs(damagePos - z.pos), TOTAL_TILES - Math.abs(damagePos - z.pos));
        if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
      });
      const newZombies = [...prev];
      const target = { ...newZombies[nearestIndex] };
      target.health -= 1;
      if (target.health <= 0) {
        newZombies.splice(nearestIndex, 1);
      } else { newZombies[nearestIndex] = target; }
      return newZombies;
    });
    setIsShaking(true);
    setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
  }, [pumpkinBoss, demonBoss, activeZombies]);

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    if (diceSum === 1) applyBombDamage(tempPos);

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      if (tempPos === 0) {
        setIsGrayscale(false);
        setIsClownMode(false);
      }

      if (cloverIndices.includes(tempPos)) {
        setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1));
        relocateItem(cloverIndices, tempPos, 'clover');
      }
      if (bombIndices.includes(tempPos)) {
        applyBombDamage(tempPos);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (ghostIndices.includes(finalPos)) {
          setIsGrayscale(true);
          setIsClownMode(false);
          relocateItem(ghostIndices, finalPos, 'ghost');
        } else if (rainbowIndices.includes(finalPos)) {
          setIsGrayscale(false);
          setIsClownMode(false);
          relocateItem(rainbowIndices, finalPos, 'rainbow');
        } else if (clownIndices.includes(finalPos)) {
          setIsClownMode(true);
          setIsGrayscale(false);
          relocateItem(clownIndices, finalPos, 'clown');
        }

        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombies(prev => [...prev, {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          }]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }
        if (pumpkinIndices.includes(finalPos)) {
          setPumpkinBoss(prev => ({ isActive: true, health: MAX_PUMPKIN_HEALTH }));
          relocateItem(pumpkinIndices, finalPos, 'pumpkin');
        }
        if (demonIndices.includes(finalPos)) {
          setDemonBoss(prev => ({ isActive: true, health: MAX_DEMON_HEALTH }));
          relocateItem(demonIndices, finalPos, 'demon');
        }

        setActiveZombies(prev => {
          let gameOver = false;
          const moveSteps = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + moveSteps) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) {
            setPlayerHealth(h => {
              const next = h - 1;
              if (next <= 0) {
                handleGameOver();
                return MAX_PLAYER_HEALTH;
              }
              return next;
            });
            return [];
          }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, pumpkinBoss, demonBoss, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, applyBombDamage]);

  const handleGameOver = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setIsGrayscale(false);
    setIsClownMode(false);
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }, index: number) => {
    if (rollBank <= 0 || isRolling || isMoving) return;

    if (pumpkinBoss.isActive) {
      setIsDeducting(true);
      setJarCount(prev => Math.max(0, prev - 5));
      setTimeout(() => setIsDeducting(false), 800);
    }

    setIsRolling(true);
    setRollBank(r => r - 1);

    // Roll counter logic
    setRollsCount(prev => {
      const next = prev + 1;
      if (next % 5 === 0) {
        setShowSweets(true);
      } else {
        setShowSweets(false);
      }
      return next;
    });

    const diceCount = isGrayscale ? 3 : 1;
    const newValues = Array.from({ length: diceCount }, () => Math.floor(Math.random() * 6) + 1);
    const newPositions = Array.from({ length: diceCount }, (_, i) => ({
      x: landing.x + (i - Math.floor(diceCount / 2)) * (isClownMode ? 180 : 80),
      y: landing.y
    }));

    setDicePositions(newPositions);

    setTimeout(() => {
      setIsRolling(false);
      setDiceValues(newValues);
      setIsMoving(true);
      const sum = newValues.reduce((a, b) => a + b, 0);
      processMovement(sum);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  const ENEMY_ICON = isWinterMode ? '⛄' : (darkMode ? '🧛🏻' : '🧟');
  const BOMB_ICON = isWinterMode ? '🔥' : (darkMode ? '🧄' : '💣');

  const getClownTileColor = (id: number) => {
    if (!isClownMode) return undefined;
    const colors = ['#ff00ff', '#00ffff', '#ffff00', '#ff0000', '#00ff00', '#ff8800', '#8800ff'];
    return colors[id % colors.length] + 'cc';
  };

  const activeDiceCount = isGrayscale ? 3 : 1;
  const currentDiceScale = isClownMode ? 3.5 : 1;

  const playerBaseSize = tileSize * 1.3;

  return (
    <div className={`h-screen w-screen flex transition-all duration-700 bg-white dark:bg-zinc-950
      ${isExploding ? 'bg-indigo-600/10' : ''} 
      ${isGrayscale ? 'filter grayscale' : ''}
    `}>
      {isWinterMode && <div className="fixed inset-0 z-10 pointer-events-none snow-effect" />}

      {/* Main Game Area (Left) */}
      <div 
        ref={gameAreaRef}
        className="flex-1 relative overflow-hidden notion-grid"
      >
        <div 
          className="relative w-full h-full origin-top-left flex items-center justify-center"
          style={{ transform: `scale(${APP_SCALE})` }}
        >
          <div className="relative w-full h-full">
            <div className="absolute inset-0 z-0 pointer-events-none">
                {boardSpaces.map(s => {
                  const bloom = blooms[s.id];
                  const isBomb = bombIndices.includes(s.id);
                  const isZombie = zombieIndicators.includes(s.id);
                  const isPumpkin = pumpkinIndices.includes(s.id);
                  const isDemon = demonIndices.includes(s.id);
                  const isClover = cloverIndices.includes(s.id);
                  const isGhost = ghostIndices.includes(s.id);
                  const isRainbow = rainbowIndices.includes(s.id);
                  const isClown = clownIndices.includes(s.id);
                  const isStart = s.id === 0;

                  let icon = null;
                  if (isBomb) icon = BOMB_ICON;
                  else if (isZombie) icon = ENEMY_ICON;
                  else if (isPumpkin) icon = '🎃';
                  else if (isDemon) icon = '👹';
                  else if (isClover) icon = '🍀';
                  else if (isGhost) icon = '👻';
                  else if (isRainbow) icon = '🌈';
                  else if (isClown) icon = '🤡';

                  return (
                    <div 
                      key={s.id}
                      className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
                      style={{ 
                          left: s.x, top: s.y, width: tileSize, height: tileSize,
                          backgroundColor: isClownMode ? getClownTileColor(s.id) : undefined 
                      }}
                    >
                      <span className="text-[5px] opacity-20 absolute top-0.5 left-0.5 font-bold">{s.id + 1}</span>
                      {icon && <span className="drop-shadow-sm opacity-25" style={{ fontSize: tileSize * 0.55 }}>{icon}</span>}
                      {bloom && <span className="bloom absolute opacity-25" style={{ fontSize: tileSize * 0.5 }}>{bloom}</span>}
                      {isStart && !bloom && !icon && <span className="text-[7px] font-black opacity-30 uppercase tracking-widest">Home</span>}
                    </div>
                  );
                })}

                {activeZombies.map(z => boardSpaces[z.pos] && (
                <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
                    left: boardSpaces[z.pos].x + tileSize/2, 
                    top: boardSpaces[z.pos].y + tileSize/2, 
                    transform: `translate(-50%, -60%) scale(${demonBoss.isActive ? 1.8 : 0.9})` 
                }}>
                    <div className="flex flex-col items-center">
                        <div className="flex gap-0.5 mb-1 bg-white/90 dark:bg-black/80 p-0.5 rounded-full px-1.5 border border-black/5 shadow-sm">
                        {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                            <div key={i} className={`w-1.5 h-0.5 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-200 dark:bg-gray-800'}`} />
                        ))}
                        </div>
                        <span className="drop-shadow-2xl animate-pulse" style={{ fontSize: tileSize * 1.1 }}>{ENEMY_ICON}</span>
                    </div>
                </div>
                ))}

                <div 
                onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
                className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto`}
                style={{ 
                    left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, 
                    top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, 
                    transform: 'translate(-50%, -60%)',
                    fontSize: tileSize * 1.3
                }}
                >
                <div className="flex flex-col items-center">
                    <div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-1.5 border border-black/5 shadow-sm">
                        {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (
                        <div key={i} className={`w-1.5 h-0.5 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />
                        ))}
                    </div>
                    <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">
                    {isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}
                    </span>
                </div>
                </div>

                {bombAnimation.active && (
                <div className="absolute z-50 animate-bomb-drop" style={{ 
                    left: boardSpaces[bombAnimation.pos]?.x + tileSize/2, 
                    top: boardSpaces[bombAnimation.pos]?.y + tileSize/2,
                    transform: 'translate(-50%, -100%)'
                }}>
                    <span className="text-7xl drop-shadow-2xl">{darkMode ? '✨' : '💥'}</span>
                </div>
                )}
            </div>

            {/* Central Area: Alchemy Jar (Center) and Sweets (Left) */}
            <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
                <div className="flex items-center gap-16 translate-y-6">
                    {/* Sweets Section (Left of Jar) */}
                    <div className="flex flex-col items-center gap-4 min-w-[300px] h-[350px] justify-center transition-opacity duration-1000" style={{ opacity: showSweets ? 1 : 0 }}>
                       <div className="flex gap-12">
                          <span className="drop-shadow-xl select-none" style={{ fontSize: playerBaseSize * 3 }}>🍦</span>
                          <span className="drop-shadow-xl select-none" style={{ fontSize: playerBaseSize * 3 }}>🍰</span>
                       </div>
                       <div className="translate-y-4">
                          <span className="drop-shadow-2xl select-none" style={{ fontSize: playerBaseSize * 5 }}>🎂</span>
                       </div>
                    </div>

                    {/* Alchemy Jar (CENTER) */}
                    <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} height={tileSize * 6} />

                    {/* Bosses Section (Right of Jar) */}
                    <div className="flex flex-col items-center gap-10 min-w-[150px]">
                    {pumpkinBoss.isActive && (
                        <div className="flex flex-col items-center animate-bounce-slow">
                        <div className="flex gap-1 mb-1.5 bg-white/90 p-1 rounded-full shadow-lg border border-orange-500/20 backdrop-blur-md">
                            {[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (
                                <div key={i} className={`w-3.5 h-1 rounded-full ${i < pumpkinBoss.health ? 'bg-orange-500' : 'bg-gray-200 opacity-20'}`} />
                            ))}
                        </div>
                        <span className="leading-none drop-shadow-2xl" style={{ fontSize: tileSize * 1.8 }}>🎃</span>
                        </div>
                    )}

                    {demonBoss.isActive && (
                        <div className="flex flex-col items-center animate-bounce-slow" style={{ animationDelay: '-1.5s' }}>
                        <div className="flex gap-1 mb-1.5 bg-white/90 p-1 rounded-full shadow-lg border border-red-500/20 backdrop-blur-md">
                            {[...Array(MAX_DEMON_HEALTH)].map((_, i) => (
                                <div key={i} className={`w-3.5 h-1 rounded-full ${i < demonBoss.health ? 'bg-red-500' : 'bg-gray-200 opacity-20'}`} />
                            ))}
                        </div>
                        <span className="leading-none drop-shadow-2xl" style={{ fontSize: tileSize * 1.8 }}>👹</span>
                        </div>
                    )}
                    </div>
                </div>
            </div>
          </div>
        </div>

        {Array.from({ length: activeDiceCount }).map((_, i) => (
          <Dice3D 
            key={i}
            color={diceColor} 
            value={diceValues[i] || 1} 
            isRolling={isRolling} 
            currentPos={dicePositions[i] || { x: (window.innerWidth - SIDEBAR_WIDTH) / 2, y: window.innerHeight / 2 }} 
            onRoll={(landing) => handleRoll(landing, i)} 
            onDragEnd={(finalPos) => setDicePositions(prev => {
              const next = [...prev];
              next[i] = finalPos;
              return next;
            })} 
            scale={currentDiceScale}
          />
        ))}
      </div>

      {/* Sidebar (Right) - Notion Inspired */}
      <div 
        className="w-[380px] h-full bg-[#fbfbfa] dark:bg-[#191919] border-l border-[#efefef] dark:border-white/5 flex flex-col z-50 shadow-2xl transition-colors duration-500 overflow-hidden"
      >
        <div className="p-4 flex flex-col h-full">
          {/* Minimalism Top Header */}
          <div className="flex items-center justify-between py-2 border-b border-[#eee] dark:border-white/5 mb-4">
             <div className="flex items-center gap-3">
                <div className="flex items-center gap-1 group cursor-pointer">
                   <span className="text-[14px]">💎</span>
                   <span className="text-[13px] font-bold tabular-nums opacity-80">{diamonds}</span>
                </div>
                <div className="flex items-center gap-1 group cursor-pointer">
                   <span className="text-[14px]">🪙</span>
                   <span className="text-[13px] font-bold tabular-nums opacity-80">{coins}</span>
                </div>
             </div>

             <div className="flex items-center gap-1">
                <div className="flex items-center gap-1 mr-1 border-r border-[#eee] dark:border-white/10 pr-2">
                  <span className="text-[10px] font-black opacity-30 uppercase tracking-tighter">⚡</span>
                  <span className="text-[16px] font-black tracking-tighter">{rollBank}</span>
                </div>
                <button onClick={() => setIsWinterMode(!isWinterMode)} className={`p-1.5 rounded-md transition-all text-sm ${isWinterMode ? 'bg-blue-100 text-blue-600' : 'hover:bg-black/5 opacity-40'}`}>❄️</button>
                <button onClick={() => setDarkMode(!darkMode)} className="p-1.5 rounded-md hover:bg-black/5 dark:hover:bg-white/5 transition-colors text-sm">{darkMode ? '☀️' : '🌙'}</button>
                <div className="w-5 h-5 rounded overflow-hidden flex flex-wrap gap-0.5 p-0.5 bg-black/5 dark:bg-white/5 cursor-pointer ml-1" onClick={() => {
                  const idx = DICE_COLORS.indexOf(diceColor);
                  setDiceColor(DICE_COLORS[(idx + 1) % DICE_COLORS.length]);
                }}>
                  <div className="flex-1 h-full rounded-[1px]" style={{background: diceColor}} />
                </div>
             </div>
          </div>

          {/* Task Management */}
          <div className="flex-1 flex flex-col overflow-hidden">
             <div className="flex items-center justify-between px-1 mb-6">
                <div className="flex items-center gap-2 text-[14px] font-bold opacity-90">
                   <span>📋</span>
                   <h1>Quests</h1>
                </div>
                <div className="flex gap-4">
                   <button onClick={() => setShowHistory(false)} className={`text-[12px] font-medium transition-all ${!showHistory ? 'text-indigo-600 underline underline-offset-4' : 'opacity-40 hover:opacity-100'}`}>Active</button>
                   <button onClick={() => setShowHistory(true)} className={`text-[12px] font-medium transition-all ${showHistory ? 'text-indigo-600 underline underline-offset-4' : 'opacity-40 hover:opacity-100'}`}>Logbook</button>
                </div>
             </div>

             <div className="flex-1 overflow-y-auto custom-scrollbar px-1 pb-4">
                {!showHistory ? (
                   <div className="flex flex-col gap-1">
                      {tasks.map(t => (
                        <div key={t.id} className="group flex items-start gap-3 p-2 hover:bg-[#f3f3f2] dark:hover:bg-white/5 rounded-lg transition-all cursor-pointer border border-transparent">
                           <button onClick={() => handleTaskComplete(t)} className="mt-0.5 w-4.5 h-4.5 rounded-[4px] border border-[#ccc] dark:border-white/20 group-hover:border-indigo-500 group-hover:bg-indigo-50 dark:group-hover:bg-indigo-900/20 transition-all flex items-center justify-center">
                              <div className="w-2 h-2 bg-indigo-500 rounded-[1px] opacity-0 group-hover:opacity-40 transition-opacity" />
                           </button>
                           <div className="flex-1 min-w-0" onClick={() => handleTaskComplete(t)}>
                              <p className="text-[14px] leading-[1.4] opacity-80 group-hover:opacity-100 transition-opacity">{t.text}</p>
                              <div className={`mt-2 inline-flex items-center px-2 py-0.5 rounded-md text-[10px] font-bold uppercase border ${getPriorityColor(t.priority)}`}>
                                {t.priority}
                              </div>
                           </div>
                        </div>
                      ))}

                      <div className="mt-4 border-t border-[#efefef] dark:border-white/5 pt-6">
                        <form 
                          className="flex flex-col gap-4"
                          onSubmit={e => { 
                            e.preventDefault(); 
                            if(!newTask.trim()) return; 
                            setTasks([...tasks, { id: Date.now().toString(), text: newTask, completed: false, priority: newTaskPriority }]); 
                            setNewTask(''); 
                          }}
                        >
                           <div className="flex items-center gap-2 px-1">
                              {['low', 'medium', 'high'].map(p => (
                                <button key={p} type="button" onClick={() => setNewTaskPriority(p as any)} className={`px-2 py-1 rounded text-[9px] font-black uppercase tracking-widest transition-all border ${newTaskPriority === p ? 'bg-indigo-500 text-white border-indigo-500 shadow-sm' : 'bg-transparent border-transparent opacity-40 hover:opacity-100'}`}>
                                   {p}
                                </button>
                              ))}
                           </div>
                           <div className="group relative">
                             <span className="absolute left-3 top-3 text-[#ccc] group-focus-within:text-indigo-500 transition-colors">+</span>
                             <input 
                                value={newTask} 
                                onChange={e => setNewTask(e.target.value)}
                                placeholder="New mission..."
                                className="w-full pl-8 pr-4 py-2.5 bg-transparent border-none outline-none text-[15px] placeholder:opacity-40 focus:placeholder:opacity-20"
                             />
                           </div>
                        </form>
                      </div>
                   </div>
                ) : (
                  <div className="flex flex-col gap-2">
                     {history.map(h => (
                       <div key={h.id} className="p-3 bg-black/[0.01] dark:bg-white/[0.01] rounded-lg border-l-2 border-[#efefef] dark:border-white/10 opacity-60">
                          <p className="text-[13px] line-through opacity-80">{h.text}</p>
                          <span className="text-[9px] font-black opacity-30 mt-2 block">{h.completedAt}</span>
                       </div>
                     ))}
                  </div>
                )}
             </div>
          </div>
        </div>
      </div>

      <style>{`
        .notion-grid { background-image: radial-gradient(#efefef 1px, transparent 1px); background-size: 20px 20px; }
        .dark .notion-grid { background-image: radial-gradient(rgba(255,255,255,0.05) 1px, transparent 1px); }
        @keyframes bounce-slow { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-12px); } }
        .animate-bounce-slow { animation: bounce-slow 4s ease-in-out infinite; }
        @keyframes bomb-drop { 0% { transform: translate(-50%, -300%) scale(2); opacity: 0; } 60% { transform: translate(-50%, -60%) scale(1); opacity: 1; } 100% { transform: translate(-50%, -60%) scale(14); opacity: 0; filter: blur(50px); } }
        .animate-bomb-drop { animation: bomb-drop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.06); background: rgba(255,255,255,0.98); border-radius: 4px; box-shadow: 0 1px 2px rgba(0,0,0,0.02); }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.03); background: rgba(18,18,18,0.95); }
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.08); border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.08); }

        .snow-effect {
          background-image: radial-gradient(circle, #fff 10%, transparent 10%), radial-gradient(circle, #fff 10%, transparent 10%);
          background-size: 15px 15px, 25px 25px;
          background-position: 0 0, 50px 50px;
          animation: snow-fall 10s linear infinite;
          opacity: 0.5;
        }
        @keyframes snow-fall {
          0% { background-position: 0 0, 50px 50px; }
          100% { background-position: 100px 500px, 150px 1000px; }
        }
      `}</style>
    </div>
  );
};

export default App;

export interface Task {
  id: string;
  text: string;
  completed: boolean;
  priority?: 'low' | 'medium' | 'high';
}

export interface BoardSpace {
  id: number;
  x: number;
  y: number;
  type: 'normal' | 'special';
}

export interface BigZombie {
  id: string;
  pos: number;
  health: number;
  isActive: boolean;
}

export interface PumpkinBoss {
  isActive: boolean;
  health: number;
}

export interface DemonBoss {
  isActive: boolean;
  health: number;
}

export interface SweetGoal {
  id: string;
  emoji: string;
  steps: number;
  maxSteps: number;
  timeLeft: number; // in seconds
  points: number;
  sizeMultiplier: number;
}

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss, SweetGoal } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

const ZOMBIE_INDICATOR_COUNT = 10; 
const BOMB_COUNT = 10;           
const MAX_PLAYER_HEALTH = 5; 

const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 

const APP_SCALE = 1.25; 
const SIDEBAR_WIDTH = 380;

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', 
  '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🐾',
  '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤',
  '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const EXPLOSION_POOL = [
  '🍦','🍧','🍨','🍩','🍪','🎂','🍰','🧁','🥧','🍫','🍬','🍭','🍮',
  '🍇','🍈','🍉','🍊','🍋','🍋‍🟩','🍌','🍍','🥭','🍎','🍏','🍐','🍑','🍒','🍓','🫐','🥝','🍅','🫒','🥥'
];

interface Particle {
  id: number;
  emoji: string;
  x: number;
  y: number;
  vx: number;
  vy: number;
  isFlying: boolean;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [diceColor, setDiceColor] = useState('rgba(255, 255, 255, 0.4)');
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  const [rewardPoints, setRewardPoints] = useState(0);
  const [rollsSinceSweets, setRollsSinceSweets] = useState(0);
  const [activeSweets, setActiveSweets] = useState<SweetGoal[]>([]);
  const [particles, setParticles] = useState<Particle[]>([]);

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<(Task & { completedAt: string })[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);
  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);

  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2, y: window.innerHeight / 2 },
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2 - 80, y: window.innerHeight / 2 },
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2 + 80, y: window.innerHeight / 2 }
  ]);

  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });

  const gameAreaRef = useRef<HTMLDivElement>(null);

  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(48);

  useEffect(() => {
    const updateSize = () => {
      const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
      const availableH = window.innerHeight / APP_SCALE;
      const horizontalLimit = (availableW - 60) / BOARD_W;
      const verticalLimit = (availableH - 60) / BOARD_H;
      const bestSize = Math.max(25, Math.min(horizontalLimit, verticalLimit, 45));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
    const availableH = window.innerHeight / APP_SCALE;
    const boardRealW = (BOARD_W - 1) * tileSize;
    const boardRealH = (BOARD_H - 1) * tileSize;
    const startX = (availableW - boardRealW) / 2;
    const startY = (availableH - boardRealH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, x: startX + i * tileSize, y: startY, type: 'normal' });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize, type: 'normal' });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize, type: 'normal' });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, x: startX, y: startY + i * tileSize, type: 'normal' });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    setZombieIndicators(getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude));
    setBombIndices(getRandomUnique(BOMB_COUNT, startExclude));
    setGhostIndices(getRandomUnique(3, startExclude));
    setRainbowIndices(getRandomUnique(3, startExclude));
    setClownIndices(getRandomUnique(2, startExclude));
  }, [boardSpaces.length, getRandomUnique]);

  // Main Ticker for Sweets and Particles
  useEffect(() => {
    const ticker = setInterval(() => {
      // Countdown time for sweets
      setActiveSweets(prev => {
        const next = prev.map(s => ({ ...s, timeLeft: Math.max(0, s.timeLeft - 1) }));
        // Remove sweets where time reached 0
        return next.filter(s => s.timeLeft > 0);
      });

      // Update particles
      setParticles(prev => {
        if (prev.length === 0) return prev;
        return prev.map(p => {
          if (p.isFlying) {
            // Target the 🎁 Box in sidebar (Top-Right of screen area basically)
            const targetX = (window.innerWidth - 100) / APP_SCALE;
            const targetY = 100 / APP_SCALE;
            const dx = targetX - p.x;
            const dy = targetY - p.y;
            const dist = Math.sqrt(dx*dx + dy*dy);
            if (dist < 15) return null;
            return {
              ...p,
              x: p.x + dx * 0.12,
              y: p.y + dy * 0.12
            };
          } else {
            // Burst phase
            const nextX = p.x + p.vx;
            const nextY = p.y + p.vy;
            const nextVx = p.vx * 0.94;
            const nextVy = p.vy * 0.94;
            if (Math.abs(nextVx) < 0.2 && Math.abs(nextVy) < 0.2) {
              return { ...p, isFlying: true };
            }
            return { ...p, x: nextX, y: nextY, vx: nextVx, vy: nextVy };
          }
        }).filter(Boolean) as Particle[];
      });
    }, 40);
    return () => clearInterval(ticker);
  }, []);

  const spawnParticles = (startX: number, startY: number, points: number) => {
    const count = 30;
    const newParts: Particle[] = [];
    for (let i = 0; i < count; i++) {
      const angle = (Math.PI * 2 * i) / count;
      const speed = Math.random() * 8 + 4;
      newParts.push({
        id: Math.random(),
        emoji: EXPLOSION_POOL[Math.floor(Math.random() * EXPLOSION_POOL.length)],
        x: startX,
        y: startY,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        isFlying: false
      });
    }
    setParticles(prev => [...prev, ...newParts]);
    setRewardPoints(p => p + points);
  };

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      stepsDone++;
      setJarCount(prev => Math.min(MAX_JAR, prev + 0.5));

      // Decrement steps for active sweets
      setActiveSweets(prev => prev.map(s => ({ ...s, steps: Math.max(0, s.steps - 1) })));

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (ghostIndices.includes(finalPos)) setIsGrayscale(true);
        if (rainbowIndices.includes(finalPos)) setIsGrayscale(false);
        if (clownIndices.includes(finalPos)) setIsClownMode(true);

        setActiveZombies(prev => {
          let hit = false;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + 2) % TOTAL_TILES;
            if (nextZPos === finalPos) hit = true;
            return { ...z, pos: nextZPos };
          });
          if (hit) setPlayerHealth(h => Math.max(0, h - 1));
          return moved;
        });

        if (zombieIndicators.includes(finalPos)) {
          setActiveZombies(z => [...z, { id: Math.random().toString(), pos: (finalPos - 5 + TOTAL_TILES) % TOTAL_TILES, health: 5, isActive: true }]);
        }
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, ghostIndices, rainbowIndices, clownIndices, zombieIndicators]);

  // Sweet completion check
  useEffect(() => {
    activeSweets.forEach(s => {
      if (s.steps === 0) {
        // Calculate explosion origin (Left of center jar)
        const centerX = (window.innerWidth - SIDEBAR_WIDTH) / 2 / APP_SCALE;
        const centerY = window.innerHeight / 2 / APP_SCALE;
        let x = centerX - 180;
        let y = centerY;
        // Adjust based on triangle layout offset
        if (s.id === '🍦') { x -= 40; y -= 40; }
        if (s.id === '🍰') { x += 40; y -= 40; }
        if (s.id === '🎂') { y += 40; }

        spawnParticles(x, y, s.points);
        setActiveSweets(prev => prev.filter(item => item.id !== s.id));
      }
    });
  }, [activeSweets]);

  const handleRoll = (landing: { x: number, y: number }, index: number) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);

    const nextRollCount = rollsSinceSweets + 1;
    if (nextRollCount >= 5) {
      setActiveSweets([
        { id: '🍦', emoji: '🍦', steps: 12, maxSteps: 12, timeLeft: 7200, points: 10, sizeMultiplier: 3 },
        { id: '🍰', emoji: '🍰', steps: 18, maxSteps: 18, timeLeft: 14400, points: 20, sizeMultiplier: 3 },
        { id: '🎂', emoji: '🎂', steps: 28, maxSteps: 28, timeLeft: 28800, points: 30, sizeMultiplier: 5 },
      ]);
      setRollsSinceSweets(0);
    } else {
      setRollsSinceSweets(nextRollCount);
    }

    const diceCount = isGrayscale ? 3 : 1;
    const newValues = Array.from({ length: diceCount }, () => Math.floor(Math.random() * 6) + 1);
    setDiceValues(newValues);

    setTimeout(() => {
      setIsRolling(false);
      setIsMoving(true);
      processMovement(newValues.reduce((a, b) => a + b, 0));
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const formatTime = (sec: number) => {
    const h = Math.floor(sec / 3600);
    const m = Math.floor((sec % 3600) / 60);
    const s = sec % 60;
    return `${h}h ${m}m ${s}s`;
  };

  return (
    <div className={`h-screen w-screen flex bg-white dark:bg-zinc-950 transition-all duration-700 ${isGrayscale ? 'filter grayscale' : ''}`}>

      {/* Game Area */}
      <div ref={gameAreaRef} className="flex-1 relative overflow-hidden notion-grid">
        <div className="relative w-full h-full flex items-center justify-center origin-top-left" style={{ transform: `scale(${APP_SCALE})` }}>
          <div className="relative w-full h-full">

            {/* Particles */}
            {particles.map(p => (
              <div key={p.id} className="absolute z-[100] transition-all duration-300 pointer-events-none" style={{ left: p.x, top: p.y, fontSize: '22px' }}>
                {p.emoji}
              </div>
            ))}

            {/* Board Tiles */}
            {boardSpaces.map(s => (
              <div key={s.id} className="absolute sudoku-tile flex items-center justify-center" style={{ left: s.x, top: s.y, width: tileSize, height: tileSize, backgroundColor: isClownMode ? `hsl(${s.id * 15 % 360}, 65%, 50%)` : undefined }}>
                <span className="text-[5px] opacity-20 absolute top-0.5 left-0.5 font-bold">{s.id + 1}</span>
                {zombieIndicators.includes(s.id) && <span className="opacity-10 text-xs">{ENEMY_ICON}</span>}
              </div>
            ))}

            {/* Central Area: Divided into Left (Sweets) | Center (Jar) | Right (Bosses) */}
            <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
                <div className="flex items-center gap-20 translate-y-6">

                    {/* LEFT: Sweets Inverted Triangle */}
                    <div className="flex flex-col items-center gap-10 min-w-[260px]">
                      {/* Top Row: 🍦 🍰 */}
                      <div className="flex gap-16">
                        {activeSweets.filter(s => s.id !== '🎂').map(s => (
                          <div key={s.id} className="flex flex-col items-center relative animate-bounce" style={{ animationDuration: '3.5s' }}>
                             <span className="leading-none drop-shadow-xl" style={{ fontSize: (tileSize * 1.3) * s.sizeMultiplier }}>{s.emoji}</span>
                             <div className="mt-2 w-24 h-1.5 bg-gray-100 dark:bg-white/5 rounded-full overflow-hidden border border-black/5">
                                <div className="h-full bg-pink-500 transition-all duration-300" style={{ width: `${(s.steps / s.maxSteps) * 100}%` }} />
                             </div>
                             <div className="flex flex-col items-center mt-1 opacity-60">
                                <span className="text-[7px] font-black uppercase tracking-widest">{s.steps} steps</span>
                                <span className="text-[6px] font-bold tabular-nums">{formatTime(s.timeLeft)}</span>
                             </div>
                          </div>
                        ))}
                      </div>
                      {/* Bottom Row: 🎂 */}
                      {activeSweets.find(s => s.id === '🎂') && (
                        <div className="flex flex-col items-center relative animate-bounce" style={{ animationDuration: '4.5s' }}>
                           <span className="leading-none drop-shadow-2xl" style={{ fontSize: (tileSize * 1.3) * 5 }}>🎂</span>
                           <div className="mt-2 w-36 h-2 bg-gray-100 dark:bg-white/5 rounded-full overflow-hidden border border-black/5">
                              <div className="h-full bg-pink-500 transition-all duration-300" style={{ width: `${(activeSweets.find(s => s.id === '🎂')!.steps / 28) * 100}%` }} />
                           </div>
                           <div className="flex flex-col items-center mt-1 opacity-60">
                              <span className="text-[8px] font-black uppercase tracking-widest">{activeSweets.find(s => s.id === '🎂')!.steps} steps</span>
                              <span className="text-[7px] font-bold tabular-nums">{formatTime(activeSweets.find(s => s.id === '🎂')!.timeLeft)}</span>
                           </div>
                        </div>
                      )}
                    </div>

                    {/* CENTER: Alchemy Jar */}
                    <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={() => {
                      setIsExploding(true);
                      setTimeout(() => {
                        setIsExploding(false);
                        setJarCount(0);
                        setRollBank(r => r + 40);
                      }, 1500);
                    }} height={tileSize * 6} />

                    {/* RIGHT: Bosses */}
                    <div className="flex flex-col items-center gap-14 min-w-[150px]">
                      {pumpkinBoss.isActive && <span className="text-7xl animate-pulse">🎃</span>}
                      {demonBoss.isActive && <span className="text-7xl animate-bounce">👹</span>}
                    </div>
                </div>
            </div>

            {/* Player Piece */}
            <div className="absolute z-30 transition-all duration-300" style={{ left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, transform: 'translate(-50%, -60%)', fontSize: tileSize * 1.3 }}>
               <div className="flex flex-col items-center">
                  <div className="flex gap-0.5 mb-1 bg-white/80 p-0.5 rounded-full px-1.5 border border-black/5">
                    {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => <div key={i} className={`w-1.5 h-0.5 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />)}
                  </div>
                  <span>{isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}</span>
               </div>
            </div>

            {/* Enemies */}
            {activeZombies.map(z => (
              <div key={z.id} className="absolute z-20 transition-all duration-700" style={{ left: boardSpaces[z.pos].x + tileSize/2, top: boardSpaces[z.pos].y + tileSize/2, transform: 'translate(-50%, -50%)', fontSize: tileSize }}>
                {ENEMY_ICON}
              </div>
            ))}
          </div>
        </div>

        {Array.from({ length: isGrayscale ? 3 : 1 }).map((_, i) => (
          <Dice3D 
            key={i} color={diceColor} value={diceValues[i] || 1} isRolling={isRolling} 
            currentPos={dicePositions[i] ?? { x: (window.innerWidth - SIDEBAR_WIDTH) / 2, y: window.innerHeight / 2 }} 
            onRoll={(p) => handleRoll(p, i)} 
            onDragEnd={(p) => setDicePositions(prev => { const n = [...prev]; n[i] = p; return n; })} 
            scale={isClownMode ? 3.5 : 1}
          />
        ))}
      </div>

      {/* Sidebar */}
      <div className="w-[380px] h-full bg-[#fbfbfa] dark:bg-[#191919] border-l border-[#efefef] dark:border-white/5 flex flex-col z-50 shadow-2xl">
        <div className="p-4 flex flex-col h-full">
          {/* Header */}
          <div className="flex items-center justify-between py-2 border-b border-[#eee] dark:border-white/5 mb-4">
            <div className="flex items-center gap-3">
              <div className="flex items-center gap-2">
                <span className="text-3xl drop-shadow-sm">🎁</span>
                <span className="text-[24px] font-black tabular-nums">{rewardPoints}</span>
              </div>
            </div>
            <div className="flex items-center gap-1">
              <div className="mr-2 pr-2 border-r border-gray-200 dark:border-gray-800">
                <span className="text-[16px] font-black">⚡ {rollBank}</span>
              </div>
              <button onClick={() => setDarkMode(!darkMode)} className="p-1.5 text-sm">{darkMode ? '☀️' : '🌙'}</button>
            </div>
          </div>

          {/* Quests */}
          <div className="flex-1 flex flex-col overflow-hidden">
             <div className="flex items-center justify-between mb-6">
                <h1 className="text-[14px] font-bold opacity-90">📋 Quests</h1>
                <div className="flex gap-4">
                   <button onClick={() => setShowHistory(false)} className={`text-[12px] font-medium ${!showHistory ? 'text-indigo-600 underline' : 'opacity-40'}`}>Active</button>
                   <button onClick={() => setShowHistory(true)} className={`text-[12px] font-medium ${showHistory ? 'text-indigo-600 underline' : 'opacity-40'}`}>Logbook</button>
                </div>
             </div>

             <div className="flex-1 overflow-y-auto custom-scrollbar">
                {!showHistory ? (
                   <div className="flex flex-col gap-1">
                      {tasks.map(t => (
                        <div key={t.id} onClick={() => handleTaskComplete(t)} className="group flex items-start gap-3 p-2 hover:bg-[#f3f3f2] dark:hover:bg-white/5 rounded-lg transition-all cursor-pointer">
                           <div className="mt-0.5 w-4.5 h-4.5 rounded-[4px] border border-[#ccc] dark:border-white/20 group-hover:bg-indigo-500 transition-all flex items-center justify-center">
                              <div className="w-2 h-2 bg-white rounded-[1px] opacity-0 group-hover:opacity-100" />
                           </div>
                           <p className="text-[14px] leading-[1.4] opacity-80">{t.text}</p>
                        </div>
                      ))}
                      <div className="mt-4 border-t border-[#efefef] dark:border-white/5 pt-6">
                        <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([...tasks, { id: Date.now().toString(), text: newTask, completed: false }]); setNewTask(''); }}>
                           <input value={newTask} onChange={e => setNewTask(e.target.value)} placeholder="+ New mission..." className="w-full py-2 bg-transparent outline-none text-[15px] placeholder:opacity-40" />
                        </form>
                      </div>
                   </div>
                ) : (
                  <div className="flex flex-col gap-2">
                     {history.map(h => (
                       <div key={h.id} className="p-3 bg-black/[0.01] dark:bg-white/[0.01] rounded-lg opacity-60">
                          <p className="text-[13px] line-through">{h.text}</p>
                          <span className="text-[9px] font-black opacity-30 mt-2 block">{h.completedAt}</span>
                       </div>
                     ))}
                  </div>
                )}
             </div>
          </div>
        </div>
      </div>

      <style>{`
        .notion-grid { background-image: radial-gradient(#efefef 1px, transparent 1px); background-size: 20px 20px; }
        .dark .notion-grid { background-image: radial-gradient(rgba(255,255,255,0.05) 1px, transparent 1px); }
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.08); border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default App;

export interface Task {
  id: string;
  text: string;
  completed: boolean;
  priority?: 'low' | 'medium' | 'high';
}

export interface BoardSpace {
  id: number;
  x: number;
  y: number;
  type: 'normal' | 'special';
}

export interface BigZombie {
  id: string;
  pos: number;
  health: number;
  isActive: boolean;
}

export interface PumpkinBoss {
  isActive: boolean;
  health: number;
}

export interface DemonBoss {
  isActive: boolean;
  health: number;
}

export interface Resources {
  rewardPoints: number;
}

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

const ZOMBIE_INDICATOR_COUNT = 10; 
const BOMB_COUNT = 10;           
const PUMPKIN_COUNT = 5; 
const DEMON_COUNT = 5; 
const CLOVER_COUNT = 5; 
const GHOST_COUNT = 3; 
const RAINBOW_COUNT = 3; 
const CLOWN_COUNT = 2; 

const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 
const SPAWN_BEHIND_OFFSET = 5;

const APP_SCALE = 1.25; 
const SIDEBAR_WIDTH = 380;

const ANIMAL_EMOJIS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', 
  '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🐾',
  '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤',
  '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const DICE_COLORS = [
  'rgba(255, 255, 255, 0.4)', 
  'rgba(199, 210, 254, 0.6)', 
  'rgba(254, 202, 202, 0.6)', 
  'rgba(167, 243, 208, 0.6)', 
  'rgba(253, 230, 138, 0.6)', 
];

interface CompletedTask extends Task {
  completedAt: string;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [isWinterMode, setIsWinterMode] = useState(false);
  const [diceColor, setDiceColor] = useState(DICE_COLORS[0]);
  const [isGrayscale, setIsGrayscale] = useState(false);
  const [isClownMode, setIsClownMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  const [rewardPoints, setRewardPoints] = useState(0);

  // State for Sweets mechanic
  const [rollsCount, setRollsCount] = useState(0);
  const [showSweets, setShowSweets] = useState(false);

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);

  const gameAreaRef = useRef<HTMLDivElement>(null);

  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2, y: window.innerHeight / 2 },
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2 - 100, y: window.innerHeight / 2 },
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2 + 100, y: window.innerHeight / 2 }
  ]);

  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);
  const [ghostIndices, setGhostIndices] = useState<number[]>([]);
  const [rainbowIndices, setRainbowIndices] = useState<number[]>([]);
  const [clownIndices, setClownIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(48);

  useEffect(() => {
    const updateSize = () => {
      const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
      const availableH = window.innerHeight / APP_SCALE;
      const horizontalLimit = (availableW - 60) / BOARD_W;
      const verticalLimit = (availableH - 60) / BOARD_H;
      const bestSize = Math.max(25, Math.min(horizontalLimit, verticalLimit, 45));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
    const availableH = window.innerHeight / APP_SCALE;
    const boardRealW = (BOARD_W - 1) * tileSize;
    const boardRealH = (BOARD_H - 1) * tileSize;
    const startX = (availableW - boardRealW) / 2;
    const startY = (availableH - boardRealH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);
    const gInd = getRandomUnique(GHOST_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd]);
    const rInd = getRandomUnique(RAINBOW_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd]);
    const clownInd = getRandomUnique(CLOWN_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd, ...cInd, ...gInd, ...rInd]);

    setZombieIndicators(zInd);
    setBombIndices(bInd);
    setPumpkinIndices(pInd);
    setDemonIndices(dInd);
    setCloverIndices(cInd);
    setGhostIndices(gInd);
    setRainbowIndices(rInd);
    setClownIndices(clownInd);
  }, [boardSpaces.length, getRandomUnique]);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1));
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const relocateItem = (list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...ghostIndices, ...rainbowIndices, ...clownIndices, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);

    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
      case 'ghost': setGhostIndices([...newList, newPos]); break;
      case 'rainbow': setRainbowIndices([...newList, newPos]); break;
      case 'clown': setClownIndices([...newList, newPos]); break;
    }
  };

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) {
      setPumpkinBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    if (demonBoss.isActive) {
      setDemonBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    setActiveZombies(prev => {
      if (prev.length === 0) return prev;
      let nearestIndex = 0;
      let minDistance = Infinity;
      prev.forEach((z, idx) => {
        const dist = Math.min(Math.abs(damagePos - z.pos), TOTAL_TILES - Math.abs(damagePos - z.pos));
        if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
      });
      const newZombies = [...prev];
      const target = { ...newZombies[nearestIndex] };
      target.health -= 1;
      if (target.health <= 0) {
        newZombies.splice(nearestIndex, 1);
      } else { newZombies[nearestIndex] = target; }
      return newZombies;
    });
    setIsShaking(true);
    setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 500);
  }, [pumpkinBoss, demonBoss, activeZombies]);

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    if (diceSum === 1) applyBombDamage(tempPos);

    const interval = setInterval(() => {
      tempPos = (tempPos + 1) % TOTAL_TILES;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      if (tempPos === 0) {
        setIsGrayscale(false);
        setIsClownMode(false);
      }

      if (cloverIndices.includes(tempPos)) {
        setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1));
        relocateItem(cloverIndices, tempPos, 'clover');
      }
      if (bombIndices.includes(tempPos)) {
        applyBombDamage(tempPos);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (ghostIndices.includes(finalPos)) {
          setIsGrayscale(true);
          setIsClownMode(false);
          relocateItem(ghostIndices, finalPos, 'ghost');
        } else if (rainbowIndices.includes(finalPos)) {
          setIsGrayscale(false);
          setIsClownMode(false);
          relocateItem(rainbowIndices, finalPos, 'rainbow');
        } else if (clownIndices.includes(finalPos)) {
          setIsClownMode(true);
          setIsGrayscale(false);
          relocateItem(clownIndices, finalPos, 'clown');
        }

        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombies(prev => [...prev, {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          }]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }
        if (pumpkinIndices.includes(finalPos)) {
          setPumpkinBoss(prev => ({ isActive: true, health: MAX_PUMPKIN_HEALTH }));
          relocateItem(pumpkinIndices, finalPos, 'pumpkin');
        }
        if (demonIndices.includes(finalPos)) {
          setDemonBoss(prev => ({ isActive: true, health: MAX_DEMON_HEALTH }));
          relocateItem(demonIndices, finalPos, 'demon');
        }

        setActiveZombies(prev => {
          let gameOver = false;
          const moveSteps = demonBoss.isActive ? 3 : 2;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + moveSteps) % TOTAL_TILES;
            if (nextZPos === finalPos) gameOver = true;
            return { ...z, pos: nextZPos };
          });
          if (gameOver) {
            setPlayerHealth(h => {
              const next = h - 1;
              if (next <= 0) {
                handleGameOver();
                return MAX_PLAYER_HEALTH;
              }
              return next;
            });
            return [];
          }
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, pumpkinBoss, demonBoss, pumpkinIndices, demonIndices, cloverIndices, ghostIndices, rainbowIndices, clownIndices, applyBombDamage]);

  const handleGameOver = () => {
    setIsShaking(true);
    setJarCount(0);
    setCurrentPos(0);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setIsGrayscale(false);
    setIsClownMode(false);
    setTimeout(() => setIsShaking(false), 500);
  };

  const handleRoll = (landing: { x: number, y: number }, index: number) => {
    if (rollBank <= 0 || isRolling || isMoving) return;

    if (pumpkinBoss.isActive) {
      setIsDeducting(true);
      setJarCount(prev => Math.max(0, prev - 5));
      setTimeout(() => setIsDeducting(false), 800);
    }

    setIsRolling(true);
    setRollBank(r => r - 1);

    // Roll counter logic
    setRollsCount(prev => {
      const next = prev + 1;
      if (next % 5 === 0) {
        setShowSweets(true);
      } else {
        setShowSweets(false);
      }
      return next;
    });

    const diceCount = isGrayscale ? 3 : 1;
    const newValues = Array.from({ length: diceCount }, () => Math.floor(Math.random() * 6) + 1);
    const newPositions = Array.from({ length: diceCount }, (_, i) => ({
      x: landing.x + (i - Math.floor(diceCount / 2)) * (isClownMode ? 180 : 80),
      y: landing.y
    }));

    setDicePositions(newPositions);

    setTimeout(() => {
      setIsRolling(false);
      setDiceValues(newValues);
      setIsMoving(true);
      const sum = newValues.reduce((a, b) => a + b, 0);
      processMovement(sum);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  const ENEMY_ICON = isWinterMode ? '⛄' : (darkMode ? '🧛🏻' : '🧟');
  const BOMB_ICON = isWinterMode ? '🔥' : (darkMode ? '🧄' : '💣');

  const getClownTileColor = (id: number) => {
    if (!isClownMode) return undefined;
    const colors = ['#ff00ff', '#00ffff', '#ffff00', '#ff0000', '#00ff00', '#ff8800', '#8800ff'];
    return colors[id % colors.length] + 'cc';
  };

  const activeDiceCount = isGrayscale ? 3 : 1;
  const currentDiceScale = isClownMode ? 3.5 : 1;

  const playerBaseSize = tileSize * 1.3;

  return (
    <div className={`h-screen w-screen flex transition-all duration-700 bg-white dark:bg-zinc-950
      ${isExploding ? 'bg-indigo-600/10' : ''} 
      ${isGrayscale ? 'filter grayscale' : ''}
    `}>
      {isWinterMode && <div className="fixed inset-0 z-10 pointer-events-none snow-effect" />}

      {/* Main Game Area (Left) */}
      <div 
        ref={gameAreaRef}
        className="flex-1 relative overflow-hidden notion-grid"
      >
        <div 
          className="relative w-full h-full origin-top-left flex items-center justify-center"
          style={{ transform: `scale(${APP_SCALE})` }}
        >
          <div className="relative w-full h-full">
            <div className="absolute inset-0 z-0 pointer-events-none">
                {boardSpaces.map(s => {
                  const bloom = blooms[s.id];
                  const isBomb = bombIndices.includes(s.id);
                  const isZombie = zombieIndicators.includes(s.id);
                  const isPumpkin = pumpkinIndices.includes(s.id);
                  const isDemon = demonIndices.includes(s.id);
                  const isClover = cloverIndices.includes(s.id);
                  const isGhost = ghostIndices.includes(s.id);
                  const isRainbow = rainbowIndices.includes(s.id);
                  const isClown = clownIndices.includes(s.id);
                  const isStart = s.id === 0;

                  let icon = null;
                  if (isBomb) icon = BOMB_ICON;
                  else if (isZombie) icon = ENEMY_ICON;
                  else if (isPumpkin) icon = '🎃';
                  else if (isDemon) icon = '👹';
                  else if (isClover) icon = '🍀';
                  else if (isGhost) icon = '👻';
                  else if (isRainbow) icon = '🌈';
                  else if (isClown) icon = '🤡';

                  return (
                    <div 
                      key={s.id}
                      className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500 ${isStart ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
                      style={{ 
                          left: s.x, top: s.y, width: tileSize, height: tileSize,
                          backgroundColor: isClownMode ? getClownTileColor(s.id) : undefined 
                      }}
                    >
                      <span className="text-[5px] opacity-20 absolute top-0.5 left-0.5 font-bold">{s.id + 1}</span>
                      {icon && <span className="drop-shadow-sm opacity-25" style={{ fontSize: tileSize * 0.55 }}>{icon}</span>}
                      {bloom && <span className="bloom absolute opacity-25" style={{ fontSize: tileSize * 0.5 }}>{bloom}</span>}
                      {isStart && !bloom && !icon && <span className="text-[7px] font-black opacity-30 uppercase tracking-widest">Home</span>}
                    </div>
                  );
                })}

                {activeZombies.map(z => boardSpaces[z.pos] && (
                <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ 
                    left: boardSpaces[z.pos].x + tileSize/2, 
                    top: boardSpaces[z.pos].y + tileSize/2, 
                    transform: `translate(-50%, -60%) scale(${demonBoss.isActive ? 1.8 : 0.9})` 
                }}>
                    <div className="flex flex-col items-center">
                        <div className="flex gap-0.5 mb-1 bg-white/90 dark:bg-black/80 p-0.5 rounded-full px-1.5 border border-black/5 shadow-sm">
                        {[...Array(MAX_ZOMBIE_HEALTH)].map((_, i) => (
                            <div key={i} className={`w-1.5 h-0.5 rounded-full ${i < z.health ? 'bg-red-500' : 'bg-gray-200 dark:bg-gray-800'}`} />
                        ))}
                        </div>
                        <span className="drop-shadow-2xl animate-pulse" style={{ fontSize: tileSize * 1.1 }}>{ENEMY_ICON}</span>
                    </div>
                </div>
                ))}

                <div 
                onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_EMOJIS.length)}
                className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto`}
                style={{ 
                    left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, 
                    top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, 
                    transform: 'translate(-50%, -60%)',
                    fontSize: tileSize * 1.3
                }}
                >
                <div className="flex flex-col items-center">
                    <div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-1.5 border border-black/5 shadow-sm">
                        {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (
                        <div key={i} className={`w-1.5 h-0.5 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />
                        ))}
                    </div>
                    <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">
                    {isClownMode ? '🤡' : ANIMAL_EMOJIS[animalIndex]}
                    </span>
                </div>
                </div>

                {bombAnimation.active && (
                <div className="absolute z-50 animate-bomb-drop" style={{ 
                    left: boardSpaces[bombAnimation.pos]?.x + tileSize/2, 
                    top: boardSpaces[bombAnimation.pos]?.y + tileSize/2,
                    transform: 'translate(-50%, -100%)'
                }}>
                    <span className="text-7xl drop-shadow-2xl">{darkMode ? '✨' : '💥'}</span>
                </div>
                )}
            </div>

            {/* Central Area: Alchemy Jar (Center) and Sweets (Left) */}
            <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
                <div className="flex items-center gap-16 translate-y-6">
                    {/* Sweets Section (Left of Jar) */}
                    <div className="flex flex-col items-center gap-4 min-w-[300px] h-[350px] justify-center transition-opacity duration-1000" style={{ opacity: showSweets ? 1 : 0 }}>
                       <div className="flex gap-12">
                          <span className="drop-shadow-xl select-none" style={{ fontSize: playerBaseSize * 3 }}>🍦</span>
                          <span className="drop-shadow-xl select-none" style={{ fontSize: playerBaseSize * 3 }}>🍰</span>
                       </div>
                       <div className="translate-y-4">
                          <span className="drop-shadow-2xl select-none" style={{ fontSize: playerBaseSize * 5 }}>🎂</span>
