                        >
                           <div className="flex items-end gap-6 mb-2">
                              <span className="drop-shadow-xl select-none leading-none" style={{ fontSize: playerBaseSize * 2 }}>🍦</span>
                              <span className="drop-shadow-xl select-none leading-none" style={{ fontSize: playerBaseSize * 3 }}>🍰</span>
                           </div>
                           <div className="mt-1">
                              <span className="drop-shadow-2xl select-none leading-none" style={{ fontSize: playerBaseSize * 3.5 }}>🎂</span>
                           </div>
                        </div>

                        {/* CENTER COLUMN: Alchemy Jar */}
