                           <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} height={tileSize * 6} />
                        </div>

                        {/* RIGHT COLUMN: Bosses Section */}
                        <div className="flex flex-col items-center gap-10 w-full">
