import React, { useState, useRef, useEffect } from 'react';

interface AlchemyJarProps {
  count: number;
  max: number;
  isExploding: boolean;
  onExplode: () => void;
  isDeducting?: boolean;
  height?: number;
}

export const AlchemyJar: React.FC<AlchemyJarProps> = ({ 
  count, 
  max, 
  isExploding, 
  onExplode, 
  isDeducting,
  height = 320
}) => {
  const percent = Math.min(100, (count / max) * 100);
  const isFull = count >= max;
  const [holdProgress, setHoldProgress] = useState(0);
  const holdInterval = useRef<number | null>(null);

  const startHold = () => {
    if (!isFull || isExploding) return;
    holdInterval.current = window.setInterval(() => {
      setHoldProgress(prev => {
        if (prev >= 100) {
          if (holdInterval.current) clearInterval(holdInterval.current);
          onExplode();
          return 0;
        }
        return prev + 1;
      });
    }, 30);
  };

  const endHold = () => {
    if (holdInterval.current) {
      clearInterval(holdInterval.current);
      holdInterval.current = null;
    }
    setHoldProgress(0);
  };

  return (
    <div 
      className="flex flex-col items-center justify-end relative w-16 group"
      style={{ height: `${height}px` }}
    >
      <div 
        className={`relative w-12 cursor-pointer transition-all duration-700 
          ${isExploding ? 'scale-150 blur-3xl opacity-0' : 'scale-100'} 
          ${isFull && !isExploding ? 'hover:scale-105' : ''}`}
        style={{ height: '85%' }}
        onMouseDown={startHold}
        onMouseUp={endHold}
        onMouseLeave={endHold}
        onTouchStart={startHold}
        onTouchEnd={endHold}
      >
        {/* Test Tube Top (Cork) */}
        <div className="absolute -top-3 left-1/2 -translate-x-1/2 w-8 h-4 bg-[#8B4513] dark:bg-[#5D2E0C] rounded-t-sm rounded-b-md z-30 shadow-sm border-b border-black/20" />

        {/* Test Tube Body */}
        <div className="absolute inset-0 bg-white/10 dark:bg-black/20 border-x-2 border-t-2 border-white/40 dark:border-white/10 backdrop-blur-md overflow-hidden shadow-xl rounded-b-full z-10">

          {/* Glass Glare */}
          <div className="absolute left-1.5 top-2 w-1.5 h-1/2 bg-white/20 rounded-full blur-[1px] z-20" />

          {/* Liquid */}
          <div 
            className={`absolute bottom-0 left-0 w-full transition-all duration-1000 ease-out ${isDeducting ? 'bg-red-500/80' : 'bg-indigo-500/80'}`}
            style={{ height: `${percent}%` }}
          >
            {/* Liquid Shine */}
            <div className="absolute top-0 left-0 w-full h-[2px] bg-white/30" />

            {/* Bubbles */}
            <div className="absolute inset-0 overflow-hidden">
               {[...Array(5)].map((_, i) => (
                 <div 
                   key={i} 
                   className="absolute bottom-0 bg-white/30 rounded-full animate-bubble"
                   style={{
                     width: Math.random() * 4 + 2,
                     height: Math.random() * 4 + 2,
                     left: `${Math.random() * 100}%`,
                     animationDuration: `${Math.random() * 3 + 1.5}s`,
                     animationDelay: `${Math.random() * 2}s`
                   }}
                 />
               ))}
            </div>
          </div>

          {/* Percentage */}
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-30">
            <span className={`text-[9px] font-black drop-shadow-sm transition-colors ${percent > 50 ? 'text-white' : 'text-indigo-500'}`}>
              {isDeducting ? '-5%' : `${Math.floor(percent)}%`}
            </span>
          </div>
        </div>

        {/* Hold progress circle */}
        {holdProgress > 0 && (
          <div className="absolute inset-0 flex items-center justify-center z-40 pointer-events-none">
            <svg className="w-10 h-10 -rotate-90">
              <circle
                cx="20"
                cy="20"
                r="18"
                fill="none"
                stroke="white"
                strokeWidth="3"
                strokeDasharray={`${(holdProgress * 113) / 100} 113`}
                strokeLinecap="round"
                className="opacity-80"
              />
            </svg>
          </div>
        )}
      </div>

      <div className="mt-4 text-center">
        <span className={`text-[7px] font-black uppercase tracking-[0.25em] px-2.5 py-1 rounded-full border transition-all
          ${isFull ? 'bg-indigo-500 text-white border-indigo-400 shadow-indigo-500/20 shadow-lg' : 'bg-black/5 dark:bg-white/5 text-gray-400 border-transparent opacity-40'}`}>
          {isFull ? 'Extract' : 'Vial'}
        </span>
      </div>

      <style>{`
        @keyframes bubble {
          0% { transform: translateY(20px) scale(0.5); opacity: 0; }
          20% { opacity: 0.6; }
          100% { transform: translateY(-120px) scale(1.2); opacity: 0; }
        }
        .animate-bubble { animation: bubble linear infinite; }
      `}</style>
    </div>
  );
};

