import React, { useState, useRef } from 'react';

interface AlchemyJarProps {
  count: number;
  max: number;
  isExploding: boolean;
  onExplode: () => void;
  isDeducting?: boolean;
  height?: number;
}

export const AlchemyJar: React.FC<AlchemyJarProps> = ({ 
  count, 
  max, 
  isExploding, 
  onExplode, 
  isDeducting,
  height = 320
}) => {
  const percent = Math.min(100, (count / max) * 100);
  const isFull = count >= max;
  const [holdProgress, setHoldProgress] = useState(0);
  const holdInterval = useRef<number | null>(null);

  const startHold = () => {
    if (!isFull || isExploding) return;
    holdInterval.current = window.setInterval(() => {
      setHoldProgress(prev => {
        if (prev >= 100) {
          if (holdInterval.current) clearInterval(holdInterval.current);
          onExplode();
          return 0;
        }
        return prev + 1;
      });
    }, 30);
  };

  const endHold = () => {
    if (holdInterval.current) {
      clearInterval(holdInterval.current);
      holdInterval.current = null;
    }
    setHoldProgress(0);
  };

  return (
    <div 
      className="flex flex-col items-center justify-end relative w-20 group"
      style={{ height: `${height}px` }}
    >
      <div 
        className={`relative w-10 cursor-pointer transition-all duration-700 
          ${isExploding ? 'scale-150 blur-3xl opacity-0' : 'scale-100'} 
          ${isFull && !isExploding ? 'hover:scale-105 active:scale-95' : ''}`}
        style={{ height: '90%' }}
        onMouseDown={startHold}
        onMouseUp={endHold}
        onMouseLeave={endHold}
        onTouchStart={startHold}
        onTouchEnd={endHold}
      >
        {/* Cork Top */}
        <div className="absolute -top-4 left-1/2 -translate-x-1/2 w-7 h-5 bg-[#7B3F00] dark:bg-[#4D2800] rounded-t-sm rounded-b-md z-30 shadow-sm border-b border-black/30" />

        {/* Rim */}
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-12 h-2 bg-white/30 backdrop-blur-md rounded-full border border-white/40 z-20" />

        {/* Test Tube Glass Body */}
        <div className="absolute inset-0 bg-white/10 dark:bg-black/40 border-x-2 border-b-2 border-white/50 dark:border-white/20 backdrop-blur-lg overflow-hidden shadow-2xl rounded-b-full z-10">

          {/* Vertical Glare Reflection */}
          <div className="absolute left-2 top-4 w-1.5 h-3/4 bg-white/20 rounded-full blur-[1.5px] z-20" />
          <div className="absolute right-2 top-10 w-1 h-1/2 bg-white/10 rounded-full blur-[2px] z-20" />

          {/* Alchemy Liquid Content */}
          <div 
            className={`absolute bottom-0 left-0 w-full transition-all duration-1000 ease-out ${isDeducting ? 'bg-red-500/70' : 'bg-gradient-to-t from-indigo-700/80 to-indigo-500/80'}`}
            style={{ height: `${percent}%` }}
          >
            {/* Top Surface Glow */}
            <div className="absolute top-0 left-0 w-full h-[3px] bg-white/40 blur-[1px]" />

            {/* Laboratory Bubbles */}
            <div className="absolute inset-0 overflow-hidden">
               {[...Array(6)].map((_, i) => (
                 <div 
                   key={i} 
                   className="absolute bottom-0 bg-white/40 rounded-full animate-bubble"
                   style={{
                     width: Math.random() * 5 + 2,
                     height: Math.random() * 5 + 2,
                     left: `${Math.random() * 100}%`,
                     animationDuration: `${Math.random() * 2 + 1.5}s`,
                     animationDelay: `${Math.random() * 3}s`
                   }}
                 />
               ))}
            </div>
          </div>

          {/* Internal Progress Text */}
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-30">
            <span className={`text-[10px] font-black tracking-tighter transition-colors ${percent > 50 ? 'text-white' : 'text-indigo-400 dark:text-indigo-300'}`}>
              {isDeducting ? '-5' : `${Math.floor(percent)}`}
            </span>
          </div>
        </div>

        {/* Circular Hold Indicator Overlay */}
        {holdProgress > 0 && (
          <div className="absolute inset-0 flex items-center justify-center z-40 pointer-events-none">
            <svg className="w-14 h-14 -rotate-90 drop-shadow-lg">
              <circle
                cx="28"
                cy="28"
                r="24"
                fill="none"
                stroke="white"
                strokeWidth="4"
                strokeDasharray={`${(holdProgress * 151) / 100} 151`}
                strokeLinecap="round"
                className="opacity-90"
              />
            </svg>
          </div>
        )}
      </div>

      <div className="mt-6 flex flex-col items-center">
        <span className={`text-[8px] font-black uppercase tracking-[0.3em] px-3 py-1.5 rounded-full border transition-all duration-500
          ${isFull ? 'bg-indigo-600 text-white border-indigo-400 shadow-[0_0_15px_rgba(79,70,229,0.4)]' : 'bg-black/5 dark:bg-white/5 text-gray-500 dark:text-gray-400 border-transparent opacity-40'}`}>
          {isFull ? 'Ready' : 'Vial'}
        </span>
      </div>

      <style>{`
        @keyframes bubble {
          0% { transform: translateY(20px) scale(0.4); opacity: 0; }
          30% { opacity: 0.7; }
          100% { transform: translateY(-150px) scale(1.1); opacity: 0; }
        }
        .animate-bubble { animation: bubble linear infinite; }
      `}</style>
    </div>
  );
};

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

const ZOMBIE_INDICATOR_COUNT = 8; // Reduced for performance
const BOMB_COUNT = 8;           
const PUMPKIN_COUNT = 4; 
const DEMON_COUNT = 4; 
const CLOVER_COUNT = 4; 

const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 
const SPAWN_BEHIND_OFFSET = 5;

const APP_SCALE = 1.25; 
const SIDEBAR_WIDTH = 380;

const ANIMAL_ICONS = ['🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞', '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🐾', '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺', '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤', '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'];
const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const EXPLOSION_EMOJIS = ['🍦','🍧','🍨','🍩','🍪','🎂','🍰','🧁','🥧','🍫','🍬','🍭','🍮','🍇','🍈','🍉','🍊','🍋','🍋‍🟩','🍌','🍍','🥭','🍎','🍏','🍐','🍑','🍒','🍓','🫐','🍅','🫒','🥥'];

interface CompletedTask extends Task {
  completedAt: string;
}

interface SweetData {
  id: string;
  emoji: string;
  steps: number;
  totalSteps: number;
  secondsLeft: number;
  points: number;
  sizeMultiplier: number;
}

interface Particle {
  id: number;
  emoji: string;
  x: number;
  y: number;
  delay: number;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  const [rewardPoints, setRewardPoints] = useState(0);
  const [rollsCount, setRollsCount] = useState(0);
  const [jarUses, setJarUses] = useState(0);
  const [mapCompletions, setMapCompletions] = useState(0);

  const [activeSweets, setActiveSweets] = useState<Record<string, SweetData>>({});
  const [particles, setParticles] = useState<Particle[]>([]);

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);

  const gameAreaRef = useRef<HTMLDivElement>(null);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2, y: window.innerHeight / 2 }
  ]);

  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  const [tileSize, setTileSize] = useState(48);

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  useEffect(() => {
    const updateSize = () => {
      const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
      const availableH = window.innerHeight / APP_SCALE;
      const bestSize = Math.max(25, Math.min((availableW - 60) / BOARD_W, (availableH - 60) / BOARD_H, 40));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
    const availableH = window.innerHeight / APP_SCALE;
    const boardRealW = (BOARD_W - 1) * tileSize;
    const boardRealH = (BOARD_H - 1) * tileSize;
    const startX = (availableW - boardRealW) / 2;
    const startY = (availableH - boardRealH) / 2;

    for (let i = 0; i < BOARD_W; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });
    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    setZombieIndicators(getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude));
    setBombIndices(getRandomUnique(BOMB_COUNT, [...startExclude]));
    setPumpkinIndices(getRandomUnique(PUMPKIN_COUNT, [...startExclude]));
    setDemonIndices(getRandomUnique(DEMON_COUNT, [...startExclude]));
    setCloverIndices(getRandomUnique(CLOVER_COUNT, [...startExclude]));
  }, [boardSpaces.length]);

  useEffect(() => {
    const timer = setInterval(() => {
      setActiveSweets(prev => {
        const next = { ...prev };
        let changed = false;
        Object.keys(next).forEach(id => {
          if (next[id].secondsLeft > 0) {
            next[id].secondsLeft -= 1;
            changed = true;
          }
        });
        return changed ? next : prev;
      });
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const triggerExplosionTrail = useCallback((x: number, y: number, points: number) => {
    const newParticles: Particle[] = Array.from({ length: 12 }).map((_, i) => ({
      id: Math.random(),
      emoji: EXPLOSION_EMOJIS[Math.floor(Math.random() * EXPLOSION_EMOJIS.length)],
      x: x + (Math.random() - 0.5) * 40,
      y: y + (Math.random() - 0.5) * 40,
      delay: i * 60
    }));

    setParticles(prev => [...prev, ...newParticles]);
    setTimeout(() => {
      setRewardPoints(prev => prev + points);
      setParticles(prev => prev.filter(p => !newParticles.find(np => np.id === p.id)));
    }, 2200);
  }, []);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1.2)); // Faster filling
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 600);
  };

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      const nextPos = (tempPos + 1) % TOTAL_TILES;
      if (nextPos === 0) setMapCompletions(prev => prev + 1);

      tempPos = nextPos;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      setActiveSweets(prev => {
        const next = { ...prev };
        Object.keys(next).forEach(id => {
          if (next[id].steps > 0) {
            next[id].steps -= 1;
            if (next[id].steps === 0) {
              const availableW = window.innerWidth;
              const centerX = (availableW - SIDEBAR_WIDTH) / 2;
              const centerY = window.innerHeight / 2 - (tileSize * 2);
              let x = centerX, y = centerY;
              if (id === 'cone') x -= 50; else if (id === 'slice') x += 50; else y += 40;
              triggerExplosionTrail(x, y, next[id].points);
              delete next[id];
            }
          }
        });
        return next;
      });

      if (cloverIndices.includes(tempPos)) setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1));
      if (bombIndices.includes(tempPos)) {
          setBombAnimation({ active: true, pos: tempPos });
          setTimeout(() => setBombAnimation({ active: false, pos: -1 }), 400);
      }

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (zombieIndicators.includes(finalPos)) {
          setActiveZombies(prev => [...prev, { id: Math.random().toString(), pos: (finalPos - 5 + TOTAL_TILES) % TOTAL_TILES, health: MAX_ZOMBIE_HEALTH, isActive: true }]);
        }
        if (pumpkinIndices.includes(finalPos)) setPumpkinBoss({ isActive: true, health: MAX_PUMPKIN_HEALTH });
        if (demonIndices.includes(finalPos)) setDemonBoss({ isActive: true, health: MAX_DEMON_HEALTH });

        setActiveZombies(prev => {
          let damaged = false;
          const moved = prev.map(z => {
            const nz = (z.pos + 2) % TOTAL_TILES;
            if (nz === finalPos) damaged = true;
            return { ...z, pos: nz };
          });
          if (damaged) setPlayerHealth(h => Math.max(0, h - 1));
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, cloverIndices, bombIndices, zombieIndicators, pumpkinIndices, demonIndices, tileSize]);

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);

    setRollsCount(prev => {
      if (Object.keys(activeSweets).length > 0) return prev;
      const next = prev + 1;
      if (next % 5 === 0) {
        setActiveSweets({
          cone: { id: 'cone', emoji: '🍦', steps: 12, totalSteps: 12, secondsLeft: 2 * 3600, points: 10, sizeMultiplier: 1.0 },
          slice: { id: 'slice', emoji: '🍰', steps: 18, totalSteps: 18, secondsLeft: 4 * 3600, points: 20, sizeMultiplier: 1.2 },
          cake: { id: 'cake', emoji: '🎂', steps: 28, totalSteps: 28, secondsLeft: 8 * 3600, points: 30, sizeMultiplier: 1.8 },
        });
        return 0; 
      }
      return next;
    });

    const val = Math.floor(Math.random() * 6) + 1;
    setDicePositions([{ x: landing.x, y: landing.y }]);
    setTimeout(() => { setIsRolling(false); setDiceValues([val]); setIsMoving(true); processMovement(val); }, 1000);
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setJarUses(prev => prev + 1);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => { setIsExploding(false); setJarCount(0); setRollBank(r => r + 40); }, 1000);
  };

  const formatTime = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    return `${h}h${m}m`;
  };

  return (
    <div className={`h-screen w-screen flex bg-white dark:bg-zinc-950 transition-colors duration-500`}>
      {particles.map(p => (
        <div key={p.id} className="fixed z-[100] text-2xl pointer-events-none" style={{ left: p.x, top: p.y, animation: `trail-move 2s ease-in-out ${p.delay}ms forwards` }}>{p.emoji}</div>
      ))}

      <div ref={gameAreaRef} className="flex-1 relative overflow-hidden notion-grid">
        <div className="relative w-full h-full flex items-center justify-center" style={{ transform: `scale(${APP_SCALE})` }}>
          <div className="relative w-full h-full">
            <div className="absolute inset-0 z-0">
                {boardSpaces.map(s => (
                  <div key={s.id} className="absolute sudoku-tile flex items-center justify-center opacity-80" style={{ left: s.x, top: s.y, width: tileSize, height: tileSize }}>
                    {blooms[s.id] && <span className="bloom absolute text-sm opacity-60">{blooms[s.id]}</span>}
                  </div>
                ))}

                {activeZombies.map(z => boardSpaces[z.pos] && (
                  <div key={z.id} className="absolute z-20 transition-all duration-500" style={{ left: boardSpaces[z.pos].x + tileSize/2, top: boardSpaces[z.pos].y + tileSize/2, transform: 'translate(-50%, -50%)' }}>
                    <span className="text-xl">🧛🏻</span>
                  </div>
                ))}

                <div className="absolute z-30 transition-all duration-300" style={{ left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, transform: 'translate(-50%, -60%)' }}>
                    <div className="flex flex-col items-center">
                        <div className="flex gap-0.5 mb-0.5 bg-white/80 p-0.5 rounded-full border border-black/5">
                            {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => <div key={i} className={`w-1 h-0.5 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />)}
                        </div>
                        <span className="text-2xl">{ANIMAL_ICONS[animalIndex]}</span>
                    </div>
                </div>
            </div>

            <div className="absolute inset-0 flex items-center justify-center">
                <div className="grid grid-cols-3 w-full max-w-4xl items-center justify-items-center">
                    <div className="flex flex-col items-center gap-4 transition-all" style={{ opacity: Object.keys(activeSweets).length > 0 ? 1 : 0, transform: `translateY(-${tileSize}px)` }}>
                        {activeSweets.cone && <div className="flex flex-col items-center"><span className="text-[8px] font-black opacity-40">{activeSweets.cone.steps}s | {formatTime(activeSweets.cone.secondsLeft)}</span><span style={{ fontSize: tileSize * activeSweets.cone.sizeMultiplier }}>🍦</span></div>}
                        {activeSweets.slice && <div className="flex flex-col items-center"><span className="text-[8px] font-black opacity-40">{activeSweets.slice.steps}s | {formatTime(activeSweets.slice.secondsLeft)}</span><span style={{ fontSize: tileSize * activeSweets.slice.sizeMultiplier }}>🍰</span></div>}
                        {activeSweets.cake && <div className="flex flex-col items-center"><span className="text-[8px] font-black opacity-40">{activeSweets.cake.steps}s | {formatTime(activeSweets.cake.secondsLeft)}</span><span style={{ fontSize: tileSize * activeSweets.cake.sizeMultiplier }}>🎂</span></div>}
                    </div>

                    <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} height={tileSize * 9} />

                    <div className="flex flex-col gap-6">
                        {pumpkinBoss.isActive && <span className="text-3xl animate-bounce-slow">🎃</span>}
                        {demonBoss.isActive && <span className="text-3xl animate-bounce-slow" style={{ animationDelay: '-1s' }}>👹</span>}
                    </div>
                </div>
            </div>
          </div>
        </div>

        <Dice3D value={diceValues[0]} isRolling={isRolling} currentPos={dicePositions[0]} onRoll={handleRoll} onDragEnd={(p) => setDicePositions([p])} />
      </div>

      <div className="w-[380px] h-full bg-[#fbfbfa] dark:bg-[#191919] border-l border-[#efefef] dark:border-white/5 flex flex-col z-50 shadow-2xl overflow-hidden">
        <div className="p-4 flex flex-col h-full">
          <div className="flex flex-col gap-4 py-2 border-b border-[#eee] dark:border-white/5 mb-4">
             <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                   <div className="flex items-center gap-1.5"><span className="text-lg">🎁</span><span className="text-sm font-black opacity-80">{rewardPoints}</span></div>
                   <div className="flex items-center gap-1.5"><span className="text-lg">⚗️</span><span className="text-sm font-black opacity-80">{jarUses}</span></div>
                   <div className="flex items-center gap-1.5"><span className="text-lg">🏅</span><span className="text-sm font-black opacity-80">{mapCompletions}</span></div>
                </div>
                <button onClick={() => setDarkMode(!darkMode)} className="p-1.5 rounded-md hover:bg-black/5 dark:hover:bg-white/5 text-xs">{darkMode ? '☀️' : '🌙'}</button>
             </div>
             <div className="flex items-center gap-4 text-[10px] font-black opacity-30 uppercase tracking-widest">
               <div className="flex items-center gap-1"><span>⚡</span><span>Energy: {rollBank}</span></div>
               <div className="flex items-center gap-1"><span>🎲</span><span>Rolls: {rollsCount}</span></div>
             </div>
          </div>

          <div className="flex-1 overflow-y-auto px-1">
             <div className="flex items-center justify-between mb-4"><h1 className="text-sm font-bold opacity-80">Missions</h1></div>
             <div className="flex flex-col gap-2">
                {tasks.map(t => (
                  <div key={t.id} className="p-3 bg-black/5 dark:bg-white/5 rounded-lg opacity-80 hover:opacity-100 cursor-pointer transition-opacity" onClick={() => {
                    setRollBank(r => r + 15);
                    setHistory(prev => [{ ...t, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
                    setTasks(prev => prev.filter(x => x.id !== t.id));
                  }}>
                    <p className="text-xs">{t.text}</p>
                    <div className="mt-1 text-[8px] font-black uppercase opacity-40">{t.priority}</div>
                  </div>
                ))}
