        </div>
      </div>

      <style>{`
        .notion-grid { background-image: radial-gradient(#efefef 1px, transparent 1px); background-size: 20px 20px; }
        .dark .notion-grid { background-image: radial-gradient(rgba(255,255,255,0.05) 1px, transparent 1px); }
        @keyframes bounce-slow { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-8px); } }
        .animate-bounce-slow { animation: bounce-slow 4s ease-in-out infinite; }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.04); background: rgba(255,255,255,0.9); }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.02); background: rgba(20,20,20,0.8); }
        @keyframes trail-move { 0% { transform: translate(0, 0) scale(1); opacity: 1; } 100% { left: calc(100vw - 340px); top: 30px; transform: scale(0.2); opacity: 0; } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';

interface AlchemyJarProps {
  count: number;
  max: number;
  isExploding: boolean;
  onExplode: () => void;
  isDeducting?: boolean;
  height?: number;
}

export const AlchemyJar: React.FC<AlchemyJarProps> = ({ 
  count, 
  max, 
  isExploding, 
  onExplode, 
  isDeducting,
  height = 400
}) => {
  const percent = Math.min(100, (count / max) * 100);
  const isFull = count >= max;
  const [holdProgress, setHoldProgress] = useState(0);
  const holdInterval = useRef<number | null>(null);

  const startHold = () => {
    if (!isFull || isExploding) return;
    holdInterval.current = window.setInterval(() => {
      setHoldProgress(prev => {
        if (prev >= 100) {
          if (holdInterval.current) clearInterval(holdInterval.current);
          onExplode();
          return 0;
        }
        return prev + 1.1; // Approx 3 seconds
      });
    }, 30);
  };

  const endHold = () => {
    if (holdInterval.current) {
      clearInterval(holdInterval.current);
      holdInterval.current = null;
    }
    setHoldProgress(0);
  };

  return (
    <div 
      className="flex flex-col items-center justify-end relative w-16"
      style={{ height: `${height}px` }}
    >
      <div 
        className={`relative w-10 cursor-pointer transition-all duration-500 
          ${isExploding ? 'scale-150 blur-3xl opacity-0' : 'scale-100'} 
          ${isFull && !isExploding ? 'hover:scale-105 active:scale-95 shadow-[0_0_30px_rgba(79,70,229,0.3)]' : ''}`}
        style={{ height: '100%' }}
        onMouseDown={startHold}
        onMouseUp={endHold}
        onMouseLeave={endHold}
        onTouchStart={startHold}
        onTouchEnd={endHold}
      >
        {/* Rim (Open Top) */}
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-12 h-1 bg-white/20 backdrop-blur-md rounded-full border border-white/20 z-20" />

        {/* Test Tube Glass Body */}
        <div className="absolute inset-0 bg-white/5 dark:bg-black/20 border-x border-b border-white/20 dark:border-white/10 backdrop-blur-sm overflow-hidden rounded-b-full z-10 shadow-inner">

          {/* Subtle Glare */}
          <div className="absolute left-1.5 top-4 w-1 h-3/4 bg-white/10 rounded-full blur-[2px] z-20" />

          {/* Alchemy Liquid Content */}
          <div 
            className={`absolute bottom-0 left-0 w-full transition-all duration-700 ease-out ${isDeducting ? 'bg-red-500/60' : 'bg-indigo-600/60'}`}
            style={{ height: `${percent}%` }}
          >
            {/* Top Surface */}
            <div className="absolute top-0 left-0 w-full h-[2px] bg-white/30" />

            {/* Minimalist Bubbles */}
            <div className="absolute inset-0 overflow-hidden">
               {[...Array(3)].map((_, i) => (
                 <div 
                   key={i} 
                   className="absolute bottom-0 bg-white/20 rounded-full animate-bubble"
                   style={{
                     width: 4,
                     height: 4,
                     left: `${Math.random() * 80 + 10}%`,
                     animationDuration: `${Math.random() * 2 + 2}s`,
                     animationDelay: `${i * 0.5}s`
                   }}
                 />
               ))}
            </div>
          </div>

          {/* Progress Percent Text */}
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-30">
            <span className={`text-[9px] font-black opacity-60 transition-colors ${percent > 50 ? 'text-white' : 'text-indigo-400'}`}>
              {Math.floor(percent)}%
            </span>
          </div>
        </div>

        {/* Hold Progress Visualizer */}
        {holdProgress > 0 && (
          <div className="absolute inset-0 flex items-center justify-center z-40 pointer-events-none">
            <svg className="w-16 h-16 -rotate-90">
              <circle
                cx="32"
                cy="32"
                r="28"
                fill="none"
                stroke="white"
                strokeWidth="2"
                strokeDasharray={`${(holdProgress * 175) / 100} 175`}
                strokeLinecap="round"
                className="opacity-60"
              />
            </svg>
          </div>
        )}
      </div>

      <style>{`
        @keyframes bubble {
          0% { transform: translateY(10px) scale(0.5); opacity: 0; }
          50% { opacity: 0.5; }
          100% { transform: translateY(-120px) scale(1); opacity: 0; }
        }
        .animate-bubble { animation: bubble linear infinite; }
      `}</style>
    </div>
  );
};

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

const ZOMBIE_INDICATOR_COUNT = 8; // Reduced
const BOMB_COUNT = 8;           // Reduced
const PUMPKIN_COUNT = 4; 
const DEMON_COUNT = 4; 
const CLOVER_COUNT = 4; 

const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 

const APP_SCALE = 1.25; 
const SIDEBAR_WIDTH = 380;

const ANIMAL_ICONS = ['🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞', '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🐾', '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺', '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤', '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'];
const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const EXPLOSION_EMOJIS = ['🍦','🍧','🍨','🍩','🍪','🎂','🍰','🧁','🥧','🍫','🍬','🍭','🍮','🍇','🍈','🍉','🍊','🍋','🍋‍🟩','🍌','🍍','🥭','🍎','🍏','🍐','🍑','🍒','🍓','🫐','🍅','🫒','🥥'];

interface CompletedTask extends Task {
  completedAt: string;
}

interface SweetData {
  id: string;
  emoji: string;
  steps: number;
  totalSteps: number;
  secondsLeft: number;
  points: number;
  sizeMultiplier: number;
}

interface Particle {
  id: number;
  emoji: string;
  x: number;
  y: number;
  delay: number;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  const [rewardPoints, setRewardPoints] = useState(0);
  const [rollsCount, setRollsCount] = useState(0);
  const [jarUses, setJarUses] = useState(0);
  const [mapCompletions, setMapCompletions] = useState(0);

  const [activeSweets, setActiveSweets] = useState<Record<string, SweetData>>({});
  const [particles, setParticles] = useState<Particle[]>([]);

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  const [tileSize, setTileSize] = useState(48);

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  useEffect(() => {
    const updateSize = () => {
      const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
      const availableH = window.innerHeight / APP_SCALE;
      const bestSize = Math.max(25, Math.min((availableW - 60) / BOARD_W, (availableH - 60) / BOARD_H, 42));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
    const availableH = window.innerHeight / APP_SCALE;
    const boardRealW = (BOARD_W - 1) * tileSize;
    const boardRealH = (BOARD_H - 1) * tileSize;
    const startX = (availableW - boardRealW) / 2;
    const startY = (availableH - boardRealH) / 2;

    for (let i = 0; i < BOARD_W; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });
    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    setZombieIndicators(getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude));
    setBombIndices(getRandomUnique(BOMB_COUNT, startExclude));
    setPumpkinIndices(getRandomUnique(PUMPKIN_COUNT, startExclude));
    setDemonIndices(getRandomUnique(DEMON_COUNT, startExclude));
    setCloverIndices(getRandomUnique(CLOVER_COUNT, startExclude));
  }, [boardSpaces.length, getRandomUnique]);

  useEffect(() => {
    const timer = setInterval(() => {
      setActiveSweets(prev => {
        const next = { ...prev };
        let changed = false;
        Object.keys(next).forEach(id => {
          if (next[id].secondsLeft > 0) {
            next[id].secondsLeft -= 1;
            changed = true;
          }
        });
        return changed ? next : prev;
      });
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const triggerExplosionTrail = useCallback((x: number, y: number, points: number) => {
    const newParticles: Particle[] = Array.from({ length: 10 }).map((_, i) => ({
      id: Math.random(),
      emoji: EXPLOSION_EMOJIS[Math.floor(Math.random() * EXPLOSION_EMOJIS.length)],
      x: x + (Math.random() - 0.5) * 40,
      y: y + (Math.random() - 0.5) * 40,
      delay: i * 80
    }));

    setParticles(prev => [...prev, ...newParticles]);
    setTimeout(() => {
      setRewardPoints(prev => prev + points);
      setParticles(prev => prev.filter(p => !newParticles.find(np => np.id === p.id)));
    }, 2400);
  }, []);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1.2)); // Higher gain to fill faster
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 600);
  };

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      const nextPos = (tempPos + 1) % TOTAL_TILES;
      if (nextPos === 0) setMapCompletions(prev => prev + 1);

      tempPos = nextPos;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      setActiveSweets(prev => {
        const next = { ...prev };
        Object.keys(next).forEach(id => {
          if (next[id].steps > 0) {
            next[id].steps -= 1;
            if (next[id].steps === 0) {
              const centerX = (window.innerWidth - SIDEBAR_WIDTH) / 2;
              const centerY = window.innerHeight / 2 - (tileSize * 2);
              let x = centerX, y = centerY;
              if (id === 'cone') x -= 50; else if (id === 'slice') x += 50; else y += 30;
              triggerExplosionTrail(x, y, next[id].points);
              delete next[id];
            }
          }
        });
        return next;
      });

      if (cloverIndices.includes(tempPos)) setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1));
      if (bombIndices.includes(tempPos)) {
          setBombAnimation({ active: true, pos: tempPos });
          setTimeout(() => setBombAnimation({ active: false, pos: -1 }), 400);
      }

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (zombieIndicators.includes(finalPos)) {
          setActiveZombies(prev => [...prev, { id: Math.random().toString(), pos: (finalPos - 5 + TOTAL_TILES) % TOTAL_TILES, health: MAX_ZOMBIE_HEALTH, isActive: true }]);
        }
        if (pumpkinIndices.includes(finalPos)) setPumpkinBoss({ isActive: true, health: MAX_PUMPKIN_HEALTH });
        if (demonIndices.includes(finalPos)) setDemonBoss({ isActive: true, health: MAX_DEMON_HEALTH });

        setActiveZombies(prev => {
          let damaged = false;
          const moved = prev.map(z => {
            const nz = (z.pos + 2) % TOTAL_TILES;
            if (nz === finalPos) damaged = true;
            return { ...z, pos: nz };
          });
          if (damaged) setPlayerHealth(h => Math.max(0, h - 1));
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, cloverIndices, bombIndices, zombieIndicators, pumpkinIndices, demonIndices, tileSize, triggerExplosionTrail]);

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);

    setRollsCount(prev => {
      if (Object.keys(activeSweets).length > 0) return prev;
      const next = prev + 1;
      if (next % 5 === 0) {
        setActiveSweets({
          cone: { id: 'cone', emoji: '🍦', steps: 12, totalSteps: 12, secondsLeft: 2 * 3600, points: 10, sizeMultiplier: 0.8 },
          slice: { id: 'slice', emoji: '🍰', steps: 18, totalSteps: 18, secondsLeft: 4 * 3600, points: 20, sizeMultiplier: 1.0 },
          cake: { id: 'cake', emoji: '🎂', steps: 28, totalSteps: 28, secondsLeft: 8 * 3600, points: 30, sizeMultiplier: 1.5 },
        });
        return 0; 
      }
      return next;
    });

    const val = Math.floor(Math.random() * 6) + 1;
    setTimeout(() => { setIsRolling(false); setDiceValues([val]); setIsMoving(true); processMovement(val); }, 1100);
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setJarUses(prev => prev + 1);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => { setIsExploding(false); setJarCount(0); setRollBank(r => r + 40); }, 1200);
  };

  const formatTime = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    return `${h}h${m}m`;
  };

  return (
    <div className={`h-screen w-screen flex bg-white dark:bg-zinc-950 transition-colors duration-500 overflow-hidden`}>
      {particles.map(p => (
        <div key={p.id} className="fixed z-[100] text-2xl pointer-events-none" style={{ left: p.x, top: p.y, animation: `trail-move 2s ease-in-out ${p.delay}ms forwards` }}>{p.emoji}</div>
      ))}

      <div ref={gameAreaRef} className="flex-1 relative overflow-hidden notion-grid">
        <div className="relative w-full h-full flex items-center justify-center" style={{ transform: `scale(${APP_SCALE})` }}>
          <div className="relative w-full h-full">
            <div className="absolute inset-0 z-0 opacity-80">
                {boardSpaces.map(s => (
                  <div key={s.id} className="absolute sudoku-tile flex items-center justify-center" style={{ left: s.x, top: s.y, width: tileSize, height: tileSize }}>
                    {blooms[s.id] && <span className="bloom absolute text-sm opacity-50">{blooms[s.id]}</span>}
                  </div>
                ))}

                {activeZombies.map(z => boardSpaces[z.pos] && (
                  <div key={z.id} className="absolute z-20 transition-all duration-500" style={{ left: boardSpaces[z.pos].x + tileSize/2, top: boardSpaces[z.pos].y + tileSize/2, transform: 'translate(-50%, -50%)' }}>
                    <span className="text-xl">🧛🏻</span>
                  </div>
                ))}

                <div className="absolute z-30 transition-all duration-300" style={{ left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, transform: 'translate(-50%, -60%)' }}>
                    <div className="flex flex-col items-center">
                        <div className="flex gap-0.5 mb-0.5 bg-white/80 p-0.5 rounded-full border border-black/5">
                            {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => <div key={i} className={`w-1 h-0.5 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />)}
                        </div>
                        <span className="text-2xl">{ANIMAL_ICONS[animalIndex]}</span>
                    </div>
                </div>
            </div>

            <div className="absolute inset-0 flex items-center justify-center">
                <div className="grid grid-cols-3 w-full max-w-4xl items-center justify-items-center">
                    <div className="flex flex-col items-center gap-4 transition-all" style={{ opacity: Object.keys(activeSweets).length > 0 ? 1 : 0, transform: `translateY(-${tileSize}px)` }}>
                        {activeSweets.cone && <div className="flex flex-col items-center"><span className="text-[7px] font-black opacity-30">{activeSweets.cone.steps}s | {formatTime(activeSweets.cone.secondsLeft)}</span><span style={{ fontSize: tileSize * activeSweets.cone.sizeMultiplier }}>🍦</span></div>}
                        {activeSweets.slice && <div className="flex flex-col items-center"><span className="text-[7px] font-black opacity-30">{activeSweets.slice.steps}s | {formatTime(activeSweets.slice.secondsLeft)}</span><span style={{ fontSize: tileSize * activeSweets.slice.sizeMultiplier }}>🍰</span></div>}
                        {activeSweets.cake && <div className="flex flex-col items-center"><span className="text-[7px] font-black opacity-30">{activeSweets.cake.steps}s | {formatTime(activeSweets.cake.secondsLeft)}</span><span style={{ fontSize: tileSize * activeSweets.cake.sizeMultiplier }}>🎂</span></div>}
                    </div>

                    <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} height={tileSize * 10} />

                    <div className="flex flex-col gap-8">
                        {pumpkinBoss.isActive && <span className="text-3xl">🎃</span>}
                        {demonBoss.isActive && <span className="text-3xl">👹</span>}
                    </div>
                </div>
            </div>
          </div>
        </div>

        <Dice3D value={diceValues[0]} isRolling={isRolling} currentPos={dicePositions[0]} onRoll={handleRoll} onDragEnd={(p) => setDicePositions([p])} />
      </div>

      <div className="w-[380px] h-full bg-[#fbfbfa] dark:bg-[#191919] border-l border-[#efefef] dark:border-white/5 flex flex-col z-50 shadow-xl">
        <div className="p-4 flex flex-col h-full">
          <div className="flex flex-col gap-3 py-2 border-b border-[#eee] dark:border-white/5 mb-4">
             <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                   <div className="flex items-center gap-1.5"><span className="text-lg">🎁</span><span className="text-sm font-black opacity-80">{rewardPoints}</span></div>
                   <div className="flex items-center gap-1.5"><span className="text-lg">⚗️</span><span className="text-sm font-black opacity-80">{jarUses}</span></div>
                   <div className="flex items-center gap-1.5"><span className="text-lg">🏅</span><span className="text-sm font-black opacity-80">{mapCompletions}</span></div>
                </div>
                <button onClick={() => setDarkMode(!darkMode)} className="p-1.5 rounded hover:bg-black/5 dark:hover:bg-white/5 text-xs transition-colors">{darkMode ? '☀️' : '🌙'}</button>
             </div>
             <div className="flex items-center gap-4 text-[9px] font-black opacity-25 uppercase tracking-widest">
               <div className="flex items-center gap-1"><span>⚡</span><span>Energy: {rollBank}</span></div>
               <div className="flex items-center gap-1"><span>🎲</span><span>Rolls: {rollsCount}</span></div>
             </div>
          </div>

          <div className="flex-1 overflow-y-auto">
             <div className="mb-4 text-xs font-bold opacity-60">Missions</div>
             <div className="flex flex-col gap-2">
                {tasks.map(t => (
                  <div key={t.id} className="p-3 bg-black/[0.03] dark:bg-white/[0.03] rounded-lg opacity-80 hover:opacity-100 cursor-pointer transition-opacity" onClick={() => {
                    setRollBank(r => r + 15);
                    setHistory(prev => [{ ...t, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
                    setTasks(prev => prev.filter(x => x.id !== t.id));
                  }}>
                    <p className="text-xs">{t.text}</p>
                    <div className="mt-1 text-[8px] font-black uppercase opacity-30">{t.priority}</div>
                  </div>
                ))}
             </div>
          </div>
        </div>
      </div>

      <style>{`
        .notion-grid { background-image: radial-gradient(#efefef 1px, transparent 1px); background-size: 20px 20px; }
        .dark .notion-grid { background-image: radial-gradient(rgba(255,255,255,0.03) 1px, transparent 1px); }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.03); background: rgba(255,255,255,0.85); }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.01); background: rgba(20,20,20,0.7); }
        @keyframes trail-move { 0% { transform: translate(0, 0) scale(1); opacity: 1; } 100% { left: calc(100vw - 300px); top: 30px; transform: scale(0.2); opacity: 0; } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';

interface AlchemyJarProps {
  count: number;
  max: number;
  isExploding: boolean;
  onExplode: () => void;
  height?: number;
}

export const AlchemyJar: React.FC<AlchemyJarProps> = ({ 
  count, 
  max, 
  isExploding, 
  onExplode, 
  height = 400
}) => {
  const percent = Math.min(100, (count / max) * 100);
  const isFull = count >= max;
  const [holdProgress, setHoldProgress] = useState(0);
  const holdInterval = useRef<number | null>(null);

  const startHold = () => {
    if (!isFull || isExploding) return;
    holdInterval.current = window.setInterval(() => {
      setHoldProgress(prev => {
        if (prev >= 100) {
          if (holdInterval.current) clearInterval(holdInterval.current);
          onExplode();
          return 0;
        }
        return prev + 1.1; // Roughly 3 seconds (30ms * 100 / 1.1)
      });
    }, 30);
  };

  const endHold = () => {
    if (holdInterval.current) {
      clearInterval(holdInterval.current);
      holdInterval.current = null;
    }
    setHoldProgress(0);
  };

  return (
    <div 
      className="flex flex-col items-center justify-end relative w-16"
      style={{ height: `${height}px` }}
    >
      <div 
        className={`relative w-10 cursor-pointer transition-all duration-500 
          ${isExploding ? 'scale-150 blur-3xl opacity-0' : 'scale-100'} 
          ${isFull && !isExploding ? 'hover:scale-105 active:scale-95 shadow-[0_0_20px_rgba(79,70,229,0.2)]' : ''}`}
        style={{ height: '100%' }}
        onMouseDown={startHold}
        onMouseUp={endHold}
        onMouseLeave={endHold}
        onTouchStart={startHold}
        onTouchEnd={endHold}
      >
        {/* Open Top Rim */}
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-12 h-1 bg-white/30 backdrop-blur rounded-full border border-white/20 z-20" />

        {/* Tall Vial Body */}
        <div className="absolute inset-0 bg-white/5 dark:bg-black/20 border-x border-b border-white/20 dark:border-white/10 backdrop-blur-sm overflow-hidden rounded-b-full z-10">

          {/* Subtle Glare Reflection */}
          <div className="absolute left-1.5 top-5 w-1 h-3/4 bg-white/10 rounded-full blur-[2px] z-20" />

          {/* Liquid Content */}
          <div 
            className={`absolute bottom-0 left-0 w-full transition-all duration-700 ease-out bg-indigo-600/50`}
            style={{ height: `${percent}%` }}
          >
            {/* Top Surface Glow */}
            <div className="absolute top-0 left-0 w-full h-[2px] bg-white/40" />

            {/* Minimalist Bubbles */}
            <div className="absolute inset-0 overflow-hidden">
               {[...Array(3)].map((_, i) => (
                 <div 
                   key={i} 
                   className="absolute bottom-0 bg-white/20 rounded-full animate-bubble"
                   style={{
                     width: 4,
                     height: 4,
                     left: `${Math.random() * 70 + 15}%`,
                     animationDuration: `${Math.random() * 2 + 2}s`,
                     animationDelay: `${i * 0.7}s`
                   }}
                 />
               ))}
            </div>
          </div>

          {/* Internal Percent Text */}
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-30">
            <span className={`text-[8px] font-black opacity-40 transition-colors ${percent > 50 ? 'text-white' : 'text-indigo-400'}`}>
              {Math.floor(percent)}%
            </span>
          </div>
        </div>

        {/* Circular Hold Progress Ring */}
        {holdProgress > 0 && (
          <div className="absolute inset-0 flex items-center justify-center z-40 pointer-events-none">
            <svg className="w-16 h-16 -rotate-90">
              <circle
                cx="32"
                cy="32"
                r="28"
                fill="none"
                stroke="white"
                strokeWidth="2"
                strokeDasharray={`${(holdProgress * 175) / 100} 175`}
                strokeLinecap="round"
                className="opacity-50"
              />
            </svg>
          </div>
        )}
      </div>

      <style>{`
        @keyframes bubble {
          0% { transform: translateY(10px) scale(0.5); opacity: 0; }
          40% { opacity: 0.5; }
          100% { transform: translateY(-130px) scale(1); opacity: 0; }
        }
        .animate-bubble { animation: bubble linear infinite; }
      `}</style>
    </div>
  );
};

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

const ZOMBIE_INDICATOR_COUNT = 8; // Reduced
const BOMB_COUNT = 8;           // Reduced
const PUMPKIN_COUNT = 4; 
const DEMON_COUNT = 4; 
const CLOVER_COUNT = 4; 

const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 

const APP_SCALE = 1.25; 
const SIDEBAR_WIDTH = 380;

const ANIMAL_ICONS = ['🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞', '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🐾', '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺', '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤', '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'];
const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const EXPLOSION_EMOJIS = ['🍦','🍧','🍨','🍩','🍪','🎂','🍰','🧁','🥧','🍫','🍬','🍭','🍮','🍇','🍈','🍉','🍊','🍋','🍋‍🟩','🍌','🍍','🥭','🍎','🍏','🍐','🍑','🍒','🍓','🫐','🍅','🫒','🥥'];

interface CompletedTask extends Task {
  completedAt: string;
}

interface SweetData {
  id: string;
  emoji: string;
  steps: number;
  totalSteps: number;
  secondsLeft: number;
  points: number;
  sizeMultiplier: number;
}

interface Particle {
  id: number;
  emoji: string;
  x: number;
  y: number;
  delay: number;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  const [rewardPoints, setRewardPoints] = useState(0);
  const [rollsCount, setRollsCount] = useState(0);
  const [jarUses, setJarUses] = useState(0);
  const [mapCompletions, setMapCompletions] = useState(0);

  const [activeSweets, setActiveSweets] = useState<Record<string, SweetData>>({});
  const [particles, setParticles] = useState<Particle[]>([]);

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  const [tileSize, setTileSize] = useState(48);

  // Fix: Added missing state and ref to resolve compilation errors
  const gameAreaRef = useRef<HTMLDivElement>(null);
  const [dicePositions, setDicePositions] = useState<{ x: number, y: number }[]>([{ x: 200, y: 300 }]);

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  useEffect(() => {
    const updateSize = () => {
      const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
      const availableH = window.innerHeight / APP_SCALE;
      const bestSize = Math.max(25, Math.min((availableW - 60) / BOARD_W, (availableH - 60) / BOARD_H, 42));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
    const availableH = window.innerHeight / APP_SCALE;
    const boardRealW = (BOARD_W - 1) * tileSize;
    const boardRealH = (BOARD_H - 1) * tileSize;
    const startX = (availableW - boardRealW) / 2;
    const startY = (availableH - boardRealH) / 2;

    for (let i = 0; i < BOARD_W; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });
    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    setZombieIndicators(getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude));
    setBombIndices(getRandomUnique(BOMB_COUNT, startExclude));
    setPumpkinIndices(getRandomUnique(PUMPKIN_COUNT, startExclude));
    setDemonIndices(getRandomUnique(DEMON_COUNT, startExclude));
    setCloverIndices(getRandomUnique(CLOVER_COUNT, startExclude));
  }, [boardSpaces.length, getRandomUnique]);

  useEffect(() => {
    const timer = setInterval(() => {
      setActiveSweets(prev => {
        const next = { ...prev };
        let changed = false;
        Object.keys(next).forEach(id => {
          if (next[id].secondsLeft > 0) {
            next[id].secondsLeft -= 1;
            changed = true;
          }
        });
        return changed ? next : prev;
      });
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const triggerExplosionTrail = useCallback((x: number, y: number, points: number) => {
    const newParticles: Particle[] = Array.from({ length: 10 }).map((_, i) => ({
      id: Math.random(),
      emoji: EXPLOSION_EMOJIS[Math.floor(Math.random() * EXPLOSION_EMOJIS.length)],
      x: x + (Math.random() - 0.5) * 40,
      y: y + (Math.random() - 0.5) * 40,
      delay: i * 80
    }));

    setParticles(prev => [...prev, ...newParticles]);
    setTimeout(() => {
      setRewardPoints(prev => prev + points);
      setParticles(prev => prev.filter(p => !newParticles.find(np => np.id === p.id)));
    }, 2400);
  }, []);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1.2)); // Higher gain to fill faster
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 600);
  };

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      const nextPos = (tempPos + 1) % TOTAL_TILES;
      if (nextPos === 0) setMapCompletions(prev => prev + 1);

      tempPos = nextPos;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      setActiveSweets(prev => {
        const next = { ...prev };
        Object.keys(next).forEach(id => {
          if (next[id].steps > 0) {
            next[id].steps -= 1;
            if (next[id].steps === 0) {
              const centerX = (window.innerWidth - SIDEBAR_WIDTH) / 2;
              const centerY = window.innerHeight / 2 - (tileSize * 2);
              let x = centerX, y = centerY;
              if (id === 'cone') x -= 50; else if (id === 'slice') x += 50; else y += 30;
              triggerExplosionTrail(x, y, next[id].points);
              delete next[id];
            }
          }
        });
        return next;
      });

      if (cloverIndices.includes(tempPos)) setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1));
      if (bombIndices.includes(tempPos)) {
          setBombAnimation({ active: true, pos: tempPos });
          setTimeout(() => setBombAnimation({ active: false, pos: -1 }), 400);
      }

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (zombieIndicators.includes(finalPos)) {
          setActiveZombies(prev => [...prev, { id: Math.random().toString(), pos: (finalPos - 5 + TOTAL_TILES) % TOTAL_TILES, health: MAX_ZOMBIE_HEALTH, isActive: true }]);
        }
        if (pumpkinIndices.includes(finalPos)) setPumpkinBoss({ isActive: true, health: MAX_PUMPKIN_HEALTH });
        if (demonIndices.includes(finalPos)) setDemonBoss({ isActive: true, health: MAX_DEMON_HEALTH });

        setActiveZombies(prev => {
          let damaged = false;
          const moved = prev.map(z => {
            const nz = (z.pos + 2) % TOTAL_TILES;
            if (nz === finalPos) damaged = true;
            return { ...z, pos: nz };
          });
          if (damaged) setPlayerHealth(h => Math.max(0, h - 1));
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, cloverIndices, bombIndices, zombieIndicators, pumpkinIndices, demonIndices, tileSize, triggerExplosionTrail]);

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);

    setRollsCount(prev => {
      if (Object.keys(activeSweets).length > 0) return prev;
      const next = prev + 1;
      if (next % 5 === 0) {
        setActiveSweets({
          cone: { id: 'cone', emoji: '🍦', steps: 12, totalSteps: 12, secondsLeft: 2 * 3600, points: 10, sizeMultiplier: 0.8 },
          slice: { id: 'slice', emoji: '🍰', steps: 18, totalSteps: 18, secondsLeft: 4 * 3600, points: 20, sizeMultiplier: 1.0 },
          cake: { id: 'cake', emoji: '🎂', steps: 28, totalSteps: 28, secondsLeft: 8 * 3600, points: 30, sizeMultiplier: 1.5 },
        });
        return 0; 
      }
      return next;
    });

    const val = Math.floor(Math.random() * 6) + 1;
    setTimeout(() => { setIsRolling(false); setDiceValues([val]); setIsMoving(true); processMovement(val); }, 1100);
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setJarUses(prev => prev + 1);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => { setIsExploding(false); setJarCount(0); setRollBank(r => r + 40); }, 1200);
  };

  const formatTime = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    return `${h}h${m}m`;
  };

  return (
    <div className={`h-screen w-screen flex bg-white dark:bg-zinc-950 transition-colors duration-500 overflow-hidden`}>
      {particles.map(p => (
        <div key={p.id} className="fixed z-[100] text-2xl pointer-events-none" style={{ left: p.x, top: p.y, animation: `trail-move 2s ease-in-out ${p.delay}ms forwards` }}>{p.emoji}</div>
      ))}

      <div ref={gameAreaRef} className="flex-1 relative overflow-hidden notion-grid">
        <div className="relative w-full h-full flex items-center justify-center" style={{ transform: `scale(${APP_SCALE})` }}>
          <div className="relative w-full h-full">
            <div className="absolute inset-0 z-0 opacity-80">
                {boardSpaces.map(s => (
                  <div key={s.id} className="absolute sudoku-tile flex items-center justify-center" style={{ left: s.x, top: s.y, width: tileSize, height: tileSize }}>
                    {blooms[s.id] && <span className="bloom absolute text-sm opacity-50">{blooms[s.id]}</span>}
                  </div>
                ))}

                {activeZombies.map(z => boardSpaces[z.pos] && (
                  <div key={z.id} className="absolute z-20 transition-all duration-500" style={{ left: boardSpaces[z.pos].x + tileSize/2, top: boardSpaces[z.pos].y + tileSize/2, transform: 'translate(-50%, -50%)' }}>
                    <span className="text-xl">🧛🏻</span>
                  </div>
                ))}

                <div className="absolute z-30 transition-all duration-300" style={{ left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, transform: 'translate(-50%, -60%)' }}>
                    <div className="flex flex-col items-center">
                        <div className="flex gap-0.5 mb-0.5 bg-white/80 p-0.5 rounded-full border border-black/5">
                            {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => <div key={i} className={`w-1 h-0.5 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />)}
                        </div>
                        <span className="text-2xl">{ANIMAL_ICONS[animalIndex]}</span>
                    </div>
                </div>
            </div>

            <div className="absolute inset-0 flex items-center justify-center">
                <div className="grid grid-cols-3 w-full max-w-4xl items-center justify-items-center">
                    <div className="flex flex-col items-center gap-4 transition-all" style={{ opacity: Object.keys(activeSweets).length > 0 ? 1 : 0, transform: `translateY(-${tileSize}px)` }}>
                        {activeSweets.cone && <div className="flex flex-col items-center"><span className="text-[7px] font-black opacity-30">{activeSweets.cone.steps}s | {formatTime(activeSweets.cone.secondsLeft)}</span><span style={{ fontSize: tileSize * activeSweets.cone.sizeMultiplier }}>🍦</span></div>}
                        {activeSweets.slice && <div className="flex flex-col items-center"><span className="text-[7px] font-black opacity-30">{activeSweets.slice.steps}s | {formatTime(activeSweets.slice.secondsLeft)}</span><span style={{ fontSize: tileSize * activeSweets.slice.sizeMultiplier }}>🍰</span></div>}
                        {activeSweets.cake && <div className="flex flex-col items-center"><span className="text-[7px] font-black opacity-30">{activeSweets.cake.steps}s | {formatTime(activeSweets.cake.secondsLeft)}</span><span style={{ fontSize: tileSize * activeSweets.cake.sizeMultiplier }}>🎂</span></div>}
                    </div>

                    <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} height={tileSize * 10} />

                    <div className="flex flex-col gap-8">
                        {pumpkinBoss.isActive && <span className="text-3xl">🎃</span>}
                        {demonBoss.isActive && <span className="text-3xl">👹</span>}
                    </div>
                </div>
            </div>
          </div>
        </div>

        <Dice3D value={diceValues[0]} isRolling={isRolling} currentPos={dicePositions[0]} onRoll={handleRoll} onDragEnd={(p) => setDicePositions([p])} />
      </div>

      <div className="w-[380px] h-full bg-[#fbfbfa] dark:bg-[#191919] border-l border-[#efefef] dark:border-white/5 flex flex-col z-50 shadow-xl">
        <div className="p-4 flex flex-col h-full">
          <div className="flex flex-col gap-3 py-2 border-b border-[#eee] dark:border-white/5 mb-4">
             <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                   <div className="flex items-center gap-1.5"><span className="text-lg">🎁</span><span className="text-sm font-black opacity-80">{rewardPoints}</span></div>
                   <div className="flex items-center gap-1.5"><span className="text-lg">⚗️</span><span className="text-sm font-black opacity-80">{jarUses}</span></div>
                   <div className="flex items-center gap-1.5"><span className="text-lg">🏅</span><span className="text-sm font-black opacity-80">{mapCompletions}</span></div>
                </div>
                <button onClick={() => setDarkMode(!darkMode)} className="p-1.5 rounded hover:bg-black/5 dark:hover:bg-white/5 text-xs transition-colors">{darkMode ? '☀️' : '🌙'}</button>
             </div>
             <div className="flex items-center gap-4 text-[9px] font-black opacity-25 uppercase tracking-widest">
               <div className="flex items-center gap-1"><span>⚡</span><span>Energy: {rollBank}</span></div>
               <div className="flex items-center gap-1"><span>🎲</span><span>Rolls: {rollsCount}</span></div>
             </div>
          </div>

          <div className="flex-1 overflow-y-auto">
             <div className="mb-4 text-xs font-bold opacity-60">Missions</div>
             <div className="flex flex-col gap-2">
                {tasks.map(t => (
                  <div key={t.id} className="p-3 bg-black/[0.03] dark:bg-white/[0.03] rounded-lg opacity-80 hover:opacity-100 cursor-pointer transition-opacity" onClick={() => {
                    setRollBank(r => r + 15);
                    setHistory(prev => [{ ...t, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
                    setTasks(prev => prev.filter(x => x.id !== t.id));
                  }}>
                    <p className="text-xs">{t.text}</p>
                    <div className="mt-1 text-[8px] font-black uppercase opacity-30">{t.priority}</div>
                  </div>
                ))}
             </div>
          </div>
        </div>
      </div>

      <style>{`
        .notion-grid { background-image: radial-gradient(#efefef 1px, transparent 1px); background-size: 20px 20px; }
        .dark .notion-grid { background-image: radial-gradient(rgba(255,255,255,0.03) 1px, transparent 1px); }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.03); background: rgba(255,255,255,0.85); }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.01); background: rgba(20,20,20,0.7); }
        @keyframes trail-move { 0% { transform: translate(0, 0) scale(1); opacity: 1; } 100% { left: calc(100vw - 300px); top: 30px; transform: scale(0.2); opacity: 0; } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

const ZOMBIE_INDICATOR_COUNT = 8; // Slightly reduced for performance
const BOMB_COUNT = 8;           // Slightly reduced for performance
const PUMPKIN_COUNT = 5; 
const DEMON_COUNT = 5; 
const CLOVER_COUNT = 5; 

const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 
const SPAWN_BEHIND_OFFSET = 5;

const APP_SCALE = 1.25; 
const SIDEBAR_WIDTH = 380;

const ANIMAL_ICONS = [
  'Rex','🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', 
  '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🐾',
  '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦅', '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤',
  '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const EXPLOSION_EMOJIS = ['🍦','🍧','🍨','🍩','🍪','🎂','🍰','🧁','🥧','🍫','🍬','🍭','🍮','🍇','🍈','🍉','🍊','🍋','🍋‍🟩','🍌','🍍','🥭','🍎','🍏','🍐','🍑','🍒','🍓','🫐','🍅','🫒','🥥'];

interface CompletedTask extends Task {
  completedAt: string;
}

interface SweetData {
  id: string;
  emoji: string;
  steps: number;
  totalSteps: number;
  secondsLeft: number;
  points: number;
  sizeMultiplier: number;
}

interface Particle {
  id: number;
  emoji: string;
  x: number;
  y: number;
  delay: number;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  const [rewardPoints, setRewardPoints] = useState(0);
  const [rollsCount, setRollsCount] = useState(0);
  const [jarUses, setJarUses] = useState(0);
  const [mapCompletions, setMapCompletions] = useState(0);

  const [activeSweets, setActiveSweets] = useState<Record<string, SweetData>>({});
  const [particles, setParticles] = useState<Particle[]>([]);

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
    { id: '3', text: 'Lắc được xúc xắc 6', completed: false, priority: 'low' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);

  const gameAreaRef = useRef<HTMLDivElement>(null);
  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2, y: window.innerHeight / 2 }
  ]);

  const [isShaking, setIsShaking] = useState(false);
  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(48);

  useEffect(() => {
    const updateSize = () => {
      const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
      const availableH = window.innerHeight / APP_SCALE;
      const HorizontalLimit = (availableW - 60) / BOARD_W;
      const VerticalLimit = (availableH - 60) / BOARD_H;
      const bestSize = Math.max(25, Math.min(HorizontalLimit, VerticalLimit, 45));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
    const availableH = window.innerHeight / APP_SCALE;
    const boardRealW = (BOARD_W - 1) * tileSize;
    const boardRealH = (BOARD_H - 1) * tileSize;
    const startX = (availableW - boardRealW) / 2;
    const startY = (availableH - boardRealH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    setZombieIndicators(getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude));
    setBombIndices(getRandomUnique(BOMB_COUNT, [...startExclude]));
    setPumpkinIndices(getRandomUnique(PUMPKIN_COUNT, [...startExclude]));
    setDemonIndices(getRandomUnique(DEMON_COUNT, [...startExclude]));
    setCloverIndices(getRandomUnique(CLOVER_COUNT, [...startExclude]));
  }, [boardSpaces.length, getRandomUnique]);

  useEffect(() => {
    const timer = setInterval(() => {
      setActiveSweets(prev => {
        const next = { ...prev };
        let changed = false;
        Object.keys(next).forEach(id => {
          if (next[id].secondsLeft > 0) {
            next[id].secondsLeft -= 1;
            changed = true;
          }
        });
        return changed ? next : prev;
      });
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const triggerExplosionTrail = useCallback((x: number, y: number, points: number) => {
    // Reduced particle count by 80% (approx 10-12 particles instead of 18)
    const newParticles: Particle[] = Array.from({ length: 11 }).map((_, i) => ({
      id: Math.random(),
      emoji: EXPLOSION_EMOJIS[Math.floor(Math.random() * EXPLOSION_EMOJIS.length)],
      x: x + (Math.random() - 0.5) * 60,
      y: y + (Math.random() - 0.5) * 60,
      delay: i * 80
    }));

    setParticles(prev => [...prev, ...newParticles]);
    setTimeout(() => {
      setRewardPoints(prev => prev + points);
      setParticles(prev => prev.filter(p => !newParticles.find(np => np.id === p.id)));
    }, 2500);
  }, []);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1.2)); // Slightly faster gain for gameplay flow
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 800);
  };

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    const interval = setInterval(() => {
      const nextPos = (tempPos + 1) % TOTAL_TILES;

      // Map Completion Tracking
      if (nextPos === 0) {
        setMapCompletions(prev => prev + 1);
      }

      tempPos = nextPos;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      // Update Sweet Steps
      setActiveSweets(prev => {
        const next = { ...prev };
        Object.keys(next).forEach(id => {
          if (next[id].steps > 0) {
            next[id].steps -= 1;
            if (next[id].steps === 0) {
              const availableW = window.innerWidth;
              const centerX = (availableW - SIDEBAR_WIDTH) / 2;
              const centerY = window.innerHeight / 2 - (tileSize * 1.5);
              let x = centerX, y = centerY;
              if (id === 'cone') { x -= 60; y -= 60; }
              else if (id === 'slice') { x += 60; y -= 60; }
              else if (id === 'cake') { y += 40; }

              triggerExplosionTrail(x, y, next[id].points);
              delete next[id];
            }
          }
        });
        return next;
      });

      if (cloverIndices.includes(tempPos)) setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1));
      if (bombIndices.includes(tempPos)) {
        setBombAnimation({ active: true, pos: tempPos });
        setTimeout(() => setBombAnimation({ active: false, pos: -1 }), 500);
      }

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (zombieIndicators.includes(finalPos)) {
          setActiveZombies(prev => [...prev, {
            id: Math.random().toString(),
            pos: (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          }]);
        }
        if (pumpkinIndices.includes(finalPos)) setPumpkinBoss({ isActive: true, health: MAX_PUMPKIN_HEALTH });
        if (demonIndices.includes(finalPos)) setDemonBoss({ isActive: true, health: MAX_DEMON_HEALTH });

        setActiveZombies(prev => {
          let damaged = false;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + 2) % TOTAL_TILES;
            if (nextZPos === finalPos) damaged = true;
            return { ...z, pos: nextZPos };
          });
          if (damaged) setPlayerHealth(h => Math.max(0, h - 1));
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, cloverIndices, zombieIndicators, pumpkinIndices, demonIndices, triggerExplosionTrail, tileSize]);

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;

    if (pumpkinBoss.isActive) {
      setIsDeducting(true);
      setJarCount(prev => Math.max(0, prev - 5));
      setTimeout(() => setIsDeducting(false), 800);
    }

    setIsRolling(true);
    setRollBank(r => r - 1);

    // Roll counter logic: pause when sweets are active
    setRollsCount(prev => {
      if (Object.keys(activeSweets).length > 0) return prev;
      const next = prev + 1;
      if (next % 5 === 0) {
        setActiveSweets({
          cone: { id: 'cone', emoji: '🍦', steps: 12, totalSteps: 12, secondsLeft: 2 * 3600, points: 10, sizeMultiplier: 1.28 },
          slice: { id: 'slice', emoji: '🍰', steps: 18, totalSteps: 18, secondsLeft: 4 * 3600, points: 20, sizeMultiplier: 1.536 },
          cake: { id: 'cake', emoji: '🎂', steps: 28, totalSteps: 28, secondsLeft: 8 * 3600, points: 30, sizeMultiplier: 2.24 },
        });
        return 0; 
      }
      return next;
    });

    const newValues = [Math.floor(Math.random() * 6) + 1];
    setDicePositions([{ x: landing.x, y: landing.y }]);

    setTimeout(() => {
      setIsRolling(false);
      setDiceValues(newValues);
      setIsMoving(true);
      processMovement(newValues[0]);
    }, 1200);
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setJarUses(prev => prev + 1);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1500);
  };

  const getPriorityColor = (p?: string) => {
    switch(p) {
        case 'high': return 'bg-red-50 text-red-600 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30';
        case 'medium': return 'bg-orange-50 text-orange-600 border-orange-100 dark:bg-orange-900/10 dark:text-orange-400 dark:border-orange-900/30';
        default: return 'bg-blue-50 text-blue-600 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30';
    }
  }

  const formatTime = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    return `${h}h${m}m`;
  };

  return (
    <div className={`h-screen w-screen flex transition-all duration-700 bg-white dark:bg-zinc-950 ${isExploding ? 'bg-indigo-600/10' : ''}`}>
      {particles.map(p => (
        <div key={p.id} className="fixed z-[100] text-2xl pointer-events-none" style={{ left: p.x, top: p.y, animation: `trail-move 2s ease-in-out ${p.delay}ms forwards` }}>
          {p.emoji}
        </div>
      ))}

      <div ref={gameAreaRef} className="flex-1 relative overflow-hidden notion-grid">
        <div className="relative w-full h-full origin-top-left flex items-center justify-center" style={{ transform: `scale(${APP_SCALE})` }}>
          <div className="relative w-full h-full">
            <div className="absolute inset-0 z-0 pointer-events-none">
                {boardSpaces.map(s => (
                  <div key={s.id} className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500`} style={{ left: s.x, top: s.y, width: tileSize, height: tileSize }}>
                    {blooms[s.id] && <span className="bloom absolute opacity-25" style={{ fontSize: tileSize * 0.5 }}>{blooms[s.id]}</span>}
                  </div>
                ))}

                {activeZombies.map(z => boardSpaces[z.pos] && (
                <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ left: boardSpaces[z.pos].x + tileSize/2, top: boardSpaces[z.pos].y + tileSize/2, transform: 'translate(-50%, -60%)' }}>
                    <span className="text-xl">🧛🏻</span>
                </div>
                ))}

                <div 
                  onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_ICONS.length)}
                  className={`absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto`}
                  style={{ left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, transform: 'translate(-50%, -60%)', fontSize: tileSize * 1.3 }}
                >
                  <div className="flex flex-col items-center">
                      <div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-1.5 border border-black/5 shadow-sm">
                          {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => (
                          <div key={i} className={`w-1.5 h-0.5 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />
                          ))}
                      </div>
                      <span className="drop-shadow-2xl select-none filter contrast-125 brightness-110">
                        {ANIMAL_ICONS[animalIndex]}
                      </span>
                  </div>
                </div>
            </div>

            <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
                <div className="relative w-full h-full flex items-center justify-center">
                    <div className="grid grid-cols-3 w-full max-w-4xl items-center justify-items-center">
                        <div className="flex flex-col items-center justify-center transition-all duration-1000 w-full" style={{ opacity: Object.keys(activeSweets).length > 0 ? 1 : 0, transform: `translateY(-${tileSize * 1.5}px)` }}>
                           <div className="flex flex-col gap-8">
                                {activeSweets.cone && <div className="flex flex-col items-center gap-1"><span className="text-[7px] font-black opacity-40">{activeSweets.cone.steps}s | {formatTime(activeSweets.cone.secondsLeft)}</span><span style={{ fontSize: tileSize * activeSweets.cone.sizeMultiplier }}>🍦</span></div>}
                                {activeSweets.slice && <div className="flex flex-col items-center gap-1"><span className="text-[7px] font-black opacity-40">{activeSweets.slice.steps}s | {formatTime(activeSweets.slice.secondsLeft)}</span><span style={{ fontSize: tileSize * activeSweets.slice.sizeMultiplier }}>🍰</span></div>}
                                {activeSweets.cake && <div className="flex flex-col items-center gap-1"><span className="text-[7px] font-black opacity-40">{activeSweets.cake.steps}s | {formatTime(activeSweets.cake.secondsLeft)}</span><span style={{ fontSize: tileSize * activeSweets.cake.sizeMultiplier }}>🎂</span></div>}
                           </div>
                        </div>

                        <div className="flex justify-center w-full">
                           <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} height={tileSize * 9} />
                        </div>

                        <div className="flex flex-col items-center gap-10 w-full">
                           {pumpkinBoss.isActive && <span className="text-3xl">🎃</span>}
                           {demonBoss.isActive && <span className="text-3xl">👹</span>}
                        </div>
                    </div>
                </div>
            </div>
          </div>
        </div>

        <Dice3D 
          value={diceValues[0] || 1} 
          isRolling={isRolling} 
          currentPos={dicePositions[0]} 
          onRoll={handleRoll} 
          onDragEnd={(finalPos) => setDicePositions([finalPos])} 
        />
      </div>

      <div className="w-[380px] h-full bg-[#fbfbfa] dark:bg-[#191919] border-l border-[#efefef] dark:border-white/5 flex flex-col z-50 shadow-2xl overflow-hidden">
        <div className="p-4 flex flex-col h-full">
          <div className="flex flex-col gap-4 py-2 border-b border-[#eee] dark:border-white/5 mb-4">
             <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                   <div className="flex items-center gap-1.5" title="Rewards"><span className="text-lg">🎁</span><span className="text-sm font-black opacity-80">{rewardPoints}</span></div>
                   <div className="flex items-center gap-1.5" title="Alchemy Uses"><span className="text-lg">⚗️</span><span className="text-sm font-black opacity-80">{jarUses}</span></div>
                   <div className="flex items-center gap-1.5" title="Map Completions"><span className="text-lg">🏅</span><span className="text-sm font-black opacity-80">{mapCompletions}</span></div>
                </div>
                <button onClick={() => setDarkMode(!darkMode)} className="p-1.5 rounded-md hover:bg-black/5 dark:hover:bg-white/5 text-xs">{darkMode ? '☀️' : '🌙'}</button>
             </div>
             <div className="flex items-center gap-4 text-[10px] font-black opacity-25 uppercase tracking-widest">
               <div className="flex items-center gap-1"><span>⚡</span><span>Energy: {rollBank}</span></div>
               <div className="flex items-center gap-1"><span>🎲</span><span>Rolls: {rollsCount}</span></div>
             </div>
          </div>

          <div className="flex-1 overflow-y-auto px-1">
             <div className="mb-4 text-xs font-bold opacity-60">Quest Log</div>
             <div className="flex flex-col gap-2">
                {tasks.map(t => (
                  <div key={t.id} className="p-3 bg-black/5 dark:bg-white/5 rounded-lg opacity-80 hover:opacity-100 cursor-pointer transition-opacity" onClick={() => {
                    setRollBank(r => r + 15);
                    setHistory(prev => [{ ...t, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
                    setTasks(prev => prev.filter(x => x.id !== t.id));
                  }}>
                    <p className="text-xs">{t.text}</p>
                    <div className={`mt-2 inline-flex items-center px-1.5 py-0.5 rounded text-[8px] font-black uppercase border ${getPriorityColor(t.priority)}`}>{t.priority}</div>
                  </div>
                ))}
             </div>
          </div>
        </div>
      </div>

      <style>{`
        .notion-grid { background-image: radial-gradient(#efefef 1px, transparent 1px); background-size: 20px 20px; }
        .dark .notion-grid { background-image: radial-gradient(rgba(255,255,255,0.03) 1px, transparent 1px); }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.03); background: rgba(255,255,255,0.8); border-radius: 4px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.01); background: rgba(18,18,18,0.7); }
        @keyframes trail-move { 0% { transform: translate(0, 0) scale(1); opacity: 1; } 100% { left: calc(100vw - 320px); top: 30px; transform: scale(0.2); opacity: 0; } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';

interface AlchemyJarProps {
  count: number;
  max: number;
  isExploding: boolean;
  onExplode: () => void;
  isDeducting?: boolean;
  height?: number;
}

export const AlchemyJar: React.FC<AlchemyJarProps> = ({ 
  count, 
  max, 
  isExploding, 
  onExplode, 
  isDeducting,
  height = 400
}) => {
  const percent = Math.min(100, (count / max) * 100);
  const isFull = count >= max;
  const [holdProgress, setHoldProgress] = useState(0);
  const holdInterval = useRef<number | null>(null);

  const startHold = () => {
    if (!isFull || isExploding) return;
    holdInterval.current = window.setInterval(() => {
      setHoldProgress(prev => {
        if (prev >= 100) {
          if (holdInterval.current) clearInterval(holdInterval.current);
          onExplode();
          return 0;
        }
        // ~3 seconds hold (30ms interval * 100 iterations / 1.1 increment = ~2700ms)
        return prev + 1.1;
      });
    }, 30);
  };

  const endHold = () => {
    if (holdInterval.current) {
      clearInterval(holdInterval.current);
      holdInterval.current = null;
    }
    setHoldProgress(0);
  };

  return (
    <div 
      className="flex flex-col items-center justify-end relative w-16"
      style={{ height: `${height}px` }}
    >
      <div 
        className={`relative w-10 cursor-pointer transition-all duration-500 
          ${isExploding ? 'scale-150 blur-3xl opacity-0' : 'scale-100'} 
          ${isFull && !isExploding ? 'hover:scale-105 active:scale-95' : ''}`}
        style={{ height: '100%' }}
        onMouseDown={startHold}
        onMouseUp={endHold}
        onMouseLeave={endHold}
        onTouchStart={startHold}
        onTouchEnd={endHold}
      >
        {/* Rim (Open Top) */}
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-12 h-1 bg-white/30 backdrop-blur rounded-full border border-white/20 z-20" />

        {/* Tall Vial Body */}
        <div className="absolute inset-0 bg-white/5 dark:bg-black/20 border-x border-b border-white/20 dark:border-white/10 backdrop-blur-sm overflow-hidden rounded-b-full z-10 shadow-inner">

          {/* Subtle Glare Reflection */}
          <div className="absolute left-1.5 top-5 w-1 h-3/4 bg-white/10 rounded-full blur-[2px] z-20" />

          {/* Alchemy Liquid Content */}
          <div 
            className={`absolute bottom-0 left-0 w-full transition-all duration-700 ease-out ${isDeducting ? 'bg-red-500/60' : 'bg-indigo-600/60'}`}
            style={{ height: `${percent}%` }}
          >
            {/* Top Surface Glow */}
            <div className="absolute top-0 left-0 w-full h-[2px] bg-white/40" />

            {/* Minimalist Bubbles */}
            <div className="absolute inset-0 overflow-hidden">
               {[...Array(4)].map((_, i) => (
                 <div 
                   key={i} 
                   className="absolute bottom-0 bg-white/20 rounded-full animate-bubble"
                   style={{
                     width: 4,
                     height: 4,
                     left: `${Math.random() * 80 + 10}%`,
                     animationDuration: `${Math.random() * 2 + 2}s`,
                     animationDelay: `${i * 0.5}s`
                   }}
                 />
               ))}
            </div>
          </div>

          {/* Internal Progress Text */}
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-30">
            <span className={`text-[8px] font-black opacity-40 transition-colors ${percent > 50 ? 'text-white' : 'text-indigo-400'}`}>
              {isDeducting ? '-5' : Math.floor(percent)}
            </span>
          </div>
        </div>

        {/* Hold Progress Circle */}
        {holdProgress > 0 && (
          <div className="absolute inset-0 flex items-center justify-center z-40 pointer-events-none">
            <svg className="w-16 h-16 -rotate-90">
              <circle
                cx="32"
                cy="32"
                r="28"
                fill="none"
                stroke="white"
                strokeWidth="2"
                strokeDasharray={`${(holdProgress * 175) / 100} 175`}
                strokeLinecap="round"
                className="opacity-50"
              />
            </svg>
          </div>
        )}
      </div>

      <style>{`
        @keyframes bubble {
          0% { transform: translateY(10px) scale(0.5); opacity: 0; }
          40% { opacity: 0.5; }
          100% { transform: translateY(-130px) scale(1.1); opacity: 0; }
        }
        .animate-bubble { animation: bubble linear infinite; }
      `}</style>
    </div>
  );
};

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
