import React, { useState, useRef } from 'react';

interface AlchemyJarProps {
  count: number;
  max: number;
  isExploding: boolean;
  onExplode: () => void;
  isDeducting?: boolean;
  height?: number;
}

export const AlchemyJar: React.FC<AlchemyJarProps> = ({ 
  count, 
  max, 
  isExploding, 
  onExplode, 
  isDeducting,
  height = 150 
}) => {
  const percent = Math.min(100, (count / max) * 100);
  const isFull = count >= max;
  const [holdProgress, setHoldProgress] = useState(0);
  const holdInterval = useRef<number | null>(null);

  const startHold = () => {
    if (!isFull || isExploding) return;
    holdInterval.current = window.setInterval(() => {
      setHoldProgress(prev => {
        if (prev >= 100) {
          if (holdInterval.current) clearInterval(holdInterval.current);
          onExplode();
          return 0;
        }
        return prev + 1; // 3 seconds total (30ms * 100)
      });
    }, 30);
  };

  const endHold = () => {
    if (holdInterval.current) {
      clearInterval(holdInterval.current);
      holdInterval.current = null;
    }
    setHoldProgress(0);
  };

  return (
    <div 
      className="flex flex-col items-center justify-end relative w-12"
      style={{ height: `${height}px` }}
    >
      <div 
        className={`relative w-8 cursor-pointer transition-all duration-500 
          ${isExploding ? 'scale-150 blur-3xl opacity-0' : 'scale-100'} 
          ${isFull && !isExploding ? 'hover:scale-105 active:scale-95 shadow-[0_0_15px_rgba(79,70,229,0.2)]' : ''}`}
        style={{ height: '100%' }}
        onMouseDown={startHold}
        onMouseUp={endHold}
        onMouseLeave={endHold}
        onTouchStart={startHold}
        onTouchEnd={endHold}
      >
        {/* Simple Open Top */}
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-10 h-0.5 bg-white/20 backdrop-blur rounded-full border border-white/10 z-20" />

        {/* Minimal Glass Body */}
        <div className="absolute inset-0 bg-white/5 dark:bg-black/20 border-x border-b border-white/10 dark:border-white/5 backdrop-blur-sm overflow-hidden rounded-b-xl z-10 shadow-inner">

          {/* Subtle Reflection */}
          <div className="absolute left-1 top-2 w-0.5 h-3/4 bg-white/5 rounded-full blur-[1px] z-20" />

          {/* Liquid Content */}
          <div 
            className={`absolute bottom-0 left-0 w-full transition-all duration-700 ease-out ${isDeducting ? 'bg-red-500/40' : 'bg-indigo-600/40'}`}
            style={{ height: `${percent}%` }}
          >
            {/* Liquid Surface */}
            <div className="absolute top-0 left-0 w-full h-[1px] bg-white/30" />

            {/* Graphics Reduction: Only 2 bubbles */}
            <div className="absolute inset-0 overflow-hidden">
               {[...Array(2)].map((_, i) => (
                 <div 
                   key={i} 
                   className="absolute bottom-0 bg-white/10 rounded-full animate-bubble"
                   style={{
                     width: 3,
                     height: 3,
                     left: `${Math.random() * 60 + 20}%`,
                     animationDuration: `${Math.random() * 2 + 2}s`,
                     animationDelay: `${i * 1.5}s`
                   }}
                 />
               ))}
            </div>
          </div>

          {/* Minimal Text */}
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-30">
            <span className={`text-[7px] font-black opacity-20 transition-colors ${percent > 50 ? 'text-white' : 'text-indigo-400'}`}>
              {Math.floor(percent)}%
            </span>
          </div>
        </div>

        {/* Progress Hold Ring */}
        {holdProgress > 0 && (
          <div className="absolute inset-0 flex items-center justify-center z-40 pointer-events-none">
            <svg className="w-12 h-12 -rotate-90">
              <circle
                cx="24"
                cy="24"
                r="20"
                fill="none"
                stroke="white"
                strokeWidth="2"
                strokeDasharray={`${(holdProgress * 125) / 100} 125`}
                strokeLinecap="round"
                className="opacity-40"
              />
            </svg>
          </div>
        )}
      </div>

      <style>{`
        @keyframes bubble {
          0% { transform: translateY(5px) scale(0.5); opacity: 0; }
          50% { opacity: 0.3; }
          100% { transform: translateY(-80px) scale(1); opacity: 0; }
        }
        .animate-bubble { animation: bubble linear infinite; }
      `}</style>
    </div>
  );
};

