  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(48);

  useEffect(() => {
    const updateSize = () => {
      const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
      const availableH = window.innerHeight / APP_SCALE;
      const horizontalLimit = (availableW - 60) / BOARD_W;
      const verticalLimit = (availableH - 60) / BOARD_H;
      const bestSize = Math.max(25, Math.min(horizontalLimit, verticalLimit, 45));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
    const availableH = window.innerHeight / APP_SCALE;
    const boardRealW = (BOARD_W - 1) * tileSize;
    const boardRealH = (BOARD_H - 1) * tileSize;
    const startX = (availableW - boardRealW) / 2;
    const startY = (availableH - boardRealH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    const zInd = getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude);
    const bInd = getRandomUnique(BOMB_COUNT, [...startExclude, ...zInd]);
    const pInd = getRandomUnique(PUMPKIN_COUNT, [...startExclude, ...zInd, ...bInd]);
    const dInd = getRandomUnique(DEMON_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd]);
    const cInd = getRandomUnique(CLOVER_COUNT, [...startExclude, ...zInd, ...bInd, ...pInd, ...dInd]);

    setZombieIndicators(zInd);
    setBombIndices(bInd);
    setPumpkinIndices(pInd);
    setDemonIndices(dInd);
    setCloverIndices(cInd);
  }, [boardSpaces.length, getRandomUnique]);

  useEffect(() => {
    const timer = setInterval(() => {
      setActiveSweets(prev => {
        const next = { ...prev };
        let changed = false;
        Object.keys(next).forEach(id => {
          if (next[id].secondsLeft > 0) {
            next[id].secondsLeft -= 1;
            changed = true;
          }
        });
        return changed ? next : prev;
      });
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const triggerExplosionTrail = useCallback((x: number, y: number, points: number) => {
    const targetX = window.innerWidth - 60; 
    const targetY = 60;

    // Graphics Quality Reduction 30%: Particle count reduced to 5
    const newParticles: Particle[] = Array.from({ length: 5 }).map((_, i) => ({
      id: Math.random(),
      emoji: EXPLOSION_EMOJIS[Math.floor(Math.random() * EXPLOSION_EMOJIS.length)],
      x: x + (Math.random() - 0.5) * 50,
      y: y + (Math.random() - 0.5) * 50,
      targetX,
      targetY,
      delay: i * 100
    }));

    setParticles(prev => [...prev, ...newParticles]);
    setTimeout(() => {
      setRewardPoints(prev => prev + points);
      setParticles(prev => prev.filter(p => !newParticles.find(np => np.id === p.id)));
    }, 1500);
  }, []);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1.2)); 
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 400); // Shorter life bloom for performance
  };

  const relocateItem = (list: number[], pos: number, type: string) => {
    const newList = list.filter(p => p !== pos);
    const exclude = [currentPos, 0, ...newList, ...bombIndices, ...zombieIndicators, ...pumpkinIndices, ...demonIndices, ...cloverIndices, ...activeZombies.map(z => z.pos)];
    const [newPos] = getRandomUnique(1, exclude);

    switch(type) {
      case 'bomb': setBombIndices([...newList, newPos]); break;
      case 'zombie': setZombieIndicators([...newList, newPos]); break;
      case 'pumpkin': setPumpkinIndices([...newList, newPos]); break;
      case 'demon': setDemonIndices([...newList, newPos]); break;
      case 'clover': setCloverIndices([...newList, newPos]); break;
    }
  };

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) {
      setPumpkinBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    if (demonBoss.isActive) {
      setDemonBoss(prev => {
        const newHealth = prev.health - 1;
        return newHealth <= 0 ? { isActive: false, health: 0 } : { ...prev, health: newHealth };
      });
    }
    setActiveZombies(prev => {
      if (prev.length === 0) return prev;
      let nearestIndex = 0;
      let minDistance = Infinity;
      prev.forEach((z, idx) => {
        const dist = Math.min(Math.abs(damagePos - z.pos), TOTAL_TILES - Math.abs(damagePos - z.pos));
        if (dist < minDistance) { minDistance = dist; nearestIndex = idx; }
      });
      const newZombies = [...prev];
      const target = { ...newZombies[nearestIndex] };
      target.health -= 1;
      if (target.health <= 0) {
        newZombies.splice(nearestIndex, 1);
      } else { newZombies[nearestIndex] = target; }
      return newZombies;
    });
    setIsShaking(true);
    setTimeout(() => { setIsShaking(false); setBombAnimation({ active: false, pos: -1 }); }, 400);
  }, [pumpkinBoss, demonBoss, activeZombies]);

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;

    if (diceSum === 1) applyBombDamage(tempPos);

    const interval = setInterval(() => {
      const nextPos = (tempPos + 1) % TOTAL_TILES;
      if (nextPos === 0) setMapCompletions(prev => prev + 1);

      tempPos = nextPos;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      setActiveSweets(prev => {
        const next = { ...prev };
        Object.keys(next).forEach(id => {
          if (next[id].steps > 0) {
            next[id].steps -= 1;
            if (next[id].steps === 0) {
              const centerX = (window.innerWidth - SIDEBAR_WIDTH) / 2;
              const centerY = window.innerHeight / 2;
              let x = centerX, y = centerY;
              if (id === 'cone') { x -= 60; y -= 60; }
              else if (id === 'slice') { x += 60; y -= 60; }
              else if (id === 'cake') { y += 40; }
              triggerExplosionTrail(x, y, next[id].points);
              delete next[id];
            }
          }
        });
        return next;
      });

      if (cloverIndices.includes(tempPos)) {
        setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1));
        relocateItem(cloverIndices, tempPos, 'clover');
      }
      if (bombIndices.includes(tempPos)) {
        applyBombDamage(tempPos);
        relocateItem(bombIndices, tempPos, 'bomb');
      }

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        const finalPos = tempPos;

        if (zombieIndicators.includes(finalPos)) {
          const spawnPos = (finalPos - SPAWN_BEHIND_OFFSET + TOTAL_TILES) % TOTAL_TILES;
          setActiveZombies(prev => [...prev, {
            id: Math.random().toString(36).substr(2, 9),
            pos: spawnPos,
            health: MAX_ZOMBIE_HEALTH,
            isActive: true
          }]);
          relocateItem(zombieIndicators, finalPos, 'zombie');
        }
        if (pumpkinIndices.includes(finalPos)) {
          setPumpkinBoss(prev => ({ isActive: true, health: MAX_PUMPKIN_HEALTH }));
          relocateItem(pumpkinIndices, finalPos, 'pumpkin');
        }
        if (demonIndices.includes(finalPos)) {
          setDemonBoss(prev => ({ isActive: true, health: MAX_DEMON_HEALTH }));
          relocateItem(demonIndices, finalPos, 'demon');
        }

        setActiveZombies(prev => {
          let damaged = false;
          const moved = prev.map(z => {
            const nextZPos = (z.pos + 2) % TOTAL_TILES;
            if (nextZPos === finalPos) damaged = true;
            return { ...z, pos: nextZPos };
          });
          if (damaged) setPlayerHealth(h => Math.max(0, h - 1));
          return moved;
        });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, activeZombies, pumpkinIndices, demonIndices, cloverIndices, applyBombDamage, triggerExplosionTrail, tileSize]);

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);

    setRollsCount(prev => {
      if (Object.keys(activeSweets).length > 0) return prev;
      const next = prev + 1;
      if (next % 5 === 0) {
        setActiveSweets({
          cone: { id: 'cone', emoji: '🍦', steps: 12, totalSteps: 12, secondsLeft: 2 * 3600, totalSeconds: 2 * 3600, points: 10, sizeMultiplier: 1.28 },
          slice: { id: 'slice', emoji: '🍰', steps: 18, totalSteps: 18, secondsLeft: 4 * 3600, totalSeconds: 4 * 3600, points: 20, sizeMultiplier: 1.536 },
          cake: { id: 'cake', emoji: '🎂', steps: 28, totalSteps: 28, secondsLeft: 8 * 3600, totalSeconds: 8 * 3600, points: 30, sizeMultiplier: 2.24 },
        });
        return 0; 
      }
      return next;
    });

    const newValues = [Math.floor(Math.random() * 6) + 1];
    setDicePositions([{ x: landing.x, y: landing.y }]);

    setTimeout(() => {
      setIsRolling(false);
      setDiceValues(newValues);
      setIsMoving(true);
      processMovement(newValues[0]);
    }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setJarUses(u => u + 1); 
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => {
        setIsExploding(false);
        setJarCount(0);
        setRollBank(r => r + 40);
    }, 1200);
  };

  const ENEMY_ICON = darkMode ? '🧛🏻' : '🧟';
  const BOMB_ICON = darkMode ? '🧄' : '💣';

  const bossSize = tileSize * 2.24; // Same as Cake (🎂) size

  return (
    <div className={`h-screen w-screen flex transition-all duration-700 bg-white dark:bg-zinc-950 ${isExploding ? 'bg-indigo-600/10' : ''}`}>
      {particles.map(p => (
        <div key={p.id} className="fixed z-[100] text-xl pointer-events-none transition-all duration-[1500ms] ease-in-out" style={{ left: p.x, top: p.y, animation: `trail-move 1.5s ease-in-out ${p.delay}ms forwards` }}>{p.emoji}</div>
      ))}

      <div ref={gameAreaRef} className="flex-1 relative overflow-hidden notion-grid">
        <div className="relative w-full h-full origin-top-left flex items-center justify-center" style={{ transform: `scale(${APP_SCALE})` }}>
          <div className="relative w-full h-full">
            <div className="absolute inset-0 z-0 pointer-events-none opacity-40">
                {boardSpaces.map(s => {
                  const bloom = blooms[s.id];
                  const icon = bombIndices.includes(s.id) ? BOMB_ICON : (zombieIndicators.includes(s.id) ? ENEMY_ICON : (pumpkinIndices.includes(s.id) ? '🎃' : (demonIndices.includes(s.id) ? '👹' : (cloverIndices.includes(s.id) ? '🍀' : null))));
                  return (
                    <div key={s.id} className={`absolute sudoku-tile flex items-center justify-center transition-all duration-500`} style={{ left: s.x, top: s.y, width: tileSize, height: tileSize }}>
                      {icon && <span className="opacity-10" style={{ fontSize: tileSize * 0.4 }}>{icon}</span>}
                      {bloom && <span className="bloom absolute opacity-25" style={{ fontSize: tileSize * 0.4 }}>{bloom}</span>}
                    </div>
                  );
                })}

                {activeZombies.map(z => boardSpaces[z.pos] && (
                <div key={z.id} className="absolute z-20 transition-all duration-700 ease-in-out" style={{ left: boardSpaces[z.pos].x + tileSize/2, top: boardSpaces[z.pos].y + tileSize/2, transform: 'translate(-50%, -60%)' }}>
                    <span className="drop-shadow-lg" style={{ fontSize: tileSize * 0.9 }}>{ENEMY_ICON}</span>
                </div>
                ))}

                <div 
                onClick={() => setAnimalIndex(p => (p + 1) % ANIMAL_ICONS.length)}
                className="absolute z-30 transition-all duration-300 ease-out cursor-pointer pointer-events-auto"
                style={{ left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, transform: 'translate(-50%, -60%)', fontSize: tileSize * 1.2 }}
                >
                <div className="flex flex-col items-center">
                    <div className="flex gap-0.5 mb-1 bg-white/90 p-0.5 rounded-full px-1 border border-black/5 shadow-sm">
                        {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => <div key={i} className={`w-1 h-0.5 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />)}
                    </div>
                    <span className="drop-shadow-xl select-none">{ANIMAL_ICONS[animalIndex]}</span>
                </div>
                </div>
            </div>

            {/* Central Area: Jar & Bosses */}
            <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
                <div className="relative w-full h-full flex items-center justify-center">
                    <div className="flex items-end justify-center gap-[4px]">

                        {/* Alchemy Jar: Shortened to 3 tiles high */}
                        <div className="flex justify-center pointer-events-auto">
                           <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} height={tileSize * 3} />
                        </div>

                        {/* Bosses: Positioned exactly 2 tiles to the right of the jar */}
                        <div className="flex flex-col items-center gap-6 mb-1" style={{ marginLeft: tileSize * 2 }}>
                           {pumpkinBoss.isActive && (
                               <div className="flex flex-col items-center animate-bounce-slow">
                               <div className="flex gap-1 mb-1.5 bg-white/80 p-0.5 rounded-full shadow-md border border-orange-500/10">
                                   {[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => (
                                       <div key={i} className={`w-2.5 h-0.5 rounded-full ${i < pumpkinBoss.health ? 'bg-orange-500' : 'bg-gray-200 opacity-20'}`} />
                                   ))}
                               </div>
                               <span className="leading-none drop-shadow-2xl" style={{ fontSize: bossSize }}>🎃</span>
                               </div>
                           )}
                           {demonBoss.isActive && (
                               <div className="flex flex-col items-center animate-bounce-slow" style={{ animationDelay: '-1.5s' }}>
                               <div className="flex gap-1 mb-1.5 bg-white/80 p-0.5 rounded-full shadow-md border border-red-500/10">
                                   {[...Array(MAX_DEMON_HEALTH)].map((_, i) => (
                                       <div key={i} className={`w-2.5 h-0.5 rounded-full ${i < demonBoss.health ? 'bg-red-500' : 'bg-gray-200 opacity-20'}`} />
                                   ))}
                               </div>
                               <span className="leading-none drop-shadow-2xl" style={{ fontSize: bossSize }}>👹</span>
                               </div>
                           )}
                        </div>
                    </div>

                    {/* Sweets Section: Simple layout */}
                    <div className="absolute top-1/4 left-1/4 flex flex-col items-center gap-4">
                        {activeSweets.cone && <div className="flex flex-col items-center gap-1 opacity-60"><span className="text-[7px] font-black opacity-30">{activeSweets.cone.steps}s</span><span style={{ fontSize: tileSize * activeSweets.cone.sizeMultiplier }}>🍦</span></div>}
                        {activeSweets.slice && <div className="flex flex-col items-center gap-1 opacity-60"><span className="text-[7px] font-black opacity-30">{activeSweets.slice.steps}s</span><span style={{ fontSize: tileSize * activeSweets.slice.sizeMultiplier }}>🍰</span></div>}
                        {activeSweets.cake && <div className="flex flex-col items-center gap-1 opacity-60"><span className="text-[7px] font-black opacity-30">{activeSweets.cake.steps}s</span><span style={{ fontSize: tileSize * activeSweets.cake.sizeMultiplier }}>🎂</span></div>}
                    </div>
                </div>
            </div>
          </div>
        </div>

        <Dice3D value={diceValues[0] || 1} isRolling={isRolling} currentPos={dicePositions[0]} onRoll={handleRoll} onDragEnd={(p) => setDicePositions([p])} />
      </div>

      <div className="w-[380px] h-full bg-[#fbfbfa] dark:bg-[#191919] border-l border-[#efefef] dark:border-white/5 flex flex-col z-50 shadow-xl overflow-hidden">
        <div className="p-4 flex flex-col h-full">
          <div className="flex flex-col gap-3 py-2 border-b border-[#eee] dark:border-white/5 mb-4">
             <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                   <div className="flex items-center gap-1.5"><span className="text-lg">🎁</span><span className="text-sm font-black opacity-80">{rewardPoints}</span></div>
                   <div className="flex items-center gap-1.5"><span className="text-lg">⚗️</span><span className="text-sm font-black opacity-80">{jarUses}</span></div>
                   <div className="flex items-center gap-1.5"><span className="text-lg">🏅</span><span className="text-sm font-black opacity-80">{mapCompletions}</span></div>
                </div>
                <button onClick={() => setDarkMode(!darkMode)} className="p-1 rounded bg-black/5 dark:bg-white/5 text-[10px]">{darkMode ? '☀️' : '🌙'}</button>
             </div>
             <div className="flex items-center gap-4 text-[9px] font-black opacity-25 uppercase tracking-widest">
               <div className="flex items-center gap-1"><span>⚡</span><span>Energy: {rollBank}</span></div>
               <div className="flex items-center gap-1"><span>🎲</span><span>Rolls: {rollsCount}</span></div>
             </div>
          </div>

          <div className="flex-1 flex flex-col overflow-hidden">
             <div className="flex items-center justify-between px-1 mb-4">
                <div className="text-[14px] font-bold opacity-70">Quests</div>
                <div className="flex gap-4">
                   <button onClick={() => setShowHistory(false)} className={`text-[12px] font-medium transition-all ${!showHistory ? 'text-indigo-600' : 'opacity-40'}`}>Active</button>
                   <button onClick={() => setShowHistory(true)} className={`text-[12px] font-medium transition-all ${showHistory ? 'text-indigo-600' : 'opacity-40'}`}>Log</button>
                </div>
             </div>
             <div className="flex-1 overflow-y-auto px-1 pb-4">
                {!showHistory ? (
                   <div className="flex flex-col gap-2">
                      {tasks.map(t => (
                        <div key={t.id} onClick={() => handleTaskComplete(t)} className="p-2.5 bg-black/[0.02] dark:bg-white/[0.02] rounded-lg border border-transparent hover:border-black/5 transition-all cursor-pointer">
                           <p className="text-[13px] opacity-80">{t.text}</p>
                           <div className={`mt-1.5 text-[8px] font-black uppercase opacity-20`}>{t.priority}</div>
                        </div>
                      ))}
                      <div className="mt-4 border-t border-black/5 dark:border-white/5 pt-4">
                        <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([...tasks, { id: Date.now().toString(), text: newTask, completed: false, priority: 'medium' }]); setNewTask(''); }}>
                           {/* Simplified task input as requested */}
                           <input value={newTask} onChange={e => setNewTask(e.target.value)} placeholder="+ Add new task..." className="w-full bg-transparent border-none outline-none text-[13px] opacity-40 focus:opacity-100 placeholder:opacity-30" />
                        </form>
                      </div>
                   </div>
                ) : (
                  <div className="flex flex-col gap-2 opacity-50">
                     {history.map(h => (
                       <div key={h.id} className="p-2 border-b border-black/5 text-[12px] line-through opacity-60">{h.text}</div>
                     ))}
                  </div>
                )}
             </div>
          </div>
        </div>
      </div>

      <style>{`
        .notion-grid { background-image: radial-gradient(#efefef 1px, transparent 1px); background-size: 20px 20px; }
        .dark .notion-grid { background-image: radial-gradient(rgba(255,255,255,0.03) 1px, transparent 1px); }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.02); background: rgba(255,255,255,0.6); border-radius: 2px; }
        .dark .sudoku-tile { border: 1px solid rgba(255,255,255,0.01); background: rgba(18,18,18,0.5); }
        @keyframes trail-move { 
          0% { transform: translate(0, 0) scale(1); opacity: 1; } 
          100% { transform: translate(calc(100vw - 320px), -100px) scale(0.2); opacity: 0; } 
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';

interface AlchemyJarProps {
  count: number;
  max: number;
  isExploding: boolean;
  onExplode: () => void;
  isDeducting?: boolean;
  height?: number;
}

export const AlchemyJar: React.FC<AlchemyJarProps> = ({ 
  count, 
  max, 
  isExploding, 
  onExplode, 
  isDeducting,
  height = 160 // Shorter by default to match ~3 tiles
}) => {
  const percent = Math.min(100, (count / max) * 100);
  const isFull = count >= max;
  const [holdProgress, setHoldProgress] = useState(0);
  const holdInterval = useRef<number | null>(null);

  const startHold = () => {
    if (!isFull || isExploding) return;
    holdInterval.current = window.setInterval(() => {
      setHoldProgress(prev => {
        if (prev >= 100) {
          if (holdInterval.current) clearInterval(holdInterval.current);
          onExplode();
          return 0;
        }
        return prev + 1; // 3 seconds hold at 30ms interval
      });
    }, 30);
  };

  const endHold = () => {
    if (holdInterval.current) {
      clearInterval(holdInterval.current);
      holdInterval.current = null;
    }
    setHoldProgress(0);
  };

  return (
    <div 
      className="flex flex-col items-center justify-end relative w-16"
      style={{ height: `${height}px` }}
    >
      <div 
        className={`relative w-10 cursor-pointer transition-all duration-500 
          ${isExploding ? 'scale-150 blur-3xl opacity-0' : 'scale-100'} 
          ${isFull && !isExploding ? 'hover:scale-105 active:scale-95 shadow-[0_0_15px_rgba(79,70,229,0.1)]' : ''}`}
        style={{ height: '100%' }}
        onMouseDown={startHold}
        onMouseUp={endHold}
        onMouseLeave={endHold}
        onTouchStart={startHold}
        onTouchEnd={endHold}
      >
        {/* Simplified Rim */}
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-12 h-0.5 bg-white/20 backdrop-blur rounded-full border border-white/10 z-20" />

        {/* Short Vial Body */}
        <div className="absolute inset-0 bg-white/5 dark:bg-black/20 border-x border-b border-white/10 dark:border-white/5 backdrop-blur-sm overflow-hidden rounded-b-xl z-10 shadow-inner">

          {/* Subtle Reflection */}
          <div className="absolute left-1 top-2 w-0.5 h-3/4 bg-white/5 rounded-full blur-[1px] z-20" />

          {/* Liquid Content */}
          <div 
            className={`absolute bottom-0 left-0 w-full transition-all duration-700 ease-out ${isDeducting ? 'bg-red-500/30' : 'bg-indigo-600/30'}`}
            style={{ height: `${percent}%` }}
          >
            {/* Liquid Surface */}
            <div className="absolute top-0 left-0 w-full h-[1px] bg-white/20" />

            {/* Graphics Reduction 30%: Only 2 bubbles */}
            <div className="absolute inset-0 overflow-hidden">
               {[...Array(2)].map((_, i) => (
                 <div 
                   key={i} 
                   className="absolute bottom-0 bg-white/10 rounded-full animate-bubble"
                   style={{
                     width: 3,
                     height: 3,
                     left: `${Math.random() * 60 + 20}%`,
                     animationDuration: `${Math.random() * 2 + 2}s`,
                     animationDelay: `${i * 1.5}s`
                   }}
                 />
               ))}
            </div>
          </div>

          {/* Progress Percentage */}
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-30">
            <span className={`text-[8px] font-black opacity-30 transition-colors ${percent > 50 ? 'text-white' : 'text-indigo-400'}`}>
              {Math.floor(percent)}%
            </span>
          </div>
        </div>

        {/* Hold Progress Circle */}
        {holdProgress > 0 && (
          <div className="absolute inset-0 flex items-center justify-center z-40 pointer-events-none">
            <svg className="w-12 h-12 -rotate-90">
              <circle
                cx="24"
                cy="24"
                r="20"
                fill="none"
                stroke="white"
                strokeWidth="2"
                strokeDasharray={`${(holdProgress * 125) / 100} 125`}
                strokeLinecap="round"
                className="opacity-30"
              />
            </svg>
          </div>
        )}
      </div>

      <style>{`
        @keyframes bubble {
          0% { transform: translateY(5px) scale(0.5); opacity: 0; }
          50% { opacity: 0.2; }
          100% { transform: translateY(-70px) scale(1); opacity: 0; }
        }
        .animate-bubble { animation: bubble linear infinite; }
      `}</style>
    </div>
  );
};

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Task, BoardSpace, BigZombie, PumpkinBoss, DemonBoss } from './types';
import { Dice3D } from './components/Dice3D';
import { AlchemyJar } from './components/AlchemyJar';

const INITIAL_ROLLS = 35;
const MAX_JAR = 100;
const MOVE_STEP_DELAY = 220; 

// Graphics Quality 30%: Minimal item density
const ZOMBIE_INDICATOR_COUNT = 5; 
const BOMB_COUNT = 5;           
const PUMPKIN_COUNT = 3;        
const DEMON_COUNT = 3;         
const CLOVER_COUNT = 3; 

const MAX_ZOMBIE_HEALTH = 5; 
const MAX_PUMPKIN_HEALTH = 3; 
const MAX_DEMON_HEALTH = 3; 
const MAX_PLAYER_HEALTH = 5; 

const BOARD_W = 24; 
const BOARD_H = 14; 
const TOTAL_TILES = (BOARD_W + BOARD_H - 2) * 2; 
const SPAWN_BEHIND_OFFSET = 5;

const APP_SCALE = 1.25; 
const SIDEBAR_WIDTH = 380;

const ANIMAL_ICONS = [
  '🦖', '🦕', '🐊', '🐢', '🦎', '🐍', '🐉', '🐲', 
  '🐳', '🐋', '🐬', '🦈', '🐠', '🐟', '🐡', '🐙', '🦑', '🦐', '🦀', '🦞',
  '🦁', '🐯', '🐅', '🐆', '🦓', '🐘', '🦣', '🦏', '🦛', '🐪', '🐫', '🦒', '🐾',
  '🦍', '🦧', '🐼', '🐻', '🐨', '🦥', '🦦', '🦨', '🦘', '🦡', '🦝', '🦊', '🐺',
  '🦉', '🦜', '🦚', '🦩', '🦢', '🕊️', '🐧', '🦆', '🦃', '🐓', '🐔', '🐦', '🦤',
  '🐈', '🐈‍⬛', '🐕', '🐩', '🐎', '🐄', '🐂', '🐃', '🐖', '🐏', '🐑', '🐐', '🦙', '🐇', '🐹', '🐿️', '🦔', '🐸', '🦄'
];

const FLOWER_EMOJIS = ['🌸', '🌼', '🌺', '🌻', '🌹', '🌷'];
const EXPLOSION_EMOJIS = ['🍦','🍧','🍨','🍩','🍪','🎂','🍰','🧁','🥧','🍫','🍬','🍭','🍮','🍇','🍈','🍉','🍊','🍋','🍌','🍍','🥭','🍎','🍏','🍐','🍑','🍒','🍓','🫐','🍅','🫒','🥥'];

interface CompletedTask extends Task {
  completedAt: string;
}

interface SweetData {
  id: string;
  emoji: string;
  steps: number;
  totalSteps: number;
  secondsLeft: number;
  totalSeconds: number;
  points: number;
  sizeMultiplier: number;
}

interface Particle {
  id: number;
  emoji: string;
  x: number;
  y: number;
  targetX: number;
  targetY: number;
  delay: number;
}

const App: React.FC = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [animalIndex, setAnimalIndex] = useState(0);
  const [playerHealth, setPlayerHealth] = useState(MAX_PLAYER_HEALTH);

  const [rewardPoints, setRewardPoints] = useState(0);
  const [rollsCount, setRollsCount] = useState(0);
  const [jarUses, setJarUses] = useState(0);
  const [mapCompletions, setMapCompletions] = useState(0);

  const [activeSweets, setActiveSweets] = useState<Record<string, SweetData>>({});
  const [particles, setParticles] = useState<Particle[]>([]);

  const [tasks, setTasks] = useState<Task[]>([
    { id: '1', text: 'Nạp đầy 100 Alchemy', completed: false, priority: 'high' },
    { id: '2', text: 'Tiêu diệt 3 Quỷ lớn', completed: false, priority: 'medium' },
  ]);
  const [history, setHistory] = useState<CompletedTask[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [newTask, setNewTask] = useState('');

  const [currentPos, setCurrentPos] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [rollBank, setRollBank] = useState(INITIAL_ROLLS);

  const [diceValues, setDiceValues] = useState<number[]>([1]);
  const [isRolling, setIsRolling] = useState(false);

  const gameAreaRef = useRef<HTMLDivElement>(null);

  const [dicePositions, setDicePositions] = useState<{ x: number; y: number }[]>([
    { x: (window.innerWidth - SIDEBAR_WIDTH) / 2, y: window.innerHeight / 2 }
  ]);

  const [isExploding, setIsExploding] = useState(false);
  const [jarCount, setJarCount] = useState(0);
  const [isDeducting, setIsDeducting] = useState(false);
  const [blooms, setBlooms] = useState<Record<number, string>>({});

  const [zombieIndicators, setZombieIndicators] = useState<number[]>([]);
  const [activeZombies, setActiveZombies] = useState<BigZombie[]>([]);
  const [bombIndices, setBombIndices] = useState<number[]>([]);
  const [pumpkinIndices, setPumpkinIndices] = useState<number[]>([]);
  const [demonIndices, setDemonIndices] = useState<number[]>([]);
  const [cloverIndices, setCloverIndices] = useState<number[]>([]);

  const [pumpkinBoss, setPumpkinBoss] = useState<PumpkinBoss>({ isActive: false, health: 0 });
  const [demonBoss, setDemonBoss] = useState<DemonBoss>({ isActive: false, health: 0 });
  const [bombAnimation, setBombAnimation] = useState<{ active: boolean; pos: number }>({ active: false, pos: -1 });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
  }, [darkMode]);

  const [tileSize, setTileSize] = useState(48);

  useEffect(() => {
    const updateSize = () => {
      const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
      const availableH = window.innerHeight / APP_SCALE;
      const horizontalLimit = (availableW - 60) / BOARD_W;
      const verticalLimit = (availableH - 60) / BOARD_H;
      const bestSize = Math.max(25, Math.min(horizontalLimit, verticalLimit, 45));
      setTileSize(bestSize);
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const boardSpaces = useMemo(() => {
    const spaces: BoardSpace[] = [];
    const availableW = (window.innerWidth - SIDEBAR_WIDTH) / APP_SCALE;
    const availableH = window.innerHeight / APP_SCALE;
    const boardRealW = (BOARD_W - 1) * tileSize;
    const boardRealH = (BOARD_H - 1) * tileSize;
    const startX = (availableW - boardRealW) / 2;
    const startY = (availableH - boardRealH) / 2;

    for (let i = 0; i < BOARD_W; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY });
    for (let i = 1; i < BOARD_H; i++) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + (BOARD_W - 1) * tileSize, y: startY + i * tileSize });
    for (let i = BOARD_W - 2; i >= 0; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX + i * tileSize, y: startY + (BOARD_H - 1) * tileSize });
    for (let i = BOARD_H - 2; i >= 1; i--) 
      spaces.push({ id: spaces.length, type: 'normal', x: startX, y: startY + i * tileSize });

    return spaces;
  }, [tileSize]);

  const getRandomUnique = useCallback((count: number, exclude: number[]) => {
    const res: number[] = [];
    while(res.length < count) {
      const r = Math.floor(Math.random() * TOTAL_TILES);
      if (!exclude.includes(r) && !res.includes(r)) res.push(r);
    }
    return res;
  }, []);

  useEffect(() => {
    if (boardSpaces.length === 0) return;
    const startExclude = [0];
    setZombieIndicators(getRandomUnique(ZOMBIE_INDICATOR_COUNT, startExclude));
    setBombIndices(getRandomUnique(BOMB_COUNT, startExclude));
    setPumpkinIndices(getRandomUnique(PUMPKIN_COUNT, startExclude));
    setDemonIndices(getRandomUnique(DEMON_COUNT, startExclude));
    setCloverIndices(getRandomUnique(CLOVER_COUNT, startExclude));
  }, [boardSpaces.length, getRandomUnique]);

  useEffect(() => {
    const timer = setInterval(() => {
      setActiveSweets(prev => {
        const next = { ...prev };
        let changed = false;
        Object.keys(next).forEach(id => {
          if (next[id].secondsLeft > 0) {
            next[id].secondsLeft -= 1;
            changed = true;
          }
        });
        return changed ? next : prev;
      });
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const triggerExplosionTrail = useCallback((x: number, y: number, points: number) => {
    // Quality 30%: Only 4 particles
    const newParticles: Particle[] = Array.from({ length: 4 }).map((_, i) => ({
      id: Math.random(),
      emoji: EXPLOSION_EMOJIS[Math.floor(Math.random() * EXPLOSION_EMOJIS.length)],
      x: x + (Math.random() - 0.5) * 40,
      y: y + (Math.random() - 0.5) * 40,
      targetX: window.innerWidth - 60,
      targetY: 60,
      delay: i * 80
    }));

    setParticles(prev => [...prev, ...newParticles]);
    setTimeout(() => {
      setRewardPoints(prev => prev + points);
      setParticles(prev => prev.filter(p => !newParticles.find(np => np.id === p.id)));
    }, 1200);
  }, []);

  const triggerBloom = (pos: number) => {
    const flower = FLOWER_EMOJIS[Math.floor(Math.random() * FLOWER_EMOJIS.length)];
    setBlooms(prev => ({ ...prev, [pos]: flower }));
    setJarCount(c => Math.min(MAX_JAR, c + 1.2)); 
    setTimeout(() => setBlooms(prev => {
      const next = { ...prev };
      delete next[pos];
      return next;
    }), 300); // Very short bloom for performance
  };

  const applyBombDamage = useCallback((damagePos: number) => {
    setBombAnimation({ active: true, pos: damagePos });
    if (pumpkinBoss.isActive) setPumpkinBoss(p => ({ ...p, health: Math.max(0, p.health - 1) }));
    if (demonBoss.isActive) setDemonBoss(p => ({ ...p, health: Math.max(0, p.health - 1) }));
    setActiveZombies(prev => prev.map(z => z.pos === damagePos ? { ...z, health: z.health - 1 } : z).filter(z => z.health > 0));
    setTimeout(() => setBombAnimation({ active: false, pos: -1 }), 300);
  }, [pumpkinBoss, demonBoss]);

  const processMovement = useCallback((diceSum: number) => {
    let stepsDone = 0;
    let tempPos = currentPos;
    const interval = setInterval(() => {
      const nextPos = (tempPos + 1) % TOTAL_TILES;
      if (nextPos === 0) setMapCompletions(prev => prev + 1);
      tempPos = nextPos;
      setCurrentPos(tempPos);
      triggerBloom(tempPos);
      stepsDone++;

      setActiveSweets(prev => {
        const next = { ...prev };
        Object.keys(next).forEach(id => {
          if (next[id].steps > 0) {
            next[id].steps -= 1;
            if (next[id].steps === 0) {
              triggerExplosionTrail((window.innerWidth - SIDEBAR_WIDTH) / 2, window.innerHeight / 2, next[id].points);
              delete next[id];
            }
          }
        });
        return next;
      });

      if (cloverIndices.includes(tempPos)) setPlayerHealth(h => Math.min(MAX_PLAYER_HEALTH, h + 1));
      if (bombIndices.includes(tempPos)) applyBombDamage(tempPos);

      if (stepsDone >= diceSum) {
        clearInterval(interval);
        setIsMoving(false);
        if (zombieIndicators.includes(tempPos)) setActiveZombies(z => [...z, { id: Math.random().toString(), pos: (tempPos - 5 + TOTAL_TILES) % TOTAL_TILES, health: MAX_ZOMBIE_HEALTH, isActive: true }]);
        if (pumpkinIndices.includes(tempPos)) setPumpkinBoss({ isActive: true, health: MAX_PUMPKIN_HEALTH });
        if (demonIndices.includes(tempPos)) setDemonBoss({ isActive: true, health: MAX_DEMON_HEALTH });
      }
    }, MOVE_STEP_DELAY);
  }, [currentPos, bombIndices, cloverIndices, zombieIndicators, pumpkinIndices, demonIndices, triggerExplosionTrail, applyBombDamage]);

  const handleRoll = (landing: { x: number, y: number }) => {
    if (rollBank <= 0 || isRolling || isMoving) return;
    setIsRolling(true);
    setRollBank(r => r - 1);
    const val = Math.floor(Math.random() * 6) + 1;

    setRollsCount(prev => {
      if (Object.keys(activeSweets).length > 0) return prev;
      const next = prev + 1;
      if (next % 5 === 0) {
        setActiveSweets({
          cone: { id: 'cone', emoji: '🍦', steps: 12, totalSteps: 12, secondsLeft: 2 * 3600, totalSeconds: 2 * 3600, points: 10, sizeMultiplier: 1.28 },
          slice: { id: 'slice', emoji: '🍰', steps: 18, totalSteps: 18, secondsLeft: 4 * 3600, totalSeconds: 4 * 3600, points: 20, sizeMultiplier: 1.536 },
          cake: { id: 'cake', emoji: '🎂', steps: 28, totalSteps: 28, secondsLeft: 8 * 3600, totalSeconds: 8 * 3600, points: 30, sizeMultiplier: 2.24 },
        });
        return 0; 
      }
      return next;
    });

    setDicePositions([{ x: landing.x, y: landing.y }]);
    setTimeout(() => { setIsRolling(false); setDiceValues([val]); setIsMoving(true); processMovement(val); }, 1200);
  };

  const handleTaskComplete = (task: Task) => {
    setRollBank(r => r + 15);
    setHistory(prev => [{ ...task, completed: true, completedAt: new Date().toLocaleTimeString() }, ...prev]);
    setTasks(prev => prev.filter(t => t.id !== task.id));
  };

  const onJarExplode = () => {
    setIsExploding(true);
    setJarUses(u => u + 1);
    setActiveZombies([]);
    setPumpkinBoss({ isActive: false, health: 0 });
    setDemonBoss({ isActive: false, health: 0 });
    setTimeout(() => { setIsExploding(false); setJarCount(0); setRollBank(r => r + 40); }, 1000);
  };

  const bossIconSize = tileSize * 2.24; // Matching cake multiplier

  return (
    <div className={`h-screen w-screen flex bg-white dark:bg-zinc-950 transition-colors duration-700 overflow-hidden`}>
      {particles.map(p => (
        <div key={p.id} className="fixed z-[100] text-xl pointer-events-none transition-all duration-1000" style={{ left: p.x, top: p.y, animation: `trail-move 1.2s forwards` }}>{p.emoji}</div>
      ))}

      <div ref={gameAreaRef} className="flex-1 relative overflow-hidden notion-grid">
        <div className="relative w-full h-full origin-top-left flex items-center justify-center" style={{ transform: `scale(${APP_SCALE})` }}>
          <div className="relative w-full h-full">
            <div className="absolute inset-0 z-0 pointer-events-none opacity-40">
                {boardSpaces.map(s => (
                  <div key={s.id} className="absolute sudoku-tile" style={{ left: s.x, top: s.y, width: tileSize, height: tileSize }}>
                    {blooms[s.id] && <span className="bloom absolute opacity-30" style={{ fontSize: tileSize * 0.4 }}>{blooms[s.id]}</span>}
                  </div>
                ))}

                {activeZombies.map(z => boardSpaces[z.pos] && (
                  <div key={z.id} className="absolute z-20" style={{ left: boardSpaces[z.pos].x + tileSize/2, top: boardSpaces[z.pos].y + tileSize/2, transform: 'translate(-50%, -60%)' }}>
                    <span style={{ fontSize: tileSize }}>🧛🏻</span>
                  </div>
                ))}

                <div 
                  className="absolute z-30 transition-all duration-300" 
                  style={{ left: (boardSpaces[currentPos]?.x || 0) + tileSize/2, top: (boardSpaces[currentPos]?.y || 0) + tileSize/2, transform: 'translate(-50%, -60%)' }}
                >
                  <div className="flex flex-col items-center">
                    <div className="flex gap-0.5 mb-1 bg-white/80 p-0.5 rounded-full border border-black/5">
                      {[...Array(MAX_PLAYER_HEALTH)].map((_, i) => <div key={i} className={`w-1 h-0.5 rounded-full ${i < playerHealth ? 'bg-green-500' : 'bg-gray-200'}`} />)}
                    </div>
                    <span className="text-2xl">{ANIMAL_ICONS[animalIndex]}</span>
                  </div>
                </div>
            </div>

            {/* Central Area: Moved up by 2 tiles */}
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                <div className="flex items-end justify-center gap-1" style={{ transform: `translateY(-${tileSize * 2}px)` }}>
                    <div className="pointer-events-auto">
                        <AlchemyJar count={jarCount} max={MAX_JAR} isExploding={isExploding} onExplode={onJarExplode} isDeducting={isDeducting} height={tileSize * 3} />
                    </div>

                    {/* Bosses positioned 2 tiles to the right */}
                    <div className="flex flex-col items-center gap-4 mb-2" style={{ marginLeft: tileSize * 2 }}>
                        {pumpkinBoss.isActive && (
                          <div className="flex flex-col items-center">
                            <div className="flex gap-1 mb-1 bg-white/60 p-0.5 rounded-full border border-orange-500/20">
                              {[...Array(MAX_PUMPKIN_HEALTH)].map((_, i) => <div key={i} className={`w-2 h-0.5 rounded-full ${i < pumpkinBoss.health ? 'bg-orange-500' : 'bg-gray-300'}`} />)}
                            </div>
                            <span style={{ fontSize: bossIconSize }}>🎃</span>
                          </div>
                        )}
                        {demonBoss.isActive && (
                          <div className="flex flex-col items-center">
                            <div className="flex gap-1 mb-1 bg-white/60 p-0.5 rounded-full border border-red-500/20">
                              {[...Array(MAX_DEMON_HEALTH)].map((_, i) => <div key={i} className={`w-2 h-0.5 rounded-full ${i < demonBoss.health ? 'bg-red-500' : 'bg-gray-300'}`} />)}
                            </div>
                            <span style={{ fontSize: bossIconSize }}>👹</span>
                          </div>
                        )}
                    </div>
                </div>

                {/* Sweets layer */}
                <div className="absolute top-1/3 flex gap-8">
                  {activeSweets.cone && <span style={{ fontSize: tileSize * activeSweets.cone.sizeMultiplier }}>🍦</span>}
                  {activeSweets.slice && <span style={{ fontSize: tileSize * activeSweets.slice.sizeMultiplier }}>🍰</span>}
                  {activeSweets.cake && <span style={{ fontSize: tileSize * activeSweets.cake.sizeMultiplier }}>🎂</span>}
                </div>
            </div>
          </div>
        </div>

        <Dice3D value={diceValues[0] || 1} isRolling={isRolling} currentPos={dicePositions[0]} onRoll={handleRoll} onDragEnd={(p) => setDicePositions([p])} />
      </div>

      <div className="w-[380px] h-full bg-[#fbfbfa] dark:bg-[#191919] border-l border-[#efefef] dark:border-white/5 flex flex-col z-50 shadow-xl overflow-hidden">
        <div className="p-4 flex flex-col h-full">
          <div className="flex flex-col gap-3 py-2 border-b border-[#eee] dark:border-white/5 mb-4">
             <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                   <div className="flex items-center gap-1.5"><span className="text-lg">🎁</span><span className="text-sm font-black opacity-70">{rewardPoints}</span></div>
                   <div className="flex items-center gap-1.5"><span className="text-lg">⚗️</span><span className="text-sm font-black opacity-70">{jarUses}</span></div>
                   <div className="flex items-center gap-1.5"><span className="text-lg">🏅</span><span className="text-sm font-black opacity-70">{mapCompletions}</span></div>
                </div>
                <button onClick={() => setDarkMode(!darkMode)} className="p-1 rounded bg-black/5 dark:bg-white/5 text-[10px]">{darkMode ? '☀️' : '🌙'}</button>
             </div>
             <div className="flex items-center gap-4 text-[9px] font-black opacity-20 uppercase tracking-widest">
               <div>⚡ {rollBank}</div>
               <div>🎲 {rollsCount}</div>
             </div>
          </div>

          <div className="flex-1 flex flex-col overflow-hidden">
             <div className="flex items-center justify-between px-1 mb-4">
                <div className="text-[12px] font-bold opacity-60 uppercase">Quests</div>
                <div className="flex gap-4">
                   <button onClick={() => setShowHistory(false)} className={`text-[10px] font-bold ${!showHistory ? 'text-indigo-600' : 'opacity-30'}`}>Active</button>
                   <button onClick={() => setShowHistory(true)} className={`text-[10px] font-bold ${showHistory ? 'text-indigo-600' : 'opacity-30'}`}>Log</button>
                </div>
             </div>
             <div className="flex-1 overflow-y-auto px-1">
                {!showHistory ? (
                   <div className="flex flex-col gap-2">
                      {tasks.map(t => (
                        <div key={t.id} onClick={() => handleTaskComplete(t)} className="p-2 bg-black/[0.02] dark:bg-white/[0.02] rounded border border-transparent hover:border-black/5 cursor-pointer">
                           <p className="text-[13px] opacity-70">{t.text}</p>
                        </div>
                      ))}
                      <div className="mt-4 border-t border-black/5 pt-4">
                        <form onSubmit={e => { e.preventDefault(); if(!newTask.trim()) return; setTasks([...tasks, { id: Date.now().toString(), text: newTask, completed: false }]); setNewTask(''); }}>
                           <input value={newTask} onChange={e => setNewTask(e.target.value)} placeholder="+ Quick task" className="w-full bg-transparent border-none outline-none text-[13px] opacity-50 focus:opacity-100" />
                        </form>
                      </div>
                   </div>
                ) : (
                  <div className="flex flex-col gap-1 opacity-40">
                     {history.map(h => (
                       <div key={h.id} className="p-1 text-[11px] line-through">{h.text}</div>
                     ))}
                  </div>
                )}
             </div>
          </div>
        </div>
      </div>

      <style>{`
        .notion-grid { background-image: radial-gradient(#efefef 1px, transparent 1px); background-size: 20px 20px; }
        .dark .notion-grid { background-image: radial-gradient(rgba(255,255,255,0.02) 1px, transparent 1px); }
        .sudoku-tile { border: 1px solid rgba(0,0,0,0.02); background: rgba(255,255,255,0.4); border-radius: 2px; }
        @keyframes trail-move { 0% { transform: scale(1); opacity: 1; } 100% { transform: translate(300px, -100px) scale(0); opacity: 0; } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';

interface AlchemyJarProps {
  count: number;
  max: number;
  isExploding: boolean;
  onExplode: () => void;
  isDeducting?: boolean;
  height?: number;
}

export const AlchemyJar: React.FC<AlchemyJarProps> = ({ 
  count, 
  max, 
  isExploding, 
  onExplode, 
  isDeducting,
  height = 160 
}) => {
  const percent = Math.min(100, (count / max) * 100);
  const isFull = count >= max;
  const [holdProgress, setHoldProgress] = useState(0);
  const holdInterval = useRef<number | null>(null);

  const startHold = () => {
    if (!isFull || isExploding) return;
    holdInterval.current = window.setInterval(() => {
      setHoldProgress(prev => {
        if (prev >= 100) {
          if (holdInterval.current) clearInterval(holdInterval.current);
          onExplode();
          return 0;
        }
        return prev + 1; // 3 seconds at 30ms
      });
    }, 30);
  };

  const endHold = () => {
    if (holdInterval.current) {
      clearInterval(holdInterval.current);
      holdInterval.current = null;
    }
    setHoldProgress(0);
  };

  return (
    <div 
      className="flex flex-col items-center justify-end relative w-12"
      style={{ height: `${height}px` }}
    >
      <div 
        className={`relative w-8 cursor-pointer transition-all duration-500 
          ${isExploding ? 'scale-150 blur-3xl opacity-0' : 'scale-100'} 
          ${isFull && !isExploding ? 'hover:scale-105 active:scale-95' : ''}`}
        style={{ height: '100%' }}
        onMouseDown={startHold}
        onMouseUp={endHold}
        onMouseLeave={endHold}
        onTouchStart={startHold}
        onTouchEnd={endHold}
      >
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-10 h-0.5 bg-white/10 backdrop-blur rounded-full border border-white/5 z-20" />

        <div className="absolute inset-0 bg-white/5 dark:bg-black/10 border-x border-b border-white/10 dark:border-white/5 overflow-hidden rounded-b-lg z-10">
          <div 
            className={`absolute bottom-0 left-0 w-full transition-all duration-700 ${isDeducting ? 'bg-red-500/20' : 'bg-indigo-600/20'}`}
            style={{ height: `${percent}%` }}
          >
            {/* Minimal Bubbles: Only 1 for 30% quality */}
            <div className="absolute inset-0 overflow-hidden">
                 <div 
                   className="absolute bottom-0 bg-white/5 rounded-full animate-bubble"
                   style={{
                     width: 3, height: 3,
                     left: '40%',
                     animationDuration: '3s'
                   }}
                 />
            </div>
          </div>

          <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-30">
            <span className="text-[7px] font-black opacity-20">
              {Math.floor(percent)}%
            </span>
          </div>
        </div>

        {holdProgress > 0 && (
          <div className="absolute inset-0 flex items-center justify-center z-40 pointer-events-none">
            <svg className="w-10 h-10 -rotate-90">
              <circle
                cx="20" cy="20" r="18"
                fill="none"
                stroke="white"
                strokeWidth="1.5"
                strokeDasharray={`${(holdProgress * 113) / 100} 113`}
                strokeLinecap="round"
                className="opacity-20"
              />
            </svg>
          </div>
        )}
      </div>

      <style>{`
        @keyframes bubble {
          0% { transform: translateY(5px); opacity: 0; }
          50% { opacity: 0.1; }
          100% { transform: translateY(-60px); opacity: 0; }
        }
        .animate-bubble { animation: bubble linear infinite; }
      `}</style>
    </div>
  );
};
